      SUBROUTINE DPPLO1(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                        MAXNPP,   &
                        IBUGG3,IBUGQ,IFOUND,IERROR)
!
!     PURPOSE--FORM A Y PLOT, A Y VERSUS X PLOT, A SUBSET PLOT,
!              AND OTHER SIMILAR TYPE PLOTS
!              WHEN HAVE NO VERSUS AND NO EQUALS.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--DECEMBER  1977.
!     UPDATED         --JANUARY   1978.
!     UPDATED         --FEBRUARY  1978.
!     UPDATED         --MAY       1978.
!     UPDATED         --JUNE      1978.
!     UPDATED         --JULY      1978.
!     UPDATED         --NOVEMBER  1978.
!     UPDATED         --FEBRUARY  1979.
!     UPDATED         --MARCH     1979.
!     UPDATED         --JULY      1979.
!     UPDATED         --JANUARY   1981.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MARCH     1988. FIX PLOT Y FOR ... WHEN I OUT OF BOUNDS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IAND1
      CHARACTER*4 IAND2
      CHARACTER*4 IBUGG3
      CHARACTER*4 IBUGQ
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 ICASEQ
      CHARACTER*4 IHVERT
      CHARACTER*4 IHVER2
      CHARACTER*4 IHHOR
      CHARACTER*4 IHHOR2
      CHARACTER*4 IHSET
      CHARACTER*4 IHSET2
      CHARACTER*4 IERRO4
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPPL'
      ISUBN2='O1  '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      NUMAR1=0
      D2MIN=0.0
      DEL=0.0
!
!               ********************************
!               **  STEP 10--                 **
!               **  TREAT THE CASE WHEN HAVE  **
!               **  NO    VERSUS        AND   **
!               **  NO    FOR X =             **
!               ********************************
!
      IF(IBUGG3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPLO1--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)NPLOTV,NPLOTP,NS,MAXNPP
   52   FORMAT('NPLOTV,NPLOTP,NS,MAXNPP = ',4I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASPL,IAND1,IAND2,IBUGG3,IBUGQ
   53   FORMAT('ICASPL,IAND1,IAND2,IBUGG3,IBUGQ = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)IFOUND,IERROR
   55   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK THE VALIDITY OF ARGUMENT 1      **
!               **  (THIS WILL BE THE VERTICAL VARIABLE)  **
!               ********************************************
!
      ISTEPN='11'
      IF(IBUGG3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IHVERT=IHARG(1)
      IHVER2=IHARG2(1)
      IHWUSE='V'
      MESSAG='YES'
      CALL CHECKN(IHVERT,IHVER2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      IVAV=IVALUE(ILOCV)
      NLOCAL=IN(ILOCV)
!
      IF(IBUGG3.EQ.'ON')THEN
        WRITE(ICOUT,1107)IHVERT,IHVER2,ILOCV,IERROR,IVAV,NLOCAL
 1107   FORMAT('IHVERT,IHVER2,ILOCV,IERROR,IVAV,NLOCAL = ',   &
               A4,A4,2X,I8,2X,A4,I8,I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************************************
!               **  STEP 12--                          **
!               **  CHECK TO SEE THE TYPE CASE--       **
!               **    1) UNQUALIFIED (THAT IS, FULL);  **
!               **    2) SUBSET/EXCEPT; OR             **
!               **    3) FOR.                          **
!               *****************************************
!
      ISTEPN='12'
      IF(IBUGG3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASEQ='FULL'
      ILOCQ=NUMARG+1
      IF(NUMARG.LT.1)GO TO 1290
      DO 1200 J=1,NUMARG
        J1=J
        IF(IHARG(J).EQ.'SUBS'.AND.IHARG2(J).EQ.'ET  ') GO TO 1210
        IF(IHARG(J).EQ.'EXCE'.AND.IHARG2(J).EQ.'PT  ') GO TO 1210
        IF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    ') GO TO 1220
 1200 CONTINUE
      GO TO 1290
 1210 CONTINUE
      ICASEQ='SUBS'
      ILOCQ=J1
      GO TO 1290
 1220 CONTINUE
      ICASEQ='FOR'
      ILOCQ=J1
      GO TO 1290
 1290 CONTINUE
!
      IF(IBUGG3.EQ.'ON')THEN
        WRITE(ICOUT,1291)NUMARG,ILOCQ
 1291   FORMAT('NUMARG,ILOCQ = ',12I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************************
!               **  STEP 13--                              **
!               **  FORM THE VECTOR ISUB(.)                **
!               **  DEPENDING ON THE TYPE OF CASE          **
!               **  FOR THE QUALIFIER.                     **
!               *********************************************
!
      ISTEPN='13'
      IF(IBUGG3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICASEQ.EQ.'SUBS')THEN
        NIOLD=NLOCAL
        CALL DPSUBS(NIOLD,ILOCS,NS,IBUGQ,IERRO4)
        NQ=NIOLD
      ELSEIF(ICASEQ.EQ.'FOR')THEN
        NIOLD=NLOCAL
        CALL DPFOR(NIOLD,NFOR,IROW1,IROWN,   &
                   NLOCAL,ILOCS,NS,IBUGQ,IERRO4)
        NQ=NFOR
        IF(NS.GT.NIOLD)NS=NIOLD
      ELSE
        DO 1315 I=1,NLOCAL
          ISUB(I)=1
 1315   CONTINUE
        NQ=NLOCAL
      ENDIF
!
!               **********************************************************
!               **  STEP 14--                                           **
!               **  BRANCH ACCORDING TO THE NUMBER OF ARGUMENTS BEFORE  **
!               **  'SUBS', 'FOR', AND 'AND'.                          **
!               **********************************************************
!
      ISTEPN='14'
      IF(IBUGG3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ILOCA=NUMARG+1
      IF(IHARG(NUMARG).EQ.'AND')ILOCA=NUMARG
      IF(ILOCA.LT.ILOCQ)NUMAR1=ILOCA-1
      IF(ILOCQ.LT.ILOCA)NUMAR1=ILOCQ-1
      IF(ILOCA.EQ.ILOCQ)NUMAR1=NUMARG
      IF(NUMAR1.EQ.1)GO TO 1500
      IF(NUMAR1.EQ.2)GO TO 1600
      IF(NUMAR1.EQ.3)GO TO 1700
!
      WRITE(ICOUT,1401)
 1401 FORMAT('***** ERROR IN DPPLO1--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1402)
 1402 FORMAT('      NUMAR1 NOT = 1, 2, OR 3. ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1403)NUMAR1
 1403 FORMAT('      NUMAR1 = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1404)NUMARG,IHARG(NUMARG),ILOCA,ILOCQ
 1404 FORMAT('      NUMARG,IHARG(NUMARG),ILOCA,ILOCQ = ',   &
             I6,2X,A4,2I6)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1408)
 1408 FORMAT('      THE COMMAND LINE WAS AS FOLLOWS--')
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)THEN
        WRITE(ICOUT,1409)(IANS(I),I=1,IWIDTH)
 1409   FORMAT('      ',100A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      IERROR='YES'
      GO TO 9000
!
!               *************************************************************
!               **  STEP 15--                                              **
!               **  TREAT THE 1 VARIABLE CASE (WITH NO VS AND NO =) CASE.  **
!               *************************************************************
!
 1500 CONTINUE
      ISTEPN='15'
      IF(IBUGG3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               ****************************************
!               **  STEP 15.1--                       **
!               **  CHECK THE VALIDITY OF ARGUMENT 1  **
!               ****************************************
!
      IHVERT=IHARG(1)
      IHVER2=IHARG2(1)
      IHWUSE='V'
      MESSAG='YES'
      CALL CHECKN(IHVERT,IHVER2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOC,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      IVAV=IVALUE(ILOC)
!
!               *************************************************************
!               **  STEP 15.2--                                            **
!               **  FORM THE VERTICAL AND HORIZONTAL AXIS                  **
!               **  VARIABLES (Y(.) AND X(.), RESPECTIVELY) FOR THE PLOT.  **
!               **  RESET THE D(.) VECTOR TO ONES.                         **
!               **  DEFINE THE NUMBER OF PLOT POINTS    (NPLOTP).          **
!               **  DEFINE THE NUMBER OF PLOT VARIABLES (NPLOTV).          **
!               *************************************************************
!
      ISTEPN='15.2'
      IF(IBUGG3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IAND1.EQ.'NO')GO TO 1519
      IF(NPLOTP.LE.0)GO TO 1519
      D1MAX=D(1)
      DO 1510 I=1,NPLOTP
      IF(D(I).GT.D1MAX)D1MAX=D(I)
 1510 CONTINUE
      D2MIN=1.0
      IF(IAND1.EQ.'YES')DEL=D1MAX-D2MIN+1.0
 1519 CONTINUE
!
      L=NPLOTP
!
      DO 1520 I=1,NLOCAL
      IF(ISUB(I).EQ.0)GO TO 1520
      L=L+1
!
      IF(L.LE.MAXNPP)GO TO 1529
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1521)
 1521 FORMAT('***** ERROR IN DPPLO1--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1523)
 1523 FORMAT('      THE NUMBER OF PLOT POINTS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1524)MAXNPP
 1524 FORMAT('      HAS JUST EXCEEDED ',I8,' *****')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1525)I,NLOCAL,L,MAXN,MAXNPP,NPLOTP
 1525 FORMAT('I,NLOCAL,L,MAXN,MAXNPP,NPLOTP = ',6I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1526)IAND1,IAND2,IFOUND,IERROR
 1526 FORMAT('IAND1,IAND2,IFOUND,IERROR = ',A4,2X,A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
 1529 CONTINUE
!
      IJ=MAXN*(IVAV-1)+I
      IF(IVAV.LE.MAXCOL)Y(L)=V(IJ)
      IF(IVAV.EQ.MAXCP1)Y(L)=PRED(I)
      IF(IVAV.EQ.MAXCP2)Y(L)=RES(I)
      IF(IVAV.EQ.MAXCP3)Y(L)=YPLOT(I)
      IF(IVAV.EQ.MAXCP4)Y(L)=XPLOT(I)
      IF(IVAV.EQ.MAXCP5)Y(L)=X2PLOT(I)
      IF(IVAV.EQ.MAXCP6)Y(L)=TAGPLO(I)
      X(L)=L
      IF(IAND1.EQ.'NO')D(L)=1.0
      IF(IAND1.EQ.'YES')D(L)=1.0+DEL
 1520 CONTINUE
      NPLOTP=L
      NPLOTV=1
      IF(IAND1.EQ.'YES'.AND.NPLOTV.GT.1)NPLOTV=NPLOTV
      GO TO 9000
!
!               *************************************************************
!               **  STEP 16--                                              **
!               **  TREAT THE 2 VARIABLE CASE (WITH NO VS AND NO =) CASE.  **
!               *************************************************************
!
 1600 CONTINUE
      ISTEPN='16'
      IF(IBUGG3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               ****************************************
!               **  STEP 16.1--                       **
!               **  CHECK THE VALIDITY OF ARGUMENT 1  **
!               ****************************************
!
      ISTEPN='16.1'
      IF(IBUGG3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IHVERT=IHARG(1)
      IHVER2=IHARG2(1)
      IHWUSE='V'
      MESSAG='YES'
      CALL CHECKN(IHVERT,IHVER2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      IVAV=IVALUE(ILOCV)
!
!               ****************************************
!               **  STEP 16.2--                       **
!               **  CHECK THE VALIDITY OF ARGUMENT 2  **
!               ****************************************
!
      ISTEPN='16.2'
      IF(IBUGG3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IHHOR=IHARG(2)
      IHHOR2=IHARG2(2)
      IHWUSE='V'
      MESSAG='YES'
      CALL CHECKN(IHHOR,IHHOR2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCH,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      IHAV=IVALUE(ILOCH)
!
!               *************************************************************
!               **  STEP 16.3--                                            **
!               **  FORM THE VERTICAL AND HORIZONTAL AXIS                  **
!               **  VARIABLES (Y(.) AND X(.), RESPECTIVELY) FOR THE PLOT.  **
!               **  RESET THE D(.) VECTOR TO ONES.                         **
!               **  DEFINE THE NUMBER OF PLOT POINTS    (NPLOTP).          **
!               **  DEFINE THE NUMBER OF PLOT VARIABLES (NPLOTV).          **
!               *************************************************************
!
      ISTEPN='16.3'
      IF(IBUGG3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IAND1.EQ.'NO')GO TO 1619
      IF(NPLOTP.LE.0)GO TO 1619
      D1MAX=D(1)
      DO 1610 I=1,NPLOTP
      IF(D(I).GT.D1MAX)D1MAX=D(I)
 1610 CONTINUE
      D2MIN=1.0
      IF(IAND1.EQ.'YES')DEL=D1MAX-D2MIN+1.0
 1619 CONTINUE
!
      L=NPLOTP
!
      NLOCAL=IN(ILOCV)
      DO 1620 I=1,NLOCAL
      IF(ISUB(I).EQ.0)GO TO 1620
      L=L+1
!
      IF(L.LE.MAXNPP)GO TO 1629
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1621)
 1621 FORMAT('***** ERROR IN DPPLO1--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1623)
 1623 FORMAT('      THE NUMBER OF PLOT POINTS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1624)MAXNPP
 1624 FORMAT('      HAS JUST EXCEEDED ',I8,' *****')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1625)I,NLOCAL,L,MAXN,MAXNPP,NPLOTP
 1625 FORMAT('I,NLOCAL,L,MAXN,MAXNPP,NPLOTP = ',6I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1626)IAND1,IAND2,IFOUND,IERROR
 1626 FORMAT('IAND1,IAND2,IFOUND,IERROR = ',A4,2X,A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
 1629 CONTINUE
!
      IJ=MAXN*(IVAV-1)+I
      IF(IVAV.LE.MAXCOL)Y(L)=V(IJ)
      IF(IVAV.EQ.MAXCP1)Y(L)=PRED(I)
      IF(IVAV.EQ.MAXCP2)Y(L)=RES(I)
      IF(IVAV.EQ.MAXCP3)Y(L)=YPLOT(I)
      IF(IVAV.EQ.MAXCP4)Y(L)=XPLOT(I)
      IF(IVAV.EQ.MAXCP5)Y(L)=X2PLOT(I)
      IF(IVAV.EQ.MAXCP6)Y(L)=TAGPLO(I)
      IJ=MAXN*(IHAV-1)+I
      IF(IHAV.LE.MAXCOL)X(L)=V(IJ)
      IF(IHAV.EQ.MAXCP1)X(L)=PRED(I)
      IF(IHAV.EQ.MAXCP2)X(L)=RES(I)
      IF(IHAV.EQ.MAXCP3)X(L)=YPLOT(I)
      IF(IHAV.EQ.MAXCP4)X(L)=XPLOT(I)
      IF(IHAV.EQ.MAXCP5)X(L)=X2PLOT(I)
      IF(IHAV.EQ.MAXCP6)X(L)=TAGPLO(I)
      IF(IAND1.EQ.'NO')D(L)=1.0
      IF(IAND1.EQ.'YES')D(L)=1.0+DEL
 1620 CONTINUE
      NPLOTP=L
      NPLOTV=2
      IF(IAND1.EQ.'YES'.AND.NPLOTV.GT.2)NPLOTV=NPLOTV
      GO TO 9000
!
!               *************************************************************
!               **  STEP 17--                                              **
!               **  TREAT THE 3 VARIABLE CASE (WITH NO VS AND NO =) CASE.  **
!               *************************************************************
!
 1700 CONTINUE
      ISTEPN='17'
      IF(IBUGG3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               ****************************************
!               **  STEP 17.1--                       **
!               **  CHECK THE VALIDITY OF ARGUMENT 1  **
!               ****************************************
!
      ISTEPN='17.1'
      IF(IBUGG3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IHVERT=IHARG(1)
      IHVER2=IHARG2(1)
      IHWUSE='V'
      MESSAG='YES'
      CALL CHECKN(IHVERT,IHVER2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      IVAV=IVALUE(ILOCV)
!
!               ****************************************
!               **  STEP 17.2--                       **
!               **  CHECK THE VALIDITY OF ARGUMENT 2  **
!               ****************************************
!
      ISTEPN='17.2'
      IF(IBUGG3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IHHOR=IHARG(2)
      IHHOR2=IHARG2(2)
      IHWUSE='V'
      MESSAG='YES'
      CALL CHECKN(IHHOR,IHHOR2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCH,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      IHAV=IVALUE(ILOCH)
!
!               ****************************************
!               **  STEP 17.3--                       **
!               **  CHECK THE VALIDITY OF ARGUMENT 3  **
!               ****************************************
!
      ISTEPN='17.3'
      IF(IBUGG3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IHSET=IHARG(3)
      IHSET2=IHARG2(3)
      IHWUSE='V'
      MESSAG='YES'
      CALL CHECKN(IHSET,IHSET2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCD,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      ISETV=IVALUE(ILOCD)
!
!               *************************************************************
!               **  STEP 17.4--                                            **
!               **  FORM THE VERTICAL AND HORIZONTAL AXIS                  **
!               **  VARIABLES (Y(.) AND X(.), RESPECTIVELY) FOR THE PLOT.  **
!               **  RESET THE D(.) VECTOR TO ONES.                         **
!               **  DEFINE THE NUMBER OF PLOT POINTS    (NPLOTP).          **
!               **  DEFINE THE NUMBER OF PLOT VARIABLES (NPLOTV).          **
!               *************************************************************
!
      ISTEPN='17.4'
      IF(IBUGG3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IAND1.EQ.'NO')GO TO 1719
      IF(NPLOTP.LE.0)GO TO 1719
      D1MAX=D(1)
      DO 1710 I=1,NPLOTP
      IF(D(I).GT.D1MAX)D1MAX=D(I)
 1710 CONTINUE
      I=1
      IJ=MAXN*(ISETV-1)+I
      IF(ISETV.LE.MAXCOL)D2MIN=V(IJ)
      IF(ISETV.EQ.MAXCP1)D2MIN=PRED(I)
      IF(ISETV.EQ.MAXCP2)D2MIN=RES(I)
      IF(ISETV.EQ.MAXCP3)D2MIN=YPLOT(I)
      IF(ISETV.EQ.MAXCP4)D2MIN=XPLOT(I)
      IF(ISETV.EQ.MAXCP5)D2MIN=X2PLOT(I)
      IF(ISETV.EQ.MAXCP6)D2MIN=TAGPLO(I)
      NLOCAL=IN(ILOCV)
      DO 1711 I=1,NLOCAL
      IJ=MAXN*(ISETV-1)+I
      IF(ISETV.LE.MAXCOL)GO TO 1712
      IF(ISETV.EQ.MAXCP1)GO TO 1713
      IF(ISETV.EQ.MAXCP2)GO TO 1714
      IF(ISETV.EQ.MAXCP3)GO TO 1715
      IF(ISETV.EQ.MAXCP4)GO TO 1716
      IF(ISETV.EQ.MAXCP5)GO TO 1717
      IF(ISETV.EQ.MAXCP6)GO TO 1718
 1712 CONTINUE
      IF(V(IJ).LT.D2MIN)D2MIN=V(IJ)
      GO TO 1711
 1713 CONTINUE
      IF(PRED(I).LT.D2MIN)D2MIN=PRED(I)
      GO TO 1711
 1714 CONTINUE
      IF(RES(I).LT.D2MIN)D2MIN=RES(I)
      GO TO 1711
 1715 CONTINUE
      IF(YPLOT(I).LT.D2MIN)D2MIN=YPLOT(I)
      GO TO 1711
 1716 CONTINUE
      IF(XPLOT(I).LT.D2MIN)D2MIN=XPLOT(I)
      GO TO 1711
 1717 CONTINUE
      IF(X2PLOT(I).LT.D2MIN)D2MIN=X2PLOT(I)
      GO TO 1711
 1718 CONTINUE
      IF(TAGPLO(I).LT.D2MIN)D2MIN=TAGPLO(I)
      GO TO 1711
 1711 CONTINUE
      IF(IAND1.EQ.'YES')DEL=D1MAX-D2MIN+1.0
 1719 CONTINUE
!
      L=NPLOTP
!
      NLOCAL=IN(ILOCV)
      DO 1720 I=1,NLOCAL
      IF(ISUB(I).EQ.0)GO TO 1720
      L=L+1
!
      IF(L.LE.MAXNPP)GO TO 1729
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1721)
 1721 FORMAT('***** ERROR IN DPPLO1--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1723)
 1723 FORMAT('      THE NUMBER OF PLOT POINTS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1724)MAXNPP
 1724 FORMAT('      HAS JUST EXCEEDED ',I8,' *****')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1725)I,NLOCAL,L,MAXN,MAXNPP,NPLOTP
 1725 FORMAT('I,NLOCAL,L,MAXN,MAXNPP,NPLOTP = ',6I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1726)IAND1,IAND2,IFOUND,IERROR
 1726 FORMAT('IAND1,IAND2,IFOUND,IERROR = ',A4,2X,A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
 1729 CONTINUE
!
      IJ=MAXN*(IVAV-1)+I
      IF(IVAV.LE.MAXCOL)Y(L)=V(IJ)
      IF(IVAV.EQ.MAXCP1)Y(L)=PRED(I)
      IF(IVAV.EQ.MAXCP2)Y(L)=RES(I)
      IF(IVAV.EQ.MAXCP3)Y(L)=YPLOT(I)
      IF(IVAV.EQ.MAXCP4)Y(L)=XPLOT(I)
      IF(IVAV.EQ.MAXCP5)Y(L)=X2PLOT(I)
      IF(IVAV.EQ.MAXCP6)Y(L)=TAGPLO(I)
      IJ=MAXN*(IHAV-1)+I
      IF(IHAV.LE.MAXCOL)X(L)=V(IJ)
      IF(IHAV.EQ.MAXCP1)X(L)=PRED(I)
      IF(IHAV.EQ.MAXCP2)X(L)=RES(I)
      IF(IHAV.EQ.MAXCP3)X(L)=YPLOT(I)
      IF(IHAV.EQ.MAXCP4)X(L)=XPLOT(I)
      IF(IHAV.EQ.MAXCP5)X(L)=X2PLOT(I)
      IF(IHAV.EQ.MAXCP6)X(L)=TAGPLO(I)
      IJ=MAXN*(ISETV-1)+I
      IF(IAND1.EQ.'NO'.AND.ISETV.LE.MAXCOL)D(L)=V(IJ)
      IF(IAND1.EQ.'NO'.AND.ISETV.EQ.MAXCP1)D(L)=PRED(I)
      IF(IAND1.EQ.'NO'.AND.ISETV.EQ.MAXCP2)D(L)=RES(I)
      IF(IAND1.EQ.'NO'.AND.ISETV.EQ.MAXCP3)D(L)=YPLOT(I)
      IF(IAND1.EQ.'NO'.AND.ISETV.EQ.MAXCP4)D(L)=XPLOT(I)
      IF(IAND1.EQ.'NO'.AND.ISETV.EQ.MAXCP5)D(L)=X2PLOT(I)
      IF(IAND1.EQ.'NO'.AND.ISETV.EQ.MAXCP6)D(L)=TAGPLO(I)
      IF(IAND1.EQ.'YES'.AND.ISETV.LE.MAXCOL)D(L)=V(IJ)+DEL
      IF(IAND1.EQ.'YES'.AND.ISETV.EQ.MAXCP1)D(L)=PRED(I)+DEL
      IF(IAND1.EQ.'YES'.AND.ISETV.EQ.MAXCP2)D(L)=RES(I)+DEL
      IF(IAND1.EQ.'YES'.AND.ISETV.EQ.MAXCP3)D(L)=YPLOT(I)+DEL
      IF(IAND1.EQ.'YES'.AND.ISETV.EQ.MAXCP4)D(L)=XPLOT(I)+DEL
      IF(IAND1.EQ.'YES'.AND.ISETV.EQ.MAXCP5)D(L)=X2PLOT(I)+DEL
      IF(IAND1.EQ.'YES'.AND.ISETV.EQ.MAXCP6)D(L)=TAGPLO(I)+DEL
 1720 CONTINUE
      NPLOTP=L
      NPLOTV=3
      IF(IAND1.EQ.'YES'.AND.NPLOTV.GT.3)NPLOTV=NPLOTV
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPLO1--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR,ICASPL,IAND1,IAND2
 9012   FORMAT('IFOUND,IERROR,ICASPL,IAND1,IAND2 = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPLOTV,NPLOTP,NS,MAXNPP
 9013   FORMAT('NPLOTV,NPLOTP,NS,MAXNPP = ',4I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9020)
 9020   FORMAT('I,Y(.),X(.),D(.),ISUB(.)--')
        CALL DPWRST('XXX','BUG ')
        DO 9021 I=1,NPLOTP
          WRITE(ICOUT,9022)I,Y(I),X(I),D(I),ISUB(I)
 9022     FORMAT(I8,3F15.7,I8)
          CALL DPWRST('XXX','BUG ')
 9021   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPPLO1
      SUBROUTINE DPPLO2(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
      IVSLOC,NUMVS,   &
      MAXNPP,   &
      IBUGG3,IBUGQ,IFOUND,IERROR)
!
!     PURPOSE--FORM A Y PLOT, A Y VERSUS X PLOT, A SUBSET PLOT,
!              AND OTHER SIMILAR TYPE PLOTS
!              WHEN HAVE 1 OR MORE VERSUS ENTERED.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--DECEMBER  1977.
!     UPDATED         --JANUARY   1978.
!     UPDATED         --FEBRUARY  1978.
!     UPDATED         --MAY       1978.
!     UPDATED         --JUNE      1978.
!     UPDATED         --JULY      1978.
!     UPDATED         --NOVEMBER  1978.
!     UPDATED         --FEBRUARY  1979.
!     UPDATED         --MARCH     1979.
!     UPDATED         --JULY      1979.
!     UPDATED         --JANUARY   1981.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --OCTOBER   1981.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MARCH     1988. FIX PLOT Y X FOR .. WHEN I OUT OF BOUNDS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IAND1
      CHARACTER*4 IAND2
      CHARACTER*4 IBUGG3
      CHARACTER*4 IBUGQ
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ICASEQ
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 IHVERT
      CHARACTER*4 IHVER2
      CHARACTER*4 IHHOR
      CHARACTER*4 IHHOR2
      CHARACTER*4 IERRO4
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION IVSLOC(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPPL'
      ISUBN2='O2  '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!CCCC MAXNPP=1000
!
      KSTART=0
!
      DEL=0.0
!
!               ***************************************************
!               **  STEP 20--                                    **
!               **  TREAT THE CASE WHEN HAVE 1 OR MORE 'VERSUS'  **
!               **  ENTERED                                      **
!               ****************************************************
!
      IF(IBUGG3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPLO2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)NPLOTV,NPLOTP,NS,MAXNPP
   52   FORMAT('NPLOTV,NPLOTP,NS,MAXNPP = ',4I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASPL,IAND1,IAND2
   53   FORMAT('ICASPL,IAND1,IAND2 = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)IBUGG3,IBUGQ,IFOUND,IERROR
   54   FORMAT('IBUGG3,IBUGQ,IFOUND,IERROR = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      ISTEPN='20'
      IF(IBUGG3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               *****************************************
!               **  STEP 21--                          **
!               **  CHECK TO SEE THE TYPE CASE--       **
!               **    1) UNQUALIFIED (THAT IS, FULL);  **
!               **    2) SUBSET/EXCEPT; OR             **
!               **    3) FOR.                          **
!               *****************************************
!
      ISTEPN='21'
      IF(IBUGG3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASEQ='FULL'
      ILOCQ=NUMARG+1
      IF(NUMARG.LT.1)GO TO 2190
      DO 2100 J=1,NUMARG
      J1=J
      IF(IHARG(J).EQ.'SUBS'.AND.IHARG2(J).EQ.'ET  ') GO TO 2110
      IF(IHARG(J).EQ.'EXCE'.AND.IHARG2(J).EQ.'PT  ') GO TO 2110
      IF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    ') GO TO 2120
 2100 CONTINUE
      GO TO 2190
 2110 CONTINUE
      ICASEQ='SUBS'
      ILOCQ=J1
      GO TO 2190
 2120 CONTINUE
      ICASEQ='FOR'
      ILOCQ=J1
      GO TO 2190
 2190 CONTINUE
      IF(IBUGG3.EQ.'OFF')GO TO 2195
      WRITE(ICOUT,2191)NUMARG,ILOCQ
 2191 FORMAT('NUMARG,ILOCQ = ',2I8)
      CALL DPWRST('XXX','BUG ')
 2195 CONTINUE
!
!               **********************************
!               **  STEP 22--                   **
!               **  DETERMINE WHICH VARIABLES   **
!               **  ARE TO BE GROUPED TOGETHER  **
!               **********************************
!
      ISTEPN='22'
      IF(IBUGG3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      L=NPLOTP
!
      NEWSET=0
      DO 2200 J=1,NUMVS
      JM1=J-1
      IF(J.EQ.1)KSTART=1
      IF(J.GE.2)KSTART=IVSLOC(JM1)+2
      KSTOP=IVSLOC(J)-1
      IVS=IVSLOC(J)
!
      IVSP1=IVS+1
      DO 2210 K=KSTART,KSTOP
      NEWSET=NEWSET+1
!
      IHVERT=IHARG(K)
      IHVER2=IHARG2(K)
      IHWUSE='V'
      MESSAG='YES'
      CALL CHECKN(IHVERT,IHVER2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      IVAV=IVALUE(ILOCV)
      NLOCAL=IN(ILOCV)
!
      IHHOR=IHARG(IVSP1)
      IHHOR2=IHARG2(IVSP1)
      IHWUSE='V'
      MESSAG='YES'
      CALL CHECKN(IHHOR,IHHOR2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCH,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      IHAV=IVALUE(ILOCH)
!
      ISETV=NEWSET
!
      IF(IAND1.EQ.'NO')GO TO 2280
      IF(NPLOTP.LE.0)GO TO 2280
      D1MAX=D(1)
      DO 2220 I=1,NPLOTP
      IF(D(I).GT.D1MAX)D1MAX=D(I)
 2220 CONTINUE
      D2MIN=1.0
      IF(IAND1.EQ.'YES')DEL=D1MAX-D2MIN+1.0
 2280 CONTINUE
!
      IF(IBUGG3.EQ.'ON')WRITE(ICOUT,2282)IHVERT,ILOCV,IERROR,IVAV,NLOCAL
 2282 FORMAT('IHVERT,ILOCV,IERROR,IVAV,NLOCAL = ',   &
      A4,2X,I8,2X,A4,2X,A4,2X,I8)
      IF(IBUGG3.EQ.'ON')CALL DPWRST('XXX','BUG ')
!
!               *********************************************
!               **  STEP 23--                              **
!               **  FORM THE VECTOR ISUB(.)                **
!               **  DEPENDING ON THE TYPE OF CASE          **
!               **  FOR THE QUALIFIER.                     **
!               **  BRANCH TO THE PROPER CASE.             **
!               *********************************************
!
      ISTEPN='23'
      IF(IBUGG3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICASEQ.EQ.'FULL')GO TO 2310
      IF(ICASEQ.EQ.'SUBS')GO TO 2320
      IF(ICASEQ.EQ.'FOR')GO TO 2330
!CCCC IF(IHARG(J).EQ.'SUBS'.AND.IHARG2(J).EQ.'ET  ') GO TO 2320
!CCCC IF(IHARG(J).EQ.'EXCE'.AND.IHARG2(J).EQ.'PT  ') GO TO 2320
!CCCC IF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    ') GO TO 2330
!
 2310 CONTINUE
      DO 2315 I=1,NLOCAL
      ISUB(I)=1
 2315 CONTINUE
      NQ=NLOCAL
      GO TO 2350
!
 2320 CONTINUE
      NIOLD=NLOCAL
      CALL DPSUBS(NIOLD,ILOCS,NS,IBUGQ,IERRO4)
      NQ=NIOLD
      GO TO 2350
!
 2330 CONTINUE
      NIOLD=NLOCAL
      CALL DPFOR(NIOLD,NFOR,IROW1,IROWN,   &
      NLOCAL,ILOCS,NS,IBUGQ,IERRO4)
      NQ=NFOR
!CCCC THE FOLLOWING LINE WAS INSERTED MARCH 1988
      IF(NS.GT.NIOLD)NS=NIOLD
      GO TO 2350
!
 2350 CONTINUE
!
      DO 2360 I=1,NLOCAL
      IF(ISUB(I).EQ.0)GO TO 2360
      L=L+1
!
      IF(L.LE.MAXNPP)GO TO 2369
      WRITE(ICOUT,2362)
 2362 FORMAT('***** PLOT FORMATION ERROR IN DPPLO2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2363)
 2363 FORMAT('      THE NUMBER OF PLOT POINTS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2364)MAXNPP
 2364 FORMAT('      HAS JUST EXCEEDED ',I8,' *****')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
 2369 CONTINUE
!
      IJ=MAXN*(IVAV-1)+I
      IF(IVAV.LE.MAXCOL)Y(L)=V(IJ)
      IF(IVAV.EQ.MAXCP1)Y(L)=PRED(I)
      IF(IVAV.EQ.MAXCP2)Y(L)=RES(I)
      IF(IVAV.EQ.MAXCP3)Y(L)=YPLOT(I)
      IF(IVAV.EQ.MAXCP4)Y(L)=XPLOT(I)
      IF(IVAV.EQ.MAXCP5)Y(L)=X2PLOT(I)
      IF(IVAV.EQ.MAXCP6)Y(L)=TAGPLO(I)
      IJ=MAXN*(IHAV-1)+I
      IF(IHAV.LE.MAXCOL)X(L)=V(IJ)
      IF(IHAV.EQ.MAXCP1)X(L)=PRED(I)
      IF(IHAV.EQ.MAXCP2)X(L)=RES(I)
      IF(IHAV.EQ.MAXCP3)Y(L)=YPLOT(I)
      IF(IHAV.EQ.MAXCP4)Y(L)=XPLOT(I)
      IF(IHAV.EQ.MAXCP5)Y(L)=X2PLOT(I)
      IF(IHAV.EQ.MAXCP6)Y(L)=TAGPLO(I)
      IF(IAND1.EQ.'NO')D(L)=ISETV
      IF(IAND1.EQ.'YES')D(L)=ISETV+DEL
 2360 CONTINUE
 2210 CONTINUE
 2200 CONTINUE
      NPLOTP=L
!
      DHOLD=D(1)
      DO 2370 I=1,NPLOTP
      IF(D(I).NE.DHOLD)GO TO 2375
 2370 CONTINUE
      NPLOTV=2
      GO TO 2399
 2375 CONTINUE
      NPLOTV=3
      GO TO 2399
!
 2399 CONTINUE
      GO TO 9000
!
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPLO2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR,IBUGG3,IBUGQ
 9012   FORMAT('IFOUND,IERROR,IBUGG3,IBUGQ = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPLOTV,NPLOTP,NS,MAXNPP,ICASPL,IAND1,IAND2
 9013   FORMAT('NPLOTV,NPLOTP,NS,MAXNPP,ICASPL,IAND1,IAND2 = ',   &
               4I8,2(2X,A4),2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPLO2
      SUBROUTINE DPPLO3(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                        PARAM,IPARN,IPARN2,NUMPAR,   &
                        ITYPEH,IW2HOL,IW22HO,W2HOLD,NWHOLD,   &
                        IFOLOC,   &
                        MAXNPP,IANGLU,IBUGG3,IBUGCO,IBUGEV,IBUGQ,   &
                        ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--FORM A PLOT OF A FUNCTION
!              WHEN HAVE 1 OR MORE    =    ENTERED,
!              THAT IS, WHEN HAVE   PLOT Y = ... FOR X = ...
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--DECEMBER  1977.
!     UPDATED         --JANUARY   1978.
!     UPDATED         --FEBRUARY  1978.
!     UPDATED         --MAY       1978.
!     UPDATED         --JUNE      1978.
!     UPDATED         --JULY      1978.
!     UPDATED         --NOVEMBER  1978.
!     UPDATED         --FEBRUARY  1979.
!     UPDATED         --MARCH     1979.
!     UPDATED         --JULY      1979.
!     UPDATED         --JANUARY   1981.
!     UPDATED         --FEBRUARY  1981.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --OCTOBER   1981.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MARCH     1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --APRIL     1992. FIX   PLOT CONSTANT
!     UPDATED         --MAY       1994. SUPPRESS MESSAGE FOR POINT PLOT
!     UPDATED         --SEPTEMBER 2015. SUPPORT FOR FUNCTION BLOCK
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IAND1
      CHARACTER*4 IAND2
      CHARACTER*4 IPARN
      CHARACTER*4 IPARN2
      CHARACTER*4 ITYPEH
      CHARACTER*4 IW2HOL
      CHARACTER*4 IW22HO
      CHARACTER*4 IANGLU
      CHARACTER*4 IBUGG3
      CHARACTER*4 IBUGCO
      CHARACTER*4 IBUGEV
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IFTEXP
      CHARACTER*4 IFTORD
      CHARACTER*4 IFORSW
!
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 IWD1
      CHARACTER*4 IWD12
      CHARACTER*4 IWD2
      CHARACTER*4 IWD22
      CHARACTER*4 IVERTI
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 IHPARN
      CHARACTER*4 IHPAR2
      CHARACTER*4 IVDU11
      CHARACTER*4 IVDU12
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION PARAM(*)
      DIMENSION IPARN(*)
      DIMENSION IPARN2(*)
!
      DIMENSION ITYPEH(*)
      DIMENSION IW2HOL(*)
      DIMENSION IW22HO(*)
      DIMENSION W2HOLD(*)
!
      DIMENSION IFOLOC(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOFB.INC'
!
      CHARACTER*8 IFBNAM
      CHARACTER*8 IFBANS
      CHARACTER*4 IFEESV
      COMMON/IFEED/IFEESV
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPPL'
      ISUBN2='O3  '
      IFTORD='DATA'
      IFTEXP='+'
      IFORSW='E'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
      LOCDU1=0
      I2=0
      DEL=0.0
      NUMIT=1
      N2F=0
      IP7=0
!
!
!     CHECK IF FIRST ARGUMENT IS A FUNCTION BLOCK NAME
!
      IFLGFB=0
      IFBNAM=' '
      IFBANS=' '
      IF(IHARG(1).EQ.IFBNA1(1:4) .AND. IHARG2(1).EQ.IFBNA1(5:8))THEN
        IFLGFB=1
        IFBNAM=IFBNA1
        IFBANS=IFBAN1
      ELSEIF(IHARG(1).EQ.IFBNA2(1:4) .AND. IHARG2(1).EQ.IFBNA2(5:8))THEN
        IFLGFB=2
        IFBNAM=IFBNA2
        IFBANS=IFBAN2
      ELSEIF(IHARG(1).EQ.IFBNA3(1:4) .AND. IHARG2(1).EQ.IFBNA3(5:8))THEN
        IFLGFB=3
        IFBNAM=IFBNA3
        IFBANS=IFBAN3
      ENDIF
!
!               *******************************************************
!               **  TREAT THE CASE WHEN HAVE 1 OR MORE '=' ENTERED   **
!               **  THAT IS, TREAT THE PLOT Y = ... FOR X = ... CASE **
!               *******************************************************
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PLO3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPLO3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)NPLOTV,NPLOTP,NS,MAXNPP,IFOLOC(1)
   52   FORMAT('NPLOTV,NPLOTP,NS,MAXNPP,IFOLOC(1) = ',4I8,G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASPL,IAND1,IAND2,IFOUND,IERROR
   53   FORMAT('ICASPL,IAND1,IAND2,IFOUND,IERROR = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)IANGLU,IBUGG3,IBUGCO,IBUGEV,IBUGQ
   54   FORMAT('IANGLU,IBUGG3,IBUGCO,IBUGEV,IBUGQ = ',   &
               4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *******************************************
!               **  STEP 2--                             **
!               **  DETERMINE THE MAX TRACE DESIGNATION  **
!               **  (A NUMBER) AS CONTAINED              **
!               **  IN THE VECTOR D(.).                  **
!               *******************************************
!
      ISTEPN='2'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PLO3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IAND1.EQ.'YES' .AND. NPLOTP.GT.0)THEN
        D1MAX=D(1)
        DO 110 I=1,NPLOTP
          IF(D(I).GT.D1MAX)D1MAX=D(I)
  110   CONTINUE
        D2MIN=1.0
        IF(IAND1.EQ.'YES')DEL=D1MAX-D2MIN+1.0
      ENDIF
!
!               ************************************************
!               **  STEP 3--                                  **
!               **  DETERMINE THE NAME OF THE DUMMY VARIABLE  **
!               **  (IT NEVER GETS STORED PERMANENTLY)        **
!               **  IMMEDIATELY FOLLOWING 'FOR'.              **
!               ************************************************
!
      ISTEPN='3'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PLO3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 3100 J=1,NUMARG
        J2=J
        IF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    ')GO TO 3110
 3100 CONTINUE
      IBRAN=3101
      WRITE(ICOUT,3101)
 3101 FORMAT('***** ERROR IN DPPLO3--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3102)
 3102 FORMAT('      THE STRING    FOR    NOT FOUND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3103)
 3103 FORMAT('      EVEN THOUGH THE STRING    =    WAS FOUND.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3104)
 3104 FORMAT('      THE ENTIRE COMMAND LINE WAS AS FOLLOWS--')
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)THEN
        WRITE(ICOUT,3105)(IANS(I),I=1,MIN(100,IWIDTH))
 3105   FORMAT('      ',100A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      IERROR='YES'
      GO TO 9000
!
 3110 CONTINUE
      IFOLP0=J2
!
      IF(IFOLP0.GE.NUMARG)THEN
        WRITE(ICOUT,3101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3122)
 3122   FORMAT('      THE WORD    FOR    WAS THE FINAL WORD ON THE ',   &
               'COMMAND LINE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3124)
 3124   FORMAT('      THE WORD    FOR    SHOULD HAVE BEEN FOLLOWED ',   &
               'BY 5    WORDS   --')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3126)
 3126   FORMAT('      1) A DUMMY VARIABLE NAME;')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3127)
 3127   FORMAT('      2) AN EQUAL SIGN;')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3128)
 3128   FORMAT('      3) ONE LIMIT (LOWER OR UPPER) FOR THE DUMMY ',   &
               'VARIABLE;')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3129)
 3129   FORMAT('      4) THE INCREMENT FOR THE DUMMY VARIABLE;')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3130)
 3130   FORMAT('      5) THE OTHER LIMIT (UPPER OR LOWER) ',   &
               'FOR THE DUMMY VARIABLE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3104)
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,3105)(IANS(I),I=1,MIN(100,IWIDTH))
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IFOLP1=IFOLP0+1
      IVDU11=IHARG(IFOLP1)
      IVDU12=IHARG2(IFOLP1)
!
!               *******************************************
!               **  STEP 4--                             **
!               **  EVALUATE THE FUNCTION OVER           **
!               **  THE VARIOUS POINTS IN THE INTERVAL.  **
!               *******************************************
!
      ISTEPN='4'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PLO3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMAM1=NUMARG-1
      NUMAM2=NUMARG-2
      NUMAM3=NUMARG-3
!
      ILOCA=NUMAM2
      IF(IHARG(NUMARG).EQ.'AND '.AND.IHARG2(NUMARG).EQ.'    ')   &
      ILOCA=NUMAM3
      IF(IARGT(ILOCA).EQ.'NUMB')THEN
        START=ARG(ILOCA)
      ELSEIF(IARGT(ILOCA).EQ.'WORD')THEN
        IH=IHARG(ILOCA)
        IH2=IHARG2(ILOCA)
        IHWUSE='P'
        MESSAG='YES'
        CALL CHECKN(IH,IH2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOC,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        START=VALUE(ILOC)
      ELSE
        GO TO 3270
      ENDIF
!
      ILOCA=NUMAM1
      IF(IHARG(NUMARG).EQ.'AND '.AND.IHARG2(NUMARG).EQ.'    ')   &
         ILOCA=NUMAM2
      IF(IARGT(ILOCA).EQ.'NUMB')THEN
        AINC=ARG(ILOCA)
      ELSEIF(IARGT(ILOCA).EQ.'WORD')THEN
        IH=IHARG(ILOCA)
        IH2=IHARG2(ILOCA)
        IHWUSE='P'
        MESSAG='YES'
        CALL CHECKN(IH,IH2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOC,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        AINC=VALUE(ILOC)
      ELSE
        GO TO 3270
      ENDIF
!
      ILOCA=NUMARG
      IF(IHARG(NUMARG).EQ.'AND '.AND.IHARG2(NUMARG).EQ.'    ')   &
        ILOCA=NUMAM1
      IF(IARGT(ILOCA).EQ.'NUMB')THEN
        STOP=ARG(ILOCA)
      ELSEIF(IARGT(ILOCA).EQ.'WORD')THEN
        IH=IHARG(ILOCA)
        IH2=IHARG2(ILOCA)
        IHWUSE='P'
        MESSAG='YES'
        CALL CHECKN(IH,IH2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOC,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        STOP=VALUE(ILOC)
      ELSE
        GO TO 3270
      ENDIF
!
      IF(START.NE.STOP.AND.AINC.NE.0.0)THEN
!
!       *****THE FOLLOWING CORRECTIVE LINE ADDED AUGUST 1983*****
!
        IF(START.EQ.STOP)AINC=0.0
        IF(START.LT.STOP.AND.AINC.LT.0.0)AINC=-AINC
        IF(START.GT.STOP.AND.AINC.GT.0.0)AINC=-AINC
!
!       *****THE FOLLOWING 2 CORRECTIVE LINES ADDED AUGUST 1983*****
!
        IF(AINC.EQ.0.0)THEN
          NUMIT=1
        ELSEIF(AINC.NE.0.0)THEN
          NUMIT=INT((STOP-START)/AINC + 0.1)
          IF(NUMIT.LT.0)NUMIT=-NUMIT
        ENDIF
        NUMIT=NUMIT+1
      ELSE
        NUMIT=1
      ENDIF
!
!               ******************************************************
!               **  STEP 5--                                        **
!               **  EXTRACT THE FUNCTIONAL                          **
!               **  EXPRESSION FROM THE INPUT COMMAND LINE.         **
!               ******************************************************
!
      ISTEPN='5'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PLO3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      MAXN2=MAXCHF
      MAXN3=MAXCHF
      MAXN4=MAXCHF
!
      IF(IHARG(2).EQ.'=   '.AND.IHARG2(2).EQ.'    ')THEN
        IWD1='=   '
        IWD12='    '
      ELSE
        IWD1='PLOT'
        IWD12='    '
      ENDIF
!
      IWD2='FOR'
      IWD22=' '
      CALL DPEXST(IANS,IWIDTH,IWD1,IWD12,IWD2,IWD22,MAXN2,   &
                  IFUNC2,N2F,IBUGG3,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      IF(IFOUND.EQ.'NO')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3372)
 3372   FORMAT('      INVALID COMMAND FORM FOR FUNCTION PLOTTING.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3373)
 3373   FORMAT('      GENERAL FORM--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3374)
 3374   FORMAT('      PLOT ... = ...  FOR ... = ... ...')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3104)
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,3105)(IANS(I),I=1,IWIDTH)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               *********************************************************
!               **  STEP 5.1--                                         **
!               **  FIRST CHECK TO SEE IF HAVE THE VERTICAL LINES CASE;**
!               **  THEN EXTRACT THE UNDERLYING FUNCTION FROM          **
!               **  FUNCTION DEFINITIONS.                              **
!               *********************************************************
!
      ISTEPN='5.1'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PLO3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IVERTI='NO'
      IVERT1=0
      IVERT2=0
      DO 3380 I=1,NUMARG
        IF(IHARG(I).EQ.'VERT'.AND.IHARG2(I).EQ.'ICAL')THEN
          IF(IP7.LE.N2F)THEN
            IF(IFUNC2(I)  .EQ.'V' .AND. IFUNC2(I+1).EQ.'E' .AND.   &
               IFUNC2(I+2).EQ.'R' .AND. IFUNC2(I+3).EQ.'T' .AND.   &
               IFUNC2(I+4).EQ.'I' .AND. IFUNC2(I+5).EQ.'C' .AND.   &
               IFUNC2(I+6).EQ.'A' .AND. IFUNC2(I+7).EQ.'L')THEN
              IVERTI='YES'
              IVERT1=I
              IVERT2=I+7
              IF(I+8.LE.N2F .AND. IFUNC2(I+8).EQ.' ')THEN
                IVERT2=I+8
              ELSEIF(I+10.LE.N2F)THEN
                IF(IFUNC2(I+8).EQ.'L'.AND.IFUNC2(I+9).EQ.'Y'.AND.   &
                   IFUNC2(I+10).EQ.' ')IVERT2=I+10
              ENDIF
            ENDIF
          ELSE
            GO TO 3399
          ENDIF
!
          IC=0
          DO 3391 II=1,N2F
            IF(IVERT1.LE.II.AND.II.LE.IVERT2)GO TO 3391
            IC=IC+1
            IFUNC2(IC)=IFUNC2(I)
 3391     CONTINUE
          N2FOLD=N2F
          N2FNEW=IC
!
          N2FNP1=N2FNEW+1
          IF(N2FNP1.LE.N2FOLD)THEN
            DO 3392 IC=N2FNP1,N2FOLD
              IFUNC2(IC)=' '
 3392       CONTINUE
          ENDIF
          N2F=N2FNEW
          GO TO 3399
        ENDIF
 3380 CONTINUE
 3399 CONTINUE
!
      IF(IFLGFB.LE.0)THEN
        CALL DPEXFU(IFUNC2,N2F,IHNAME,IHNAM2,IUSE,IVSTAR,IVSTOP,   &
                    NUMNAM,IANS,IWIDTH,IFUNC,NUMCHF,MAXCHF,IFUNC3,   &
                    N3F,MAXN3,   &
                    IBUGG3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
!               **********************************************************
!               **  STEP 6--                                            **
!               **  MAKE A NON-CALCULATING PASS AT THE FUNCTION         **
!               **  SO AS TO EXTRACT ALL PARAMETER AND VARIABLE NAMES.  **
!               **********************************************************
!
        ISTEPN='6'
        IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PLO3')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IPASS=1
        CALL COMPIM(IFUNC3,N3F,IPASS,PARAM,IPARN,IPARN2,NUMPV,   &
                    IANGLU,ITYPEH,IW2HOL,IW22HO,W2HOLD,NWHOLD,AJUNK,   &
                    IBUGCO,IBUGEV,IERROR)
!
        IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PLO3')THEN
          WRITE(ICOUT,3411)NUMPV,IPARN(1),IPARN2(1),PARAM(1)
 3411     FORMAT('NUMPV,IPARN(1),IPARN2(1),PARAM(1) = ',   &
               I8,2X,A4,2X,A4,E15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(IERROR.EQ.'YES')GO TO 9000
!
!               ***********************************************
!               **  STEP 7--                                 **
!               **  CHECK THAT ALL PARAMETERS                **
!               **  IN THE FUNCTION ARE ALREADY PRESENT      **
!               **  IN THE AVAILABLE NAME LIST IHNAME(.).    **
!               **  ALSO CHECK THAT THE VARIABLE NAME        **
!               **  THAT FOLLOWS FOR (THAT IS, THE DUMMY     **
!               **  VARIABLE) IS IN THE FUNCTION.            **
!               ***********************************************
!
        ISTEPN='7'
        IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PLO3')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IP=0
        IV=0
        IF(NUMPV.GE.1)THEN
          DO 3600 J=1,NUMPV
            IHPARN=IPARN(J)
            IHPAR2=IPARN2(J)
            IF(IHPARN.EQ.IVDU11.AND.IHPAR2.EQ.IVDU12)THEN
              IV=IV+1
              LOCDU1=J
            ELSE
              IHWUSE='P'
              MESSAG='YES'
              CALL CHECKN(IHPARN,IHPAR2,IHWUSE,   &
                          IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,   &
                          NUMNAM,MAXNAM,   &
                          ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
              IF(IERROR.EQ.'YES')GO TO 9000
              IP=IP+1
              PARAM(J)=VALUE(ILOCP)
            ENDIF
 3600     CONTINUE
        ENDIF
!
!CCCC   THE FOLLOWING 5 LINES WERE ADDED   APRIL 1992 (JJF)
        IF(LOCDU1.LE.0)THEN
           IV=IV+1
           NUMPV=NUMPV+1
           LOCDU1=NUMPV
        ENDIF
        NUMPAR=IP
        NUMVAR=IV
!
      ENDIF
!
!               ******************************
!               **  STEP 8--                **
!               **  EVALUATE THE FUNCTION.  **
!               ******************************
!
      ISTEPN='8'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PLO3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IPASS=2
      L=NPLOTP
      L2=L
      DO 3800 I=1,NUMIT
        I2=I
        AI=I
        RESULT=START+(AI-1.0)*AINC
!
        IF(I.GT.1)THEN
          IF((START.LT.STOP.AND.RESULT.GT.STOP) .OR.   &
            (START.GT.STOP.AND.RESULT.LT.STOP))THEN
            N2=I2-1
            GO TO 3889
          ENDIF
        ENDIF
        L2=L2+1
!
        IF(L2.GT.MAXNPP)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,3101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,3822)MAXNPP
 3822     FORMAT('      THE NUMBER OF PLOT POINTS HAS JUST EXCEEDED ',   &
                 I8)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        XTEMP=RESULT
!
        IF(IFLGFB.LE.0)THEN
          PARAM(LOCDU1)=XTEMP
          CALL COMPIM(IFUNC3,N3F,IPASS,PARAM,IPARN,IPARN2,NUMPV,   &
                      IANGLU,ITYPEH,IW2HOL,IW22HO,W2HOLD,NWHOLD,YTEMP,   &
                      IBUGCO,IBUGEV,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
        ELSE
!
!         FUNCTION BLOCK CASE:
!
!            STEP 1: COMPUTE FUNCTION BLOCK (BUT FIRST SET CURRENT
!                    VALUE OF DESIRED PARAMETER)
!
          IFEESV=IFEEDB
          IFEEDB='OFF'
!
          IF(IHARG(1).EQ.IFBNA1(1:4) .AND. IHARG2(1).EQ.IFBNA1(5:8))THEN
            IH=IFBPL1(1)(1:4)
            IH2=IFBPL1(1)(5:8)
          ELSEIF(IHARG(1).EQ.IFBNA2(1:4) .AND.   &
                 IHARG2(1).EQ.IFBNA2(5:8))THEN
            IH=IFBPL2(1)(1:4)
            IH2=IFBPL2(1)(5:8)
          ELSEIF(IHARG(1).EQ.IFBNA3(1:4) .AND.   &
                 IHARG2(1).EQ.IFBNA3(5:8))THEN
            IH=IFBPL3(1)(1:4)
            IH2=IFBPL3(1)(5:8)
          ENDIF
!
          DO 3905 II=1,NUMNAM
            IF(IH.EQ.IHNAME(II) .AND. IH2.EQ.IHNAM2(II) .AND.   &
               IUSE(II).EQ.'P')THEN
              VALUE(II)=XTEMP
              IVALUE(II)=INT(XTEMP+0.5)
              GO TO 3909
            ENDIF
 3905     CONTINUE
!
!         PARAMETER NAME NOT FOUND IN CURRENT LIST, SO NEED TO ADD
!         TO NAME LIST
!
          IF(NUMNAM.LT.MAXNAM)THEN
            NUMNAM=NUMNAM+1
            IHNAME(NUMNAM)=IH
            IHNAM2(NUMNAM)=IH2
            IUSE(NUMNAM)='P'
            VALUE(NUMNAM)=XTEMP
            IVALUE(NUMNAM)=INT(XTEMP+ 0.5)
          ELSE
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,3101)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,3907)
 3907       FORMAT('      MAXIMUM NUMBER OF NAMES EXCEEDED.')
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
 3909     CONTINUE
!
          CALL DPFBEX(IFBNAM,IANGLU,ISEED,IFTEXP,IFTORD,IFORSW,   &
                      IBUGG3,IBUGG3,IBUGCO,IBUGEV,IBUGEV,   &
                      ISUBRO,IFOUND,IERROR)
          IFEEDB=IFEESV
          IF(IERROR.EQ.'YES')GO TO 9000
!
!            STEP 2: RETRIEVE RESPONSE
!
          DO 3920 II=1,NUMNAM
            IF(IFBANS(1:4).EQ.IHNAME(II) .AND.   &
               IFBANS(5:8).EQ.IHNAM2(II))THEN
              IF(IUSE(II).EQ.'P')THEN
                YTEMP=VALUE(II)
                GO TO 3929
              ELSEIF(IUSE(II).EQ.'V')THEN
                ICOLR=IVALUE(II)
                IJ=MAXN*(ICOLR-1)+1
                IF(ICOLR.LE.MAXCOL)YTEMP=V(IJ)
                IF(ICOLR.EQ.MAXCP1)YTEMP=PRED(1)
                IF(ICOLR.EQ.MAXCP2)YTEMP=RES(1)
                IF(ICOLR.EQ.MAXCP3)YTEMP=YPLOT(1)
                IF(ICOLR.EQ.MAXCP4)YTEMP=XPLOT(1)
                IF(ICOLR.EQ.MAXCP5)YTEMP=X2PLOT(1)
                IF(ICOLR.EQ.MAXCP6)YTEMP=TAGPLO(1)
                GO TO 3929
              ENDIF
            ENDIF
 3920     CONTINUE
!
!         PARAMETER/VARIABLE NAME NOT FOUND
!
          WRITE(ICOUT,3101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,3921)
 3921     FORMAT('      EXPECTED PARAMETER/VARIABLE NOT FOUND IN NAME ',   &
                 'TABLE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,3923)IFBANS
 3923     FORMAT('      EXPECTED NAME = ',A8)
          CALL DPWRST('XXX','BUG ')
!
 3929     CONTINUE
!
        ENDIF
!
        IF(IVERTI.EQ.'YES')THEN
          HOLD=YTEMP
          YTEMP=XTEMP
          XTEMP=HOLD
        ENDIF
!
        Y(L2)=YTEMP
        X(L2)=XTEMP
        IF(IAND1.EQ.'NO')D(L2)=1.0
        IF(IAND1.EQ.'YES')D(L2)=1.0+DEL
 3800 CONTINUE
      N2=I2
!
 3889 CONTINUE
      L=L2
      NPLOTP=L
!
!               *****************************
!               **  STEP 9--               **
!               **  DETERMINE THE NUMBER   **
!               **  OF PLOT VARIABLES.     **
!               **  STORE THIS IN NPLOTV.  **
!               *****************************
!
      ISTEPN='9'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PLO3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NPLOTV=2
      DHOLD=D(1)
      DO 3830 I=1,NPLOTP
        IF(D(I).NE.DHOLD)THEN
          NPLOTV=3
          GO TO 3890
        ENDIF
 3830 CONTINUE
 3890 CONTINUE
      GO TO 9000
!
!               *****************************
!               **  STEP 10--              **
!               **  ERROR SECTION          **
!               *****************************
!
 3270 CONTINUE
      WRITE(ICOUT,3271)
 3271 FORMAT('***** INTERNAL ERROR IN DPPLO3--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3272)
 3272 FORMAT('      AN ARGUMENT TYPE WHICH SHOULD BE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3273)
 3273 FORMAT('      EITHER A NUMBER OR A WORD, IS NEITHER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3274)IHARG(ILOCA),IHARG2(ILOCA)
 3274 FORMAT('      ARGUMENT                  = ',A4,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3275)ILOCA
 3275 FORMAT('      LOCATION IN ARGUMENT LIST = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3276)IARGT(ILOCA)
 3276 FORMAT('      ARGUMENT TYPE             = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3104)
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)THEN
        WRITE(ICOUT,3105)(IANS(I),I=1,IWIDTH)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      IERROR='YES'
      GO TO 9000
!
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PLO3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPLO3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR
 9012   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPLOTV,NPLOTP,NS,MAXNPP,ICASPL,IAND1,IAND2
 9013   FORMAT('NPLOTV,NPLOTP,NS,MAXNPP,ICASPL,IAND1,IAND2 = ',   &
               4I8,3(2X,A4))
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPLO3
      SUBROUTINE DPPLOT(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                        IANGLU,MAXNPP,   &
                        IBUGG2,IBUGG3,IBUGCO,IBUGEV,IBUGQ,ISUBRO,   &
                        IFOUND,IERROR)
!
!     PURPOSE--FORM A Y PLOT, A Y VS. X PLOT, A SUBSET PLOT,
!              AND OTHER SIMILAR TYPE PLOTS.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--DECEMBER  1977.
!     UPDATED         --JANUARY   1978.
!     UPDATED         --FEBRUARY  1978.
!     UPDATED         --MAY       1978.
!     UPDATED         --JUNE      1978.
!     UPDATED         --JULY      1978.
!     UPDATED         --NOVEMBER  1978.
!     UPDATED         --FEBRUARY  1979.
!     UPDATED         --MARCH     1979.
!     UPDATED         --JULY      1979.
!     UPDATED         --JANUARY   1981.
!     UPDATED         --MARCH     1981.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --APRIL     1992. FIX PLOT WITH NO ARGS
!     UPDATED         --JUNE      2022. FIX BUG WHEN HAVE 2 OR MORE
!                                       SUBSET CLAUSES WITH "="
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IAND1
      CHARACTER*4 IAND2
      CHARACTER*4 IANGLU
      CHARACTER*4 IBUGG2
      CHARACTER*4 IBUGG3
      CHARACTER*4 IBUGCO
      CHARACTER*4 IBUGEV
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IPARN
      CHARACTER*4 IPARN2
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
!     ***** THE FOLLOWING 4 DIMENSIONS RAISED FROM 150 TO 225 AUGUST 1983 *****
!     ***** THE FOLLOWING 4 DIMENSIONS RAISED FROM 225 TO 1000 AUGUST 1986 *****
!CCCC DIMENSION ITYPEH(225)
!CCCC DIMENSION IW2HOL(225)
!CCCC DIMENSION IW22HO(225)
!CCCC DIMENSION W2HOLD(225)
      CHARACTER*4 ITYPEH(1000)
      CHARACTER*4 IW2HOL(1000)
      CHARACTER*4 IW22HO(1000)
      DIMENSION W2HOLD(1000)
!
      DIMENSION PARAM(100)
      DIMENSION IPARN(100)
      DIMENSION IPARN2(100)
!
      DIMENSION IVSLOC(100)
      DIMENSION IEQLOC(100)
      DIMENSION IFOLOC(100)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      ISUBN1='DPPL'
      ISUBN2='OT  '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!     ***** THE FOLLOWING 6 LINES INSERTED AUGUST 1983 *****
!CCCC DO40I=1,225
      DO 40 I=1,1000
        ITYPEH(I)='    '
        IW2HOL(I)='    '
        IW22HO(I)='    '
        W2HOLD(I)=0.0
   40 CONTINUE
!
      DO 45 I=1,100
        IVSLOC(I)=-1
        IEQLOC(I)=-1
        IFOLOC(I)=-1
   45 CONTINUE
!
!               ***************************
!               **  TREAT THE PLOT CASE  **
!               ***************************
!
      IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'PLOT')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPLOT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)NPLOTV,NPLOTP,NS,MAXNPP
   52   FORMAT('NPLOTV,NPLOTP,NS,MAXNPP = ',4I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASPL,IAND1,IAND2,IFOUND,IERROR
   53   FORMAT('ICASPL,IAND1,IAND2,IFOUND,IERROR = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)IANGLU,IBUGG2,IBUGG3,IBUGCO,IBUGEV,IBUGQ
   54   FORMAT('IANGLU,IBUGG2,IBUGG3,IBUGCO,IBUGEV,IBUGQ = ',   &
               5(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *******************************************************
!               **  STEP 1--                                         **
!               **  CHECK FOR THE PROPER NUMBER OF INPUT ARGUMENTS.  **
!               *******************************************************
!
      ISTEPN='1'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PLOT')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      MINNA=0
      MAXNA=100
      CALL CHECKA(NUMARG,MINNA,MAXNA,IANS,IWIDTH,ISUBN1,ISUBN2,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               *******************************************
!               **  STEP 2--                             **
!               **  DETERMINE IF HAD OR HAVE THE 'AND'   **
!               **  CONTINUATION CASE.                   **
!               **  IF THE PREVIOUS PLOT COMMAND LINE    **
!               **  HAD AN 'AND' CONTINUATION,           **
!               **  OR IF THE PRESENT PLOT COMMAND LINE  **
!               **  HAS AN 'AND' CONTINUATION,           **
!               **  THEN SET SOME FLAG VARIABLES.        **
!               *******************************************
!
      ISTEPN='2'
      IF(IBUGG2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IAND1.EQ.'NO')NPLOTV=0
      IF(IAND1.EQ.'NO')NPLOTP=0
      IAND2='NO'
      IF(NUMARG.LE.0)IAND2='NO'
!CCCC THE FOLLOWING LINE WAS FIXED   APRIL 1992
!CCCC IF(NUMARG.GE.1.AND.IHARG(NUMARG).EQ.'AND')IAND2='YES'
      IF(NUMARG.GE.1)THEN
         IF(IHARG(NUMARG).EQ.'AND')IAND2='YES'
      ENDIF
      L=NPLOTP
!
!               ***************************************
!               **  STEP 3--                         **
!               **  DETERMINE THE TYPE OF PLOT CASE  **
!               **  (FOR THIS COMMAND LINE ONLY)--   **
!               **       1)  PLOT                    **
!               **       2)  PLOT ... VERSUS         **
!               **       3)  PLOT ... FOR X =        **
!               **       4)  OTHER THAN THE ABOVE.   **
!               ***************************************
!
      ISTEPN='3'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PLOT')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.LE.0)THEN
        ICASPL='NODA'
        IFOUND='YES'
        IERROR='NO'
        NS=0
        GO TO 9000
      ENDIF
!
      ICASPL='NOVE'
!
      NUMEQ=0
      NUMFO=0
      NUMVS=0
      NUMDV=0
      DO 811 J=1,NUMARG
        J2=J
        IF(IHARG(J).EQ.'=')THEN
          NUMEQ=NUMEQ+1
          IEQLOC(NUMEQ)=J2
        ELSEIF(IHARG(J).EQ.'VS' .OR. IHARG(J).EQ.'VS. ' .OR.   &
              (IHARG(J).EQ.'VERS' .AND. IHARG2(J).EQ.'US  '))THEN
          NUMVS=NUMVS+1
          IVSLOC(NUMVS)=J2
        ELSEIF(IHARG(J).EQ.'FOR')THEN
          JP1=J+1
          IF(JP1.GT.NUMARG)GO TO 837
          IF(IHARG(JP1).EQ.'I   '.AND.IHARG2(JP1).EQ.'    ')GO TO 837
          IF(IHARG(JP1).EQ.'ROW '.AND.IHARG2(JP1).EQ.'    ')GO TO 837
          NUMDV=NUMDV+1
  837     CONTINUE
          NUMFO=NUMFO+1
          IFOLOC(NUMFO)=J2
        ENDIF
  811 CONTINUE
!
!     2022/06: BUG WHEN TWO OR MORE SUBSET CLAUSES HAVE "="
!              WITH NO FOR CLAUSE
!
      IF(NUMEQ.EQ.0)ICASPL='NOVE'
      IF(NUMEQ.EQ.1.AND.NUMFO.EQ.1.AND.NUMDV.LE.0)ICASPL='NOVE'
      IF(NUMEQ.EQ.1.AND.NUMFO.EQ.1.AND.NUMDV.GE.1)ICASPL='EFE'
      IF(NUMEQ.EQ.2.AND.NUMFO.EQ.2.AND.NUMDV.GE.1)ICASPL='EFE'
      IF(NUMEQ.GE.2)ICASPL='EFE'
      IF(ICASPL.EQ.'EFE' .AND. NUMFO.EQ.0)ICASPL='NOVE'
      IF(NUMVS.GE.1)ICASPL='VS'
!
!               ******************************************
!               **  STEP 4--                            **
!               **  BRANCH ACCORDING TO THE PLOT CASE.  **
!               ******************************************
!
      ISTEPN='4'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PLOT')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IFOUND='YES'
!
      IF(ICASPL.EQ.'NOVE')THEN
        CALL DPPLO1(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                    MAXNPP,   &
                    IBUGG3,IBUGQ,IFOUND,IERROR)
      ELSEIF(ICASPL.EQ.'VS')THEN
        CALL DPPLO2(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                    IVSLOC,NUMVS,   &
                    MAXNPP,   &
                    IBUGG3,IBUGQ,IFOUND,IERROR)
      ELSEIF(ICASPL.EQ.'EFE')THEN
        CALL DPPLO3(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                    PARAM,IPARN,IPARN2,NUMPAR,   &
                    ITYPEH,IW2HOL,IW22HO,W2HOLD,NWHOLD,   &
                    IFOLOC,   &
                    MAXNPP,IANGLU,IBUGG3,IBUGCO,IBUGEV,IBUGQ,   &
                    ISUBRO,IFOUND,IERROR)
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'PLOT')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF DPPLOT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR
 9012   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2
 9013   FORMAT('NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2 = ',   &
               3I8,3(2X,A4))
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9020)
 9020   FORMAT('I,Y(.),X(.),D(.),ISUB(.)--')
        CALL DPWRST('XXX','BUG ')
        DO 9021 I=1,NPLOTP
          WRITE(ICOUT,9022)I,Y(I),X(I),D(I),ISUB(I)
 9022     FORMAT(I8,3G15.7,I8)
          CALL DPWRST('XXX','BUG ')
 9021   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPPLOT
      SUBROUTINE DPPLSY(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                        IBUGG2,IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--GENERATE A SYMBOL PLOT--
!              THE COMMAND HAS THE FOLLOWING FORMAT:
!                  SYMBOL PLOT Y X <SIZE> <SYMBOL> <COLOR> <FILL>
!              ONLY THE Y VARIABLE IS REQUIRED.  IF ONLY Y AND X ARE
!              GIVEN, THIS COMMAND IS SIMILAR TO THE PLOT Y X
!              COMMAND.  IF A SIZE VARIABLE IS GIVEN, THE CHARACTER
!              SIZE OF PLOT CHARACTER WILL BE SCALED ACCORDING TO THAT
!              VARIABLE.  THE SYMBOL VARIABLE IDENTIFIES THE SYMBOL
!              TO USE (SPECIFY AS AN INDEX BETWEEN 1 AND 100, USE THE
!              CORRESPONDING VALUE FROM THE CHARACTER ...  COMMAND).
!              THE COLOR COMMAND IDENTIFIES THE COLOR FOR THE PLOT
!              CHARACTER (AGAIN AN INDEX FROM 1 TO 100, USE CHAR COLOR
!              COMMAND SETTINGS).  THE FILL VARIABLE IDENTIFIES
!              WHETHER THE PLOT SYMBOL WILL BE FILLED (0 FOR NO FILL
!              ANYTHING ELSE TO FILL WITH SOLID PATTERN).
!                   PLSYOR ARROW <FIXED/VARIABLE>
!     EXAMPLE--SYMBOL PLOT Y X  SIZE SYMBOL COLOR FILL
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--92/8
!     ORIGINAL VERSION--AUGUST    1992.
!     UPDATED         --FEBRUARY  2011. USE DPPARS AND DPPAR5
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IAND1
      CHARACTER*4 IAND2
      CHARACTER*4 IBUGG2
      CHARACTER*4 IBUGG3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
!
      DIMENSION Y1(MAXOBV)
      DIMENSION Y2(MAXOBV)
      DIMENSION Y3(MAXOBV)
      DIMENSION Y4(MAXOBV)
      DIMENSION Y5(MAXOBV)
      DIMENSION Y6(MAXOBV)
!CCCC FOLLOWING LINES ADDED JUNE, 1990
      EQUIVALENCE (GARBAG(IGARB1),Y1(1))
      EQUIVALENCE (GARBAG(IGARB2),Y2(1))
      EQUIVALENCE (GARBAG(IGARB3),Y3(1))
      EQUIVALENCE (GARBAG(IGARB4),Y4(1))
      EQUIVALENCE (GARBAG(IGARB5),Y5(1))
      EQUIVALENCE (GARBAG(IGARB6),Y6(1))
!CCCC END CHANGE
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
      IFOUND='NO'
      ISUBN1='DPPL'
      ISUBN2='SY  '
      ICASPL='SYMB'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!               ***********************************
!               **  TREAT THE SYMBOL PLOT CASE   **
!               ***********************************
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PLSY')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPLSY--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGG2,IBUGG3,IBUGQ,ISUBRO
   52   FORMAT('IBUGG2,IBUGG3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASPL,IAND1,IAND2,MAXN,NS
   53   FORMAT('ICASPL,IAND1,IAND2,MAXN,NS = ',3(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***************************
!               **  STEP 1--             **
!               **  EXTRACT THE COMMAND  **
!               ***************************
!
      ISTEPN='11'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PLSY')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'PLOT')THEN
        ILASTC=1
      ELSE
        GO TO 9000
      ENDIF
      CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      IFOUND='YES'
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PLSY')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='SYMBOL PLOT'
      MINNA=1
      MAXNA=100
      MINN2=2
      IFLAGE=1
      IFLAGM=0
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=1
      MAXNVA=6
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PLSY')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I),IVARTY(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I),IVARTY(I) = ',I8,2X,A4,A4,2X,3I8,2X,A4)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
      ICOL=1
      CALL DPPAR5(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                  INAME,IVARN1,IVARN2,IVARTY,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVAR,   &
                  MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                  MAXCP4,MAXCP5,MAXCP6,   &
                  V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                  Y1,Y2,Y3,Y4,Y5,Y6,Y6,NLOCAL,   &
                  IBUGG3,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!
!               *******************************************************
!               **  STEP 8--                                         **
!               **  FORM THE VERTICAL AND HORIZONTAL AXIS            **
!               **  VALUES Y(.) AND X(.) FOR THE PLOT.               **
!               **  DEFINE THE NUMBER OF PLOT POINTS    (NPLOTP).    **
!               **  DEFINE THE NUMBER OF PLOT VARIABLES (NPLOTV).    **
!               *******************************************************
!
      ISTEPN='5'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PLSY')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,5001)NLOCAL,ICASPL
 5001   FORMAT('NLOCAL,ICASPL=',I5,1X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      CALL DPPLS2(Y1,Y2,Y3,Y4,Y5,Y6,NLOCAL,ICASPL,NUMVAR,   &
                  Y,X,D,DSIZE,DSYMB,DCOLOR,DFILL,   &
                  NPLOTP,NPLOTV,IBUGG3,ISUBRO,IERROR)
!
!               *****************
!               **  STEP 9--   **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PLSY')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPLSY--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IFOUND,IERROR
 9013   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)NPLOTV,NPLOTP,NLOCAL,ICASPL,IAND1,IAND2
 9014   FORMAT('NPLOTV,NPLOTP,NLOCAL,ICASPL,IAND1,IAND2 = ',   &
               3I8,2X,2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        IF(NLOCAL.GE.1)THEN
         DO 9042 I=1,NLOCAL
           WRITE(ICOUT,9043)I,Y1(I),Y2(I),Y3(I),Y4(I),Y5(I),Y6(I)
 9043      FORMAT('I,Y1(I),Y2(I),Y3(I),Y4(I)Y5(I),Y(6) = ',I8,6E15.7)
           CALL DPWRST('XXX','BUG ')
 9042    CONTINUE
        ENDIF
        IF(NPLOTP.GE.1)THEN
          DO 9052 I=1,NPLOTP
            WRITE(ICOUT,9053)I,Y(I),X(I),D(I),DSIZE(I),DSYMB(I),   &
                             DCOLOR(I),DFILL(I)
 9053       FORMAT('I,Y(I),X(I),D(I),DSIZE(I),DSYMB(I),DCOLOR(I),',   &
                   'DFILL(I) = ',I8,7F12.5)
            CALL DPWRST('XXX','BUG ')
 9052     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPPLSY
      SUBROUTINE DPPLS2(Y1,Y2,Y3,Y4,Y5,Y6,NZ,ICASPL,NUMV2,   &
      Y,X,D,DSIZE,DSYMB,DCOLOR,DFILL,   &
      N2,NPLOTV,IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--GENERATE A PAIR OF COORDINATE VECTORS
!              THAT WILL DEFINE
!              A SYMBOL PLOT
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--92/8
!     ORIGINAL VERSION--AUGUST    1992.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION Y3(*)
      DIMENSION Y4(*)
      DIMENSION Y5(*)
      DIMENSION Y6(*)
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION D(*)
      DIMENSION DSIZE(*)
      DIMENSION DSYMB(*)
      DIMENSION DCOLOR(*)
      DIMENSION DFILL(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPPL'
      ISUBN2='S2  '
      IERROR='NO'
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(NZ.LT.1)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
   31   FORMAT('***** ERROR IN SYMBOL PLOT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)
   32   FORMAT('      THE NUMBER OF OBSERVATIONS MUST BE AT LEAST 1;')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,34)NZ
   34   FORMAT('      THE NUMBER OF OBSERVATIONS HERE = ',I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PLS2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,71)
   71   FORMAT('***** AT THE BEGINNING OF DPPLS2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,72)ICASPL,NZ,N2,NPLOTV,NUMV2
   72   FORMAT('ICASPL,NZ,N2,NPLOTV,NUMV2 = ',A4,2X,4I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ****************************************
!               **  STEP 1--                          **
!               **  INITIALIZE DSIZE, ETC.            **
!               ****************************************
!
      DO 100 I=1,NZ
        Y(I)=Y1(I)
        D(I)=1.0
        DSIZE(I)=1.0
        DSYMB(I)=1.0
        DCOLOR(I)=1.0
        DFILL(I)=0.0
 100  CONTINUE
!
!               ****************************************
!               **  STEP 2--                          **
!               **  IF NO X, CREATE IT                **
!               ****************************************
!
      IF(NUMV2.LT.2)THEN
        DO 200 I=1,NZ
        X(I)=REAL(I)
 200    CONTINUE
        GO TO 8000
      ELSE
        DO 210 I=1,NZ
        X(I)=Y2(I)
 210    CONTINUE
      ENDIF
!
!               ****************************************
!               **  STEP 3--                          **
!               **  HANDLE THE SIZE VARIABLE          **
!               ****************************************
!
      IF(NUMV2.GE.3)THEN
        AMAXSZ=0.0
        DO 300 I=1,NZ
          ATEMP=ABS(Y3(I))
          IF(ATEMP.GT.AMAXSZ)AMAXSZ=ATEMP
 300    CONTINUE
        DO 310 I=1,NZ
          ATEMP=ABS(Y3(I))/AMAXSZ
          IF(ATEMP.GT.1.0)ATEMP=1.0
          IF(ATEMP.LT.0.05)ATEMP=0.05
          DSIZE(I)=ATEMP
 310    CONTINUE
!
        IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PLS2')THEN
          WRITE(ICOUT,371)
  371     FORMAT('***** AFTER CALCULATING SIZE --')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,372)AMAXSZ
  372     FORMAT('AMAXSZ = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          DO 381 I=1,10
            WRITE(ICOUT,382)I,Y3(I),DSIZE(I)
  382       FORMAT('I,Y3(I),DSIZE(I) = ',I4,E15.7,1X,F8.5)
            CALL DPWRST('XXX','BUG ')
  381     CONTINUE
        ENDIF
!
      ENDIF
!
!               ****************************************
!               **  STEP 4--                          **
!               **  HANDLE THE SYMBOL VARIABLE        **
!               **  SHOULD BE AN INDEX BETWEEN 1 AND  **
!               **  100                               **
!               ****************************************
!
      IF(NUMV2.GE.4)THEN
        DO 400 I=1,NZ
          DSYMB(I)=Y4(I)
          DSYMB(I)=ABS(DSYMB(I))
          IF(DSYMB(I).LT.0.5)DSYMB(I)=1.0
          IF(DSYMB(I).GT.99.5)DSYMB(I)=100.0
 400    CONTINUE
      ENDIF
!
!               ****************************************
!               **  STEP 5--                          **
!               **  HANDLE THE COLOR  VARIABLE        **
!               **  SHOULD BE AN INDEX BETWEEN 1 AND  **
!               **  100                               **
!               ****************************************
!
      IF(NUMV2.GE.5)THEN
        DO 500 I=1,NZ
          DCOLOR(I)=Y5(I)
          DCOLOR(I)=ABS(DCOLOR(I))
          IF(DCOLOR(I).LT.0.5)DCOLOR(I)=1.0
          IF(DCOLOR(I).GT.99.5)DCOLOR(I)=100.0
 500    CONTINUE
      ENDIF
!
!               ****************************************
!               **  STEP 6--                          **
!               **  HANDLE THE FILL   VARIABLE        **
!               **  SHOULD BE 0 FOR NO FILL, ANYTHING **
!               **  ELSE FOR SOLID FILL               **
!               ****************************************
!
      IF(NUMV2.GE.5)THEN
        DO 600 I=1,NZ
          DFILL(I)=Y6(I)
          IF(DFILL(I).GE.-0.5.AND.DFILL(I).LE.0.5)THEN
            DFILL(I)=0.0
          ELSE
            DFILL(I)=1.0
          ENDIF
 600    CONTINUE
      ENDIF
!
 8000 CONTINUE
      N2=NZ
      NPLOTV=3
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PLS2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPLS2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICASPL,IERROR,NZ,N2,NPLOTV
 9012   FORMAT('ICASPL,IERROR,NZ,N2,NPLOTV = ',2(A4,2X),3I8)
        CALL DPWRST('XXX','BUG ')
        IF(NZ.GE.1)THEN
          DO 9021 I=1,NZ
            WRITE(ICOUT,9022)I,Y1(I),Y2(I),Y3(I),Y4(I)
 9022       FORMAT('I,Y1(I),Y2(I),Y3(I) = ',I8,4E12.5)
            CALL DPWRST('XXX','BUG ')
 9021     CONTINUE
        ENDIF
        DO 9035 I=1,N2
          WRITE(ICOUT,9036)I,Y(I),X(I),D(I)
 9036     FORMAT('I,Y(I),X(I),D(I) = ',I8,2E15.7,F9.2)
          CALL DPWRST('XXX','BUG ')
 9035   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPPLS2
      SUBROUTINE DPPMTI(IANS,IANSLC,IWIDTH,IHARG,IHARG2,NUMARG,   &
                        IBUGP2,IFOUND,IERROR)
!
!     PURPOSE--EXTRACT THE STRING TO BE USED AS A TITLE
!              FOR SUBSEQUENT SAVED PIXMAPS;
!     INPUT  ARGUMENTS--IANS   (A  CHARACTER VECTOR)
!                     --IWIDTH
!                     --IHARG  (A  CHARACTER VECTOR)
!                     --IHARG2  (A  CHARACTER VECTOR)
!                     --NUMARG
!     OUTPUT ARGUMENTS--IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--97/4
!     ORIGINAL VERSION--APRIL      1997.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IANS
      CHARACTER*4 IANSLC
      CHARACTER*4 IHARG
      CHARACTER*4 IHARG2
!
      CHARACTER*4 IBUGP2
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IANS(*)
      DIMENSION IANSLC(*)
      DIMENSION IHARG(*)
      DIMENSION IHARG2(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOPM.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(IBUGP2.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGINNING OF DPPMTI--')
        CALL DPWRST('XXX','BUG ')
        DO 60 I=1,NUMARG
          WRITE(ICOUT,61)I,IHARG(I),IHARG2(I)
   61     FORMAT('I,IHARG(I),IHARG2(I) = ',I8,2X,2A4)
          CALL DPWRST('XXX','BUG ')
   60   CONTINUE
      ENDIF
!
!     *****************************************
!     **  STEP 1--                           **
!     **  DETERMINE THE COMMAND              **
!     **  (TITLE) AND ITS LOCATION           **
!     **  ON THE LINE.                       **
!     *****************************************
!
      DO 1000 I=1,IWIDTH
      I2=I
      IP1=I+1
      IP2=I+2
      IP3=I+3
      IP4=I+4
      IP5=I+5
      IP6=I+6
      IF(IANS(I).EQ.'T'.AND.IANS(IP1).EQ.'I'   &
      .AND.IANS(IP2).EQ.'T'.AND.IANS(IP3).EQ.'L'   &
      .AND.IANS(IP4).EQ.'E')   &
      GO TO 100
!
 1000 CONTINUE
      WRITE(ICOUT,1001)
 1001 FORMAT('***** ERROR IN DPPMTI--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1002)
 1002 FORMAT('      NO MATCH FOR COMMAND.')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 800
!
!     **********************************************************
!     **  STEP 2--                                            **
!     **  DEFINE THE START POSITION (ISTART) FOR THE STRING.  **
!     **********************************************************
!
  100 CONTINUE
      ISTART=I2+6
      GO TO 300
!
!     ********************************************************
!     **  STEP 3--                                          **
!     **  DEFINE THE STOP POSITION (ISTOP) FOR THE STRING.  **
!     ********************************************************
!
  300 CONTINUE
      IFOUND='YES'
      ISTOP=0
      IF(ISTART.GT.IWIDTH)GO TO 329
      DO 320 I=ISTART,IWIDTH
      IREV=IWIDTH-I+ISTART
      IF(IANS(IREV).NE.' ')GO TO 325
  320 CONTINUE
      GO TO 329
  325 CONTINUE
      ISTOP=IREV
  329 CONTINUE
!
!     *****************************************
!     **  STEP 4--                           **
!     **  COPY OVER THE STRING OF INTEREST.  **
!     *****************************************
!
      IF(ISTART.GT.ISTOP)GO TO 359
      IF(ISTOP.EQ.0)GO TO 359
      IPXMCM(NUMPXM+1)=' '
      J=0
      DO 350 I=ISTART,ISTOP
      J=J+1
      IPXMCM(NUMPXM+1)(J:J)=IANSLC(I)(1:1)
  350 CONTINUE
      NCTITL=J
      GO TO 800
  359 CONTINUE
!
!     ************************************
!     **  STEP 5--                      **
!     **  TREAT THE EMPTY-STRING CASE.  **
!     ************************************
!
      NCTITL=0
      GO TO 800
!
!     ***************************
!     **  STEP 6--             **
!     **  PRINT OUT A MESSAGE  **
!     ***************************
!
  800 CONTINUE
!
      IF(IFEEDB.EQ.'OFF')GO TO 889
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)
  811 FORMAT('THE TITLE FOR THE NEXT SAVED PIXMAP HAS JUST BEEN ',   &
      'SET TO')
      CALL DPWRST('XXX','BUG ')
      IF(NCTITL.EQ.0)THEN
        WRITE(ICOUT,999)
      ELSE IF(NCTITL.GE.1)THEN
        WRITE(ICOUT,812)(IPXMCM(NUMPXM+1)(I:I),I=1,NCTITL)
      ENDIF
      CALL DPWRST('XXX','BUG ')
  812 FORMAT(10X,120A1)
  889 CONTINUE
      GO TO 9000
!
!     ****************
!     **  STEP 90-- **
!     **  EXIT      **
!     ****************
!
 9000 CONTINUE
      IF(IBUGP2.NE.'ON')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('AT THE END       OF DPPMTI--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)NCTITL
 9012 FORMAT('NCTITL = ',I5)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPPMTI
      SUBROUTINE DPPOI2(X1,Y1,IFIG,   &
                        ILINPA,ILINCO,ILINC2,MAXLN,PLINTH,   &
                        AREGBA,IREBLI,IREBCO,IREBC2,MAXRG,PREBTH,   &
                        IREFSW,IREFCO,IREFC2,   &
                        IREPTY,IREPLI,IREPCO,IREPC2,PREPTH,PREPSP,   &
                        PTEXHE,PTEXWI,PTEXVG,PTEXHG)
!
!     PURPOSE--DRAW A POINT WITH THE COORDINATES (X1,Y1)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--APRIL     1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --JANUARY   1989. MODIFY CALLS TO DPDRPL (ALAN)
!     UPDATED         --JANUARY   1989. MODIFY CALL  TO DPFIRE (ALAN)
!     UPDATED         --OCTOBER   2020. SUPPORT FOR RGB COLOR
!
!-----NON-COMMON VARIABLES-------------------------------------
!
      CHARACTER*4 IFIG
      CHARACTER*4 IPATT2
!
      CHARACTER*4 ILINPA
      CHARACTER*4 ILINCO
!
      CHARACTER*4 IREBLI
      CHARACTER*4 IREBCO
      CHARACTER*4 IREFSW
      CHARACTER*4 IREFCO
      CHARACTER*4 IREPTY
      CHARACTER*4 IREPLI
      CHARACTER*4 IREPCO
!
      CHARACTER*4 IPATT
      CHARACTER*4 ICOLF
      CHARACTER*4 ICOLP
      CHARACTER*4 ICOL
      CHARACTER*4 IFLAG
!
      DIMENSION PX(10)
      DIMENSION PY(10)
!CCCC DIMENSION PX3(10)
!CCCC DIMENSION PY3(10)
!
      DIMENSION ILINPA(*)
      DIMENSION ILINCO(*)
      DIMENSION ILINC2(MAXLN,3)
      DIMENSION PLINTH(*)
!
      DIMENSION AREGBA(*)
      DIMENSION IREBLI(*)
      DIMENSION IREBCO(*)
      DIMENSION IREBC2(MAXRG,3)
      DIMENSION PREBTH(*)
      DIMENSION IREFSW(*)
      DIMENSION IREFCO(*)
      DIMENSION IREFC2(MAXRG,3)
      DIMENSION IREPTY(*)
      DIMENSION IREPLI(*)
      DIMENSION IREPCO(*)
      DIMENSION IREPC2(MAXRG,3)
      DIMENSION PREPTH(*)
      DIMENSION PREPSP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'POI2')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPPOI2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)X1,Y1
   53 FORMAT('X1,Y1 = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,59)IFIG
   59 FORMAT('IFIG = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,61)ILINPA(1),ILINCO(1),PLINTH(1)
   61 FORMAT('ILINPA(1),ILINCO(1),PLINTH(1) = ',A4,2X,A4,E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,62)AREGBA(1)
   62 FORMAT('AREGBA(1) = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,63)IREBLI(1),IREBCO(1),PREBTH(1)
   63 FORMAT('IREBLI(1),IREBCO(1),PREBTH(1) = ',A4,2X,A4,E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,64)IREFSW(1),IREFCO(1)
   64 FORMAT('IREFSW(1),IREFCO(1) = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,65)IREPTY(1),IREPLI(1),IREPCO(1),PREPTH(1),PREPSP(1)
   65 FORMAT('IREPTY(1),IREPLI(1),IREPCO(1),PREPTH(1),PREPSP(1) = ',   &
      A4,2X,A4,2X,A4,2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,69)PTEXHE,PTEXWI
   69 FORMAT('PTEXHE,PTEXWI= ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,70)PTEXVG,PTEXHG
   70 FORMAT('PTEXVG,PTEXHG= ',2E15.6)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,79)IBUGG4,ISUBG4,IERRG4
   79 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               *********************************
!               **  STEP 1--                   **
!               **  DETERMINE THE COORDINATES  **
!               **  FOR THE POINT              **
!               *********************************
!
      PX(1)=X1
      PY(1)=Y1
!
      PX(2)=X1
      PY(2)=Y1
!
      NP=2
!
!               ***********************
!               **  STEP 2--         **
!               **  FILL THE FIGURE  **
!               **  (IF CALLED FOR)  **
!               ***********************
!
      IF(IREFSW(1).EQ.'OFF')GO TO 2190
      IPATT=IREPTY(1)
      IPATT2='SOLI'
      PTHICK=PREPTH(1)
      PXGAP=PREPSP(1)
      PYGAP=PREPSP(1)
      ICOLF=IREFCO(1)
      ICOLFR=IREFC2(1,1)
      ICOLFG=IREFC2(1,2)
      ICOLFB=IREFC2(1,3)
      ICOLP=IREPCO(1)
      ICOLPR=IREPC2(1,1)
      ICOLPG=IREPC2(1,2)
      ICOLPB=IREPC2(1,3)
      ICOLBR=IREBC2(1,1)
      ICOLBG=IREBC2(1,2)
      ICOLBB=IREBC2(1,3)
      CALL DPFIRE(PX,PY,NP,   &
                  IFIG,IPATT,PTHICK,PXGAP,PYGAP,   &
                  ICOLF,ICOLFR,ICOLFG,ICOLFB,   &
                  ICOLP,ICOLPR,ICOLPG,ICOLPB,   &
                  IPATT2)
 2190 CONTINUE
!
!               ***************************
!               **  STEP 3--             **
!               **  DRAW OUT THE FIGURE  **
!               ***************************
!
      IPATT=ILINPA(1)
      PTHICK=PLINTH(1)
      ICOL=ILINCO(1)
      ICOLR=ILINC2(1,1)
      ICOLG=ILINC2(1,2)
      ICOLB=ILINC2(1,3)
      IFLAG='ON'
      CALL DPDRPL(PX,PY,NP,   &
                  IFIG,IPATT,PTHICK,   &
                  ICOL,ICOLR,ICOLG,ICOLB,   &
                  JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'POI2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPOI2--')
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,NP
          WRITE(ICOUT,9016)I,PX(I),PY(I)
 9016     FORMAT('I,PX(I),PY(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
        WRITE(ICOUT,9039)IBUGG4,ISUBG4,IERRG4,NP
 9039   FORMAT('IBUGG4,ISUBG4,IERRG4,NP = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPOI2
      SUBROUTINE DPPOIN(IHARG,IARGT,ARG,NUMARG,   &
                        PXSTAR,PYSTAR,PXEND,PYEND,   &
                        ILINPA,ILINCO,ILINC2,MAXLNZ,PLINTH,   &
                        AREGBA,IREBLI,IREBCO,IREBC2,MAXRGZ,PREBTH,   &
                        IREFSW,IREFCO,IREFC2,   &
                        IREPTY,IREPLI,IREPCO,IREPC2,PREPTH,PREPSP,   &
                        PTEXHE,PTEXWI,PTEXVG,PTEXHG,   &
                        IGRASW,IDIASW,   &
                        PGRAXF,PGRAYF,PDIAXC,PDIAYC,PDIAX2,PDIAY2,   &
                        PDIAHE,PDIAWI,PDIAVG,PDIAHG,   &
                        NUMDEV,IDMANU,IDMODE,IDMOD2,IDMOD3,   &
                        IDPOWE,IDCONT,IDCOLO,IDNVPP,IDNHPP,IDUNIT,   &
                        IDNVOF,IDNHOF,IDFONT,UNITSW,PDSCAL,   &
                        IBACCO,IBACC2,   &
                        IBUGD2,IFOUND,IERROR)
!
!     PURPOSE--DRAW ONE OR MORE POINTS (DEPENDING ON HOW MANY NUMBERS
!              ARE PROVIDED).  THE COORDINATES ARE IN STANDARDIZED UNITS
!              OF 0 TO 100.
!     NOTE--THE INPUT COORDINATES DEFINE THE POINT.
!     NOTE-THE USUAL INPUT NUMBER OF COORDINATES IS 1 AND THEREFORE
!          THE USUAL INPUT NUMBER OF NUMBERS IS 2*1 = 2.
!     NOTE--IF NO NUMBERS ARE PROVIDED, THEN THE DRAWN POINT WILL BE
!           AT THE LAST CURSOR POSITION
!     NOTE--IF 2 NUMBERS ARE PROVIDED, THEN THE DRAWN POINT WILL BE AT
!           THE ABSOLUTE (X,Y) POSITION AS DEFINED BY THE 2 NUMBERS
!     NOTE--AND SO FORTH FOR 2, 3, 4, ... NUMBERS.
!     INPUT  ARGUMENTS--IHARG
!                     --IARGT
!                     --ARG
!                     --NUMARG
!                     --PXSTAR
!                     --PYSTAR
!     OUTPUT ARGUMENTS--PXEND
!                     --PYEND
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--APRIL     1981.
!     UPDATED         --MARCH     1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --NOVEMBER  1982.
!     UPDATED         --JANUARY   1989. CALL LIST FOR OFFSET VAR (ALAN)
!     UPDATED         --MARCH     1997. SUPPORT FOR DEVICE FONT (ALAN)
!     UPDATED         --JULY      1997. SUPPORT FOR "DATA" UNITS (ALAN)
!     UPDATED         --DECEMBER  2018. CHECK FOR DISCRETE, NULL, OR
!                                       NONE DEVICE
!     UPDATED         --DECEMBER  2018. SUPPORT FOR "DEVICE ... SCALE"
!                                       COMMAND
!     UPDATED         --OCTOBER   2020. SUPPORT FOR RGB COLORS
!
!-----NON-COMMON VARIABLES-----------------------------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
!
      CHARACTER*4 ILINPA
      CHARACTER*4 ILINCO
!
      CHARACTER*4 IREBLI
      CHARACTER*4 IREBCO
      CHARACTER*4 IREFSW
      CHARACTER*4 IREFCO
      CHARACTER*4 IREPTY
      CHARACTER*4 IREPLI
      CHARACTER*4 IREPCO
!
      CHARACTER*4 IGRASW
      CHARACTER*4 IDIASW
!
      CHARACTER*4 IDMANU
      CHARACTER*4 IDMODE
      CHARACTER*4 IDMOD2
      CHARACTER*4 IDMOD3
      CHARACTER*4 IDPOWE
      CHARACTER*4 IDCONT
      CHARACTER*4 IDCOLO
!CCCC ADD FOLLOWING LINE MARCH 1997.
      CHARACTER*4 IDFONT
!CCCC ADD FOLLOWING LINE JULY 1997.
      CHARACTER*4 UNITSW
!
      CHARACTER*4 IFOUND
      CHARACTER*4 IBUGD2
      CHARACTER*4 IERROR
      CHARACTER*4 ISUBRO
!
      CHARACTER*4 IFIG
      CHARACTER*4 IBELSW
      CHARACTER*4 IERASW
      CHARACTER*4 IBACCO
      CHARACTER*4 ICOPSW
      CHARACTER*4 ITYPEO
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION ARG(*)
!
      DIMENSION ILINPA(*)
      DIMENSION ILINCO(*)
      DIMENSION ILINC2(MAXLNZ,3)
      DIMENSION PLINTH(*)
!
      DIMENSION AREGBA(*)
      DIMENSION IREBLI(*)
      DIMENSION IREBCO(*)
      DIMENSION IREBC2(MAXRGZ,3)
      DIMENSION PREBTH(*)
      DIMENSION IREFSW(*)
      DIMENSION IREFCO(*)
      DIMENSION IREFC2(MAXRGZ,3)
      DIMENSION IREPTY(*)
      DIMENSION IREPLI(*)
      DIMENSION IREPCO(*)
      DIMENSION IREPC2(MAXRGZ,3)
      DIMENSION PREPTH(*)
      DIMENSION PREPSP(*)
      DIMENSION PDSCAL(*)
!
      DIMENSION IDMANU(*)
      DIMENSION IDMODE(*)
      DIMENSION IDMOD2(*)
      DIMENSION IDMOD3(*)
      DIMENSION IDPOWE(*)
      DIMENSION IDCONT(*)
      DIMENSION IDCOLO(*)
!CCCC ADD FOLLOWING LINE MARCH 1997.
      DIMENSION IDFONT(*)
      DIMENSION IDNVPP(*)
      DIMENSION IDNHPP(*)
      DIMENSION IDUNIT(*)
!
      DIMENSION IDNVOF(*)
      DIMENSION IDNHOF(*)
      DIMENSION IBACC2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      IERRG4=IERROR
!CCCC IBUGG4=IBUGD2
!CCCC ISUBG4=ISUBRO
!
      ILOCFN=0
      NUMNUM=0
!
      X1=0.0
      Y1=0.0
      X2=0.0
      Y2=0.0
!
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'POIN')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPOIN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)NUMARG,NUMDEV
   53   FORMAT('NUMARG,NUMDEV = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NUMARG
          WRITE(ICOUT,56)I,IHARG(I),IARGT(I),ARG(I)
   56     FORMAT('I,IHARG(I),IARGT(I),ARG(I) = ',I8,2(2X,A4),G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        WRITE(ICOUT,57)PXSTAR,PYSTAR,PXEND,PYEND
   57   FORMAT('PXSTAR,PYSTAR,PXEND,PYEND = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,61)ILINPA(1),ILINCO(1),PLINTH(1)
   61   FORMAT('ILINPA(1),ILINCO(1),PLINTH(1) = ',2(A4,2X),G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)IREBLI(1),IREBCO(1),PREBTH(1),AREGBA(1)
   63   FORMAT('IREBLI(1),IREBCO(1),PREBTH(1),AREGBA(1) = ',   &
               2(A4,2X),2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,64)IREFSW(1),IREFCO(1)
   64   FORMAT('IREFSW(1),IREFCO(1) = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,65)IREPTY(1),IREPLI(1),IREPCO(1),PREPTH(1),PREPSP(1)
   65   FORMAT('IREPTY(1),IREPLI(1),IREPCO(1),PREPTH(1),PREPSP(1) = ',   &
               3(A4,2X),2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,69)PTEXHE,PTEXWI,PTEXVG,PTEXHG
   69   FORMAT('PTEXHE,PTEXWI,PTEXVG,PTEXHG = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,76)IGRASW,IDIASW
   76   FORMAT('IGRASW,IDIASW = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,77)PGRAXF,PGRAYF,PDIAXC,PDIAYC
   77   FORMAT('PGRAXF,PGRAYF,PDIAXC,PDIAYC = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,78)PDIAHE,PDIAWI,PDIAVG,PDIAHG
   78   FORMAT('PDIAHE,PDIAWI,PDIAVG,PDIAHG = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 81 I=1,NUMDEV
          WRITE(ICOUT,82)IDMANU(I),IDMODE(I),IDMOD2(I),IDMOD3(I)
   82     FORMAT('IDMANU(I),IDMODE(I),IDMOD2(I),IDMOD3(I) = ',   &
                 3(A4,2X),A4)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,83)IDPOWE(I),IDCONT(I),IDCOLO(I)
   83     FORMAT('IDPOWE(I),IDCONT(I),IDCOLO(I) = ',2(A4,2X),A4)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,84)IDNVPP(I),IDNHPP(I),IDUNIT(I)
   84     FORMAT('IDNVPP(I),IDNHPP(I),IDUNIT(I) = ',3I8)
          CALL DPWRST('XXX','BUG ')
   81   CONTINUE
        WRITE(ICOUT,88)IBUGG4,ISUBG4,IERRG4,IBUGD2,IFOUND,IERROR
   88   FORMAT('IBUGG4,ISUBG4,IERRG4,IBUGD2,IFOUND,IERROR = ',   &
               5(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IFIG='POIN'
      NUMPT=1
      NUMPT2=2*NUMPT
!
!               ********************************
!               **  STEP 0--                  **
!               **  STEP THROUGH EACH DEVICE  **
!               ********************************
!
      IF(NUMDEV.LE.0)GO TO 9000
      DO 8000 IDEVIC=1,NUMDEV
!
      IF(IDPOWE(IDEVIC).EQ.'OFF')GO TO 8000
      IF(IDMANU(IDEVIC).EQ.'OFF')GO TO 8000
      IF(IDMANU(IDEVIC).EQ.'NULL')GO TO 8000
      IF(IDMANU(IDEVIC).EQ.'NONE')GO TO 8000
      IF(IDMANU(IDEVIC).EQ.'DISC')GO TO 8000
!
      IMANUF=IDMANU(IDEVIC)
      IMODEL=IDMODE(IDEVIC)
      IMODE2=IDMOD2(IDEVIC)
      IMODE3=IDMOD3(IDEVIC)
      IGCONT=IDCONT(IDEVIC)
      IGCOLO=IDCOLO(IDEVIC)
      IGFONT=IDFONT(IDEVIC)
      NUMVPP=IDNVPP(IDEVIC)
      NUMHPP=IDNHPP(IDEVIC)
      ANUMVP=NUMVPP
      ANUMHP=NUMHPP
      IOFFSV=IDNVOF(IDEVIC)
      IOFFSH=IDNHOF(IDEVIC)
      IGUNIT=IDUNIT(IDEVIC)
      PCHSCA=PDSCAL(IDEVIC)
!
!               ************************************
!               **  STEP 1--                      **
!               **  CARRY OUT OPENING OPERATIONS  **
!               **  ON THE GRAPHICS DEVICES       **
!               ************************************
!
      CALL DPOPDE
!
      IBELSW='OFF'
      NUMRIN=0
      IERASW='OFF'
!
      CALL DPOPPL(IGRASW,IBELSW,NUMRIN,IERASW,IBACCO,IBACC2)
!
!               *****************************************
!               **  STEP 2--                           **
!               **  SEARCH FOR COMMAND SPECIFICATIONS  **
!               *****************************************
!
      IF(NUMARG.GE.2.AND.   &
      IARGT(1).EQ.'NUMB'.AND.IARGT(2).EQ.'NUMB')   &
      GO TO 1111
      IF(NUMARG.GE.3.AND.IHARG(1).EQ.'ABSO'.AND.   &
      IARGT(2).EQ.'NUMB'.AND.IARGT(3).EQ.'NUMB')   &
      GO TO 1112
      IF(NUMARG.GE.3.AND.IHARG(1).EQ.'RELA'.AND.   &
      IARGT(2).EQ.'NUMB'.AND.IARGT(3).EQ.'NUMB')   &
      GO TO 1113
      GO TO 1130
!
 1111 CONTINUE
      ITYPEO='ABSO'
      ILOCFN=1
      GO TO 1119
!
 1112 CONTINUE
      ITYPEO='ABSO'
      ILOCFN=2
      GO TO 1119
!
 1113 CONTINUE
      ITYPEO='RELA'
      ILOCFN=2
      GO TO 1119
 1119 CONTINUE
!
      IF(ILOCFN.GT.NUMARG)GO TO 1129
      DO 1120 I=ILOCFN,NUMARG
      IF(IARGT(I).EQ.'NUMB')GO TO 1120
      GO TO 1129
 1120 CONTINUE
      IFOUND='YES'
      GO TO 1149
 1129 CONTINUE
      GO TO 1130
!
 1130 CONTINUE
      IERRG4='YES'
      WRITE(ICOUT,1131)
 1131 FORMAT('***** ERROR IN DPPOIN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1132)
 1132 FORMAT('      ILLEGAL FORM FOR DRAW ',   &
      'COMMAND.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1134)
 1134 FORMAT('      TEST EXAMPLE TO DEMONSTRATE THE ',   &
      'PROPER FORM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1135)
 1135 FORMAT('      SUPPOSE IT IS DESIRED TO DRAW A POINT ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1136)
 1136 FORMAT('      AT 20 20 ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1141)
 1141 FORMAT('      THEN THE ALLOWABLE FORMS ARE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1142)
 1142 FORMAT('      POINT 20 20 ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1143)
 1143 FORMAT('      BOX ABSOLUTE 20 20 ')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
 1149 CONTINUE
!
!               ****************************
!               **  STEP 3--              **
!               **  DRAW OUT THE LINE(S)  **
!               ****************************
!
      NUMNUM=NUMARG-ILOCFN+1
      IF(NUMNUM.LT.NUMPT2)GO TO 1151
      GO TO 1152
!
 1151 CONTINUE
      J=ILOCFN-1
      X1=PXSTAR
      Y1=PYSTAR
      GO TO 1170
!
 1152 CONTINUE
      J=ILOCFN
      IF(J.GT.NUMARG)GO TO 1190
      X1=ARG(J)
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1997
      IF(UNITSW.EQ.'DATA')CALL DPCODS('X',X1,X1,IBUGD2,ISUBRO,IERROR)
      J=J+1
      IF(J.GT.NUMARG)GO TO 1190
      Y1=ARG(J)
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1997
      IF(UNITSW.EQ.'DATA')CALL DPCODS('Y',Y1,Y1,IBUGD2,ISUBRO,IERROR)
      GO TO 1170
!
 1160 CONTINUE
      J=J+1
      IF(J.GT.NUMARG)GO TO 1190
      X2=ARG(J)
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1997
      IF(UNITSW.EQ.'DATA')CALL DPCODS('X',X2,X2,IBUGD2,ISUBRO,IERROR)
      IF(ITYPEO.EQ.'RELA')X2=X1+X2
      J=J+1
      IF(J.GT.NUMARG)GO TO 1190
      Y2=ARG(J)
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1997
      IF(UNITSW.EQ.'DATA')CALL DPCODS('Y',Y2,Y2,IBUGD2,ISUBRO,IERROR)
      IF(ITYPEO.EQ.'RELA')Y2=Y1+Y2
      X1=X2
      Y1=Y2
      GO TO 1170
!
 1170 CONTINUE
      CALL DPPOI2(X1,Y1,IFIG,   &
                  ILINPA,ILINCO,ILINC2,MAXLNZ,PLINTH,   &
                  AREGBA,IREBLI,IREBCO,IREBC2,MAXRGZ,PREBTH,   &
                  IREFSW,IREFCO,IREFC2,   &
                  IREPTY,IREPLI,IREPCO,IREPC2,PREPTH,PREPSP,   &
                  PTEXHE,PTEXWI,PTEXVG,PTEXHG)
!
      X1=X1
      Y1=Y1
!
      GO TO 1160
 1190 CONTINUE
!
      PXEND=X1
      PYEND=Y1
!
!               ************************************
!               **  STEP 4--                      **
!               **  CARRY OUT CLOSING OPERATIONS  **
!               **  ON THE GRAPHICS DEVICES       **
!               ************************************
!
      ICOPSW='OFF'
      NUMCOP=0
      CALL DPCLPL(ICOPSW,NUMCOP,   &
      PGRAXF,PGRAYF,   &
      IGRASW,PDIAXC,PDIAYC,PDIAX2,PDIAY2,   &
      PDIAHE,PDIAWI,PDIAVG,PDIAHG)
!
      CALL DPCLDE
!
 8000 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'POIN')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPOIN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ILOCFN,NUMNUM
 9012   FORMAT('ILOCFN,NUMNUM = ',2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)X1,Y1
 9013   FORMAT('X1,Y1 = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)PXSTAR,PYSTAR,PXEND,PYEND
 9015   FORMAT('PXSTAR,PYSTAR,PXEND,PYEND = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9027)IFOUND,IERROR
 9027   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPOIN
      SUBROUTINE DPPOIS(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                        CLLIMI,CLWIDT,   &
                        IBUGG2,IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--GENERATE ONE OF THE FOLLOWING PLOTS:
!              POISSON PLOT Y X
!              POISSON PLOT Y
!              NEGATIVE BINOMIAL PLOT Y X
!              NEGATIVE BINOMIAL PLOT Y
!              BINOMIAL PLOT Y X
!              BINOMIAL PLOT Y
!              GEOMETRIC PLOT Y X
!              GEOMETRIC PLOT Y
!              LOGARITHMIC SERIES PLOT Y X
!              LOGARITHMIC SERIES PLOT Y
!     REFERENCE--MICHAEL FRIENDLY (200), "VISUALIZING CATEGORICAL
!                DATA", SAS PUBLISHING, PP. 49-56.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATROY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/5
!     ORIGINAL VERSION--MAY       2007.
!     UPDATED         --JANUARY   2012. USE DPPARS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IAND1
      CHARACTER*4 IAND2
      CHARACTER*4 IBUGG2
      CHARACTER*4 IBUGG3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IDATSW
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISUBN0
      CHARACTER*4 ISTEPN
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 IH
      CHARACTER*4 IH2
!
      CHARACTER*20 IDIST
!
      CHARACTER*4 ICASE
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=10)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
!
      DIMENSION CLLIMI(*)
      DIMENSION CLWIDT(*)
!
      DIMENSION Y1(MAXOBV)
      DIMENSION X1(MAXOBV)
      DIMENSION TEMP1(MAXOBV)
      DIMENSION TEMP2(MAXOBV)
      DIMENSION TEMP3(MAXOBV)
      DIMENSION TEMP4(MAXOBV)
      DIMENSION WEIGHH(MAXOBV)
      DIMENSION WEIGHV(MAXOBV)
!
      EQUIVALENCE (GARBAG(IGARB1),X1(1))
      EQUIVALENCE (GARBAG(IGARB2),Y1(1))
      EQUIVALENCE (GARBAG(IGARB3),TEMP1(1))
      EQUIVALENCE (GARBAG(IGARB4),TEMP2(1))
      EQUIVALENCE (GARBAG(IGARB5),TEMP3(1))
      EQUIVALENCE (GARBAG(IGARB6),TEMP4(1))
      EQUIVALENCE (GARBAG(IGARB7),WEIGHH(1))
      EQUIVALENCE (GARBAG(IGARB8),WEIGHV(1))
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      ISUBN1='DPPO'
      ISUBN2='IS  '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!               ************************************
!               **  TREAT THE POISSON       PLOT  **
!               ************************************
!
      IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'POIS ')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPOIS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ICASPL,IAND1,IAND2
   52   FORMAT('ICASPL,IAND1,IAND2 = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGG2,IBUGG3,IBUGQ,ISUBRO
   53   FORMAT('IBUGG2,IBUGG3,IBUGQ,ISUBRO = ',A4,2X,A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***************************
!               **  STEP 1--             **
!               **  EXTRACT THE COMMAND  **
!               ***************************
!
      ISTEPN='1'
      IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'POIS')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICOM.EQ.'POIS' .AND. IHARG(1).EQ.'PLOT')THEN
        ILASTC=1
        CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
        IFOUND='YES'
        ICASPL='POIS'
        IDIST='POISSON'
      ELSEIF(ICOM.EQ.'GEOM' .AND. IHARG(1).EQ.'PLOT')THEN
        ILASTC=1
        CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
        IFOUND='YES'
        ICASPL='GEOM'
        IDIST='GEOMETRIC'
      ELSEIF(ICOM.EQ.'BINO' .AND. IHARG(1).EQ.'PLOT')THEN
        ILASTC=1
        CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
        IFOUND='YES'
        ICASPL='BINO'
        IDIST='BINOMIAL'
      ELSEIF(ICOM.EQ.'LOGA' .AND. IHARG(1).EQ.'SERI' .AND.   &
             IHARG(2).EQ.'PLOT')THEN
        ILASTC=2
        CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
        IFOUND='YES'
        ICASPL='LOGS'
        IDIST='LOGARITHMIC SERIES'
      ELSEIF(ICOM.EQ.'NEGA' .AND. IHARG(1).EQ.'BINO' .AND.   &
             IHARG(2).EQ.'PLOT')THEN
        ILASTC=2
        CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
        IFOUND='YES'
        ICASPL='NBIN'
        IDIST='NEGATIVE BINOMIAL'
      ELSE
        IFOUND='NO'
        GO TO 9000
      ENDIF
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'POIS')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME(1:20)=IDIST(1:20)
      INAME(21:25)=' PLOT'
      MINNA=1
      MAXNA=100
      MINN2=1
      IFLAGE=1
      IFLAGM=0
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=1
      MAXNVA=2
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'POIS')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
      ICOL=1
      IF(NUMVAR.EQ.1)THEN
        IDATSW='RAW'
        CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVAR,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    X1,X1,X1,NLOCAL,NLOCAL,NLOCAL,ICASE,   &
                    IBUGG3,ISUBRO,IFOUND,IERROR)
      ELSE
        IDATSW='FREQ'
        CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVAR,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    Y1,X1,X1,NLOCAL,NLOCAL,NLOCAL,ICASE,   &
                    IBUGG3,ISUBRO,IFOUND,IERROR)
      ENDIF
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               ****************************************************
!               **  STEP 7--                                      **
!               **  DETERMINE IF THE ANALYST                      **
!               **  HAS SPECIFIED    1)  THE CLASS WIDTH,         **
!               **                   2)  THE MIN POINT OF THE     **
!               **                       FIRST CELL,              **
!               **                   3)  THE MAX POINT OF THE     **
!               **                       LAST  CELL,              **
!               **  FOR THE DISTRIBUTIONAL ANALYSIS.              **
!               **  IF NON-DEFAULT, USE THE SPECIFIED VALUES.     **
!               **  IF DEFAULT, USE THE DEFAULT VALUES--          **
!               **     1)  CLASS WIDTH = .3 OF A SAMPLE STANDARD  **
!               **         DEVIATION;                             **
!               **     2)  START = SAMPLE MEAN - 6*(SAMPLE        **
!               **         STANDARD DEVIATION);                   **
!               **     3)  STOP  = SAMPLE MEAN + 6*(SAMPLE        **
!               **         STANDARD DEVIATION);                   **
!               **  NOTE THAT THE DEFAULT SETTINGS ARE IN FACT    **
!               ****************************************************
!
      ISTEPN='7'
      IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'POIS')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CLWID=CLWIDT(1)
      XSTART=CLLIMI(1)
      XSTOP=CLLIMI(2)
!
!               *****************************************************
!               **  STEP 8--                                       **
!               **  FORM THE VERTICAL AND HORIZONTAL AXIS          **
!               **  VALUES Y(.) AND X(.) FOR THE PLOT.             **
!               **  RESET THE VECTOR D(.) TO ALL ONES.             **
!               **  DEFINE THE NUMBER OF PLOT POINTS    (NPLOTP).  **
!               **  DEFINE THE NUMBER OF PLOT VARIABLES (NPLOTV).  **
!               *****************************************************
!
      IF(ICASPL.EQ.'LOGS'.AND.IPOILV.EQ.'ON')THEN
        IH='THET'
        IH2='A   '
        IHWUSE='P'
        MESSAG='YES'
        CALL CHECKN(IH,IH2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        THETA=VALUE(ILOCP)
      ELSEIF(ICASPL.EQ.'BINO'.AND.IPOILV.EQ.'ON')THEN
        IH='N   '
        IH2='    '
        IHWUSE='P'
        MESSAG='YES'
        CALL CHECKN(IH,IH2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        NTRIAL=INT(VALUE(ILOCP)+0.5)
      ELSEIF(ICASPL.EQ.'NBIN'.AND.IPOILV.EQ.'ON')THEN
        IH='K   '
        IH2='    '
        IHWUSE='P'
        MESSAG='YES'
        CALL CHECKN(IH,IH2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        AKNB=VALUE(ILOCP)
      ENDIF
!
      CALL DPPOIZ(Y1,X1,NLOCAL,NUMVAR,   &
                  WEIGHH,WEIGHV,TEMP1,TEMP2,TEMP3,TEMP4,   &
                  IDATSW,ICASPL,IPOILV,   &
                  THETA,NTRIAL,AKNB,   &
                  PPA0,PPA1,PPA0AD,PPA1AD,   &
                  ALMBPP,ALMBP2,PPP,PP2,THETPP,THETP2,   &
                  Y,X,D,NPLOTP,NPLOTV,ISUBRO,IBUGG3,IERROR)
!
      IH='PPA0'
      IH2='    '
      VALUE0=PPA0
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='PPA1'
      IH2='    '
      VALUE0=PPA1
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='PPA0'
      IH2='ADJU'
      VALUE0=PPA0AD
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='PPA1'
      IH2='ADJU'
      VALUE0=PPA1AD
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IF(ICASPL.EQ.'POIS')THEN
        IH='LAMB'
        IH2='DAPP'
        VALUE0=ALMBPP
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGG3,IERROR)
        IH='LAMB'
        IH2='DAPA'
        VALUE0=ALMBP2
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGG3,IERROR)
      ENDIF
!
      IF(ICASPL.EQ.'GEOM' .OR. ICASPL.EQ.'BINO' .OR.   &
         ICASPL.EQ.'NBIN')THEN
        IH='PPP '
        IH2='    '
        VALUE0=PPP
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGG3,IERROR)
        IH='PPPA'
        IH2='DJ  '
        VALUE0=PP2
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGG3,IERROR)
      ENDIF
!
      IF(ICASPL.EQ.'LOGS')THEN
        IH='THET'
        IH2='APP '
        VALUE0=THETPP
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGG3,IERROR)
        IH='THET'
        IH2='APPA'
        VALUE0=THETP2
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGG3,IERROR)
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'POIS')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPOIS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR,CLWID,XSTART,XSTOP
 9012   FORMAT('IFOUND,IERROR,CLWID,XSTART,XSTOP = ',2(A4,2X),3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2
 9013   FORMAT('NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2 = ',3I8,3(2X,A4))
        CALL DPWRST('XXX','BUG ')
        IF(NPLOTP.GE.1)THEN
          DO 9015 I=1,NPLOTP
            WRITE(ICOUT,9016)I,Y(I),X(I),D(I)
 9016       FORMAT('I,Y(I),X(I),D(I) = ',I8,3G15.7)
            CALL DPWRST('XXX','BUG ')
 9015     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPPOIS
      SUBROUTINE DPPOIZ(Y,X,N,NVAR,   &
                        WEIGHH,WEIGHV,TEMP1,TEMP2,TEMP3,TEMP4,   &
                        IDATSW,ICASPL,IPOILV,   &
                        THETA,NTRIAL,AKNB,   &
                        PPA0,PPA1,PPA0AD,PPA1AD,   &
                        ALMBPP,ALMBP2,PPP,PP2,THETPP,THETP2,   &
                        Y2,X2,D2,N2,NPLOTV,ISUBRO,IBUGG3,IERROR)
!
!     PURPOSE--GENERATE A PAIR OF COORDINATE VECTORS
!              THAT WILL DEFINE A POISSON PLOT
!     REFERENCE--MICHAEL FRIENDLY (200), "VISUALIZING CATEGORICAL
!                DATA", SAS PUBLISHING, PP. 49-56.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATROY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/5
!     ORIGINAL VERSION--MAY       2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IDATSW
      CHARACTER*4 ICASPL
      CHARACTER*4 IPOILV
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGG3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IRELAT
      CHARACTER*4 IRHSTG
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
      DOUBLE PRECISION DLNGAM
      DOUBLE PRECISION DBINLN
!
      EXTERNAL DLNGAM
      EXTERNAL DBINLN
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION WEIGHH(*)
      DIMENSION WEIGHV(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DIMENSION TEMP4(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION D2(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPPO'
      ISUBN2='IZ  '
      IWRITE='OFF'
      IERROR='NO'
!
      ALAMB=CPUMIN
      NTOT=0
      NTEMP=0
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'POIZ')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,70)
   70   FORMAT('***** AT THE BEGINNING OF DPPOIZ--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,72)N,NVAR,NPLOTV,IDATSW
   72   FORMAT('N,NVAR,NPLOTV,IDATSW = ',3I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 73 I=1,N
          WRITE(ICOUT,74)I,Y(I),X(I)
   74     FORMAT('I, Y(I), X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   73   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='11'
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'POIZ')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NVAR.EQ.1)THEN
        HOLD=Y(1)
        DO 1135 I=2,N
          IF(Y(I).NE.HOLD)GO TO 1139
 1135   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1111)
 1111   FORMAT('***** ERROR IN POISSON PLOT--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1133)HOLD
 1133   FORMAT('      HAS ALL ELEMENTS = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
 1139   CONTINUE
!
        DO 1145 I=1,N
          IF(Y(I).LT.0.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1111)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1148)I,Y(I)
 1148       FORMAT('      ROW ',I8,' IS NON-POSITIVE (VALUE = ',   &
                   G15.7,')')
            CALL DPWRST('XXX','WRIT')
            IERROR='YES'
            GO TO 9000
          ENDIF
 1145   CONTINUE
!
        CALL SORT(Y,N,TEMP2)
        DO 1160 I=1,N
          Y(I)=TEMP2(I)
 1160   CONTINUE
!
        CALL MEAN(Y,N,IWRITE,XMEAN,IBUGG3,IERROR)
        IF(ICASPL.EQ.'POIS')THEN
          ALAMB=XMEAN
        ELSEIF(ICASPL.EQ.'GEOM')THEN
          PML=1.0/(XMEAN+1.0)
        ELSEIF(ICASPL.EQ.'BINO')THEN
          PML=XMEAN/REAL(NTRIAL)
        ELSEIF(ICASPL.EQ.'NBIN')THEN
          CALL SD(Y,N,IWRITE,XSD,IBUGG3,IERROR)
          KNB=INT(AKNB+0.5)
          AKNB=REAL(KNB)
          AKMOM=XMEAN*XMEAN/(XSD*XSD - XMEAN)
          PMOM=((XSD*XSD/XMEAN) - 1.0)
!
          PML=0.0
          IF(AKNB.GT.0.0)THEN
            PML=AKNB/(XMEAN+AKNB)
            IF(AKNB.GE.2.0)THEN
              PML=(AKNB-1.0)/(XMEAN+AKNB-1.0)
            ENDIF
          ELSE
            PML=AKMOM/(XMEAN+AKMOM)
            IF(AKMOM.GE.2.0)THEN
              PML=(AKMOM-1.0)/(XMEAN+AKMOM-1.0)
            ENDIF
            AKNB=AKMOM
          ENDIF
!
        ELSEIF(ICASPL.EQ.'LOGS')THEN
        ENDIF
!
        IRELAT='OFF'
        IRHSTG='OFF'
        XMIN=Y(1)
        XMAX=Y(N)
        XSTART=XMIN-0.5
        XSTOP=XMAX+0.5
        CLWID=1.0
        CALL DPBINI(Y,N,IRELAT,CLWID,XSTART,XSTOP,IRHSTG,   &
                    TEMP2,TEMP1,N2,IBUGG3,IERROR)
        NTOT=N
        ICNT=0
        DO 101 I=1,N2
          IF(TEMP2(I).GT.0)THEN
            ICNT=ICNT+1
            Y(ICNT)=TEMP2(I)
            X(ICNT)=TEMP1(I)
          ENDIF
 101    CONTINUE
        N2=ICNT
        IF(IERROR.EQ.'YES')GO TO 9000
!
      ELSEIF(NVAR.EQ.2)THEN
!
        CALL WEMEAN(X,Y,N,IWRITE,XMEAN,IBUGG3,IERROR)
!
        IF(ICASPL.EQ.'POIS')THEN
          ALAMB=XMEAN
        ELSEIF(ICASPL.EQ.'GEOM')THEN
          PML=1.0/(XMEAN+1.0)
        ELSEIF(ICASPL.EQ.'BINO')THEN
          PML=XMEAN/REAL(NTRIAL)
        ELSEIF(ICASPL.EQ.'NBIN')THEN
          CALL WESD(X,Y,N,IWRITE,XSD,IBUGG3,IERROR)
          KNB=INT(AKNB+0.5)
          AKNB=REAL(KNB)
          AKMOM=XMEAN*XMEAN/(XSD*XSD - XMEAN)
          PMOM=((XSD*XSD/XMEAN) - 1.0)
!
          PML=0.0
          IF(AKNB.GT.0.0)THEN
            PML=AKNB/(XMEAN+AKNB)
            IF(AKNB.GE.2.0)THEN
              PML=(AKNB-1.0)/(XMEAN+AKNB-1.0)
            ENDIF
          ELSE
            PML=AKMOM/(XMEAN+AKMOM)
            IF(AKMOM.GE.2.0)THEN
              PML=(AKMOM-1.0)/(XMEAN+AKMOM-1.0)
            ENDIF
            AKNB=AKMOM
          ENDIF
!
        ELSEIF(ICASPL.EQ.'LOGS')THEN
        ENDIF
!
        CALL SORTC(X,Y,N,TEMP1,TEMP2)
        NTOT=0
        DO 1210 I=1,N
          X(I)=TEMP1(I)
          Y(I)=TEMP2(I)
          NTOT=NTOT + INT(Y(I) + 0.1)
 1210   CONTINUE
        N2=N
!
        DO 1220 I=1,N
          IF(Y(I).LT.0.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1111)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1223)
 1223       FORMAT('      A NEGATIVE FREQUENCY WAS SPECIFIED.')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1225)I,Y(I)
 1225       FORMAT('      ROW ',I8,' (AFTER SORTING) HAS FREQUENCY ',   &
                   G15.7)
            CALL DPWRST('XXX','WRIT')
          ENDIF
 1220   CONTINUE
      ENDIF
!
      IF(ICASPL.EQ.'BINO')THEN
        DO 1310 I=1,N2
          IF(NTRIAL.LT.INT(Y2(I)+0.1))THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1111)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1311)
 1311       FORMAT('      FOR THE BINOMIAL PLOT, THE NUMBER OF TRIALS')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1313)NTRIAL
 1313       FORMAT('      PARAMETER, ',I8,' IS LESS THAT THE')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1315)INT(X2(I)+0.1)
 1315       FORMAT('      FREQUENCY FOR CLASS ',I8)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1317)INT(X2(I)+0.1),INT(Y2(I)+0.1)
 1317       FORMAT('      THE FREQUENCY FOR CLASS ',I8,' = ',G15.7)
            CALL DPWRST('XXX','WRIT')
            IERROR='YES'
            GO TO 9000
          ENDIF
 1310   CONTINUE
      ELSEIF(ICASPL.EQ.'NBIN')THEN
        KNB=INT(AKNB+0.5)
        IF(KNB.LE.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,1111)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,1321)
 1321     FORMAT('      FOR THE NEGATIVE BINOMIAL PLOT, THE SHAPE')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,1323)
 1323     FORMAT('      PARAMETER, K, IS NON-POSITIVE.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,1325)KNB
 1325     FORMAT('      THE VALUE OF THE SHAPE PARAMETER = ',I8)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
!               ****************************************************
!               **  STEP 2.0--                                    **
!               **  GENERATE                                      **
!               **  A) POISSON PLOT:                              **
!               **     PLOT LOG(K!*N(K)/N) VERSUS K               **
!               **  B) BINOMIAL PLOT:                             **
!               **  C) NEGATIVE BINOMIAL PLOT:                    **
!               **  D) LOGARITHMIC SERIES PLOT:                   **
!               ****************************************************
!
      ISTEPN='2'
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'POIZ')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICASPL.EQ.'POIS')THEN
        ICNT=0
        DTERM1=DLOG(DBLE(NTOT))
        DO 2000 I=1,N2
          AK=X(I)
          IK=INT(AK+0.1)
          ANK=Y(I)
          IF(ANK.GT.0.0)THEN
            ICNT=ICNT+1
            DTERM2=DLOG(DBLE(ANK))
            IF(IK.EQ.0 .OR. IK.EQ.1)THEN
              DTERM3=DLOG(1.0D0)
            ELSEIF(IK.EQ.2)THEN
              DTERM3=DLOG(2.0D0)
            ELSE
              DTERM3=DLNGAM(DBLE(AK+1.0))
            ENDIF
            Y2(ICNT)=REAL(DTERM2 + DTERM3 - DTERM1)
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=ALAMB - AK*LOG(ALAMB)
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=1.0
            WEIGHH(ICNT)=1.0
            WEIGHV(ICNT)=1.0
          ENDIF
!
          IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'POIZ')THEN
            WRITE(ICOUT,2011)I,AK,ANK
 2011       FORMAT('I,AK,ANK = ',I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2012)DTERM1,DTERM2,DTERM3
 2012       FORMAT('DTERM1,DTERM2,DTERM3 = ',3G15.7)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2013)ICNT,Y2(ICNT),X2(ICNT)
 2013       FORMAT('ICNT,Y2(ICNT),X2(ICNT) = ',I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
 2000   CONTINUE
        NTEMP=ICNT
!
      ELSEIF(ICASPL.EQ.'GEOM')THEN
        ICNT=0
        DTERM1=DLOG(DBLE(NTOT))
        DO 2100 I=1,N2
          AK=X(I)
          IK=INT(AK+0.1)
          ANK=Y(I)
          IF(ANK.GT.0.0)THEN
            ICNT=ICNT+1
            DTERM2=DLOG(DBLE(ANK))
            Y2(ICNT)=REAL(DTERM2 - DTERM1)
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(LOG(PML) + AK*LOG(1.0 - PML))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=1.0
            WEIGHH(ICNT)=1.0
            WEIGHV(ICNT)=1.0
          ENDIF
!
          IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'POIZ')THEN
            WRITE(ICOUT,2111)I,AK,ANK,PML
 2111       FORMAT('I,AK,ANK,PML = ',I8,3G15.7)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2112)DTERM1,DTERM2
 2112       FORMAT('DTERM1,DTERM2 = ',2G15.7)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2113)ICNT,Y2(ICNT),X2(ICNT)
 2113       FORMAT('ICNT,Y2(ICNT),X2(ICNT) = ',I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
 2100   CONTINUE
        NTEMP=ICNT
!
      ELSEIF(ICASPL.EQ.'BINO')THEN
        ICNT=0
        DTERM1=DLOG(DBLE(NTOT))
        DO 2200 I=1,N2
          AK=X(I)
          IK=INT(AK+0.1)
          ANK=Y(I)
          INK=INT(ANK+0.1)
          IF(ANK.GT.0.0)THEN
            ICNT=ICNT+1
            DTERM2=DLOG(DBLE(ANK))
            ITEMP1=NTRIAL
            ITEMP2=IK
            DTERM3=DBINLN(ITEMP1,ITEMP2)
            Y2(ICNT)=REAL(DTERM2 - DTERM1 - DTERM3)
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(REAL(NTRIAL)*LOG(1.0-PML) +   &
                      AK*LOG(PML/(1.0-PML)))
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=1.0
            WEIGHH(ICNT)=1.0
            WEIGHV(ICNT)=1.0
          ENDIF
