          IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'POIZ')THEN
            WRITE(ICOUT,2311)I,NTRIAL,AK,ANK,PML
 2311       FORMAT('I,NTRIAL,AK,ANK,PML = ',2I8,3G15.7)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2312)DTERM1,DTERM2,DTERM3,ATEMP2
 2312       FORMAT('DTERM1,DTERM2,DTERM3,ATEMP2 = ',4G15.7)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2313)ICNT,Y2(ICNT),X2(ICNT)
 2313       FORMAT('ICNT,Y2(ICNT),X2(ICNT) = ',I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
 2300   CONTINUE
        NTEMP=ICNT
!
      ELSEIF(ICASPL.EQ.'LOGS')THEN
        ICNT=0
        DTERM1=DLOG(DBLE(NTOT))
        DO 2400 I=1,N2
          AK=X(I)
          IK=INT(AK+0.1)
          ANK=Y(I)
          IF(ANK.GT.0.0)THEN
            ICNT=ICNT+1
            DTERM2=DLOG(DBLE(ANK))
            DTERM3=DLOG(DBLE(AK))
            Y2(ICNT)=REAL(DTERM2 + DTERM3 - DTERM1)
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(-LOG(-LOG(1.0 - THETA)) + AK*LOG(THETA))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=1.0
            WEIGHH(ICNT)=1.0
            WEIGHV(ICNT)=1.0
          ENDIF
!
          IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'POIZ')THEN
            WRITE(ICOUT,2411)I,AK,ANK,PML
 2411       FORMAT('I,AK,ANK,PML = ',I8,3G15.7)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2412)DTERM1,DTERM2
 2412       FORMAT('DTERM1,DTERM2 = ',2G15.7)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2413)ICNT,Y2(ICNT),X2(ICNT)
 2413       FORMAT('ICNT,Y2(ICNT),X2(ICNT) = ',I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
 2400   CONTINUE
        NTEMP=ICNT
!
      ENDIF
!
!               ****************************************************
!               **  STEP 3.0--                                    **
!               **  NOW FIT A LINE TO THE POINTS ON THE PLOT.     **
!               **  USE FRIENDLY'S SUGGESTION OF WEIGHTING THE    **
!               **  POINTS WITH SQRT(N(K) - 1)                    **
!               ****************************************************
!
      ISTEPN='3'
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'POIZ')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IT=1
      I1=1
      I2=NTEMP
      I3=1
      I4=NTEMP
      XMAXHF=1.0
!
      CALL LINEAR(IT,I1,I2,X2,Y2,WEIGHH,WEIGHV,NTEMP,XMAXHF,I3,I4,   &
                  PPA0,PPA1,TEMP1,TEMP2,   &
                  ISUBRO,IBUGG3,IERROR)
!
      DO 3010 I=1,NTEMP
        ICNT=ICNT+1
        Y2(ICNT)=TEMP1(I)
        X2(ICNT)=X2(I)
        D2(ICNT)=2.0
 3010 CONTINUE
!
!     NOW COMPUTE THE APPROXIMATE CONFIDENCE INTERVALS
!
      ICNT2=0
!
      IF(ICASPL.EQ.'POIS')THEN
        DTERM1=DLOG(DBLE(NTOT))
        AN=REAL(NTOT)
        DO 3100 I=1,N2
          AK=X(I)
          IK=INT(AK+0.1)
          ANK=Y(I)
          INK=INT(ANK+0.1)
          IF(INK.GE.2)THEN
            ANKST=ANK - (0.8*ANK/AN) - 0.67
          ELSEIF(INK.EQ.1)THEN
            ANKST=1.0/EXP(1.0)
          ENDIF
          IF(ANK.GT.0.0)THEN
            ICNT=ICNT+1
            DTERM2=DLOG(DBLE(ANKST))
            IF(IK.EQ.0 .OR. IK.EQ.1)THEN
              DTERM3=DLOG(1.0D0)
            ELSEIF(IK.EQ.2)THEN
              DTERM3=DLOG(2.0D0)
            ELSE
              DTERM3=DLNGAM(DBLE(AK+1.0))
            ENDIF
            Y2(ICNT)=REAL(DTERM2 + DTERM3 - DTERM1)
            ATEMP=Y2(ICNT)
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=ALAMB - AK*LOG(ALAMB)
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=3.0
!
            ICNT2=ICNT2+1
            TEMP1(ICNT2)=Y2(ICNT)
            TEMP2(ICNT2)=X2(ICNT)
!
            PK=ANK/REAL(NTOT)
            ANUM=SQRT(1.0 - PK)
            ADEN=SQRT(ANK - (0.25*PK + 0.47)*SQRT(ANK))
            HK=1.96*ANUM/ADEN
            ICNT=ICNT+1
            Y2(ICNT)=ATEMP + HK
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=ALAMB - AK*LOG(ALAMB)
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=5.0
            ICNT=ICNT+1
            Y2(ICNT)=ATEMP - HK
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=ALAMB - AK*LOG(ALAMB)
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=6.0
          ENDIF
 3100   CONTINUE
!
        ITAG=6
        DTERM1=DLOG(DBLE(NTOT))
        AN=REAL(NTOT)
        DO 3110 I=1,N2
          AK=X(I)
          IK=INT(AK+0.1)
          ANK=Y(I)
          INK=INT(ANK+0.1)
          IF(INK.GE.2)THEN
            ANKST=ANK - (0.8*ANK/AN) - 0.67
          ELSEIF(INK.EQ.1)THEN
            ANKST=1.0/EXP(1.0)
          ENDIF
          IF(ANK.GT.0.0)THEN
            ITAG=ITAG+1
            DTERM2=DLOG(DBLE(ANKST))
            IF(IK.EQ.0 .OR. IK.EQ.1)THEN
              DTERM3=DLOG(1.0D0)
            ELSEIF(IK.EQ.2)THEN
              DTERM3=DLOG(2.0D0)
            ELSE
              DTERM3=DLNGAM(DBLE(AK+1.0))
            ENDIF
            ATEMP=REAL(DTERM2 + DTERM3 - DTERM1)
            PK=ANK/REAL(NTOT)
            ANUM=SQRT(1.0 - PK)
            ADEN=SQRT(ANK - (0.25*PK + 0.47)*SQRT(ANK))
            HK=1.96*ANUM/ADEN
            ICNT=ICNT+1
            Y2(ICNT)=ATEMP + HK
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=ALAMB - AK*LOG(ALAMB)
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=REAL(ITAG)
            ICNT=ICNT+1
            Y2(ICNT)=ATEMP - HK
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=ALAMB - AK*LOG(ALAMB)
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=REAL(ITAG)
          ENDIF
!
 3110   CONTINUE
        N2=ICNT
!
      ELSEIF(ICASPL.EQ.'GEOM')THEN
        DTERM1=DLOG(DBLE(NTOT))
        AN=REAL(NTOT)
        DO 3200 I=1,N2
          AK=X(I)
          IK=INT(AK+0.1)
          ANK=Y(I)
          INK=INT(ANK+0.1)
          IF(INK.GE.2)THEN
            ANKST=ANK - (0.8*ANK/AN) - 0.67
          ELSEIF(INK.EQ.1)THEN
            ANKST=1.0/EXP(1.0)
          ENDIF
          IF(ANK.GT.0.0)THEN
            ICNT=ICNT+1
            DTERM2=DLOG(DBLE(ANKST))
            Y2(ICNT)=REAL(DTERM2 - DTERM1)
            ATEMP=Y2(ICNT)
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(LOG(PML) + AK*LOG(1.0 - PML))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=3.0
!
            ICNT2=ICNT2+1
            TEMP1(ICNT2)=Y2(ICNT)
            TEMP2(ICNT2)=X2(ICNT)
!
            PK=ANK/REAL(NTOT)
            ANUM=SQRT(1.0 - PK)
            ADEN=SQRT(ANK - (0.25*PK + 0.47)*SQRT(ANK))
            HK=1.96*ANUM/ADEN
            ICNT=ICNT+1
            Y2(ICNT)=ATEMP + HK
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(LOG(PML) + AK*LOG(1.0 - PML))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=5.0
            ICNT=ICNT+1
            Y2(ICNT)=ATEMP - HK
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(LOG(PML) + AK*LOG(1.0 - PML))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=6.0
          ENDIF
 3200   CONTINUE
!
        ITAG=6
        DTERM1=DLOG(DBLE(NTOT))
        AN=REAL(NTOT)
        DO 3210 I=1,N2
          AK=X(I)
          IK=INT(AK+0.1)
          ANK=Y(I)
          INK=INT(ANK+0.1)
          IF(INK.GE.2)THEN
            ANKST=ANK - (0.8*ANK/AN) - 0.67
          ELSEIF(INK.EQ.1)THEN
            ANKST=1.0/EXP(1.0)
          ENDIF
          IF(ANK.GT.0.0)THEN
            ITAG=ITAG+1
            DTERM2=DLOG(DBLE(ANKST))
            DTERM3=DBINLN(NTRIAL,IK)
            ATEMP=REAL(DTERM2 - DTERM1 - DTERM3)
            PK=ANK/REAL(NTOT)
            ANUM=SQRT(1.0 - PK)
            ADEN=SQRT(ANK - (0.25*PK + 0.47)*SQRT(ANK))
            HK=1.96*ANUM/ADEN
            ICNT=ICNT+1
            Y2(ICNT)=ATEMP + HK
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(LOG(PML) + AK*LOG(1.0 - PML))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=REAL(ITAG)
            ICNT=ICNT+1
            Y2(ICNT)=ATEMP - HK
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(LOG(PML) + AK*LOG(1.0 - PML))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=REAL(ITAG)
          ENDIF
!
 3210   CONTINUE
        N2=ICNT
!
      ELSEIF(ICASPL.EQ.'BINO')THEN
        DTERM1=DLOG(DBLE(NTOT))
        AN=REAL(NTOT)
        DO 3300 I=1,N2
          AK=X(I)
          IK=INT(AK+0.1)
          ANK=Y(I)
          INK=INT(ANK+0.1)
          IF(INK.GE.2)THEN
            ANKST=ANK - (0.8*ANK/AN) - 0.67
          ELSEIF(INK.EQ.1)THEN
            ANKST=1.0/EXP(1.0)
          ENDIF
          IF(ANK.GT.0.0)THEN
            ICNT=ICNT+1
            DTERM2=DLOG(DBLE(ANKST))
            DTERM3=DBINLN(NTRIAL,IK)
            Y2(ICNT)=REAL(DTERM2 - DTERM1 - DTERM3)
            ATEMP=Y2(ICNT)
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(REAL(NTRIAL)*LOG(1.0-PML) +   &
                      AK*LOG(PML/(1.0-PML)))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=3.0
!
            ICNT2=ICNT2+1
            TEMP1(ICNT2)=Y2(ICNT)
            TEMP2(ICNT2)=X2(ICNT)
!
            IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'POIZ')THEN
              WRITE(ICOUT,3311)I,NTRIAL,AK,ANKST,PML
 3311         FORMAT('I,NTRIAL,AK,ANKST,PML = ',2I8,3G15.7)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,3312)DTERM1,DTERM2,DTERM3,ATEMP2
 3312         FORMAT('DTERM1,DTERM2,DTERM3,ATEMP2 = ',4G15.7)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,3313)ICNT,Y2(ICNT),X2(ICNT)
 3313         FORMAT('ICNT,Y2(ICNT),X2(ICNT) = ',I8,2G15.7)
              CALL DPWRST('XXX','BUG ')
            ENDIF
!
            PK=ANK/REAL(NTOT)
            ANUM=SQRT(1.0 - PK)
            ADEN=SQRT(ANK - (0.25*PK + 0.47)*SQRT(ANK))
            HK=1.96*ANUM/ADEN
            ICNT=ICNT+1
            Y2(ICNT)=ATEMP + HK
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(REAL(NTRIAL)*LOG(1.0-PML) +   &
                      AK*LOG(PML/(1.0-PML)))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=5.0
            ICNT=ICNT+1
            Y2(ICNT)=ATEMP - HK
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(REAL(NTRIAL)*LOG(1.0-PML) +   &
                      AK*LOG(PML/(1.0-PML)))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=6.0
!
            IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'POIZ')THEN
              WRITE(ICOUT,3321)PK,ANUM,ADEN,HK
 3321         FORMAT('PK,ANUM,ADEN,HK = ',4G15.7)
              CALL DPWRST('XXX','BUG ')
            ENDIF
!
          ENDIF
 3300   CONTINUE
!
        ITAG=6
        DTERM1=DLOG(DBLE(NTOT))
        AN=REAL(NTOT)
        DO 3310 I=1,N2
          AK=X(I)
          IK=INT(AK+0.1)
          ANK=Y(I)
          INK=INT(ANK+0.1)
          IF(INK.GE.2)THEN
            ANKST=ANK - (0.8*ANK/AN) - 0.67
          ELSEIF(INK.EQ.1)THEN
            ANKST=1.0/EXP(1.0)
          ENDIF
          IF(ANK.GT.0.0)THEN
            ITAG=ITAG+1
            DTERM2=DLOG(DBLE(ANKST))
            DTERM3=DBINLN(NTRIAL,IK)
            ATEMP=REAL(DTERM2 - DTERM1 - DTERM3)
            PK=ANK/REAL(NTOT)
            ANUM=SQRT(1.0 - PK)
            ADEN=SQRT(ANK - (0.25*PK + 0.47)*SQRT(ANK))
            HK=1.96*ANUM/ADEN
            ICNT=ICNT+1
            Y2(ICNT)=ATEMP + HK
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(REAL(NTRIAL)*LOG(1.0-PML) +   &
                      AK*LOG(PML/(1.0-PML)))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=REAL(ITAG)
            ICNT=ICNT+1
            Y2(ICNT)=ATEMP - HK
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(REAL(NTRIAL)*LOG(1.0-PML) +   &
                      AK*LOG(PML/(1.0-PML)))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=REAL(ITAG)
          ENDIF
!
 3310   CONTINUE
        N2=ICNT
!
      ELSEIF(ICASPL.EQ.'NBIN')THEN
        DTERM1=DLOG(DBLE(NTOT))
        AN=REAL(NTOT)
        DO 3400 I=1,N2
          AK=X(I)
          IK=INT(AK+0.1)
          ANK=Y(I)
          INK=INT(ANK+0.1)
          IF(INK.GE.2)THEN
            ANKST=ANK - (0.8*ANK/AN) - 0.67
          ELSEIF(INK.EQ.1)THEN
            ANKST=1.0/EXP(1.0)
          ENDIF
          IF(ANK.GT.0.0)THEN
            ICNT=ICNT+1
            DTERM2=DLOG(DBLE(ANKST))
            ITEMP1=KNB+IK-1
            ITEMP2=IK
            DTERM3=DBINLN(ITEMP1,ITEMP2)
            Y2(ICNT)=REAL(DTERM2 - DTERM1 - DTERM3)
            ATEMP=Y2(ICNT)
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(REAL(KNB)*LOG(PML) + AK*LOG(1.0-PML))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=3.0
!
            ICNT2=ICNT2+1
            TEMP1(ICNT2)=Y2(ICNT)
            TEMP2(ICNT2)=X2(ICNT)
!
            IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'POIZ')THEN
              WRITE(ICOUT,3411)I,KNB,AK,ANKST,PML
 3411         FORMAT('I,KNB,AK,ANKST,PML = ',2I8,3G15.7)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,3412)DTERM1,DTERM2,DTERM3,ATEMP2
 3412         FORMAT('DTERM1,DTERM2,DTERM3,ATEMP2 = ',4G15.7)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,3413)ICNT,Y2(ICNT),X2(ICNT)
 3413         FORMAT('ICNT,Y2(ICNT),X2(ICNT) = ',I8,2G15.7)
              CALL DPWRST('XXX','BUG ')
            ENDIF
!
            PK=ANK/REAL(NTOT)
            ANUM=SQRT(1.0 - PK)
            ADEN=SQRT(ANK - (0.25*PK + 0.47)*SQRT(ANK))
            HK=1.96*ANUM/ADEN
            ICNT=ICNT+1
            Y2(ICNT)=ATEMP + HK
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(REAL(KNB)*LOG(PML) + AK*LOG(1.0-PML))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=5.0
            ICNT=ICNT+1
            Y2(ICNT)=ATEMP - HK
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(REAL(KNB)*LOG(PML) + AK*LOG(1.0-PML))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=6.0
!
            IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'POIZ')THEN
              WRITE(ICOUT,3421)PK,ANUM,ADEN,HK
 3421         FORMAT('PK,ANUM,ADEN,HK = ',4G15.7)
              CALL DPWRST('XXX','BUG ')
            ENDIF
!
          ENDIF
 3400   CONTINUE
!
        ITAG=6
        DTERM1=DLOG(DBLE(NTOT))
        AN=REAL(NTOT)
        DO 3410 I=1,N2
          AK=X(I)
          IK=INT(AK+0.1)
          ANK=Y(I)
          INK=INT(ANK+0.1)
          IF(INK.GE.2)THEN
            ANKST=ANK - (0.8*ANK/AN) - 0.67
          ELSEIF(INK.EQ.1)THEN
            ANKST=1.0/EXP(1.0)
          ENDIF
          IF(ANK.GT.0.0)THEN
            ITAG=ITAG+1
            DTERM2=DLOG(DBLE(ANKST))
            ITEMP1=KNB+IK-1
            ITEMP2=IK
            DTERM3=DBINLN(ITEMP1,ITEMP2)
            ATEMP=REAL(DTERM2 - DTERM1 - DTERM3)
            PK=ANK/REAL(NTOT)
            ANUM=SQRT(1.0 - PK)
            ADEN=SQRT(ANK - (0.25*PK + 0.47)*SQRT(ANK))
            HK=1.96*ANUM/ADEN
            ICNT=ICNT+1
            Y2(ICNT)=ATEMP + HK
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(REAL(KNB)*LOG(PML) + AK*LOG(1.0-PML))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=REAL(ITAG)
            ICNT=ICNT+1
            Y2(ICNT)=ATEMP - HK
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(REAL(KNB)*LOG(PML) + AK*LOG(1.0-PML))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=REAL(ITAG)
          ENDIF
!
 3410   CONTINUE
        N2=ICNT
      ELSEIF(ICASPL.EQ.'LOGS')THEN
        DTERM1=DLOG(DBLE(NTOT))
        AN=REAL(NTOT)
        DO 3500 I=1,N2
          AK=X(I)
          IK=INT(AK+0.1)
          ANK=Y(I)
          INK=INT(ANK+0.1)
          IF(INK.GE.2)THEN
            ANKST=ANK - (0.8*ANK/AN) - 0.67
          ELSEIF(INK.EQ.1)THEN
            ANKST=1.0/EXP(1.0)
          ENDIF
          IF(ANK.GT.0.0)THEN
            ICNT=ICNT+1
            DTERM2=DLOG(DBLE(ANKST))
            DTERM3=DLOG(DBLE(AK))
            Y2(ICNT)=REAL(DTERM2 + DTERM3 - DTERM1)
            ATEMP=Y2(ICNT)
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(-LOG(-LOG(1.0 - THETA)) + AK*LOG(THETA))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=3.0
!
            ICNT2=ICNT2+1
            TEMP1(ICNT2)=Y2(ICNT)
            TEMP2(ICNT2)=X2(ICNT)
!
            PK=ANK/REAL(NTOT)
            ANUM=SQRT(1.0 - PK)
            ADEN=SQRT(ANK - (0.25*PK + 0.47)*SQRT(ANK))
            HK=1.96*ANUM/ADEN
            ICNT=ICNT+1
            Y2(ICNT)=ATEMP + HK
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(-LOG(-LOG(1.0 - THETA)) + AK*LOG(THETA))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=5.0
            ICNT=ICNT+1
            Y2(ICNT)=ATEMP - HK
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(-LOG(-LOG(1.0 - THETA)) + AK*LOG(THETA))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=6.0
          ENDIF
 3500   CONTINUE
!
        ITAG=6
        DTERM1=DLOG(DBLE(NTOT))
        AN=REAL(NTOT)
        DO 3510 I=1,N2
          AK=X(I)
          IK=INT(AK+0.1)
          ANK=Y(I)
          INK=INT(ANK+0.1)
          IF(INK.GE.2)THEN
            ANKST=ANK - (0.8*ANK/AN) - 0.67
          ELSEIF(INK.EQ.1)THEN
            ANKST=1.0/EXP(1.0)
          ENDIF
          IF(ANK.GT.0.0)THEN
            ITAG=ITAG+1
            DTERM2=DLOG(DBLE(ANKST))
            DTERM3=DLOG(DBLE(AK))
            ATEMP=REAL(DTERM2 + DTERM3 - DTERM1)
            PK=ANK/REAL(NTOT)
            ANUM=SQRT(1.0 - PK)
            ADEN=SQRT(ANK - (0.25*PK + 0.47)*SQRT(ANK))
            HK=1.96*ANUM/ADEN
            ICNT=ICNT+1
            Y2(ICNT)=ATEMP + HK
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(-LOG(-LOG(1.0 - THETA)) + AK*LOG(THETA))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=REAL(ITAG)
            ICNT=ICNT+1
            Y2(ICNT)=ATEMP - HK
!
            IF(IPOILV.EQ.'ON')THEN
              ATEMP2=-(-LOG(-LOG(1.0 - THETA)) + AK*LOG(THETA))
              Y2(ICNT)=Y2(ICNT) + ATEMP2
            ENDIF
!
            X2(ICNT)=AK
            D2(ICNT)=REAL(ITAG)
          ENDIF
!
 3510   CONTINUE
!
      ENDIF
!
      IT=1
      I1=1
      I2=ICNT2
      I3=1
      I4=ICNT2
      XMAXHF=1.0
!
      CALL LINEAR(IT,I1,I2,TEMP2,TEMP1,WEIGHH,WEIGHV,ICNT2,XMAXHF,   &
      I3,I4,   &
      PPA0AD,PPA1AD,TEMP3,TEMP4,   &
      ISUBRO,IBUGG3,IERROR)
!
      DO 4010 I=1,ICNT2
        ICNT=ICNT+1
        Y2(ICNT)=TEMP3(I)
        X2(ICNT)=X2(I)
        D2(ICNT)=4.0
 4010 CONTINUE
!
      N2=ICNT
!
      IF(ICASPL.EQ.'POIS')THEN
        ALMBPP=EXP(PPA1)
        ALMBP2=EXP(PPA1AD)
      ELSEIF(ICASPL.EQ.'GEOM')THEN
        PPP=1.0 - EXP(PPA1)
        PP2=1.0 - EXP(PPA1AD)
      ELSEIF(ICASPL.EQ.'LOGS')THEN
        THETPP=EXP(PPA1)
        THETP2=EXP(PPA1AD)
      ELSEIF(ICASPL.EQ.'BINO')THEN
        PPP=EXP(PPA1)/(1.0 + EXP(PPA1))
        PP2=EXP(PPA1AD)/(1.0 + EXP(PPA1AD))
      ELSEIF(ICASPL.EQ.'NBIN')THEN
        PPP=1.0 - EXP(PPA1)
        PP2=1.0 - EXP(PPA1AD)
      ENDIF
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'POIZ')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPOIZ--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IDATSW,N2,AN3,DENOM
 9013   FORMAT('IDATSW,N2,AN3,DENOM = ',A4,2X,I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,N2
          WRITE(ICOUT,9016)I,Y2(I),X2(I),D2(I)
 9016     FORMAT('I,Y2(I),X2(I),D2(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPPOIZ
      SUBROUTINE DPPOLY(PXSTAR,PYSTAR,PXEND,PYEND,   &
                        ILINPA,ILINCO,ILINC2,MAXLNZ,PLINTH,   &
                        AREGBA,IREBLI,IREBCO,IREBC2,MAXRGZ,PREBTH,   &
                        IREFSW,IREFCO,IREFC2,   &
                        IREPTY,IREPLI,IREPCO,IREPC2,PREPTH,PREPSP,   &
                        PTEXHE,PTEXWI,PTEXVG,PTEXHG,   &
                        IGRASW,IDIASW,   &
                        PGRAXF,PGRAYF,PDIAXC,PDIAYC,PDIAX2,PDIAY2,   &
                        PDIAHE,PDIAWI,PDIAVG,PDIAHG,   &
                        NUMDEV,IDMANU,IDMODE,IDMOD2,IDMOD3,   &
                        IDPOWE,IDCONT,IDCOLO,IDNVPP,IDNHPP,IDUNIT,   &
                        IDNVOF,IDNHOF,IDFONT,UNITSW,PDSCAL,   &
                        IBACCO,IBACC2,   &
                        IBUGD2,IFOUND,IERROR)
!
!     PURPOSE--DRAW A POLYGON, THE COORDINATES ARE IN STANDARDIZED UNITS
!              OF 0 TO 100.
!     NOTE--THE INPUT COORDINATES ARE AN ARRAY OF X AND Y VALUES
!     INPUT  ARGUMENTS--IHARG
!                     --IARGT
!                     --ARG
!                     --NUMARG
!                     --PXSTAR
!                     --PYSTAR
!     OUTPUT ARGUMENTS--PXEND
!                     --PYEND
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--97/7
!     ORIGINAL VERSION--JULY      1997.
!     UPDATED         --DECEMBER  2018. CHECK FOR DISCRETE, NULL, OR
!                                       NONE DEVICE
!     UPDATED         --DECEMBER  2018. SUPPORT FOR "DEVICE ... SCALE"
!                                       COMMAND
!     UPDATED         --OCTOBER   2020. SUPPORT FOR RGB COLOR
!
!-----NON-COMMON VARIABLES-----------------------------------------
!
      CHARACTER*4 ILINPA
      CHARACTER*4 ILINCO
!
      CHARACTER*4 IREBLI
      CHARACTER*4 IREBCO
      CHARACTER*4 IREFSW
      CHARACTER*4 IREFCO
      CHARACTER*4 IREPTY
      CHARACTER*4 IREPLI
      CHARACTER*4 IREPCO
!
      CHARACTER*4 IGRASW
      CHARACTER*4 IDIASW
!
      CHARACTER*4 IDMANU
      CHARACTER*4 IDMODE
      CHARACTER*4 IDMOD2
      CHARACTER*4 IDMOD3
      CHARACTER*4 IDPOWE
      CHARACTER*4 IDCONT
      CHARACTER*4 IDCOLO
      CHARACTER*4 IDFONT
      CHARACTER*4 UNITSW
!
      CHARACTER*4 IFOUND
      CHARACTER*4 IBUGD2
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IERROR
      CHARACTER*4 ISUBRO
!
      CHARACTER*4 IFIG
      CHARACTER*4 IBELSW
      CHARACTER*4 IERASW
      CHARACTER*4 IBACCO
      CHARACTER*4 ICOPSW
      CHARACTER*4 ITYPEO
!
      CHARACTER*4 IHFACT
      CHARACTER*4 IHFAC2
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 ICASEQ
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
!
      DIMENSION XP(MAXOBV)
      DIMENSION YP(MAXOBV)
!
      DIMENSION ILINPA(*)
      DIMENSION ILINCO(*)
      DIMENSION ILINC2(MAXLNZ,3)
      DIMENSION PLINTH(*)
!
      DIMENSION AREGBA(*)
      DIMENSION IREBLI(*)
      DIMENSION IREBCO(*)
      DIMENSION IREBC2(MAXRGZ,3)
      DIMENSION PREBTH(*)
      DIMENSION IREFSW(*)
      DIMENSION IREFCO(*)
      DIMENSION IREFC2(MAXRGZ,3)
      DIMENSION IREPTY(*)
      DIMENSION IREPLI(*)
      DIMENSION IREPCO(*)
      DIMENSION IREPC2(MAXRGZ,3)
      DIMENSION PREPTH(*)
      DIMENSION PREPSP(*)
      DIMENSION PDSCAL(*)
!
      DIMENSION IDMANU(*)
      DIMENSION IDMODE(*)
      DIMENSION IDMOD2(*)
      DIMENSION IDMOD3(*)
      DIMENSION IDPOWE(*)
      DIMENSION IDCONT(*)
      DIMENSION IDCOLO(*)
!CCCC ADD FOLLOWING LINE MARCH 1997.
      DIMENSION IDFONT(*)
      DIMENSION IDNVPP(*)
      DIMENSION IDNHPP(*)
      DIMENSION IDUNIT(*)
!
      DIMENSION IDNVOF(*)
      DIMENSION IDNHOF(*)
      DIMENSION IBACC2(*)
!
      DIMENSION ICOLIV(2)
      DIMENSION NIV(2)
!
      EQUIVALENCE (GARBAG(IGARB1),XP(1))
      EQUIVALENCE (GARBAG(IGARB2),YP(1))
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOM2.INC'
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='YES'
      IERROR='NO'
      IERRG4=IERROR
      IBUGQ=IBUGD2
      ISUBN1='DPPO'
      ISUBN2='LY  '
!
      ILOCFN=0
      NPTS=0
!
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'POLY')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPOLY--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)NUMARG,NUMDEV,IFIG
   53   FORMAT('NUMARG,NUMDEV,IFIG = ',2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NUMARG
          WRITE(ICOUT,56)I,IHARG(I),IARGT(I),ARG(I)
   56     FORMAT('I,IHARG(I),IARGT(I),ARG(I) = ',I8,2(2X,A4),G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        WRITE(ICOUT,57)PXSTAR,PYSTAR,PXEND,PYEND
   57   FORMAT('PXSTAR,PYSTAR,PXEND,PYEND = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,61)ILINPA(1),ILINCO(1),PLINTH(1)
   61   FORMAT('ILINPA(1),ILINCO(1),PLINTH(1) = ',2(A4,2X),G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)IREBLI(1),IREBCO(1),PREBTH(1),AREGBA(1)
   63   FORMAT('IREBLI(1),IREBCO(1),PREBTH(1),AREGBA(1) = ',   &
               2(A4,2X),2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,64)IREFSW(1),IREFCO(1)
   64   FORMAT('IREFSW(1),IREFCO(1) = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,65)IREPTY(1),IREPLI(1),IREPCO(1),PREPTH(1),PREPSP(1)
   65   FORMAT('IREPTY(1),IREPLI(1),IREPCO(1),PREPTH(1),PREPSP(1) = ',   &
               3(A4,2X),2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,69)PTEXHE,PTEXWI,PTEXVG,PTEXHG
   69   FORMAT('PTEXHE,PTEXWI,PTEXVG,PTEXHG = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,76)IGRASW,IDIASW
   76   FORMAT('IGRASW,IDIASW = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,77)PGRAXF,PGRAYF,PDIAXC,PDIAYC
   77   FORMAT('PGRAXF,PGRAYF,PDIAXC,PDIAYC = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,78)PDIAHE,PDIAWI,PDIAVG,PDIAHG
   78   FORMAT('PDIAHE,PDIAWI,PDIAVG,PDIAHG = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 81 I=1,NUMDEV
          WRITE(ICOUT,82)IDMANU(I),IDMODE(I),IDMOD2(I),IDMOD3(I)
   82     FORMAT('IDMANU(I),IDMODE(I),IDMOD2(I),IDMOD3(I) = ',   &
                 3(A4,2X),A4)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,83)IDPOWE(I),IDCONT(I),IDCOLO(I)
   83     FORMAT('IDPOWE(I),IDCONT(I),IDCOLO(I) = ',2(A4,2X),A4)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,84)IDNVPP(I),IDNHPP(I),IDUNIT(I)
   84     FORMAT('IDNVPP(I),IDNHPP(I),IDUNIT(I) = ',3I8)
          CALL DPWRST('XXX','BUG ')
   81   CONTINUE
        WRITE(ICOUT,88)IBUGG4,ISUBG4,IERRG4,IBUGD2,IFOUND,IERROR
   88   FORMAT('IBUGG4,ISUBG4,IERRG4,IBUGD2,IFOUND,IERROR = ',   &
               5(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IFIG='POLY'
      NUMPT=3
      NUMPT2=2*NUMPT
!
!               ********************************
!               **  STEP 0--                  **
!               **  STEP THROUGH EACH DEVICE  **
!               ********************************
!
      IF(NUMDEV.LE.0)GO TO 9000
      DO 8000 IDEVIC=1,NUMDEV
!
      IF(IDPOWE(IDEVIC).EQ.'OFF')GO TO 8000
      IF(IDMANU(IDEVIC).EQ.'OFF')GO TO 8000
      IF(IDMANU(IDEVIC).EQ.'NULL')GO TO 8000
      IF(IDMANU(IDEVIC).EQ.'NONE')GO TO 8000
      IF(IDMANU(IDEVIC).EQ.'DISC')GO TO 8000
!
      IMANUF=IDMANU(IDEVIC)
      IMODEL=IDMODE(IDEVIC)
      IMODE2=IDMOD2(IDEVIC)
      IMODE3=IDMOD3(IDEVIC)
      IGCONT=IDCONT(IDEVIC)
      IGCOLO=IDCOLO(IDEVIC)
      IGFONT=IDFONT(IDEVIC)
      NUMVPP=IDNVPP(IDEVIC)
      NUMHPP=IDNHPP(IDEVIC)
      ANUMVP=NUMVPP
      ANUMHP=NUMHPP
      IOFFSV=IDNVOF(IDEVIC)
      IOFFSH=IDNHOF(IDEVIC)
      IGUNIT=IDUNIT(IDEVIC)
      PCHSCA=PDSCAL(IDEVIC)
!
!               ************************************
!               **  STEP 1--                      **
!               **  CARRY OUT OPENING OPERATIONS  **
!               **  ON THE GRAPHICS DEVICES       **
!               ************************************
!
      CALL DPOPDE
!
      IBELSW='OFF'
      NUMRIN=0
      IERASW='OFF'
      IBACCO='JUNK'
!
      CALL DPOPPL(IGRASW,IBELSW,NUMRIN,IERASW,IBACCO,IBACC2)
!
!               *****************************************
!               **  STEP 2--                           **
!               **  SEARCH FOR COMMAND SPECIFICATIONS  **
!               *****************************************
!
      IF(NUMARG.GE.3.AND.IHARG(1).EQ.'ABSO')GO TO 1112
      IF(NUMARG.GE.3.AND.IHARG(1).EQ.'RELA')GO TO 1113
      IF(NUMARG.GE.2) GO TO 1111
      GO TO 1130
!
 1111 CONTINUE
      ITYPEO='ABSO'
      ILOCFN=1
      GO TO 1119
!
 1112 CONTINUE
      ITYPEO='ABSO'
      ILOCFN=2
      GO TO 1119
!
 1113 CONTINUE
      ITYPEO='RELA'
      ILOCFN=2
      GO TO 1119
 1119 CONTINUE
!
      IF(ILOCFN.GT.NUMARG)GO TO 1129
      GO TO 1149
 1129 CONTINUE
      GO TO 1130
!
 1130 CONTINUE
      IERRG4='YES'
      WRITE(ICOUT,1131)
 1131 FORMAT('***** ERROR IN DPPOLY--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1132)
 1132 FORMAT('      ILLEGAL FORM FOR POLYGON ',   &
      'COMMAND.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1134)
 1134 FORMAT('      TEST EXAMPLE TO DEMONSTRATE THE ',   &
      'PROPER FORM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1135)
 1135 FORMAT('      SUPPOSE IT IS DESIRED TO DRAW AN POLYGON ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1136)
 1136 FORMAT('      WITH COORDINATES STORED IN THE ARRAYS X AND Y')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1141)
 1141 FORMAT('      THEN THE ALLOWABLE FORMS ARE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1142)
 1142 FORMAT('      POLYGON X Y')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1143)
 1143 FORMAT('      POLYGON ABSOLUTE X Y')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1144)
 1144 FORMAT('      POLYGON RELATIVE X Y')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
 1149 CONTINUE
!
!               *****************************************
!               **  STEP 4--                           **
!               **  SEARCH FOR COMMAND ARGUMENTS       **
!               *****************************************
!
      ICASEQ='FULL'
      ILOCQ=NUMARG+1
      IF(NUMARG.LT.1)GO TO 2190
      DO 2100 J=1,NUMARG
      J1=J
      IF(IHARG(J).EQ.'SUBS'.AND.IHARG2(J).EQ.'ET  ') GO TO 2110
      IF(IHARG(J).EQ.'EXCE'.AND.IHARG2(J).EQ.'PT  ') GO TO 2110
      IF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    ') GO TO 2120
 2100 CONTINUE
      GO TO 2190
 2110 CONTINUE
      ICASEQ='SUBS'
      ILOCQ=J1
      GO TO 2190
 2120 CONTINUE
      ICASEQ='FOR'
      ILOCQ=J1
      GO TO 2190
 2190 CONTINUE
      IF(IBUGD2.EQ.'OFF')GO TO 2195
      WRITE(ICOUT,2191)NUMARG,ILOCQ
 2191 FORMAT('NUMARG,ILOCQ = ',2I8)
      CALL DPWRST('XXX','BUG ')
 2195 CONTINUE
!
      DO 530 J=ILOCFN,ILOCFN+1
      IFAC=J-ILOCFN+1
      IHFACT=IHARG(IFAC)
      IHFAC2=IHARG2(IFAC)
      IHWUSE='V'
      MESSAG='YES'
      CALL CHECKN(IHFACT,IHFAC2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      ICOLIV(IFAC)=IVALUE(ILOCV)
      NIV(IFAC)=IN(ILOCV)
      IF(IBUGD2.EQ.'ON')WRITE(ICOUT,532)IFAC,IHFACT,IHFAC2,ICOLIV(IFAC),   &
      NIV(IFAC)
  532 FORMAT('I,IHFACT,IHFAC2,ICOLIV(IFAC),NIV(IFAC) = ',   &
      I8,2X,A4,2X,A4,I8,I8)
      IF(IBUGD2.EQ.'ON')CALL DPWRST('XXX','BUG ')
  530 CONTINUE
!
      IF(NIV(1).NE.NIV(2))GO TO 550
      GO TO 590
!
  550 CONTINUE
      WRITE(ICOUT,551)
  551 FORMAT('***** ERROR IN DPPOLY--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,552)
  552 FORMAT('      FOR A POLYGON, THE NUMBER OF ELEMENTS IN THE',   &
      ' TWO ARRAYS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,555)
  555 FORMAT('      SHOULD HAVE THE SAME AS THE NUMBER OF ELEMENTS;')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,557)
  557 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,561)
  561 FORMAT('      THE TWO VARIABLES HAVE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,566)NIV(ILOCFN),NIV(ILOCFN)
  566 FORMAT('      ',I8,I8,' ELEMENTS RESPECTIVELY.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,567)
  567 FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)WRITE(ICOUT,568)(IANS(I),I=1,IWIDTH)
  568 FORMAT(80A1)
      IF(IWIDTH.GE.1)CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
  590 CONTINUE
!
!               *****************************************
!               **  STEP 7--                           **
!               **  BRANCH TO THE APPROPRIATE SUBCASE; **
!               **  THEN FORM THE RESPONSE VARIABLE    **
!               **  AND THE FACTORS                    **
!               *****************************************
!
      ISTEPN='7'
!
      IF(ICASEQ.EQ.'FULL')GO TO 610
      IF(ICASEQ.EQ.'SUBS')GO TO 620
      IF(ICASEQ.EQ.'FOR')GO TO 630
!
  610 CONTINUE
      DO 615 I=1,NIV(1)
      ISUB(I)=1
  615 CONTINUE
      NQ=NIV(1)
      GO TO 650
!
  620 CONTINUE
      NIOLD=NIV(1)
      CALL DPSUBS(NIOLD,ILOCS,NS,IBUGQ,IERROR)
      NQ=NIOLD
      GO TO 650
!
  630 CONTINUE
      NIOLD=NIV(1)
      CALL DPFOR(NIOLD,NFOR,IROW1,IROWN,   &
      NLOCAL,ILOCS,NS,IBUGQ,IERROR)
      NQ=NFOR
      GO TO 650
!
  650 CONTINUE
      J=0
      IMAX=NIV(1)
      IF(NQ.LT.NIV(1))IMAX=NQ
      DO 660 I=1,IMAX
      IF(ISUB(I).EQ.0)GO TO 660
      J=J+1
!
      IJ=MAXN*(ICOLIV(1)-1)+I
      IF(ICOLIV(1).LE.MAXCOL)XP(J)=V(IJ)
      IF(ICOLIV(1).EQ.MAXCP1)XP(J)=PRED(I)
      IF(ICOLIV(1).EQ.MAXCP2)XP(J)=RES(I)
      IF(ICOLIV(1).EQ.MAXCP3)XP(J)=YPLOT(I)
      IF(ICOLIV(1).EQ.MAXCP4)XP(J)=XPLOT(I)
      IF(ICOLIV(1).EQ.MAXCP5)XP(J)=X2PLOT(I)
      IF(ICOLIV(1).EQ.MAXCP6)XP(J)=TAGPLO(I)
!
      ICOLR=ICOLIV(2)
      IJ=MAXN*(ICOLR-1)+I
      IF(ICOLR.LE.MAXCOL)YP(J)=V(IJ)
      IF(ICOLR.EQ.MAXCP1)YP(J)=PRED(I)
      IF(ICOLR.EQ.MAXCP2)YP(J)=RES(I)
      IF(ICOLR.EQ.MAXCP3)YP(J)=YPLOT(I)
      IF(ICOLR.EQ.MAXCP4)YP(J)=XPLOT(I)
      IF(ICOLR.EQ.MAXCP5)YP(J)=X2PLOT(I)
      IF(ICOLR.EQ.MAXCP6)YP(J)=TAGPLO(I)
!
  660 CONTINUE
      NPTS=J
!
!               ****************************
!               **  STEP 3--              **
!               **  DRAW OUT THE LINE(S)  **
!               ****************************
!
      IF(UNITSW.EQ.'DATA')THEN
        CALL DPCODS('X',XP(1),XP(1),IBUGD2,ISUBRO,IERROR)
        CALL DPCODS('Y',YP(1),YP(1),IBUGD2,ISUBRO,IERROR)
      ENDIF
      DO 1170 I=2,NPTS
        IF(UNITSW.EQ.'DATA')THEN
          CALL DPCODS('X',XP(I),XP(I),IBUGD2,ISUBRO,IERROR)
          IF(ITYPEO.EQ.'RELA')XP(I)=XP(I-1)+XP(I)
          CALL DPCODS('Y',YP(I),YP(I),IBUGD2,ISUBRO,IERROR)
          IF(ITYPEO.EQ.'RELA')YP(I)=YP(I-1)+YP(I)
        ENDIF
!
 1170 CONTINUE
!
      CALL DPPOL2(XP,YP,NPTS,IFIG,   &
                  ILINPA,ILINCO,ILINC2,MAXLNZ,PLINTH,   &
                  AREGBA,IREBLI,IREBCO,IREBC2,MAXRGZ,PREBTH,   &
                  IREFSW,IREFCO,IREFC2,   &
                  IREPTY,IREPLI,IREPCO,IREPC2,PREPTH,PREPSP,   &
                  PTEXHE,PTEXWI,PTEXVG,PTEXHG)
!
      PXEND=XP(NPTS)
      PYEND=YP(NPTS)
!
!               ************************************
!               **  STEP 4--                      **
!               **  CARRY OUT CLOSING OPERATIONS  **
!               **  ON THE GRAPHICS DEVICES       **
!               ************************************
!
      ICOPSW='OFF'
      NUMCOP=0
      CALL DPCLPL(ICOPSW,NUMCOP,   &
      PGRAXF,PGRAYF,   &
      IGRASW,PDIAXC,PDIAYC,PDIAX2,PDIAY2,   &
      PDIAHE,PDIAWI,PDIAVG,PDIAHG)
!
      CALL DPCLDE
!
 8000 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'POLY')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPOLY--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ILOCFN,NPTS
 9012   FORMAT('ILOCFN,NPTS = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NPTS.GT.0)THEN
          DO 9013 I=1,NPTS
            WRITE(ICOUT,9014)I,XP(I),YP(I)
 9014       FORMAT('I,XP(I),YP(I) = ',I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
 9013     CONTINUE
        ENDIF
        WRITE(ICOUT,9015)PXSTAR,PYSTAR,PXEND,PYEND
 9015   FORMAT('PXSTAR,PYSTAR,PXEND,PYEND = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9027)IFOUND,IERROR
 9027   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPOLY
      SUBROUTINE DPPOL2(X,Y,NPTS,IFIG,   &
                        ILINPA,ILINCO,ILINC2,MAXLN,PLINTH,   &
                        AREGBA,IREBLI,IREBCO,IREBC2,MAXRG,PREBTH,   &
                        IREFSW,IREFCO,IREFC2,   &
                        IREPTY,IREPLI,IREPCO,IREPC2,PREPTH,PREPSP,   &
                        PTEXHE,PTEXWI,PTEXVG,PTEXHG)
!
!     PURPOSE--DRAW A POLYGON.  COORDINATES OF THE POLYGON ARE STORED IN
!              THE ARRAYS X AND Y
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--97/7
!     ORIGINAL VERSION--JULY      1997.
!     UPDATED         --OCTOBER   2020. SUPPORT FOR RGB COLOR
!
!-----NON-COMMON VARIABLES-------------------------------------
!
      CHARACTER*4 IPATT2
      CHARACTER*4 IFIG
!
      CHARACTER*4 ILINPA
      CHARACTER*4 ILINCO
!
      CHARACTER*4 IREBLI
      CHARACTER*4 IREBCO
      CHARACTER*4 IREFSW
      CHARACTER*4 IREFCO
      CHARACTER*4 IREPTY
      CHARACTER*4 IREPLI
      CHARACTER*4 IREPCO
!
      CHARACTER*4 IPATT
      CHARACTER*4 ICOLF
      CHARACTER*4 ICOLP
      CHARACTER*4 ICOL
      CHARACTER*4 IFLAG
!
      DIMENSION X(*)
      DIMENSION Y(*)
!
      DIMENSION ILINPA(*)
      DIMENSION ILINCO(*)
      DIMENSION ILINC2(MAXLN,3)
      DIMENSION PLINTH(*)
!
      DIMENSION AREGBA(*)
      DIMENSION IREBLI(*)
      DIMENSION IREBCO(*)
      DIMENSION IREBC2(MAXRG,3)
      DIMENSION PREBTH(*)
      DIMENSION IREFSW(*)
      DIMENSION IREFCO(*)
      DIMENSION IREFC2(MAXRG,3)
      DIMENSION IREPTY(*)
      DIMENSION IREPLI(*)
      DIMENSION IREPCO(*)
      DIMENSION IREPC2(MAXRG,3)
      DIMENSION PREPTH(*)
      DIMENSION PREPSP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'POL2')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPPOL2--')
      CALL DPWRST('XXX','BUG ')
      DO 52 I=1,NPTS
      WRITE(ICOUT,53)I,X(I),Y(I)
   53 FORMAT('I,X,Y = ',I6,2E15.7)
   52 CONTINUE
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,59)IFIG
   59 FORMAT('IFIG = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,61)ILINPA(1),ILINCO(1),PLINTH(1)
   61 FORMAT('ILINPA(1),ILINCO(1),PLINTH(1) = ',A4,2X,A4,E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,62)AREGBA(1)
   62 FORMAT('AREGBA(1) = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,63)IREBLI(1),IREBCO(1),PREBTH(1)
   63 FORMAT('IREBLI(1),IREBCO(1),PREBTH(1) = ',A4,2X,A4,E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,64)IREFSW(1),IREFCO(1)
   64 FORMAT('IREFSW(1),IREFCO(1) = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,65)IREPTY(1),IREPLI(1),IREPCO(1),PREPTH(1),PREPSP(1)
   65 FORMAT('IREPTY(1),IREPLI(1),IREPCO(1),PREPTH(1),PREPSP(1) = ',   &
      A4,2X,A4,2X,A4,2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,69)PTEXHE,PTEXWI
   69 FORMAT('PTEXHE,PTEXWI= ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,70)PTEXVG,PTEXHG
   70 FORMAT('PTEXVG,PTEXHG= ',2E15.6)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,79)IBUGG4,ISUBG4,IERRG4
   79 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               *********************************
!               **  STEP 1--                   **
!               **  DETERMINE THE COORDINATES  **
!               **  FOR THE POLYGON            **
!               *********************************
!
!
      IF(X(1).EQ.X(NPTS).AND.Y(1).EQ.Y(NPTS))THEN
        NP=NPTS
      ELSE
        NP=NPTS+1
        X(NP)=X(1)
        Y(NP)=Y(1)
      ENDIF
!
!               ***********************
!               **  STEP 2--         **
!               **  FILL THE FIGURE  **
!               **  (IF CALLED FOR)  **
!               ***********************
!
      IF(IREFSW(1).EQ.'OFF')GO TO 2190
      IPATT=IREPTY(1)
      IPATT2='SOLI'
      PTHICK=PREPTH(1)
      PXGAP=PREPSP(1)
      PYGAP=PREPSP(1)
      ICOLF=IREFCO(1)
      ICOLFR=IREFC2(1,1)
      ICOLFG=IREFC2(1,2)
      ICOLFB=IREFC2(1,3)
      ICOLP=IREPCO(1)
      ICOLPR=IREPC2(1,1)
      ICOLPG=IREPC2(1,2)
      ICOLPB=IREPC2(1,3)
      ICOLBR=IREBC2(1,1)
      ICOLBG=IREBC2(1,2)
      ICOLBB=IREBC2(1,3)
      CALL DPFIRE(X,Y,NP,   &
                  IFIG,IPATT,PTHICK,PXGAP,PYGAP,   &
                  ICOLF,ICOLFR,ICOLFG,ICOLFB,   &
                  ICOLP,ICOLPR,ICOLPG,ICOLPB,   &
                  IPATT2)
 2190 CONTINUE
!
!               ***************************
!               **  STEP 3--             **
!               **  DRAW OUT THE FIGURE  **
!               ***************************
!
      IPATT=ILINPA(1)
      PTHICK=PLINTH(1)
      ICOL=ILINCO(1)
      ICOLR=ILINC2(1,1)
      ICOLG=ILINC2(1,2)
      ICOLB=ILINC2(1,3)
      IFLAG='ON'
      CALL DPDRPL(X,Y,NP,   &
                  IFIG,IPATT,PTHICK,   &
                  ICOL,ICOLR,ICOLG,ICOLB,   &
                  JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'POL2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPOL2--')
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,NP
          WRITE(ICOUT,9016)I,X(I),Y(I)
 9016     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
        WRITE(ICOUT,9039)IBUGG4,ISUBG4,IERRG4
 9039   FORMAT('IBUGG4,ISUBG4,IERRG4 = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPOL2
      SUBROUTINE DPPOPL(XVAL,YVAL,NPNTS,   &
                        XPOLY,YPOLY,XPOLY2,YPOLY2,NPOLY,   &
                        TAG,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--POINTS IN POLYGON (I.E., DETERMINE WHETHER POINTS
!              ARE INSIDE OR OUTSIDE OF A POLYGON, ON THE EDGE,
!              OR EQUAL TO A VERTEX).  FORTRAN IMPLEMENTATION
!              OF O'ROURKE InPoly1 C ROUTINE.
!     INPUT  ARGUMENTS--XVAL   = A REAL VECTOR CONTAINING THE X
!                                COORDINATES OF THE POINTS
!                     --YVAL   = A REAL VECTOR CONTAINING THE Y
!                                COORDINATES OF THE POINTS
!                     --NPOINT = NUMBER OF POINTS IN XVAL, YVAL
!                     --XPOLY  = A REAL VECTOR CONTAINING THE X
!                                COORDINATES OF THE POLYGON
!                     --YPOLY  = A REAL VECTOR CONTAINING THE Y
!                                COORDINATES OF THE POLYGON
!                     --NPOLY  = NUMBER OF POINTS IN XPOLY, YPOLY
!     OUTPUT ARGUMENTS--TAG    = THE OUTPUT ARRAY THAT CONTAINS:
!                                    1 = INTERIOR POINT
!                                    2 = EXTERIOR POINT
!                                    3 = EDGE     POINT
!                                    4 = VERTEX   POINT
!     REFERENCE--O'ROURKE (1998), "COMPUTATIONAL GEOMETRY IN C",
!                SECOND EDITION, CAMBRIDGE UNIVERSITY PRESS, PP.
!                239-245.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2011.9
!     ORIGINAL VERSION--SEPTEMBER 2011.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
      REAL XVAL(*)
      REAL YVAL(*)
      REAL XPOLY(*)
      REAL YPOLY(*)
      REAL XPOLY2(*)
      REAL YPOLY2(*)
      REAL TAG(*)
      INTEGER NPNTS
      INTEGER NPOLY
      INTEGER RCROSS
      INTEGER LCROSS
      INTEGER LTEMP1
      INTEGER LTEMP2
      LOGICAL RSTRAD
      LOGICAL LSTRAD
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      INCLUDE 'DPCOP2.INC'
!
      DATA EPS /0.0000001/
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'POPL')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF GATHER--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,NPNTS,NPOLY
   52   FORMAT('IBUGA3,ISUBRO,NPNTS,NPOLY = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NPOLY.GT.0)THEN
          DO 65 I=1,NPOLY
            WRITE(ICOUT,66)I,XPOLY(I),YPOLY(I)
   66       FORMAT('I,XPOLY(I),YPOLY(I) = ',I8,2X,2G15.7)
            CALL DPWRST('XXX','BUG ')
   65     CONTINUE
        ENDIF
      ENDIF
!
!     CHECK IF FIRST POINT IN POLYGON IS EQUAL TO LAST POINT.
!
      IF(XPOLY(1).EQ.XPOLY(NPOLY) .AND. YPOLY(1).EQ.YPOLY(NPOLY))THEN
        NPOLY=NPOLY-1
      ENDIF
!
      DO 100 IROW=1,NPNTS
!
!       LOOP THROUGH EACH OF THE POINTS
!
        X1=XVAL(IROW)
        Y1=YVAL(IROW)
        TAG(IROW)=-99.0
        RCROSS=0
        LCROSS=0
!
!       SHIFT POLYGON COORDINATES SO THAT POINT IS ORIGIN
!
        DO 110 I=1,NPOLY
          XPOLY2(I)=XPOLY(I)-X1
          YPOLY2(I)=YPOLY(I)-Y1
  110   CONTINUE
!
!       FOR EACH EDGE, SEE IF IT CROSSES RAYS
!
        DO 200 II=0,NPOLY-1
          I1=MOD(II+NPOLY-1,NPOLY)
          I=II+1
          I1=I1+1
!CCCC     IF(XPOLY2(I).EQ.0.0 .AND. YPOLY2(I).EQ.0.0)THEN
          IF(ABS(XPOLY2(I)).LT.EPS .AND. ABS(YPOLY2(I)).LT.EPS)THEN
            TAG(IROW)=4.0
            GO TO 100
          ENDIF
!
!         CHECK IF EDGE STRADLES X-AXIS WITH BIAS ABOVE/BELOW
!
          RSTRAD=.FALSE.
          LSTRAD=.FALSE.
          LTEMP1=0
          LTEMP2=0
          IF(YPOLY2(I).GT.0.0)LTEMP1=1
          IF(YPOLY2(I1).GT.0.0)LTEMP2=1
          IF(LTEMP1.NE.LTEMP2)RSTRAD=.TRUE.
          LTEMP1=0
          LTEMP2=0
          IF(YPOLY2(I).LT.0.0)LTEMP1=1
          IF(YPOLY2(I1).LT.0.0)LTEMP2=1
          IF(LTEMP1.NE.LTEMP2)LSTRAD=.TRUE.
!
          IF(RSTRAD .OR. LSTRAD)THEN
            TEMP1=XPOLY2(I)*YPOLY2(I1) - XPOLY2(I1)*YPOLY2(I)
            TEMP2=YPOLY2(I1) - YPOLY2(I)
            XTEMP=TEMP1/TEMP2
            IF(RSTRAD .AND. XTEMP.GT.0.0)RCROSS=RCROSS+1
            IF(LSTRAD .AND. XTEMP.LT.0.0)LCROSS=LCROSS+1
          ENDIF
!
  200   CONTINUE
!
        IF(MOD(RCROSS,2) .NE. MOD(LCROSS,2))THEN
          TAG(IROW)=3.0
        ELSEIF(MOD(RCROSS,2).EQ.1)THEN
          TAG(IROW)=1.0
        ELSE
          TAG(IROW)=2.0
        ENDIF
!
  100 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'POPL')THEN
        WRITE(ICOUT,9051)
 9051   FORMAT('***** AT THE END OF DPPOPL--')
        CALL DPWRST('XXX','BUG ')
        DO 9055 I=1,NPNTS
          WRITE(ICOUT,9056)I,XVAL(I),YVAL(I),TAG(I)
 9056     FORMAT('I,XVAL(I),YVAL(I),TAG(I) = ',I8,2X,3G15.7)
          CALL DPWRST('XXX','BUG ')
 9055   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPPOPL
      SUBROUTINE DPPOTA(Y1,YSTAT,TEMPZ,MAXNXT,   &
                        ISEED,   &
                        ICAPSW,IFORSW,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--GENERATE A POSITION-TABULATION FOR ONE OF DATAPLOT'S
!              SUPPORTED UNIVARIATE STATISTICS.
!
!              FOR EXAMPLE, GIVEN THE COMMAND
!
!                   MEAN POSITION TABULATION A B C D E
!
!              WHERE A, B, C, D, AND E ARE EITHER ALL MATRICES OR
!              VECTORS OF THE SAME DIMENSION.  FOR EXAMPLE, IF
!              THEY ARE ALL 5x5 MATRICES, THEN THE OUTPUT WILL
!              BE A SET OF 25 MEANS.  THE FIRST MEAN WILL BE THE
!              MEAN OF A(1,1), B(1,1), C(1,1), D(1,1), and E(1,1).
!              THAT IS, THE POSITION BY POSITION MEANS WILL BE
!              COMPUTED.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2011/9
!     ORIGINAL VERSION--SEPTEMBER 2011.
!     UPDATED         --AUGUST    2023. CALL LIST TO CMPSTA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=50)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ISTADF
      CHARACTER*4 ISTARA
      CHARACTER*60 ISTANM
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION YSTAT(*)
      DIMENSION TEMPZ(*)
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
      INCLUDE 'DPCOZI.INC'
      INCLUDE 'DPCOZD.INC'
!
      DIMENSION XTEMP1(MAXOBV)
      DIMENSION XTEMP2(MAXOBV)
      DIMENSION XTEMP3(MAXOBV)
      DIMENSION XTEMP4(MAXOBV)
      DIMENSION XTEMP5(MAXOBV)
      DIMENSION XROW(MAXOBV)
      DIMENSION XCOL(MAXOBV)
      DIMENSION ITEMP1(MAXOBV)
      DIMENSION ITEMP2(MAXOBV)
      DIMENSION ITEMP3(MAXOBV)
      DIMENSION ITEMP4(MAXOBV)
      DIMENSION ITEMP5(MAXOBV)
      DIMENSION ITEMP6(MAXOBV)
      DOUBLE PRECISION DTEMP1(MAXOBV)
      DOUBLE PRECISION DTEMP2(MAXOBV)
      DOUBLE PRECISION DTEMP3(MAXOBV)
!
      EQUIVALENCE (GARBAG(IGARB1),XTEMP1(1))
      EQUIVALENCE (GARBAG(IGARB2),XTEMP2(1))
      EQUIVALENCE (GARBAG(IGARB3),XTEMP3(1))
      EQUIVALENCE (GARBAG(IGARB4),XROW(1))
      EQUIVALENCE (GARBAG(IGARB5),XCOL(1))
      EQUIVALENCE (GARBAG(IGARB6),XTEMP4(1))
      EQUIVALENCE (GARBAG(IGARB7),XTEMP5(1))
!
      EQUIVALENCE (IGARBG(IIGAR1),ITEMP1(1))
      EQUIVALENCE (IGARBG(IIGAR2),ITEMP2(1))
      EQUIVALENCE (IGARBG(IIGAR3),ITEMP3(1))
      EQUIVALENCE (IGARBG(IIGAR4),ITEMP4(1))
      EQUIVALENCE (IGARBG(IIGAR5),ITEMP5(1))
      EQUIVALENCE (IGARBG(IIGAR6),ITEMP6(1))
!
      EQUIVALENCE (DGARBG(IDGAR1),DTEMP1(1))
      EQUIVALENCE (DGARBG(IDGAR2),DTEMP2(1))
      EQUIVALENCE (DGARBG(IDGAR3),DTEMP3(1))
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
      ISUBN1='DPPO'
      ISUBN2='TA  '
!
!               *********************************************
!               **  TREAT THE POSITIONAL-TABULATION  CASE  **
!               *********************************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'POTA')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPOTA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGA2,IBUGA3,IBUGQ,ISUBRO
   53   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***************************
!               **  STEP 1--             **
!               **  EXTRACT THE COMMAND  **
!               ***************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'POTA')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               *******************************************************
!               **  STEP 1.5--                                       **
!               **  SEARCH FOR COMMAND                               **
!               *******************************************************
!
      IF(ICOM.EQ.'POSI' .AND. IHARG(1).EQ.'TABU')THEN
        JMIN=2
      ELSE
        IFOUND='NO'
        GO TO 9000
      ENDIF
      JMAX=MIN(NUMARG,JMIN+6)
!
      CALL EXTSTA(ICOM,ICOM2,IHARG,IHARG2,IARGT,ARG,NUMARG,JMIN,JMAX,   &
                  ICASPL,ISTANM,ISTANR,ISTADF,ISTARA,   &
                  IFOUND,ILOCV,ISUBRO,IBUGA3,IERROR)
!
      IF(ISTANR.GT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN POSITIONAL TABULATION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)
  103   FORMAT('      THIS COMMAND IS ONLY SUPPORTED FOR UNIVARIATE ',   &
               'STATISTICS.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,105)ISTANM
  105   FORMAT('      THE STATISTIC: ',A60)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,107)ISTANR
  107   FORMAT('      EXPECTS ',I1,' RESPONSE VARIABLES.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      ILASTC=ILOCV-1
      IF(ILASTC.GE.1)THEN
        CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      ENDIF
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'POTA')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='POSITIONAL TABULATION'
      MINNA=1
      MAXNA=100
      MINN2=1
      IFLAGE=1
      IFLAGM=2
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=1
      MAXNVA=MAXSPN
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'POTA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               *****************************************************
!               **  STEP 8--                                       **
!               **  COMPUTE THE APPROPRIATE POSITIONAL-TABULATION  **
!               **  STATISTIC--                                    **
!               *****************************************************
!
      ISTEPN='8'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'POTA')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPPOT9(Y1,YSTAT,NUMVAR,ICASPL,ISTANM,ISTARA,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,INAME,   &
                  MAXCOL,V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                  TEMPZ,XROW,XCOL,XTEMP1,XTEMP2,XTEMP3,XTEMP4,XTEMP5,   &
                  ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                  DTEMP1,DTEMP2,DTEMP3,   &
                  ICAPSW,ICAPTY,IFORSW,MAXNXT,MAXN,ISEED,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'POTA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPOTA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR
 9012   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPOTA
      SUBROUTINE DPPOT9(Y,YSTAT,NUMVAR,ICASPL,ISTANM,ISTARA,   &
                        IVARN1,IVARN2,IVARTY,PVAR,   &
                        ILIS,NRIGHT,ICOLR,ISUB,NQ,INAME,   &
                        MAXCOL,V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                        TEMPZ,XROW,XCOL,XTEMP1,XTEMP2,XTEMP3,   &
                        XTEMP4,XTEMP5,   &
                        ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                        DTEMP1,DTEMP2,DTEMP3,   &
                        ICAPSW,ICAPTY,IFORSW,MAXNXT,MAXN,ISEED,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--GENERATE A POSITION-TABULATION FOR ONE OF DATAPLOT'S
!              SUPPORTED UNIVARIATE STATISTICS.
!
!              FOR EXAMPLE, GIVEN THE COMMAND
!
!                   MEAN POSITION TABULATION A B C D E
!
!              WHERE A, B, C, D, AND E ARE EITHER ALL MATRICES OR
!              VECTORS OF THE SAME DIMENSION.  FOR EXAMPLE, IF
!              THEY ARE ALL 5x5 MATRICES, THEN THE OUTPUT WILL
!              BE A SET OF 25 MEANS.  THE FIRST MEAN WILL BE THE
!              MEAN OF A(1,1), B(1,1), C(1,1), D(1,1), and E(1,1).
!              THAT IS, THE POSITION BY POSITION MEANS WILL BE
!              COMPUTED.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     REFERENCE--ASTM MANUAL STP-15D, PAGES 78-84, 100-105
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2011/9
!     ORIGINAL VERSION--SEPTEMBER 2011.
!     UPDATED         --AUGUST    2023. CALL LIST TO CMPSTA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IVARN1(*)
      CHARACTER*4 IVARN2(*)
      CHARACTER*4 IVARTY(*)
      CHARACTER*40 INAME
      CHARACTER*40 ISTANM
      CHARACTER*4 ICASPL
      CHARACTER*4 ISTARA
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 ICASE
      CHARACTER*4 IOP
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION YSTAT(*)
      DIMENSION TEMPZ(*)
      DIMENSION XROW(*)
      DIMENSION XCOL(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION XTEMP3(*)
      DIMENSION XTEMP4(*)
      DIMENSION XTEMP5(*)
      DIMENSION PVAR(*)
!
      REAL    V(*)
      REAL    PRED(*)
      REAL    RES(*)
      REAL    YPLOT(*)
      REAL    XPLOT(*)
      REAL    X2PLOT(*)
      REAL    TAGPLO(*)
!
      INTEGER ILIS(*)
      INTEGER NRIGHT(*)
      INTEGER ICOLR(*)
      INTEGER ISUB(*)
      INTEGER ITEMP1(*)
      INTEGER ITEMP2(*)
      INTEGER ITEMP3(*)
      INTEGER ITEMP4(*)
      INTEGER ITEMP5(*)
      INTEGER ITEMP6(*)
!
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION DTEMP2(*)
      DOUBLE PRECISION DTEMP3(*)
!
      PARAMETER(NUMCLI=3)
      PARAMETER(MAXLIN=1)
      PARAMETER (MAXROW=40)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUZ(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPPO'
      ISUBN2='T9  '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'POT9')THEN
        WRITE(ICOUT,70)
   70   FORMAT('AT THE BEGINNING OF DPPOT9--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,71)ICASPL,INAME
   71   FORMAT('ICASPL,INAME = ',A4,2X,A40)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,72)NUMVAR,NQ,PVAR(1),PVAR(2)
   72   FORMAT('NUMVAR,NQ,PVAR(1),PVAR(2) = ',2I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 75 I=1,NQ
          WRITE(ICOUT,77)I,ISUB(I)
   77     FORMAT('I,ISUB(I) = ',2I8)
          CALL DPWRST('XXX','BUG ')
   75   CONTINUE
      ENDIF
!
      ICOL=1
      NROW=NRIGHT(1)
      IF(IVARTY(1).EQ.'VARI')THEN
        NCOL=1
      ELSE
        ILISR=ILIS(ICOL)
        ICOL1=IVALUE(ILISR)
        ICOL2=IVALU2(ILISR)
        NCOL=(ICOL2 - ICOL1) + 1
      ENDIF
!
!     NOW LOOP OVER THE ROWS/COLUMNS OF THE ARGUMENTS
!
      ICNT=0
      DO 100 JCOL=1,NCOL
        DO 200 IROW=1,NROW
          ICNT2=0
          DO 300 ICOL=1,NUMVAR
            CALL DPPAR9(ICOL,IVALUE,IVALU2,IN,MAXN,MAXNXT,IROW,JCOL,   &
                        INAME,IVARN1,IVARN2,IVARTY,   &
                        ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVAR,   &
                        MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                        MAXCP4,MAXCP5,MAXCP6,   &
                        V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                        AVAL,NCOLZ,ICASE,   &
                        IBUGA3,ISUBRO,IERROR)
            IF(IERROR.EQ.'YES')GO TO 9000
            IF(NCOLZ.NE.NCOL .AND. ICASE.EQ.'MATR')THEN
              WRITE(ICOUT,999)
  999         FORMAT(1X)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,301)
  301         FORMAT('***** ERROR IN POSITIONAL TABULATION--')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,303)ICOL
  303         FORMAT('      MATRIX ',I2,' DOES NOT HAVE THE EXPECTED ',   &
                     'NUMBER OF COLUMNS.')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,305)NCOLZ
  305         FORMAT('      NUMBER OF COLUMNS           = ',I8)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,307)NCOL
  307         FORMAT('      NUMBER OF COLUMNS EXPECTED  = ',I8)
              CALL DPWRST('XXX','BUG ')
              IERROR='YES'
              GO TO 9000
            ENDIF
            ICNT2=ICNT2+1
            Y(ICNT2)=AVAL
  300     CONTINUE
!
!         NOW COMPUTE THE DESIRED STATISTIC
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'POT9')THEN
            WRITE(ICOUT,351)IROW,ICOL,ICNT2
  351       FORMAT('IROW,ICOL,ICNT2 = ',3I8)
            CALL DPWRST('XXX','BUG ')
            IF(ICNT2.GE.1)THEN
              DO 355 II=1,ICNT2
                WRITE(ICOUT,358)II,Y(II)
  358           FORMAT('II,Y(II) = ',I8,G15.7)
                CALL DPWRST('XXX','BUG ')
  355         CONTINUE
            ENDIF
          ENDIF
!
          IF(ICNT2.GE.1)THEN
            NUMV2=1
            CALL CMPSTA(Y,TEMPZ,TEMPZ,XTEMP1,XTEMP2,XTEMP3,   &
                        XTEMP4,XTEMP5,   &
                        MAXNXT,ICNT2,ICNT2,ICNT2,NUMV2,ICASPL,ISTARA,   &
                        ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                        DTEMP1,DTEMP2,DTEMP3,   &
                        RIGHT,   &
                        ISUBRO,IBUGA3,IERROR)
            ICNT=ICNT+1
            XROW(ICNT)=REAL(IROW)
            XCOL(ICNT)=REAL(JCOL)
            IF(IERROR.EQ.'YES' .OR. RIGHT.EQ.CPUMIN)THEN
              YSTAT(ICNT)=PSTAMV
            ELSE
              YSTAT(ICNT)=RIGHT
            ENDIF
          ELSE
            ICNT=ICNT+1
            XROW(ICNT)=REAL(IROW)
            XCOL(ICNT)=REAL(JCOL)
            YSTAT(ICNT)=PSTAMV
          ENDIF
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'POT9')THEN
            WRITE(ICOUT,371)ICNT,XROW(ICNT),XCOL(ICNT),YSTAT(ICNT)
  371       FORMAT('ICNT,XROW(ICNT),XCOL(ICNT),YSTAT(ICNT) = ',   &
                   I8,2F8.0,G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
!
  200   CONTINUE
  100 CONTINUE
!
!     WRITE RESULTS TO "dpst1f.dat"
!
      IOP='OPEN'
      IFLG11=1
      IFLG21=0
      IFLG31=0
      IFLAG4=0
      IFLAG5=0
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      DO 510 I=1,ICNT
        WRITE(IOUNI1,'(3E15.7)')XROW(I),XCOL(I),YSTAT(I)
  510 CONTINUE
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
!
!               ****************************
!               **  STEP 5--              **
!               **  WRITE EVERYTHING OUT  **
!               ****************************
!
      ISTEPN='5'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'POT9')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      NUMDIG=-7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=10
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE='Positional Tabulation ('
      ITITLE(24:59)=ISTANM(1:35)
      NCTITL=59
      DO 4010 I=59,1,-1
        IF(ITITLE(I:I).NE.' ')THEN
          NCTITL=I+1
          ITITLE(NCTITL:NCTITL)=')'
          GO TO 4019
        ENDIF
 4010 CONTINUE
 4019 CONTINUE
!
      ITITLZ=' '
      NCTITZ=0
!
      ITITL2(1,1)='Row'
      NCTIT2(1,1)=3
      ITITL2(1,2)='Column'
      NCTIT2(1,2)=6
      ITITL2(1,3)='Statistic'
      NCTIT2(1,3)=9
!
      NUMLIN=1
      NUMCOL=3
      N2=ICNT
!
      NMAX=0
      DO 4210 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        IDIGIT(I)=0
        NTOT(I)=8
        IF(I.EQ.3)THEN
          NTOT(I)=15
          IDIGIT(I)=NUMDIG
        ENDIF
        NMAX=NMAX+NTOT(I)
        ITYPCO(I)='NUME'
 4210 CONTINUE
!
      IWHTML(1)=100
      IWHTML(2)=100
      IWHTML(3)=150
      IJUNK=1200
      IWRTF(1)=IJUNK
      IWRTF(2)=IWRTF(1)+IJUNK
      IWRTF(3)=IWRTF(2)+2000
      IFRST=.TRUE.
      IFLAGS=.TRUE.
      ILAST=.TRUE.
      IFLAGE=.FALSE.
!
      ICALL=0
      ICNT=0
      DO 4310 I=1,N2
        IF(ICNT.GE.40)THEN
          IF(I.EQ.N2)IFLAGE=.TRUE.
          CALL DPDTA5(ITITLE,NCTITL,   &
                      ITITLZ,NCTITZ,ITITL2,NCTIT2,   &
                      MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                      IVALUZ,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                      IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                      ICAPSW,ICAPTY,IFRST,ILAST,   &
                      IFLAGS,IFLAGE,   &
                      ISUBRO,IBUGA3,IERROR)
          IFRST=.FALSE.
          IFLAGS=.FALSE.
          ICALL=1
          ICNT=0
        ENDIF
        ICNT=ICNT+1
        NCTEXT(ICNT)=0
        AMAT(ICNT,1)=XROW(I)
        AMAT(ICNT,2)=XCOL(I)
        AMAT(ICNT,3)=YSTAT(I)
        DO 4320 J=1,NUMCOL
          NCVALU(ICNT,J)=0
          IVALUZ(ICNT,J)=' '
 4320   CONTINUE
 4310 CONTINUE
!
      IF(ICNT.GE.1)THEN
        IFLAGE=.TRUE.
        ILAST=.TRUE.
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITLZ,NCTITZ,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUZ,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'POT9')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPOT9--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPOT9
      SUBROUTINE DPPOTP(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                        IBOOSS,ISEED,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        IBUGG2,IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--GENERATE A PAIR OF COORDINATE VECTORS
!              THAT WILL DEFINE A PEAKS OVER THRESHOLD PLOT--
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005/4
!     ORIGINAL VERSION--APRIL     2005.
!     UPDATED         --JULY      2010. USE DPDTA1, DPDTA2 TO
!                                       GENERATE TABLES
!     UPDATED         --MAY       2010. USE DPPARS AND DPPAR3 TO PERFORM
!                                       THE COMMAND PARSING
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IAND1
      CHARACTER*4 IAND2
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGG2
      CHARACTER*4 IBUGG3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 IHP
      CHARACTER*4 IHP2
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION Y1(MAXOBV)
      DIMENSION XTEMP1(MAXOBV)
      DIMENSION XTEMP2(MAXOBV)
      DIMENSION XTEMP3(MAXOBV)
      DIMENSION XTEMP4(MAXOBV)
      DIMENSION XTEMP5(MAXOBV)
      DIMENSION XTEMP6(MAXOBV)
      DIMENSION XTEMP7(MAXOBV)
      DIMENSION XTEMP8(MAXOBV)
      DIMENSION XTEMP9(MAXOBV)
      DIMENSION XTMP10(MAXOBV)
      DIMENSION ITEMP1(MAXOBV)
      DIMENSION R(MAXOBV)
      DOUBLE PRECISION DTEMP1(MAXOBV)
      INCLUDE 'DPCOZZ.INC'
      INCLUDE 'DPCOZI.INC'
      INCLUDE 'DPCOZD.INC'
      EQUIVALENCE (GARBAG(IGARB1),Y1(1))
      EQUIVALENCE (GARBAG(IGARB2),XTEMP1(1))
      EQUIVALENCE (GARBAG(IGARB3),XTEMP2(1))
      EQUIVALENCE (GARBAG(IGARB4),XTEMP3(1))
      EQUIVALENCE (GARBAG(IGARB5),XTEMP4(1))
      EQUIVALENCE (GARBAG(IGARB6),XTEMP5(1))
      EQUIVALENCE (GARBAG(IGARB7),XTEMP6(1))
      EQUIVALENCE (GARBAG(IGARB8),XTEMP7(1))
      EQUIVALENCE (GARBAG(IGARB9),XTEMP8(1))
      EQUIVALENCE (GARBAG(IGAR10),XTEMP9(1))
      EQUIVALENCE (GARBAG(JGAR11),XTMP10(1))
      EQUIVALENCE (GARBAG(JGAR12),R(1))
      EQUIVALENCE (IGARBG(1),ITEMP1(1))
      EQUIVALENCE (DGARBG(1),DTEMP1(1))
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DATA MINSIZ/5/
      DATA MINSI2/30/
!
      IFOUND='NO'
      IERROR='NO'
      ISUBN1='DPPO'
      ISUBN2='TP  '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      MAXV2=2
      MINN2=MINSIZ
!
!               **************************************************
!               **  TREAT THE PEAKS OVER THRESHOLD    PLOT CASE **
!               **************************************************
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'POTP')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPOTP--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ICASPL,IAND1,IAND2
   52   FORMAT('ICASPL,IAND1,IAND2 = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGG2,IBUGG3,IBUGQ,ISUBRO
   53   FORMAT('IBUGG2,IBUGG3,IBUGQ,ISUBRO = ',A4,2X,A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***************************
!               **  STEP 1--             **
!               **  EXTRACT THE COMMAND  **
!               ***************************
!
      ISTEPN='1'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'POTP')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASPL='POTP'
!
      IF(ICOM.EQ.'POT ')THEN
         IF(NUMARG.GE.1)THEN
            IF(IHARG(1).EQ.'PLOT')THEN
               ILASTC=1
               GO TO 119
            ENDIF
         ENDIF
      ENDIF
!
      IF(ICOM.EQ.'PEAK')THEN
         IF(NUMARG.GE.3)THEN
            IF(IHARG(1).EQ.'OVER'.AND.IHARG(2).EQ.'THRE'.AND.   &
              IHARG(3).EQ.'PLOT')THEN
               ILASTC=3
               GO TO 119
            ENDIF
         ENDIF
      ENDIF
!
      GO TO 9000
!
  119 CONTINUE
      CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      IFOUND='YES'
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'POTP')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='PEAKS OVER THRESHOLD PLOT'
      MINNA=1
      MAXNA=100
      IFLAGE=0
      IFLAGM=0
      IFLAGP=0
      JMIN=1
      MINNVA=1
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'POTP')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I),IVARTY(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I),IVARTY(I) = ',I8,2X,A4,A4,2X,3I8,2X,A4)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               ****************************************
!               **  STEP 3--                          **
!               **  PUT THE DATA INTO Y1 AND R        **
!               ****************************************
!
      ISTEPN='3'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'POTP')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICOL=1
      CALL DPPAR4(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                  INAME,IVARN1,IVARN2,IVARTY,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVAR,   &
                  MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                  MAXCP4,MAXCP5,MAXCP6,   &
                  V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                  Y1,R,NLOCAL,NRET,IFLAGM,IFLAGE,   &
                  IBUGG3,ISUBRO,IFOUND,IERROR)
!
      IF(NLOCAL.LT.MINSIZ)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,351)
  351   FORMAT('***** ERROR IN PEAKS OVER THRESHOLD PLOT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,352)MINSIZ
  352   FORMAT('      THE NUMBER OF OBSERVATIONS IN THE RESPONSE ',   &
               'VARIABLE MUST BE AT LEAST ',I5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,354)NLOCAL
  354   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               *****************************************************
!               **  STEP 4--                                       **
!               **  FORM THE VERTICAL AND HORIZONTAL AXIS          **
!               **  VALUES Y(.) AND X(.) FOR THE PLOT.             **
!               **  RESET THE VECTOR D(.) TO ALL ONES.             **
!               **  DEFINE THE NUMBER OF PLOT POINTS    (NPLOTP).  **
!               **  DEFINE THE NUMBER OF PLOT VARIABLES (NPLOTV).  **
!               *****************************************************
!
      ISTEPN='4'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'POTP')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPOTME.EQ.'PPCC')THEN
        IHP='GAMM'
        IHP2='A1  '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')THEN
          GAMMA1=-3.0
        ELSE
          GAMMA1=VALUE(ILOCP)
        ENDIF
!
        IHP='GAMM'
        IHP2='A2  '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')THEN
          GAMMA2=3.0
        ELSE
          GAMMA2=VALUE(ILOCP)
        ENDIF
!
        IF(GAMMA1.GT.GAMMA2)THEN
          GAMMSV=GAMMA1
          GAMMA1=GAMMA2
          GAMMA2=GAMMSV
        ENDIF
      ENDIF
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'POTP')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)
  811   FORMAT('***** FROM THE MIDDLE  OF DPPOTP--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,812)ICASPL,IPOTME,NUMV2
  812   FORMAT('ICASPL,IPOTME,NUMV2 = ',A4,2X,A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      CALL DPPOT2(Y1,NLOCAL,ICASPL,MINSIZ,MINSI2,MAXOBV,   &
                  XTEMP1,XTEMP2,XTEMP3,XTEMP4,XTEMP5,XTEMP6,XTEMP7,   &
                  XTEMP8,XTEMP9,XTMP10,ITEMP1,DTEMP1,   &
                  R,NRET,   &
                  ICAPSW,ICAPTY,IFORSW,GAMMA1,GAMMA2,   &
                  IBOOSS,ISEED,MINMAX,   &
                  Y,X,D,NPLOTP,NPLOTV,IBUGG3,ISUBRO,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'POTP')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF DPPOTP--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR
 9012   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2
 9013   FORMAT('NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2 = ',   &
               I8,I8,I8,2X,A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        IF(NPLOTP.GE.1)THEN
          DO 9020 I=1,NPLOTP
            WRITE(ICOUT,9021)I,Y(I),X(I),D(I)
 9021       FORMAT('I,Y(I),X(I),D(I) = ',I8,3F12.5)
            CALL DPWRST('XXX','BUG ')
 9020     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPPOTP
      SUBROUTINE DPPOT2(Y,N,ICASPL,MINSIZ,MINSI2,MAXNXT,   &
                        XTEMP1,XTEMP2,XTEMP3,XTEMP4,XTEMP5,   &
                        XTEMP6,XTEMP7,   &
                        XTEMP8,XTEMP9,XTMP10,ITEMP1,DTEMP1,   &
                        R,NRET,   &
                        ICAPSW,ICAPTY,IFORSW,GAMMA1,GAMMA2,   &
                        IBOOSS,ISEED,MINMAX,   &
                        Y2,X2,D2,N2,NPLOTV,IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--GENERATE A PAIR OF COORDINATE VECTORS
!              THAT WILL DEFINE A PEAKS OVER THRESHOLD PLOT
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005/04
!     ORIGINAL VERSION--APRIL      2005.
!     UPDATED         --JULY       2010. USE DPDTA1 TO PRINT OUTPUT
!     UPDATED         --JULY       2010. MODIFY HOW PPCC VALUE IS
!                                        GENERATED
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IPRISV
      CHARACTER*4 IFEESV
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 IMETHD
      CHARACTER*4 ICASJB
      CHARACTER*4 ICENSO
      CHARACTER*4 ICASP2
      CHARACTER*4 IOP
!
      INCLUDE 'DPCOST.INC'
!
      PARAMETER (MAXROW=20)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*40 ITEXT(MAXROW)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      LOGICAL IFRST
      LOGICAL ILAST
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DG
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DXR
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION XTEMP3(*)
      DIMENSION XTEMP4(*)
      DIMENSION XTEMP5(*)
      DIMENSION XTEMP6(*)
      DIMENSION XTEMP7(*)
      DIMENSION XTEMP8(*)
      DIMENSION XTEMP9(*)
      DIMENSION XTMP10(*)
      DIMENSION R(*)
      DIMENSION ITEMP1(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION D2(*)
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION XMOM(3)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPPO'
      ISUBN2='T2  '
      IERROR='NO'
      IWRITE='OFF'
!
      IPRISV=IPRINT
      IFEESV=IFEEDB
      SHAPE1=CPUMIN
      SHAPE2=CPUMIN
      XR50=CPUMIN
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'POT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LT.MINSI2)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
   31   FORMAT('***** ERROR IN PEAKS OVER THRESHOLD PLOT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)MINSI2
   32   FORMAT('      THE NUMBER OF OBSERVATIONS MUST BE AT LEAST ',   &
               I8,';')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,34)N
   34   FORMAT('      THE ENTERED NUMBER OF OBSERVATIONS HERE = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'POT2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,71)
   71   FORMAT('***** AT THE BEGINNING OF DPPOT2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,72)ICASPL,IPOTME,IPOTDI,IPOTIT,IPOTNP,N
   72   FORMAT('ICASPL,IPOTME,IPOTDI,IPOTIT,IPOTNP,N, = ',3(A4,2X),3I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,74)PPOTTH,PPOTIN,MINSIZ,MINSI2,NRET
   74   FORMAT('PPOTTH,PPOTIN,MINSIZ,MINSI2,NRET = ',2G15.7,3I8)
        CALL DPWRST('XXX','BUG ')
        DO 85 I=1,N
          WRITE(ICOUT,86)I,Y(I)
   86     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   85   CONTINUE
      ENDIF
!
!  THE BASIC ALGORITHM FOR GENERATING A PEAKS OVER THRESHOLDS
!  PLOT IS:
!
!  1. START WITH AN INITIAL THRESHOLD VALUE
!     USER CAN SPECIFY INITIAL THRESHOLD OR THE NUMBER OF POINTS
!     TO BE EXTRACTED FOR THE INITIAL THRESHOLD
!  2. EXTRACT THE POINTS IN THE DATA SET ABOVE THIS THRESHOLD
!  3. FOR THIS EXTRACTED DATA SET, ESTIMATE THE PARAMETERS OF
!     THE DISTRIBUTION.  NOTE THAT DATAPLOT ALLOWS YOU TO SELECT
!     BOTH THE TYPE OF DISTRIBUTION BEING ESTIMATED (GENERALIZED
!     PATRETO, WEIBULL, GUMBEL, OR FRECHET) AND THE METHOD USED
!     TO ESTIMATE THE PARAMETERS (AVAILABLE METHODS DEPEND ON
!     THE DISTRIBUTION).
!  4. CALCULATE A STANDARD DEVIATION FOR THE PARAMETER ESTIMATES.
!  5. INCREMENT THE THRESHOLD AND REPEAT STEPS 1-4.
!  6. PLOT THE RESULTING PARAMETER ESTIMATES ALONG WITH THE
!     "CONFIDENCE LIMITS" (USUALLY +/- 2*SD).
!
!               ********************************************
!               **  STEP 2--                              **
!               **  SORT THE DATA                         **
!               ********************************************
!
      ISTEPN='2'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'POT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NRET.GT.0)THEN
        IR50=0
        DO 101 I=1,NRET
          IF(ABS(R(I) - 50.0).LT.1.0)THEN
            IR50=1
            GO TO 109
          ENDIF
  101   CONTINUE
  109   CONTINUE
        IF(IR50.EQ.0)THEN
          NRET=NRET+1
          R(NRET)=50.0
        ENDIF
        CALL SORT(R,NRET,R)
        IR50=0
        DO 111 I=1,NRET
          IF(ABS(R(I) - 50.0).LT.1.0)THEN
            IR50=I
            GO TO 119
          ENDIF
  111   CONTINUE
  119   CONTINUE
      ENDIF
!
      CALL SORT(Y,N,XTEMP1)
      DO 210 I=1,N
        Y(I)=XTEMP1(I)
  210 CONTINUE
!
      IF(PPOTTH.GT.0.0)THEN
        ATHRSH=PPOTTH
      ELSEIF(IPOTNP.GT.0)THEN
        INDX=N-IPOTNP+1
        IF(INDX.LT.1)INDX=1
        IF(INDX.GT.N)INDX=N
        ATHRSH=Y(INDX)
      ELSE
        NKEEP=INT(REAL(N)*0.025 + 0.5)
        IF(NKEEP.LT.MINSIZ)NKEEP=MINSIZ
        ATHRSH=Y(N-NKEEP+1)
      ENDIF
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'POT2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,211)ATHRSH,PPOTIN,NKEEP,IPOTIT
  211   FORMAT('ATHRSH,PPOTIN,NKEEP,IPOTIT = ',2G15.7,2X,2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IOP='OPEN'
      IFLG1=1
      IFLG2=0
      IF(NRET.GT.0)IFLG2=1
      IFLG3=0
      IFLG4=0
      IFLG5=0
      CALL DPAUFI(IOP,IFLG1,IFLG2,IFLG3,IFLG4,IFLG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGG3,ISUBRO,IERROR)
!
!               ********************************************
!               **  STEP 3--                              **
!               **  LOOP THROUGH THE THRESHOLDS           **
!               ********************************************
!
      ISTEPN='3'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'POT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICNT=0
      NLOCSV=0
      DO 300 I=1,IPOTIT
!
        U=ATHRSH + REAL(I-1)*PPOTIN
        NLOCAL=0
        DO 310 J=1,N
          IF(Y(J).GE.U)THEN
            NLOCAL=NLOCAL+1
            XTEMP1(NLOCAL)=Y(J)
          ENDIF
  310   CONTINUE
!
        IF(NLOCAL.EQ.NLOCSV)GO TO 300
        NLOCSV=NLOCAL
!
        IF(NLOCAL.LT.MINSIZ)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,311)U
  311     FORMAT('***** WARNING--FOR A THRESHOLD OF ',G12.5)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,313)NLOCAL
  313     FORMAT('      ONLY ',I8,' ABOVE THE THRESHOLD.  THIS IS')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,315)MINSIZ
  315     FORMAT('      BELOW THE REQUIRED ',I8,'.  THIS ITERATION ',   &
                 'SKIPPED.')
          CALL DPWRST('XXX','BUG ')
          GO TO 300
        ENDIF
!
        IF(IPOTDI.EQ.'GPAR')THEN
!
!  DEHAAN METHOD
!
          IF(IPOTME.EQ.'DEHA')THEN
!
            IFEEDB='OFF'
            IPRINT='OFF'
!
            IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'POT2')THEN
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,321)ATHRSH,NKEEP
  321         FORMAT('BEFORE DPDEGP: ATHRSH,NKEEP = ',G15.7,2X,I8)
              CALL DPWRST('XXX','BUG ')
            ENDIF
!
            THRESH=CPUMIN
            IERROR='NO'
            CALL DPDEGP(XTEMP1,NLOCAL,MAXNXT,   &
                        GAMMA,A,GAMMSD,THRESH,   &
                        GAMMA2,ALOC,SCALE,   &
                        ALIKE,AIC,AICC,BIC,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        ISUBRO,IBUGG3,IERROR)
!
            IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'POT2')THEN
              WRITE(ICOUT,323)U,GAMMA,A,GAMMSD,IERROR
  323         FORMAT('AFTER DPDEGP: U,GAMMA,A,GAMMSD,IERROR = ',   &
                     4G15.7,2X,A4)
              CALL DPWRST('XXX','BUG ')
            ENDIF
!
            IF(IERROR.EQ.'YES')GO TO 9000
            IF(IGEPDF.NE.'SIMI')THEN
              GAMMA=-GAMMA
            ENDIF
!
            ICNT=ICNT+1
            Y2(ICNT)=GAMMA
            IF(IPOTAX.EQ.'POIN')THEN
              X2(ICNT)=REAL(NLOCAL)
            ELSE
              X2(ICNT)=U
            ENDIF
            D2(ICNT)=1.0
            IF(GAMMSD.GT.0.0)THEN
              ICNT=ICNT+1
              Y2(ICNT)=GAMMA + 2.0*GAMMSD
              IF(IPOTAX.EQ.'POIN')THEN
                X2(ICNT)=REAL(NLOCAL)
              ELSE
                X2(ICNT)=U
              ENDIF
              D2(ICNT)=2.0
              ICNT=ICNT+1
              Y2(ICNT)=GAMMA - 2.0*GAMMSD
              IF(IPOTAX.EQ.'POIN')THEN
                X2(ICNT)=REAL(NLOCAL)
              ELSE
                X2(ICNT)=U
              ENDIF
              D2(ICNT)=3.0
            ENDIF
!
            ASCALE=A
            ALOC=U
!
            IFEEDB=IFEESV
            IPRINT=IPRISV
!
!         CME METHOD
!
          ELSEIF(IPOTME.EQ.'CME')THEN
!
            IFEEDB='OFF'
            IPRINT='OFF'
!
            THRESH=0.0
            CALL DPCMGP(XTEMP1,NLOCAL,   &
                        GAMMA,A,GAMMSD,THRESH,   &
                        XTEMP2,XTEMP3,XTEMP4,ITEMP1,   &
                        ALIKE,AIC,AICC,BIC,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        ISUBRO,IBUGG3,IERROR)
            IF(IERROR.EQ.'YES')GO TO 9000
            IF(IGEPDF.NE.'SIMI')THEN
              GAMMA=-GAMMA
            ENDIF
!
            ICNT=ICNT+1
            Y2(ICNT)=GAMMA
            IF(IPOTAX.EQ.'POIN')THEN
              X2(ICNT)=REAL(NLOCAL)
            ELSE
              X2(ICNT)=U
            ENDIF
            D2(ICNT)=1.0
            IF(GAMMSD.GT.0.0)THEN
              ICNT=ICNT+1
              Y2(ICNT)=GAMMA + 2.0*GAMMSD
              IF(IPOTAX.EQ.'POIN')THEN
                X2(ICNT)=REAL(NLOCAL)
              ELSE
                X2(ICNT)=U
              ENDIF
              D2(ICNT)=2.0
              ICNT=ICNT+1
              Y2(ICNT)=GAMMA - 2.0*GAMMSD
              IF(IPOTAX.EQ.'POIN')THEN
                X2(ICNT)=REAL(NLOCAL)
              ELSE
                X2(ICNT)=U
              ENDIF
              D2(ICNT)=3.0
            ENDIF
!
            ASCALE=A
            ALOC=U
!
            IFEEDB=IFEESV
            IPRINT=IPRISV
!
!         PPCC METHOD
!
          ELSEIF(IPOTME.EQ.'PPCC')THEN
!
            IFEEDB='OFF'
            IPRINT='OFF'
!
!CCCC       NUMDIS=100
            NUMDIS=50
            ANUMDI=REAL(NUMDIS)
            GAMLL=GAMMA1
            GAMUL=GAMMA2
            CORRMX=-99.0
            MINMAX=1
            CALL UNIMED(NLOCAL,XTEMP2)
            DO 360 IDIS=1,NUMDIS
              AIDIS=IDIS
              SHAPE=GAMLL+((AIDIS-1.0)/(ANUMDI-1.0))*(GAMUL-GAMLL)
              ICNT2=0
              DO 370 II=1,NLOCAL
                ICNT2=ICNT2+1
                CALL GEPPPF(XTEMP2(II),SHAPE,MINMAX,IGEPDF,   &
                            XTEMP3(ICNT2))
  370         CONTINUE
!
              IWRITE='OFF'
              CALL CORR(XTEMP3,XTEMP1,NLOCAL,IWRITE,CC,IBUGG3,IERROR)
              IF(CC.GT.CORRMX)THEN
                CORRMX=CC
                SHAPE1=SHAPE
                CALL LINFI2(XTEMP3,XTEMP1,NLOCAL,   &
                            ALOC,SCALE,   &
                            ISUBRO,IBUGG3,IERROR)
              ENDIF
  360       CONTINUE
!
!  USE BOOTSTRAP TO OBTAIN 95% CONFIDENCE INTERVAL FOR
!  SHAPE PARAMETER
!
            ICASP2='GPAR'
            ICASJB='BOOT'
            ICENSO='OFF'
            IADEDF='OFF'
            ILGADF='OFF'
            ISKNDF='OFF'
            IMETHD='KAPL'
            NHOR1=0
            NPERC=0
            IPPCDP=0
!
            DO 380 IRESAM=1,IBOOSS
              IF(IBOOPA.EQ.'PARA')THEN
                IF(SHAPE1.EQ.0.0)THEN
                  CALL EXPRAN(NLOCAL,ISEED,XTEMP5)
                ELSE
                  CALL UNIRAN(NLOCAL,ISEED,XTEMP5)
                  DG=DBLE(SHAPE1)
                  IF(IGEPDF.EQ.'JOHN')THEN
                    DO 381 II=1,NLOCAL
                      DP=DBLE(XTEMP5(II))
                      DPPF=(-1.0D0/DG)*(((1.0D0-DP)**DG)-1.0D0)
                      XTEMP5(II)=REAL(DPPF)
  381               CONTINUE
                  ELSE
                    DO 382 II=1,NLOCAL
                      DP=DBLE(XTEMP5(II))
                      DPPF=(1.0D0/DG)*(((1.0D0-DP)**(-DG))-1.0D0)
                      XTEMP5(II)=REAL(DPPF)
  382               CONTINUE
                  ENDIF
                ENDIF
                NS3=NLOCAL
!
              ELSE
                CALL DPJBS3(XTEMP1,NLOCAL,ICASJB,IRESAM,ISEED,   &
                            XTEMP5,NS3,   &
                            ITEMP1,   &
                            XTEMP6,   &
                            IBUGG3,IERROR)
              ENDIF
              CALL SORT(XTEMP5,NLOCAL,XTEMP5)
!
!             NOW FIT BOOTSTRAP SAMPLE VIA PPCC METHOD
!
              CORRMX=-99.0
              MINMAX=1
              CALL UNIMED(NLOCAL,XTEMP2)
              DO 460 IDIS=1,NUMDIS
                AIDIS=IDIS
                SHAPE=GAMLL+((AIDIS-1.0)/(ANUMDI-1.0))*(GAMUL-GAMLL)
                ICNT2=0
                DO 470 II=1,NLOCAL
                  ICNT2=ICNT2+1
                  CALL GEPPPF(XTEMP2(II),SHAPE,MINMAX,IGEPDF,   &
                              XTEMP3(ICNT2))
  470           CONTINUE
!
                IWRITE='OFF'
                CALL CORR(XTEMP3,XTEMP5,NLOCAL,IWRITE,CC,IBUGG3,IERROR)
                IF(CC.GT.CORRMX)THEN
                  CORRMX=CC
                  SHAPE2=SHAPE
                ENDIF
  460         CONTINUE
              XTMP10(IRESAM)=SHAPE2
!
  380       CONTINUE
!
            IQUAME='ORDE'
            QNT=0.025
            NTEMP=IBOOSS
            CALL QUANT(QNT,XTMP10,NTEMP,IWRITE,XTEMP6,MAXNXT,   &
                       IQUAME,   &
                       XQU025,IBUGG3,IERROR)
            QNT=0.975
            CALL QUANT(QNT,XTMP10,NTEMP,IWRITE,XTEMP6,MAXNXT,   &
                       IQUAME,   &
                       XQU975,IBUGG3,IERROR)
!
            ICNT=ICNT+1
            Y2(ICNT)=SHAPE1
            IF(IPOTAX.EQ.'POIN')THEN
              X2(ICNT)=REAL(NLOCAL)
            ELSE
              X2(ICNT)=U
            ENDIF
            D2(ICNT)=1.0
            ICNT=ICNT+1
            Y2(ICNT)=XQU025
            IF(IPOTAX.EQ.'POIN')THEN
              X2(ICNT)=REAL(NLOCAL)
            ELSE
              X2(ICNT)=U
            ENDIF
            D2(ICNT)=2.0
            ICNT=ICNT+1
            Y2(ICNT)=XQU975
            IF(IPOTAX.EQ.'POIN')THEN
              X2(ICNT)=REAL(NLOCAL)
            ELSE
              X2(ICNT)=U
            ENDIF
            D2(ICNT)=3.0
!
            ASCALE=SCALE
            GAMMA=SHAPE1
!
            IFEEDB=IFEESV
            IPRINT=IPRISV
!
!           METHOD OF MOMENTS, L-MOMENTS, ELEMENTAL PERCENTILES,
!           MAXIMUM LIKELIHOOD
!
          ELSEIF(IPOTME.EQ.'MOME' .OR. IPOTME.EQ.'LMOM' .OR.   &
                 IPOTME.EQ.'EPER' .OR. IPOTME.EQ.'MLE')THEN
!
            IFEEDB='OFF'
            IPRINT='OFF'
!
            GAMMSV=CPUMIN
            SCALSV=CPUMIN
            MLFLAG=1
            IF(IPOTME.EQ.'MLE')MLFLAG=0
            CALL GEPML1(XTEMP1,NLOCAL,MAXNXT,MINMAX,   &
                        ICASPL,IGEPDF,IGEPSV,IDFTTY,   &
                        GAMMSV,SCALSV,ISEED,THRESH,   &
                        XTEMP2,XTEMP3,XTEMP4,XTEMP5,XTEMP6,XTEMP7,   &
                        DTEMP1,XMOM,NMOM,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,   &
                        ALOCMO,SCALMO,SHAPMO,   &
                        ALOCLM,SCALLM,SHAPLM,   &
                        ALOCEP,SCALEP,SHAPEP,   &
                        ALOCML,SCALML,SHAPML,MLFLAG,   &
                        NUSE,ZMEAN,ZVAR,ZSD,ALOC,   &
                        VARMM1,VARMM2,COVMOM,   &
                        VARML1,VARML2,COVML,   &
                        ISUBRO,IBUGG3,IERROR)
!
            IF(IPOTME.EQ.'MOME')THEN
              GAMMA=SHAPMO
            ELSEIF(IPOTME.EQ.'LMOM')THEN
              GAMMA=SHAPLM
            ELSEIF(IPOTME.EQ.'EPER')THEN
              GAMMA=SHAPEP
            ELSEIF(IPOTME.EQ.'MLE')THEN
              GAMMA=SHAPML
            ENDIF
            IF(GAMMA.EQ.CPUMIN)THEN
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,31)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,1011)I
 1011         FORMAT('      AT ITERATION ',I5,': UNABLE TO ESTIMATE ',   &
                     'GAMMA PARAMETER')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,1013)
 1013         FORMAT('      PEAKS OVER THRESHOLD PLOT NOT GENERATED.')
              CALL DPWRST('XXX','BUG ')
              IERROR='YES'
              GO TO 9000
            ENDIF
!
            ICNT=ICNT+1
            Y2(ICNT)=GAMMA
            X2(ICNT)=REAL(NLOCAL)
            D2(ICNT)=1.0
!
            IFEEDB=IFEESV
            IPRINT=IPRISV
          ENDIF
!
!         NOW DO THE FOLLOWING:
!
!         1) WRITE INFO TO DPST1F.DAT (POINTS ABOVE THRESHOLD,
!            THRESHOLD, ESTIMATES OF GAMMA, LOC, SCALE
!
!         2) IF REQUESTED, COMPUTE MEAN RECURRENCE INTERVALS.
!
!         3) WRITE MEAN RECURRENCE INTERVAL INFO TO FILE.
!
          WRITE(IOUNI1,'(I8,2X,4E15.7)')NLOCAL,U,GAMMA,ALOC,ASCALE
!
          IF(NRET.GT.0)THEN
            ALAMB=1.0
            IF(PPOTPE.GT.0.0)THEN
              ALAMB=REAL(NLOCAL)/(REAL(N)/PPOTPE)
            ENDIF
!
            IF(IPRINT.EQ.'OFF')GO TO 2399
!
            IF(I.EQ.1)THEN
              ITITLE='Peaks Over Threshold Analysis'
              NCTITL=29
            ELSE
              ITITLE=' '
              NCTITL=0
            ENDIF
            ITITLZ=' '
            NCTITZ=0
            ICNT2=1
            ITEXT(ICNT2)='Iteration:'
            WRITE(ITEXT(ICNT2)(12:16),'(I5)')I
            NCTEXT(ICNT2)=11
            AVALUE(ICNT2)=REAL(I)
            IDIGIT(ICNT2)=0
            ICNT2=ICNT2+1
            ITEXT(ICNT2)='Sample Size:'
            NCTEXT(ICNT2)=12
            AVALUE(ICNT2)=REAL(N)
            IDIGIT(ICNT2)=0
            ICNT2=ICNT2+1
            ITEXT(ICNT2)='Threshold:'
            NCTEXT(ICNT2)=10
            AVALUE(ICNT2)=U
            IDIGIT(ICNT2)=NUMDIG
            ICNT2=ICNT2+1
            ITEXT(ICNT2)='Number of Observations Above Threshold:'
            NCTEXT(ICNT2)=39
            AVALUE(ICNT2)=REAL(NLOCAL)
            IDIGIT(ICNT2)=0
            ICNT2=ICNT2+1
            ITEXT(ICNT2)='Value of Lambda:'
            NCTEXT(ICNT2)=16
            AVALUE(ICNT2)=ALAMB
            IDIGIT(ICNT2)=NUMDIG
            ICNT2=ICNT2+1
            ITEXT(ICNT2)=' '
            NCTEXT(ICNT2)=0
            AVALUE(ICNT2)=0.0
            IDIGIT(ICNT2)=-1
            ICNT2=ICNT2+1
            ITEXT(ICNT2)='Parameter Estimation (PPCC Method):'
            NCTEXT(ICNT2)=35
            IF(IPOTME.EQ.'DEHA')THEN
              ITEXT(ICNT2)='Parameter Estimation (de Haan Method):'
              NCTEXT(ICNT2)=38
            ELSEIF(IPOTME.EQ.'DEHA')THEN
              ITEXT(ICNT2)='Parameter Estimation (CME Method):'
              NCTEXT(ICNT2)=34
            ELSEIF(IPOTME.EQ.'EPER')THEN
              ITEXT(ICNT2)=   &
                'Par Estimation (Elemental Percentiles):'
              NCTEXT(ICNT2)=45
            ELSEIF(IPOTME.EQ.'LMOM')THEN
              ITEXT(ICNT2)='Parameter Estimation (L-Moments Method):'
              NCTEXT(ICNT2)=40
            ELSEIF(IPOTME.EQ.'MOME')THEN
              ITEXT(ICNT2)='Parameter Estimation (Moments Method):'
              NCTEXT(ICNT2)=38
            ENDIF
            AVALUE(ICNT2)=0.0
            IDIGIT(ICNT2)=-1
            ICNT2=ICNT2+1
            ITEXT(ICNT2)='Estimate of Shape Parameter (Gamma):'
            NCTEXT(ICNT2)=36
            AVALUE(ICNT2)=GAMMA
            IDIGIT(ICNT2)=NUMDIG
            IF(IPOTME.EQ.'DEHA' .OR. IPOTME.EQ.'CME')THEN
              ICNT2=ICNT2+1
              ITEXT(ICNT2)='Standard Deviation of Gamma:'
              NCTEXT(ICNT2)=28
              AVALUE(ICNT2)=GAMMSD
              IDIGIT(ICNT2)=NUMDIG
            ELSEIF(IPOTME.EQ.'PPCC')THEN
              ICNT2=ICNT2+1
              ITEXT(ICNT2)='Lower 95% Confidence Limit:'
              NCTEXT(ICNT2)=27
              AVALUE(ICNT2)=XQU025
              IDIGIT(ICNT2)=NUMDIG
              ICNT2=ICNT2+1
              ITEXT(ICNT2)='Upper 95% Confidence Limit:'
              NCTEXT(ICNT2)=27
              AVALUE(ICNT2)=XQU975
              IDIGIT(ICNT2)=NUMDIG
            ENDIF
            ICNT2=ICNT2+1
            ITEXT(ICNT2)='Estimate of Location Parameter:'
            NCTEXT(ICNT2)=31
            AVALUE(ICNT2)=ALOC
            IDIGIT(ICNT2)=NUMDIG
            ICNT2=ICNT2+1
            ITEXT(ICNT2)='Estimate of Scale Parameter:'
            NCTEXT(ICNT2)=28
            AVALUE(ICNT2)=ASCALE
            IDIGIT(ICNT2)=NUMDIG
!
            NUMROW=ICNT2
            DO 2320 II=1,NUMROW
              NTOT(II)=15
 2320       CONTINUE
!
            IFRST=.TRUE.
            ILAST=.FALSE.
            CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,   &
                        NCTEXT,AVALUE,IDIGIT,   &
                        NTOT,NUMROW,   &
                        ICAPSW,ICAPTY,ILAST,IFRST,   &
                        ISUBRO,IBUGG3,IERROR)
!
 2399       CONTINUE
!
            DG=DBLE(GAMMA)
            IF(IPOTLF.EQ.'ON' .AND. GAMMA.LT.0.0)THEN
              XMAX=U - (ASCALE/GAMMA)
              DXR=DBLE(ALOC) - DBLE(ASCALE)*   &
                  (1.0D0 - (DBLE(ALAMB*50.0))**DG)/DG
              XR50=REAL(DXR)
              IF(IR50.GT.0)THEN
                XLF50=(XMAX/XR50)**2
              ELSE
                XLF50=-99.0
              ENDIF
            ENDIF
!
            DO 410 II=1,NRET
!CCCC         DTEMP=1.0D0 - 1.0D0/(DBLE(ALAMB)*DBLE(R(II)))
!CCCC         CALL GEDPPF(DTEMP,DBLE(GAMMA),MINMAX,IGEPDF,DXR)
              DXR=DBLE(ALOC) - DBLE(ASCALE)*   &
                  (1.0D0 - (DBLE(ALAMB*R(II)))**DG)/DG
              XR=REAL(DXR)
              IF(IPOTLF.EQ.'ON')THEN
                IF(GAMMA.LT.0.0 .AND. R(II).GE.51.0)THEN
                  XLF=(XR/XR50)**2
                ELSE
                  XLF=-99.0
                ENDIF
                WRITE(IOUNI2,'(2(I8,2X),4E15.7)')I,NLOCAL,U,R(II),   &
                      XR,XLF
              ELSE
                WRITE(IOUNI2,'(2(I8,2X),3E15.7)')I,NLOCAL,U,R(II),XR
              ENDIF
  410       CONTINUE
!
            IF(IPRINT.EQ.'OFF')GO TO 300
!
            CALL DPDTAP(R,NRET,   &
                        ALOC,ASCALE,ALAMB,DG,XR,   &
                        ICAPSW,ICAPTY,NUMDIG,   &
                        ISUBRO,IBUGG3,IERROR)
!
            IF(IPOTLF.EQ.'ON' .AND. GAMMA.LT.0.0)THEN
              ITITLE=' '
              NCTITL=0
              ICNT2=1
              ITEXT(ICNT2)=' '
              NCTEXT(ICNT2)=0
              AVALUE(ICNT2)=0.0
              IDIGIT(ICNT2)=-1
              ICNT2=ICNT2+1
              ITEXT(ICNT2)='Maximum Wind Speed:'
              NCTEXT(ICNT2)=19
              AVALUE(ICNT2)=XMAX
              IDIGIT(ICNT2)=NUMDIG
              ICNT2=ICNT2+1
              ITEXT(ICNT2)='Load Factor (Max/XR(50)**2:'
              NCTEXT(ICNT2)=27
              AVALUE(ICNT2)=XLF
              IDIGIT(ICNT2)=NUMDIG
              IFRST=.TRUE.
              ILAST=.FALSE.
!
              NUMROW=ICNT2
              DO 2330 II=1,NUMROW
                NTOT(II)=15
 2330         CONTINUE
!
              CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,   &
                          NCTEXT,AVALUE,IDIGIT,   &
                          NTOT,NUMROW,   &
                          ICAPSW,ICAPTY,ILAST,IFRST,   &
                          ISUBRO,IBUGG3,IERROR)
            ENDIF
          ENDIF
!
        ELSEIF(IPOTDI.EQ.'WEIB')THEN
        ELSEIF(IPOTDI.EQ.'GUMB')THEN
        ELSEIF(IPOTDI.EQ.'FREC')THEN
        ENDIF
!
  300 CONTINUE
!
      N2=ICNT
      NPLOTV=2
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IPRINT=IPRISV
      IFEEDB=IFEESV
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLG1,IFLG2,IFLG3,IFLG4,IFLG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGG3,ISUBRO,IERROR)
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'POT2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPOT2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICASPL,IERROR,N
 9012   FORMAT('ICASPL,IERROR = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)N2,NPLOTV
 9014   FORMAT('N2,NPLOTV = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,N2
          WRITE(ICOUT,9016)I,Y2(I),X2(I),D2(I),XTEMP8(I),XTEMP9(I)
 9016     FORMAT('I,Y2(I),X2(I),D2(I),XTEMP8(I),XTEMP9(I) = ',   &
                 I8,2G15.7,F9.2,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPPOT2
