      CHARACTER*4 IMULT
      CHARACTER*4 IHIGH
      CHARACTER*4 ILEVEL
!
      CHARACTER*4 IFLAGU
      LOGICAL IFRST
      LOGICAL ILAST
!
      CHARACTER*60 IDIST
      CHARACTER*40 INAME
!
