!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
!CCCC THE FOLLOWING LINE WAS ADDED (FOR MINMAX)    MAY 1993
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCOS2.INC'
!CCCC THE FOLLOWING LINE WAS ADDED (FOR IHOST1/2)   MAY 1993
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOST.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
      ICASPL='    '
      ICENSO='OFF'
      IREPL='OFF'
      IMULT='OFF'
      IHIGH='OFF'
      IMETHD='UNIM'
      ILEVEL='OFF'
      IF(IPPLCN.EQ.'KAPL')IMETHD=IPPLCN
!
      ISUBN1='DPPP'
      ISUBN2='    '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!CCCC MAXV2=2
      MINN2=3
!
!               ***************************************
!               **  TREAT THE PROBABILITY PLOT CASE  **
!               ***************************************
!
      IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'DPPP')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPP--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ICASPL,IAND1,IAND2
   52   FORMAT('ICASPL,IAND1,IAND2 = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGG2,IBUGG3,IBUGQ
   53   FORMAT('IBUGG2,IBUGG3,IBUGQ = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************************************
!               **  STEP 1--                                           **
!               **  EXTRACT THE COMMAND                                **
!               **  LOOK FOR ONE OF THE FOLLOWING COMMANDS:            **
!               **    1) <DIST> PROBABILITY PLOT Y                     **
!               **    2) <DIST> PROBABILITY PLOT Y X                   **
!               **    3) <DIST> PROBABILITY PLOT Y XLOW XHIGH          **
!               **                                                     **
!               **    4) <DIST> CENSORED PROBABILITY PLOT Y X          **
!               **    5) <DIST> CENSORED PROBABILITY PLOT Y X XMID     **
!               **    6) <DIST> CENSORED PROBABILITY PLOT Y X XLOW     **
!               **                                        XLOW XHIGH   **
!               **                                                     **
!               **    7) <DIST> MULTIPLE PROBABILITY PLOT Y1 ... YK    **
!               **    8) <DIST> REPLICATED PROBABILITY PLOT Y X1 ...XK **
!               **    9) <DIST> REPLICATED CENSORED PROBABILITY PLOT   **
!               **              Y X X1 ...XK                           **
!               **   10) <DIST> HIGHLIGHTED PROBABILITY PLOT Y X1 X2   **
!               *********************************************************
!
!     LOOK FOR THE WORD "PROBABILITY PLOT" (ERROR IF NOT FOUND).
!     ALSO LOOK FOR OPTIONAL KEYWORDS "CENSOR", "REPLICATION",
!     AND "MULTIPLE".
!
      ISTEPN='1'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'DPPP')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICOM.EQ.'FLUC' .OR. ICOM.EQ.'TABU')THEN
        IFOUND='NO'
        GO TO 9000
      ENDIF
!
      ILASTC=9999
      ILASTZ=9999
      IFOUND='NO'
      DO 100 I=1,NUMARG-1
        IF(IHARG(I).EQ.'PROB' .AND. IHARG(I+1).EQ.'PLOT')THEN
          IFOUND='YES'
          ILASTC=MIN(ILASTC,I-1)
          ILASTZ=I+1
        ELSEIF(IHARG(I).EQ.'CENS')THEN
          ICENSO='ON'
          ILASTC=MIN(ILASTC,I-1)
        ELSEIF(IHARG(I).EQ.'REPL')THEN
          IREPL='ON'
          ILASTC=MIN(ILASTC,I-1)
        ELSEIF(IHARG(I).EQ.'MULT')THEN
          IMULT='ON'
          ILASTC=MIN(ILASTC,I-1)
        ELSEIF(IHARG(I).EQ.'HIGH')THEN
          IHIGH='ON'
          ILASTC=MIN(ILASTC,I-1)
        ENDIF
  100 CONTINUE
!
      IF(IFOUND.EQ.'NO')GO TO 9000
      IF(IMULT.EQ.'ON')THEN
        IF(IREPL.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
  101     FORMAT('***** ERROR IN PROBABILITY PLOT--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)
  102     FORMAT('      YOU CANNOT SPECIFY BOTH "MULTIPLE" AND ',   &
                 '"REPLICATION" FOR THE PROBABILITY PLOT.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ELSEIF(ICENSO.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,112)
  112     FORMAT('      YOU CANNOT SPECIFY BOTH "MULTIPLE" AND ',   &
                 '"CENSORING" FOR THE PROBABILITY PLOT.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ELSEIF(IHIGH.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,122)
  122     FORMAT('      YOU CANNOT SPECIFY BOTH "MULTIPLE" AND ',   &
                 '"HIGHTLIGHTED" FOR THE PROBABILITY PLOT.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
!               ***************************************************
!               **  STEP 2--EXTRACT THE DISTRIBUTION NAME        **
!               ***************************************************
!
      ISTEPN='2'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'DPPP')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,211)IMULT,IREPL,ICENSO,IHIGH,ILASTC,ILASTZ
  211   FORMAT('IMULT,IREPL,ICENSO,IHIGH,ILASTC,ILASTZ = ',4(A4,2X),2I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      JMIN=0
      JMAX=ILASTC
!
      CALL EXTDIS(ICOM,ICOM2,IHARG,IHARG2,NUMARG,JMIN,JMAX,   &
                  ICASPL,IDIST,NUMSHA,IFOUND,ILOCV,   &
                  ISUBRO,IBUGG3,IERROR)
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'DPPP')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,251)
  251   FORMAT('***** AFTER CALL EXTDIS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,252)ICASPL,NUMSHA,IDIST
  252   FORMAT('ICASPL,NUMSHA,IDIST = ',A4,2X,I8,2X,A60)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IFOUND.EQ.'NO')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,262)
  262   FORMAT('      NO MATCH FOUND FOR DISTRIBUTION NAME.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSE
        CALL ADJUST(ILASTZ,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      ENDIF
!
!               ***************************************************
!               **  STEP 3--EXTRACT THE SHAPE PARAMETERS FOR     **
!               **          THE SPECIFIED DISTRIBUTION.          **
!               ***************************************************
!
      ISTEPN='3'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'DPPP')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IHP='PPLO'
      IHP2='C   '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
      IF(IERROR.EQ.'YES')THEN
        PPLOC=0.0
      ELSE
        PPLOC=VALUE(ILOCV)
      ENDIF
      IHP='PPSC'
      IHP2='ALE '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
      IF(IERROR.EQ.'YES')THEN
        PPSCAL=1.0
      ELSE
        PPSCAL=VALUE(ILOCV)
        IF(PPSCAL.LE.0.0)PPSCAL=1.0
      ENDIF
!
      IF(ICASPL.EQ.'GMCL' .OR. ICASPL.EQ.'TRAP' .OR.   &
             ICASPL.EQ.'GTRA' .OR. ICASPL.EQ.'UTSP' .OR.   &
             ICASPL.EQ.'GLGP' .OR.   &
             ICASPL.EQ.'PARE' .OR. ICASPL.EQ.'PAR2'   &
        )THEN
        CONTINUE
      ELSE
        IHP='A   '
        IHP2='    '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
        IF(IERROR.EQ.'YES')THEN
          A=0.0
        ELSE
          A=VALUE(ILOCV)
        ENDIF
!
        IHP='B   '
        IHP2='    '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
        IF(IERROR.EQ.'YES')THEN
          B=1.0
        ELSE
          B=VALUE(ILOCV)
        ENDIF
!
      ENDIF
!
      IF(NUMSHA.GE.1)THEN
        CALL EXTPA1(ICASPL,IDIST,A,B,   &
                    SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                    SHAPE5,SHAPE6,SHAPE7,   &
                    IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                    ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                    IGETDF,ICONDF,IGOMDF,IKATDF,   &
                    IGIGDF,IGEODF,   &
                    IBFWLI,IEEWLI,   &
                    ISUBRO,IBUGG2,IERROR)
      ENDIF
!
!               *********************************
!               **  STEP 4--                   **
!               **  EXTRACT THE VARIABLE LIST  **
!               *********************************
!
      ISTEPN='4'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'DPPP')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='PROBABILITY PLOT'
      MINNA=1
      MAXNA=100
      MINN2=2
      IFLAGE=1
      IFLAGM=0
      IF(IMULT.EQ.'ON')THEN
        IFLAGE=0
        IFLAGM=1
      ELSE
         IF(IREPL.EQ.'OFF' .AND. ICENSO.EQ.'OFF' .AND.   &
            IHIGH.EQ.'OFF')IFLAGM=1
      ENDIF
      IF(ICASPL.EQ.'BFWE' .AND.   &
        (IBFWTY.EQ.'ON' .OR. IBFWLI.EQ.'VARI'))THEN
        IFLAGM=0
      ENDIF
      IF(ICASPL.EQ.'EEWE' .AND. IEEWLI.EQ.'VARI')THEN
        IFLAGM=0
      ENDIF
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=-99
      MAXNVA=-99
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'DPPP')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               ***********************************************
!               **  STEP 5--                                 **
!               **  DETERMINE:                               **
!               **  1) NUMBER OF REPLICATION VARIABLES (0-6) **
!               **  2) NUMBER OF CENSORING   VARIABLES (0-1) **
!               **  3) NUMBER OF GROUPING    VARIABLES (0-2) **
!               **  4) NUMBER OF RESPONSE    VARIABLES (>= 1)**
!               **  5) NUMBER OF HIGHLIGHT   VARIABLES (0-2) **
!               ***********************************************
!
      ISTEPN='5'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'DPPP')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NRESP=0
      NREPL=0
      NCENS=0
      NGROUP=0
      NHIGH=0
      NLEVEL=0
      IDATSW='RAW'
      IF(IMULT.EQ.'ON')THEN
        NRESP=NUMVAR
      ELSEIF(IHIGH.EQ.'ON')THEN
        NRESP=1
        IF(ICASPL.EQ.'BFWE')THEN
          IF(IBFWTY.EQ.'ON' .AND. NUMVAR.GT.1)THEN
            NLEVEL=1
            ILEVEL='ON'
          ENDIF
          IF(IBFWLI.EQ.'VARI' .AND. NUMVAR.GT.1)THEN
            NLEVEL=1
            ILEVEL='ON'
          ENDIF
          NHIGH=NUMVAR-NRESP-NLEVEL
        ELSEIF(ICASPL.EQ.'EEWE')THEN
          IF(IEEWLI.EQ.'VARI' .AND. NUMVAR.GT.1)THEN
            NLEVEL=1
            ILEVEL='ON'
          ENDIF
          NHIGH=NUMVAR-NRESP-NLEVEL
        ELSE
          NHIGH=NUMVAR-1
        ENDIF
        IF(NHIGH.EQ.0)THEN
          NHIGH=0
        ELSEIF(NHIGH.LT.1 .OR. NHIGH.GT.2)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,501)
  501     FORMAT('      FOR THE HIGHLIGHTED CASE, THE NUMBER OF ',   &
                 'HIGHLIGHT VARIABLES')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,502)
  502     FORMAT('      MUST BE BETWEEN 1 AND 2;  SUCH WAS NOT THE ',   &
                 'CASE HERE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,503)NHIGH
  503     FORMAT('      THE NUMBER OF HIGHLIGHT VARIABLES = ',I5)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ELSEIF(IREPL.EQ.'ON')THEN
        NRESP=1
        IF(ICENSO.EQ.'ON')THEN
          NCENS=1
        ENDIF
        NREPL=NUMVAR-NRESP-NCENS
        IF(NREPL.LT.1 .OR. NREPL.GT.6)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,511)
  511     FORMAT('      FOR THE REPLICATION CASE, THE NUMBER OF ',   &
                 'REPLICATION VARIABLES')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,512)
  512     FORMAT('      MUST BE BETWEEN 1 AND 4;  SUCH WAS NOT THE ',   &
                 'CASE HERE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,513)NREPL
  513     FORMAT('      THE NUMBER OF REPLICATION VARIABLES = ',I5)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
!       NOTE 09/2010: FOR BRITTLE FIBER WEIBULL, THE CASE WHERE THERE
!                     ARE MULTIPLE VARIABLES IS AMBIGUOUS IN TERMS
!                     OF WHETHER THIS IMPLIES A "GAUGE LENGTH"
!                     VARIABLE OR A CLASS MID-POINT VARIABLE.
!                     THE COMMAND
!
!                         SET BRITTLE FIBER WEIBULL LENGTH <ON/OFF>
!
!                     SPECIFIES WHETHER
!
      ELSE
        NRESP=1
        NLEVEL=0
        IF(ICENSO.EQ.'ON' .AND. NUMVAR.GT.1)THEN
          NCENS=1
        ENDIF
        IF(ICASPL.EQ.'BFWE')THEN
          IF(IBFWTY.EQ.'ON' .AND. NUMVAR.GT.1)THEN
            NLEVEL=1
            ILEVEL='ON'
          ENDIF
          IF(IBFWLI.EQ.'VARI' .AND. NUMVAR.GT.1)THEN
            NLEVEL=1
            ILEVEL='ON'
          ENDIF
          NGROUP=NUMVAR-NRESP-NCENS-NLEVEL
        ELSEIF(ICASPL.EQ.'EEWE')THEN
          IF(IEEWLI.EQ.'VARI' .AND. NUMVAR.GT.1)THEN
            NLEVEL=1
            ILEVEL='ON'
          ENDIF
          NGROUP=NUMVAR-NRESP-NCENS-NLEVEL
        ELSE
          NGROUP=NUMVAR-NRESP-NCENS
        ENDIF
        IF(NGROUP.EQ.1)IDATSW='FREQ'
        IF(NGROUP.EQ.2)IDATSW='FRE2'
!
        IF(NGROUP.LT.0 .OR. NGROUP.GT.2)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,521)
  521     FORMAT('      THE NUMBER OF CLASS VARIABLES IS LESS THAN ',   &
                 'ZERO OR GREATER THAN TWO.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,523)NGROUP
  523     FORMAT('      THE NUMBER OF CLASS VARIABLES = ',I5)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
!               *****************************************
!               **  STEP 6--                           **
!               **  GENERATE THE PROBABILITY PLOTS FOR **
!               **  THE VARIOUS CASES.                 **
!               *****************************************
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'DPPP')THEN
        ISTEPN='6'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,601)NRESP,NREPL,NHIGH,NGROUP
  601   FORMAT('NRESP,NREPL,NHIGH,NGROUP = ',4I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************************************
!               **  STEP 7A--                          **
!               **  CASE 1: SINGLE RESPONSE VARIABLE   **
!               **          WITH NO REPLICATION        **
!               *****************************************
!
      IF(NRESP.EQ.1 .AND. NREPL.EQ.0 .AND. NHIGH.EQ.0)THEN
        ISTEPN='7A'
        IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'DPPP')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        ICOL=1
        IF(IFLAGM.EQ.1 .AND. NUMVAR.EQ.1)THEN
          CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                      INAME,IVARN1,IVARN2,IVARTY,   &
                      ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVAR,   &
                      MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                      MAXCP4,MAXCP5,MAXCP6,   &
                      V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                      Y1,XTEMP1,XTEMP2,NLOCAL,NLOCA2,NLOCA3,ICASE,   &
                      IBUGG3,ISUBRO,IFOUND,IERROR)
        ELSE
          J=0
          IMAX=NRIGHT(1)
          IF(NQ.LT.NRIGHT(1))IMAX=NQ
          DO 710 I=1,IMAX
            IF(ISUB(I).EQ.0)GO TO 710
            J=J+1
!
!           RESPONSE VARIABLE IN Y1
!
            IJ=MAXN*(ICOLR(1)-1)+I
            IF(ICOLR(1).LE.MAXCOL)Y1(J)=V(IJ)
            IF(ICOLR(1).EQ.MAXCP1)Y1(J)=PRED(I)
            IF(ICOLR(1).EQ.MAXCP2)Y1(J)=RES(I)
            IF(ICOLR(1).EQ.MAXCP3)Y1(J)=YPLOT(I)
            IF(ICOLR(1).EQ.MAXCP4)Y1(J)=XPLOT(I)
            IF(ICOLR(1).EQ.MAXCP5)Y1(J)=X2PLOT(I)
            IF(ICOLR(1).EQ.MAXCP6)Y1(J)=TAGPLO(I)
            ICOLC=1
!
!           LEVEL VARIABLE IN XLEVEL
!
            IF(NLEVEL.EQ.1)THEN
              ICOLC=ICOLC+1
              ICOLT=ICOLR(ICOLC)
              IJ=MAXN*(ICOLT-1)+I
              IF(ICOLT.LE.MAXCOL)XLEVEL(J)=V(IJ)
              IF(ICOLT.EQ.MAXCP1)XLEVEL(J)=PRED(I)
              IF(ICOLT.EQ.MAXCP2)XLEVEL(J)=RES(I)
              IF(ICOLT.EQ.MAXCP3)XLEVEL(J)=YPLOT(I)
              IF(ICOLT.EQ.MAXCP4)XLEVEL(J)=XPLOT(I)
              IF(ICOLT.EQ.MAXCP5)XLEVEL(J)=X2PLOT(I)
              IF(ICOLT.EQ.MAXCP6)XLEVEL(J)=TAGPLO(I)
            ELSE
              XLEVEL(J)=CPUMIN
            ENDIF
!
!           CENSORING VARIABLE IN XCENS
!
            IF(ICENSO.EQ.'ON')THEN
              ICOLC=ICOLC+1
              ICOLT=ICOLR(ICOLC)
              IJ=MAXN*(ICOLT-1)+I
              IF(ICOLT.LE.MAXCOL)XCENS(J)=V(IJ)
              IF(ICOLT.EQ.MAXCP1)XCENS(J)=PRED(I)
              IF(ICOLT.EQ.MAXCP2)XCENS(J)=RES(I)
              IF(ICOLT.EQ.MAXCP3)XCENS(J)=YPLOT(I)
              IF(ICOLT.EQ.MAXCP4)XCENS(J)=XPLOT(I)
              IF(ICOLT.EQ.MAXCP5)XCENS(J)=X2PLOT(I)
              IF(ICOLT.EQ.MAXCP6)XCENS(J)=TAGPLO(I)
            ENDIF
!
!           CLASS VARIABLE IN X1 FOR FREQUENCY DATA
!
            IF(NGROUP.GE.1)THEN
              ICOLC=ICOLC+1
              ICOLT=ICOLR(ICOLC)
              IJ=MAXN*(ICOLT-1)+I
              IF(ICOLT.LE.MAXCOL)X1(J)=V(IJ)
              IF(ICOLT.EQ.MAXCP1)X1(J)=PRED(I)
              IF(ICOLT.EQ.MAXCP2)X1(J)=RES(I)
              IF(ICOLT.EQ.MAXCP3)X1(J)=YPLOT(I)
              IF(ICOLT.EQ.MAXCP4)X1(J)=XPLOT(I)
              IF(ICOLT.EQ.MAXCP5)X1(J)=X2PLOT(I)
              IF(ICOLT.EQ.MAXCP6)X1(J)=TAGPLO(I)
            ENDIF
!
!           IF FREQUENCY DATA GIVEN WITH LOWER AND UPPER CLASS LIMITS,
!           THEN UPPER CLASS LIMIT VARIABLE IN XHIGH
!
            IF(NGROUP.EQ.2)THEN
              ICOLC=ICOLC+1
              ICOLT=ICOLR(ICOLC)
              IJ=MAXN*(ICOLT-1)+I
              IF(ICOLT.LE.MAXCOL)XHIGH(J)=V(IJ)
              IF(ICOLT.EQ.MAXCP1)XHIGH(J)=PRED(I)
              IF(ICOLT.EQ.MAXCP2)XHIGH(J)=RES(I)
              IF(ICOLT.EQ.MAXCP3)XHIGH(J)=YPLOT(I)
              IF(ICOLT.EQ.MAXCP4)XHIGH(J)=XPLOT(I)
              IF(ICOLT.EQ.MAXCP5)XHIGH(J)=X2PLOT(I)
              IF(ICOLT.EQ.MAXCP6)XHIGH(J)=TAGPLO(I)
            ENDIF
!
  710     CONTINUE
          NLOCAL=J
        ENDIF
!
!       *****************************************************
!       **  STEP 7B--                                      **
!       **  FORM THE VERTICAL AND HORIZONTAL AXIS          **
!       **  VALUES Y(.) AND X(.) FOR THE PLOT.             **
!       **  RESET THE VECTOR D(.) TO ALL ONES.             **
!       **  DEFINE THE NUMBER OF PLOT POINTS    (NPLOTP).  **
!       **  DEFINE THE NUMBER OF PLOT VARIABLES (NPLOTV).  **
!       *****************************************************
!
        ISTEPN='7B'
        IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'DPPP')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'DPPP')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,711)
  711     FORMAT('***** FROM THE MIDDLE  OF DPPP--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,712)ICASPL,NUMVAR,IDATSW,NLOCAL
  712     FORMAT('ICASPL,NUMVAR,IDATSW,NQ = ',   &
                 A4,I8,2X,A4,I8)
          CALL DPWRST('XXX','BUG ')
          IF(NLOCAL.GE.1)THEN
            DO 715 I=1,NLOCAL
              WRITE(ICOUT,716)I,Y1(I),X1(I),XHIGH(I),XCENS(I)
  716         FORMAT('I,Y1(I),X1(I),XHIGH(I),XCENS(I) = ',I8,4F12.5)
              CALL DPWRST('XXX','BUG ')
  715       CONTINUE
          ENDIF
        ENDIF
!
        NPLOTP=0
        NCURVE=1
        IF(NGROUP.EQ.0)THEN
          CALL DPPP2(Y1,XCENS,XLEVEL,NLOCAL,ICASPL,NHIGH,         &
                     XTEMP1,XTEMP2,XTEMP3,                        &
                     YLOWLM,YUPPLM,A,B,MINMAX,                    &
                     SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,          &
                     SHAPE6,SHAPE7,                               &
                     IADEDF,IGEPDF,IMAKDF,IBEIDF,                 &
                     ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                     IGOMDF,IKATDF,IGIGDF,IGEODF,                 &
                     IPPLDP,MAXOBV,ICENSO,IMETHD,ILEVEL,          &
                     PPLOC,PPSCAL,                                &
                     PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,  &
                     CCALBE,PPA0BW,PPA1BW,                        &
                     WEIGHH,WEIGHV,                               &
                     Y,X,D,NPLOTP,NPLOTV,NCURVE,IBUGG3,ISUBRO,IERROR)
        ELSE
          CALL DPPP3(Y1,X1,XHIGH,NLOCAL,ICASPL,IDATSW,            &
                     XCENS,XTEMP1,XTEMP2,XTEMP3,XTEMP4,           &
                     YLOWLM,YUPPLM,A,B,MINMAX,                    &
                     SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,          &
                     SHAPE6,SHAPE7,                               &
                     IADEDF,IGEPDF,IMAKDF,IBEIDF,                 &
                     ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                     IGOMDF,IKATDF,IGIGDF,IGEODF,                 &
                     IPPLDP,MAXOBV,ICENSO,IMETHD,                 &
                     PPLOC,PPSCAL,                                &
                     PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,  &
                     CCALBE,PPA0BW,PPA1BW,                        &
                     WEIGHH,WEIGHV,                               &
                     Y,X,D,NPLOTP,NPLOTV,NCURVE,IBUGG3,ISUBRO,IERROR)
        ENDIF
!
!               ***************************************
!               **  STEP 7C--                        **
!               **  COMPUTE PROB PLOT STAT           **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
        ISTEPN='7C'
        IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'DPPP')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IFLAGU='ON'
        IFRST=.FALSE.
        ILAST=.FALSE.
        CALL DPPP4(PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                   CCALBE,PPA0BW,PPA1BW,                         &
                   IFLAGU,IFRST,ILAST,                           &
                   IBUGG2,IBUGG3,ISUBRO,IERROR)
!
!               ******************************************
!               **  STEP 8A--                           **
!               **  CASE 2: MULTIPLE RESPONSE VARIABLES **
!               **          NOTE THAT CENSORING AND     **
!               **          GROUPING ARE NOT SUPPORTED  **
!               **          FOR THIS CASE.              **
!               ******************************************
!
      ELSEIF(NRESP.GT.1)THEN
        ISTEPN='8A'
        IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'DPPP')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!       LOOP THROUGH EACH OF THE RESPONSE VARIABLES
!
        NPLOTP=0
        NCURVE=0
        DO 810 IRESP=1,NRESP
          NCURVE=NCURVE+1
!
          IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'DPPP')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,811)IRESP,NCURVE
  811       FORMAT('IRESP,NCURVE = ',2I5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          ICOL=IRESP
          NUMVA2=1
          CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                      INAME,IVARN1,IVARN2,IVARTY,   &
                      ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                      MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                      MAXCP4,MAXCP5,MAXCP6,   &
                      V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                      Y1,XTEMP1,XTEMP2,NLOCAL,NLOCA2,NLOCA3,ICASE,   &
                      IBUGG3,ISUBRO,IFOUND,IERROR)
!
!         *****************************************************
!         **  STEP 8B--                                      **
!         **  FORM THE VERTICAL AND HORIZONTAL AXIS          **
!         **  VALUES Y(.) AND X(.) FOR THE PLOT.             **
!         **  RESET THE VECTOR D(.) TO ALL ONES.             **
!         **  DEFINE THE NUMBER OF PLOT POINTS    (NPLOTP).  **
!         **  DEFINE THE NUMBER OF PLOT VARIABLES (NPLOTV).  **
!         *****************************************************
!
          ISTEPN='8B'
          IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'DPPP')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
          IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'DPPP')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,822)
  822       FORMAT('***** FROM THE MIDDLE  OF DPPP--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,823)ICASPL,NUMVAR,IDATSW,NLOCAL
  823       FORMAT('ICASPL,NUMVAR,IDATSW,NQ = ',   &
                   A4,I8,2X,A4,I8)
            CALL DPWRST('XXX','BUG ')
            IF(NLOCAL.GE.1)THEN
              DO 825 I=1,NLOCAL
                WRITE(ICOUT,826)I,Y1(I),X1(I),XHIGH(I),XCENS(I)
  826           FORMAT('I,Y1(I),X1(I),XHIGH(I),XCENS(I) = ',I8,4F12.5)
                CALL DPWRST('XXX','BUG ')
  825         CONTINUE
            ENDIF
          ENDIF
!
          NPLOT1=NPLOTP
          CALL DPPP2(Y1,XCENS,XLEVEL,NLOCAL,ICASPL,NHIGH,   &
                     XTEMP1,XTEMP2,XTEMP3,   &
                     YLOWLM,YUPPLM,A,B,MINMAX,   &
                     SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                     SHAPE6,SHAPE7,   &
                     IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                     ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                     IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                     IPPLDP,MAXOBV,ICENSO,IMETHD,ILEVEL,   &
                     PPLOC,PPSCAL,   &
                     PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                     CCALBE,PPA0BW,PPA1BW,   &
                     WEIGHH,WEIGHV,   &
                     Y,X,D,NPLOTP,NPLOTV,NCURVE,IBUGG3,ISUBRO,IERROR)
          NPLOT2=NPLOTP
!
!               ***************************************
!               **  STEP 8C--                        **
!               **  COMPUTE PROB PLOT STAT           **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
          ISTEPN='8C'
          IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'DPPP')   &
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
          IFLAGU='FILE'
          IFRST=.FALSE.
          ILAST=.FALSE.
          IF(IRESP.EQ.1)IFRST=.TRUE.
          IF(IRESP.EQ.NRESP)ILAST=.TRUE.
          NPTEMP=NPLOT2-NPLOT1
          CALL DPPP4(PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                     CCALBE,PPA0BW,PPA1BW,   &
                     IFLAGU,IFRST,ILAST,   &
                     IBUGG2,IBUGG3,ISUBRO,IERROR)
!
  810   CONTINUE
!
!               ***************************************************
!               **  STEP 9A--                                    **
!               **  CASE 3: ONE OR MORE REPLICATION VARIABLES.   **
!               **          FOR THIS CASE, THE NUMBER OF         **
!               **          VARIABLES MUST BE EXACTLY 1.  BOTH   **
!               **          CENSORING AND GROUPING ARE SUPPORTED.**
!               **          FOR THIS CASE, ALL VARIABLES MUST    **
!               **          HAVE THE SAME LENGTH.                **
!               ***************************************************
!
      ELSEIF(NRESP.EQ.1 .AND. NREPL.GE.1)THEN
        ISTEPN='9A'
        IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'DPPP')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        J=0
        IMAX=NRIGHT(1)
        IF(NQ.LT.NRIGHT(1))IMAX=NQ
        DO 910 I=1,IMAX
          IF(ISUB(I).EQ.0)GO TO 910
          J=J+1
!
!         RESPONSE VARIABLE IN Y1
!
          IJ=MAXN*(ICOLR(1)-1)+I
          IF(ICOLR(1).LE.MAXCOL)Y1(J)=V(IJ)
          IF(ICOLR(1).EQ.MAXCP1)Y1(J)=PRED(I)
          IF(ICOLR(1).EQ.MAXCP2)Y1(J)=RES(I)
          IF(ICOLR(1).EQ.MAXCP3)Y1(J)=YPLOT(I)
          IF(ICOLR(1).EQ.MAXCP4)Y1(J)=XPLOT(I)
          IF(ICOLR(1).EQ.MAXCP5)Y1(J)=X2PLOT(I)
          IF(ICOLR(1).EQ.MAXCP6)Y1(J)=TAGPLO(I)
!
!         CENSORING VARIABLE IN XCENS
!
          ICOLC=1
          IF(ICENSO.EQ.'ON')THEN
            ICOLC=ICOLC+1
            ICOLT=ICOLR(ICOLC)
            IJ=MAXN*(ICOLT-1)+I
            IF(ICOLT.LE.MAXCOL)XCENS(J)=V(IJ)
            IF(ICOLT.EQ.MAXCP1)XCENS(J)=PRED(I)
            IF(ICOLT.EQ.MAXCP2)XCENS(J)=RES(I)
            IF(ICOLT.EQ.MAXCP3)XCENS(J)=YPLOT(I)
            IF(ICOLT.EQ.MAXCP4)XCENS(J)=XPLOT(I)
            IF(ICOLT.EQ.MAXCP5)XCENS(J)=X2PLOT(I)
            IF(ICOLT.EQ.MAXCP6)XCENS(J)=TAGPLO(I)
          ENDIF
!
!         CLASS VARIABLE IN X1 FOR FREQUENCY DATA
!
          IF(NGROUP.GE.1)THEN
            ICOLC=ICOLC+1
            ICOLT=ICOLR(ICOLC)
            IJ=MAXN*(ICOLT-1)+I
            IF(ICOLT.LE.MAXCOL)X1(J)=V(IJ)
            IF(ICOLT.EQ.MAXCP1)X1(J)=PRED(I)
            IF(ICOLT.EQ.MAXCP2)X1(J)=RES(I)
            IF(ICOLT.EQ.MAXCP3)X1(J)=YPLOT(I)
            IF(ICOLT.EQ.MAXCP4)X1(J)=XPLOT(I)
            IF(ICOLT.EQ.MAXCP5)X1(J)=X2PLOT(I)
            IF(ICOLT.EQ.MAXCP6)X1(J)=TAGPLO(I)
          ENDIF
!
!         IF FREQUENCY DATA GIVEN WITH LOWER AND UPPER CLASS LIMITS,
!         THEN UPPER CLASS LIMIT VARIABLE IN XHIGH
!
          IF(NGROUP.EQ.2)THEN
            ICOLC=ICOLC+1
            ICOLT=ICOLR(ICOLC)
            IJ=MAXN*(ICOLT-1)+I
            IF(ICOLT.LE.MAXCOL)XHIGH(J)=V(IJ)
            IF(ICOLT.EQ.MAXCP1)XHIGH(J)=PRED(I)
            IF(ICOLT.EQ.MAXCP2)XHIGH(J)=RES(I)
            IF(ICOLT.EQ.MAXCP3)XHIGH(J)=YPLOT(I)
            IF(ICOLT.EQ.MAXCP4)XHIGH(J)=XPLOT(I)
            IF(ICOLT.EQ.MAXCP5)XHIGH(J)=X2PLOT(I)
            IF(ICOLT.EQ.MAXCP6)XHIGH(J)=TAGPLO(I)
          ENDIF
!
          DO 920 IR=1,MIN(NREPL,6)
            ICOLC=ICOLC+1
            ICOLT=ICOLR(ICOLC)
            IJ=MAXN*(ICOLT-1)+I
            IF(ICOLT.LE.MAXCOL)XDESGN(J,IR)=V(IJ)
            IF(ICOLT.EQ.MAXCP1)XDESGN(J,IR)=PRED(I)
            IF(ICOLT.EQ.MAXCP2)XDESGN(J,IR)=RES(I)
            IF(ICOLT.EQ.MAXCP3)XDESGN(J,IR)=YPLOT(I)
            IF(ICOLT.EQ.MAXCP4)XDESGN(J,IR)=XPLOT(I)
            IF(ICOLT.EQ.MAXCP5)XDESGN(J,IR)=X2PLOT(I)
            IF(ICOLT.EQ.MAXCP6)XDESGN(J,IR)=TAGPLO(I)
  920     CONTINUE
!
  910   CONTINUE
        NLOCAL=J
!
!       *****************************************************
!       **  STEP 9B--                                      **
!       **  FORM THE VERTICAL AND HORIZONTAL AXIS          **
!       **  VALUES Y(.) AND X(.) FOR THE PLOT.             **
!       **                                                 **
!       **  FOR THIS CASE, WE NEED TO LOOP THROUGH THE     **
!       **  VARIOUS REPLICATIONS.                          **
!       *****************************************************
!
        ISTEPN='9B'
        IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'DPPP')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'DPPP')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,931)
  931     FORMAT('***** FROM THE MIDDLE  OF DPPP--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,932)ICASPL,NUMVAR,IDATSW,NLOCAL
  932     FORMAT('ICASPL,NUMVAR,IDATSW,NQ = ',   &
                 A4,I8,2X,A4,I8)
          CALL DPWRST('XXX','BUG ')
          IF(NLOCAL.GE.1)THEN
            DO 935 I=1,NLOCAL
              WRITE(ICOUT,936)I,Y1(I),X1(I),XHIGH(I),XCENS(I),   &
                              XDESGN(I,1),XDESGN(I,2)
  936         FORMAT('I,Y1(I),X1(I),XHIGH(I),XCENS(I),XDESGN(I,1)',   &
                     'XDESGN(I,2) = ',I8,6F12.5)
              CALL DPWRST('XXX','BUG ')
  935       CONTINUE
          ENDIF
        ENDIF
!
!       *****************************************************
!       **  STEP 9C--                                      **
!       **  FIND THE DISTINCT VALUES IN EACH OF THE        **
!       **  REPLICATION VARIABLES.                         **
!       *****************************************************
!
        CALL DPPP5(XDESGN(1,1),XDESGN(1,2),XDESGN(1,3),   &
                   XDESGN(1,4),XDESGN(1,5),XDESGN(1,6),   &
                   NREPL,NLOCAL,MAXOBV,   &
                   XIDTEM,XIDTE2,XIDTE3,XIDTE4,XIDTE5,XIDTE6,   &
                   XTEMP1,XTEMP2,   &
                   NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5,NUMSE6,   &
                   IBUGG3,ISUBRO,IERROR)
!
!       *****************************************************
!       **  STEP 9D--                                      **
!       **  NOW LOOP THROUGH THE VARIOUS REPLICATIONS      **
!       *****************************************************
!
        NPLOTP=0
        NCURVE=0
        IF(NREPL.EQ.1)THEN
          J=0
          DO 1110 ISET1=1,NUMSE1
            K=0
            DO 1130 I=1,NLOCAL
              IF(XIDTEM(ISET1).EQ.XDESGN(I,1))THEN
                K=K+1
                ZY(K)=Y1(I)
                ZXLOW(K)=X1(I)
                ZXHIGH(K)=XHIGH(I)
                ZCENS(K)=XCENS(I)
              ENDIF
 1130       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            NPLOT1=NPLOTP
            IF(NGROUP.EQ.0)THEN
              IF(NTEMP.GT.0)THEN
                CALL DPPP2(ZY,ZCENS,XLEVEL,NTEMP,ICASPL,NHIGH,   &
                           XTEMP1,XTEMP2,XTEMP3,   &
                           YLOWLM,YUPPLM,A,B,MINMAX,   &
                           SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                           SHAPE6,SHAPE7,   &
                           IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                           ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                           IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                           IPPLDP,MAXOBV,ICENSO,IMETHD,ILEVEL,   &
                           PPLOC,PPSCAL,   &
                           PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                           CCALBE,PPA0BW,PPA1BW,   &
                           WEIGHH,WEIGHV,   &
                           Y,X,D,NPLOTP,NPLOTV,NCURVE,   &
                           IBUGG3,ISUBRO,IERROR)
              ENDIF
            ELSE
              IF(NTEMP.GT.0)THEN
                CALL DPPP3(ZY,ZXLOW,ZXHIGH,NTEMP,ICASPL,IDATSW,   &
                           ZCENS,XTEMP1,XTEMP2,XTEMP3,XTEMP4,   &
                           YLOWLM,YUPPLM,A,B,MINMAX,   &
                           SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                           SHAPE6,SHAPE7,   &
                           IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                           ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                           IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                           IPPLDP,MAXOBV,ICENSO,IMETHD,   &
                           PPLOC,PPSCAL,   &
                           PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                           CCALBE,PPA0BW,PPA1BW,   &
                           WEIGHH,WEIGHV,   &
                           Y,X,D,NPLOTP,NPLOTV,NCURVE,   &
                           IBUGG3,ISUBRO,IERROR)
              ENDIF
            ENDIF
            NPLOT2=NPLOTP
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NUMSE1)ILAST=.TRUE.
            NPTEMP=NPLOT2-NPLOT1
            CALL DPPP4(PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                       CCALBE,PPA0BW,PPA1BW,   &
                       IFLAGU,IFRST,ILAST,   &
                       IBUGG2,IBUGG3,ISUBRO,IERROR)
 1110     CONTINUE
        ELSEIF(NREPL.EQ.2)THEN
          J=0
          NTOT=NUMSE1*NUMSE2
          DO 1210 ISET1=1,NUMSE1
          DO 1220 ISET2=1,NUMSE2
            K=0
            DO 1290 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2)   &
                )THEN
                K=K+1
                ZY(K)=Y1(I)
                ZXLOW(K)=X1(I)
                ZXHIGH(K)=XHIGH(I)
                ZCENS(K)=XCENS(I)
              ENDIF
 1290       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            NPLOT1=NPLOTP
            IF(NGROUP.EQ.0)THEN
              IF(NTEMP.GT.0)THEN
                CALL DPPP2(ZY,ZCENS,XLEVEL,NTEMP,ICASPL,NHIGH,   &
                           XTEMP1,XTEMP2,XTEMP3,   &
                           YLOWLM,YUPPLM,A,B,MINMAX,   &
                           SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                           SHAPE6,SHAPE7,   &
                           IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                           ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                           IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                           IPPLDP,MAXOBV,ICENSO,IMETHD,ILEVEL,   &
                           PPLOC,PPSCAL,   &
                           PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                           CCALBE,PPA0BW,PPA1BW,   &
                           WEIGHH,WEIGHV,   &
                           Y,X,D,NPLOTP,NPLOTV,NCURVE,   &
                           IBUGG3,ISUBRO,IERROR)
              ENDIF
            ELSE
              IF(NTEMP.GT.0)THEN
                CALL DPPP3(ZY,ZXLOW,ZXHIGH,NTEMP,ICASPL,IDATSW,   &
                           ZCENS,XTEMP1,XTEMP2,XTEMP3,XTEMP4,   &
                           YLOWLM,YUPPLM,A,B,MINMAX,   &
                           SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                           SHAPE6,SHAPE7,   &
                           IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                           ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                           IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                           IPPLDP,MAXOBV,ICENSO,IMETHD,   &
                           PPLOC,PPSCAL,   &
                           PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                           CCALBE,PPA0BW,PPA1BW,   &
                           WEIGHH,WEIGHV,   &
                           Y,X,D,NPLOTP,NPLOTV,NCURVE,   &
                           IBUGG3,ISUBRO,IERROR)
              ENDIF
            ENDIF
            NPLOT2=NPLOTP
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
            NPTEMP=NPLOT2-NPLOT1
            CALL DPPP4(PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                       CCALBE,PPA0BW,PPA1BW,   &
                       IFLAGU,IFRST,ILAST,   &
                       IBUGG2,IBUGG3,ISUBRO,IERROR)
 1220     CONTINUE
 1210     CONTINUE
        ELSEIF(NREPL.EQ.3)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3
          DO 1310 ISET1=1,NUMSE1
          DO 1320 ISET2=1,NUMSE2
          DO 1330 ISET3=1,NUMSE3
            K=0
            DO 1390 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3)   &
                )THEN
                K=K+1
                ZY(K)=Y1(I)
                ZXLOW(K)=X1(I)
                ZXHIGH(K)=XHIGH(I)
                ZCENS(K)=XCENS(I)
              ENDIF
 1390       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            NPLOT1=NPLOTP
            IF(NGROUP.EQ.0)THEN
              IF(NTEMP.GT.0)THEN
                CALL DPPP2(ZY,ZCENS,XLEVEL,NTEMP,ICASPL,NHIGH,   &
                           XTEMP1,XTEMP2,XTEMP3,   &
                           YLOWLM,YUPPLM,A,B,MINMAX,   &
                           SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                           SHAPE6,SHAPE7,   &
                           IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                           ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                           IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                           IPPLDP,MAXOBV,ICENSO,IMETHD,ILEVEL,   &
                           PPLOC,PPSCAL,   &
                           PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                           CCALBE,PPA0BW,PPA1BW,   &
                           WEIGHH,WEIGHV,   &
                           Y,X,D,NPLOTP,NPLOTV,NCURVE,   &
                           IBUGG3,ISUBRO,IERROR)
              ENDIF
            ELSE
              IF(NTEMP.GT.0)THEN
                CALL DPPP3(ZY,ZXLOW,ZXHIGH,NTEMP,ICASPL,IDATSW,   &
                           ZCENS,XTEMP1,XTEMP2,XTEMP3,XTEMP4,   &
                           YLOWLM,YUPPLM,A,B,MINMAX,   &
                           SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                           SHAPE6,SHAPE7,   &
                           IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                           ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                           IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                           IPPLDP,MAXOBV,ICENSO,IMETHD,   &
                           PPLOC,PPSCAL,   &
                           PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                           CCALBE,PPA0BW,PPA1BW,   &
                           WEIGHH,WEIGHV,   &
                           Y,X,D,NPLOTP,NPLOTV,NCURVE,   &
                           IBUGG3,ISUBRO,IERROR)
              ENDIF
            ENDIF
            NPLOT2=NPLOTP
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
            NPTEMP=NPLOT2-NPLOT1
            CALL DPPP4(PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                       CCALBE,PPA0BW,PPA1BW,   &
                       IFLAGU,IFRST,ILAST,   &
                       IBUGG2,IBUGG3,ISUBRO,IERROR)
 1330     CONTINUE
 1320     CONTINUE
 1310     CONTINUE
        ELSEIF(NREPL.EQ.4)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3*NUMSE4
          DO 1410 ISET1=1,NUMSE1
          DO 1420 ISET2=1,NUMSE2
          DO 1430 ISET3=1,NUMSE3
          DO 1440 ISET4=1,NUMSE4
            K=0
            DO 1490 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3) .AND.   &
                 XIDTE4(ISET4).EQ.XDESGN(I,4)   &
                )THEN
                K=K+1
                ZY(K)=Y1(I)
                ZXLOW(K)=X1(I)
                ZXHIGH(K)=XHIGH(I)
                ZCENS(K)=XCENS(I)
              ENDIF
 1490       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            NPLOT1=NPLOTP
            IF(NGROUP.EQ.0)THEN
              IF(NTEMP.GT.0)THEN
                CALL DPPP2(ZY,ZCENS,XLEVEL,NTEMP,ICASPL,NHIGH,   &
                           XTEMP1,XTEMP2,XTEMP3,   &
                           YLOWLM,YUPPLM,A,B,MINMAX,   &
                           SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                           SHAPE6,SHAPE7,   &
                           IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                           ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                           IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                           IPPLDP,MAXOBV,ICENSO,IMETHD,ILEVEL,   &
                           PPLOC,PPSCAL,   &
                           PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                           CCALBE,PPA0BW,PPA1BW,   &
                           WEIGHH,WEIGHV,   &
                           Y,X,D,NPLOTP,NPLOTV,NCURVE,   &
                           IBUGG3,ISUBRO,IERROR)
              ENDIF
            ELSE
              IF(NTEMP.GT.0)THEN
                CALL DPPP3(ZY,ZXLOW,ZXHIGH,NTEMP,ICASPL,IDATSW,   &
                           ZCENS,XTEMP1,XTEMP2,XTEMP3,XTEMP4,   &
                           YLOWLM,YUPPLM,A,B,MINMAX,   &
                           SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                           SHAPE6,SHAPE7,   &
                           IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                           ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                           IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                           IPPLDP,MAXOBV,ICENSO,IMETHD,   &
                           PPLOC,PPSCAL,   &
                           PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                           CCALBE,PPA0BW,PPA1BW,   &
                           WEIGHH,WEIGHV,   &
                           Y,X,D,NPLOTP,NPLOTV,NCURVE,   &
                           IBUGG3,ISUBRO,IERROR)
              ENDIF
            ENDIF
            NPLOT2=NPLOTP
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
            NPTEMP=NPLOT2-NPLOT1
            CALL DPPP4(PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                       CCALBE,PPA0BW,PPA1BW,   &
                       IFLAGU,IFRST,ILAST,   &
                       IBUGG2,IBUGG3,ISUBRO,IERROR)
 1440     CONTINUE
 1430     CONTINUE
 1420     CONTINUE
 1410     CONTINUE
        ELSEIF(NREPL.EQ.5)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3*NUMSE4*NUMSE5
          DO 1510 ISET1=1,NUMSE1
          DO 1520 ISET2=1,NUMSE2
          DO 1530 ISET3=1,NUMSE3
          DO 1540 ISET4=1,NUMSE4
          DO 1550 ISET5=1,NUMSE5
            K=0
            DO 1590 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3) .AND.   &
                 XIDTE4(ISET4).EQ.XDESGN(I,4) .AND.   &
                 XIDTE5(ISET5).EQ.XDESGN(I,5)   &
                )THEN
                K=K+1
                ZY(K)=Y1(I)
                ZXLOW(K)=X1(I)
                ZXHIGH(K)=XHIGH(I)
                ZCENS(K)=XCENS(I)
              ENDIF
 1590       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            NPLOT1=NPLOTP
            IF(NGROUP.EQ.0)THEN
              IF(NTEMP.GT.0)THEN
                CALL DPPP2(ZY,ZCENS,XLEVEL,NTEMP,ICASPL,NHIGH,   &
                           XTEMP1,XTEMP2,XTEMP3,   &
                           YLOWLM,YUPPLM,A,B,MINMAX,   &
                           SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                           SHAPE6,SHAPE7,   &
                           IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                           ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                           IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                           IPPLDP,MAXOBV,ICENSO,IMETHD,ILEVEL,   &
                           PPLOC,PPSCAL,   &
                           PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                           CCALBE,PPA0BW,PPA1BW,   &
                           WEIGHH,WEIGHV,   &
                           Y,X,D,NPLOTP,NPLOTV,NCURVE,   &
                           IBUGG3,ISUBRO,IERROR)
              ENDIF
            ELSE
              IF(NTEMP.GT.0)THEN
                CALL DPPP3(ZY,ZXLOW,ZXHIGH,NTEMP,ICASPL,IDATSW,   &
                           ZCENS,XTEMP1,XTEMP2,XTEMP3,XTEMP4,   &
                           YLOWLM,YUPPLM,A,B,MINMAX,   &
                           SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                           SHAPE6,SHAPE7,   &
                           IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                           ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                           IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                           IPPLDP,MAXOBV,ICENSO,IMETHD,   &
                           PPLOC,PPSCAL,   &
                           PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                           CCALBE,PPA0BW,PPA1BW,   &
                           WEIGHH,WEIGHV,   &
                           Y,X,D,NPLOTP,NPLOTV,NCURVE,   &
                           IBUGG3,ISUBRO,IERROR)
              ENDIF
            ENDIF
            NPLOT2=NPLOTP
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
            NPTEMP=NPLOT2-NPLOT1
            CALL DPPP4(PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                       CCALBE,PPA0BW,PPA1BW,   &
                       IFLAGU,IFRST,ILAST,   &
                       IBUGG2,IBUGG3,ISUBRO,IERROR)
 1550     CONTINUE
 1540     CONTINUE
 1530     CONTINUE
 1520     CONTINUE
 1510     CONTINUE
        ELSEIF(NREPL.EQ.6)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3*NUMSE4*NUMSE5*NUMSE6
          DO 1610 ISET1=1,NUMSE1
          DO 1620 ISET2=1,NUMSE2
          DO 1630 ISET3=1,NUMSE3
          DO 1640 ISET4=1,NUMSE4
          DO 1650 ISET5=1,NUMSE5
          DO 1660 ISET6=1,NUMSE6
            K=0
            DO 1690 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3) .AND.   &
                 XIDTE4(ISET4).EQ.XDESGN(I,4) .AND.   &
                 XIDTE5(ISET5).EQ.XDESGN(I,5) .AND.   &
                 XIDTE6(ISET6).EQ.XDESGN(I,6)   &
                )THEN
                K=K+1
                ZY(K)=Y1(I)
                ZXLOW(K)=X1(I)
                ZXHIGH(K)=XHIGH(I)
                ZCENS(K)=XCENS(I)
              ENDIF
 1690       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            NPLOT1=NPLOTP
            IF(NGROUP.EQ.0)THEN
              IF(NTEMP.GT.0)THEN
                CALL DPPP2(ZY,ZCENS,XLEVEL,NTEMP,ICASPL,NHIGH,   &
                           XTEMP1,XTEMP2,XTEMP3,   &
                           YLOWLM,YUPPLM,A,B,MINMAX,   &
                           SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                           SHAPE6,SHAPE7,   &
                           IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                           ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                           IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                           IPPLDP,MAXOBV,ICENSO,IMETHD,ILEVEL,   &
                           PPLOC,PPSCAL,   &
                           PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                           CCALBE,PPA0BW,PPA1BW,   &
                           WEIGHH,WEIGHV,   &
                           Y,X,D,NPLOTP,NPLOTV,NCURVE,   &
                           IBUGG3,ISUBRO,IERROR)
              ENDIF
            ELSE
              IF(NTEMP.GT.0)THEN
                CALL DPPP3(ZY,ZXLOW,ZXHIGH,NTEMP,ICASPL,IDATSW,   &
                           ZCENS,XTEMP1,XTEMP2,XTEMP3,XTEMP4,   &
                           YLOWLM,YUPPLM,A,B,MINMAX,   &
                           SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                           SHAPE6,SHAPE7,   &
                           IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                           ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                           IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                           IPPLDP,MAXOBV,ICENSO,IMETHD,   &
                           PPLOC,PPSCAL,   &
                           PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                           CCALBE,PPA0BW,PPA1BW,   &
                           WEIGHH,WEIGHV,   &
                           Y,X,D,NPLOTP,NPLOTV,NCURVE,   &
                           IBUGG3,ISUBRO,IERROR)
              ENDIF
            ENDIF
            NPLOT2=NPLOTP
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
            NPTEMP=NPLOT2-NPLOT1
            CALL DPPP4(PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                       CCALBE,PPA0BW,PPA1BW,   &
                       IFLAGU,IFRST,ILAST,   &
                       IBUGG2,IBUGG3,ISUBRO,IERROR)
 1660     CONTINUE
 1650     CONTINUE
 1640     CONTINUE
 1630     CONTINUE
 1620     CONTINUE
 1610     CONTINUE
        ENDIF
!
!               ***************************************************
!               **  STEP 10A--                                   **
!               **  CASE 4: ONE OR TWO HIGHLIGHT VARIABLES.      **
!               **          THIS CASE SUPPORTS CENSORING, BUT    **
!               **          NOT GROUPING.  FOR THIS CASE, ALL    **
!               **          VARIABLES MUST HAVE THE SAME LENGTH. **
!               ***************************************************
!
      ELSEIF(NRESP.EQ.1 .AND. NHIGH.GE.1)THEN
        ISTEPN='10A'
        IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'DPPP')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        J=0
        IMAX=NRIGHT(1)
        IF(NQ.LT.NRIGHT(1))IMAX=NQ
        DO 1710 I=1,IMAX
          IF(ISUB(I).EQ.0)GO TO 1710
          J=J+1
!
!         RESPONSE VARIABLE IN Y1
!
          IJ=MAXN*(ICOLR(1)-1)+I
          IF(ICOLR(1).LE.MAXCOL)Y1(J)=V(IJ)
          IF(ICOLR(1).EQ.MAXCP1)Y1(J)=PRED(I)
          IF(ICOLR(1).EQ.MAXCP2)Y1(J)=RES(I)
          IF(ICOLR(1).EQ.MAXCP3)Y1(J)=YPLOT(I)
          IF(ICOLR(1).EQ.MAXCP4)Y1(J)=XPLOT(I)
          IF(ICOLR(1).EQ.MAXCP5)Y1(J)=X2PLOT(I)
          IF(ICOLR(1).EQ.MAXCP6)Y1(J)=TAGPLO(I)
!
!         CENSORING VARIABLE IN XCENS
!
          ICOLC=1
          IF(ICENSO.EQ.'ON')THEN
            ICOLC=ICOLC+1
            ICOLT=ICOLR(ICOLC)
            IJ=MAXN*(ICOLT-1)+I
            IF(ICOLT.LE.MAXCOL)XCENS(J)=V(IJ)
            IF(ICOLT.EQ.MAXCP1)XCENS(J)=PRED(I)
            IF(ICOLT.EQ.MAXCP2)XCENS(J)=RES(I)
            IF(ICOLT.EQ.MAXCP3)XCENS(J)=YPLOT(I)
            IF(ICOLT.EQ.MAXCP4)XCENS(J)=XPLOT(I)
            IF(ICOLT.EQ.MAXCP5)XCENS(J)=X2PLOT(I)
            IF(ICOLT.EQ.MAXCP6)XCENS(J)=TAGPLO(I)
          ENDIF
!
!         HIGHLIGHT VARIABLE ONE IN X1
!
          IF(NHIGH.GE.1)THEN
            ICOLC=ICOLC+1
            ICOLT=ICOLR(ICOLC)
            IJ=MAXN*(ICOLT-1)+I
            IF(ICOLT.LE.MAXCOL)X1(J)=V(IJ)
            IF(ICOLT.EQ.MAXCP1)X1(J)=PRED(I)
            IF(ICOLT.EQ.MAXCP2)X1(J)=RES(I)
            IF(ICOLT.EQ.MAXCP3)X1(J)=YPLOT(I)
            IF(ICOLT.EQ.MAXCP4)X1(J)=XPLOT(I)
            IF(ICOLT.EQ.MAXCP5)X1(J)=X2PLOT(I)
            IF(ICOLT.EQ.MAXCP6)X1(J)=TAGPLO(I)
          ENDIF
!
!         HIGHLIGHT VARIABLE TWO IN XHIGH
!
          IF(NHIGH.GE.2)THEN
            ICOLC=ICOLC+1
            ICOLT=ICOLR(ICOLC)
            IJ=MAXN*(ICOLT-1)+I
            IF(ICOLT.LE.MAXCOL)XHIGH(J)=V(IJ)
            IF(ICOLT.EQ.MAXCP1)XHIGH(J)=PRED(I)
            IF(ICOLT.EQ.MAXCP2)XHIGH(J)=RES(I)
            IF(ICOLT.EQ.MAXCP3)XHIGH(J)=YPLOT(I)
            IF(ICOLT.EQ.MAXCP4)XHIGH(J)=XPLOT(I)
            IF(ICOLT.EQ.MAXCP5)XHIGH(J)=X2PLOT(I)
            IF(ICOLT.EQ.MAXCP6)XHIGH(J)=TAGPLO(I)
          ENDIF
!
 1710   CONTINUE
        NLOCAL=J
!
        IF(NHIGH.EQ.1)THEN
          CALL CODE(X1,NLOCAL,IWRITE,WEIGHH,XTEMP1,MAXOBV,   &
                    IBUGG3,IERROR)
        ELSE
          ICCTOF=0
          ICCTG1=0
          CALL CODCT2(X1,XHIGH,NLOCAL,ICCTOF,ICCTG1,IWRITE,   &
                      WEIGHH,XTEMP1,XTEMP2,   &
                      IBUGG3,ISUBRO,IERROR)
        ENDIF
!
!       *****************************************************
!       **  STEP 10B--                                     **
!       **  FORM THE VERTICAL AND HORIZONTAL AXIS          **
!       **  VALUES Y(.) AND X(.) FOR THE PLOT.             **
!       **                                                 **
!       **  FOR THIS CASE, WE NEED TO LOOP THROUGH THE     **
!       **  VARIOUS REPLICATIONS.                          **
!       *****************************************************
!
        IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'DPPP')THEN
          ISTEPN='10B'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1731)
 1731     FORMAT('***** FROM THE MIDDLE  OF DPPP--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1732)ICASPL,NUMVAR,IDATSW,NLOCAL
 1732     FORMAT('ICASPL,NUMVAR,IDATSW,NQ = ',   &
                 A4,I8,2X,A4,I8)
          CALL DPWRST('XXX','BUG ')
          IF(NLOCAL.GE.1)THEN
            DO 1735 I=1,NLOCAL
              WRITE(ICOUT,1736)I,Y1(I),XCENS(I),WEIGHH(I)
 1736         FORMAT('I,Y1(I),XCENS(I),WEIGHH(I,1) = ',I8,3F12.5)
              CALL DPWRST('XXX','BUG ')
 1735       CONTINUE
          ENDIF
        ENDIF
!
!       *****************************************************
!       **  STEP 10C--                                     **
!       **  GENERATE THE PROBABILITY PLOT (RAW DATA CASE   **
!       **  ONLY).                                         **
!       *****************************************************
!
        NPLOTP=0
        NCURVE=1
        CALL DPPP2(Y1,XCENS,XLEVEL,NLOCAL,ICASPL,NHIGH,   &
                   XTEMP1,XTEMP2,XTEMP3,   &
                   YLOWLM,YUPPLM,A,B,MINMAX,   &
                   SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                   SHAPE6,SHAPE7,   &
                   IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                   ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                   IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                   IPPLDP,MAXOBV,ICENSO,IMETHD,ILEVEL,   &
                   PPLOC,PPSCAL,   &
                   PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                   CCALBE,PPA0BW,PPA1BW,   &
                   WEIGHH,WEIGHV,   &
                   Y,X,D,NPLOTP,NPLOTV,NCURVE,   &
                   IBUGG3,ISUBRO,IERROR)
!
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IF(IERROR.EQ.'YES')THEN
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,9001)(IANS(I),I=1,MIN(100,IWIDTH))
 9001     FORMAT(100A1)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
      IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'DPPP')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPP--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR
 9012   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        IF(IFOUND.EQ.'NO')GO TO 9099
        WRITE(ICOUT,9013)NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2
 9013   FORMAT('NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2 = ',   &
               I8,I8,I8,2X,A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)MINMAX
 9016   FORMAT('MINMAX = ',I8)
        CALL DPWRST('XXX','BUG ')
        IF(NPLOTP.GE.1)THEN
          DO 9020 I=1,NPLOTP
            WRITE(ICOUT,9021)I,Y(I),X(I),D(I)
 9021       FORMAT('I,Y(I),X(I),D(I) = ',I8,3F12.5)
            CALL DPWRST('XXX','BUG ')
 9020     CONTINUE
        ENDIF
      ENDIF
!
 9099 CONTINUE
      RETURN
      END SUBROUTINE DPPP
      SUBROUTINE DPPP2(Y,X,XLEVEL,N,ICASPL,NHIGH,   &
                       XTEMP1,Y2TEMP,X2TEMP,   &
                       YLOWLM,YUPPLM,A,B,MINMAX,   &
                       SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                       SHAPE5,SHAPE6,SHAPE7,   &
                       IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                       ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                       IGETDF,ICONDF,IGOMDF,IKATDF,   &
                       IGIGDF,IGEODF,   &
                       IPPLDP,MAXOBV,ICENSO,IMETHD,ILEVEL,   &
                       PPLOC,PPSCAL,   &
                       PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                       CCALBE,PPA0BW,PPA1BW,   &
                       WEIGHH,WEIGHV,   &
                       Y2,X2,D2,N2,NPLOTV,NCURVE,   &
                       IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--GENERATE A PAIR OF COORDINATE VECTORS THAT WILL DEFINE
!              A PROBABILITY PLOT FOR A SPECIFIED  DISTRIBUTION FOR
!              THE RAW DATA CASE.  CENSORED CASE ALSO SUPPORTED.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--APRIL     1978.
!     UPDATED         --MAY       1978.
!     UPDATED         --JUNE      1978.
!     UPDATED         --OCTOBER   1978.
!     UPDATED         --MARCH     1979.
!     UPDATED         --APRIL     1979.
!     UPDATED         --JANUARY   1981.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MARCH     1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --MAY       1990.  IG, WALD, RIG, FL (SAUNDERS)
!     UPDATED         --MAY       1992.  MOVE KPAR SINCE UNDEFINED
!     UPDATED         --MAY       1993.  MINMAX FOR EV1/EV2/WEIB DIST.
!     UPDATED         --DECEMBER  1993.  GENERALIZED PARETO
!     UPDATED         --DECEMBER  1993.  FIX TRACE INFO
!     UPDATED         --SEPTEMBER 1994.  ADD 9 DISTRIBUTIONS, FIX TRIANG
!     UPDATED         --APRIL     1995.  ADD NEW DISTRIBUTIONS
!     UPDATED         --SEPTEMBER 1995.  ADD NEW DISTRIBUTIONS
!     UPDATED         --OCTOBER   1995.  ADD NEW DISTRIBUTIONS
!     UPDATED         --DECEMBER  1995.  ADD NEW DISTRIBUTIONS
!     UPDATED         --JANUARY   1996.  ADD DOUBLE GAMMA, MIELKE'S
!                                        BETA-KAPPA, FOLDED CAUCHY
!     UPDATED         --JANUARY   1996.  DO NOT HANDLE LOG-NORMAL SEPARATELY
!     UPDATED         --FEBRUARY  1996.  BETA-BINOMIAL, BETA-PASCAL,
!                                        GENERALIZED EXPONENTIAL
!     UPDATED         --MAY       1996.  RECIPROCAL
!     UPDATED         --FEBRUARY  1998.  FOR BINNED DATA, CHECK FOR
!                                        ZERO COUNT BINS
!     UPDATED         --MAY       1998.  NORMAL MIXTURE
!     UPDATED         --MAY       1998.  INVERTED GAMMA
!     UPDATED         --AUGUST    2001.  GENERALIZED LAMBDA
!     UPDATED         --SEPTEMBER 2001.  JOHNSON SB, JOHNSON SU,
!                                        INVERTED WEIBULL,
!                                        LOG DOUBLE EXPONENTIAL
!     UPDATED         --MAY       2002.  TWO-SIDED POWER
!     UPDATED         --MAY       2002.  BIWEIBULL
!     UPDATED         --JANUARY   2003.  G-AND-H
!     UPDATED         --APRIL     2003.  LANDAU
!     UPDATED         --MAY       2003.  ERROR
!     UPDATED         --JUNE      2003.  TRAPEZOID
!     UPDATED         --JUNE      2003.  GENERALIZED TRAPEZOID
!     UPDATED         --NOVEMBER  2003.  FOLDED T
!     UPDATED         --DECEMBER  2003.  SLASH, INVERTED BETA,
!                                        SKEWED NORMAL, SKEWED T,
!                                        GOMPERTZ-MAKEHAM
!     UPDATED         --MARCH     2004.  LOG-SKEW-NORMAL
!     UPDATED         --MARCH     2004.  LOG-SKEW-T
!     UPDATED         --MARCH     2004.  POLYA
!     UPDATED         --APRIL     2004.  HERMITE
!     UPDATED         --JUNE      2004.  SKEW DOUBLE EXPONENTIAL
!     UPDATED         --JUNE      2004.  ASYMMETRIC DOUBLE EXPONENTIAL
!     UPDATED         --JUNE      2004.  MAXWELL, RAYLEIGH
!     UPDATED         --JULY      2004.  ALTERNATE DEFINITION FOR
!                                        GOMPERTZ-MAKEHAM
!     UPDATED         --AUGUST    2004.  GENERALIZED INVERSE GAUSSIAN
!     UPDATED         --AUGUST    2004.  MCLEISH
!     UPDATED         --AUGUST    2004.  BESSEL I-FUNCTION
!     UPDATED         --SEPTEMBER 2004.  SUPPORT FOR:
!                                          SET PROBABILITY PLOT DATA
!                                              POINTS
!     UPDATED         --OCTOBER   2004.  SUPPORT FOR CENSORED DATA
!     UPDATED         --OCTOBER   2004.  FOR BINNED DATA, REMOVE
!                                        ZERO FREQUENCY BINS
!     UPDATED         --MAY       2005.  FOR BINNED DATA, SUPPORT
!                                        CASE WHERE LOWER AND UPPER
!                                        LIMITS OF BIN GIVEN (AS
!                                        OPPOSSED TO JUST MID-POINTS)
!     UPDATED         --MAY       2005.  ADD ISUBRO BUG SWITCH
!     UPDATED         --JULY      2005.  CALL LIST TO LGAPPF AND SNPPF
!     UPDATED         --FEBRUARY  2006.  GENERALIZED LOGISTIC TYPE 5
!     UPDATED         --FEBRUARY  2006.  WAKEBY
!     UPDATED         --FEBRUARY  2006.  FMLK PARAMERIZATION OF
!                                        GENERALIZED TUKEY-LAMBDA
!     UPDATED         --MARCH     2006.  BETA-NORMAL
!     UPDATED         --MARCH     2006.  GENERALIZED LOGISTIC TYPE 2
!     UPDATED         --MARCH     2006.  GENERALIZED LOGISTIC TYPE 3
!     UPDATED         --MARCH     2006.  GENERALIZED LOGISTIC TYPE 4
!     UPDATED         --MARCH     2006.  ASYMMETRIC LOG LAPLACE
!     UPDATED         --MAY       2006.  BETA GEOMETRIC
!     UPDATED         --MAY       2006.  ZETA
!     UPDATED         --MAY       2006.  ZIPF
!     UPDATED         --MAY       2006.  BOREL-TANNER
!     UPDATED         --MAY       2006.  BETA NEGATIVE BINOMIAL
!     UPDATED         --JUNE      2006.  LAGRANGE POISSON
!     UPDATED         --JUNE      2006.  LEADS IN COIN TOSSING
!     UPDATED         --JUNE      2006.  CLASSICAL MATCHING
!     UPDATED         --JUNE      2006.  CLASSICAL OCCUPANCY
!     UPDATED         --JUNE      2006.  LOG BETA
!     UPDATED         --JUNE      2006.  POLYA AEPPLI
!     UPDATED         --JUNE      2006.  LOST GAMES
!     UPDATED         --JUNE      2006.  GENERALIZED LOGARITHMIC
!                                        SERIES
!     UPDATED         --JULY      2006.  GENERALIZED NEGATIVE
!                                        BINOMIAL
!     UPDATED         --JULY      2006.  GEETA
!     UPDATED         --JULY      2006.  QUASI BINOMIAL TYPE I
!     UPDATED         --AUGUST    2006.  CONSUL (GENERALIZED GEOMTRIC)
!     UPDATED         --AUGUST    2006.  LAGRANGE KATZ
!     UPDATED         --OCTOBER   2006.  SHAPE PARAMETER FOR SEMI-CIRCULAR
!                                        DISTRIBUTION
!     UPDATED         --NOVEMBER  2006.  DISCRETE WEIBULL
!     UPDATED         --NOVEMBER  2006.  GENERALIZED LOST GAMES
!     UPDATED         --JANUARY   2007.  TRUNCATED GENERALIZED
!                                        NEGATIVE BINOMIAL
!     UPDATED         --JANUARY   2007.  KATZ
!     UPDATED         --FEBRUARY  2007.  TOPP AND LEONE
!     UPDATED         --FEBRUARY  2007.  GENERALIZED TOPP AND LEONE
!     UPDATED         --FEBRUARY  2007.  REFLECTED GENERALIZED
!                                        TOPP AND LEONE
!     UPDATED         --MARCH     2007.  FOR TRIANGULAR, LET USER
!                                        SPECIFY LOWER/UPPER LIMIT
!                                        PARAMETERS
!     UPDATED         --JUNE      2007.  FOR TWO-SIDED POWER, LET USER
!                                        SPECIFY LOWER/UPPER LIMIT
!                                        PARAMETERS
!     UPDATED         --AUGUST    2007.  SUPPORT CENSORING FOR
!                                        FREQUENCY DATA
!     UPDATED         --SEPTEMBER 2007.  SLOPE
!     UPDATED         --SEPTEMBER 2007.  TWO-SIDED SLOPE
!     UPDATED         --SEPTEMBER 2007.  OGIVE
!     UPDATED         --SEPTEMBER 2007.  TWO-SIDED OGIVE
!     UPDATED         --OCTOBER   2007.  BURR TYPE 1 (= UNIFORM)
!     UPDATED         --OCTOBER   2007.  BURR TYPE 2
!     UPDATED         --OCTOBER   2007.  BURR TYPE 3
!     UPDATED         --OCTOBER   2007.  BURR TYPE 4
!     UPDATED         --OCTOBER   2007.  BURR TYPE 5
!     UPDATED         --OCTOBER   2007.  BURR TYPE 6
!     UPDATED         --OCTOBER   2007.  BURR TYPE 7
!     UPDATED         --OCTOBER   2007.  BURR TYPE 8
!     UPDATED         --OCTOBER   2007.  BURR TYPE 9
!     UPDATED         --OCTOBER   2007.  BURR TYPE 10
!     UPDATED         --OCTOBER   2007.  BURR TYPE 11
!     UPDATED         --OCTOBER   2007.  BURR TYPE 12
!     UPDATED         --OCTOBER   2007.  DOUBLY-PARETO UNIFORM
!     UPDATED         --OCTOBER   2007.  UNEVEN TWO-SIDED POWER
!     UPDATED         --OCTOBER   2007.  KUMARASWAMY
!     UPDATED         --DECEMBER  2007.  REFLECTED POWER
!     UPDATED         --JANUARY   2008.  MUTH
!     UPDATED         --FEBRUARY  2008.  LOGISTIC-EXPONENTIAL
!     UPDATED         --FEBRUARY  2008.  SIGMA PARAMETER FOR MAXWELL
!                                        IS REALLY A SCALE PARAMETER
!     UPDATED         --MARCH     2008.  TRUNCATED PARETO
!     UPDATED         --MARCH     2008.  BRITTLE FRACTURE
!     UPDATED         --MARCH     2008.  3-PARAMETER LOGISTIC-EXPONENTIAL
!     UPDATED         --MAY       2008.  RENAME MIELKE'S BETA-KAPPA
!     UPDATED         --MAY       2008.  KAPPA
!     UPDATED         --MAY       2008.  PEARSON TYPE 3
!     UPDATED         --JULY      2008.  MODIFY GIG PARAMETERIZATION
!     UPDATED         --JULY      2008.  2-SHAPE PARAMETERIZATION
!                                        FOR GIG
!     UPDATED         --AUGUST    2009.  GROUPED DATA MOVED TO A
!                                        SEPARATE SUBROUTINE
!     UPDATED         --SEPTEMBER 2009.  USE "GENERIC" PARAMETERS
!                                        (SIMPLIFY USE BY OTHER
!                                        ROUTINES)
!     UPDATED         --OCTOBER   2009.  MOVE COMPUTATION OF PPA0,
!                                        PPA1, ETC., TO THIS ROUTINE
!                                        (NOTE THAT DPPP ROUTINE IS
!                                        STILL RESPONSIBLE FOR UPDATING
!                                        PARAMETER TABLE, BUT COMPUTING
!                                        HERE SIMPLIFIES USE BY OTHER
!                                        ROUTINES, E.G. DPGOF9)
!     UPDATED         --JANUARY   2010.  SUPPORT FOR "HIGHLIGHTING"
!     UPDATED         --JULY      2010.  END EFFECTS WEIBULL
!     UPDATED         --AUGUST    2010.  BRITTLE FIBER WEIBULL
!     UPDATED         --SEPTEMBER 2010.  SUPPORT A "LEVEL" VARIABLE
!                                        FOR BRITTLE FIBER WEIBULL
!                                        (MAY ADD TO A FEW OTHERS AT
!                                        A LATER TIME).  NOTE THAT THIS
!                                        IS CURRENTLY ONLY SUPPORTED
!                                        FOR THE SINGLE RESPONSE
!                                        VARIABLE RAW DATA CASE
!     UPDATED         --JULY      2019.  REDUCE SCRATCH SPACE USAGE
!                                        (BY TWO ARRAYS).
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IADEDF
      CHARACTER*4 IGEPDF
      CHARACTER*4 IMAKDF
      CHARACTER*4 IBEIDF
      CHARACTER*4 ILGADF
      CHARACTER*4 ISKNDF
      CHARACTER*4 IGLDDF
      CHARACTER*4 IBGEDF
      CHARACTER*4 IGETDF
      CHARACTER*4 ICONDF
      CHARACTER*4 IGOMDF
      CHARACTER*4 IKATDF
      CHARACTER*4 IGIGDF
      CHARACTER*4 IGEODF
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ICENSO
      CHARACTER*4 IMETHD
      CHARACTER*4 ILEVEL
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 IWRITE
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION XLEVEL(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION D2(*)
      DIMENSION XTEMP1(*)
      DIMENSION Y2TEMP(*)
      DIMENSION X2TEMP(*)
!
      DIMENSION WEIGHH(*)
      DIMENSION WEIGHV(*)
!CCCC DIMENSION PREDBW(*)
!CCCC DIMENSION RESBW(*)
!
      PARAMETER (MAXLEV=10)
      DOUBLE PRECISION API(MAXLEV)
      DOUBLE PRECISION LI(MAXLEV)
      DOUBLE PRECISION PPFOUT(1)
      DOUBLE PRECISION DXTEMP(1)
!
      DOUBLE PRECISION LANPPF
      DOUBLE PRECISION DX2OUT
      DOUBLE PRECISION DLOC
      DOUBLE PRECISION DSCALE
!
      DOUBLE PRECISION QUAGLO
      DOUBLE PRECISION QUAWAK
      DOUBLE PRECISION XPAR(5)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
      ISUBN1='DPPP'
      ISUBN2='2   '
      IERROR='NO'
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPP2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,171)
  171   FORMAT('***** AT THE BEGINNING OF DPPP2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,172)ICASPL,N,NPLOTV,MINMAX,IPPLDP
  172   FORMAT('ICASPL,N,NPLOTV,MINMAX,IPPLDP = ',A4,2X,4I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,174)N2,NCURVE,ILEVEL
  174   FORMAT('N2,NCURVE,ILEVEL = ',2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        IF(N.GE.1)THEN
          IF(NHIGH.GT.0)THEN
            DO 181 I=1,N
              WRITE(ICOUT,182)I,Y(I),X(I),WEIGHH(I)
  182         FORMAT('I,Y(I),X(I),WEIGHH(I) = ',I8,3G12.5)
              CALL DPWRST('XXX','BUG ')
  181       CONTINUE
          ELSE
            DO 185 I=1,N
              WRITE(ICOUT,186)I,Y(I),X(I),XLEVEL(I)
  186         FORMAT('I,Y(I),X(I),XLEVEL(I) = ',I8,3G12.5)
              CALL DPWRST('XXX','BUG ')
  185       CONTINUE
          ENDIF
        ENDIF
      ENDIF
!
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LE.1)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)
   46   FORMAT('***** ERROR IN PROBABILITY PLOT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)
   47   FORMAT('      THE NUMBER OF OBSERVATIONS WAS LESS THAN OR ',   &
               'EQUAL TO 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,49)N
   49   FORMAT('      THE ENTERED NUMBER OF OBSERVATIONS HERE = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=Y(1)
      DO 60 I=1,N
        IF(Y(I).NE.HOLD)GO TO 69
   60 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,62)HOLD
   62 FORMAT('      ALL INPUT VERTICAL AXIS ELEMENTS ARE ',   &
             'IDENTICALLY EQUAL TO ',G15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
   69 CONTINUE
!
!
!               ********************************************
!               **  STEP 1B--                             **
!               **  FOR THE CASE WHERE THERE ARE MULIPLE  **
!               **  LEVELS (E.G., BRITTLE FIBER WEIBULL), **
!               **  COMPUTE THE "MIXING PROPORTION" FOR   **
!               **  THE VARIOUS LEVELS.                   **
!               ********************************************
!
      IF(ILEVEL.EQ.'ON')THEN
        CALL DISTIN(XLEVEL,N,IWRITE,XTEMP1,NILEVE,IBUGG3,IERROR)
        IF(NILEVE.GT.MAXLEV)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,71)
   71     FORMAT('      FOR THE MULTIPLE LEVELS CASE, THE MAXIMUM ',   &
                 'NUMBER OF DISTINCT LEVELS EXCEEDED.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,73)NILEVE
   73     FORMAT('      NUMBER OF LEVELS DETECTED        = ',I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,75)MAXLEV
   75     FORMAT('      MAXIMUM NUMBER OF LEVELS ALOWED  = ',I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
        CALL SORT(XTEMP1,NILEVE,XTEMP1)
        DO 80 I=1,NILEVE
          AHOLD=XTEMP1(I)
          ICNT=0
          DO 81 J=1,N
            IF(XLEVEL(J).EQ.AHOLD)THEN
              ICNT=ICNT+1
            ENDIF
   81     CONTINUE
          LI(I)=DBLE(AHOLD)
          API(I)=DBLE(ICNT)/DBLE(N)
!
          IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPP2')THEN
            WRITE(ICOUT,86)I,LI(I),API(I)
   86       FORMAT('I,LI(I),API(I) = ',I5,2G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
   80   CONTINUE
      ENDIF
!
!               **************************************************
!               **  STEP 2--                                    **
!               **  IF SET PROBABILITY PLOT DATA POINTS COMMAND **
!               **  WAS ENTERED, THIN DATA SET BY COMPUTING     **
!               **  PERCENTILES OF THE DATA.  CURRENTLY         **
!               **  ONLY SUPPORTED FOR UNBINNED DATA.           **
!               **************************************************
!
      IF(IPPLDP.GT.0 .AND. ICENSO.EQ.'OFF' .AND. ILEVEL.EQ.'OFF')THEN
!
        IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPP2')THEN
          WRITE(ICOUT,201)IPPLDP,NPERC
  201     FORMAT('***** THIN DATA, IPPLDP,NPERC=',2I8)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        NPERC=MAX(20,IPPLDP)
        NPERC=MIN(NPERC,N)
        CALL SORT(Y,N,XTEMP1)
        ASTRT=0.0
        ASTOP=100.0
        AINC=(ASTOP - ASTRT)/REAL(NPERC+1)
        IWRITE='OFF'
        DO 210 I=1,NPERC
          P100=ASTRT + REAL(I)*AINC
          CALL PERCEN(P100,XTEMP1,N,IWRITE,X2,MAXOBV,   &
                      XPERC,IBUGG3,IERROR)
          Y(I)=XPERC
  210   CONTINUE
        N=NPERC
!
        IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPP2')THEN
          WRITE(ICOUT,213)IPPLDP,NPERC,N
  213     FORMAT('      IPPLDP, NPERC, N = ',3I8)
          CALL DPWRST('XXX','BUG ')
          DO 217 I=1,N
            WRITE(ICOUT,218)I,Y(I)
  218       FORMAT('      I, Y(I) = ',I8,G15.7)
            CALL DPWRST('XXX','BUG ')
  217     CONTINUE
        ENDIF
!
      ENDIF
!
!               *****************************************************
!               **  STEP 3--                                       **
!               **  DETERMINE PLOT COORDINATES FOR THE 1-VARIABLE  **
!               **  CASE (THAT IS, FOR THE RAW DATA CASE)          **
!               *****************************************************
!
!
!CCCC OCTOBER 2004.  FOR CENSORED CASE, CHECK THAT SECOND VARIABLE
!CCCC                CONTAINS TWO DISTINCT VALUES, SET TO 1 AND 0.
!
      IF(ICENSO.EQ.'ON')THEN
        CALL DISTIN(X,N,IWRITE,XTEMP1,NDIST,IBUGG3,IERROR)
        IF(NDIST.EQ.1)THEN
          DO 302 I=1,N
            X(I)=1.0
  302     CONTINUE
        ELSEIF(NDIST.EQ.2)THEN
          IF(XTEMP1(1).EQ.1.0 .OR. XTEMP1(2).EQ.1.0)THEN
            DO 303 I=1,N
              IF(X(I).NE.1.0)X(I)=0.0
  303       CONTINUE
          ELSE
            ATEMP1=MIN(XTEMP1(1),XTEMP1(2))
            ATEMP2=MAX(XTEMP1(1),XTEMP1(2))
            DO 308 I=1,N
              IF(X(I).EQ.ATEMP1)X(I)=1.0
              IF(X(I).EQ.ATEMP2)X(I)=0.0
  308       CONTINUE
          ENDIF
        ELSE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT, 305)
  305     FORMAT('      FOR CENSORED DATA, THE CENSORING VARIABLE')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT, 306)
  306     FORMAT('      SHOULD CONTAIN AT MOST TWO DISTINCT VALUES.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT, 307)NDIST
  307     FORMAT('      ',I8,' DISTINCT VALUES FOUND.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
        CALL SORTC(Y,X,N,Y2TEMP,XTEMP1)
        DO 310 I=1,N
          X(I)=XTEMP1(I)
  310   CONTINUE
        IF(NHIGH.GE.1)THEN
          CALL SORTC(Y,WEIGHH,N,XTEMP1,WEIGHV)
          DO 311 I=1,N
            WEIGHH(I)=WEIGHV(I)
  311     CONTINUE
        ELSEIF(ILEVEL.EQ.'ON')THEN
          CALL SORTC(Y,XLEVEL,N,XTEMP1,WEIGHV)
          DO 312 I=1,N
            XLEVEL(I)=WEIGHV(I)
  312     CONTINUE
        ENDIF
        XMIN=Y2TEMP(1)
        XMAX=Y2TEMP(N)
        CALL UNIME3(N,X2TEMP,X,IMETHD)
      ELSE
        IF(NHIGH.GE.1)THEN
          CALL SORTC(Y,WEIGHH,N,Y2TEMP,WEIGHV)
          DO 313 I=1,N
            WEIGHH(I)=WEIGHV(I)
  313     CONTINUE
        ELSEIF(ILEVEL.EQ.'ON')THEN
          CALL SORTC(Y,XLEVEL,N,Y2TEMP,WEIGHV)
          DO 314 I=1,N
            XLEVEL(I)=WEIGHV(I)
  314     CONTINUE
        ELSE
          CALL SORT(Y,N,Y2TEMP)
        ENDIF
        XMIN=Y2TEMP(1)
        XMAX=Y2TEMP(N)
        CALL UNIMED(N,X2TEMP)
      ENDIF
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPP2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,371)N
  371   FORMAT('***** AFTER CREATE X2TEMP,Y2TEMP, N = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 373 I=1,MIN(100,N)
          WRITE(ICOUT,375)I,X2TEMP(I),Y2TEMP(I)
  375     FORMAT('I,X2TEMP(I),Y2TEMP(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
  373   CONTINUE
      ENDIF
!
      EPS=0.00001
      IF(XMIN.LT.YLOWLM)YLOWLM=XMIN-EPS
      IF(XMAX.GT.YUPPLM)YUPPLM=XMAX+EPS
!
      ICNT=0
!
      IF(ICASPL.EQ.'UNIF')THEN
        DO 1001 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 1001
          ICNT=ICNT+1
          CALL UNIPPF(X2TEMP(I),X2OUT)
          X2TEMP(ICNT)=X2OUT
 1001   CONTINUE
      ELSEIF(ICASPL.EQ.'NORM')THEN
        DO 1011 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 1011
          ICNT=ICNT+1
          CALL NODPPF(DBLE(X2TEMP(I)),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 1011   CONTINUE
      ELSEIF(ICASPL.EQ.'LOGI')THEN
        DO 1021 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 1021
          ICNT=ICNT+1
          CALL LOGPPF(X2TEMP(I),X2OUT)
          X2TEMP(ICNT)=X2OUT
 1021   CONTINUE
      ELSEIF(ICASPL.EQ.'DEXP')THEN
        DO 1031 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 1031
          ICNT=ICNT+1
          CALL DEXPPF(X2TEMP(I),X2OUT)
          X2TEMP(ICNT)=X2OUT
 1031   CONTINUE
      ELSEIF(ICASPL.EQ.'CAUC')THEN
        DO 1041 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 1041
          ICNT=ICNT+1
          CALL CAUPPF(X2TEMP(I),X2OUT)
          X2TEMP(ICNT)=X2OUT
 1041   CONTINUE
      ELSEIF(ICASPL.EQ.'TULA')THEN
        DO 1051 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 1051
          ICNT=ICNT+1
          CALL LAMPPF(X2TEMP(I),SHAPE1,X2OUT)
          X2TEMP(ICNT)=X2OUT
 1051   CONTINUE
      ELSEIF(ICASPL.EQ.'LOGN' .OR. ICASPL.EQ.'3LGN')THEN
        DO 1061 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 1061
          ICNT=ICNT+1
          CALL LGNPPF(X2TEMP(I),SHAPE1,X2OUT)
          X2TEMP(ICNT)=X2OUT
 1061   CONTINUE
      ELSEIF(ICASPL.EQ.'HNOR')THEN
        DO 1071 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 1071
          ICNT=ICNT+1
          CALL HFNPPF(X2TEMP(I),X2OUT)
          X2TEMP(ICNT)=X2OUT
 1071   CONTINUE
