        DO 2291 I=1,N
          ICNT=ICNT+1
          CALL DIWPPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DBLE(SHAPE2),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2291   CONTINUE
      ELSEIF(ICASPL.EQ.'GLGP')THEN
        DO 2301 I=1,N
          ICNT=ICNT+1
          CALL GLGPPF(X2TEMP(I),SHAPE1,INT(SHAPE2+0.1),SHAPE3,X2OUT)
          X2TEMP(ICNT)=X2OUT
 2301   CONTINUE
      ELSEIF(ICASPL.EQ.'TGNB')THEN
        DO 2311 I=1,N
          ICNT=ICNT+1
          CALL GNTPPF(X2TEMP(I),SHAPE1,SHAPE2,SHAPE3,INT(SHAPE4+0.1),   &
                      X2OUT)
          X2TEMP(ICNT)=X2OUT
 2311   CONTINUE
      ELSEIF(ICASPL.EQ.'TOPL')THEN
        DO 2321 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2321
          ICNT=ICNT+1
          CALL TOPPPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2321   CONTINUE
      ELSEIF(ICASPL.EQ.'GTOL')THEN
        DO 2331 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2331
          ICNT=ICNT+1
          CALL GTLPPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DBLE(SHAPE2),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2331   CONTINUE
      ELSEIF(ICASPL.EQ.'RGTL')THEN
        DO 2341 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2341
          ICNT=ICNT+1
          CALL RGTPPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DBLE(SHAPE2),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2341   CONTINUE
      ELSEIF(ICASPL.EQ.'SLOP')THEN
        DO 2351 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2351
          ICNT=ICNT+1
          CALL SLOPPF(X2TEMP(I),SHAPE1,X2OUT)
          X2TEMP(ICNT)=X2OUT
 2351   CONTINUE
      ELSEIF(ICASPL.EQ.'OGIV')THEN
        DO 2361 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2361
          ICNT=ICNT+1
          CALL OGIPPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2361   CONTINUE
      ELSEIF(ICASPL.EQ.'TSSL')THEN
        DO 2371 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2371
          ICNT=ICNT+1
          CALL TSSPPF(X2TEMP(I),SHAPE2,SHAPE1,A,B,X2OUT)
          X2TEMP(ICNT)=X2OUT
 2371   CONTINUE
      ELSEIF(ICASPL.EQ.'TSOG')THEN
        DO 2381 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2381
          ICNT=ICNT+1
          CALL TSOPPF(DBLE(X2TEMP(I)),DBLE(SHAPE2),DBLE(SHAPE1),   &
                      DBLE(A),DBLE(B),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2381   CONTINUE
      ELSEIF(ICASPL.EQ.'BUR2')THEN
        DO 2391 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2391
          ICNT=ICNT+1
          CALL BU2PPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2391   CONTINUE
      ELSEIF(ICASPL.EQ.'BUR3')THEN
        DO 2401 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2401
          ICNT=ICNT+1
          CALL BU3PPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DBLE(SHAPE2),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2401   CONTINUE
      ELSEIF(ICASPL.EQ.'BUR4')THEN
        DO 2411 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2411
          ICNT=ICNT+1
          CALL BU4PPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DBLE(SHAPE2),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2411   CONTINUE
      ELSEIF(ICASPL.EQ.'BUR5')THEN
        DO 2421 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2421
          ICNT=ICNT+1
          CALL BU5PPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DBLE(SHAPE2),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2421   CONTINUE
      ELSEIF(ICASPL.EQ.'BUR6')THEN
        DO 2431 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2431
          ICNT=ICNT+1
          CALL BU6PPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DBLE(SHAPE2),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2431   CONTINUE
      ELSEIF(ICASPL.EQ.'BUR7')THEN
        DO 2441 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2441
          ICNT=ICNT+1
          CALL BU7PPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2441   CONTINUE
      ELSEIF(ICASPL.EQ.'BUR8')THEN
        DO 2451 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2451
          ICNT=ICNT+1
          CALL BU8PPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2451   CONTINUE
      ELSEIF(ICASPL.EQ.'BUR9')THEN
        DO 2461 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2461
          ICNT=ICNT+1
          CALL BU9PPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DBLE(SHAPE2),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2461   CONTINUE
      ELSEIF(ICASPL.EQ.'BU10')THEN
        DO 2471 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2471
          ICNT=ICNT+1
          CALL B10PPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2471   CONTINUE
      ELSEIF(ICASPL.EQ.'BU11')THEN
        DO 2481 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2481
          ICNT=ICNT+1
          CALL B11PPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2481   CONTINUE
      ELSEIF(ICASPL.EQ.'BU12')THEN
        DO 2491 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2491
          ICNT=ICNT+1
          CALL B12PPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DBLE(SHAPE2),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2491   CONTINUE
      ELSEIF(ICASPL.EQ.'DPUN')THEN
        ALOCT=0.0
        SCALET=1.0
        DO 2501 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2501
          ICNT=ICNT+1
          CALL DPUPPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DBLE(SHAPE2),   &
                      DBLE(ALOCT),DBLE(SCALET),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2501   CONTINUE
!
      ELSEIF(ICASPL.EQ.'KUMA')THEN
        DO 2511 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2511
          ICNT=ICNT+1
          CALL KUMPPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DBLE(SHAPE2),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2511   CONTINUE
      ELSEIF(ICASPL.EQ.'RPOW')THEN
        DO 2521 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2521
          ICNT=ICNT+1
          CALL RPOPPF(X2TEMP(I),SHAPE1,X2OUT)
          X2TEMP(ICNT)=X2OUT
 2521   CONTINUE
      ELSEIF(ICASPL.EQ.'UTSP')THEN
        DO 2531 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2531
          ICNT=ICNT+1
          CALL UTSPPF(X2TEMP(I),SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                      SHAPE6,X2OUT)
          X2TEMP(ICNT)=X2OUT
 2531   CONTINUE
      ELSEIF(ICASPL.EQ.'MUTH')THEN
        DO 2541 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2541
          ICNT=ICNT+1
          CALL MUTPPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2541   CONTINUE
      ELSEIF(ICASPL.EQ.'LEXP')THEN
        DO 2551 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2551
          ICNT=ICNT+1
          CALL LEXPPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2551   CONTINUE
      ELSEIF(ICASPL.EQ.'TPAR')THEN
        DO 2561 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2561
          ICNT=ICNT+1
          CALL TNPPPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DBLE(SHAPE2),   &
                      DBLE(SHAPE3),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2561   CONTINUE
      ELSEIF(ICASPL.EQ.'BFRA')THEN
        DO 2571 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2571
          ICNT=ICNT+1
          CALL BFRPPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DBLE(SHAPE2),   &
                      DBLE(SHAPE3),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2571   CONTINUE
      ELSEIF(ICASPL.EQ.'L3EX')THEN
        DO 2581 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2581
          ICNT=ICNT+1
          CALL LE3PPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DBLE(SHAPE2),   &
                      DBLE(SHAPE3),DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2581   CONTINUE
      ELSEIF(ICASPL.EQ.'KAPP')THEN
        DLOC=0.0D0
        DSCALE=1.0D0
        DO 2591 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2591
          ICNT=ICNT+1
          CALL KAPPPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DBLE(SHAPE2),   &
                      DLOC,DSCALE,DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2591   CONTINUE
      ELSEIF(ICASPL.EQ.'PEA3')THEN
        DLOC=0.0D0
        DSCALE=1.0D0
        DO 2601 I=1,N
          IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2601
          ICNT=ICNT+1
          CALL PE3PPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DLOC,DSCALE,DX2OUT)
          X2TEMP(ICNT)=REAL(DX2OUT)
 2601   CONTINUE
      ELSEIF(ICASPL.EQ.'EEWE')THEN
!
!       DO DIFFERENTLY DEPENDING ON WHETHER L IS CONSTANT OR VARIABLE
!
        IF(ILEVEL.EQ.'ON')THEN
          DO 2613 I=1,N
            IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2613
            ICNT=ICNT+1
            CALL EEWPPF(DBLE(X2TEMP(I)),DBLE(XLEVEL(I)),DBLE(SHAPE1),   &
                        DBLE(SHAPE2),DBLE(SHAPE3),DBLE(SHAPE4),   &
                        DX2OUT)
            X2TEMP(ICNT)=REAL(DX2OUT)
2613      CONTINUE
        ELSE
          DO 2611 I=1,N
            IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2611
            ICNT=ICNT+1
            CALL EEWPPF(DBLE(X2TEMP(I)),DBLE(SHAPE5),DBLE(SHAPE1),   &
                        DBLE(SHAPE2),DBLE(SHAPE3),DBLE(SHAPE4),   &
                        DX2OUT)
            X2TEMP(ICNT)=REAL(DX2OUT)
2611      CONTINUE
        ENDIF
      ELSEIF(ICASPL.EQ.'BFWE')THEN
        IF(ILEVEL.EQ.'ON')THEN
          NTEMP=1
          ALOC=0.0
          SCALE=1.0
          DO 2626 I=1,N
            IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2626
            ICNT=ICNT+1
            DXTEMP(1)=DBLE(X2TEMP(I))
            CALL BFWPP2(DXTEMP,NTEMP,LI,API,NILEVE,   &
                        DBLE(SHAPE1),DBLE(ALOC),DBLE(SCALE),   &
                        PPFOUT,   &
                        ISUBRO,IBUGG3,IERROR)
            X2TEMP(ICNT)=REAL(PPFOUT(1))
2626      CONTINUE
        ELSE
          DO 2621 I=1,N
            IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 2621
            ICNT=ICNT+1
            CALL BFWPPF(DBLE(X2TEMP(I)),DBLE(SHAPE1),DBLE(SHAPE2),   &
                        DX2OUT)
            X2TEMP(ICNT)=REAL(DX2OUT)
2621      CONTINUE
        ENDIF
      ENDIF
!
      NTEMP=ICNT
      IF(NHIGH.EQ.0)THEN
        DO 1910 I=1,NTEMP
          X2(N2+I)=PPLOC + PPSCAL*X2TEMP(I)
          D2(N2+I)=REAL(NCURVE)
 1910   CONTINUE
      ELSE
        DO 1911 I=1,NTEMP
          X2(N2+I)=PPLOC + PPSCAL*X2TEMP(I)
          D2(N2+I)=WEIGHH(I)
 1911   CONTINUE
      ENDIF
!
      ICNT2=0
      DO 1912 I=1,N
        IF(ICENSO.EQ.'ON' .AND. X(I).EQ.0.0)GO TO 1912
        ICNT2=ICNT2+1
        Y2(N2+ICNT2)=Y2TEMP(I)
 1912 CONTINUE
      N2OLD=N2
      NPTS=ICNT
      N2=N2+ICNT2
      NPLOTV=2
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPP2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1917)N2OLD,N2,NPTS
 1917   FORMAT('N2OLD,N2,NPTS = ',3I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     OCTOBER 2009: MOVE COMPUTATION OF PPA0, PPA1, PPCC, PPAOBW,
!                   AND PPA1BW HERE (INSTEAD OF DPPP).  THIS MAKES
!                   THE DPPP2 ROUTINE MORE USEFUL FOR OTHER ROUTINES
!                   THAT WANT TO COMPUTE A PPCC VALUE INDEPENDENT OF
!                   THE PROBABILITY PLOT COMMAND (E.G., DPGOF9, DPPPC2).
!
      PPA0=CPUMIN
      PPA1=CPUMIN
      XRESSD=CPUMIN
      XRESDF=CPUMIN
      PPCC=CPUMIN
      SDPPA0=CPUMIN
      SDPPA1=CPUMIN
      CCALBE=CPUMIN
      PPA0BW=CPUMIN
      PPA1BW=CPUMIN
!
      IF(NPTS.GE.2)THEN
        CALL LINFIT(Y2(N2OLD+1),X2(N2OLD+1),NPTS,   &
                    PPA0,PPA1,XRESSD,XRESDF,PPCC,SDPPA0,SDPPA1,CCALBE,   &
                    ISUBRO,IBUGG3,IERROR)
!
        IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPP2')THEN
          WRITE(ICOUT,8001)PPA0,PPA1,NPTS
 8001     FORMAT('AFTER LINFIT: PPA0,PPA1,NPTS = ',2G15.7,I10)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
!       2019/07: IN ORDER TO REDUCE SCRATCH SPACE USAGE, USE
!                XTEMP1 FOR PREDBW AND X2TEMP FOR RESBW.
!
        DO 8010 I=1,NPTS
          X2TEMP(I)=Y2(N2OLD+I) - (PPA0 + PPA1*X2(N2OLD+I))
          WEIGHH(I)=1.0
          WEIGHV(I)=1.0
 8010   CONTINUE
        IWRITE='OFF'
        CALL BIWEIG(X2TEMP,NPTS,IWRITE,WEIGHV,IBUGG3,IERROR)
!
        IT=1
        I1=1
        I2=NPTS
        I3=1
        I4=NPTS
        XMAXHF=1.0
!
        CALL LINEAR(IT,I1,I2,X2(N2OLD+1),Y2(N2OLD+1),   &
                    WEIGHH,WEIGHV,NPTS,XMAXHF,I3,I4,   &
                    PPA0BW,PPA1BW,XTEMP1,X2TEMP,   &
                    ISUBRO,IBUGG3,IERROR)
!
        DO 8020 I=1,NPTS
          X2TEMP(I)=Y2(N2OLD+I) - (PPA0BW + PPA1BW*X2(N2OLD+I))
 8020   CONTINUE
        CALL BIWEIG(X2TEMP,NPTS,IWRITE,WEIGHV,IBUGG3,IERROR)
        CALL LINEAR(IT,I1,I2,X2(N2OLD+1),Y2(N2OLD+1),   &
                    WEIGHH,WEIGHV,NPTS,XMAXHF,I3,I4,   &
                    PPA0BW,PPA1BW,XTEMP1,X2TEMP,   &
                    ISUBRO,IBUGG3,IERROR)
!
        IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPP2')THEN
          WRITE(ICOUT,8021)PPA0BW,PPA1BW
 8021     FORMAT('AFTER BIWEIGHT: PPA0BW,PPA1BW = ',2G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
      ENDIF
!
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPP2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPP2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICASPL,N2,NPTS,IERROR
 9012   FORMAT('ICASPL,N2,NPTS,IERROR = ',A4,2X,2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)MINMAX
 9015   FORMAT('MINMAX = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,N2
          WRITE(ICOUT,9021)I,Y2(I),X2(I),D2(I)
 9021     FORMAT('I,Y2(I),X2(I),D2(I) = ',I8,2G15.7,F9.2)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPPP2
      SUBROUTINE DPPP3(Y,X,XHIGH,N,ICASPL,IDATSW,   &
                       XCENS,XTEMP1,   &
                       XTEMP2,XTEMP3,XTEMP4,   &
                       YLOWLM,YUPPLM,A,B,MINMAX,   &
                       SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                       SHAPE5,SHAPE6,SHAPE7,   &
                       IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                       ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                       IGETDF,ICONDF,IGOMDF,IKATDF,   &
                       IGIGDF,IGEODF,   &
                       IPPLDP,MAXOBV,ICENSO,IMETH,   &
                       PPLOC,PPSCAL,   &
                       PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                       CCALBE,PPA0BW,PPA1BW,   &
                       WEIGHH,WEIGHV,   &
                       Y2,X2,D2,N2,NPLOTV,NCURVE,IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--GENERATE A PAIR OF COORDINATE VECTORS THAT WILL DEFINE
!              A PROBABILITY PLOT FOR A SPECIFIED DISTRIBUTION FOR
!              THE GROUPED DATA CASE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/8
!     ORIGINAL VERSION--AUGUST    2009. SPLIT OFF AS SEPARATE SUBROUTINE
!                                       FROM DPPP2
!     UPDATED         --JULY      2010. END EFFECTS WEIBULL
!     UPDATED         --AUGUST    2010. BRITTLE FIBER WEIBULL
!     UPDATED         --JULY      2019. REDUCE USE OF SCRATCH SPACE BY
!                                       TWO ARRAYS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IDATSW
      CHARACTER*4 IADEDF
      CHARACTER*4 IGEPDF
      CHARACTER*4 IMAKDF
      CHARACTER*4 IBEIDF
      CHARACTER*4 ILGADF
      CHARACTER*4 ISKNDF
      CHARACTER*4 IGLDDF
      CHARACTER*4 IBGEDF
      CHARACTER*4 IGETDF
      CHARACTER*4 ICONDF
      CHARACTER*4 IGOMDF
      CHARACTER*4 IKATDF
      CHARACTER*4 IGIGDF
      CHARACTER*4 IGEODF
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ICENSO
      CHARACTER*4 IMETH
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      CHARACTER*4 IWRITE
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION XHIGH(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION D2(*)
      DIMENSION XCENS(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION XTEMP3(*)
      DIMENSION XTEMP4(*)
!
      DIMENSION WEIGHH(*)
      DIMENSION WEIGHV(*)
!CCCC DIMENSION PREDBW(*)
!CCCC DIMENSION RESBW(*)
!
      DOUBLE PRECISION LANPPF
      DOUBLE PRECISION DX2OUT
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DLOC
      DOUBLE PRECISION DSCALE
      DOUBLE PRECISION SUM
!
      DOUBLE PRECISION QUAGLO
      DOUBLE PRECISION QUAWAK
      DOUBLE PRECISION XPAR(5)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
      ISUBN1='DPPP'
      ISUBN2='3   '
      IERROR='NO'
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPP3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,171)
  171   FORMAT('***** AT THE BEGINNING OF DPPP3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,172)ICASPL,IDATSW,N,NPLOTV,MINMAX,IPPLDP
  172   FORMAT('ICASPL,IDATSW,N,NPLOTV,MINMAX,IPPLDP = ',   &
               A4,2X,A4,2X,4I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,174)N2,NCURVE,MAXOBV
  174   FORMAT('N2,NCURVE,MAXOBV = ',3I8)
        CALL DPWRST('XXX','BUG ')
        IF(N.GE.1)THEN
          DO 185 I=1,N
            WRITE(ICOUT,186)I,Y(I),X(I),XHIGH(I)
  186       FORMAT('I,Y(I),X(I),XHIGH(I) = ',I8,3G12.5)
            CALL DPWRST('XXX','BUG ')
  185     CONTINUE
        ENDIF
      ENDIF
!
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LE.1)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)
   46   FORMAT('***** ERROR IN PROBABILITY PLOT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)
   47   FORMAT('      THE NUMBER OF OBSERVATIONS WAS LESS THAN OR')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)
   48   FORMAT('      EQUAL TO 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,49)N
   49   FORMAT('      THE ENTERED NUMBER OF OBSERVATIONS HERE = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      NMIN=2
      NJUNK=0
      MAXGRP=50000
      IF(IDATSW.EQ.'FREQ')THEN
        CALL CKDIS2(Y,X,XTEMP1,N,MAXGRP,NMIN,XTEMP2,NJUNK,NTOT2,   &
                    ISUBRO,IBUGG3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
      ELSEIF(IDATSW.EQ.'FRE2')THEN
        CALL CKDIS3(Y,X,XHIGH,XTEMP1,N,MAXGRP,NMIN,XTEMP2,NJUNK,NTOT2,   &
                    ISUBRO,IBUGG3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 2--                              **
!               **  DETERMINE PLOT COORDINATES            **
!               **  FOR THE 2-VARIABLE CASE               **
!               **  (THAT IS, FOR THE GROUPED DATA CASE)  **
!               ********************************************
!
!CCCC OCTOBER 2004: REMOVE BINS WITH ZERO FREQUENCY
!
      ICNT=0
      DO 201 I=1,N
        IF(Y(I).GT.0.0)THEN
          ICNT=ICNT+1
          XTEMP2(ICNT)=Y(I)
          XTEMP3(ICNT)=X(I)
          XTEMP4(ICNT)=XHIGH(I)
          XTEMP1(ICNT)=XCENS(I)
        ENDIF
  201 CONTINUE
      N=ICNT
      DO 203 I=1,N
        Y(I)=XTEMP2(I)
        X(I)=XTEMP3(I)
        XHIGH(I)=XTEMP4(I)
        XCENS(I)=XTEMP1(I)
  203 CONTINUE
!
!CCCC MAY 2005: FOR CASE WHERE BINS SPECIFIED AS LOWER AND UPPER
!CCCC           LIMITS, COMPUTE THE MID-POINTS OF EACH OF THE BINS.
!CCCC
!CCCC           SAVE ORIGINAL LOWER LIMIT (WILL BE RESTORED AT
!CCCC           END OF ROUTINE).
!
      IF(IDATSW.EQ.'FRE2')THEN
        DO 211 I=1,N
          XTEMP4(I)=X(I)
          X(I)=(X(I) + XHIGH(I))/2.0
  211   CONTINUE
      ENDIF
!
      IF(ICENSO.EQ.'ON')THEN
        CALL SORTC(X,XCENS,N,XTEMP2,XTEMP1)
        DO 213 I=1,N
          XCENS(I)=XTEMP1(I)
  213   CONTINUE
      ENDIF
!
      CALL SORTC(X,Y,N,XTEMP2,D2)
      DO 215 II=1,N
        Y2(II)=XTEMP2(II)
  215 CONTINUE
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPP3')THEN
        DO 221 II=1,MIN(100,N)
          WRITE(ICOUT,223)II,D2(II),Y2(II)
  223     FORMAT('II,D2(II),Y2(II)=',I10,2G15.7)
          CALL DPWRST('XXX','BUG ')
  221   CONTINUE
      ENDIF
!
      XMIN=XTEMP2(1)
      XMAX=XTEMP2(N)
!
      EPS=0.00001
      IF(XMIN.LT.YLOWLM)YLOWLM=XMIN-EPS
      IF(XMAX.GT.YUPPLM)YUPPLM=XMAX+EPS
!
      SUM=0.0D0
      DO 230 I=1,N
        SUM=SUM+DBLE(Y(I))
        IF(ICENSO.EQ.'ON')SUM=SUM+DBLE(XCENS(I))
  230 CONTINUE
      NTOT=INT(SUM+0.5D0)
!
      ICNT=N2
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPP3')THEN
        WRITE(ICOUT,240)NTOT
  240   FORMAT('NTOT = ',I10)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     AUGUST 2009: NOTE THAT OUTER LOOP DOES NOT DEPEND ON
!                  SPECIFIC DISTRIBUTION.  MODIFY CODE SO
!                  THAT ONLY INNER LOOP DEPENDS ON SPECIFIC
!                  DISTRIBUTION.
!
      I2=0
      DO 1000 I=1,N
        NI=INT(D2(I)+0.5)
        IF(NI.LE.0)GO TO 1000
!
        IF(ICENSO.EQ.'ON')THEN
          NI2=INT(XCENS(I)+0.5)
        ELSE
          NI2=0
        ENDIF
!
        ANI=NI
        I1=I2+1
        I2=I1+NI-1
        SUM=0.0D0
!
!       NOW LOOP THROUGH THE SPECIFIC DISTRIBUTIONS
!
        IF(ICASPL.EQ.'UNIF')THEN
          DO 1001 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL UNIPPF(UNIOSM,DISOSM)
            SUM=SUM+DISOSM
 1001     CONTINUE
        ELSEIF(ICASPL.EQ.'NORM')THEN
          DO 1011 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL NODPPF(DBLE(UNIOSM),DX2OUT)
            SUM=SUM+DX2OUT
 1011     CONTINUE
        ELSEIF(ICASPL.EQ.'LOGI')THEN
          DO 1021 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL LOGPPF(UNIOSM,DISOSM)
            SUM=SUM+DISOSM
 1021     CONTINUE
        ELSEIF(ICASPL.EQ.'DEXP')THEN
          DO 1031 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL DEXPPF(UNIOSM,DISOSM)
            SUM=SUM+DISOSM
 1031     CONTINUE
        ELSEIF(ICASPL.EQ.'CAUC')THEN
          DO 1041 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL CAUPPF(UNIOSM,DISOSM)
            SUM=SUM+DISOSM
 1041     CONTINUE
        ELSEIF(ICASPL.EQ.'TULA')THEN
          DO 1051 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL LAMPPF(UNIOSM,SHAPE1,DISOSM)
            SUM=SUM+DISOSM
 1051     CONTINUE
        ELSEIF(ICASPL.EQ.'LOGN' .OR. ICASPL.EQ.'3LGN')THEN
          DO 1061 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL LGNPPF(UNIOSM,SHAPE1,DISOSM)
            SUM=SUM+DISOSM
 1061     CONTINUE
        ELSEIF(ICASPL.EQ.'HNOR')THEN
          DO 1071 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL HFNPPF(UNIOSM,DISOSM)
            SUM=SUM+DISOSM
 1071     CONTINUE
        ELSEIF(ICASPL.EQ.'TPP')THEN
          DO 1081 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL TPPF(UNIOSM,SHAPE1,DISOSM)
            SUM=SUM+DISOSM
 1081     CONTINUE
        ELSEIF(ICASPL.EQ.'CHIS')THEN
          DO 1091 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL CHSPPF(UNIOSM,INT(SHAPE1+0.1),DISOSM)
            SUM=SUM+DISOSM
 1091     CONTINUE
        ELSEIF(ICASPL.EQ.'FPP')THEN
          DO 1101 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL FPPF(UNIOSM,INT(SHAPE1+0.1),INT(SHAPE1+0.1),DISOSM)
            SUM=SUM+DISOSM
 1101     CONTINUE
        ELSEIF(ICASPL.EQ.'EXPO')THEN
          DO 1111 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL EXPPPF(UNIOSM,DISOSM)
            SUM=SUM+DISOSM
 1111     CONTINUE
        ELSEIF(ICASPL.EQ.'GAMM' .OR. ICASPL.EQ.'3GAM')THEN
          DO 1121 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL GAMPPF(UNIOSM,SHAPE1,DISOSM)
            SUM=SUM+DISOSM
 1121     CONTINUE
        ELSEIF(ICASPL.EQ.'BETA')THEN
          DO 1126 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL BETPPF(UNIOSM,SHAPE1,SHAPE2,DISOSM)
            SUM=SUM+DISOSM
 1126     CONTINUE
        ELSEIF(ICASPL.EQ.'WEIB' .OR. ICASPL.EQ.'3WEI')THEN
          DO 1131 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL WEIPPF(UNIOSM,SHAPE1,MINMAX,DISOSM)
            SUM=SUM+DISOSM
 1131     CONTINUE
        ELSEIF(ICASPL.EQ.'EV1 ')THEN
          DO 1141 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL EV1PPF(UNIOSM,MINMAX,DISOSM)
            SUM=SUM+DISOSM
 1141     CONTINUE
        ELSEIF(ICASPL.EQ.'EV2 ' .OR. ICASPL.EQ.'3EV2')THEN
          DO 1151 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL EV2PPF(UNIOSM,SHAPE1,MINMAX,DISOSM)
            SUM=SUM+DISOSM
 1151     CONTINUE
        ELSEIF(ICASPL.EQ.'PARE')THEN
          ZLOC=SHAPE2
          IF(ZLOC.GT.XMIN)ZLOC=XMIN
          DO 1161 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL PARPPF(UNIOSM,SHAPE1,ZLOC,DISOSM)
            SUM=SUM+DISOSM
 1161     CONTINUE
        ELSEIF(ICASPL.EQ.'BINO')THEN
          DO 1171 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL BINPPF(DBLE(UNIOSM),DBLE(SHAPE1),INT(SHAPE2+0.1),   &
                        DX2OUT)
            SUM=SUM+DX2OUT
 1171     CONTINUE
        ELSEIF(ICASPL.EQ.'GEOM')THEN
          IF(IGEODF.EQ.'DLMF')THEN
            DO 1181 K=I1,I2
              IF(ICENSO.EQ.'ON')THEN
                CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
              ELSE
                CALL UNIME2(NTOT,K,UNIOSM)
              ENDIF
              CALL GE2PPF(DBLE(UNIOSM),DBLE(SHAPE1),DX2OUT)
              SUM=SUM+DX2OUT
 1181       CONTINUE
          ELSE
            DO 1186 K=I1,I2
              IF(ICENSO.EQ.'ON')THEN
                CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
              ELSE
                CALL UNIME2(NTOT,K,UNIOSM)
              ENDIF
              CALL GEOPPF(DBLE(UNIOSM),DBLE(SHAPE1),DX2OUT)
              SUM=SUM+DX2OUT
 1186       CONTINUE
          ENDIF
!
        ELSEIF(ICASPL.EQ.'POIS')THEN
          DO 1191 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL POIPPF(UNIOSM,SHAPE1,DISOSM)
            SUM=SUM+DISOSM
 1191     CONTINUE
        ELSEIF(ICASPL.EQ.'NEBI')THEN
          DO 1201 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL NBPPF(DBLE(UNIOSM),DBLE(SHAPE1),DBLE(SHAPE2),DX2OUT)
            SUM=SUM+DX2OUT
 1201     CONTINUE
        ELSEIF(ICASPL.EQ.'SEMC')THEN
          ASCALE=1.0
          DO 1211 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL SEMPPF(UNIOSM,ASCALE,DISOSM)
            SUM=SUM+DISOSM
 1211     CONTINUE
        ELSEIF(ICASPL.EQ.'TRIA')THEN
          DO 1221 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL TRIPPF(UNIOSM,SHAPE1,A,B,DISOSM)
            SUM=SUM+DISOSM
 1221     CONTINUE
        ELSEIF(ICASPL.EQ.'INGA')THEN
          DO 1231 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL IGPPF(DBLE(UNIOSM),DBLE(SHAPE1),DBLE(SHAPE2),DPPF)
            SUM=SUM+REAL(DPPF)
 1231     CONTINUE
        ELSEIF(ICASPL.EQ.'WALD')THEN
          DO 1241 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            AVAL=1.0
            CALL IGPPF(DBLE(UNIOSM),DBLE(SHAPE1),DBLE(AVAL),DPPF)
            SUM=SUM+REAL(DPPF)
 1241     CONTINUE
        ELSEIF(ICASPL.EQ.'RIGA')THEN
          DO 1251 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL RIGPPF(DBLE(UNIOSM),DBLE(SHAPE1),DBLE(SHAPE2),DPPF)
            SUM=SUM+REAL(DPPF)
 1251     CONTINUE
        ELSEIF(ICASPL.EQ.'FATL')THEN
          DO 1261 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL FLPPF(UNIOSM,SHAPE1,DISOSM)
            SUM=SUM+DISOSM
 1261     CONTINUE
        ELSEIF(ICASPL.EQ.'GPAR')THEN
          DO 1271 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL GEPPPF(UNIOSM,SHAPE1,MINMAX,IGEPDF,DISOSM)
            SUM=SUM+DISOSM
 1271     CONTINUE
        ELSEIF(ICASPL.EQ.'DUNI')THEN
          DO 1281 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
           CALL DISPPF(UNIOSM,INT(SHAPE1),DISOSM)
            SUM=SUM+DISOSM
 1281     CONTINUE
        ELSEIF(ICASPL.EQ.'NCT ')THEN
          DO 1291 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL NCTPPF(UNIOSM,SHAPE1,SHAPE2,DISOSM)
            SUM=SUM+DISOSM
 1291     CONTINUE
        ELSEIF(ICASPL.EQ.'NCF ')THEN
          DO 1301 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL NCFPPF(UNIOSM,SHAPE1,SHAPE2,SHAPE3,DISOSM)
            SUM=SUM+DISOSM
 1301     CONTINUE
        ELSEIF(ICASPL.EQ.'NCCS')THEN
          DO 1311 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL NCCPPF(UNIOSM,SHAPE1,SHAPE2,DISOSM)
            SUM=SUM+DISOSM
 1311     CONTINUE
        ELSEIF(ICASPL.EQ.'NCBE')THEN
          DO 1321 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL NCBPPF(UNIOSM,SHAPE1,SHAPE2,SHAPE3,DISOSM)
            SUM=SUM+DISOSM
 1321     CONTINUE
        ELSEIF(ICASPL.EQ.'DNCT')THEN
          DO 1331 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL DNTPPF(UNIOSM,SHAPE1,SHAPE2,SHAPE3,DISOSM)
            SUM=SUM+DISOSM
 1331     CONTINUE
        ELSEIF(ICASPL.EQ.'DNCF')THEN
          DO 1341 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL DNFPPF(UNIOSM,SHAPE1,SHAPE2,SHAPE3,SHAPE4,DISOSM)
            SUM=SUM+DISOSM
 1341     CONTINUE
        ELSEIF(ICASPL.EQ.'HYPG')THEN
          DO 1351 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL HYPPPF(UNIOSM,INT(SHAPE1+0.1),INT(SHAPE2+0.1),   &
                      INT(SHAPE3+0.1),DISOSM)
            SUM=SUM+DISOSM
 1351     CONTINUE
        ELSEIF(ICASPL.EQ.'VONM')THEN
          DO 1361 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL VONPPF(UNIOSM,SHAPE1,DISOSM)
            SUM=SUM+DISOSM
 1361     CONTINUE
        ELSEIF(ICASPL.EQ.'POWN')THEN
!CCCC     SDTEMP=1.0
          DO 1371 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
