            ENDIF
            CALL BU8PPF(DBLE(UNIOSM),DBLE(SHAPE1),DX2OUT)
            SUM=SUM+DX2OUT
 2451     CONTINUE
        ELSEIF(ICASPL.EQ.'BUR9')THEN
          DO 2461 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
