            ENDIF
            CALL BU9PPF(DBLE(UNIOSM),DBLE(SHAPE1),DBLE(SHAPE2),DX2OUT)
            SUM=SUM+DX2OUT
 2461     CONTINUE
        ELSEIF(ICASPL.EQ.'BU10')THEN
          DO 2471 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
