            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL B10PPF(DBLE(UNIOSM),DBLE(SHAPE1),DX2OUT)
            SUM=SUM+DX2OUT
 2471     CONTINUE
        ELSEIF(ICASPL.EQ.'BU11')THEN
          DO 2481 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
