            ENDIF
            CALL B11PPF(DBLE(UNIOSM),DBLE(SHAPE1),DX2OUT)
            SUM=SUM+DX2OUT
 2481     CONTINUE
        ELSEIF(ICASPL.EQ.'BU12')THEN
          DO 2491 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
