            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL LEXPPF(DBLE(UNIOSM),DBLE(SHAPE1),DX2OUT)
            SUM=SUM+DX2OUT
 2551     CONTINUE
        ELSEIF(ICASPL.EQ.'TPAR')THEN
