            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL LE3PPF(DBLE(UNIOSM),DBLE(SHAPE1),DBLE(SHAPE2),   &
                      DBLE(SHAPE3),DX2OUT)
            SUM=SUM+DX2OUT
 2581     CONTINUE
        ELSEIF(ICASPL.EQ.'KAPP')THEN
          DLOC=0.0D0
