              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL KAPPPF(DBLE(UNIOSM),DBLE(SHAPE1),DBLE(SHAPE2),   &
                      DLOC,DSCALE,DX2OUT)
            SUM=SUM+DX2OUT
 2591     CONTINUE
        ELSEIF(ICASPL.EQ.'PEA3')THEN
