            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL PE3PPF(DBLE(UNIOSM),DBLE(SHAPE1),DLOC,DSCALE,DX2OUT)
            SUM=SUM+DX2OUT
 2601     CONTINUE
        ELSEIF(ICASPL.EQ.'EEWE')THEN
          DO 2611 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL EEWPPF(DBLE(UNIOSM),DBLE(SHAPE5),DBLE(SHAPE1),   &
                        DBLE(SHAPE2),DBLE(SHAPE3),DBLE(SHAPE4),DX2OUT)
            SUM=SUM+DX2OUT
2611      CONTINUE
        ELSEIF(ICASPL.EQ.'BFWE')THEN
          DO 2711 K=I1,I2
            IF(ICENSO.EQ.'ON')THEN
              CALL UNIME4(NTOT,K,UNIOSM,IMETH,D2,XCENS,N)
            ELSE
              CALL UNIME2(NTOT,K,UNIOSM)
            ENDIF
            CALL BFWPPF(DBLE(UNIOSM),DBLE(SHAPE1),DBLE(SHAPE2),DX2OUT)
            SUM=SUM+DX2OUT
2711      CONTINUE
        ENDIF
!
        X2(N2+I)=PPLOC + PPSCAL*REAL(SUM/DBLE(ANI))
        I2=I2+NI2
 1000 CONTINUE
!
      DO 4100 I=1,N
        D2(N2+I)=REAL(NCURVE)
 4100 CONTINUE
      N2OLD=N2
      NPTS=N
      N2=N2+N
      NPLOTV=2
!
!     OCTOBER 2009: MOVE COMPUTATION OF PPA0, PPA1, PPCC, PPAOBW,
!                   AND PPA1BW HERE (INSTEAD OF DPPP).  THIS MAKES
!                   THE DPPP3 ROUTINE MORE USEFUL FOR OTHER ROUTINES
!                   THAT WANT TO COMPUTE A PPCC VALUE INDEPENDENT OF
!                   THE PROBABILITY PLOT COMMAND (E.G., DPGOF9, DPPPC3).
!
!     JULY 2019:    USE XTEMP1 FOR PREDBW AND XTEMP2 FOR RESBW TO REDUCE
!                   REQUIRED SCRATCH SPACE
!
      PPA0=CPUMIN
      PPA1=CPUMIN
      XRESSD=CPUMIN
      XRESDF=CPUMIN
      PPCC=CPUMIN
      SDPPA0=CPUMIN
      SDPPA1=CPUMIN
      CCALBE=CPUMIN
      PPA0BW=CPUMIN
      PPA1BW=CPUMIN
!
      IF(NPTS.GE.2)THEN
        CALL LINFIT(Y2(N2OLD+1),X2(N2OLD+1),NPTS,   &
                    PPA0,PPA1,XRESSD,XRESDF,PPCC,SDPPA0,SDPPA1,CCALBE,   &
                    ISUBRO,IBUGG3,IERROR)
        DO 8010 I=1,NPTS
          XTEMP2(I)=Y2(N2OLD+I) - (PPA0 + PPA1*X2(N2OLD+I))
          WEIGHH(I)=1.0
          WEIGHV(I)=1.0
 8010   CONTINUE
        IWRITE='OFF'
        CALL BIWEIG(XTEMP2,NPTS,IWRITE,WEIGHV,IBUGG3,IERROR)
!
        IT=1
        I1=1
        I2=NPTS
        I3=1
        I4=NPTS
        XMAXHF=1.0
!
        CALL LINEAR(IT,I1,I2,X2(N2OLD+1),Y2(N2OLD+1),   &
                    WEIGHH,WEIGHV,NPTS,XMAXHF,I3,I4,   &
                    PPA0BW,PPA1BW,XTEMP1,XTEMP2,   &
                    ISUBRO,IBUGG3,IERROR)
!
        DO 8020 I=1,NPTS
          XTEMP2(I)=Y2(N2OLD+I) - (PPA0BW + PPA1BW*X2(N2OLD+I))
 8020   CONTINUE
        CALL BIWEIG(XTEMP2,NPTS,IWRITE,WEIGHV,IBUGG3,IERROR)
        CALL LINEAR(IT,I1,I2,X2(N2OLD+1),Y2(N2OLD+1),   &
                    WEIGHH,WEIGHV,NPTS,XMAXHF,I3,I4,   &
                    PPA0BW,PPA1BW,XTEMP1,XTEMP2,   &
                    ISUBRO,IBUGG3,IERROR)
      ENDIF
!
!     FOR UNEQUI-SPACED BINS, RESTORE THE LOWER LIMIT (NEEDED
!     BY PPCC PLOT).
!
      IF(IDATSW.EQ.'FRE2')THEN
        DO 8110 I=1,N
          X(I)=XTEMP4(I)
 8110   CONTINUE
      ENDIF
!
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPPP3--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)ICASPL,IDATSW,N2,IERROR
 9012 FORMAT('ICASPL,IDATSW,N2,IERROR = ',A4,2X,A4,I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)NTOT
 9014 FORMAT('NTOT = ',I8)
      CALL DPWRST('XXX','BUG ')
!CCCC THE FOLLOWING 2 LINES WERE ADDED   MAY 1993
      WRITE(ICOUT,9015)MINMAX
 9015 FORMAT('MINMAX = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 9020 I=1,N2
      WRITE(ICOUT,9021)I,Y2(I),X2(I),D2(I)
 9021 FORMAT('I,Y2(I),X2(I),D2(I) = ',I8,2E15.7,F9.2)
      CALL DPWRST('XXX','BUG ')
 9020 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPPP3
      SUBROUTINE DPPP4(PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                       CCALBE,PPA0BW,PPA1BW,   &
                       IFLAGU,IFRST,ILAST,   &
                       IBUGG2,IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--UTILITY ROUTINE USED BY DPPP.  UPDATE THE DATAPLOT
!              PARAMETER TABLE OR WRITE VALUES TO EXTERNAL FILE.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/9
!     ORIGINAL VERSION--SEPTEMBER 2009. EXTRACTED AS SEPARATE ROUTINE
!                                       FROM DPPP
!     UPDATED         --OCTOBER   2009. MOVED COMPUTATION OF
!                                       PARAMETERS TO DPPP2 AND DPPP3
!                                       TO FACILITATE USE BY OTHER
!                                       ROUTINES.  THIS ROUTINE JUST
!                                       UPDATES THE PARAMETER TABLE OR
!                                       WRITES THE PARAMETERS TO A FILE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IFLAGU
      CHARACTER*4 IBUGG2
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      LOGICAL IFRST
      LOGICAL ILAST
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 ISUBN0
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IOP
!
      SAVE IOUNI1
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOF2.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ***************************************
!               **  STEP 1--                         **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
      IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'PPP4')THEN
        ISTEPN='1'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPP4--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IFLAGU,IFRST,ILAST
   53   FORMAT('IFLAGU,IFRST,ILAST = ',A4,2X,A8,2X,A8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)PPA0,PPA1,XRESSD,XRESDF
   63   FORMAT('PPA0,PPA1,XRESSD,XRESDF = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,65)PPCC,SDPPA0,SDPPA1,CCALBE
   65   FORMAT('PPCC,SDPPA0,SDPPA1,CCALBE = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,67)PPA0BW,PPA1BW
   67   FORMAT('PPA0BW,PPA1BW = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      ISUBN0='PPP4'
!
      IF(IFLAGU.EQ.'FILE')THEN
!
        IF(IFRST)THEN
          IOP='OPEN'
          IFLAG1=1
          IFLAG2=0
          IFLAG3=0
          IFLAG4=0
          IFLAG5=0
          CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                      IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                      IBUGG2,ISUBRO,IERROR)
!
          IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'PPP4')THEN
            ISTEPN='2A'
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,201)IOUNI1
  201       FORMAT('AFTER CALL DPOPFI, IOUNI1 = ',I5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          IF(IERROR.EQ.'YES')GO TO 9000
!
          WRITE(IOUNI1,299)
  299     FORMAT(11X,'PPA0',11X,'PPA1',11X,'PPCC',   &
                 9X,'PPA0BW',9X,'PPA1BW',   &
                 9X,'PPA0SD',9X,'PPA1SD',8X,'PPRESSD',8X,'PPRESDF',   &
                 9X,'CCALBE')
        ENDIF
      ELSEIF(IFLAGU.EQ.'ON')THEN
        IH='PPCC'
        IH2='    '
        VALUE0=PPCC
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGG3,IERROR)
!
        IH='PPA0'
        IH2='    '
        VALUE0=PPA0
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGG3,IERROR)
!
        IH='PPA1'
        IH2='    '
        VALUE0=PPA1
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGG3,IERROR)
!
        IH='SDPP'
        IH2='A0  '
        VALUE0=SDPPA0
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGG3,IERROR)
!
        IH='SDPP'
        IH2='A1  '
        VALUE0=SDPPA1
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGG3,IERROR)
!
        IH='PPRE'
        IH2='SSD '
        VALUE0=XRESSD
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGG3,IERROR)
!
        IH='PPRE'
        IH2='SDF '
        VALUE0=XRESDF
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGG3,IERROR)
!
        IH='CCAL'
        IH2='PBET'
        VALUE0=CCALBE
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGG3,IERROR)
!
        IH='PPA0'
        IH2='BW  '
        VALUE0=PPA0BW
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGG3,IERROR)
!
        IH='PPA1'
        IH2='BW  '
        VALUE0=PPA1BW
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGG3,IERROR)
!
      ENDIF
!
      IF(IFLAGU.EQ.'FILE')THEN
        WRITE(IOUNI1,1031)PPA0,PPA1,PPCC,PPA0BW,PPA1BW,   &
                          SDPPA0,SDPPA1,XRESSD,XRESDF,CCALBE
 1031   FORMAT(10E15.7)
      ENDIF
!
      IF(IFLAGU.EQ.'FILE')THEN
        IF(ILAST)THEN
          IOP='CLOS'
          IFLAG1=1
          IFLAG2=0
          IFLAG3=0
          IFLAG4=0
          IFLAG5=0
          CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                      IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                      IBUGG2,ISUBRO,IERROR)
!
          IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'PPP4')THEN
            ISTEPN='3A'
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,301)IERROR,IOUNI1
  301       FORMAT('AFTER CALL DPCLFI: IERROR,IOUNI1 = ',A4,2X,I5)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,303)IOUNI1,IFILE1
  303       FORMAT('IOUNI1,IFILE1 = ',I5,A80)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          IF(IERROR.EQ.'YES')GO TO 9000
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'PPP4')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF DPPP4--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPP4
      SUBROUTINE DPPP5(TAG1,TAG2,TAG3,TAG4,TAG5,TAG6,NREPL,N,MAXOBV,   &
                       XIDTEM,XIDTE2,XIDTE3,XIDTE4,   &
                       XIDTE5,XIDTE6,   &
                       TEMP1,TEMP2,   &
                       NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5,NUMSE6,   &
                       IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--UTILITY ROUTINE USED BY DPPP (AND POSSIBLY OTHER
!              ROUTINES). FOR 1 TO 6 REPLICATION VARIABLES, IT
!              EXTRACTS THE DISTINCT ELEMENTS FROM EACH OF THEM
!              (AND CODES THEM 1 TO K WHERE K IS THE NUMBER OF
!              DISTINCT ELEMENTS).
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/9
!     ORIGINAL VERSION--SEPTEMBER 2009.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION TAG1(*)
      DIMENSION TAG2(*)
      DIMENSION TAG3(*)
      DIMENSION TAG4(*)
      DIMENSION TAG5(*)
      DIMENSION TAG6(*)
      DIMENSION XIDTEM(*)
      DIMENSION XIDTE2(*)
      DIMENSION XIDTE3(*)
      DIMENSION XIDTE4(*)
      DIMENSION XIDTE5(*)
      DIMENSION XIDTE6(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
!
!-----COMMON----------------------------------------------------------
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ***************************************
!               **  STEP 1--                         **
!               **  COMPUTE LINEAR FIT AND           **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPP5')THEN
        ISTEPN='1'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPP5--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N,NREPL
   53   FORMAT('N,NREPL = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,57)I,TAG1(I),TAG2(I),TAG3(I),TAG4(I),TAG5(I),   &
                         TAG6(I)
   57     FORMAT('I,TAG1(I) ... TAG6(I) = ',I8,6E15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ******************************************************
!               **  STEP 1--                                        **
!               **  DETERMINE THE NUMBER OF DISTINCT VALUES         **
!               **  FOR THE GROUP VARIABLES (TAG1, TAG2)            **
!               **  IF ALL VALUES ARE DISTINCT, THEN THIS           **
!               **  IMPLIES WE HAVE THE NO REPLICATION CASE         **
!               **  WHICH IS AN ERROR CONDITION.                    **
!               ******************************************************
!
      ISTEPN='1'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PPP5')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IWRITE='OFF'
      NUMSE1=0
      NUMSE2=0
      NUMSE3=0
      NUMSE4=0
      NUMSE5=0
      NUMSE6=0
!
      IF(NREPL.GE.1)THEN
        CALL CODE(TAG1,N,IWRITE,TEMP1,TEMP2,MAXOBV,IBUGG3,IERROR)
        DO 110 I=1,N
          TAG1(I)=TEMP1(I)
  110   CONTINUE
        CALL DISTIN(TAG1,N,IWRITE,XIDTEM,NUMSE1,IBUGG3,IERROR)
        CALL SORT(XIDTEM,NUMSE1,XIDTEM)
      ENDIF
!
      IF(NREPL.GE.2)THEN
        CALL CODE(TAG2,N,IWRITE,TEMP1,TEMP2,MAXOBV,IBUGG3,IERROR)
        DO 120 I=1,N
          TAG2(I)=TEMP1(I)
  120   CONTINUE
        CALL DISTIN(TAG2,N,IWRITE,XIDTE2,NUMSE2,IBUGG3,IERROR)
        CALL SORT(XIDTE2,NUMSE2,XIDTE2)
      ENDIF
!
      IF(NREPL.GE.3)THEN
        CALL CODE(TAG3,N,IWRITE,TEMP1,TEMP2,MAXOBV,IBUGG3,IERROR)
        DO 130 I=1,N
          TAG3(I)=TEMP1(I)
  130   CONTINUE
        CALL DISTIN(TAG3,N,IWRITE,XIDTE3,NUMSE3,IBUGG3,IERROR)
        CALL SORT(XIDTE3,NUMSE3,XIDTE3)
      ENDIF
!
      IF(NREPL.GE.4)THEN
        CALL CODE(TAG4,N,IWRITE,TEMP1,TEMP2,MAXOBV,IBUGG3,IERROR)
        DO 140 I=1,N
          TAG4(I)=TEMP1(I)
  140   CONTINUE
        CALL DISTIN(TAG4,N,IWRITE,XIDTE4,NUMSE4,IBUGG3,IERROR)
        CALL SORT(XIDTE4,NUMSE4,XIDTE4)
      ENDIF
!
      IF(NREPL.GE.5)THEN
        CALL CODE(TAG5,N,IWRITE,TEMP1,TEMP2,MAXOBV,IBUGG3,IERROR)
        DO 150 I=1,N
          TAG5(I)=TEMP1(I)
  150   CONTINUE
        CALL DISTIN(TAG5,N,IWRITE,XIDTE5,NUMSE5,IBUGG3,IERROR)
        CALL SORT(XIDTE5,NUMSE5,XIDTE5)
      ENDIF
!
      IF(NREPL.GE.6)THEN
        CALL CODE(TAG6,N,IWRITE,TEMP1,TEMP2,MAXOBV,IBUGG3,IERROR)
        DO 160 I=1,N
          TAG6(I)=TEMP1(I)
  160   CONTINUE
        CALL DISTIN(TAG6,N,IWRITE,XIDTE6,NUMSE6,IBUGG3,IERROR)
        CALL SORT(XIDTE6,NUMSE6,XIDTE6)
      ENDIF
!
      IF(NUMSE1.LT.1 .OR. NUMSE1.GT.N)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,201)
  201   FORMAT('***** ERROR IN DPPP5 ROUTINE--')
        CALL DPWRST('XXX','BUG ')
        ITEMP=1
        WRITE(ICOUT,202)ITEMP,NUMSE1
  202   FORMAT('      THE NUMBER OF SETS FOR THE GROUP ',I1,   &
               ' VARIABLE, ',I8,',')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)
  203   FORMAT('      IS EITHER LESS THAN ONE OR GREATER THAN THE ',   &
               'NUMBER')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,205)N
  205   FORMAT('      OF OBSERVATIONS, ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(NREPL.GE.2 .AND. (NUMSE2.LT.1 .OR. NUMSE2.GT.N))THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,201)
        CALL DPWRST('XXX','BUG ')
        ITEMP=2
        WRITE(ICOUT,202)ITEMP,NUMSE2
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,205)N
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(NREPL.GE.3 .AND. (NUMSE3.LT.1 .OR. NUMSE3.GT.N))THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,201)
        CALL DPWRST('XXX','BUG ')
        ITEMP=3
        WRITE(ICOUT,202)ITEMP,NUMSE3
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,205)N
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(NREPL.GE.4 .AND. (NUMSE4.LT.1 .OR. NUMSE4.GT.N))THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,201)
        CALL DPWRST('XXX','BUG ')
        ITEMP=4
        WRITE(ICOUT,202)ITEMP,NUMSE4
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,205)N
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(NREPL.GE.5 .AND. (NUMSE5.LT.1 .OR. NUMSE5.GT.N))THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,201)
        CALL DPWRST('XXX','BUG ')
        ITEMP=5
        WRITE(ICOUT,202)ITEMP,NUMSE5
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,205)N
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(NREPL.GE.6 .AND. (NUMSE6.LT.1 .OR. NUMSE6.GT.N))THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,201)
        CALL DPWRST('XXX','BUG ')
        ITEMP=6
        WRITE(ICOUT,202)ITEMP,NUMSE6
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,205)N
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPP5')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9001)
 9001   FORMAT('***** AT THE END OF DPPP5--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9003)NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5,NUMSE6
 9003   FORMAT('NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5,NUMSE6 = ',6I6)
        CALL DPWRST('XXX','BUG ')
        IF(NREPL.GE.1)THEN
          DO 9011 I=1,NUMSE1
            WRITE(ICOUT,9013)I,XIDTEM(I)
 9013       FORMAT('I,XIDTEM(I) = ',I8,G15.7)
            CALL DPWRST('XXX','BUG ')
 9011     CONTINUE
        ENDIF
        IF(NREPL.GE.2)THEN
          DO 9021 I=1,NUMSE2
            WRITE(ICOUT,9023)I,XIDTE2(I)
 9023       FORMAT('I,XIDTE2(I) = ',I8,G15.7)
            CALL DPWRST('XXX','BUG ')
 9021     CONTINUE
        ENDIF
        IF(NREPL.GE.3)THEN
          DO 9031 I=1,NUMSE3
            WRITE(ICOUT,9033)I,XIDTE3(I)
 9033       FORMAT('I,XIDTE3(I) = ',I8,G15.7)
            CALL DPWRST('XXX','BUG ')
 9031     CONTINUE
        ENDIF
        IF(NREPL.GE.4)THEN
          DO 9041 I=1,NUMSE4
            WRITE(ICOUT,9043)I,XIDTE4(I)
 9043       FORMAT('I,XIDTE4(I) = ',I8,G15.7)
            CALL DPWRST('XXX','BUG ')
 9041     CONTINUE
        ENDIF
        IF(NREPL.GE.5)THEN
          DO 9051 I=1,NUMSE5
            WRITE(ICOUT,9053)I,XIDTE5(I)
 9053       FORMAT('I,XIDTE5(I) = ',I8,G15.7)
            CALL DPWRST('XXX','BUG ')
 9051     CONTINUE
        ENDIF
        IF(NREPL.GE.6)THEN
          DO 9061 I=1,NUMSE6
            WRITE(ICOUT,9063)I,XIDTE6(I)
 9063       FORMAT('I,XIDTE6(I) = ',I8,G15.7)
            CALL DPWRST('XXX','BUG ')
 9061     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPPP5
      SUBROUTINE DPPPCC(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,ICASP2,   &
                        IBUGG2,IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--GENERATE A PROBABILITY PLOT CORRELATION COEFFICIENT PLOT
!              FOR ONE OF THE FOLLOWING DISTRIBUTIONAL FAMILIES--
!              UNIVARIATE CONTINUOUS (ONE SHAPE PARAMETER)
!               1) TUKEY LAMBDA
!               2) T
!               3) CHI-SQUARED
!               4) GAMMA
!               5) WEIBULL --MIN & MAX
!               6) EXTREME VALUE TYPE 2 (FRECHET) --MIN & MAX
!               7) PARETO
!               8) WALD
!               9) FATIGUE LIFE
!              10) EXTREME VALUE (GENERAL)
!                        EXTREME VALUE PPCC PLOT Y
!                        EXTREME PPCC PLOT Y
!                        EV PPCCC PLOT Y
!              11) GENERALIZED PARETO
!                        GENERALIZED PARETO PPCC PLOT Y
!                        GEP PPCC PLOT Y
!                        GP PPCC PLOT Y
!              12) LOGNORMAL
!              13) POWER NORMAL
!              14) POWER FUNCTION
!              15) CHI
!              16) VON MISES
!              17) LOG LOGISTIC
!              18) LOG GAMMA
!              19) DOUBLE WEIBULL
!              20) GENERALIZED EXTREME VALUE
!              21) PARETO SECOND KIND
!              22) GENERALIZED HALF LOGISTIC
!              23) WRAPPED CAUCHY
!              24) GENERALIZED LOGISTIC
!              25) DOUBLE GAMMA
!              26) BRADFORD
!              27) RECIPROCAL
!              28) INVERTED GAMMA
!              29) INVERTED WEIBULL
!              30) LOG DOUBLE EXPONENTIAL
!              31) GEOMETRIC EXTREME  EXPONENTIAL
!              32) ERROR (SUBBOTIN/EXPONENTIAL POWER)
!              33) FOLDED T
!              34) SKEW NORMAL
!              35) SKEW DOUBLE EXPONENTIAL
!              36) ASYMMETRIC DOUBLE EXPONENTIAL
!              37) MCLEISH
!              38) GENERALIZED LOGISTIC TYPE 5
!              39) GENERALIZED LOGISTIC TYPE 2
!              40) GENERALIZED LOGISTIC TYPE 3
!              41) TOPP AND LEONE
!              42) SLOPE
!              43) OGIVE
!              44) BURR TYPE 2
!              45) BURR TYPE 7
!              46) BURR TYPE 8
!              47) BURR TYPE 10
!              48) BURR TYPE 11
!              49) EXPONENTIAL POWER
!              50) ALPHA
!              51) REFLECTED POWER
!              52) MUTH
!              53) LOGISTIC-EXPONENTIAL
!              54) PEARSON TYPE 3
!              55) G
!              56) H
!
!              NOTE: EVEN THOUGH PARETO, PARETO SECOND KIND
!                    ACTUALLY HAVE A SECOND SHAPE PARAMETER, TREAT
!                    THIS AS KNOWN AND FIXED (SET TO MINIMUM OF
!                    THE DATA FOR THE PARETO, LET USER SET FOR
!                    PARETO SECOND KIND (DEFAULT TO 1)).
!
!              UNIVARIATE DISCRETE (USE A LITTLE IFFY HERE, BUT
!              INCLUDE FOR EXPERIMENTAL PURPOSES, CHI-SQUARE PLOT WORKS
!              BETTER THAN THE PPCC PLOT HERE)
!               1) GEOMETRIC
!               2) POISSON
!               3) LOGARITHMIC SERIES
!               4) NEGATIVE BIONOMIAL
!               5) BETA-BINOMIAL (ASSUME N PARAMETER KNOWN)
!               6) POLYA (ASSUME N PARAMETER KNOWN)
!               7) HYPERGEOMETRIC (NOT SUPPORTED)
!               8) YULE (SUPPORT CHI-SQUARE PLOT, BUT NOT PPCC)
!               9) WARING (SUPPORT CHI-SQUARE PLOT, BUT NOT PPCC)
!              10) HERMITE
!              11) BINOMIAL
!              12) BETA GEOMETRIC (RE-PARAMETERIZED WARING)
!              13) ZETA (SUPPORT CHI-SQUARE PLOT, BUT NOT PPCC)
!              14) ZIPF (SUPPORT CHI-SQUARE PLOT, BUT NOT PPCC)
!              15) BOREL-TANNER
!              16) LAGRANGE-POISSON
!              17) POLYA-AEPPLI
!              18) LOST GAMES
!              19) GENERALIZED LOGARITHMIC SERIES
!              20) GEETA
!              21) CONSUL (GENERALIZED GEOMTRIC)
!              22) KATZ
!              23) DISCRETE WEIBULL
!              24) GENERALIZED LOST GAMES
!
!              WE DO NOT INCLUDE DISCRETE UNIFORM, MATCHING, LOST GAMES,
!              OR LEADS IN COIN TOSSING (DISCRETE ARCSINE) SINCE THE
!              PARAMETER ESTIMATES ARE SIMPLY THE MINIMUM AND/OR
!              MAXIMUM POINTS IN THE DATA.  ALSO, WE DO NOT
!              INCLUDE THE BETA-NEGATIVE BINOMIAL (= GENERALIZED
!              WARING) SINCE THIS HAS 3 SHAPE PARAMETERS.
!
!              SUPPORT FOR FOLLOWING DISTRIBUTIONS WITH 2 SHAPE
!              PARAMETERS (AUGUST 2001).  FOR THESE, WE WILL
!              GENERATE A 3-D PLOT.  FOR SOME OF THESE, PPCC PLOT
!              CAN BE SLOW DUE TO FACT THAT PPCC MAY BE EXPENSIVE
!              TO COMPUTE.
!               1) GENERALIZED TUKEY LAMBDA
!               2) BETA
!               3) GENERALIZED GAMMA
!               4) GOMPERTZ
!               5) POWER LOGNORMAL
!               6) EXPONENTIATED WEIBULL
!               7) JOHNSON SB
!               8) JOHNSON SU
!               9) TWO-SIDED POWER
!              10) F
