      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     DATAPLOT SUPPORTS THE FOLLOWING SYNTAX:
!
!     NO CENSORING, NO REPLICATION
!     ============================
!     <DIST> PPCC PLOT Y                            - RAW DATA
!     <DIST> PPCC PLOT Y X                          - BINNED DATA
!     <DIST> PPCC PLOT Y XLOW XUPP                  - UNEQUAL BINNED DATA
!
!     CENSORING, NO REPLICATION
!     ============================
!     <DIST> CENSORED PPCC PLOT Y CENS              - RAW DATA
!     <DIST> CENSORED PPCC PLOT Y CENS XMID         - BINNED DATA
!     <DIST> CENSORED PPCC PLOT Y CENS XLOW XUPP    - UNEQUAL BINS
!
!     NO CENSORING, REPLICATION
!     ============================
!     <DIST> MULTIPLE PPCC PLOT Y1 ... YK               - RAW DATA
!     <DIST> REPLICATED PPCC PLOT Y X1 ... XK           - RAW DATA
!     <DIST> REPLICATED GROUPED PPCC PLOT Y XMID X1 ... XK
!                                                       - BINNED DATA
!     <DIST> REPLICATED UNEQUAL GROUPED PPCC PLOT Y XLOW XUPP X1 ... XK
!                                                       - UNEQUAL BINS
!
!     CENSORING, REPLICATION
!     ============================
!     <DIST> CENSORED REPLICATED PCC PLOT Y CENS X1 ... XK - RAW DATA
!     <DIST> CENSORED REPLICATED GROUPED PCC PLOT Y CENS XMID X1 .. XK
!                                                          - BINNED DATA
!     <DIST> CENSORED REPLICATED UNEQUAL GROUPED PPCC PLOT Y CENS
!                                XLOW XUPP X1 ... XK       - UNEQUAL BINS
!
!     LOOK FOR THE WORD "PPCC PLOT" (ERROR IF NOT FOUND).
!     ALSO LOOK FOR OPTIONAL KEYWORDS "CENSOR", "REPLICATION",
!     AND "MULTIPLE".
!
!     ALSO LOOK FOR THE FOLLOWING "GOODNESS OF FIT" KEYWORDS:
!
!         KOLMOGOROV SMIRNOV  (KS)
!         ANDERSON DARLING    (AD)
!         CHI-SQUARE          (CHISQUARE)
!         AIC
!         BIC
!         BICC
!
!     THE AIC/BIC/BICC ARE STILL BEING DEVELOPED AND ARE NOT ACTIVE YET.
!     THE CHI-SQUARE IS RESTRICTED TO GROUPED DATA AND THE K-S AND
!     A-D ARE RESTRICTED TO THE RAW DATA CASE.
!
      ISTEPN='1'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PPCC')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     CHECK FOR CONFLICT WITH NORMAL PPCC PLOT AND UNIFORM PPCC PLOT
!     COMMANDS.
!
!     CHECK FOR CONFLICT WITH BOX COX NORMALITY PPCC/LAMBDA PLOT
!
      IF(ICOM.EQ.'NORM' .OR. ICOM.EQ.'UNIF' .OR. ICOM.EQ.'CAUC' .OR.   &
          ICOM.EQ.'LOGI' .OR. ICOM.EQ.'COSI' .OR. ICOM.EQ.'ANGL' .OR.   &
          ICOM.EQ.'ARCS' .OR. ICOM.EQ.'EXPO' .OR. ICOM.EQ.'SLAS' .OR.   &
          ICOM.EQ.'LAPL' .OR. ICOM.EQ.'GUMB' .OR.   &
          ICOM.EQ.'MAXW' .OR. ICOM.EQ.'RAYL' .OR. ICOM.EQ.'SLAS')THEN
         IF(IHARG(1).EQ.'PPCC' .AND. IHARG(2).EQ.'PLOT')GO TO 9000
         IF(IHARG(1).EQ.'AD  ' .AND. IHARG(2).EQ.'PLOT')GO TO 9000
         IF(IHARG(1).EQ.'ANDE' .AND. IHARG(2).EQ.'DARL' .AND.   &
           IHARG(3).EQ.'PLOT')GO TO 9000
      ENDIF
!
      IF(ICOM.EQ.'DOUB' .AND. IHARG(1).EQ.'EXPO')THEN
        IF(IHARG(2).EQ.'PPCC' .AND. IHARG(3).EQ.'PLOT')GO TO 9000
        IF(IHARG(2).EQ.'AD  ' .AND. IHARG(3).EQ.'PLOT')GO TO 9000
        IF(IHARG(2).EQ.'ANDE' .AND. IHARG(3).EQ.'DARL' .AND.   &
           IHARG(4).EQ.'PLOT')GO TO 9000
      ENDIF
      IF(ICOM.EQ.'HYPE' .AND. IHARG(1).EQ.'SECA')THEN
        IF(IHARG(2).EQ.'PPCC' .AND. IHARG(3).EQ.'PLOT')GO TO 9000
        IF(IHARG(2).EQ.'AD  ' .AND. IHARG(3).EQ.'PLOT')GO TO 9000
        IF(IHARG(2).EQ.'ANDE' .AND. IHARG(3).EQ.'DARL' .AND.   &
           IHARG(4).EQ.'PLOT')GO TO 9000
      ENDIF
      IF(ICOM.EQ.'HALF' .AND. IHARG(1).EQ.'NORM')THEN
        IF(IHARG(2).EQ.'PPCC' .AND. IHARG(3).EQ.'PLOT')GO TO 9000
        IF(IHARG(2).EQ.'AD  ' .AND. IHARG(3).EQ.'PLOT')GO TO 9000
        IF(IHARG(2).EQ.'ANDE' .AND. IHARG(3).EQ.'DARL' .AND.   &
           IHARG(4).EQ.'PLOT')GO TO 9000
      ENDIF
!
!     CHECK FOR CONFLICT WITH
!
!        <DIST> PPCC STATISTIC PLOT
!        <DIST> AD STATISTIC PLOT
!        <DIST> ANDERSON DARLING STATISTIC PLOT
!
      IF(IHARG(1).EQ.'PPCC' .AND. IHARG(2).EQ.'STAT' .AND.   &
         IHARG(3).EQ.'PLOT')GO TO 9000
      IF(IHARG(1).EQ.'AD  ' .AND. IHARG(2).EQ.'STAT' .AND.   &
         IHARG(3).EQ.'PLOT')GO TO 9000
!
      IF(IHARG(2).EQ.'PPCC' .AND. IHARG(3).EQ.'STAT' .AND.   &
         IHARG(4).EQ.'PLOT')GO TO 9000
      IF(IHARG(2).EQ.'AD  ' .AND. IHARG(3).EQ.'STAT' .AND.   &
         IHARG(4).EQ.'PLOT')GO TO 9000
!
      IF(IHARG(3).EQ.'PPCC' .AND. IHARG(4).EQ.'STAT' .AND.   &
         IHARG(5).EQ.'PLOT')GO TO 9000
      IF(IHARG(3).EQ.'AD  ' .AND. IHARG(4).EQ.'STAT' .AND.   &
         IHARG(5).EQ.'PLOT')GO TO 9000
!
      IF(IHARG(1).EQ.'ANDE' .AND. IHARG(2).EQ.'DARL' .AND.   &
         IHARG(3).EQ.'STAT' .AND. IHARG(4).EQ.'PLOT')GO TO 9000
      IF(IHARG(2).EQ.'ANDE' .AND. IHARG(3).EQ.'DARL' .AND.   &
         IHARG(4).EQ.'STAT' .AND. IHARG(5).EQ.'PLOT')GO TO 9000
      IF(IHARG(3).EQ.'ANDE' .AND. IHARG(4).EQ.'DARL' .AND.   &
         IHARG(5).EQ.'STAT' .AND. IHARG(6).EQ.'PLOT')GO TO 9000
!
      IF(ICOM.EQ.'BOX ' .AND. IHARG(1).EQ.'COX ' .AND.   &
         IHARG(2).EQ.'NORM')GO TO 9000
!
      ILASTC=9999
      ILASTZ=9999
      IFOUND='NO'
      DO 100 I=1,NUMARG-1
        IF(IHARG(I).EQ.'PPCC' .AND. IHARG(I+1).EQ.'PLOT')THEN
          IFOUND='YES'
          ICASPL='PPCC'
          ILASTC=MIN(ILASTC,I-1)
          ILASTZ=I+1
        ELSEIF(IHARG(I).EQ.'KS  ' .AND. IHARG(I+1).EQ.'PLOT')THEN
          IFOUND='YES'
          ICASPL='KS'
          ILASTC=MIN(ILASTC,I-1)
          ILASTZ=I+1
        ELSEIF(I.LE.NUMARG-2 .AND. IHARG(I).EQ.'KOLM' .AND.   &
               IHARG(I+1).EQ.'SMIR'.AND. IHARG(I+2).EQ.'PLOT')THEN
          IFOUND='YES'
          ICASPL='KS'
          ILASTC=MIN(ILASTC,I-1)
          ILASTZ=I+2
        ELSEIF(I.LE.NUMARG-2 .AND. IHARG(I).EQ.'K   ' .AND.   &
               IHARG(I+1).EQ.'S   '.AND. IHARG(I+2).EQ.'PLOT')THEN
          IFOUND='YES'
          ICASPL='KS'
          ILASTC=MIN(ILASTC,I-1)
          ILASTZ=I+2
        ELSEIF(IHARG(I).EQ.'AD  ' .AND. IHARG(I+1).EQ.'PLOT')THEN
          IFOUND='YES'
          ICASPL='AD'
          ILASTC=MIN(ILASTC,I-1)
          ILASTZ=I+1
        ELSEIF(I.LE.NUMARG-2 .AND. IHARG(I).EQ.'ANDE' .AND.   &
               IHARG(I+1).EQ.'DARL'.AND. IHARG(I+2).EQ.'PLOT')THEN
          IFOUND='YES'
          ICASPL='AD'
          ILASTC=MIN(ILASTC,I-1)
          ILASTZ=I+2
        ELSEIF(I.LE.NUMARG-2 .AND. IHARG(I).EQ.'A   ' .AND.   &
               IHARG(I+1).EQ.'D   '.AND. IHARG(I+2).EQ.'PLOT')THEN
          IFOUND='YES'
          ICASPL='AD'
          ILASTC=MIN(ILASTC,I-1)
          ILASTZ=I+2
        ELSEIF(IHARG(I).EQ.'CHIS' .AND. IHARG(I+1).EQ.'PLOT')THEN
          IFOUND='YES'
          ICASPL='CHSQ'
          ILASTC=MIN(ILASTC,I-1)
          ILASTZ=I+1
        ELSEIF(I.LE.NUMARG-2 .AND. IHARG(I).EQ.'CHI ' .AND.   &
               IHARG(I+1).EQ.'SQUA'.AND. IHARG(I+2).EQ.'PLOT')THEN
          IFOUND='YES'
          ICASPL='CHSQ'
          ILASTC=MIN(ILASTC,I-1)
          ILASTZ=I+2
        ELSEIF(IHARG(I).EQ.'CENS')THEN
          ICENSO='ON'
          ILASTC=MIN(ILASTC,I-1)
        ELSEIF(IHARG(I).EQ.'REPL')THEN
          IREPL='ON'
          ILASTC=MIN(ILASTC,I-1)
        ELSEIF(IHARG(I).EQ.'MULT')THEN
          IMULT='ON'
          ILASTC=MIN(ILASTC,I-1)
        ELSEIF(IHARG(I).EQ.'GROU')THEN
          IF(IGROUP.NE.'UNEQ')IGROUP='EQUA'
          ILASTC=MIN(ILASTC,I-1)
        ELSEIF(IHARG(I).EQ.'UNEQ')THEN
          IGROUP='UNEQ'
          ILASTC=MIN(ILASTC,I-1)
        ENDIF
  100 CONTINUE
!
      IF(IFOUND.EQ.'NO')GO TO 9000
      IF(IMULT.EQ.'ON')THEN
        IF(IREPL.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
  101     FORMAT('***** ERROR IN PPCC PLOT--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)
  102     FORMAT('      YOU CANNOT SPECIFY BOTH "MULTIPLE" AND ',   &
                 '"REPLICATION" FOR THE PPCC PLOT.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ELSEIF(ICENSO.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,112)
  112     FORMAT('      YOU CANNOT SPECIFY BOTH "MULTIPLE" AND ',   &
                 '"CENSORING" FOR THE PPCC PLOT.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
!               ***************************************************
!               **  STEP 2--EXTRACT THE DISTRIBUTION NAME        **
!               ***************************************************
!
      ISTEPN='2'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PPCC')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,211)IMULT,IREPL,ICENSO,ILASTC,ILASTZ
  211   FORMAT('IMULT,IREPL,ICENSO,ILASTC,ILASTZ = ',3(A4,2X),2I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      NLOCAL=0
      NPLOTP=0
!
      JMIN=0
      JMAX=ILASTC
!
      CALL EXTDIS(ICOM,ICOM2,IHARG,IHARG2,NUMARG,JMIN,JMAX,   &
                  ICASP2,IDIST,NUMSHA,IFOUND,ILOCV,   &
                  ISUBRO,IBUGG3,IERROR)
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PPCC')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,251)
  251   FORMAT('***** AFTER CALL EXTDIS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,252)ICASPL,ICASP2,NUMSHA,IDIST
  252   FORMAT('ICASPL,ICASP2,NUMSHA,IDIST = ',A4,2X,A4,2X,I8,2X,A60)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IFOUND.EQ.'NO')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,262)
  262   FORMAT('      NO MATCH FOUND FOR DISTRIBUTION NAME.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NUMSHA.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,272)IDIST
  272   FORMAT('      THE ',A60,' DISTRIBUTION')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,274)
  274   FORMAT('      HAS NO SHAPE PARAMETERS, SO PPCC PLOT IS NOT ',   &
               'APPLICABLE.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NUMSHA.GT.1 .AND. IREPL.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)
  282   FORMAT('      REPLICATION NOT SUPPORTED FOR CASES WITH MORE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,284)
  284   FORMAT('      THAN ONE SHAPE PARAMETER.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NUMSHA.GT.1 .AND. IMULT.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,292)
  292   FORMAT('      "MULTIPLE" NOT SUPPORTED FOR CASES WITH MORE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,294)
  294   FORMAT('      THAN ONE SHAPE PARAMETER.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSE
        CALL ADJUST(ILASTZ,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      ENDIF
!
!               ***************************************************
!               **  STEP 3--EXTRACT THE RANGES FOR THE SHAPE     **
!               **          PARAMETERS FOR THE SPECIFIED         **
!               **          DISTRIBUTION.                        **
!               ***************************************************
!
      ISTEPN='3'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PPCC')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICASP2.EQ.'GMCL' .OR. ICASP2.EQ.'TRAP' .OR.   &
             ICASP2.EQ.'GTRA' .OR. ICASP2.EQ.'UTSP' .OR.   &
             ICASP2.EQ.'GLGP' .OR.   &
             ICASP2.EQ.'PARE' .OR. ICASP2.EQ.'PAR2'   &
        )THEN
        CONTINUE
      ELSE
        IHP='A   '
        IHP2='    '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
        IF(IERROR.EQ.'YES')THEN
          A=0.0
          IF(ICASP2.EQ.'TRIA')A=-1.0
        ELSE
          A=VALUE(ILOCV)
        ENDIF
!
        IHP='B   '
        IHP2='    '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
        IF(IERROR.EQ.'YES')THEN
          B=1.0
        ELSE
          B=VALUE(ILOCV)
        ENDIF
!
      ENDIF
!
      SHAPE1=CPUMIN
      SHAPE2=CPUMIN
      SHAPE3=CPUMIN
      SHAPE4=CPUMIN
      SHAPE5=CPUMIN
      IF(NUMSHA.GE.1)THEN
        CALL EXTPA2(ICASP2,IDIST,A,B,   &
                    SHAP11,SHAP12,SHAP21,SHAP22,   &
                    SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                    IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                    ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                    IGETDF,ICONDF,IGOMDF,IKATDF,   &
                    IGIGDF,IGEODF,   &
                    ISUBRO,IBUGG2,IERROR)
        IF(IERROR.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,302)
  302     FORMAT('      UNABLE TO EXTRACT PARAMETER RANGES.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,304)ICASP2
  304     FORMAT('      ICASP2 = ',A4)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PPCC')THEN
          WRITE(ICOUT,312)ICASP2,IDIST
  312     FORMAT('AFTER EXTPA2: ICASP2,IDIST = ',A4,2X,A60)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,314)SHAP11,SHAP12,SHAP21,SHAP22
  314     FORMAT('SHAP11,SHAP12,SHAP21,SHAP22 = ',4G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
!               *********************************
!               **  STEP 4--                   **
!               **  EXTRACT THE VARIABLE LIST  **
!               *********************************
!
      ISTEPN='4'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PPCC')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='PPCC PLOT'
      MINNA=1
      MAXNA=100
      MINN2=2
      IFLAGE=1
      IFLAGM=0
      IF(IMULT.EQ.'ON')THEN
        IFLAGE=0
        IFLAGM=1
      ELSE
         IF(IREPL.EQ.'OFF' .AND. ICENSO.EQ.'OFF')IFLAGM=1
      ENDIF
      IF(ICASP2.EQ.'BFWE' .AND. IBFWTY.EQ.'ON')THEN
        IFLAGM=0
      ELSEIF(ICASP2.EQ.'BFWE' .AND. IBFWLI.EQ.'VARI')THEN
        IFLAGM=0
      ELSEIF(ICASP2.EQ.'EEWE' .AND. IEEWLI.EQ.'VARI')THEN
        IFLAGM=0
      ENDIF
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=1
      MAXNVA=MAXSPN
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PPCC')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,481)
  481   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,482)NQ,NUMVAR
  482   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 485 I=1,NUMVAR
            WRITE(ICOUT,487)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  487       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  485     CONTINUE
        ENDIF
      ENDIF
!
!               *************************************************
!               **  STEP 5--                                   **
!               **  DETERMINE:                                 **
!               **  1) NUMBER OF REPLICATION VARIABLES (0-6)   **
!               **  2) NUMBER OF CENSORING   VARIABLES (0-1)   **
!               **  3) NUMBER OF GROUPING    VARIABLES (0-2)   **
!               **  4) NUMBER OF RESPONSE    VARIABLES (>= 1)  **
!               *************************************************
!
      ISTEPN='5'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PPCC')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NRESP=0
      NREPL=0
      NCENS=0
      NGROUP=0
      NLEVEL=0
      IDATSW='RAW'
      IF(IMULT.EQ.'ON')THEN
        NRESP=NUMVAR
      ELSEIF(IREPL.EQ.'ON')THEN
        NRESP=1
        IF(ICENSO.EQ.'ON')THEN
          NCENS=1
        ENDIF
        IF(IGROUP.EQ.'EQUA')THEN
          NGROUP=1
          IDATSW='FREQ'
        ELSEIF(IGROUP.EQ.'UNEQ')THEN
          NGROUP=2
          IDATSW='FRE2'
        ENDIF
        NREPL=NUMVAR-NRESP-NCENS-NGROUP
        IF(NREPL.LT.1 .OR. NREPL.GT.6)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,511)
  511     FORMAT('      FOR THE REPLICATION CASE, THE NUMBER OF ',   &
                 'REPLICATION VARIABLES')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,512)
  512     FORMAT('      MUST BE BETWEEN 1 AND 6;  SUCH WAS NOT THE ',   &
                 'CASE HERE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,513)NREPL
  513     FORMAT('      THE NUMBER OF REPLICATION VARIABLES = ',I5)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ELSE
        NRESP=1
        NLEVEL=0
        IF(ICENSO.EQ.'ON')THEN
          NCENS=1
        ENDIF
        IF(ICASP2.EQ.'BFWE')THEN
          IF(IBFWTY.EQ.'ON' .AND. NUMVAR.GT.1)THEN
             NLEVEL=1
             ILEVEL='ON'
          ENDIF
          IF(IBFWLI.EQ.'VARI' .AND. NUMVAR.GT.1)THEN
             NLEVEL=1
             ILEVEL='ON'
          ENDIF
          NGROUP=NUMVAR-NRESP-NCENS-NLEVEL
        ELSEIF(ICASP2.EQ.'EEWE')THEN
          IF(IEEWLI.EQ.'VARI' .AND. NUMVAR.GT.1)THEN
             NLEVEL=1
             ILEVEL='ON'
          ENDIF
          NGROUP=NUMVAR-NRESP-NCENS-NLEVEL
        ELSE
          NGROUP=NUMVAR-NRESP-NCENS
        ENDIF
        IF(NGROUP.EQ.1)IDATSW='FREQ'
        IF(NGROUP.EQ.2)IDATSW='FRE2'
        IF(NGROUP.LT.0 .OR. NGROUP.GT.2)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,521)
  521     FORMAT('      THE NUMBER OF CLASS VARIABLES IS LESS THAN ',   &
                 'ZERO OR GREATER THAN TWO.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,523)NGROUP
  523     FORMAT('      THE NUMBER OF CLASS VARIABLES = ',I5)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
!               *****************************************
!               **  STEP 6--                           **
!               **  GENERATE THE PPCC        PLOTS FOR **
!               **  THE VARIOUS CASES.  SEE IF USER    **
!               **  HAS SPECIFIED VALUES FOR KSLOC,    **
!               **  KSSCAL, MINSIZE, OR CHSLIM.        **
!               *****************************************
!
      ISTEPN='6'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PPCC')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IHP='KSLO'
      IHP2='C   '
      IHWUSE='P'
      MESSAG='NO '
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        KSLOC=CPUMIN
      ELSE
       KSLOC=VALUE(ILOCP)
      ENDIF
!
      IHP='KSSC'
      IHP2='ALE '
      IHWUSE='P'
      MESSAG='NO '
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        KSSCAL=CPUMIN
      ELSE
        KSSCAL=VALUE(ILOCP)
      ENDIF
      IF(KSSCAL.LE.0.0)KSSCAL=CPUMIN
!
      IHP='MINS'
      IHP2='IZE '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        MINSIZ=5
      ELSE
        MINSIZ=INT(VALUE(ILOCP)+0.5)
        IF(MINSIZ.LE.0)MINSIZ=5
      ENDIF
!
!
!               *****************************************
!               **  STEP 7A--                          **
!               **  CASE 1: SINGLE RESPONSE VARIABLE   **
!               **          WITH NO REPLICATION        **
!               *****************************************
!
      IF(NRESP.EQ.1 .AND. NREPL.EQ.0)THEN
        ISTEPN='7A'
        IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PPCC')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        ICOL=1
        IF(IFLAGM.EQ.1 .AND. NUMVAR.EQ.1)THEN
          CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                      INAME,IVARN1,IVARN2,IVARTY,   &
                      ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVAR,   &
                      MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                      MAXCP4,MAXCP5,MAXCP6,   &
                      V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                      Y1,XTEMP1,XTEMP2,NLOCAL,NLOCA2,NLOCA3,ICASE,   &
                      IBUGG3,ISUBRO,IFOUND,IERROR)
        ELSE
          J=0
          IMAX=NRIGHT(1)
          IF(NQ.LT.NRIGHT(1))IMAX=NQ
          DO 710 I=1,IMAX
            IF(ISUB(I).EQ.0)GO TO 710
            J=J+1
!
!           RESPONSE VARIABLE IN Y1
!
            IJ=MAXN*(ICOLR(1)-1)+I
            IF(ICOLR(1).LE.MAXCOL)Y1(J)=V(IJ)
            IF(ICOLR(1).EQ.MAXCP1)Y1(J)=PRED(I)
            IF(ICOLR(1).EQ.MAXCP2)Y1(J)=RES(I)
            IF(ICOLR(1).EQ.MAXCP3)Y1(J)=YPLOT(I)
            IF(ICOLR(1).EQ.MAXCP4)Y1(J)=XPLOT(I)
            IF(ICOLR(1).EQ.MAXCP5)Y1(J)=X2PLOT(I)
            IF(ICOLR(1).EQ.MAXCP6)Y1(J)=TAGPLO(I)
            ICOLC=1
!
!           LENGTH VARIABLE IN XLEVEL
!
            IF(ILEVEL.EQ.'ON')THEN
              ICOLC=ICOLC+1
              ICOLT=ICOLR(ICOLC)
              IJ=MAXN*(ICOLT-1)+I
              IF(ICOLT.LE.MAXCOL)XLEVEL(J)=V(IJ)
              IF(ICOLT.EQ.MAXCP1)XLEVEL(J)=PRED(I)
              IF(ICOLT.EQ.MAXCP2)XLEVEL(J)=RES(I)
              IF(ICOLT.EQ.MAXCP3)XLEVEL(J)=YPLOT(I)
              IF(ICOLT.EQ.MAXCP4)XLEVEL(J)=XPLOT(I)
              IF(ICOLT.EQ.MAXCP5)XLEVEL(J)=X2PLOT(I)
              IF(ICOLT.EQ.MAXCP6)XLEVEL(J)=TAGPLO(I)
            ENDIF
!
!           CENSORING VARIABLE IN XCENS
!
            IF(ICENSO.EQ.'ON')THEN
              ICOLC=ICOLC+1
              ICOLT=ICOLR(ICOLC)
              IJ=MAXN*(ICOLT-1)+I
              IF(ICOLT.LE.MAXCOL)XCENS(J)=V(IJ)
              IF(ICOLT.EQ.MAXCP1)XCENS(J)=PRED(I)
              IF(ICOLT.EQ.MAXCP2)XCENS(J)=RES(I)
              IF(ICOLT.EQ.MAXCP3)XCENS(J)=YPLOT(I)
              IF(ICOLT.EQ.MAXCP4)XCENS(J)=XPLOT(I)
              IF(ICOLT.EQ.MAXCP5)XCENS(J)=X2PLOT(I)
              IF(ICOLT.EQ.MAXCP6)XCENS(J)=TAGPLO(I)
            ENDIF
!
!           CLASS VARIABLE IN XLOW FOR FREQUENCY DATA
!
            IF(NGROUP.GE.1)THEN
              IDATSW='FREQ'
              ICOLC=ICOLC+1
              ICOLT=ICOLR(ICOLC)
              IJ=MAXN*(ICOLT-1)+I
              IF(ICOLT.LE.MAXCOL)XLOW(J)=V(IJ)
              IF(ICOLT.EQ.MAXCP1)XLOW(J)=PRED(I)
              IF(ICOLT.EQ.MAXCP2)XLOW(J)=RES(I)
              IF(ICOLT.EQ.MAXCP3)XLOW(J)=YPLOT(I)
              IF(ICOLT.EQ.MAXCP4)XLOW(J)=XPLOT(I)
              IF(ICOLT.EQ.MAXCP5)XLOW(J)=X2PLOT(I)
              IF(ICOLT.EQ.MAXCP6)XLOW(J)=TAGPLO(I)
            ENDIF
!
!           IF FREQUENCY DATA GIVEN WITH LOWER AND UPPER CLASS LIMITS,
!           THEN UPPER CLASS LIMIT VARIABLE IN XHIGH
!
            IF(NGROUP.EQ.2)THEN
              IDATSW='FRE2'
              ICOLC=ICOLC+1
              ICOLT=ICOLR(ICOLC)
              IJ=MAXN*(ICOLT-1)+I
              IF(ICOLT.LE.MAXCOL)XHIGH(J)=V(IJ)
              IF(ICOLT.EQ.MAXCP1)XHIGH(J)=PRED(I)
              IF(ICOLT.EQ.MAXCP2)XHIGH(J)=RES(I)
              IF(ICOLT.EQ.MAXCP3)XHIGH(J)=YPLOT(I)
              IF(ICOLT.EQ.MAXCP4)XHIGH(J)=XPLOT(I)
              IF(ICOLT.EQ.MAXCP5)XHIGH(J)=X2PLOT(I)
              IF(ICOLT.EQ.MAXCP6)XHIGH(J)=TAGPLO(I)
            ENDIF
!
  710     CONTINUE
          NLOCAL=J
        ENDIF
!
!       *****************************************************
!       **  STEP 7B--                                      **
!       **  FORM THE VERTICAL AND HORIZONTAL AXIS          **
!       **  VALUES Y(.) AND X(.) FOR THE PLOT.             **
!       **  RESET THE VECTOR D(.) TO ALL ONES.             **
!       **  DEFINE THE NUMBER OF PLOT POINTS    (NPLOTP).  **
!       **  DEFINE THE NUMBER OF PLOT VARIABLES (NPLOTV).  **
!       *****************************************************
!
        ISTEPN='7B'
        IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PPCC')THEN
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,711)
  711     FORMAT('***** FROM THE MIDDLE  OF DPPPCC--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,712)ICASPL,ILEVEL,NUMVAR,IDATSW,NLOCAL
  712     FORMAT('ICASPL,ILEVEL,NUMVAR,IDATSW,NQ = ',   &
                 2(A4,2X),I8,2X,A4,I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,713)NRESP,NCENS,NLEVEL,NGROUP
  713     FORMAT('NRESP,NCENS,NLEVEL,NGROUP = ',4I8)
          CALL DPWRST('XXX','BUG ')
          IF(NLOCAL.GE.1)THEN
            DO 715 I=1,NLOCAL
              WRITE(ICOUT,716)I,Y1(I),XLOW(I),XHIGH(I),XCENS(I),   &
                              XLEVEL(I)
  716         FORMAT('I,Y1(I),XLOW(I),XHIGH(I),XCENS(I),XLEVEL(I) = ',   &
                     I8,5F12.5)
              CALL DPWRST('XXX','BUG ')
  715       CONTINUE
          ENDIF
        ENDIF
!
        NPLOTP=0
        NCURVE=1
        IFLAGF='ON'
        IF(NGROUP.EQ.0 .AND. ICASPL.NE.'CHSQ')THEN
          CALL DPPPC2(Y1,XCENS,XLEVEL,NLOCAL,MAXOBV,   &
                      ICASPL,ICASP2,   &
                      SHAP11,SHAP12,SHAP21,SHAP22,   &
                      SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                      YLOWLM,YUPPLM,A,B,MINMAX,   &
                      DISPAR,DISPA2,DISPA3,CORR,NUMSHA,   &
                      XTEMP1,XTEMP2,XTEMP3,XTEMP4,XTEMP5,   &
                      X2TEMP,Y2TEMP,D2TEMP,WEIGHH,WEIGHV,IPPCBW,   &
                      IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                      ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                      IGETDF,ICONDF,IGOMDF,IKATDF,   &
                      IGIGDF,IGEODF,   &
                      IPPCCC,IPPCFO,IPPLDP,KSLOC,KSSCAL,   &
                      IPPCDP,IPPCAP,IPPCAO,IMETHD,ICENSO,IFLAGF,NCURVE,   &
                      PCHSLM,ILEVEL,   &
                      Y,X,X3D,D,NPLOTP,NPLOTV,   &
                      PPCCMX,SHA1MX,SHA2MX,A0SAVE,A1SAVE,A0BWSV,A1BWSV,   &
                      IBUGG3,ISUBRO,IERROR)
        ELSE
          CALL DPPPC3(Y1,XCENS,XLOW,XHIGH,NLOCAL,MAXOBV,   &
                      ICASPL,ICASP2,IDATSW,IDIST,   &
                      SHAP11,SHAP12,SHAP21,SHAP22,   &
                      SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                      YLOWLM,YUPPLM,A,B,MINMAX,   &
                      DISPAR,DISPA2,DISPA3,CORR,NUMSHA,   &
                      XTEMP1,XTEMP2,XTEMP3,XTEMP4,XTEMP5,   &
                      X2TEMP,Y2TEMP,D2TEMP,WEIGHH,WEIGHV,IPPCBW,   &
                      IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                      ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                      IGETDF,ICONDF,IGOMDF,IKATDF,   &
                      IGIGDF,IGEODF,   &
                      IPPCCC,IPPCFO,IPPLDP,KSLOC,KSSCAL,   &
                      IPPCDP,IPPCAP,IPPCAO,IMETHD,ICENSO,IFLAGF,NCURVE,   &
                      PCHSLM,MINSIZ,IHSTCW,CLWIDT,CLLIMI,   &
                      Y,X,X3D,D,NPLOTP,NPLOTV,   &
                      PPCCMX,SHA1MX,SHA2MX,A0SAVE,A1SAVE,   &
                      IBUGG3,ISUBRO,IERROR)
        ENDIF
!
!               ***************************************
!               **  STEP 7C--                        **
!               **  COMPUTE PPCC PLOT STAT           **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
        ISTEPN='7C'
        IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'DPPP')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IFLAGU='ON'
        IFRST=.FALSE.
        ILAST=.FALSE.
        CALL DPPPC4(ICASPL,PPCCMX,SHA1MX,SHA2MX,A0SAVE,A1SAVE,NUMSHA,   &
                    IFLAGU,IFRST,ILAST,   &
                    IBUGG2,IBUGG3,ISUBRO,IERROR)
!
!               ******************************************
!               **  STEP 8A--                           **
!               **  CASE 2: MULTIPLE RESPONSE VARIABLES **
!               **          NOTE THAT CENSORING AND     **
!               **          GROUPING ARE NOT SUPPORTED  **
!               **          FOR THIS CASE.              **
!               ******************************************
!
      ELSEIF(NRESP.GT.1)THEN
        ISTEPN='8A'
        IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PPCC')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!       LOOP THROUGH EACH OF THE RESPONSE VARIABLES
!
        NPLOTP=0
        NCURVE=0
        IFLAGF='ON'
        DO 810 IRESP=1,NRESP
          NCURVE=NCURVE+1
!
          IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PPCC')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,811)IRESP,NCURVE
  811       FORMAT('IRESP,NCURVE = ',2I5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          ICOL=IRESP
          NUMVA2=1
          CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                      INAME,IVARN1,IVARN2,IVARTY,   &
                      ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                      MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                      MAXCP4,MAXCP5,MAXCP6,   &
                      V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                      Y1,XTEMP1,XTEMP2,NLOCAL,NLOCA2,NLOCA3,ICASE,   &
                      IBUGG3,ISUBRO,IFOUND,IERROR)
!
!         *****************************************************
!         **  STEP 8B--                                      **
!         **  FORM THE VERTICAL AND HORIZONTAL AXIS          **
!         **  VALUES Y(.) AND X(.) FOR THE PLOT.             **
!         **  RESET THE VECTOR D(.) TO ALL ONES.             **
!         **  DEFINE THE NUMBER OF PLOT POINTS    (NPLOTP).  **
!         **  DEFINE THE NUMBER OF PLOT VARIABLES (NPLOTV).  **
!         *****************************************************
!
          ISTEPN='8B'
          IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PPCC')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
          IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'DPPP')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,822)
  822       FORMAT('***** FROM THE MIDDLE  OF DPPP--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,823)ICASPL,NUMVAR,NLOCAL
  823       FORMAT('ICASPL,NUMVAR,NQ = ',A4,2I8)
            CALL DPWRST('XXX','BUG ')
            IF(NLOCAL.GE.1)THEN
              DO 825 I=1,NLOCAL
                WRITE(ICOUT,826)I,Y1(I)
  826           FORMAT('I,Y1(I) = ',I8,G15.7)
                CALL DPWRST('XXX','BUG ')
  825         CONTINUE
            ENDIF
          ENDIF
!
          NPLOT1=NPLOTP
          CALL DPPPC2(Y1,XCENS,XLEVEL,NLOCAL,MAXOBV,   &
                      ICASPL,ICASP2,   &
                      SHAP11,SHAP12,SHAP21,SHAP22,   &
                      SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                      YLOWLM,YUPPLM,A,B,MINMAX,   &
                      DISPAR,DISPA2,DISPA3,CORR,NUMSHA,   &
                      XTEMP1,XTEMP2,XTEMP3,XTEMP4,XTEMP5,   &
                      X2TEMP,Y2TEMP,D2TEMP,WEIGHH,WEIGHV,IPPCBW,   &
                      IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                      ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                      IGETDF,ICONDF,IGOMDF,IKATDF,   &
                      IGIGDF,IGEODF,   &
                      IPPCCC,IPPCFO,IPPLDP,KSLOC,KSSCAL,   &
                      IPPCDP,IPPCAP,IPPCAO,IMETHD,ICENSO,IFLAGF,NCURVE,   &
                      PCHSLM,ILEVEL,   &
                      Y,X,X3D,D,NPLOTP,NPLOTV,   &
                      PPCCMX,SHA1MX,SHA2MX,A0SAVE,A1SAVE,A0BWSV,A1BWSV,   &
                      IBUGG3,ISUBRO,IERROR)
          NPLOT2=NPLOTP
!
!               ***************************************
!               **  STEP 8C--                        **
!               **  COMPUTE PROB PLOT STAT           **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
          ISTEPN='8C'
          IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'DPPP')   &
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
          IFLAGU='FILE'
          IFRST=.FALSE.
          ILAST=.FALSE.
          IF(IRESP.EQ.1)IFRST=.TRUE.
          IF(IRESP.EQ.NRESP)ILAST=.TRUE.
          CALL DPPPC4(ICASPL,PPCCMX,SHA1MX,SHA2MX,A0SAVE,A1SAVE,NUMSHA,   &
                      IFLAGU,IFRST,ILAST,   &
                      IBUGG2,IBUGG3,ISUBRO,IERROR)
!
  810   CONTINUE
!
!               ***************************************************
!               **  STEP 9A--                                    **
!               **  CASE 3: ONE OR MORE REPLICATION VARIABLES.   **
!               **          FOR THIS CASE, THE NUMBER OF         **
!               **          VARIABLES MUST BE EXACTLY 1.  BOTH   **
!               **          CENSORING AND GROUPING ARE SUPPORTED.**
!               **          FOR THIS CASE, ALL VARIABLES MUST    **
!               **          HAVE THE SAME LENGTH.                **
!               ***************************************************
!
      ELSEIF(NRESP.EQ.1 .AND. NREPL.GE.1)THEN
        ISTEPN='9A'
        IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'DPPP')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        J=0
        IMAX=NRIGHT(1)
        IF(NQ.LT.NRIGHT(1))IMAX=NQ
        DO 910 I=1,IMAX
          IF(ISUB(I).EQ.0)GO TO 910
          J=J+1
!
!         RESPONSE VARIABLE IN Y1
!
          IJ=MAXN*(ICOLR(1)-1)+I
          IF(ICOLR(1).LE.MAXCOL)Y1(J)=V(IJ)
          IF(ICOLR(1).EQ.MAXCP1)Y1(J)=PRED(I)
          IF(ICOLR(1).EQ.MAXCP2)Y1(J)=RES(I)
          IF(ICOLR(1).EQ.MAXCP3)Y1(J)=YPLOT(I)
          IF(ICOLR(1).EQ.MAXCP4)Y1(J)=XPLOT(I)
          IF(ICOLR(1).EQ.MAXCP5)Y1(J)=X2PLOT(I)
          IF(ICOLR(1).EQ.MAXCP6)Y1(J)=TAGPLO(I)
!
!         CENSORING VARIABLE IN XCENS
!
          ICOLC=1
          IF(ICENSO.EQ.'ON')THEN
            ICOLC=ICOLC+1
            ICOLT=ICOLR(ICOLC)
            IJ=MAXN*(ICOLT-1)+I
            IF(ICOLT.LE.MAXCOL)XCENS(J)=V(IJ)
            IF(ICOLT.EQ.MAXCP1)XCENS(J)=PRED(I)
            IF(ICOLT.EQ.MAXCP2)XCENS(J)=RES(I)
            IF(ICOLT.EQ.MAXCP3)XCENS(J)=YPLOT(I)
            IF(ICOLT.EQ.MAXCP4)XCENS(J)=XPLOT(I)
            IF(ICOLT.EQ.MAXCP5)XCENS(J)=X2PLOT(I)
            IF(ICOLT.EQ.MAXCP6)XCENS(J)=TAGPLO(I)
          ENDIF
!
!         CLASS VARIABLE IN X1 FOR FREQUENCY DATA
!
          IF(NGROUP.GE.1)THEN
            IDATSW='FREQ'
            ICOLC=ICOLC+1
            ICOLT=ICOLR(ICOLC)
            IJ=MAXN*(ICOLT-1)+I
            IF(ICOLT.LE.MAXCOL)XLOW(J)=V(IJ)
            IF(ICOLT.EQ.MAXCP1)XLOW(J)=PRED(I)
            IF(ICOLT.EQ.MAXCP2)XLOW(J)=RES(I)
            IF(ICOLT.EQ.MAXCP3)XLOW(J)=YPLOT(I)
            IF(ICOLT.EQ.MAXCP4)XLOW(J)=XPLOT(I)
            IF(ICOLT.EQ.MAXCP5)XLOW(J)=X2PLOT(I)
            IF(ICOLT.EQ.MAXCP6)XLOW(J)=TAGPLO(I)
          ENDIF
!
!         IF FREQUENCY DATA GIVEN WITH LOWER AND UPPER CLASS LIMITS,
!         THEN UPPER CLASS LIMIT VARIABLE IN XHIGH
!
          IF(NGROUP.EQ.2)THEN
            IDATSW='FRE2'
            ICOLC=ICOLC+1
            ICOLT=ICOLR(ICOLC)
            IJ=MAXN*(ICOLT-1)+I
            IF(ICOLT.LE.MAXCOL)XHIGH(J)=V(IJ)
            IF(ICOLT.EQ.MAXCP1)XHIGH(J)=PRED(I)
            IF(ICOLT.EQ.MAXCP2)XHIGH(J)=RES(I)
            IF(ICOLT.EQ.MAXCP3)XHIGH(J)=YPLOT(I)
            IF(ICOLT.EQ.MAXCP4)XHIGH(J)=XPLOT(I)
            IF(ICOLT.EQ.MAXCP5)XHIGH(J)=X2PLOT(I)
            IF(ICOLT.EQ.MAXCP6)XHIGH(J)=TAGPLO(I)
          ENDIF
!
          DO 920 IR=1,MIN(NREPL,6)
            ICOLC=ICOLC+1
            ICOLT=ICOLR(ICOLC)
            IJ=MAXN*(ICOLT-1)+I
            IF(ICOLT.LE.MAXCOL)XDESGN(J,IR)=V(IJ)
            IF(ICOLT.EQ.MAXCP1)XDESGN(J,IR)=PRED(I)
            IF(ICOLT.EQ.MAXCP2)XDESGN(J,IR)=RES(I)
            IF(ICOLT.EQ.MAXCP3)XDESGN(J,IR)=YPLOT(I)
            IF(ICOLT.EQ.MAXCP4)XDESGN(J,IR)=XPLOT(I)
            IF(ICOLT.EQ.MAXCP5)XDESGN(J,IR)=X2PLOT(I)
            IF(ICOLT.EQ.MAXCP6)XDESGN(J,IR)=TAGPLO(I)
  920     CONTINUE
!
  910   CONTINUE
        NLOCAL=J
!
!       *****************************************************
!       **  STEP 9B--                                      **
!       **  FORM THE VERTICAL AND HORIZONTAL AXIS          **
!       **  VALUES Y(.) AND X(.) FOR THE PLOT.             **
!       **                                                 **
!       **  FOR THIS CASE, WE NEED TO LOOP THROUGH THE     **
!       **  VARIOUS REPLICATIONS.                          **
!       *****************************************************
!
        ISTEPN='9B'
        IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PPCC')THEN
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,931)
  931     FORMAT('***** FROM THE MIDDLE  OF DPPPCC--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,932)ICASPL,NUMVAR,IDATSW,NLOCAL
  932     FORMAT('ICASPL,NUMVAR,IDATSW,NLOCAL = ',   &
                 A4,I8,2X,A4,I8)
          CALL DPWRST('XXX','BUG ')
          IF(NLOCAL.GE.1)THEN
            DO 935 I=1,NLOCAL
              WRITE(ICOUT,936)I,Y1(I),XLOW(I),XHIGH(I),XCENS(I),   &
                              XDESGN(I,1),XDESGN(I,2)
  936         FORMAT('I,Y1(I),XLOW(I),XHIGH(I),XCENS(I),XDESGN(I,1)',   &
                     'XDESGN(I,2) = ',I8,6F12.5)
              CALL DPWRST('XXX','BUG ')
  935       CONTINUE
          ENDIF
        ENDIF
!
!       *****************************************************
!       **  STEP 9C--                                      **
!       **  FIND THE DISTINCT VALUES IN EACH OF THE        **
!       **  REPLICATION VARIABLES.                         **
