            IF(NGROUP.EQ.0 .AND. ICASPL.NE.'CHSQ')THEN
              IF(NTEMP.GT.0)THEN
                CALL DPPPC2(Y1,XCENS,XLEVEL,NLOCAL,MAXOBV,   &
                            ICASPL,ICASP2,   &
                            SHAP11,SHAP12,SHAP21,SHAP22,   &
                            SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                            YLOWLM,YUPPLM,A,B,MINMAX,   &
                            DISPAR,DISPA2,DISPA3,CORR,NUMSHA,   &
                            XTEMP1,XTEMP2,XTEMP3,XTEMP4,XTEMP5,   &
                            X2TEMP,Y2TEMP,D2TEMP,WEIGHH,WEIGHV,IPPCBW,   &
                            IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                            ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                            IGETDF,ICONDF,IGOMDF,IKATDF,   &
                            IGIGDF,IGEODF,   &
                            IPPCCC,IPPCFO,IPPLDP,KSLOC,KSSCAL,   &
                            IPPCDP,IPPCAP,IPPCAO,IMETHD,ICENSO,   &
                            IFLAGF,NCURVE,   &
                            PCHSLM,ILEVEL,   &
                            Y,X,X3D,D,NPLOTP,NPLOTV,   &
                            PPCCMX,SHA1MX,SHA2MX,A0SAVE,A1SAVE,   &
                            A0BWSV,A1BWSV,   &
                            IBUGG3,ISUBRO,IERROR)
              ENDIF
            ELSE
              IF(NTEMP.GT.0)THEN
                CALL DPPPC3(Y1,XCENS,XLOW,XHIGH,NLOCAL,MAXOBV,   &
                            ICASPL,ICASP2,IDATSW,IDIST,   &
                            SHAP11,SHAP12,SHAP21,SHAP22,   &
                            SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                            YLOWLM,YUPPLM,A,B,MINMAX,   &
                            DISPAR,DISPA2,DISPA3,CORR,NUMSHA,   &
                            XTEMP1,XTEMP2,XTEMP3,XTEMP4,XTEMP5,   &
                            X2TEMP,Y2TEMP,D2TEMP,WEIGHH,WEIGHV,IPPCBW,   &
                            IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                            ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                            IGETDF,ICONDF,IGOMDF,IKATDF,   &
                            IGIGDF,IGEODF,   &
                            IPPCCC,IPPCFO,IPPLDP,KSLOC,KSSCAL,   &
                            IPPCDP,IPPCAP,IPPCAO,IMETHD,ICENSO,   &
                            IFLAGF,NCURVE,   &
                            PCHSLM,MINSIZ,IHSTCW,CLWIDT,CLLIMI,   &
                            Y,X,X3D,D,NPLOTP,NPLOTV,   &
                            PPCCMX,SHA1MX,SHA2MX,A0SAVE,A1SAVE,   &
                            IBUGG3,ISUBRO,IERROR)
              ENDIF
            ENDIF
            NPLOT2=NPLOTP
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
            CALL DPPPC4(ICASPL,PPCCMX,SHA1MX,SHA2MX,   &
                        A0SAVE,A1SAVE,NUMSHA,   &
                        IFLAGU,IFRST,ILAST,   &
                        IBUGG2,IBUGG3,ISUBRO,IERROR)
 1660     CONTINUE
 1650     CONTINUE
 1640     CONTINUE
 1630     CONTINUE
 1620     CONTINUE
 1610     CONTINUE
        ENDIF
!
!
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PPCC')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPPCC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR
 9012   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        IF(IFOUND.EQ.'NO')GO TO 9099
        WRITE(ICOUT,9013)NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2
 9013   FORMAT('NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2 = ',   &
               I8,I8,I8,2X,A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9021)NLOCAL,MINMAX
 9021   FORMAT('NLOCAL,MINMAX = ',2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9017)PPCCMX,SHA1MX,SHA2MX
 9017   FORMAT('PPCCMX,SHA1MX,SHA2MX = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
        IF(NLOCAL.GT.0)THEN
          DO 9022 I=1,NLOCAL
            WRITE(ICOUT,9023)I,Y1(I),XCENS(I),XLOW(I),XHIGH(I)
 9023       FORMAT('I,Y1(I),XCENS(I),XLOW(I),XHIGH(I) = ',I8,4F12.5)
            CALL DPWRST('XXX','BUG ')
 9022     CONTINUE
        ENDIF
        IF(NPLOTP.GT.0)THEN
          DO 9032 I=1,NPLOTP
            WRITE(ICOUT,9033)I,Y(I),X(I),D(I)
 9033       FORMAT('I,Y(I),X(I),D(I) = ',I8,3F12.5)
            CALL DPWRST('XXX','BUG ')
 9032     CONTINUE
        ENDIF
      ENDIF
!
 9099 CONTINUE
      RETURN
      END SUBROUTINE DPPPCC
      SUBROUTINE DPPPC2(Y1,XCENS,XLEVEL,N1,MAXNXT,   &
                        ICASPL,ICASP2,   &
                        SHAP11,SHAP12,SHAP21,SHAP22,   &
                        SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                        YLOWLM,YUPPLM,A,B,MINMAX,   &
                        DISPAR,DISPA2,DISPA3,CORRV,NUMSHA,   &
                        XTEMP1,XTEMP2,XTEMP3,XTEMP4,XTEMP5,   &
                        X2TEMP,Y2TEMP,D2TEMP,WEIGHH,WEIGHV,IPPCBW,   &
                        IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                        ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                        IGETDF,ICONDF,IGOMDF,IKATDF,   &
                        IGIGDF,IGEODF,   &
                        IPPCCC,IPPCFO,IPPLDP,KSLOC,KSSCAL,   &
                        IPPCDP,IPPCAP,IPPCAO,IMETHD,ICENSO,   &
                        IFLAGF,NCURVE,   &
                        PCHSLM,ILEVEL,   &
                        Y2,X2,X3D2,D2,N2,NPLOTV,   &
                        PPCCMX,SHA1MX,SHA2MX,A0SAVE,A1SAVE,   &
                        A0BWSV,A1BWSV,   &
                        IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--GENERATE A PAIR OF COORDINATE VECTORS THAT WILL DEFINE
!              THE PROBABILITY PLOT CORRELATION COEFFICIENT TRACE FOR
!              SOME DISTRIBUTIONAL FAMILY.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--FEBRUARY  1981.
!     UPDATED         --JUNE      1981.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MAY       1990.  IG, WALD, RIG, FL (SAUNDERS)
!     UPDATED         --APRIL     1992.  AN TO AN1
!     UPDATED         --DECEMBER  1993.  MINMAX FOR EV1/EV2/WEIB DIST.
!     UPDATED         --MAY       1993.  EXTREME VALUE (GENERAL)
!     UPDATED         --MAY       1993.  GENERALIZED PARETO
!     UPDATED         --APRIL     1995.  NEW DISTRIBUTIONS
!     UPDATED         --OCTOBER   1995.  LOG GAMMA DISTRIBUTION
!     UPDATED         --OCTOBER   1995.  5 DISTRIBUTIONS
!     UPDATED         --DECEMBER  1995.  GENERALIZED LOGISTIC
!     UPDATED         --JANUARY   1996.  DOUBLE GAMMA
!     UPDATED         --FEBRUARY  1996.  BRADFORD
!     UPDATED         --MAY       1996.  RECIPROCAL
!     UPDATED         --JANUARY   1998.  BINOMIAL
!     UPDATED         --JANUARY   1998.  NEGATIVE BINOMIAL
!     UPDATED         --JANUARY   1998.  LOGARITHMIC SERIES
!     UPDATED         --FEBRUARY  1998.  CHECK FOR 0 COUNT FREQUENCIES
!                                        FOR BINNED DATA
!     UPDATED         --AUGUST    2001.  SUPPORT FOR A NUMBER OF
!                                        2 SHAPE PARAMETER
!                                        DISTRIBUTIONS.
!     UPDATED         --SEPTEMBER 2001.  SUPPORT FOR 4 ADDITIONAL
!                                        DISTRIBUTIONS
!     UPDATED         --NOVEMBER  2001.  GEE DISTRIBUTION
!     UPDATED         --NOVEMBER  2001.  ALPHA DISTRIBUTION
!     UPDATED         --NOVEMBER  2001.  POWER LOGNORMAL SUPPORT
!                                        2 SHAPE PARAMETERS
!     UPDATED         --MAY       2003.  ERROR (=SUBBOTIN=EXPO POWER)
!     UPDATED         --NOVEMBER  2003.  FOLDED T
!     UPDATED         --DECEMBER  2003.  SKEW NORMAL, SKEW T,
!                                        INVERTED BETA,
!                                        G-AND-H
!     UPDATED         --MARCH     2004.  LOG SKEW NORMAL,
!                                        NON-CENTRAL T
!                                        NON-CENTRAL CHI-SQUARE
!     UPDATED         --MARCH     2004.  FOR 2 SHAPE PARAMETER CASE,
!                                        WRITE COORDINATES TO FILE
!     UPDATED         --APRIL     2004.  HERMITE
!     UPDATED         --MAY       2004.  SUPPORT DIFFERENT CORRELATION
!                                        MEASURES
!     UPDATED         --MAY       2004.  SUPPORT FOR KS PLOT
!     UPDATED         --MAY       2004.  SUPPORT FOR GENERATING 2-SHAPE
!                                        PARAMETER CASE AS MULTI-TRACE
!                                        PLOT
!     UPDATED         --JUNE      2004.  SKEW DOUBLE EXPONENTIAL
!     UPDATED         --JUNE      2004.  ASYMMETRIC DOUBLE EXPONENTIAL
!     UPDATED         --JUNE      2004.  MAXWELL
!     UPDATED         --JULY      2004.  GOMPERTZ-MAKEHAM
!     UPDATED         --AUGUST    2004.  GENERALIZED ASYMMETRIC
!                                        DOUBLE EXPONENTIAL
!     UPDATED         --AUGUST    2004.  MCLEISH
!     UPDATED         --SEPTEMBER 2004. GENERALIZED MCLEISH
!     UPDATED         --SEPTEMBER 2004. HYPERBOLIC (NOT WORKING YET)
!     UPDATED         --SEPTEMBER 2004. SUPPORT FOR FOLLOWING OPTIONS:
!                                       1) SET PPCC PLOT DATA POINTS
!                                       2) SET PPCC PLOT AXIS POINTS
!                                       3) SET PPCC PLOT AXIS ORDER
!     UPDATED         --OCTOBER   2004. MODIFY HOW "ALOC"
!                                       PARAMETER HANDLED
!                                       FOR PARETO DISTRIBUTION
!     UPDATED         --OCTOBER   2004. WRITE LOCATION AND SCALE
!                                       PARAMETERS TO FILE
!     UPDATED         --OCTOBER   2004. FOR BINNED CASE, USE CHI-SQUARE
!                                       RATHER THAN K-S TEST
!     UPDATED         --OCTOBER   2004. FOR UNBINNED DATA, SUPPORT
!                                       CENSORING
!     UPDATED         --OCTOBER   2004. WRITE : PPCC, LOC, SCALE,
!                                               SHAPE1, SHAPE2 TO
!                                               DPST2F.DAT
!     UPDATED         --DECEMBER  2004. IF USER HAS NOT SET KSLOC
!                                       AND KSSCAL, SET THEM TO 0 AND
!                                       1 FOR PARETO DISTRIBUTIONS
!     UPDATED         --APRIL     2005. FOR ONE SHAPE PARAMETER CASE,
!                                       ADD SUPPORT FOR REPLICATION
!                                       CASE (GROUPS, AS OPPOSSED TO
!                                       BINS, IN THE DATA)
!     UPDATED         --APRIL     2005. FOR BINNED DATA, SUPPORT CASE
!                                       WHERE BINS GIVEN AS LOWER AND
!                                       UPPER LIMITS (INSTEAD OF
!                                       JUST THE MID-POINT).  THIS
!                                       ALLOWS UNEQUALLY SPACED BINS.
!     UPDATED         --JULY      2005. CALL LIST TO LGAPPF AND SNPPF
!                                       CALL LIST TO DP1KS2
!                                       CALL LIST TO DPCHS2
!     UPDATED         --FEBRUARY  2006. GENERALIZED LOGISTIC TYPE 5
!     UPDATED         --FEBRUARY  2006. FMKL PARAMETERIZATION OF
!                                       GENERALIZED TUKEY LAMBDA
!     UPDATED         --MARCH     2006. SUPPORT FOR DIFFERENT DEFAULT
!                                       BINNING ALGORITHMS
!     UPDATED         --MARCH     2006. BETA NORMAL
!     UPDATED         --MARCH     2006. GENERALIZED LOGISTIC TYPE 2
!     UPDATED         --MARCH     2006. GENERALIZED LOGISTIC TYPE 3
!     UPDATED         --MARCH     2006. GENERALIZED LOGISTIC TYPE 4
!     UPDATED         --MARCH     2006. ASYMMETRIC LOG LAPLACE
!     UPDATED         --MAY       2006. FOR KS PLOT, ALLOW BIWEIGHT
!                                       ADJUSTMENT FOR LOCATION AND
!                                       SCALE PARAMETERS.
!     UPDATED         --MAY       2006. BETA-GEOMETRIC
!     UPDATED         --MAY       2006. ZETA, ZIPF
!     UPDATED         --MAY       2006. BOREL-TANNER
!     UPDATED         --JUNE      2006. LAGRANGE-POISSON
!     UPDATED         --JUNE      2006. LOG BETA
!     UPDATED         --JUNE      2006. POLYA-AEPPLI
!     UPDATED         --JUNE      2006. LOST GAMES
!     UPDATED         --JUNE      2006. GENERALIZED LOGARITHMIC SERIES
!     UPDATED         --JULY      2006. GEETA
!     UPDATED         --JULY      2006. QUASI BINOMIAL TYPE 1
!     UPDATED         --AUGUST    2006. CONSUL
!     UPDATED         --NOVEMBER  2006. DISCRETE WEIBULL
!     UPDATED         --NOVEMBER  2006. GENERALIZED LOST GAMES
!     UPDATED         --JANUARY   2007. KATZ
!     UPDATED         --FEBRUARY  2007. TOPP AND LEONE
!     UPDATED         --FEBRUARY  2007. TRAPEZOID
!     UPDATED         --FEBRUARY  2007. GENERALIZED TOPP AND LEONE
!     UPDATED         --FEBRUARY  2007. REFLECTED GENERALIZED
!                                       TOPP AND LEONE
!     UPDATED         --MARCH     2007. SPECIFY LOWER/UPPER LIMITS
!                                       FOR TRIANGULAR DISTRIBUTION
!     UPDATED         --JUNE      2007. SPECIFY LOWER/UPPER LIMITS
!                                       FOR TWO-SIDED POWER DISTRIBUTION
!     UPDATED         --AUGUST    2007. EXTRACT FREQUENCY CASE TO A
!                                       SEPARATE ROUTINE (DPPPC3)
!     UPDATED         --SEPTEMBER 2007. SLOPE
!     UPDATED         --SEPTEMBER 2007. TWO-SIDED SLOPE
!     UPDATED         --SEPTEMBER 2007. OGIVE
!     UPDATED         --SEPTEMBER 2007. TWO-SIDED OGIVE
!     UPDATED         --OCTOBER   2007. BURR TYPE 2
!     UPDATED         --OCTOBER   2007. BURR TYPE 3
!     UPDATED         --OCTOBER   2007. BURR TYPE 4
!     UPDATED         --OCTOBER   2007. BURR TYPE 5
!     UPDATED         --OCTOBER   2007. BURR TYPE 6
!     UPDATED         --OCTOBER   2007. BURR TYPE 7
!     UPDATED         --OCTOBER   2007. BURR TYPE 8
!     UPDATED         --OCTOBER   2007. BURR TYPE 9
!     UPDATED         --OCTOBER   2007. BURR TYPE 10
!     UPDATED         --OCTOBER   2007. BURR TYPE 12
!     UPDATED         --OCTOBER   2007. DOUBLY-PARETO UNIFORM
!     UPDATED         --OCTOBER   2007. KUMARASWAMY
!     UPDATED         --DECEMBER  2007. REFLECTED POWER
!     UPDATED         --JANUARY   2008. MUTH
!     UPDATED         --FEBRUARY  2008. LOGISTIC-EXPONENTIAL
!     UPDATED         --FEBRUARY  2008. SIGMA PARAMETER FOR
!                                       MAXWELL REALLY A SCALE
!                                       PARAMETER, SO REMOVE
!     UPDATED         --MARCH     2008. TRUNCATED PARETO
!     UPDATED         --MARCH     2008. 3-PARAMETER LOGISTIC-EXPONENTIAL
!     UPDATED         --MAY       2008. PEARSON TYPE 3
!     UPDATED         --MAY       2008. KAPPA
!     UPDATED         --MAY       2008. MIELKE'S BETA-KAPPA
!     UPDATED         --JULY      2008. 2-SHAPE PARAMERER GENERALIZED
!                                       INVERSE GAUSSIAN
!     UPDATED         --DECEMBER  2008. TRUNCATED NORMAL (ASSUME
!                                       TRUNCATION POINTS KNOWN)
!     UPDATED         --OCTOBER   2009. CALL "DPPP2" TO GENERATE
!                                       UNDERLYING PROBABILITY PLOT
!     UPDATED         --OCTOBER   2009. GENERALIZE GOODNESS OF FIT
!                                       STATISTIC THAT WILL BE USED
!     UPDATED         --OCTOBER   2009. HANDLING OF REPLICATION MOVED
!                                       TO CALLING ROUTINE (DPPPCC)
!     UPDATED         --OCTOBER   2009. REMOVE OPTION FOR ROBUST
!                                       ESTIMATES FOR CORRELATION
!                                       COEFFICIENT (E.G., BIWEIGHT
!                                       MID-CORRELATION).  THESE
!                                       TEND TO RESULT IN A "FLAT"
!                                       PPCC PLOT THAT DOES NOT
!                                       DISTINGUISH BETWEEN VALUES OF
!                                       THE SHAPE PARAMETER.
!     UPDATED         --OCTOBER   2009. MAKE OUTPUT TO "dpst1f.dat" AND
!                                       "dpst2f.dat" OPTIONAL (TO
!                                       FACILITATE USE OF DPPPC2 BY
!                                       ROUTINES OTHER THAN DPPPCC)
!     UPDATED         --SEPTEMBER 2010. SUPPORT A "LEVEL" VARIABLE
!                                       FOR BRITTLE FIBER WEIBULL
!                                       (MAY ADD TO A FEW OTHERS AT
!                                       A LATER TIME).  NOTE THAT THIS
!                                       IS CURRENTLY ONLY SUPPORTED
!                                       FOR THE SINGLE RESPONSE
!                                       VARIABLE RAW DATA CASE
!     UPDATED         --JULY      2019. CALL LIST TO DPPP2
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICASP2
      CHARACTER*4 IPPCCC
      CHARACTER*4 IPPCFO
      CHARACTER*4 IPPCAO
      CHARACTER*4 IADEDF
      CHARACTER*4 IGEPDF
      CHARACTER*4 IMAKDF
      CHARACTER*4 IBEIDF
      CHARACTER*4 ILGADF
      CHARACTER*4 ISKNDF
      CHARACTER*4 IGLDDF
      CHARACTER*4 IBGEDF
      CHARACTER*4 IGETDF
      CHARACTER*4 ICONDF
      CHARACTER*4 IGOMDF
      CHARACTER*4 IKATDF
      CHARACTER*4 IGIGDF
      CHARACTER*4 IGEODF
      CHARACTER*4 IGIGSV
      CHARACTER*4 IMETHD
      CHARACTER*4 ICENSO
      CHARACTER*4 ILEVEL
      CHARACTER*4 IFLAGF
      CHARACTER*4 IWRITE
      CHARACTER*4 IDATSW
      CHARACTER*4 IDIR
      CHARACTER*4 IPPCBW
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 IDISFL
      CHARACTER*4 IFOUND
      CHARACTER*4 IOP
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOF2.INC'
!
!---------------------------------------------------------------------
!
      INTEGER IPPCDP
      INTEGER IPPCAP(2)
!
      DIMENSION Y1(*)
      DIMENSION XCENS(*)
      DIMENSION XLEVEL(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION X3D2(*)
      DIMENSION D2(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION XTEMP3(*)
      DIMENSION XTEMP4(*)
      DIMENSION XTEMP5(*)
      DIMENSION X2TEMP(*)
      DIMENSION Y2TEMP(*)
      DIMENSION D2TEMP(*)
      DIMENSION WEIGHH(*)
      DIMENSION WEIGHV(*)
!
      DIMENSION DISPAR(*)
      DIMENSION DISPA2(*)
      DIMENSION DISPA3(*)
      DIMENSION CORRV(*)
!
      REAL KSLOC
      REAL KSSCAL
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!CCCC DATA PI / 3.1415926535 /
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPPP'
      ISUBN2='C2  '
      IWRITE='OFF'
      IERROR='NO'
      IGIGSV=IGIGDF
!
      IF(ICASP2.EQ.'PARE' .OR. ICASP2.EQ.'PAR2')THEN
        IF(KSLOC.EQ.CPUMIN .AND.  KSSCAL.EQ.CPUMIN)THEN
          KSLOC=0.0
          KSSCAL=1.0
        ENDIF
      ENDIF
      AN1=0.0
!
      NHOR1=IPPCAP(1)
      NHOR2=IPPCAP(2)
!
!     DISTINGUISH DISCRETE DISTRIBUTIONS
!
      CALL EXTDST(ICASPL,IDISFL,ILOWLM,   &
                  SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                  SHAPE5,SHAPE6,SHAPE7,   &
                  IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                  ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                  IGETDF,ICONDF,IGOMDF,IKATDF,   &
                  IGIGDF,IGEODF)
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PPC2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,11)
   11   FORMAT('***** AT THE BEGINNING OF DPPPC2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,12)ICASPL,ICASP2,ILEVEL,IPPCCC,N1,NPLOTV
   12   FORMAT('ICASPL,ICASP2,ILEVEL,IPPCCC,N1,NPLOTV = ',4(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,13)SHAP11,SHAP12,SHAP21,SHAP22,PCHSLM
   13   FORMAT('SHAP11,SHAP12,SHAP21,SHAP22,PCHSLM = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,14)MINMAX,IPPCDP,IPPLDP,KSLOC,KSSCAL
   14   FORMAT('MINMAX,IPPCDP,IPPLDP,KSLOC,KSSCAL = ',3I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
        IF(N1.GT.0)THEN
          DO 25 I=1,MIN(N1,200)
            WRITE(ICOUT,26)I,Y1(I),XCENS(I),XLEVEL(I)
   26       FORMAT('I,Y1(I),XCENS(I),XLEVEL(I) = ',I8,4G12.5)
            CALL DPWRST('XXX','BUG ')
   25     CONTINUE
        ENDIF
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N1.LE.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)
   46   FORMAT('***** ERROR IN PPCC PLOT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)
   47   FORMAT('      THE NUMBER OF OBSERVATIONS IS LESS THAN OR ',   &
               'EQUAL TO 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)N1
   48   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=Y1(1)
      DO 60 I=1,N1
        IF(Y1(I).NE.HOLD)GO TO 69
   60 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,62)
   62 FORMAT('      ALL INPUT RESPONSE VARIABLE ELEMENTS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,63)HOLD
   63 FORMAT('      ARE IDENTICALLY EQUAL TO ',G15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
   69 CONTINUE
!
!     CURRENTLY, CENSORING NOT SUPPORTED FOR KS, ANDERSON-DARLING,
!     AIC, CHI-SQUARE, ETC., GOODNESS OF FIT CASES.  SO FOR NOW,
!     TREAT THIS COMBINATION AS AN ERROR.
!
      IF(ICENSO.EQ.'ON' .AND. ICASPL.NE.'PPCC')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)
        CALL DPWRST('XXX','BUG ')
        IF(ICASPL.EQ.'KS  ')THEN
          WRITE(ICOUT,72)
   72     FORMAT('      CURRENTLY, THE KOLMOGOROV-SMIRNOV GOODNESS OF ',   &
                 'FIT STATISTIC')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICASPL.EQ.'AD  ')THEN
          WRITE(ICOUT,73)
   73     FORMAT('      CURRENTLY, THE ANDERSON-DARLING GOODNESS OF ',   &
                 'FIT STATISTIC')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICASPL.EQ.'CHSQ')THEN
          WRITE(ICOUT,74)
   74     FORMAT('      CURRENTLY, THE CHI-SQUARE GOODNESS OF ',   &
                 'FIT STATISTIC')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICASPL.EQ.'AIC ')THEN
          WRITE(ICOUT,75)
   75     FORMAT('      CURRENTLY, THE AIC GOODNESS OF ',   &
                 'FIT STATISTIC')
          CALL DPWRST('XXX','BUG ')
        ENDIF
        WRITE(ICOUT,79)
   79   FORMAT('      IS NOT SUPPORTED FOR THE CENSORED CASE.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 1B-                              **
!               **  IF SET PPCC DATA POINTS COMMAND WAS   **
!               **  ENTERED, THIN DATA SET BY COMPUTING   **
!               **  PERCENTILES OF THE DATA.  CURRENTLY   **
!               **  ONLY SUPPORTED FOR UNBINNED AND       **
!               **  UNCENSORED DATA.                      **
!               ********************************************
!
      IF(IPPCDP.GT.0 .AND. ICENSO.EQ.'OFF' .AND. ILEVEL.EQ.'OFF')THEN
        NPERC=MAX(20,IPPCDP)
        NPERC=MIN(NPERC,N1)
        ASTRT=0.0
        ASTOP=100.0
        AINC=(ASTOP - ASTRT)/REAL(NPERC+1)
        CALL SORT(Y1,N1,Y1)
        AN=REAL(N1)
        DO 100 I=1,NPERC
          P100=(ASTRT + REAL(I)*AINC)/100.0
          ANI=P100*(AN+1.0)
          NI=INT(ANI)
          A2NI=REAL(NI)
          REM=ANI-A2NI
          NIP1=NI+1
          IF(NI.LE.1)NI=1
          IF(NI.GE.N1)NI=N1
          IF(NIP1.LE.1)NIP1=1
          IF(NIP1.GE.N1)NIP1=N1
          XPERC=(1.0-REM)*Y1(NI)+REM*Y1(NIP1)
          XTEMP1(I)=XPERC
  100   CONTINUE
        N1=NPERC
        DO 110 I=1,N1
          Y1(I)=XTEMP1(I)
  110   CONTINUE
!
        IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PPC2')THEN
          WRITE(ICOUT,113)IPPCDP,NPERC,N1
  113     FORMAT('      IPPCDP, NPER, N1 = ',3I8)
          CALL DPWRST('XXX','BUG ')
          DO 117 I=1,N1
            WRITE(ICOUT,118)I,Y1(I)
  118       FORMAT('      I, Y1(I) = ',I8,G15.7)
            CALL DPWRST('XXX','BUG ')
  117     CONTINUE
        ENDIF
      ENDIF
!
!               *******************************************************
!               **  STEP 2--                                         **
!               **  DETERMINE MIN AND MAX OF DATA, CHECK CENSORING   **
!               **  VARIABLES, OPEN DPST1F.DAT AND DPST2F.DAT FILES. **
!               *******************************************************
!
      IF(ICENSO.EQ.'ON')THEN
        CALL DISTIN(XCENS,N1,IWRITE,XTEMP1,NDIST,IBUGG3,IERROR)
        IF(NDIST.EQ.1)THEN
          DO 201 I=1,N1
            XCENS(I)=1.0
  201     CONTINUE
        ELSEIF(NDIST.EQ.2)THEN
          IF(XTEMP1(1).EQ.1.0 .OR. XTEMP1(2).EQ.1.0)THEN
            DO 203 I=1,N1
              IF(XCENS(I).NE.1.0)XCENS(I)=0.0
  203       CONTINUE
          ELSE
            ATEMP1=MIN(XTEMP1(1),XTEMP1(2))
            ATEMP2=MAX(XTEMP1(1),XTEMP1(2))
            DO 208 I=1,N1
              IF(XCENS(I).EQ.ATEMP1)XCENS(I)=1.0
              IF(XCENS(I).EQ.ATEMP2)XCENS(I)=0.0
  208       CONTINUE
          ENDIF
        ELSE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,215)
  215     FORMAT('      FOR CENSORED DATA, THE CENSORING VARIABLE')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,216)
  216     FORMAT('      SHOULD CONTAIN AT MOST TWO DISTINCT VALUES.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,217)NDIST
  217     FORMAT('      ',I8,' DISTINCT VALUES FOUND.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        CALL SORTC(Y1,XCENS,N1,XTEMP1,XCENS)
        IF(ILEVEL.EQ.'YES')THEN
          CALL SORTC(Y1,XLEVEL,N1,XTEMP1,XLEVEL)
        ENDIF
        DO 220 I=1,N1
          Y1(I)=XTEMP1(I)
  220   CONTINUE
        XMIN=Y1(1)
        XMAX=Y1(N1)
      ELSE
        IF(ILEVEL.EQ.'YES')THEN
          CALL SORTC(Y1,XLEVEL,N1,XTEMP1,XLEVEL)
          DO 222 I=1,N1
            Y1(I)=XTEMP1(I)
  222     CONTINUE
        ELSE
          CALL SORT(Y1,N1,Y1)
        ENDIF
        XMIN=Y1(1)
        XMAX=Y1(N1)
      ENDIF
!
      IF(MOD(N1,2).EQ.1)THEN
        XMED=Y1((N1/2)+1)
      ELSE
        XMED=(Y1(N1/2)+Y1((N1/2)+1))/2.0
      ENDIF
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPC2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,221)XMIN,XMAX,XMED
  221   FORMAT('XMIN,XMAX,XMED = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 223 I=1,N1
          WRITE(ICOUT,224)I,Y1(I),XCENS(I),XLEVEL(I)
  224     FORMAT('I,Y1(I),XCENS(I),XLEVEL(I)=',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
  223   CONTINUE
      ENDIF
!
      IF(IFLAGF.EQ.'ON')THEN
        IOP='OPEN'
        IFLAG1=0
        IFLAG2=1
        IFLAG3=1
        IFLAG4=0
        IFLAG5=0
        CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                    IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                    IBUGG3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               *******************************************************
!               **  STEP 3--                                         **
!               **  BRANCH TO THE APPROPRIATE DISTRIBUTIONAL FAMILY  **
!               **  AND DETERMINE THE SET OF PARAMETER VALUES        **
!               **  TO BE USED FOR THE PROBABILITY PLOTS             **
!               *******************************************************
!
      CALL DPPPC7(ICASPL,ICASP2,IPPCAP,   &
                  SHAP11,SHAP12,SHAP21,SHAP22,   &
                  SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                  XMIN,XMAX,A,B,   &
                  DISPAR,DISPA2,NUMDIS,NUMSHA,   &
                  IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                  ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,   &
                  ICONDF,IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                  IBUGG3,ISUBRO,IERROR)
!
!               **************************************
!               **  STEP 4--                        **
!               **  DETERMINE PLOT COORDINATES      **
!               **************************************
!
!
!     FOR TRIANGULAR DISTRIBUTION, ADJUST LIMITS BASED ON
!     MIN/MAX OF DATA IF NEEDED.
!
      IF(ICASPL.EQ.'TRIA' .AND. ICASP2.NE.'PPCC')THEN
        IF(DISPAR(1).LT.XMIN .OR. DISPAR(NUMDIS).GT.XMAX)THEN
          NUMDIS=50
          IF(NHOR1.GT.0)NUMDIS=NHOR1
          AINC=(XMAX-XMIN)/REAL(NUMDIS+1)
          ANUMDI=NUMDIS
          A=XMIN
          B=XMAX
          SHAPE1=XMIN + AINC
          SHAPE2=XMAX - AINC
          DO 411 IDIS=1,NUMDIS
            AIDIS=IDIS
            DISPAR(IDIS)=SHAP11 +   &
                         ((AIDIS-1.0)/(ANUMDI-1.0))*(SHAP12-SHAP11)
  411     CONTINUE
        ENDIF
      ENDIF
!
      IDIR='MAXI'
      IF(ICASPL.EQ.'KS  ')IDIR='MINI'
      IF(ICASPL.EQ.'AD  ')IDIR='MINI'
      IF(ICASPL.EQ.'CHSQ')IDIR='MINI'
      IF(ICASPL.EQ.'AIC ')IDIR='AMIN'
      SHA1MX=CPUMIN
      SHA1MX=CPUMIN
      IF(IDIR.EQ.'MAXI')THEN
        PPCCMX=CPUMIN
      ELSE
        PPCCMX=CPUMAX
      ENDIF
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPC2')THEN
        WRITE(ICOUT,420)
  420   FORMAT('****** AFTER CALL DPPPC7')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,421)SHAP11,SHAP12,SHAP21,SHAP22
  421   FORMAT('SHAP11,SHAP12,SHAP21,SHAP22 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,422)A,B,YLOWLM,YUPPLM,NUMDIS
  422   FORMAT('A,B,YLOWLM,YUPPLM,NUMDIS = ',4G15.7,I8)
        CALL DPWRST('XXX','BUG ')
        DO 425 I=1,NUMDIS
          WRITE(ICOUT,427)I,DISPAR(I),DISPA2(I)
  427     FORMAT('I,DISPAR(I),DISPA2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
  425   CONTINUE
      ENDIF
!
!     NOTE: FOR PPCC PLOT, WE NEED TO GENERATE AN UNDERLYING
!           PROBABILITY PLOT TO ESTIMATE PPCC VALUE.
!
!           FOR THE OTHER GOODNESS OF FIT MEASURES, WE GENERATE THE
!           PROBABILITY PLOT TO ESTIMATE LOCATION/SCALE.  IF USER HAS
!           DEFINED "KSLOC" AND "KSSCAL", THEN WE SKIP THIS STEP.
!           WE ALSO SKIP FOR DISCRETE DISTRIBUTIONS SINCE WE DO
!           NOT DEFINE LOCATION/SCALE FOR THESE.
!
      IF(ICASPL.EQ.'PPCC')THEN
        IPPFLG=1
      ELSE
        IPPFLG=0
        IF(KSLOC.EQ.CPUMIN .OR. KSSCAL.EQ.CPUMIN)IPPFLG=1
!CCCC   IF(IFLAG.EQ.1)IPPFLG=0
      ENDIF
!
      IFLAG2=0
      IF(NUMSHA.EQ.2)THEN
        CALL DISTIN(DISPAR,NUMDIS,IWRITE,XTEMP1,N1SHAP,IBUGG3,IERROR)
        CALL DISTIN(DISPA2,NUMDIS,IWRITE,XTEMP1,N2SHAP,IBUGG3,IERROR)
        IF(N1SHAP.EQ.1)IFLAG2=2
        IF(N2SHAP.EQ.1)IFLAG2=1
      ELSE
        N1SHAP=-99
        N2SHAP=-99
      ENDIF
!
      IF(NCURVE.EQ.1)THEN
        ICNTPT=0
      ELSE
        ICNTPT=N2
      ENDIF
      AHOLD=CPUMIN
      ATAG=0.0
!
      DO 1105 IDIS=1,NUMDIS
!
        ICNT=0
        SHAPE1=DISPAR(IDIS)
        IF(NUMSHA.GT.1)THEN
          SHAPE2=DISPA2(IDIS)
        ELSE
          IF(SHAPE2.EQ.CPUMIN)SHAPE2=-999999.0
        ENDIF
!
        IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPC2')THEN
          WRITE(ICOUT,1107)IDIS,N1,SHAPE1,SHAPE2
 1107     FORMAT('IDIS,N1,SHAPE1,SHAPE2 = ',2I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        CALL DPPPC8(ICASPL,ICASP2,   &
                    SHAP11,SHAP12,SHAP21,SHAP22,   &
                    SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                    YLOWLM,YUPPLM,A,B,MINMAX,   &
                    IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                    ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                    IGETDF,ICONDF,IGOMDF,IKATDF,   &
                    IGIGDF,IGEODF,   &
                    AMIN,AMAX,   &
                    IBUGG3,ISUBRO,IERROR)
!
!       GENERATE UNDERLYING PROBABILITY PLOT:
!
!       1) FOR PPCC METHOD, THIS IS USED TO OBTAIN PPCC VALUE
!          (ONLY INTERESTED IN LOCATION/SCALE FOR MAXIMUM PPCC VALUE)
!
!       2) FOR NON-PPCC METHOD, THIS IS USED TO OBTAIN THE
!          LOCATION/SCALE ESTIMATES (AND WE DON'T CARE ABOUT THE
!          PPCC VALUE)
!
        IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPC2')THEN
          WRITE(ICOUT,520)
  520     FORMAT('****** BEFORE CALL DPPP2')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,521)IPPFLG,ICASP2,AMIN,AMAX,N1
  521     FORMAT('IPPFLG,ICASP2,AMIN,AMAX,N1 = ',I5,2X,A4,2X,2G15.7,I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,522)SHAPE1,SHAPE2
  522     FORMAT('SHAPE1,SHAPE2 = ',2G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(IPPFLG.EQ.1)THEN
          NCURVT=1
          NHIGH=0
          N2TEMP=0
          PPLOC=0.0
          PPSCAL=1.0
          CALL DPPP2(Y1,XCENS,XLEVEL,N1,ICASP2,NHIGH,   &
                     XTEMP1,XTEMP2,XTEMP3,   &
                     YLOWLM,YUPPLM,A,B,MINMAX,   &
                     SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                     SHAPE5,SHAPE6,SHAPE7,   &
                     IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                     ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                     IGETDF,ICONDF,IGOMDF,IKATDF,   &
                     IGIGDF,IGEODF,   &
                     IPPLDP,MAXNXT,ICENSO,IMETHD,ILEVEL,   &
                     PPLOC,PPSCAL,   &
                     PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                     CCALBE,PPA0BW,PPA1BW,   &
                     WEIGHH,WEIGHV,   &
                     Y2TEMP,X2TEMP,D2TEMP,N2TEMP,NPLOTV,NCURVT,   &
                     IBUGG3,ISUBRO,IERROR)
!
          CORRV(IDIS)=PPCC
          A0TEMP=PPA0
          A1TEMP=PPA1
          IF(IPPCBW.EQ.'BIWE')THEN
            A0TEMP=PPA0BW
            A1TEMP=PPA1BW
          ENDIF
!
          IF(ICASPL.EQ.'PPCC' .AND. CORRV(IDIS).GT.PPCCMX)THEN
            A0SAVE=PPA0
            A1SAVE=PPA1
            A0BWSV=PPA0BW
            A1BWSV=PPA1BW
            PPCCMX=CORRV(IDIS)
            SHA1MX=DISPAR(IDIS)
            SHA2MX=DISPA2(IDIS)
          ENDIF
!
          IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPC2')THEN
             WRITE(ICOUT,530)
  530        FORMAT('****** AFTER CALL DPPP2')
             CALL DPWRST('XXX','BUG ')
             WRITE(ICOUT,531)N1,N2TEMP
  531        FORMAT('N1,N2TEMP = ',2I8)
             CALL DPWRST('XXX','BUG ')
             WRITE(ICOUT,532)PPA0,PPA1,PPCC,PPA0BW,PPA1BW
  532        FORMAT('PPA0,PPA1,PPCC,PPA0BW,PPA1BW = ',5G15.7)
             CALL DPWRST('XXX','BUG ')
             WRITE(ICOUT,533)A0SAVE,A1SAVE,PPCCMX,SHA1MX
  533        FORMAT('A0SAVE,A1SAVE,PPCCMX,SHA1MX = ',4G15.7)
             CALL DPWRST('XXX','BUG ')
          ENDIF
!
        ELSE
          IF(KSLOC.NE.CPUMIN .AND. KSSCAL.NE.CPUMIN)THEN
            A0TEMP=KSLOC
            A1TEMP=KSSCAL
          ELSE
            A0TEMP=0.0
            A1TEMP=1.0
          ENDIF
        ENDIF
!
        IF(ICASPL.NE.'PPCC')THEN
!
          CALL DPPPC6(ICASPL,ICASP2,   &
                      SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                      A0TEMP,A1TEMP,XMIN,XMAX,AMIN,AMAX,XMED,   &
                      IBUGG3,ISUBRO,IERROR)
!
          CALL DPGOF9(Y1,N1,ICASP2,ICASPL,   &
                      XTEMP1,XTEMP2,XTEMP3,N3TEMP,   &
                      YLOWLM,YUPPLM,A,B,MINMAX,   &
                      SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                      SHAPE5,SHAPE6,SHAPE7,   &
                      IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                      ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                      IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                      MAXNXT,   &
                      A0TEMP,A1TEMP,   &
                      STATVA,DM,   &
                      IBUGG3,ISUBRO,IERROR,IERRFL)
!
          IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PPC2')THEN
            WRITE(ICOUT,1740)STATVA,DM
 1740       FORMAT('AFTER CALL DPGOF9: STATVA,DM = ',2G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          CORRV(IDIS)=STATVA
          XTEMP4(IDIS)=A0TEMP
          XTEMP5(IDIS)=A1TEMP
          IF(IDIR.EQ.'MAXI')THEN
            IF(CORRV(IDIS).LT.PPCCMX)THEN
              A0SAVE=A0TEMP
              A1SAVE=A1TEMP
              PPCCMX=CORRV(IDIS)
              SHA1MX=DISPAR(IDIS)
              SHA2MX=DISPA2(IDIS)
            ENDIF
          ELSE
            IF(CORRV(IDIS).LT.PPCCMX)THEN
              A0SAVE=A0TEMP
              A1SAVE=A1TEMP
              PPCCMX=CORRV(IDIS)
              SHA1MX=DISPAR(IDIS)
              SHA2MX=DISPA2(IDIS)
            ENDIF
          ENDIF
!
        ENDIF
!
        IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PPC2')THEN
          WRITE(ICOUT,1830)N1
 1830     FORMAT('AT END OF 1105 LOOP: N1 = ',I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1831)NUMDIS,IDIS,DISPAR(IDIS),DISPA2(IDIS),   &
                           CORRV(IDIS)
 1831     FORMAT('NUMDIS,IDIS,DISPAR(IDIS),DISPA2(IDIS),CORRV(IDIS)=',   &
                 2I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1832)A0SAVE,A1SAVE
 1832     FORMAT('A0SAVE,A1SAVE = ',2G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        XTEMP4(IDIS)=A0SAVE
        XTEMP5(IDIS)=A1SAVE
!
 1105 CONTINUE
!
!     NOW THAT WE HAVE LOOPED OVER ALL VALUES OF THE SHAPE
!     PARAMETER(S), DO THE FOLLOWING:
!
!       1) WRITE RELEVANT INFO TO DPST1F.DAT
!
!       2) GENERATE THE PLOT POINTS (Y2, X2, D2).  NEED TO ACCOUNT
!          FOR REPLICATION CASE.  ALSO, NEED TO DISTINGUISH BETWEEN
!          THE ONE SHAPE PARAMETER AND THE TWO SHAPE PARAMETER
!          CASE.  NOTE THAT DISTRIBUTIONS WITH TWO SHAPE PARAMETERS
!          MAY ONLY HAVE A SINGLE VALUE FOR ONE OF THE SHAPE PARAMETERS.
!          THESE CASES NEED TO BE PLOTTED AS A SINGLE SHAPE PARAMETER
!          CASE.
!
!          ALSO, THE TWO SHAPE PARAMETER CASE MAY BE PLOTTED AS A
!          3D PLOT OR AS A 2D PLOT WHERE EACH VALUE OF THE SECOND
!          SHAPE PARAMETER IS DRAWN AS A SEPARATE TRACE ON THE
!          2D PLOT.
!
      CALL DPPPC9(ICASPL,ICASP2,IOUNI2,ICNTPT,IFLAG2,   &
                  DISPAR,DISPA2,DISPA3,NUMDIS,CORRV,NUMSHA,   &
                  XTEMP4,XTEMP5,X2TEMP,   &
                  IPPCFO,IPPCAO,IFLAGF,NCURVE,   &
                  Y2,X2,X3D2,D2,N2,NPLOTV,   &
                  IBUGG3,ISUBRO,IERROR)
!
      IF(NCURVE.EQ.1 .AND. NUMSHA.EQ.1)THEN
        IDATSW='RAW'
        CALL DPWCPP(XTEMP1,N1,ICASP2,IDATSW,   &
                    CORRV,DISPAR,NUMDIS,   &
                    IBUGG3,ISUBRO,IFOUND,IERROR)
      ENDIF
!
      IF(IFLAGF.EQ.'ON')THEN
        IOP='CLOS'
        CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                    IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                    IBUGG3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IF(ICASPL.EQ.'GIGA')THEN
        IGIGDF=IGIGSV
      ENDIF
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PPC2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPPC2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)N2,A0SAVE,A1SAVE,IERROR
 9012   FORMAT('N2,A0SAVE,A1SAVE,IERROR = ',I8,2X,2G15.7,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)PPCCMX,SHA1MX,SHA2MX
 9015   FORMAT('PPCCMX,SHA1MX,SHA2MX=',3G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,N2
          WRITE(ICOUT,9021)I,Y2(I),X2(I),D2(I)
 9021     FORMAT('I,Y2(I),X2(I),D2(I) = ',I8,2E15.7,F9.2)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPPPC2
      SUBROUTINE DPPPC3(Y1,XCENS,XLOW,XHIGH,N1,MAXNXT,   &
                        ICASPL,ICASP2,IDATSW,IDIST,   &
                        SHAP11,SHAP12,SHAP21,SHAP22,   &
                        SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                        YLOWLM,YUPPLM,A,B,MINMAX,   &
                        DISPAR,DISPA2,DISPA3,CORRV,NUMSHA,   &
                        XTEMP1,XTEMP2,XTEMP3,XTEMP4,XTEMP5,   &
                        X2TEMP,Y2TEMP,D2TEMP,WEIGHH,WEIGHV,IPPCBW,   &
                        IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                        ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                        IGETDF,ICONDF,IGOMDF,IKATDF,   &
                        IGIGDF,IGEODF,   &
                        IPPCCC,IPPCFO,IPPLDP,KSLOC,KSSCAL,   &
                        IPPCDP,IPPCAP,IPPCAO,IMETHD,ICENSO,   &
                        IFLAGF,NCURVE,   &
                        PCHSLM,MINSIZ,IHSTCW,CLWIDT,CLLIMI,   &
                        Y2,X2,X3D2,D2,N2,NPLOTV,   &
                        PPCCMX,SHA1MX,SHA2MX,A0SAVE,A1SAVE,   &
                        IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--GENERATE A PAIR OF COORDINATE VECTORS THAT WILL DEFINE
!              THE PROBABILITY PLOT CORRELATION COEFFICIENT TRACE FOR
!              SOME DISTRIBUTIONAL FAMILY.
!
!              THIS ROUTINE HANDLES THE GROUPED CASE.  NOTE THAT
!              CURRENTLY ONLY THE PPCC AND THE CHI-SQUARE METHODS
!              SUPPORT GROUPED DATA.  HOWEVER, IT IS POSSIBLE THAT
!              THE K-S, ANDERSON-DARLING, AND AIC WILL ADD IT AT
!              A LATER TIME.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/8
!     ORIGINAL VERSION--AUGUST    2007. EXTRACTED FROM DPPPC2
!     UPDATED         --NOVEMBER  2009. RE-WRITTEN IN A SIMILAR
!                                       FASHION AS DPPPC2 TO BE
!                                       MORE MODULARIZED AND TO REDUCE
!                                       CODE DUPLICATION AND TO MAKE
!                                       EASIER TO CALL BY ROUTINES
!                                       OTHER THAN DPPPCC.
!     UPDATED         --JULY      2019. CALL LIST TO DPPP3
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICASP2
      CHARACTER*4 IPPCCC
      CHARACTER*4 IPPCFO
      CHARACTER*4 IPPCAO
      CHARACTER*4 IADEDF
      CHARACTER*4 IGEPDF
      CHARACTER*4 IMAKDF
      CHARACTER*4 IBEIDF
      CHARACTER*4 ILGADF
      CHARACTER*4 ISKNDF
      CHARACTER*4 IGLDDF
      CHARACTER*4 IBGEDF
      CHARACTER*4 IGETDF
      CHARACTER*4 ICONDF
      CHARACTER*4 IGOMDF
      CHARACTER*4 IKATDF
      CHARACTER*4 IGIGDF
      CHARACTER*4 IGEODF
      CHARACTER*4 IGIGSV
      CHARACTER*4 IMETHD
      CHARACTER*4 ICENSO
      CHARACTER*4 IFLAGF
      CHARACTER*4 IWRITE
      CHARACTER*4 IDATSW
      CHARACTER*4 IHSTCW
      CHARACTER*4 IHSTOU
      CHARACTER*4 IDIR
      CHARACTER*4 IPPCBW
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*60 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 IDISFL
      CHARACTER*4 IFOUND
      CHARACTER*4 IOP
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOF2.INC'
!
!---------------------------------------------------------------------
!
      INTEGER IPPCDP
      INTEGER IPPCAP(2)
!
      DIMENSION Y1(*)
      DIMENSION XCENS(*)
      DIMENSION XLOW(*)
      DIMENSION XHIGH(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION X3D2(*)
      DIMENSION D2(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION XTEMP3(*)
      DIMENSION XTEMP4(*)
      DIMENSION XTEMP5(*)
      DIMENSION X2TEMP(*)
      DIMENSION Y2TEMP(*)
      DIMENSION D2TEMP(*)
      DIMENSION WEIGHH(*)
      DIMENSION WEIGHV(*)
!
      DIMENSION DISPAR(*)
      DIMENSION DISPA2(*)
      DIMENSION DISPA3(*)
      DIMENSION CORRV(*)
!
      DIMENSION CLWIDT(*)
      DIMENSION CLLIMI(*)
!
      REAL KSLOC
      REAL KSSCAL
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!CCCC DATA PI / 3.1415926535 /
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPPP'
      ISUBN2='C3  '
      IWRITE='OFF'
      IERROR='NO'
      IGIGSV=IGIGDF
!
      NHOR1=IPPCAP(1)
      NHOR2=IPPCAP(2)
!
      IF(ICASP2.EQ.'PARE' .OR. ICASP2.EQ.'PAR2')THEN
        IF(KSLOC.EQ.CPUMIN .AND.  KSSCAL.EQ.CPUMIN)THEN
          KSLOC=0.0
          KSSCAL=1.0
        ENDIF
      ENDIF
      AN1=0.0
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PPC3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,10)
   10   FORMAT('***** AT THE BEGINNING OF DPPPC3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,11)IDATSW,IPPCCC
   11   FORMAT('IDATSW,IPPCCC = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,12)ICASPL,ICASP2,N1,NPLOTV,MINSIZ
   12   FORMAT('ICASPL,ICASP2,N1,NPLOTV,MINSIZ = ',2(A4,2X),3I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,13)SHAP11,SHAP12,SHAP21,SHAP22
   13   FORMAT('SHAP11,SHAP12,SHAP21,SHAP22 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,14)MINMAX,IPPCDP,IPPLDP,KSLOC,KSSCAL
   14   FORMAT('MINMAX,IPPCDP,IPPLDP,KSLOC,KSSCAL = ',3I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
        IF(N1.GT.0)THEN
          DO 25 I=1,MIN(N1,200)
            WRITE(ICOUT,26)I,Y1(I),XCENS(I),XLOW(I),XHIGH(I)
   26       FORMAT('I,Y1(I),XCENS(I),XLOW(I),XHIGH(I) = ',   &
                   I8,5G12.5)
            CALL DPWRST('XXX','BUG ')
   25     CONTINUE
        ENDIF
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N1.LE.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)
   46   FORMAT('***** ERROR IN PPCC PLOT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)
   47   FORMAT('      THE NUMBER OF OBSERVATIONS IS LESS THAN OR ',   &
               'EQUAL TO 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)N1
   48   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     CURRENTLY, CENSORING NOT SUPPORTED FOR KS, ANDERSON-DARLING,
!     AIC, CHI-SQUARE, ETC., GOODNESS OF FIT CASES.  SO FOR NOW,
!     TREAT THIS COMBINATION AS AN ERROR.
!
      IF(ICENSO.EQ.'ON' .AND. ICASPL.NE.'PPCC')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)
        CALL DPWRST('XXX','BUG ')
        IF(ICASPL.EQ.'KS  ')THEN
          WRITE(ICOUT,52)
   52     FORMAT('      CURRENTLY, THE KOLMOGOROV-SMIRNOV GOODNESS OF ',   &
                 'FIT STATISTIC')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICASPL.EQ.'AD  ')THEN
          WRITE(ICOUT,53)
   53     FORMAT('      CURRENTLY, THE ANDERSON-DARLING GOODNESS OF ',   &
                 'FIT STATISTIC')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICASPL.EQ.'CHSQ')THEN
          WRITE(ICOUT,54)
   54     FORMAT('      CURRENTLY, THE CHI-SQUARE GOODNESS OF ',   &
                 'FIT STATISTIC')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICASPL.EQ.'AIC ')THEN
          WRITE(ICOUT,55)
   55     FORMAT('      CURRENTLY, THE AIC GOODNESS OF ',   &
                 'FIT STATISTIC')
          CALL DPWRST('XXX','BUG ')
        ENDIF
        WRITE(ICOUT,59)
   59   FORMAT('      IS NOT SUPPORTED FOR THE CENSORED CASE.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               *******************************************************
!               **  STEP 3--                                         **
!               **  BRANCH TO THE APPROPRIATE DISTRIBUTIONAL FAMILY  **
!               **  AND DETERMINE THE SET OF PARAMETER VALUES        **
!               **  TO BE USED FOR THE PROBABILITY PLOTS             **
!               *******************************************************
!
      CALL DPPPC7(ICASPL,ICASP2,IPPCAP,   &
                  SHAP11,SHAP12,SHAP21,SHAP22,   &
                  SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                  XMIN,XMAX,A,B,   &
                  DISPAR,DISPA2,NUMDIS,NUMSHA,   &
                  IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                  ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,   &
                  ICONDF,IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!     CALL DPGOFB TO CHECK FOR ERRORS IN BINNING.  CHECK FOR
!     ERRORS IN CENSORING VARIABLE IN THIS ROUTINE.
!
      DO 69 I=1,N1
!
        IF(ICENSO.EQ.'ON' .AND. XCENS(I).LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,66)INT(XCENS(I)-0.01)
   66     FORMAT('      A NEGATIVE NUMBER OF CENSORED VALUES (',I8,   &
                 ') WAS ENCOUTERED FOR ROW ',I8)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ELSE
          IVAL=INT(XCENS(I)+0.5)
          XCENS(I)=REAL(IVAL)
        ENDIF
   69 CONTINUE
!
      IHSTOU='ON'
      CALL DPGOFB(Y1,XLOW,XHIGH,XCENS,N1,   &
                  ICASP2,ICASPL,IDATSW,   &
                  XTEMP1,XTEMP2,XTEMP3,   &
                  YLOWLM,YUPPLM,A,B,MINMAX,   &
                  CLWIDT,CLLIMI,IHSTCW,IHSTOU,MINSIZ,   &
                  SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                  SHAPE5,SHAPE6,SHAPE7,   &
                  IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                  ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                  IGETDF,ICONDF,IGOMDF,IKATDF,   &
                  IGIGDF,IGEODF,   &
                  MAXNXT,NUMSHA,KSLOC,KSSCAL,   &
                  NCELLS,NTOT,IDISFL,ILOWLM,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      IF(N1.LE.1)THEN
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(IDATSW.EQ.'FREQ')THEN
        XDEL=XLOW(2) - XLOW(1)
        XMIN=XLOW(1) - XDEL
        XMAX=XLOW(N1) + XDEL
      ELSEIF(IDATSW.EQ.'FRE2')THEN
        XMIN=XLOW(1)
        XMAX=XHIGH(N1)
      ENDIF
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPC3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,221)XMIN,XMAX
  221   FORMAT('AFTER DPGOFB: XMIN,XMAX = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,222)N1,IDATSW
  222   FORMAT('N1,IDATSW = ',I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IFLAGF.EQ.'ON')THEN
        IOP='OPEN'
        IFLAG1=0
        IFLAG2=1
        IFLAG3=1
        IFLAG4=0
        IFLAG5=0
        CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                    IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                    IBUGG3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
      ENDIF
!
!               **************************************
!               **  STEP 4--                        **
!               **  DETERMINE PLOT COORDINATES      **
!               **************************************
!
!
!     FOR TRIANGULAR DISTRIBUTION, ADJUST LIMITS BASED ON
!     MIN/MAX OF DATA IF NEEDED.
!
      IF(ICASPL.EQ.'TRIA' .AND. ICASP2.NE.'PPCC')THEN
        IF(DISPAR(1).LT.XMIN .OR. DISPAR(NUMDIS).GT.XMAX)THEN
          NUMDIS=50
          IF(NHOR1.GT.0)NUMDIS=NHOR1
          AINC=(XMAX-XMIN)/REAL(NUMDIS+1)
          ANUMDI=NUMDIS
          A=XMIN
          B=XMAX
          SHAPE1=XMIN + AINC
          SHAPE2=XMAX - AINC
          DO 411 IDIS=1,NUMDIS
            AIDIS=IDIS
            DISPAR(IDIS)=SHAP11 +   &
                         ((AIDIS-1.0)/(ANUMDI-1.0))*(SHAP12-SHAP11)
  411     CONTINUE
        ENDIF
      ENDIF
!
      IDIR='MAXI'
      IF(ICASPL.EQ.'KS  ')IDIR='MINI'
      IF(ICASPL.EQ.'AD  ')IDIR='MINI'
      IF(ICASPL.EQ.'CHSQ')IDIR='MINI'
      IF(ICASPL.EQ.'AIC ')IDIR='AMIN'
      SHA1MX=CPUMIN
      SHA1MX=CPUMIN
      IF(IDIR.EQ.'MAXI')THEN
        PPCCMX=CPUMIN
      ELSE
        PPCCMX=CPUMAX
      ENDIF
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPC3')THEN
        WRITE(ICOUT,420)
  420   FORMAT('****** AFTER CALL DPPPC7')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,421)SHAP11,SHAP12,SHAP21,SHAP22
  421   FORMAT('SHAP11,SHAP12,SHAP21,SHAP22 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,422)A,B,YLOWLM,YUPPLM,NUMDIS
  422   FORMAT('A,B,YLOWLM,YUPPLM,NUMDIS = ',4G15.7,I8)
        CALL DPWRST('XXX','BUG ')
        DO 425 I=1,NUMDIS
          WRITE(ICOUT,427)I,DISPAR(I),DISPA2(I)
  427     FORMAT('I,DISPAR(I),DISPA2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
  425   CONTINUE
      ENDIF
!
!     NOTE: FOR PPCC PLOT, WE NEED TO GENERATE AN UNDERLYING
!           PROBABILITY PLOT TO ESTIMATE PPCC VALUE.
!
!           FOR THE OTHER GOODNESS OF FIT MEASURES, WE GENERATE THE
!           PROBABILITY PLOT TO ESTIMATE LOCATION/SCALE.  IF USER HAS
!           DEFINED "KSLOC" AND "KSSCAL", THEN WE SKIP THIS STEP.
!           WE ALSO SKIP FOR DISCRETE DISTRIBUTIONS SINCE WE DO
!           NOT DEFINE LOCATION/SCALE FOR THESE.
!
      IF(ICASPL.EQ.'PPCC')THEN
        IPPFLG=1
      ELSE
        IPPFLG=0
        IF(KSLOC.EQ.CPUMIN .OR. KSSCAL.EQ.CPUMIN)IPPFLG=1
        IF(IDISFL.EQ.'DISC')IPPFLG=0
      ENDIF
!
      IFLAG2=0
      IF(NUMSHA.EQ.2)THEN
        CALL DISTIN(DISPAR,NUMDIS,IWRITE,XTEMP1,N1SHAP,IBUGG3,IERROR)
        CALL DISTIN(DISPA2,NUMDIS,IWRITE,XTEMP1,N2SHAP,IBUGG3,IERROR)
        IF(N1SHAP.EQ.1)IFLAG2=2
        IF(N2SHAP.EQ.1)IFLAG2=1
      ELSE
        N1SHAP=-99
        N2SHAP=-99
      ENDIF
!
      IF(NCURVE.EQ.1)THEN
        ICNTPT=0
      ELSE
        ICNTPT=N2
      ENDIF
      AHOLD=CPUMIN
      ATAG=0.0
!
      DO 1105 IDIS=1,NUMDIS
!
        ICNT=0
        SHAPE1=DISPAR(IDIS)
        IF(NUMSHA.GT.1)THEN
          SHAPE2=DISPA2(IDIS)
        ELSE
          SHAPE2=-999999.0
        ENDIF
!
        IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPC3')THEN
          WRITE(ICOUT,1107)IDIS,N1,IPPFLG,SHAPE1,SHAPE2
 1107     FORMAT('IDIS,N1,IPPFLG,SHAPE1,SHAPE2,IPPFL = ',3I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        CALL DPPPC8(ICASPL,ICASP2,   &
                    SHAP11,SHAP12,SHAP21,SHAP22,   &
                    SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                    YLOWLM,YUPPLM,A,B,MINMAX,   &
                    IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                    ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                    IGETDF,ICONDF,IGOMDF,IKATDF,   &
                    IGIGDF,IGEODF,   &
                    AMIN,AMAX,   &
                    IBUGG3,ISUBRO,IERROR)
!
!       GENERATE UNDERLYING PROBABILITY PLOT:
!
!       1) FOR PPCC METHOD, THIS IS USED TO OBTAIN PPCC VALUE
!          (ONLY INTERESTED IN LOCATION/SCALE FOR MAXIMUM PPCC VALUE)
!
!       2) FOR NON-PPCC METHOD, THIS IS USED TO OBTAIN THE
!          LOCATION/SCALE ESTIMATES (AND WE DON'T CARE ABOUT THE
!          PPCC VALUE)
!
        IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPC3')THEN
          WRITE(ICOUT,520)
  520     FORMAT('****** BEFORE CALL DPPP3/DPGOFA')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,521)IPPFLG,AMIN,AMAX,N1
  521     FORMAT('IPPFLG,AMIN,AMAX,N1 = ',I5,2G15.7,I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,522)SHAPE1,SHAPE2
  522     FORMAT('SHAPE1,SHAPE2 = ',2G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(IPPFLG.EQ.1)THEN
          NCURVT=1
          N2TEMP=0
          PPLOC=0.0
          PPSCAL=1.0
          CALL DPPP3(Y1,XLOW,XHIGH,N1,ICASP2,IDATSW,   &
                     XCENS,XTEMP1,   &
                     XTEMP2,XTEMP3,XTEMP4,   &
                     YLOWLM,YUPPLM,A,B,MINMAX,   &
                     SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                     SHAPE5,SHAPE6,SHAPE7,   &
                     IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                     ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                     IGETDF,ICONDF,IGOMDF,IKATDF,   &
                     IGIGDF,IGEODF,   &
                     IPPLDP,MAXNXT,ICENSO,IMETHD,   &
                     PPLOC,PPSCAL,   &
                     PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                     CCALBE,PPA0BW,PPA1BW,   &
                     WEIGHH,WEIGHV,   &
                     Y2TEMP,X2TEMP,D2TEMP,N2TEMP,NPLOTV,NCURVT,   &
                     IBUGG3,ISUBRO,IERROR)
!
          IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPC3')THEN
             WRITE(ICOUT,530)
  530        FORMAT('****** AFTER CALL DPPP3')
             CALL DPWRST('XXX','BUG ')
             WRITE(ICOUT,531)N1,N2TEMP
  531        FORMAT('N1,N2TEMP = ',2I8)
             CALL DPWRST('XXX','BUG ')
             WRITE(ICOUT,532)PPA0,PPA1,PPCC,PPA0BW,PPA1BW
  532        FORMAT('PPA0,PPA1,PPCC,PPA0BW,PPA1BW = ',5G15.7)
             CALL DPWRST('XXX','BUG ')
          ENDIF
!
          CORRV(IDIS)=PPCC
          A0TEMP=PPA0
          A1TEMP=PPA1
          IF(IPPCBW.EQ.'BIWE')THEN
            A0TEMP=PPA0BW
            A1TEMP=PPA1BW
          ENDIF
!
          IF(ICASPL.EQ.'PPCC' .AND. CORRV(IDIS).GT.PPCCMX)THEN
            A0SAVE=PPA0
            A1SAVE=PPA1
            A0BWSV=PPA0BW
            A1BWSV=PPA1BW
            PPCCMX=CORRV(IDIS)
            SHA1MX=DISPAR(IDIS)
            SHA2MX=DISPA2(IDIS)
          ENDIF
        ELSE
          IF(KSLOC.NE.CPUMIN .AND. KSSCAL.NE.CPUMIN)THEN
            A0TEMP=KSLOC
            A1TEMP=KSSCAL
          ELSE
            A0TEMP=0.0
            A1TEMP=1.0
          ENDIF
        ENDIF
!
        IF(ICASPL.NE.'PPCC')THEN
!
          CALL DPPPC6(ICASPL,ICASP2,   &
                      SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                      A0TEMP,A1TEMP,XMIN,XMAX,AMIN,AMAX,XMED,   &
                      IBUGG3,ISUBRO,IERROR)
!
          CALL DPGOFA(Y1,XLOW,XHIGH,N1,ICASP2,ICASPL,IDATSW,   &
                      XCENS,XTEMP1,XTEMP2,XTEMP3,XTEMP4,   &
                      WEIGHH,WEIGHV,Y2,X2,D2,N2,   &
                      YLOWLM,YUPPLM,A,B,MINMAX,   &
                      PCHSLM,MINSIZ,   &
                      SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                      SHAPE5,SHAPE6,SHAPE7,   &
                      IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                      ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                      IGETDF,ICONDF,IGOMDF,IKATDF,   &
                      IGIGDF,IGEODF,   &
                      MAXNXT,NUMSHA,A0TEMP,A1TEMP,   &
                      PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                      CCALBE,PPA0BW,PPA1BW,   &
                      STATVA,STAT,STATCD,PVAL,IDF,   &
                      NCELLS,NTOT,IDISFL,ILOWLM,IMETHD,IDIST,   &
                      IBUGG3,ISUBRO,IERROR)
          IF(ICASPL.EQ.'CHSQ')STATVA=STAT
          IF(IERROR.EQ.'YES')GO TO 9000
!
          IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PPC3')THEN
            WRITE(ICOUT,1740)STATVA
 1740       FORMAT('AFTER CALL DPGOFA: STATVA = ',2G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          CORRV(IDIS)=STATVA
          XTEMP4(IDIS)=A0TEMP
          XTEMP5(IDIS)=A1TEMP
          IF(IDIR.EQ.'MAXI')THEN
            IF(CORRV(IDIS).LT.PPCCMX)THEN
              A0SAVE=A0TEMP
              A1SAVE=A1TEMP
              PPCCMX=CORRV(IDIS)
              SHA1MX=DISPAR(IDIS)
              SHA2MX=DISPA2(IDIS)
            ENDIF
          ELSE
            IF(CORRV(IDIS).LT.PPCCMX)THEN
              A0SAVE=A0TEMP
              A1SAVE=A1TEMP
              PPCCMX=CORRV(IDIS)
              SHA1MX=DISPAR(IDIS)
              SHA2MX=DISPA2(IDIS)
            ENDIF
          ENDIF
!
        ENDIF
!
        IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PPC3')THEN
          WRITE(ICOUT,1830)N1
 1830     FORMAT('AT END OF 1105 LOOP: N1 = ',I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1831)NUMDIS,IDIS,DISPAR(IDIS),DISPA2(IDIS),   &
                           CORRV(IDIS)
 1831     FORMAT('NUMDIS,IDIS,DISPAR(IDIS),DISPA2(IDIS),CORRV(IDIS)=',   &
                 2I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1832)A0TEMP,A1TEMP
 1832     FORMAT('A0TEMP,A1TEMP = ',2G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        XTEMP4(IDIS)=A0TEMP
        XTEMP5(IDIS)=A1TEMP
!
 1105 CONTINUE
!
!     NOW THAT WE HAVE LOOPED OVER ALL VALUES OF THE SHAPE
!     PARAMETER(S), DO THE FOLLOWING:
!
!       1) WRITE RELEVANT INFO TO DPST1F.DAT
!
!       2) GENERATE THE PLOT POINTS (Y2, X2, D2).  NEED TO ACCOUNT
!          FOR REPLICATION CASE.  ALSO, NEED TO DISTINGUISH BETWEEN
!          THE ONE SHAPE PARAMETER AND THE TWO SHAPE PARAMETER
!          CASE.  NOTE THAT DISTRIBUTIONS WITH TWO SHAPE PARAMETERS
!          MAY ONLY HAVE A SINGLE VALUE FOR ONE OF THE SHAPE PARAMETERS.
!          THESE CASES NEED TO BE PLOTTED AS A SINGLE SHAPE PARAMETER
!          CASE.
!
!          ALSO, THE TWO SHAPE PARAMETER CASE MAY BE PLOTTED AS A
!          3D PLOT OR AS A 2D PLOT WHERE EACH VALUE OF THE SECOND
!          SHAPE PARAMETER IS DRAWN AS A SEPARATE TRACE ON THE
!          2D PLOT.
!
      CALL DPPPC9(ICASPL,ICASP2,IOUNI2,ICNTPT,IFLAG2,   &
                  DISPAR,DISPA2,DISPA3,NUMDIS,CORRV,NUMSHA,   &
                  XTEMP4,XTEMP5,X2TEMP,   &
                  IPPCFO,IPPCAO,IFLAGF,NCURVE,   &
                  Y2,X2,X3D2,D2,N2,NPLOTV,   &
                  IBUGG3,ISUBRO,IERROR)
!
      IF(NCURVE.EQ.1 .AND. NUMSHA.EQ.1)THEN
        IDATSW='RAW'
        CALL DPWCPP(XTEMP1,N1,ICASP2,IDATSW,   &
                    CORRV,DISPAR,NUMDIS,   &
                    IBUGG3,ISUBRO,IFOUND,IERROR)
      ENDIF
!
      IF(IFLAGF.EQ.'ON')THEN
        WRITE(IOUNI3,'(I8,5E15.7)')NCURVE,PPCCMX,SHA1MX,SHA2MX,   &
                                   A0SAVE,A1SAVE
!
        IOP='CLOS'
        CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                    IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                    IBUGG3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
      ENDIF
!
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IF(ICASPL.EQ.'GIGA')THEN
        IGIGDF=IGIGSV
      ENDIF
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PPC3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPPC3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)N2,IERROR
 9012   FORMAT('N2,IERROR = ',I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,N2
          WRITE(ICOUT,9021)I,Y2(I),X2(I),D2(I)
 9021     FORMAT('I,Y2(I),X2(I),D2(I) = ',I8,2E15.7,F9.2)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPPPC3
      SUBROUTINE DPPPC4(ICASPL,PPCC,SHAPE1,SHAPE2,A0SAVE,A1SAVE,NUMSHA,   &
                       IFLAGU,IFRST,ILAST,   &
                       IBUGG2,IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--UTILITY ROUTINE USED BY DPPPCC.  UPDATE THE DATAPLOT
!              PARAMETER TABLE OR WRITE VALUES TO EXTERNAL FILE.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/11
!     ORIGINAL VERSION--NOVEMBER  2009. EXTRACTED AS SEPARATE ROUTINE
!                                       FROM DPPPCC
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IFLAGU
      CHARACTER*4 IBUGG2
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      LOGICAL IFRST
      LOGICAL ILAST
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 ISUBN0
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IOP
      CHARACTER*15 ISTAT
!
      SAVE IOUNI1
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOF2.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ***************************************
!               **  STEP 1--                         **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
      IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'PPC4')THEN
        ISTEPN='1'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPPC4--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASPL,IFLAGU,IFRST,ILAST
   53   FORMAT('ICASPL,IFLAGU,IFRST,ILAST = ',A4,2X,A4,2X,A8,2X,A8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,65)PPCC,SHAPE1,SHAPE2,A0SAVE,A1SAVE,NUMSHA
   65   FORMAT('PPCC,SHAPE1,SHAPE2,A0SAVE,A1SAVE,NUMSHA = ',5G15.7,I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      ISUBN0='PPC4'
!
      IF(IFLAGU.EQ.'FILE')THEN
        IF(IFRST)THEN
          IOP='OPEN'
          IFLAG1=1
          IFLAG2=0
          IFLAG3=0
          IFLAG4=0
          IFLAG5=0
          CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                      IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                      IBUGG2,ISUBRO,IERROR)
!
          IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'PPC4')THEN
            ISTEPN='2A'
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,201)
  201       FORMAT('AFTER CALL DPOPFI, IERRF1 = ',A4)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,203)IERROR,IOUNI1
  203       FORMAT('IERROR,IOUNI1 = ',A4,2X,I5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          IF(IERROR.EQ.'YES')GO TO 9000
!
          ISTAT='        MAXPPCC'
          IF(ICASPL.EQ.'KS  ')ISTAT='          MINKS'
          IF(ICASPL.EQ.'AD  ')ISTAT='          MINAD'
          IF(NUMSHA.EQ.1)THEN
            WRITE(IOUNI1,297)ISTAT
  297       FORMAT(A15,10X,'SHAPE',7X,'LOCATION',10X,'SCALE')
          ELSE
            WRITE(IOUNI1,299)ISTAT
  299       FORMAT(A15,9X,'SHAPE1',9X,'SHAPE2',7X,'LOCATION',10X,   &
                   'SCALE')
          ENDIF
        ENDIF
      ELSEIF(IFLAGU.EQ.'ON')THEN
!
        IH='LOCS'
        IH2='AVE '
        VALUE0=A0SAVE
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGG3,IERROR)
!
        IH='SCAL'
        IH2='ESAV'
        VALUE0=A1SAVE
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGG3,IERROR)
!
        IF(ICASPL.EQ.'PPCC')THEN
          IH='MAXP'
          IH2='PCC '
          VALUE0=PPCC
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGG3,IERROR)
        ELSEIF(ICASPL.EQ.'KS  ')THEN
          IH='MINK'
          IH2='S   '
          VALUE0=PPCC
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGG3,IERROR)
        ELSEIF(ICASPL.EQ.'CHSQ')THEN
          IH='MINC'
          IH2='HISQ'
          VALUE0=PPCC
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGG3,IERROR)
        ELSEIF(ICASPL.EQ.'AD  ')THEN
          IH='MINA'
          IH2='D   '
          VALUE0=PPCC
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGG3,IERROR)
        ENDIF
!
        IF(NUMSHA.EQ.1)THEN
          IH='SHAP'
          IH2='E   '
          VALUE0=SHAPE1
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGG3,IERROR)
        ELSE
          IH='SHAP'
          IH2='E1  '
          VALUE0=SHAPE1
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGG3,IERROR)
!
          IH='SHAP'
          IH2='E2  '
          VALUE0=SHAPE2
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGG3,IERROR)
        ENDIF
!
      ENDIF
!
      IF(IFLAGU.EQ.'FILE')THEN
        IF(NUMSHA.EQ.1)THEN
          WRITE(IOUNI1,1030)PPCC,SHAPE1,A0SAVE,A1SAVE
 1030     FORMAT(4E15.7)
        ELSE
          WRITE(IOUNI1,1031)PPCC,SHAPE1,SHAPE2,A0SAVE,A1SAVE
 1031     FORMAT(5E15.7)
        ENDIF
      ENDIF
!
      IF(IFLAGU.EQ.'FILE')THEN
        IF(ILAST)THEN
          IOP='CLOS'
          IFLAG1=1
          IFLAG2=0
          IFLAG3=0
          IFLAG4=0
          IFLAG5=0
          CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                      IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                      IBUGG2,ISUBRO,IERROR)
!
          IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'PPC4')THEN
            ISTEPN='3A'
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,301)IERROR,IOUNI1
  301       FORMAT('AFTER CALL DPCLFI: IERROR,IOUNI1 = ',A4,2X,I5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          IF(IERROR.EQ.'YES')GO TO 9000
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'PPC4')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF DPPPC4--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPPC4
      SUBROUTINE DPPPC6(ICASPL,ICASP2,   &
                        SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                        A0TEMP,A1TEMP,XMIN,XMAX,AMIN,AMAX,XMED,   &
                        IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--NON-PPCC BASED GOODNESS OF FIT METHODS ARE NOT
!              INVARIANT TO LOCATION AND SCALE.  IF THESE WERE
!              ESTIMATED FROM PROBABILITY PLOT, THEN MAY NEED
!              TO TWEAK LOCATION AND SCALE SO THAT MINIMUM AND
!              MAXIMUM POINTS ARE IN THE VALID DOMAIN OF THE
!              SPECIFIED DISTRIBUTION.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/1
!     ORIGINAL VERSION--JANUARY   2010. EXTRACTED AS SEPARATE ROUTINE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICASP2
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PPC6')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,11)
   11   FORMAT('***** AT THE BEGINNING OF DPPPC6--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,12)ICASPL,ICASP2
   12   FORMAT('ICASPL,ICASP2 = ',2(A4,2X))
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,13)A0TEMP,A1TEMP
   13   FORMAT('A0TEMP,A1TEMP = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,14)AMIN,AMAX,XMIN,XMAX
   14   FORMAT('AMIN,AMAX,XMIN,XMAX = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,17)SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5
   17   FORMAT('SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5 = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     FOR NON-PPCC METHODS, CHECK THAT LOCATION AND SCALE ESTIMATES
!     GENERATED FROM PROBABILITY PLOT RESULT IN THE MINIMUM/MAXIMUM
!     OF THE DATA BEING IN THE VALID DOMAIN OF THE SPECIFIED
!     DISTRIBUTION.  IF NOT, TWEAK THE LOCATION/SCALE ESTIMATES
!     ENOUGH SO THAT THEY ARE.
!
      IF(ICASPL.EQ.'PPCC')GO TO 9000
!
      IERROR='NO'
      EPS=0.000001
      ZMIN=A0TEMP
      ZMAX=A0TEMP + A1TEMP
!
!     CASE 1: DISTRIBUTIONS BOUNDED ON (0,1)
                                                                                                                                  
!             TOPP AND LEONE, TWO-SIDED POWER, TWO-SIDED SLOPE,
!             TWO-SIDED OGIVE, GENERALIZED TOPP AND LEONE,
!             REFLECTED GENERALIZED TOPP AND LEONE, BETA,
!             KUMARASWAMY DISTRIBUTIONS.
!
      IF(ICASP2.EQ.'TOPL' .OR. ICASP2.EQ.'TSPO' .OR.   &
         ICASP2.EQ.'BETA' .OR. ICASP2.EQ.'KUMA' .OR.   &
         ICASP2.EQ.'TSSL' .OR. ICASP2.EQ.'TSOG' .OR.   &
         ICASP2.EQ.'GTOL' .OR. ICASP2.EQ.'RGTL')THEN
        IF(ZMIN.GT.XMIN .OR. ZMAX.LT. XMAX)THEN
          IF(XMIN.GE.0.0 .AND. XMIN.LE.1.0 .AND.   &
             XMAX.GE.0.0 .AND. XMAX.LE.1.0)THEN
            A0TEMP=0.0
            A1TEMP=1.0
          ELSE
            A0TEMP=XMIN-EPS
            A1TEMP=(XMAX+EPS) - (XMIN-EPS)
          ENDIF
        ENDIF
!
!       CASE 2: TRIANGULAR DISTRIBUTION
!
!               FOR TRIANGULAR, IF MIN AND MAX ARE IN (0,1),
!               USE (0,1), IF THEY ARE IN (-1,1), USE (-1,1).
!               OTHERWISE, USE MIN AND MAX.
!
                                                                                                                                  
      ELSEIF(ICASP2.EQ.'TRIA')THEN
        IF(ZMIN.GT.XMIN .OR. ZMAX.LT. XMAX)THEN
          EPS=(XMAX-XMIN)/1000.
          IF(XMIN.GE.0.0 .AND. XMAX.LE.1.0)THEN
            A0TEMP=0.0
            A1TEMP=1.0
          ELSEIF(XMIN.GE.-1.0 .AND. XMAX.LE.1.0)THEN
            A0TEMP=-1.0
            A1TEMP=1.0
          ELSE
            A0TEMP=XMIN - EPS
            A1TEMP=XMAX + EPS
          ENDIF
        ENDIF
!
!       CASE 3: TUKEY-LAMBDA DISTRIBUTION
!
      ELSEIF(ICASP2.EQ.'TULA' .AND. SHAPE1.GT.0.0)THEN
        IF((XMIN-A0TEMP)/A1TEMP.LT.AMIN .OR.   &
           (XMAX-A0TEMP)/A1TEMP.GT.AMAX)THEN
           A0TEMP=XMED
           ATEMP1=SHAPE1*ABS(XMAX-A0TEMP) + 0.1
           ATEMP2=SHAPE2*ABS(XMIN-A0TEMP) + 0.1
           A1TEMP=MAX(ATEMP1,ATEMP2)
        ENDIF
!
!       CASE 4: VON-MISES AND WRAPPED CAUCHY DISTRIBUTIONS
!
      ELSEIF(ICASP2.EQ.'VONM' .OR. ICASP2.EQ.'WCAU')THEN
        IF((XMIN-A0TEMP)/A1TEMP.LT.AMIN .OR.   &
           (XMAX-A0TEMP)/A1TEMP.GT.AMAX)THEN
           A0TEMP=XMED
           ATEMP1=(XMAX-A0TEMP)/AMAX
        ENDIF
!
!       CASE 5: GENERIC CASE WHERE DOMAIN BOUNDED BOTH ABOVE
!               AND BELOW.  SOLVE
!
!               (XMIN-A0)/A1 = AMIN
!               (XMAX-A0)/A1 = AMAX
!
!               NOTE: IF AMIN = -AMAX (E.G., VON MISES), THEN GET
!                     DIVISION BY ZERO.  IN THIS CASE, SET A0 TO
!                     DATA MINIMUM MINUS EPS, THEN SET
!                     A1 = (XMAX-A0)/AMAX
!
      ELSEIF(AMIN.GT.CPUMIN .AND. AMAX.LT.CPUMAX)THEN
        IF((XMIN-A0TEMP)/A1TEMP.LT.AMIN .OR.   &
           (XMAX-A0TEMP)/A1TEMP.GT.AMAX)THEN
           CMIN=AMIN
           CMAX=AMAX
           CONST=CMIN/CMAX
           IF(CONST.NE.-1.0)THEN
             A0TEMP=(XMIN-CONST*XMAX)/(1.0+CONST) - EPS
             A1TEMP=(XMAX-A0TEMP)/CMAX + EPS
           ELSE
             A0TEMP=XMIN - EPS
             A1TEMP=(XMAX - A0TEMP)/AMAX
           ENDIF
        ENDIF
!
!       CASE 6: GENERIC CASE WHERE DOMAIN BOUNDED BELOW ONLY
!
      ELSEIF(AMIN.GT.CPUMIN .AND. AMAX.EQ.CPUMAX)THEN
        IF((XMIN-A0TEMP)/A1TEMP.LT.AMIN)THEN
          A0TEMP=XMIN-EPS
        ENDIF
!
!       CASE 7: GENERIC CASE WHERE DOMAIN BOUNDED ABOVE ONLY
!
      ELSEIF(AMIN.EQ.CPUMIN .AND. AMAX.LT.CPUMAX)THEN
        CTEMP=(XMAX-A0TEMP)/A1TEMP
        IF(CTEMP.GE.AMAX)THEN
          A0TEMP=(XMAX-EPS) - A1TEMP*AMAX
        ENDIF
!
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PPC6')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPPC6--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)A0TEMP,A1TEMP
 9013   FORMAT('A0TEMP,A1TEMP = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPPC6
      SUBROUTINE DPPPC7(ICASPL,ICASP2,IPPCAP,   &
                        SHAP11,SHAP12,SHAP21,SHAP22,   &
                        SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                        YMIN,YMAX,A,B,   &
                        DISPAR,DISPA2,NUMDIS,NUMSHA,   &
                        IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                        ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,   &
                        ICONDF,IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                        IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--UTILITY ROUTINE FOR PPCC PLOT.  CREATE THE ARRAYS THAT
!              CONTAIN THE VALUES OF THE SHAPE PARAMETER(S) WHERE THE
!              UNDERLYING PROBABILITY PLOT WILL BE GENERATED.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/10
!     ORIGINAL VERSION--OCTOBER   2009. EXTRACTED FROM DPPPC2 AND
!                                       DPPPC3 ROUTINES
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICASP2
      CHARACTER*4 IADEDF
      CHARACTER*4 IGEPDF
      CHARACTER*4 IMAKDF
      CHARACTER*4 IBEIDF
      CHARACTER*4 ILGADF
      CHARACTER*4 ISKNDF
      CHARACTER*4 IGLDDF
      CHARACTER*4 IBGEDF
      CHARACTER*4 IGETDF
      CHARACTER*4 ICONDF
      CHARACTER*4 IGOMDF
      CHARACTER*4 IKATDF
      CHARACTER*4 IGIGDF
      CHARACTER*4 IGEODF
!
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      INTEGER IPPCAP(2)
!
      DIMENSION DISPAR(*)
      DIMENSION DISPA2(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PPC7')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,11)
   11   FORMAT('***** AT THE BEGINNING OF DPPPC7--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,12)ICASPL,ICASP2,A,B
   12   FORMAT('ICASPL,ICASP2,A,B = ',A4,2X,A4,2X,2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,13)SHAP11,SHAP12,SHAP21,SHAP22
   13   FORMAT('SHAP11,SHAP12,SHAP21,SHAP22 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IERROR='NO'
!
!               *******************************************************
!               **  STEP 1--                                         **
!               **  DEFINE DEFAULT NUMBER OF POINTS AT WHICH TO      **
!               **  COMPUTE THE PPCC (OR OTHER GOODNESS OF FIT).     **
!               *******************************************************
!
      NHOR1=IPPCAP(1)
      NHOR2=IPPCAP(2)
!
      N1DFLT=50
      N2DFLT=50
      IF(ICASP2.EQ.'BETA' .OR. ICASP2.EQ.'GGAM' .OR.   &
         ICASP2.EQ.'IBET' .OR. ICASP2.EQ.'LSNO' .OR.   &
         ICASP2.EQ.'BNOR' .OR. ICASP2.EQ.'BGEO' .OR.   &
         ICASP2.EQ.'LBET' .OR. ICASP2.EQ.'KATZ' .OR.   &
         ICASP2.EQ.'KUMA' .OR. ICASP2.EQ.'MBKA' .OR.   &
         ICASP2.EQ.'KAPP' .OR. ICASP2.EQ.'GIGA' .OR.   &
         ICASP2.EQ.'WARI' .OR. ICASP2.EQ.'TRAP' .OR.   &
         (ICASP2.EQ.'GEET' .AND. IGETDF.EQ.'MU') .OR.   &
         (ICASP2.EQ.'CONS' .AND. ICONDF.EQ.'MU')   &
         )THEN
        N1DFLT=25
        N2DFLT=25
      ELSEIF(ICASP2.EQ.'AEPP')THEN
        N1DFLT=25
        N2DFLT=18
      ELSEIF((ICASP2.EQ.'GEET' .AND. IGETDF.EQ.'THET') .OR.   &
             ICASP2.EQ.'GLOS')THEN
        N1DFLT=25
        N2DFLT=20
      ELSEIF(ICASP2.EQ.'GHPP')THEN
        N1DFLT=21
        N2DFLT=41
      ELSEIF(ICASP2.EQ.'GPP')THEN
        N1DFLT=101
        N2DFLT=1
      ELSEIF(ICASP2.EQ.'HPP')THEN
        N1DFLT=51
        N2DFLT=1
      ELSEIF(ICASP2.EQ.'TEXP')THEN
        N1DFLT=21
        N2DFLT=51
      ELSEIF(ICASP2.EQ.'FNOR' .OR. ICASP2.EQ.'FCAU' .OR.   &
             ICASP2.EQ.'BBIN' .OR. ICASP2.EQ.'HERM' .OR.   &
             ICASP2.EQ.'TNOR'   &
            )THEN
        N1DFLT=51
        N2DFLT=51
      ELSEIF(ICASP2.EQ.'GALP' .OR. ICASP2.EQ.'G4LO')THEN
        N1DFLT=20
        N2DFLT=20
      ELSEIF(ICASP2.EQ.'LPOI')THEN
        N1DFLT=31
        N2DFLT=31
      ELSEIF(ICASP2.EQ.'L3EX')THEN
        N1DFLT=50
        N2DFLT=25
      ELSEIF(ICASP2.EQ.'NCCS')THEN
        N1DFLT=10
        N2DFLT=21
      ELSEIF(ICASP2.EQ.'GMCL')THEN
        N1DFLT=17
        N2DFLT=20
      ELSEIF(ICASP2.EQ.'DISW' .OR. ICASP2.EQ.'GLGP' .OR.   &
             ICASP2.EQ.'GTOL' .OR. ICASP2.EQ.'RGTL')THEN
        N1DFLT=21
        N2DFLT=25
      ELSEIF(ICASP2.EQ.'MCLE' .OR. ICASP2.EQ.'G3LO' .OR.   &
             ICASP2.EQ.'ZETA' .OR. ICASP2.EQ.'ZIPF' .OR.   &
             ICASP2.EQ.'BTAN'   &
            )THEN
        N1DFLT=30
      ELSEIF(ICASP2.EQ.'LOST')THEN
        N1DFLT=45
      ENDIF
!
      IF(SHAP11.GT.SHAP12)THEN
        ATEMP=SHAP11
        SHAP11=SHAP12
        SHAP12=SHAP11
      ENDIF
      IF(SHAP21.GT.SHAP22)THEN
        ATEMP=SHAP21
        SHAP21=SHAP22
        SHAP22=SHAP21
      ENDIF
!
      IF(ICASP2.EQ.'TEXP')THEN
        IF(SHAP22.GE.YMIN)THEN
          SHAP22=YMIN-0.1
          IF(SHAP21.GE.SHAP22)THEN
            SHAP21=SHAP22-5.0
            IF(SHAP21.LT.0.0)SHAP21=0.0
          ENDIF
        ENDIF
      ENDIF
!
!               *******************************************************
!               **  STEP 2--                                         **
!               **  CREATE THE DISPAR AND DISPA2 ARRAYS (VALUES      **
!               **  FOR THE SHAPE PARAMETER(S)).                     **
!               *******************************************************
!
      IF(NUMSHA.EQ.1)THEN
!
!       ONE SHAPE PARAMETER CASES:
!
!       A) CASES WITH AN INTEGER SHAPE PARAMETER
!
        IF(ICASP2.EQ.'TPP' .OR. ICASP2.EQ.'CHIS' .OR.   &
           ICASP2.EQ.'CHI' .OR. ICASP2.EQ.'FT')THEN
          NUMDIS=N1DFLT
          IF(NHOR1.GT.1)NUMDIS=NHOR1
          IHIGH=INT(SHAP12+0.1)
          ILOW =INT(SHAP11+0.1)
          IF(ILOW.EQ.IHIGH)IHIGH=ILOW+9
          NUMDI2=IHIGH-ILOW+1
          NUMDIS=MIN(NUMDIS,NUMDI2)
          ANUMDI=REAL(NUMDIS)
          ICNT=0
          DO 110 IDIS=1,NUMDIS
            AIDIS=REAL(IDIS)
            AFACT=(AIDIS-1.0)/(ANUMDI-1.0)
            ATEMP=SHAP11 + AFACT*(SHAP12-SHAP11)
            ITEMP=INT(ATEMP+0.1)
            ATEMP=REAL(ITEMP)
            IF(IDIS.GT.1 .AND. ATEMP.EQ.DISPAR(ICNT))GO TO 110
            ICNT=ICNT+1
            DISPAR(ICNT)=ATEMP
  110     CONTINUE
!
!       GENERIC CASE
!
        ELSE
          NUMDIS=N1DFLT
          IF(NHOR1.GT.1)NUMDIS=NHOR1
          ANUMDI=REAL(NUMDIS)
          DO 190 IDIS=1,NUMDIS
            AIDIS=REAL(IDIS)
            AFACT=(AIDIS-1.0)/(ANUMDI-1.0)
            DISPAR(IDIS)=SHAP11 + AFACT*(SHAP12-SHAP11)
  190     CONTINUE
        ENDIF
!
!       CASES WITH TWO SHAPE PARAMETERS
!
      ELSE
!
!       CASES THAT REQUIRE SPECIAL HANDLING
!
!       A) SECOND SHAPE PARAMETER SET TO A FIXED VALUE
!
        IF(ICASP2.EQ.'NBIN' .AND. SHAP21.EQ.SHAP22)THEN
          NUMDIS=N1DFLT
          IF(NHOR1.GT.1)NUMDIS=NHOR1
          ANUMDI=REAL(NUMDIS)
          DO 210 IDIS=1,NUMDIS
            AIDIS=REAL(IDIS)
            AFACT=(AIDIS-1.0)/(ANUMDI-1.0)
            DISPAR(IDIS)=SHAP11 + AFACT*(SHAP12-SHAP11)
            DISPAR(IDIS)=SHAP21
  210     CONTINUE
!
!       B) FIRST SHAPE PARAMETER IS BOUNDED BY A MINIMUM (A) AND
!          A MAXIMUM (B)
!
        ELSEIF(ICASP2.EQ.'TSPO' .OR. ICASP2.EQ.'TSSL' .OR.   &
               ICASP2.EQ.'TSOG')THEN
          NUMDI1=N1DFLT
          IF(NHOR1.GT.0)NUMDI1=NHOR1
          ANMDI1=NUMDI1
          NUMDI2=N2DFLT
          IF(NHOR2.GT.0)NUMDI2=NHOR2
          ANMDI2=NUMDI2
          ICOUNT=0
          IF(SHAP11.LT.A)SHAP11=A
          IF(SHAP12.GT.B)SHAP12=B
          DO 220 IDIS1=1,NUMDI1
            AIDI1=IDIS1
            A1=SHAP11+((AIDI1-1.0)/(ANMDI1-1.0))*(SHAP12-SHAP11)
            DO 225 IDIS2=1,NUMDI2
              AIDI2=IDIS2
              A2=SHAP21+((AIDI2-1.0)/(ANMDI2-1.0))*(SHAP22-SHAP21)
              ICOUNT=ICOUNT+1
              DISPAR(ICOUNT)=A1
              DISPA2(ICOUNT)=A2
  225       CONTINUE
  220     CONTINUE
          NUMDIS=ICOUNT
!
!       C) BOTH SHAPE PARAMETERS REQUIRE INTEGER VALUES
!          A MAXIMUM (B)
!
        ELSEIF(ICASP2.EQ.'FPP ')THEN
          NU11=INT(SHAP11+0.1)
          NU12=INT(SHAP12+0.1)
          NU21=INT(SHAP21+0.1)
          NU22=INT(SHAP22+0.1)
          NUMDI1=NU12 - NU11 + 1
          IF(NHOR1.GT.0)NUMDI1=NHOR1
          IF(NUMDI1.LT.10)NUMDI1=10
          ANMDI1=NUMDI1
          NUMDI2=NU22 - NU21 + 1
          IF(NHOR2.GT.0)NUMDI2=NHOR2
          IF(NUMDI2.LT.10)NUMDI2=10
          ANMDI2=NUMDI2
          ICOUNT=0
          DO 230 IDIS1=1,NUMDI1
            NTEMP1=NU11 + IDIS1 - 1
            DO 235 IDIS2=1,NUMDI2
              NTEMP2=NU21 + IDIS2 - 1
              ICOUNT=ICOUNT+1
              DISPAR(ICOUNT)=REAL(NTEMP1)
              DISPA2(ICOUNT)=REAL(NTEMP2)
  235       CONTINUE
  230     CONTINUE
          NUMDIS=ICOUNT
!
!       D) FIRST SHAPE PARAMETER REQUIRES INTEGER VALUE
!
        ELSEIF(ICASP2.EQ.'TSKE' .OR. ICASP2.EQ.'NCCS' .OR.   &
               ICASP2.EQ.'NCT')THEN
          NU11=INT(SHAP11+0.1)
          NU12=INT(SHAP12+0.1)
          NUMDI1=NU12 - NU11 + 1
          IF(NHOR1.GT.0)NUMDI1=NHOR1
          IF(NUMDI1.LT.10)NUMDI1=10
          ANMDI1=REAL(NUMDI1)
          NUMDI2=N2DFLT
          IF(NHOR2.GT.0)NUMDI2=NHOR2
          ANMDI2=REAL(NUMDI2)
          ICOUNT=0
          DO 240 IDIS1=1,NUMDI1
            NTEMP1=NU11 + IDIS1 - 1
            DO 245 IDIS2=1,NUMDI2
              AIDIS2=IDIS2
              A2=SHAP21+((AIDIS2-1.0)/(ANMDI2-1.0))*(SHAP22-SHAP21)
              ICOUNT=ICOUNT+1
              DISPAR(ICOUNT)=REAL(NTEMP1)
              DISPA2(ICOUNT)=A2
  245       CONTINUE
  240     CONTINUE
          NUMDIS=ICOUNT
!
!       E) FOR WARING, SECOND SHAPE PARAMETER BOUNDED BY THE FIRST
!
        ELSEIF(ICASP2.EQ.'WARI')THEN
          NUMDI1=N1DFLT
          IF(NHOR1.GT.0)NUMDI1=NHOR1
          ANMDI1=NUMDI1
          NUMDI2=N2DFLT
          IF(NHOR2.GT.0)NUMDI2=NHOR2
          ANMDI2=NUMDI2
          ICOUNT=0
          DO 250 IDIS1=1,NUMDI1
            AIDI1=IDIS1
            A1=SHAP11+((AIDI1-1.0)/(ANMDI1-1.0))*(SHAP12-SHAP11)
            DO 255 IDIS2=1,NUMDI2
              AIDI2=IDIS2
              A2=SHAP21+((AIDI2-1.0)/(ANMDI2-1.0))*(SHAP22-SHAP21)
              IF(A1.GT.A2)THEN
                ICOUNT=ICOUNT+1
                DISPAR(ICOUNT)=A1
                DISPA2(ICOUNT)=A2
              ENDIF
  255       CONTINUE
  250     CONTINUE
          NUMDIS=ICOUNT
!
!       F) FOR GENERALIZED LOGARITHMIC SERIES, GEETA (THETA
!          PARAMETERIZATION), AND CONSUL (THETA PARAMETERIZATION),
!          THE SECOND SHAPE PARAMETER BOUNDED BY THE FIRST
!
        ELSEIF(ICASP2.EQ.'GLOS' .OR.   &
              (ICASP2.EQ.'GEET' .AND. IGETDF.EQ.'THET') .OR.   &
              (ICASP2.EQ.'CONS' .AND. ICONDF.EQ.'THET'))THEN
          NUMDI1=N1DFLT
          IF(NHOR1.GT.0)NUMDI1=NHOR1
          ANMDI1=NUMDI1
          NUMDI2=N2DFLT
          IF(NHOR2.GT.0)NUMDI2=NHOR2
          ANMDI2=NUMDI2
          ICOUNT=0
          DO 260 IDIS1=1,NUMDI1
            AIDI1=IDIS1
            A1=SHAP11+((AIDI1-1.0)/(ANMDI1-1.0))*(SHAP12-SHAP11)
            BETA1Z=SHAP21
            BETA2Z=SHAP22
            ZMAXBE=1.0/A1
            ATEMP=REAL(N2DFLT)
            IF(BETA1Z.GE.ZMAXBE)BETA1Z=1.0 + (ZMAXBE-1.0)/ATEMP
            IF(BETA2Z.GE.ZMAXBE)BETA2Z=1.0 +   &
                                (ATEMP-1.0)*(ZMAXBE-1.0)/ATEMP
            DO 265 IDIS2=1,NUMDI2
              AIDI2=IDIS2
              A2=BETA1Z+((AIDI2-1.0)/(ANMDI2-1.0))*(BETA2Z-BETA1Z)
              ICOUNT=ICOUNT+1
              DISPAR(ICOUNT)=A1
              DISPA2(ICOUNT)=A2
  265       CONTINUE
  260     CONTINUE
          NUMDIS=ICOUNT
!
!       G) FOR QUASI BINOMIAL TYPE 1, -P/M < PHI < (1-P)/M
!          SO SET RANGE FOR PHI DEPENDENT ON P.
!
        ELSEIF(ICASP2.EQ.'QBIN')THEN
          NUMDI1=19
          IF(NHOR1.GT.0)NUMDI1=NHOR1
          ANMDI1=NUMDI1
          NUMDI2=20
          IF(NHOR2.GT.0)NUMDI2=NHOR2
          ANMDI2=NUMDI2
          ICOUNT=0
          DO 270 IDIS1=1,NUMDI1
            AIDI1=IDIS1
            A1=SHAP11+((AIDI1-1.0)/(ANMDI1-1.0))*(SHAP12-SHAP11)
            ZMINPH=-A1/SHAPE3
            ZMAXPH=(1.0-A1)/SHAPE3
            AINC=(ZMAXPH-ZMINPH)/REAL(NUMDI2)
            ZMINPH=ZMINPH + AINC
            ZMAXPH=ZMAXPH - AINC
            PHI1Z=SHAP21
            PHI2Z=SHAP22
            IF(PHI1Z.LT.ZMINPH)PHI1Z=ZMINPH
            IF(PHI2Z.GT.ZMAXPH)PHI2Z=ZMAXPH
            DO 275 IDIS2=1,NUMDI2
              AIDI2=IDIS2
              A2=PHI1Z+((AIDI2-1.0)/(ANMDI2-1.0))*(PHI2Z-PHI1Z)
              ICOUNT=ICOUNT+1
              DISPAR(ICOUNT)=A1
              DISPA2(ICOUNT)=A2
  275       CONTINUE
  270     CONTINUE
          NUMDIS=ICOUNT
!
!       H) FOR TRAPEZOID DISTRIBUTION, B < C,
!          SO SET RANGE FOR C DEPENDENT ON B.
!
        ELSEIF(ICASP2.EQ.'TRAP')THEN
          NUMDI1=N1DFLT
          IF(NHOR1.GT.0)NUMDI1=NHOR1
          ANMDI1=NUMDI1
          NUMDI2=N2DFLT
          IF(NHOR2.GT.0)NUMDI2=NHOR2
          ANMDI2=NUMDI2
          ICOUNT=0
          DO 280 IDIS1=1,NUMDI1
            AIDI1=IDIS1
            A1=SHAP11+((AIDI1-1.0)/(ANMDI1-1.0))*(SHAP12-SHAP11)
            ZMINC=A1
            DO 285 IDIS2=1,NUMDI2
              AIDI2=IDIS2
              A2=SHAP21+((AIDI2-1.0)/(ANMDI2-1.0))*(SHAP22-SHAP21)
              IF(A2.GT.ZMINC)THEN
                ICOUNT=ICOUNT+1
                DISPAR(ICOUNT)=A1
                DISPA2(ICOUNT)=A2
              ENDIF
  285       CONTINUE
  280     CONTINUE
          NUMDIS=ICOUNT
!
!       GENERIC CASE
!
        ELSE
          NUMDI1=N1DFLT
          IF(NHOR1.GT.0)NUMDI1=NHOR1
          ANMDI1=NUMDI1
          NUMDI2=N2DFLT
          IF(NHOR2.GT.0)NUMDI2=NHOR2
          ANMDI2=NUMDI2
          ICOUNT=0
          DO 290 IDIS1=1,NUMDI1
            AIDI1=IDIS1
            A1=SHAP11+((AIDI1-1.0)/(ANMDI1-1.0))*(SHAP12-SHAP11)
            DO 295 IDIS2=1,NUMDI2
              AIDI2=IDIS2
              A2=SHAP21+((AIDI2-1.0)/(ANMDI2-1.0))*(SHAP22-SHAP21)
              ICOUNT=ICOUNT+1
              DISPAR(ICOUNT)=A1
              DISPA2(ICOUNT)=A2
  295       CONTINUE
  290     CONTINUE
          NUMDIS=ICOUNT
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PPC7')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPPC7--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)SHAPE1,SHAPE2,SHAPE3,SHAPE4
 9012   FORMAT('SHAPE1,SHAPE2,SHAPE3,SHAPE4 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NUMDI1,NUMDI2,NUMDIS
 9013   FORMAT('NUMDI1,NUMDI2,NUMDIS = ',3I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)IADEDF,IBEIDF,IBGEDF,ICONDF,IGEODF
 9015   FORMAT('IADEDF,IBEIDF,IBGEDF,ICONDF,IGEODF = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IGEODF,IGETDF,IGOMDF,IKATDF,ILGADF
 9016   FORMAT('IGEODF,IGETDF,IGOMDF,IKATDF,ILGADF = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9018)IMAKDF,ISKNDF,IGIGDF,IGEPDF,IGLDDF
 9018   FORMAT('IGEODF,IGETDF,IGIGDF,IGEPDF,IGLDDF = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,NUMDIS
          WRITE(ICOUT,9021)I,DISPAR(I),DISPA2(I)
 9021     FORMAT('I,DISPAR(I),DISPA2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
        WRITE(ICOUT,9031)YMIN,YMAX,A,B
 9031   FORMAT('YMIN,YMAX,A,B = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPPC7
      SUBROUTINE DPPPC8(ICASPL,ICASP2,   &
                        SHAP11,SHAP12,SHAP21,SHAP22,   &
                        SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                        YLOWLM,YUPPLM,A,B,MINMAX,   &
                        IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                        ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                        IGETDF,ICONDF,IGOMDF,IKATDF,   &
                        IGIGDF,IGEODF,   &
                        AMIN,AMAX,   &
                        IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--FOR PPCC PLOT (DPPPC2, DPPPC3), SET VALUES FOR AMIN
!              AND AMAX.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/1
!     ORIGINAL VERSION--JANUARY   2010. EXTRACT AS SEPARATE SUBROUTINE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICASP2
      CHARACTER*4 IADEDF
      CHARACTER*4 IGEPDF
      CHARACTER*4 IMAKDF
      CHARACTER*4 IBEIDF
      CHARACTER*4 ILGADF
      CHARACTER*4 ISKNDF
      CHARACTER*4 IGLDDF
      CHARACTER*4 IBGEDF
      CHARACTER*4 IGETDF
      CHARACTER*4 ICONDF
      CHARACTER*4 IGOMDF
      CHARACTER*4 IKATDF
      CHARACTER*4 IGIGDF
      CHARACTER*4 IGEODF
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      DOUBLE PRECISION DPPF
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA PI / 3.1415926535 /
!
!-----START POINT-----------------------------------------------------
!
      IWRITE='OFF'
      IERROR='NO'
!
      AMIN=CPUMIN
      AMAX=CPUMAX
!
!     CONVERT 3-PARAMETER DISTRIBUTION NAMES TO BE EQUIVALENT TO
!     2-PARAMETER DISTRIBUTION NAMES
!
      IF(ICASP2.EQ.'3WEI')ICASP2='WEIB'
      IF(ICASP2.EQ.'3IWE')ICASP2='IWEI'
      IF(ICASP2.EQ.'3GAM')ICASP2='GAMM'
      IF(ICASP2.EQ.'3IGA')ICASP2='IGAU'
      IF(ICASP2.EQ.'3LGN')ICASP2='LOGN'
!
      IF(ICASPL.NE.'PPCC')THEN
        IF(ICASP2.EQ.'TULA')THEN
          IF(SHAPE1.GT.0.0)THEN
            AMAX=ABS(1.0/SHAPE1)
            AMIN=-AMAX
          ENDIF
        ELSEIF(ICASP2.EQ.'CHIS' .OR. ICASP2.EQ.'WEIB' .OR.   &
               ICASP2.EQ.'GAMM' .OR. ICASP2.EQ.'INGA' .OR.   &
               ICASP2.EQ.'WALD' .OR. ICASP2.EQ.'RIGA' .OR.   &
               ICASP2.EQ.'FATL' .OR. ICASP2.EQ.'LOGN' .OR.   &
               ICASP2.EQ.'PLGN' .OR. ICASP2.EQ.'CHI ' .OR.   &
               ICASP2.EQ.'LOGL' .OR. ICASP2.EQ.'LGAM' .OR.   &
               ICASP2.EQ.'HLOG' .OR. ICASP2.EQ.'IGAM' .OR.   &
               ICASP2.EQ.'GGAM' .OR. ICASP2.EQ.'GOMP' .OR.   &
               ICASP2.EQ.'PEXP' .OR. ICASP2.EQ.'EWEI' .OR.   &
               ICASP2.EQ.'IWEI' .OR. ICASP2.EQ.'LDEX' .OR.   &
               ICASP2.EQ.'GEEX' .OR. ICASP2.EQ.'ALPH' .OR.   &
               ICASP2.EQ.'FT  ' .OR. ICASP2.EQ.'FPP ' .OR.   &
               ICASP2.EQ.'IBET' .OR. ICASP2.EQ.'LSNO' .OR.   &
               ICASP2.EQ.'NCCS' .OR. ICASP2.EQ.'FNOR' .OR.   &
               ICASP2.EQ.'FCAU' .OR. ICASP2.EQ.'FNOR' .OR.   &
               ICASP2.EQ.'MAXW' .OR. ICASP2.EQ.'GOMM' .OR.   &
               ICASP2.EQ.'ALDE' .OR. ICASP2.EQ.'LBET' .OR.   &
               ICASP2.EQ.'BUR3' .OR. ICASP2.EQ.'BU12' .OR.   &
               ICASP2.EQ.'MUTH' .OR. ICASP2.EQ.'BU12' .OR.   &
               ICASP2.EQ.'LEXP' .OR. ICASP2.EQ.'L3EX' .OR.   &
               ICASP2.EQ.'MBKA' .OR. ICASP2.EQ.'L3EX' .OR.   &
               ICASP2.EQ.'GIGA' .OR. ICASP2.EQ.'BFWE'   &
              )THEN
          AMIN=0.0
        ELSEIF(ICASP2.EQ.'POWF' .OR. ICASP2.EQ.'BETA' .OR.   &
               ICASP2.EQ.'JOSB' .OR. ICASP2.EQ.'TOPL' .OR.   &
               ICASP2.EQ.'GTOL' .OR. ICASP2.EQ.'RGTL' .OR.   &
               ICASP2.EQ.'SLOP' .OR. ICASP2.EQ.'TSSL' .OR.   &
               ICASP2.EQ.'OGIV' .OR. ICASP2.EQ.'TSOG' .OR.   &
               ICASP2.EQ.'RPOW' .OR. ICASP2.EQ.'KUMA'   &
              )THEN
          AMIN=0.0
          AMAX=1.0
        ELSEIF(ICASP2.EQ.'VONM')THEN
          AMIN=-PI
          AMAX=PI
        ELSEIF(ICASP2.EQ.'BUR4')THEN
          AMIN=0.0
          AMAX=SHAPE2
        ELSEIF(ICASP2.EQ.'WCAU')THEN
          AMIN=0.0
          AMAX=2.0*PI
        ELSEIF(ICASP2.EQ.'TEXP')THEN
          AMIN=SHAPE1
          AMAX=SHAPE3
        ELSEIF(ICASP2.EQ.'TPAR')THEN
          AMIN=A
          AMAX=SHAPE3
        ELSEIF(ICASP2.EQ.'TRAP')THEN
          AMIN=YLOWLM
          AMAX=YUPPLM
        ELSEIF(ICASP2.EQ.'RECI')THEN
          AMIN=1.0/SHAPE1
          AMAX=1.0
        ELSEIF(ICASP2.EQ.'TRIA')THEN
!CCCC     AMIN=XMIN
!CCCC     AMAX=XMAX
        ELSEIF(ICASP2.EQ.'EV2 ')THEN
          IF(MINMAX.EQ.1)THEN
            AMAX=0.0
          ELSE
            AMIN=0.0
          ENDIF
        ELSEIF(ICASP2.EQ.'GEV ')THEN
          IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
            IF(SHAPE1.GT.0.0)THEN
              AMAX=(1.0/SHAPE1) - 0.1E-6
            ELSE
              AMIN=(1.0/SHAPE1) + 0.1E-6
            ENDIF
          ELSE
            IF(SHAPE1.GT.0.0)THEN
              AMIN=(-1.0/SHAPE1) + 0.1E-6
            ELSE
              AMAX=(-1.0/SHAPE1) - 0.1E-6
            ENDIF
          ENDIF
        ELSEIF(ICASP2.EQ.'PARE' .OR. ICASP2.EQ.'PAR2')THEN
          AMIN=A
        ELSEIF(ICASP2.EQ.'GHLO')THEN
          AMIN=0.0
          AMAX=1.0/SHAPE1
        ELSEIF(ICASP2.EQ.'GPAR')THEN
          IF(IGEPDF.EQ.'JOHN')THEN
            IF(SHAPE1.LE.0.0)THEN
              AMIN=0.0
            ELSE
              AMIN=0.0
              AMAX=(1.0/SHAPE1)
            ENDIF
          ELSE
            IF(SHAPE1.GE.0.0)THEN
              AMIN=0.0
            ELSE
              AMIN=0.0
              AMAX=-(1.0/SHAPE1)
            ENDIF
          ENDIF
        ELSEIF(ICASP2.EQ.'GTLA')THEN
          IF(SHAPE1.LE.0.0 .AND. SHAPE2.LE.0.0)THEN
            AMIN=CPUMIN
            AMAX=CPUMAX
          ELSEIF(SHAPE1.LE.0.0)THEN
            AMIN=CPUMIN
            CALL GLDPPF(1.0D0,DBLE(SHAPE1),DBLE(SHAPE2),DPPF,   &
                        IGLDDF,IWRITE)
            AMAX=REAL(DPPF)
          ELSEIF(SHAPE2.LE.0.0)THEN
            AMIN=1.0/SHAPE2
            AMAX=CPUMAX
          ELSE
            CALL GLDPPF(0.0D0,DBLE(SHAPE1),DBLE(SHAPE2),DPPF,   &
                        IGLDDF,IWRITE)
            AMIN=REAL(DPPF)
            CALL GLDPPF(1.0D0,DBLE(SHAPE1),DBLE(SHAPE2),DPPF,   &
                        IGLDDF,IWRITE)
            AMAX=REAL(DPPF)
          ENDIF
        ELSEIF(ICASP2.EQ.'PEA3')THEN
          IF(SHAPE1.GT.0.0)THEN
            AMIN=-2.0/SHAPE1
          ELSEIF(SHAPE1.LT.0.0)THEN
            AMAX=-2.0/SHAPE1
          ENDIF
        ELSEIF(ICASP2.EQ.'KAPP')THEN
          IF(SHAPE1.GT.0.0)THEN
            AMAX=1.0/SHAPE1
          ENDIF
          IF(SHAPE2.GT.0.0)THEN
            AMIN=(1.0 - SHAPE2**(-SHAPE1))/SHAPE1
          ELSE
            IF(SHAPE1.LT.0.0)THEN
              AMIN=1.0/SHAPE1
            ENDIF
          ENDIF
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PPC8')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPPC8--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)AMIN,AMAX,A,B
 9012   FORMAT('AMIN,AMAX,A,B = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)SHAP11,SHAP12,SHAP21,SHAP22
 9013   FORMAT('SHAP11,SHAP12,SHAP21,SHAP22 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5
 9014   FORMAT('SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5 = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)IADEDF,IBEIDF,IBGEDF,ICONDF,IGEODF
 9015   FORMAT('IADEDF,IBEIDF,IBGEDF,ICONDF,IGEODF = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IGEODF,IGETDF,IGOMDF,IKATDF,ILGADF
 9016   FORMAT('IGEODF,IGETDF,IGOMDF,IKATDF,ILGADF = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9018)IMAKDF,ISKNDF,IGIGDF
 9018   FORMAT('IGEODF,IGETDF,IGIGDF = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPPC8
      SUBROUTINE DPPPC9(ICASPL,ICASP2,IOUNI2,ICNTPT,IFLAG2,   &
                        DISPAR,DISPA2,DISPA3,NUMDIS,CORRV,NUMSHA,   &
                        XTEMP4,XTEMP5,X2TEMP,   &
                        IPPCFO,IPPCAO,IFLAGF,NCURVE,   &
                        Y2,X2,X3D2,D2,N2,NPLOTV,   &
                        IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--UTILITY ROUTINE FOR DPPPC2 AND DPPPC3:
!
!              AFTER WE HAVE LOOPED OVER ALL VALUES OF THE SHAPE
!              PARAMETER(S), DO THE FOLLOWING:
!
!              1) WRITE RELEVANT INFO TO DPST1F.DAT
!
!              2) GENERATE THE PLOT POINTS (Y2, X2, D2).  NEED TO ACCOUNT
!                 FOR REPLICATION CASE.  ALSO, NEED TO DISTINGUISH BETWEEN
!                 THE ONE SHAPE PARAMETER AND THE TWO SHAPE PARAMETER
!                 CASE.  NOTE THAT DISTRIBUTIONS WITH TWO SHAPE PARAMETERS
!                 MAY ONLY HAVE A SINGLE VALUE FOR ONE OF THE SHAPE
!                 PARAMETERS.  THESE CASES NEED TO BE PLOTTED AS A SINGLE
!                 SHAPE PARAMETER CASE.
!
!              ALSO, THE TWO SHAPE PARAMETER CASE MAY BE PLOTTED AS A
!              3D PLOT OR AS A 2D PLOT WHERE EACH VALUE OF THE SECOND
!              SHAPE PARAMETER IS DRAWN AS A SEPARATE TRACE ON THE
!              2D PLOT.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/1
!     ORIGINAL VERSION--JANUARY   2010. EXTRACTED AS SEPARATE ROUTINE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICASP2
      CHARACTER*4 IPPCFO
      CHARACTER*4 IPPCAO
      CHARACTER*4 IFLAGF
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION X3D2(*)
      DIMENSION D2(*)
      DIMENSION XTEMP4(*)
      DIMENSION XTEMP5(*)
      DIMENSION X2TEMP(*)
!
      DIMENSION DISPAR(*)
      DIMENSION DISPA2(*)
      DIMENSION DISPA3(*)
      DIMENSION CORRV(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IWRITE='OFF'
      IERROR='NO'
!
      AHOLD=CPUMIN
      ATAG=0.0
!
!     CASE 1: ONE SHAPE PARAMETER
!
      IF(NUMSHA.EQ.1 .OR. IFLAG2.GT.0)THEN
        DO 1930 IDIS=1,NUMDIS
          ICNTPT=ICNTPT+1
          IF(IFLAG2.EQ.2)THEN
            X2(ICNTPT)=DISPA2(IDIS)
          ELSE
            X2(ICNTPT)=DISPAR(IDIS)
          ENDIF
          Y2(ICNTPT)=CORRV(IDIS)
          D2(ICNTPT)=REAL(NCURVE)
          IF(IFLAGF.EQ.'ON')THEN
            WRITE(IOUNI2,'(5E15.7,I8)')Y2(ICNTPT),   &
                                       XTEMP4(ICNTPT),XTEMP5(ICNTPT),   &
                                       X2(ICNTPT),D2(ICNTPT),NCURVE
          ENDIF
 1930   CONTINUE
        N2=ICNTPT
        NPLOTV=2
!
!     CASE 2: TWO SHAPE PARAMETERS, MULTI-TRACE PLOT
!
      ELSEIF(NUMSHA.EQ.2 .AND. IFLAG2.EQ.0 .AND. IPPCFO.EQ.'TRAC')THEN
        DO 1940 IDIS=1,NUMDIS
          ICNTPT=ICNTPT+1
          IF(IPPCAO.EQ.'DEFA')THEN
            IF(DISPAR(IDIS).NE.AHOLD)THEN
              ATAG=ATAG+1.0
              AHOLD=DISPAR(IDIS)
            ENDIF
          ELSE
            DO 1942 JJ=1,NUMDIS
              IF(DISPA2(IDIS).EQ.DISPA2(JJ))THEN
                ATAG=REAL(JJ)
                GO TO 1945
              ENDIF
 1942       CONTINUE
 1945       CONTINUE
          ENDIF
          Y2(ICNTPT)=CORRV(IDIS)
          IF(IPPCAO.EQ.'DEFA')THEN
            X2(ICNTPT)=DISPA2(IDIS)
            X3D2(ICNTPT)=DISPAR(IDIS)
          ELSE
            X3D2(ICNTPT)=DISPA2(IDIS)
            X2TEMP(ICNTPT)=DISPAR(IDIS)
          ENDIF
          D2(ICNTPT)=ATAG
          IF(IFLAGF.EQ.'ON')THEN
            WRITE(IOUNI2,'(6E15.7)')Y2(ICNTPT),   &
                                    XTEMP4(IDIS),XTEMP5(IDIS),   &
                                    X2(ICNTPT),X3D2(ICNTPT),   &
                                    D2(ICNTPT)
          ENDIF
 1940   CONTINUE
        N2=ICNTPT
        NPLOTV=3
!
!     CASE 3: TWO SHAPE PARAMETERS, 3D-PLOT
!
      ELSEIF(NUMSHA.EQ.2 .AND. IFLAG2.EQ.0 .AND. IPPCFO.EQ.'3D  ')THEN
        IWRITE='OFF'
        CALL DISTIN(DISPA2,NUMDIS,IWRITE,DISPA3,NTEMP,IBUGG3,IERROR)
        IF(IERROR.EQ.'YES'.OR.IERROR.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1946)
 1946     FORMAT('***** ERROR IN PCCC PLOT--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1941)
 1941     FORMAT('       INTERNAL ERROR IN DPPPC9')
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
!
        DO 1960 IDIS=1,NUMDIS
          ICNTPT=ICNTPT+1
          IF(DISPAR(IDIS).NE.AHOLD)THEN
            ATAG=ATAG+1.0
            AHOLD=DISPAR(IDIS)
          ENDIF
          Y2(ICNTPT)=CORRV(IDIS)
          IF(IPPCAO.EQ.'DEFA')THEN
            X2(ICNTPT)=DISPAR(IDIS)
            X3D2(ICNTPT)=DISPA2(IDIS)
          ELSE
            X3D2(ICNTPT)=DISPAR(IDIS)
            X2(ICNTPT)=DISPA2(IDIS)
          ENDIF
          D2(ICNTPT)=ATAG
          IF(IFLAGF.EQ.'ON')THEN
            WRITE(IOUNI2,'(6E15.7)')Y2(ICNTPT),   &
                                    XTEMP4(IDIS),XTEMP5(IDIS),   &
                                    X2(ICNTPT),X3D2(ICNTPT),   &
                                    D2(ICNTPT)
          ENDIF
 1960   CONTINUE
!
        DO 1970 J=1,NTEMP
          AHOLD=DISPA3(J)
          ATAG=ATAG+1.0
          DO 1975 IDIS=1,NUMDIS
            IF(DISPA2(IDIS).EQ.AHOLD)THEN
              ICNTPT=ICNTPT+1
              N2=N2+1
              Y2(ICNTPT)=CORRV(IDIS)
              IF(IPPCAO.EQ.'DEFA')THEN
                X2(ICNTPT)=DISPAR(IDIS)
                X3D2(ICNTPT)=DISPA2(IDIS)
              ELSE
                X3D2(ICNTPT)=DISPAR(IDIS)
                X2(ICNTPT)=DISPA2(IDIS)
              ENDIF
              D2(ICNTPT)=ATAG
            ENDIF
 1975     CONTINUE
 1970   CONTINUE
!
        NPLOTV=3
        N2=ICNTPT
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PPC9')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPPC9--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)N2,IERROR,ICASPL,ICASP2
 9012   FORMAT('N2,IERROR,ICASPL,ICASP2 = ',I8,3(2X,A4))
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,N2
          WRITE(ICOUT,9021)I,Y2(I),X2(I),D2(I)
 9021     FORMAT('I,Y2(I),X2(I),D2(I) = ',I8,2G15.7,F9.2)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPPPC9
      SUBROUTINE DPPPD(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                       IBUGG2,IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--GENERATE A PHASE PLANE DIAGRAM
!              (USED IN TIME SERIES MODELING).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89/8
!     ORIGINAL VERSION--JULY      1989.
!     UPDATED         --JUNE      1990. TEMPORARY ARRAYS TO GARBAGE COMMON
!     UPDATED         --JANUARY   2012. USE DPPARS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IAND1
      CHARACTER*4 IAND2
      CHARACTER*4 IBUGG2
      CHARACTER*4 IBUGG3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 ICASE
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=10)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION Y1(MAXOBV)
      DIMENSION Y2(MAXOBV)
!
!CCCC FOLLOWING LINES ADDED JUNE, 1990
      INCLUDE 'DPCOZZ.INC'
      EQUIVALENCE (GARBAG(IGARB1),Y1(1))
      EQUIVALENCE (GARBAG(IGARB2),Y2(1))
!CCCC END CHANGE
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      ISUBN1='DPPP'
      ISUBN2='D   '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!               *******************************************
!               **  TREAT THE PHASE PLANE DIAGRAM CASE   **
!               *******************************************
!
      IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'PPPD')THEN
        WRITE(ICOUT,999)
 999    FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPPD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ICASPL,IAND1,IAND2
   52   FORMAT('ICASPL,IAND1,IAND2 = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGG2,IBUGG3,IBUGQ,ISUBRO
   53   FORMAT('IBUGG2,IBUGG3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***************************
!               **  STEP 1--             **
!               **  EXTRACT THE COMMAND  **
!               ***************************
!
      ISTEPN='1'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PPPD')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.GE.3.AND. ICOM.EQ.'PHAS' .AND. IHARG(1).EQ.'PLAN' .AND.   &
        (IHARG(2).EQ.'DIAG' .OR. IHARG(2).EQ.'PLOT'))THEN
        ILASTC=2
      ELSE
        GO TO 9000
      ENDIF
!
      CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      IFOUND='YES'
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PPPD')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='PHASE PLANE DIAGRAM'
      MINNA=1
      MAXNA=100
      MINN2=2
      IFLAGE=1
      IFLAGM=1
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=1
      MAXNVA=2
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PPPD')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I),IVARTY(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I),IVARTY(I) = ',I8,2X,A4,A4,2X,3I8,2X,A4)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
      ICASPL='PPD1'
      ICOL=1
      NUMVA2=1
      CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                  INAME,IVARN1,IVARN2,IVARTY,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                  MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                  MAXCP4,MAXCP5,MAXCP6,   &
                  V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                  Y1,Y1,Y1,NS,NS,NS,ICASE,   &
                  IBUGG3,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      IF(NUMVAR.EQ.2)THEN
        ICASPL='PPD2'
        ICOL=2
        NUMVA2=1
        CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    Y2,Y2,Y2,NS,NS,NS,ICASE,   &
                    IBUGG3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               ********************************************************
!               **  STEP 9--                                           *
!               **  FORM THE VERTICAL AND HORIZONTAL AXIS              *
!               **  VARIABLES (Y(.) AND X(.), RESPECTIVELY) FOR THE    *
!               **  PLOT.  FORM THE CURVE DESIGNATION VARIABLE D(.)  . *
!               **  THIS WILL BE BOTH ONES FOR BOTH CASES              *
!               **  DEFINE THE NUMBER OF PLOT POINTS    (NPLOTP).      *
!               **  DEFINE THE NUMBER OF PLOT VARIABLES (NPLOTV).      *
!               ********************************************************
!
      ISTEPN='9'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PPPD')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPPPD2(Y1,Y2,NS,ICASPL,   &
                  Y,X,D,NPLOTP,NPLOTV,IBUGG3,ISUBRO,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'PPPD')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPPD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR
 9012   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2
 9013   FORMAT('NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2 = ',3I8,3(2X,A4))
        CALL DPWRST('XXX','BUG ')
        IF(NPLOTP.LE.0)THEN
          DO 9015 I=1,NPLOTP
            WRITE(ICOUT,9016)I,Y(I),X(I),D(I)
 9016       FORMAT('I,Y(I),X(I),D(I) = ',I8,3F12.5)
            CALL DPWRST('XXX','BUG ')
 9015     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPPPD
      SUBROUTINE DPPPD2(Y1,Y2,N,ICASPL,   &
                        Y,X,D,NPLOTP,NPLOTV,IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--GENERATE A PAIR OF COORDINATE VECTORS
!              THAT WILL DEFINE
!                   1) A 1-VARIABLE PHASE PLANE DIAGRAM
!                   2) A 2-VARIABLE PHASE PLANE DIAGRAM
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--JANUARY   1989.
!     UPDATED         --JANUARY   1989.  DIVISION BY 0 TRAP
!     UPDATED         --APRIL     1992.  ICASPLN TO ICASPL
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION D(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPPP'
      ISUBN2='D2  '
      IERROR='NO'
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'PPD2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,70)
   70   FORMAT('***** AT THE BEGINNING OF DPPPD2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,71)N,ICASPL
   71   FORMAT('N,ICASPL = ',I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 73 I=1,N
          WRITE(ICOUT,74)I,Y1(I),Y2(I)
   74     FORMAT('I, Y1(I), Y2(I) = ',I8,2E15.7)
          CALL DPWRST('XXX','BUG ')
   73   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
   31   FORMAT('***** ERROR IN DPPPD2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)
   32   FORMAT('      THE NUMBER OF OBSERVATIONS MUST BE AT LEAST 1;')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,34)N
   34   FORMAT('      THE ENTERED NUMBER OF OBSERVATIONS HERE = ',I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(N.GE.2)GO TO 49
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)
   46 FORMAT('***** ERROR IN DPPPD2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,47)
   47 FORMAT('      THE NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,48)
   48 FORMAT('      WAS EXACTLY EQUAL TO 1.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
   49 CONTINUE
!
!               **************************************
!               **  STEP 3--                        **
!               **  BRANCH TO THE APPROPRIATE CASE  **
!               **  AND DETERMINE PLOT COORDINATES  **
!               **************************************
!
      IF(ICASPL.EQ.'PPD1')GO TO 1100
      IF(ICASPL.EQ.'PPD2')GO TO 1200
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1011)
 1011 FORMAT('***** INTERNAL ERROR IN DPPPD2 ',   &
      'AT BRANCH POINT 1011--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1012)
 1012 FORMAT('      ICASPL SHOULD BE EITHER')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1013)
 1013 FORMAT('      PPD1  OR   PPD2, BUT IS NEITHER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1014)ICASPL
 1014 FORMAT('      ICASPL = ',A4)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
!               *****************************************
!               **  STEP 4.1--                         **
!               **  FORM THE 1-VARIABLE PHASE PLANE DIAGRAM  **
!               *****************************************
!
 1100 CONTINUE
      IMIN=1
      IMAX=N-1
      J=0
      DO 1110 I=IMIN,IMAX
      J=J+1
      IP1=I+1
      Y(J)=Y1(IP1)-Y1(I)
      X(J)=Y1(I)
      D(J)=1.0
 1110 CONTINUE
      NPLOTP=J
      NPLOTV=2
      GO TO 9000
!
!               *****************************************
!               **  STEP 4.2--                         **
!               **  FORM THE 2-VARIABLE PHASE PLANE DIAGRAM  **
!               *****************************************
!
 1200 CONTINUE
      IMIN=1
      IMAX=N-1
      J=0
      DO 1210 I=IMIN,IMAX
      J=J+1
      IP1=I+1
      ANUM=Y1(IP1)-Y1(I)
      ADEN=Y2(IP1)-Y2(I)
!
      IF(ADEN.EQ.0.0)GO TO 1230
      GO TO 1239
 1230 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1231)
 1231 FORMAT('***** ERROR IN DPPPD2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1232)
 1232 FORMAT('      A DIVISION BY ZERO WAS ATTEMPTED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1233)
 1233 FORMAT('      BECAUSE THE INPUT DATA HAD 2 REPEATED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1234)
 1234 FORMAT('      X VALUES AND THEREFORE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1235)
 1235 FORMAT('      YIELDED A 0 IN THE COMPUTATION')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1236)
 1236 FORMAT('      OF DELY / DELX   .')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1237)Y2(I)
 1237 FORMAT('      THE REPEAT WAS AT X = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
 1239 CONTINUE
!
      Y(J)=ANUM/ADEN
      X(J)=Y1(I)
      D(J)=1.0
 1210 CONTINUE
      NPLOTP=J
      NPLOTV=2
      GO TO 9000
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPPPD2--')
      CALL DPWRST('XXX','BUG ')
!CCCC THE FOLLOWING 2 LINES WERE FIXED   APRIL 1992
!CCCC WRITE(ICOUT,9012)ICASPLN,NPLOTP,IERROR
!9012 FORMAT('ICASPLN,NPLOTP,IERROR = ',A4,2I8,2X,A4)
!CCCC CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)ICASPL,NPLOTP,IERROR
 9012 FORMAT('ICASPL,NPLOTP,IERROR = ',A4,2I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
      DO 9015 I=1,NPLOTP
      WRITE(ICOUT,9016)I,Y(I),X(I),D(I)
 9016 FORMAT('I,Y(I),X(I),D(I) = ',I8,2E15.7,F9.2)
      CALL DPWRST('XXX','BUG ')
 9015 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPPPD2
      SUBROUTINE DPPPF1(Y,Y2,N,ICASPL,   &
                        SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                        SHAPE5,SHAPE6,SHAPE7,   &
                        YLOWLM,YUPPLM,A,B,MINMAX,   &
                        ICAPSW,ICAPTY,   &
                        IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                        ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                        IGETDF,ICONDF,IGOMDF,IKATDF,   &
                        IGIGDF,IGEODF,   &
                        KSLOC,KSSCAL,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--COMPUTE THE PPF VALUE AT GIVEN SET OF POINTS.  FOR
!              EXAMPLE, THIS CAN BE USED TO COMPUTE THE QUANTILES
!              FROM A BOOTSTRAP SAMPLE.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/3
!     ORIGINAL VERSION--MARCH     2010.
!     UPDATED         --JULY      2010. END EFFECTS WEIBULL
!     UPDATED         --AUGUST    2010. BRITTLE FIBER WEIBULL
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IADEDF
      CHARACTER*4 IGEPDF
      CHARACTER*4 IMAKDF
      CHARACTER*4 IBEIDF
      CHARACTER*4 ILGADF
      CHARACTER*4 ISKNDF
      CHARACTER*4 IGLDDF
      CHARACTER*4 IBGEDF
      CHARACTER*4 IGETDF
      CHARACTER*4 ICONDF
      CHARACTER*4 IGOMDF
      CHARACTER*4 IKATDF
      CHARACTER*4 IGIGDF
      CHARACTER*4 IGEODF
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 IFLAG2
!
      REAL KSLOC
      REAL KSSCAL
      REAL KSLOC2
      REAL KSSCA2
!
      DOUBLE PRECISION LANPPF
      DOUBLE PRECISION DXOUT
      DOUBLE PRECISION QUAGLO
      DOUBLE PRECISION QUAWAK
      DOUBLE PRECISION XPAR(5)
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION Y2(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
      ISUBN1='DPPP'
      ISUBN2='F1  '
      IERROR='NO'
      IWRITE='OFF'
!
      KSLOC2=KSLOC
      KSSCA2=KSSCAL
      IF(KSLOC.EQ.CPUMIN)KSLOC=0.0
      IF(KSSCAL.EQ.CPUMIN)KSSCAL=1.0
!
      CALL MINIM(Y,N,IWRITE,XMIN,IBUGA3,IERROR)
      CALL MAXIM(Y,N,IWRITE,XMAX,IBUGA3,IERROR)
!
      IFLAGD=0
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
   31   FORMAT('***** ERROR IN DPPPF1--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)
   32   FORMAT('      THE NUMBER OF OBSERVATIONS MUST BE AT LEAST 2.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,34)N
   34   FORMAT('      THE ENTERED NUMBER OF OBSERVATIONS HERE = ',I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PPF1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,71)
   71   FORMAT('***** AT THE BEGINNING OF DPPPF1--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,72)ICASPL,ICAPSW,ICAPTY,N,MINMAX
   72   FORMAT('ICASPL,ICAPSW,ICAPTY,N,MINMAX = ',3(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,74)KSLOC,KSSCAL,SHAPE1,SHAPE2
   74   FORMAT('KSLOC,KSSCAL,SHAPE1,SHAPE2 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 85 I=1,N
          WRITE(ICOUT,86)I,Y(I)
   86     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   85   CONTINUE
      ENDIF
!
!               ************************************************
!               **  STEP 2.1--                                **
!               **  COMPUTE CDF VALUE AT GIVEN POINTS         **
!               ************************************************
!
      ZSCALE=B - A
      ZLOC=A
!
      IF(ICASPL.EQ.'UNIF')THEN
        DO 1010 I=1,N
          CALL UNIPPF(Y(I),Y2(I))
          Y2(I)=KSLOC + ZSCALE*Y2(I)
 1010   CONTINUE
!
      ELSEIF(ICASPL.EQ.'NORM')THEN
        DO 1020 I=1,N
          CALL NODPPF(DBLE(Y(I)),DXOUT)
          Y2(I)=REAL(DXOUT)
          Y2(I)=KSLOC + KSSCAL*Y2(I)
 1020   CONTINUE
!
      ELSEIF(ICASPL.EQ.'LOGI')THEN
        DO 1030 I=1,N
          CALL LOGPPF(Y(I),Y2(I))
          Y2(I)=KSLOC + KSSCAL*Y2(I)
 1030   CONTINUE
!
      ELSEIF(ICASPL.EQ.'DEXP')THEN
        DO 1040 I=1,N
          CALL DEXPPF(Y(I),Y2(I))
          Y2(I)=KSLOC + KSSCAL*Y2(I)
 1040   CONTINUE
!
      ELSEIF(ICASPL.EQ.'CAUC')THEN
        DO 1050 I=1,N
          CALL CAUPPF(Y(I),Y2(I))
          Y2(I)=KSLOC + KSSCAL*Y2(I)
 1050   CONTINUE
!
      ELSEIF(ICASPL.EQ.'TULA')THEN
        DO 1060 I=1,N
          CALL LAMPPF(Y(I),SHAPE1,Y2(I))
          Y2(I)=KSLOC + KSSCAL*Y2(I)
 1060   CONTINUE
!
      ELSEIF(ICASPL.EQ.'LOGN' .OR. ICASPL.EQ.'3LGN')THEN
        DO 1070 I=1,N
          CALL LGNPPF(Y(I),SHAPE1,Y2(I))
          Y2(I)=KSLOC + KSSCAL*Y2(I)
 1070   CONTINUE
!
      ELSEIF(ICASPL.EQ.'HNOR')THEN
        DO 1080 I=1,N
          CALL HFNPPF(Y(I),Y2(I))
          Y2(I)=KSLOC + KSSCAL*Y2(I)
 1080   CONTINUE
!
      ELSEIF(ICASPL.EQ.'TPP')THEN
        DO 1090 I=1,N
          CALL TPPF(Y(I),SHAPE1,Y2(I))
          Y2(I)=KSLOC + KSSCAL*Y2(I)
 1090   CONTINUE
!
      ELSEIF(ICASPL.EQ.'CHIS')THEN
        DO 1100 I=1,N
          CALL CHSPPF(Y(I),INT(SHAPE1+0.1),Y2(I))
          Y2(I)=KSLOC + KSSCAL*Y2(I)
 1100   CONTINUE
!
      ELSEIF(ICASPL.EQ.'FPP')THEN
        DO 1110 I=1,N
          CALL FPPF(Y(I),INT(SHAPE1+0.1),INT(SHAPE2+0.1),Y2(I))
          Y2(I)=KSLOC + KSSCAL*Y2(I)
 1110   CONTINUE
!
      ELSEIF(ICASPL.EQ.'EXPO' .OR. ICASPL.EQ.'1EXP')THEN
        DO 1120 I=1,N
          CALL EXPPPF(Y(I),Y2(I))
          Y2(I)=KSLOC + KSSCAL*Y2(I)
 1120   CONTINUE
!
      ELSEIF(ICASPL.EQ.'GAMM' .OR. ICASPL.EQ.'3GAM')THEN
        DO 1130 I=1,N
          CALL GAMPPF(Y(I),SHAPE1,Y2(I))
          Y2(I)=KSLOC + KSSCAL*Y2(I)
 1130   CONTINUE
!
      ELSEIF(ICASPL.EQ.'BETA')THEN
        DO 1140 I=1,N
          CALL BETPPF(Y(I),SHAPE1,SHAPE2,Y2(I))
          Y2(I)=KSLOC + ZSCALE*Y2(I)
 1140   CONTINUE
!
      ELSEIF(ICASPL.EQ.'WEIB' .OR. ICASPL.EQ.'3WEI')THEN
        DO 1150 I=1,N
          CALL WEIPPF(Y(I),SHAPE1,MINMAX,Y2(I))
          Y2(I)=KSLOC + KSSCAL*Y2(I)
 1150   CONTINUE
!
      ELSEIF(ICASPL.EQ.'EV1 ')THEN
        DO 1160 I=1,N
          CALL EV1PPF(Y(I),MINMAX,Y2(I))
          Y2(I)=KSLOC + KSSCAL*Y2(I)
 1160   CONTINUE
!
      ELSEIF(ICASPL.EQ.'EV2 ' .OR. ICASPL.EQ.'3EV2')THEN
        DO 1170 I=1,N
          CALL EV2PPF(Y(I),SHAPE1,MINMAX,Y2(I))
          Y2(I)=KSLOC + KSSCAL*Y2(I)
 1170   CONTINUE
!
      ELSEIF(ICASPL.EQ.'PARE')THEN
        ZLOC=SHAPE2
        IF(ZLOC.GT.XMIN)ZLOC=XMIN
        DO 1180 I=1,N
          CALL PARPPF(Y(I),SHAPE1,ZLOC,Y2(I))
          Y2(I)=KSLOC + KSSCAL*Y2(I)
 1180   CONTINUE
!
      ELSEIF(ICASPL.EQ.'BINO')THEN
        IF(IFLAGD.EQ.1)GO TO 8000
        DO 1190 I=1,N
          CALL BINPPF(DBLE(Y(I)),DBLE(SHAPE1),INT(SHAPE2+0.1),DXOUT)
          Y2(I)=REAL(DXOUT)
 1190   CONTINUE
!
      ELSEIF(ICASPL.EQ.'GEOM')THEN
        IF(IFLAGD.EQ.1)GO TO 8000
        IF(IGEODF.EQ.'DLMF')THEN
          DO 1200 I=1,N
            CALL GE2PPF(DBLE(Y(I)),DBLE(SHAPE1),DXOUT)
            Y2(I)=REAL(DXOUT)
 1200     CONTINUE
        ELSE
          DO 1205 I=1,N
            CALL GEOPPF(DBLE(Y(I)),DBLE(SHAPE1),DXOUT)
            Y2(I)=REAL(DXOUT)
 1205     CONTINUE
        ENDIF
!
      ELSEIF(ICASPL.EQ.'POIS')THEN
        IF(IFLAGD.EQ.1)GO TO 8000
        DO 1210 I=1,N
          CALL POIPPF(Y(I),SHAPE1,Y2(I))
 1210   CONTINUE
!
      ELSEIF(ICASPL.EQ.'NEBI')THEN
        IF(IFLAGD.EQ.1)GO TO 8000
        DO 1220 I=1,N
          CALL NBPPF(DBLE(Y(I)),DBLE(SHAPE1),DBLE(SHAPE2),DXOUT)
          Y2(I)=REAL(DXOUT)
 1220   CONTINUE
!
      ELSEIF(ICASPL.EQ.'SEMI')THEN
        DO 1230 I=1,N
          CALL SEMPPF(Y(I),KSSCAL,Y2(I))
          Y2(I)=KSLOC + Y2(I)
 1230   CONTINUE
!
      ELSEIF(ICASPL.EQ.'TRIA')THEN
        IF(A.EQ.CPUMIN .OR. B.EQ.CPUMAX)THEN
          ZLOWLM=-1.0
          ZUPPLM=1.0
        ELSE
          ZLOWLM=MIN(A,B)
          ZUPPLM=MAX(A,B)
        ENDIF
        IF(ZLOWLM.GT.XMIN)ZLOWLM=XMIN
        IF(ZUPPLM.LT.XMAX)ZUPPLM=XMAX
        IF(SHAPE1.LT.ZLOWLM .OR. SHAPE1.GT.ZUPPLM)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,31)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1343)
 1343     FORMAT('       FOR THE TRIANGULAR DISTRIBUTION, THE VALUE')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1344)
 1344     FORMAT('       OF THE SHAPE PARAMETER IS OUTSIDE THE ',   &
                 'INTERVAL')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1345)
 1345     FORMAT('       OF THE LOWER AND UPPER LIMIT PARAMETERS.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1346)SHAPE1
 1346     FORMAT('       THE VALUE OF THE SHAPE PARAMETER       = ',   &
               G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1347)ZLOWLM
 1347     FORMAT('       THE VALUE OF THE LOWER LIMIT PARAMETER = ',   &
                 G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1348)ZUPPLM
 1348     FORMAT('       THE VALUE OF THE LOWER LIMIT PARAMETER = ',   &
                 G15.7)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        DO 1240 I=1,N
          CALL TRIPPF(Y(I),SHAPE1,ZLOWLM,ZUPPLM,Y2(I))
 1240   CONTINUE
!
      ELSEIF(ICASPL.EQ.'INGA' .OR. ICASPL.EQ.'3IGA')THEN
        DO 1250 I=1,N
          CALL IGPPF(DBLE(Y(I)),DBLE(SHAPE1),DBLE(SHAPE2),DXOUT)
          Y2(I)=KSLOC + KSSCAL*REAL(DXOUT)
 1250   CONTINUE
!
      ELSEIF(ICASPL.EQ.'WALD')THEN
        ATEMP=1.0
        DO 1260 I=1,N
          CALL IGPPF(DBLE(Y(I)),DBLE(SHAPE1),DBLE(ATEMP),DXOUT)
