        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8011)ICASPL
 8011   FORMAT('      UNKNOWN DISTRIBUTION -- ',A40)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      GO TO 9000
!
!     SET AN ERROR FLAG TO INDICATE A DISCRETE DISTRIBUTION
!     IS NOT TO BE PROCESSED.
!
 8000 CONTINUE
      IFLAGD=99
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      KSLOC=KSLOC2
      KSSCAL=KSSCA2
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PPF1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPPF1--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICASPL,N,MINMAX,IERROR
 9012   FORMAT('ICASPL,N,MINMAX,IERROR = ',A4,2X,2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)KSLOC,KSSCAL
 9014   FORMAT('KSLOC,KSSCAL = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,N
          WRITE(ICOUT,9021)I,Y(I),Y2(I)
 9021     FORMAT('I,Y(I),Y2(I), = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPPPF1
      SUBROUTINE DPPPGF(ICASPL,IDIST,NUMSHA,IFORSW,IADCVM,IGOFFS,   &
