                        KSLOC,KSSCAL,ICAPSW,ICAPTY,IRTFFF,IRTFFP,   &
                        STATVA,STATV2,CDF1,CDF2,CDF3,CDF4,   &
                        PVAL,YSTAT,NMCSAM,NCNT,   &
                        XTEMP,MAXNXT,   &
                        IBUGA3,ISUBRO,IERROR)
