      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAG1
      LOGICAL IFLAG2
      LOGICAL IFLAG3
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ALPHA/   &
       0.0, 0.5, 1.0, 2.5, 5.0, 10.0, 25.0, 50.0, 75.0,   &
        90.0, 95.0, 97.5, 99.0, 99.5/
!
!-----START POINT-----------------------------------------------------
!
!
      ISUBN1='DPPP'
      ISUBN2='GF  '
      IERROR='NO'
      IWRITE='OFF'
      CALL DPCONA(92,IBASLC)
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PPGF')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,71)
   71   FORMAT('***** AT THE BEGINNING OF DPPPGF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,72)ICASPL,IDIST
   72   FORMAT('ICASPL,IDIST = ',A4,2X,A60)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,73)N,MINMAX,XMIN,XMAX,XMEAN,XSD
   73   FORMAT('N,MINMAX,XMIN,XMAX,XMEAN,XSD = ',2I8,4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,75)YLOWLM,YUPPLM
   75   FORMAT('YLOWLM,YUPPLM = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *******************************************
!               **   STEP 1--                            **
!               **   DETERMINE CRITICAL VALUES FROM      **
!               **   PRE-COMPUTED TABLES.  CURRENTLY NOT **
!               **   SUPPORTED, BUT MAY ADD ABILITY TO   **
!               **   READ FROM EXTERNAL FILES (FILES ARE **
!               **   CURRENTLY AVAILABLE FOR NORMAL AND  **
!               **   UNIFORM DISTRIBUTIONS).             **
!               *******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PPGF')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IADCVT=IADCVM
      STATV2=STATVA
!
!     COMMENT OUT FOR NOW.  CURRENTLY, CRITICAL VALUES ALWAYS
!     GENERATED FROM SIMULATION.
!
!CCCC IF(IADCVM.EQ.'TABL')THEN
!CCCC   IERROR='YES'
!CCCC   GO TO 9000
!CCCC ELSE
!CCCC   IADCVM='SIMU'
!CCCC ENDIF
!
!               *******************************************
!               **   STEP 41--                           **
!               **   WRITE OUT TABLES FOR PPCC GOODNESS  **
!               **   OF FIT TEST                         **
!               *******************************************
!
      ISTEPN='41'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PPGF')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE='PPCC Goodness of Fit Test'
      NCTITL=25
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Response Variable: '
      WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(1)(1:4)
      WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(1)(1:4)
      NCTEXT(ICNT)=27
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      DO 4101 I=1,NREPL
        ICNT=ICNT+1
        ITEXT(ICNT)='Factor Variable  : '
        WRITE(ITEXT(ICNT)(17:17),'(I1)')I
        WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(I+1)(1:4)
        WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(I+1)(1:4)
        NCTEXT(ICNT)=27
        AVALUE(ICNT)=PID(I+1)
        IDIGIT(ICNT)=NUMDIG
 4101 CONTINUE
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='H0: The distribution fits the data'
      NCTEXT(ICNT)=34
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Ha: The distribution does not fit the data'
      NCTEXT(ICNT)=43
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      IEND=46
      DO 4111 I=46,1,-1
        IF(IDIST(I:I).NE.' ')THEN
          IEND=I
          GO TO 4119
        ENDIF
 4111 CONTINUE
      IEND=1
 4119 CONTINUE
      CALL EXTBOU(ICASPL,IBOUND)
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)(1:14)='Distribution: '
      ISTRT=15
      ISTOP=15+IEND-1
      ITEXT(ICNT)(ISTRT:ISTOP)=IDIST(1:IEND)
      NCTEXT(ICNT)=ISTOP
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      IF(IBOUND.EQ.0)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Location Parameter:'
        NCTEXT(ICNT)=19
        AVALUE(ICNT)=KSLOC
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Scale Parameter:'
        NCTEXT(ICNT)=16
        AVALUE(ICNT)=KSSCAL
        IDIGIT(ICNT)=NUMDIG
      ELSE
        ICNT=ICNT+1
        ITEXT(ICNT)='Lower Limit Parameter:'
        NCTEXT(ICNT)=22
        AVALUE(ICNT)=A
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Upper Limit Parameter:'
        NCTEXT(ICNT)=22
        AVALUE(ICNT)=B
        IDIGIT(ICNT)=NUMDIG
      ENDIF
      IF(NUMSHA.GE.1)THEN
        DO 4140 I=1,NUMSHA
          ICNT=ICNT+1
          ITEXT(ICNT)='Shape Parameter  :'
          WRITE(ITEXT(ICNT)(17:17),'(I1)')I
          NCTEXT(ICNT)=18
          IF(I.EQ.1)THEN
            AVALUE(ICNT)=SHAPE1
          ELSEIF(I.EQ.2)THEN
            AVALUE(ICNT)=SHAPE2
          ELSEIF(I.EQ.3)THEN
            AVALUE(ICNT)=SHAPE3
          ELSEIF(I.EQ.4)THEN
            AVALUE(ICNT)=SHAPE4
          ELSEIF(I.EQ.5)THEN
            AVALUE(ICNT)=SHAPE5
          ELSEIF(I.EQ.6)THEN
            AVALUE(ICNT)=SHAPE6
          ELSEIF(I.EQ.7)THEN
            AVALUE(ICNT)=SHAPE7
          ENDIF
          IDIGIT(ICNT)=NUMDIG
 4140   CONTINUE
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Minimum:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=XMIN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Maximum:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=XMAX
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Mean:'
      NCTEXT(ICNT)=12
      AVALUE(ICNT)=XMEAN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample SD:'
      NCTEXT(ICNT)=10
      AVALUE(ICNT)=XSD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='PPCC Test Statistic Value:'
      NCTEXT(ICNT)=38
      AVALUE(ICNT)=STATVA
      IDIGIT(ICNT)=NUMDIG
!
!CCCC IF(IADCVM.EQ.'SIMU' .AND. IGOFFM.NE.'NULL')THEN
      IF(IGOFFM.NE.'NULL')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Number of Monte Carlo Simulations:'
        NCTEXT(ICNT)=34
        AVALUE(ICNT)=REAL(NMCSAM)
        IDIGIT(ICNT)=NUMDIG
        IF(NMCSAM.NE.NCNT)THEN
          ICNT=ICNT+1
          ITEXT(ICNT)='Number of Samples Rejected:'
          NCTEXT(ICNT)=27
          AVALUE(ICNT)=REAL(NMCSAM-NCNT)
          IDIGIT(ICNT)=NUMDIG
        ENDIF
        ICNT=ICNT+1
        ITEXT(ICNT)='CDF Value:'
        NCTEXT(ICNT)=10
        STACDF=1.0 - PVAL
        AVALUE(ICNT)=STACDF
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='P-Value:'
        NCTEXT(ICNT)=7
        AVALUE(ICNT)=PVAL
        IDIGIT(ICNT)=NUMDIG
      ENDIF
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      NUMROW=ICNT
      DO 2310 I=1,NUMROW
        NTOT(I)=15
 2310 CONTINUE
!
      ITITLZ=' '
      NCTITZ=0
      IFRST=.TRUE.
      IF(IGOFFM.NE.'NULL')THEN
        IF(IGOFFS.EQ.'ON')THEN
          ITITLZ='(Fully Specified Model)'
          NCTITZ=23
        ELSE
          ITITLZ='(Parameters Estimated from the Data)'
          NCTITZ=36
        ENDIF
!CCCC   IF(IADCVM.EQ.'SIMU')THEN
          ILAST=.TRUE.
!CCCC   ELSE
!CCCC     ILAST=.FALSE.
!CCCC   ENDIF
      ELSE
        ILAST=.TRUE.
      ENDIF
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IGOFFM.EQ.'NULL')GO TO 9000
!
      ITITLE=' '
      NCTITL=0
      ITITL9=' '
      NCTIT9=0
!
!CCCC IF(IADCVM.EQ.'SIMU')THEN
        ITITLE(1:44)='Percent Points of the Reference Distribution'
        NCTITL=44
        NUMLIN=1
        NUMROW=14
        NUMCOL=3
        ITITL2(1,1)='Percent Point'
        ITITL2(1,2)=' '
        ITITL2(1,3)='Value'
        NCTIT2(1,1)=13
        NCTIT2(1,2)=1
        NCTIT2(1,3)=5
!
        NMAX=0
        DO 2521 I=1,NUMCOL
          VALIGN(I)='b'
          ALIGN(I)='r'
          NTOT(I)=15
          IF(I.EQ.2)NTOT(I)=5
          NMAX=NMAX+NTOT(I)
          IDIGIT(I)=NUMDIG
          ITYPCO(I)='NUME'
 2521   CONTINUE
        ITYPCO(2)='ALPH'
        IDIGIT(1)=1
        IDIGIT(3)=4
        DO 2523 I=1,NUMROW
          DO 2525 J=1,NUMCOL
            NCVALU(I,J)=0
            IVALUE(I,J)=' '
            NCVALU(I,J)=0
            AMAT(I,J)=0.0
            IF(J.EQ.1)THEN
              AMAT(I,J)=ALPHA(I)
            ELSEIF(J.EQ.2)THEN
              IVALUE(I,J)='='
              NCVALU(I,J)=1
            ELSEIF(J.EQ.3)THEN
              IF(I.GE.2)THEN
!CCCC           P100=100.0 - ALPHA(I)
                P100=ALPHA(I)
                CALL PERCEN(P100,YSTAT,NCNT,IWRITE,XTEMP,MAXNXT,   &
                            XPERC,IBUGA3,IERROR)
                XPERC2=RND(XPERC,4)
                AMAT(I,J)=XPERC2
              ENDIF
            ENDIF
 2525     CONTINUE
 2523   CONTINUE
!
        IWHTML(1)=150
        IWHTML(2)=50
        IWHTML(3)=150
        IWRTF(1)=2000
        IWRTF(2)=IWRTF(1)+500
        IWRTF(3)=IWRTF(2)+2000
        IFRST=.TRUE.
        ILAST=.FALSE.
!
        CALL DPDTA4(ITITL9,NCTIT9,   &
                    ITITLE,NCTITL,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,NUMROW,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    ISUBRO,IBUGA3,IERROR)
!
        CDF1=AMAT(3,3)
        CDF2=AMAT(4,3)
        CDF3=AMAT(5,3)
        CDF4=AMAT(6,3)
!
        ITITL9=' '
        NCTIT9=0
        ITITLE='Conclusions (Lower 1-Tailed Test)'
        NCTITL=33
        NUMLIN=1
        NUMROW=4
        NUMCOL=4
        ITITL2(1,1)='Alpha'
        ITITL2(1,2)='CDF'
        ITITL2(1,3)='Critical Value'
        ITITL2(1,4)='Conclusion'
        NCTIT2(1,1)=5
        NCTIT2(1,2)=3
        NCTIT2(1,3)=14
        NCTIT2(1,4)=10
!
        NMAX=0
        DO 2821 I=1,NUMCOL
          VALIGN(I)='b'
          ALIGN(I)='r'
          NTOT(I)=15
          IF(I.EQ.1 .OR. I.EQ.2)NTOT(I)=7
          IF(I.EQ.3)NTOT(I)=17
          NMAX=NMAX+NTOT(I)
!CCCC     IDIGIT(I)=NUMDIG
          IDIGIT(I)=4
          ITYPCO(I)='ALPH'
 2821   CONTINUE
        ITYPCO(3)='NUME'
        IDIGIT(1)=0
        IDIGIT(2)=0
        DO 2823 I=1,NUMROW
          DO 2825 J=1,NUMCOL
            NCVALU(I,J)=0
            IVALUE(I,J)=' '
            NCVALU(I,J)=0
            AMAT(I,J)=0.0
 2825     CONTINUE
 2823   CONTINUE
        IVALUE(1,1)='1%'
        IVALUE(2,1)='2.5%'
        IVALUE(3,1)='5%'
        IVALUE(4,1)='10%'
        NCVALU(1,1)=2
        NCVALU(2,1)=4
        NCVALU(3,1)=2
        NCVALU(4,1)=3
        IVALUE(1,2)='1%'
        IVALUE(2,2)='2.5%'
        IVALUE(3,2)='5%'
        IVALUE(4,2)='10%'
        NCVALU(1,2)=2
        NCVALU(2,2)=4
        NCVALU(3,2)=2
        NCVALU(4,2)=3
        IVALUE(1,4)='Accept H0'
        IVALUE(2,4)='Accept H0'
        IVALUE(3,4)='Accept H0'
        IVALUE(4,4)='Accept H0'
        NCVALU(1,4)=9
        NCVALU(2,4)=9
        NCVALU(3,4)=9
        NCVALU(4,4)=9
        IF(STATVA.LT.CDF1)IVALUE(1,4)='Reject H0'
        IF(STATVA.LT.CDF2)IVALUE(2,4)='Reject H0'
        IF(STATVA.LT.CDF3)IVALUE(3,4)='Reject H0'
        IF(STATVA.LT.CDF4)IVALUE(4,4)='Reject H0'
        AMAT(1,3)=RND(CDF1,IDIGIT(3))
        AMAT(2,3)=RND(CDF2,IDIGIT(3))
        AMAT(3,3)=RND(CDF3,IDIGIT(3))
        AMAT(4,3)=RND(CDF4,IDIGIT(3))
!
        IWHTML(1)=150
        IWHTML(2)=150
        IWHTML(3)=150
        IWHTML(4)=150
        IWRTF(1)=1500
        IWRTF(2)=IWRTF(1)+1500
        IWRTF(3)=IWRTF(2)+2000
        IWRTF(4)=IWRTF(3)+2000
        IFRST=.FALSE.
!
!       FOR LATEX, WE WANT TO ENSURE THAT TRAILING LINE IS PART
!       OF THE TABLE SO THAT IT WILL BE PRINTED IN THE PROPER PLACE.
!
        IF(ICAPTY.EQ.'LATE')THEN
          ILAST=.FALSE.
        ELSE
          ILAST=.TRUE.
        ENDIF
!
        CALL DPDTA4(ITITL9,NCTIT9,   &
                    ITITLE,NCTITL,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,NUMROW,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    ISUBRO,IBUGA3,IERROR)
!
        IF(IPRINT.EQ.'ON')THEN
!
        ITITLE(1:26)='*Critical Values Based on '
        WRITE(ITITLE(27:34),'(I8)')NCNT
        ITITLE(35:58)=' Monte Carlo Simulations'
        NCTITL=58
!
        IF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'HTML')THEN
          CALL DPHTMV(ITITLE,NCTITL,CPUMIN,NUMDIG)
        ELSEIF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'LATE')THEN
          CALL DPLATV(ITITLE,NCTITL,CPUMIN,NUMDIG)
          IFLAG1=.FALSE.
          IFLAG2=.TRUE.
          IFLAG3=.TRUE.
          CALL DPLATZ(IFLAG1,IFLAG2,IFLAG3,NHEAD)
        ELSEIF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'RTF ')THEN
!
          IRTFMD='OFF'
          IPTSZ=14
          WRITE(ICOUT,8199)IBASLC,IPTSZ
 8199     FORMAT(A1,'fs',I2)
          CALL DPWRST(ICOUT,'WRIT')
          IF(IRTFFF.EQ.'Courier New')THEN
            ITEMP=1
          ELSEIF(IRTFFF.EQ.'Lucida Console')THEN
            ITEMP=8
          ENDIF
          WRITE(ICOUT,8301)IBASLC,ITEMP
          CALL DPWRST(ICOUT,'WRIT')
          CALL DPRTFZ(ITITLE,NCTITL,CPUMIN,NUMDIG)
!CCCC     CALL DPRTF6(NHEAD)
!CCCC     CALL DPRTF6(NHEAD)
          IF(IRTFFP.EQ.'Times New Roman')THEN
            ITEMP=0
          ELSEIF(IRTFFP.EQ.'Lucida Sans')THEN
            ITEMP=6
          ELSEIF(IRTFFP.EQ.'Arial')THEN
            ITEMP=2
          ELSEIF(IRTFFP.EQ.'Bookman')THEN
            ITEMP=3
          ELSEIF(IRTFFP.EQ.'Georgia')THEN
            ITEMP=4
          ELSEIF(IRTFFP.EQ.'Tahoma')THEN
            ITEMP=5
          ELSEIF(IRTFFP.EQ.'Verdana')THEN
            ITEMP=7
          ENDIF
          WRITE(ICOUT,8301)IBASLC,ITEMP
 8301     FORMAT(A1,'f',I1)
          CALL DPWRST(ICOUT,'WRIT')
!
!         END TABLE AND RESET "ASIS" MODE
!
          IF(IRTFFF.EQ.'Courier New')THEN
            ITEMP=1
          ELSEIF(IRTFFF.EQ.'Lucida Console')THEN
            ITEMP=8
          ENDIF
          WRITE(ICOUT,8091)IBASLC,ITEMP
 8091     FORMAT(A1,'f',I1)
          CALL DPWRST(ICOUT,'WRIT')
!
          CALL DPRTF6(NHEAD)
          CALL DPRTF6(NHEAD)
!
          IRTFMD='VERB'
!
        ELSE
          WRITE(ICOUT,2589)ITITLE(1:58)
 2589     FORMAT(A60)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        ENDIF
!
!CCCC ELSE
!
!CCCC   ITITL9=' '
!CCCC   NCTIT9=0
!CCCC   ITITLE='Conclusions (Upper 1-Tailed Test)'
!CCCC   NCTITL=33
!CCCC   NUMLIN=1
!CCCC   NUMROW=4
!CCCC   NUMCOL=4
!CCCC   ITITL2(1,1)='Alpha'
!CCCC   ITITL2(1,2)='CDF'
!CCCC   ITITL2(1,3)='Critical Value'
!CCCC   ITITL2(1,4)='Conclusion'
!CCCC   NCTIT2(1,1)=5
!CCCC   NCTIT2(1,2)=3
!CCCC   NCTIT2(1,3)=14
!CCCC   NCTIT2(1,4)=10
!
!CCCC   NMAX=0
!CCCC   DO2421I=1,NUMCOL
!CCCC     VALIGN(I)='b'
!CCCC     ALIGN(I)='r'
!CCCC     NTOT(I)=15
!CCCC     IF(I.EQ.1 .OR. I.EQ.2)NTOT(I)=7
!CCCC     IF(I.EQ.3)NTOT(I)=17
!CCCC     NMAX=NMAX+NTOT(I)
!CCCC     IDIGIT(I)=NUMDIG
!CCCC     IDIGIT(I)=3
!CCCC     ITYPCO(I)='ALPH'
!2421   CONTINUE
!CCCC   ITYPCO(3)='NUME'
!CCCC   IDIGIT(1)=0
!CCCC   IDIGIT(2)=0
!CCCC   DO2423I=1,NUMROW
!CCCC     DO2425J=1,NUMCOL
!CCCC       NCVALU(I,J)=0
!CCCC       IVALUE(I,J)=' '
!CCCC       NCVALU(I,J)=0
!CCCC       AMAT(I,J)=0.0
!2425     CONTINUE
!2423   CONTINUE
!CCCC   IVALUE(1,1)='10%'
!CCCC   IVALUE(2,1)='5%'
!CCCC   IVALUE(3,1)='2.5%'
!CCCC   IVALUE(4,1)='1%'
!CCCC   IVALUE(1,2)='90%'
!CCCC   IVALUE(2,2)='95%'
!CCCC   IVALUE(3,2)='97.5%'
!CCCC   IVALUE(4,2)='99%'
!CCCC   NCVALU(1,1)=3
!CCCC   NCVALU(2,1)=2
!CCCC   NCVALU(3,1)=4
!CCCC   NCVALU(4,1)=2
!CCCC   NCVALU(1,2)=3
!CCCC   NCVALU(2,2)=3
!CCCC   NCVALU(3,2)=5
!CCCC   NCVALU(4,2)=3
!CCCC   IVALUE(1,4)='Accept H0'
!CCCC   IVALUE(2,4)='Accept H0'
!CCCC   IVALUE(3,4)='Accept H0'
!CCCC   IVALUE(4,4)='Accept H0'
!CCCC   NCVALU(1,4)=9
!CCCC   NCVALU(2,4)=9
!CCCC   NCVALU(3,4)=9
!CCCC   NCVALU(4,4)=9
!CCCC   IF(STATVA.GT.CDF1)IVALUE(1,4)='Reject H0'
!CCCC   IF(STATVA.GT.CDF2)IVALUE(2,4)='Reject H0'
!CCCC   IF(STATVA.GT.CDF3)IVALUE(3,4)='Reject H0'
!CCCC   IF(STATVA.GT.CDF4)IVALUE(4,4)='Reject H0'
!CCCC   AMAT(1,3)=RND(CDF1,IDIGIT(3))
!CCCC   AMAT(2,3)=RND(CDF2,IDIGIT(3))
!CCCC   AMAT(3,3)=RND(CDF3,IDIGIT(3))
!CCCC   AMAT(4,3)=RND(CDF4,IDIGIT(3))
!
!CCCC   IWHTML(1)=150
!CCCC   IWHTML(2)=150
!CCCC   IWHTML(3)=150
!CCCC   IWHTML(4)=150
!CCCC   IWRTF(1)=1500
!CCCC   IWRTF(2)=IWRTF(1)+1500
!CCCC   IWRTF(3)=IWRTF(2)+2000
!CCCC   IWRTF(4)=IWRTF(3)+2000
!CCCC   IFRST=.FALSE.
!CCCC   ILAST=.TRUE.
!
!CCCC   CALL DPDTA4(ITITL9,NCTIT9,
!CCCC1              ITITLE,NCTITL,ITITL2,NCTIT2,
!CCCC1              MAXLIN,NUMLIN,NUMCLI,NUMCOL,
!CCCC1              IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,NUMROW,
!CCCC1              IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,
!CCCC1              ICAPSW,ICAPTY,IFRST,ILAST,
!CCCC1              ISUBRO,IBUGA3,IERROR)
!
!CCCC ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IADCVM=IADCVT
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PPGF')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPPGF--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPPGF
      SUBROUTINE DPPRCL(MAXNXT,ICASAN,ANOPL1,ANOPL2,ICAPSW,IFORSW,   &
                        ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
!
!     PURPOSE--GENERATE (SYMMETRIC) CONFIDENCE LIMITS FOR THE
!              PROPORTION OF SUCCESSES FOR PROBABILITY VALUE
!              P = .90, .95, .99, .999, AND .9999.
!              ALSO HANDLE THE DIFFERENCE OF TWO PROPORTIONS.
!              NOTE: 1 = SUCCESS
!                    0 = FAILURE
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--99/3
!     ORIGINAL VERSION--MARCH     1999.
!     UPDATED         --AUGUST    2008. REFORMAT OUTPUT
!                                       SUPPORT FOR HTML, LATEX,
!                                       RTF FORMATTED OUTPUT
!                                       ACCEPT DATA IN SUMMARY FORM
!     UPDATED         --FEBRUARY  2011. USE DPPARS, DPPAR3
!     UPDATED         --NOVEMBER  2017. SUPPORT AGRESTI-CAFO ADJUSTED
!                                       INTERVAL
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASAN
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 ICASE
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=20)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPPR'
      ISUBN2='CL  '
      IFOUND='YES'
      IERROR='NO'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!               ***************************************************
!               **  TREAT THE PROPORTION CONFIDENCE LIMITS CASE  **
!               ***************************************************
!
      IF(ISUBRO.EQ.'PRCL'.OR.IBUGA2.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPRCL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ISUBRO
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)MAXNXT,ICASAN
   55   FORMAT('MAXNXT,ICASAN = ',I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************
!               **  STEP 4--                   **
!               **  EXTRACT THE VARIABLE LIST  **
!               *********************************
!
      ISTEPN='4'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PRCL')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICASAN.EQ.'DPRO')THEN
        INAME='DIFFERENCE OF PROPORTIONS CONFIDENCE LIM'
      ELSE
        INAME='PROPORTION CONFIDENCE LIMITS'
      ENDIF
      MINNA=1
      MAXNA=100
      MINN2=2
      IFLAGE=0
      IFLAGM=1
      JMIN=1
      JMAX=NUMARG
      IF(ICASAN.EQ.'DPRO')THEN
        MINNVA=2
        MAXNVA=4
        IFLAGP=9
      ELSE
        MINNVA=1
        MAXNVA=2
        IFLAGP=1
      ENDIF
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PRCL')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I),PVAR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I),PVAR(I) = ',I8,2X,A4,A4,2X,3I8,G15.7)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               ***********************************
!               **  STEP 22--                    **
!               **  CHECK FOR PROPER VALUES FOR  **
!               **  INPUT PARAMETERS             **
!               ***********************************
!
      IF(IVARTY(1).EQ.'PARA' .OR. IVARTY(1).EQ.'NUMB')THEN
        P1=PVAR(1)
        AN1=PVAR(2)
        N1=INT(AN1+0.1)
        IF(ICASAN.EQ.'DPRO')THEN
          P2=PVAR(3)
          AN2=PVAR(4)
          N2=INT(AN2+0.1)
        ENDIF
        ICASE='PARA'
!
        ISTEPN='22'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'BNTE')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IF(P1.LT.0.0 .OR. P1.GT.1.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          IF(ICASAN.EQ.'PROP')THEN
            WRITE(ICOUT,2201)
 2201       FORMAT('***** ERROR FROM PROPORTION CONFIDENCE LIMITS--')
          ELSE
            WRITE(ICOUT,2202)
 2202       FORMAT('***** ERROR FROM DIFFERENCE OF PROPORTION ',   &
                   'CONFIDENCE LIMITS--')
          ENDIF
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2203)
 2203     FORMAT('      THE VALUE OF THE FIRST PARAMETER (P1 = THE ',   &
                 'PROBABILITY OF SUCCESS')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2204)
 2204     FORMAT('      FOR THE FIRST VARIABLE MUST BE IN THE ',   &
                 'INTERVAL (0,1).')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2205)P1
 2205     FORMAT('      P1 = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
!
        ELSEIF(N1.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          IF(ICASAN.EQ.'PROP')THEN
            WRITE(ICOUT,2201)
          ELSE
            WRITE(ICOUT,2202)
          ENDIF
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2213)
 2213     FORMAT('      THE VALUE OF THE SECOND PARAMETER (N1 = THE ',   &
                 'NUMBER OF TRIALS')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2214)
 2214     FORMAT('      FOR THE FIRST VARIABLE MUST BE NON-NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2215)N1
 2215     FORMAT('      N1 = ',I8)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
!
        ELSEIF(ICASAN.EQ.'DPRO'.AND.P2.LT.0.0 .OR. P2.GT.1.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          IF(ICASAN.EQ.'PROP')THEN
            WRITE(ICOUT,2201)
          ELSE
            WRITE(ICOUT,2202)
          ENDIF
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2223)
 2223     FORMAT('      THE VALUE OF THE THIRD PARAMETER (P2 = THE ',   &
                 'PROBABILITY OF SUCCESS')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2224)
 2224     FORMAT('      FOR THE SECOND VARIABLE MUST BE IN THE ',   &
                 'INTERVAL (0,1).')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2225)P2
 2225     FORMAT('      P2 = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
!
        ELSEIF(N2.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          IF(ICASAN.EQ.'PROP')THEN
            WRITE(ICOUT,2201)
          ELSE
            WRITE(ICOUT,2202)
          ENDIF
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2233)
 2233     FORMAT('      THE VALUE OF THE FOURTH PARAMETER (N2 = THE ',   &
                 'NUMBER OF TRIALS')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2234)
 2234     FORMAT('      FOR THE SECOND VARIABLE MUST BE NON-NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2235)N2
 2235     FORMAT('      N2 = ',I8)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
!
        ENDIF
!
      ELSEIF(IVARTY(1).EQ.'VARI' .OR. IVARTY(I).EQ.'MATR')THEN
!
        ICASE='VARI'
        ICOL=1
        IF(ICASAN.EQ.'PROP' .AND. NUMVAR.NE.1)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2303)
 2303     FORMAT('      EXACTLY ONE VARIABLE MUST BE GIVEN.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2305)NUMVAR
 2305     FORMAT('      THE NUMBER OF VARIABLES GIVEN  = ',I5)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ELSEIF(ICASAN.EQ.'DPRO' .AND. NUMVAR.NE.2)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2202)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2313)
 2313     FORMAT('      EXACTLY TWO VARIABLES MUST BE GIVEN.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2315)NUMVAR
 2315     FORMAT('      THE NUMBER OF VARIABLES GIVEN  = ',I5)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
        CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVAR,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    Y,X,X,N1,N2,NLOCA3,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
      ENDIF
!
!               ******************************************************
!               **  STEP 8--                                        **
!               **  PREPARE FOR ENTRANCE INTO DPPRC2--              **
!               ******************************************************
!
      ISTEPN='8'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PRCL')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               *********************************
!               **  STEP 9--                   **
!               **  FORM THE CONFIDENCE LIMITS **
!               *********************************
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PRCL')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6211)
 6211   FORMAT('***** FROM DPPRCL, AS WE ARE ABOUT TO CALL DPPRC2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6212)N1,N2,MAXN
 6212   FORMAT('N1,N2,MAXN = ',3I8)
        CALL DPWRST('XXX','BUG ')
        IF(ICASE.EQ.'PARA')THEN
          WRITE(ICOUT,6214)P1,P2
 6214     FORMAT('P1,P2 = ',2G15.7)
          CALL DPWRST('XXX','BUG ')
        ELSE
          DO 6215 I=1,MIN(N1,N2)
            WRITE(ICOUT,6216)I,Y(I),X(I)
 6216       FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
 6215      CONTINUE
        ENDIF
      ENDIF
!
      CALL DPPRC2(Y,N1,X,N2,MAXNXT,   &
                  P1,P2,   &
                  ICASAN,ICASE,   &
                  PVAR,IVARN1,IVARN2,   &
                  ANOPL1,ANOPL2,   &
                  ICAPSW,ICAPTY,IFORSW,IBINME,IBI2ME,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PRCL')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPRCL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPRCL
      SUBROUTINE DPPRC2(Y,N1,X,N2,MAXNXT,   &
                        P1,P2,   &
                        ICASAN,ICASE,   &
                        PID,IVARID,IVARI2,   &
                        ANOPL1,ANOPL2,   &
                        ICAPSW,ICAPTY,IFORSW,IBINME,IBI2ME,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE GENERATES CONFIDENCE LIMITS FOR THE
!              PROPORTIONS FOR THE DATA IN THE INPUT VECTOR Y.
!              ALSO HANDLES THE DIFFERENCE OF TWO PROPORTIONS CASE.
!     NOTE--ASSUMPTION--MODEL IS   RESPONSE = CONSTANT + ERROR.
!     INPUT  ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR
!                                OF OBSERVATIONS FOR BOTH CASES
!                       X      = THE SINGLE PRECISION VECTOR
!                                OF OBSERVATIONS FOR THE DIFFERENCE
!                                OF PROPORTIONS CASE
!                       N1     = THE INTEGER NUMBER OF
!                                OBSERVATIONS IN THE VECTOR Y.
!                       N2     = THE INTEGER NUMBER OF
!                                OBSERVATIONS IN THE VECTOR X.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--99/3
!     ORIGINAL VERSION--MARCH     1999.
!     UPDATED         --AUGUST    2008. MODIFY THE OUTPUT FORMAT
!                                       SUPPORT FOR HTML, LATEX, AND
!                                       RTF FORMAT
!                                       SUPPORT FOR SUMMARY DATA
!     UPDATED         --FEBRUARY  2011. USE DPDTA1, DPDTA5 TO PRINT
!                                       TABLES
!     UPDATED         --OCTOBER   2015. TWEAK TO TITLE FOR DIFFERENCE OF
!                                       PROPORTIONS
!     UPDATED         --NOVEMBER  2017. SUPPORT FOR AGRESTI-CAFO
!                                       ADJUSTED INTERVAL AND
!                                       BAYESIAN INTERVAL
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IBINME
      CHARACTER*4 IBI2ME
      CHARACTER*4 ICASAN
      CHARACTER*4 ICASE
      CHARACTER*4 ICASE2
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IVARID(*)
      CHARACTER*4 IVARI2(*)
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IWRITE
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION PID(*)
!
      DIMENSION CONF(8)
      DIMENSION T(8)
      DIMENSION ALOWER(8)
      DIMENSION AUPPER(8)
!
      PARAMETER(NUMCLI=3)
      PARAMETER(MAXLIN=2)
      PARAMETER (MAXROW=25)
      PARAMETER (MAXRO2=8)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*1  ITITL9
      CHARACTER*60 ITEXT(MAXROW)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      CHARACTER*15 IVALUE(MAXRO2,NUMCLI)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXRO2,NUMCLI)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXRO2,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPPR'
      ISUBN2='C2  '
      IERROR='NO'
      IWRITE='OFF'
!
      PR1=CPUMIN
      PR2=CPUMIN
      PDIFF=CPUMIN
      YMIN=CPUMIN
      YMAX=CPUMIN
      NR1=0
      NR2=0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPPRC2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)N1,N2,MAXNXT,PID(1),ICASE,IBUGA3
   52   FORMAT('N1,N2,MAXNXT,PID(1),ICASE,IBUGA3 = ',   &
               3I8,G15.7,2(2X,A4))
        CALL DPWRST('XXX','WRIT')
        IF(ICASE.EQ.'PARA')THEN
          WRITE(ICOUT,54)P1,P2
   54     FORMAT('P1,P2 = ',2G15.7)
          CALL DPWRST('XXX','WRIT')
        ELSE
          DO 56 I=1,MIN(N1,N2)
            WRITE(ICOUT,57)I,Y(I),X(I)
   57       FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
            CALL DPWRST('XXX','WRIT')
   56     CONTINUE
        ENDIF
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N1.LE.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        IF(ICASAN.EQ.'DPRO')THEN
          WRITE(ICOUT,111)
  111     FORMAT('****** ERROR IN DIFFERENCE OF PROPORTION ',   &
                 'CONFIDENCE LIMITS--')
          CALL DPWRST('XXX','BUG ')
        ELSE
          WRITE(ICOUT,112)
  112     FORMAT('****** ERROR IN PROPORTION CONFIDENCE LIMITS--')
          CALL DPWRST('XXX','BUG ')
        ENDIF
        WRITE(ICOUT,113)
  113   FORMAT('         THE NUMBER OF OBSERVATIONS FOR THE FIRST ',   &
               'RESPONSE VARIABLE IS LESS THAN 2.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,114)N1
  114   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(ICASAN.EQ.'DPRO'.AND.N2.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('         THE NUMBER OF OBSERVATIONS FOR THE ',   &
               'SECOND RESPONSE VARIABLE IS LESS THAN 2.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,124)N2
  124   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ***************************************************
!               **  STEP 3--                                     **
!               **  COMPUTE THE NUMBER OF SUCCESSES.             **
!               ***************************************************
!
!
      ISTEPN='3'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICASE.EQ.'VARI')THEN
        IF(ANOPL1.NE.CPUMIN .AND. ANOPL2.NE.CPUMAX)THEN
          YMIN=ANOPL1
          IF(ANOPL1.GT.ANOPL2)YMIN=ANOPL2
          YMAX=ANOPL2
          IF(ANOPL1.GT.ANOPL2)YMAX=ANOPL1
        ELSE
          YMIN=0.5
          YMAX=1.5
        ENDIF
!
        AN=REAL(N1)
        NR1=0
        DO 2120 J=1,N1
          IF(YMIN.LE.Y(J).AND.Y(J).LE.YMAX)NR1=NR1+1
 2120   CONTINUE
        ANR1=NR1
        PR1=ANR1/AN
      ELSE
        PR1=REAL(P1)
        AN=REAL(N1)
        NR1=INT(PR1*AN + 0.5)
      ENDIF
!
      IF(ICASAN.EQ.'PROP'.AND.PR1.LT.0.0 .OR. PR1.GT.1.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        IF(ICASAN.EQ.'DPRO')THEN
          WRITE(ICOUT,111)
          CALL DPWRST('XXX','BUG ')
        ELSE
          WRITE(ICOUT,112)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        WRITE(ICOUT,201)
  201   FORMAT('      FOR THE FIRST RESPONSE VARIABLE, THE ',   &
               'PROPORTION OF SUCCESSES IS ')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,203)
  203   FORMAT('      OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(ICASAN.EQ.'DPRO')THEN
        IF(ICASE.EQ.'VARI')THEN
          AN2=REAL(N2)
          NR2=0
          DO 210 J=1,N2
            IF(YMIN.LE.X(J).AND.X(J).LE.YMAX)NR2=NR2+1
 210      CONTINUE
          ANR2=REAL(NR2)
          PR2=ANR2/AN2
        ELSE
          ANR2=REAL(N2)
          PR2=P2
          NR2=INT(PR2*ANR2 + 0.5)
        ENDIF
!
        IF(ICASAN.EQ.'PROP'.AND.PR1.LT.0.0 .OR. PR1.GT.1.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,111)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,211)
  211     FORMAT('      FOR THE SECOND RESPONSE VARIABLE, THE ',   &
               'PROPORTION OF SUCCESSES IS ')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,213)
  213     FORMAT('      OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
      ENDIF
!
!               ***************************************
!               **  STEP 4--                         **
!               **  COMPUTE CONFIDENCE LIMITS        **
!               **  FOR VARIOUS PROBABILITY VALUES.  **
!               ***************************************
!
      ISTEPN='4'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CONF(1)=50.0
      CONF(2)=75.0
      CONF(3)=90.0
      CONF(4)=95.0
      CONF(5)=99.0
      CONF(6)=99.9
      CONF(7)=99.99
      CONF(8)=99.999
!
      IF(ICASAN.EQ.'PROP')THEN
        AN=REAL(N1)
        P=PR1
        Q=1.0 - P
        SE=SQRT(P*Q/AN)
        DO 1400 I=1,8
          PCONF=1.0-(CONF(I)/100.0)
          PCONF=PCONF/2.0
          IF(IBINME.EQ.'WILS')THEN
            CALL NORPPF(PCONF,ZALPHA)
            TERM1=ZALPHA*ZALPHA/(2.0*AN)
            TERM2=ZALPHA*SQRT((P*Q/AN) + ZALPHA*ZALPHA/(4.0*AN*AN))
            TERM3=1.0 + ZALPHA*ZALPHA/AN
            TERM4=(P + TERM1 + TERM2)/TERM3
            TERM5=(P + TERM1 - TERM2)/TERM3
            ALOWLM=MIN(TERM4,TERM5)
            AUPPLM=MAX(TERM4,TERM5)
            ALOWER(I)=ALOWLM
            AUPPER(I)=AUPPLM
            IF(AUPPER(I).GT.1.0)AUPPER(I)=1.0
            IF(ALOWER(I).LT.0.0)ALOWER(I)=0.0
          ELSEIF(IBINME.EQ.'WALD')THEN
            CALL NORPPF(PCONF,ZALPHA)
            AK2=ZALPHA**2
            AX=AN*P
            IX=INT(AX+0.5)
            AX=REAL(IX) + (AK2/2.0)
            ANTEMP=AN + (AK2/2.0)
            PTEMP=AX/ANTEMP
            A1=PTEMP - ZALPHA*SQRT(PTEMP*(1.0-PTEMP))/SQRT(ANTEMP)
            A2=PTEMP + ZALPHA*SQRT(PTEMP*(1.0-PTEMP))/SQRT(ANTEMP)
            ALOWER(I)=MIN(A1,A2)
            AUPPER(I)=MAX(A1,A2)
            IF(AUPPER(I).GT.1.0)AUPPER(I)=1.0
            IF(ALOWER(I).LT.0.0)ALOWER(I)=0.0
          ELSEIF(IBINME.EQ.'JEFF')THEN
            AX=AN*P
            IX=INT(AX+0.5)
            AX=REAL(IX)
            ALPHA=AX+0.5
            BETA=AN-AX+0.5
            CALL BETPPF(PCONF,ALPHA,BETA,ALOWLM)
            PCONF2=1.0 - PCONF
            CALL BETPPF(PCONF2,ALPHA,BETA,AUPPLM)
            ALOWER(I)=ALOWLM
            AUPPER(I)=AUPPLM
            IF(AUPPER(I).GT.1.0)AUPPER(I)=1.0
            IF(ALOWER(I).LT.0.0)ALOWER(I)=0.0
          ELSEIF(IBINME.EQ.'NORM')THEN
            CALL NORPPF(PCONF,ZALPHA)
            ALOWLM=P - ZALPHA*SQRT(P*Q/AN)
            AUPPLM=P + ZALPHA*SQRT(P*Q/AN)
            ALOWER(I)=MIN(ALOWLM,AUPPLM)
            AUPPER(I)=MAX(ALOWLM,AUPPLM)
            IF(AUPPER(I).GT.1.0)AUPPER(I)=1.0
            IF(ALOWER(I).LT.0.0)ALOWER(I)=0.0
          ELSE
            ICASE2='TWOS'
            PCONF=CONF(I)/100.0
            CALL DPEBLL(P,N1,PCONF,IWRITE,ALOWLM,ICASE2,IBUGA3,IERROR)
            CALL DPEBUL(P,N1,PCONF,IWRITE,AUPPLM,ICASE2,IBUGA3,IERROR)
            ALOWER(I)=ALOWLM
            AUPPER(I)=AUPPLM
            IF(AUPPER(I).GT.1.0)AUPPER(I)=1.0
            IF(ALOWER(I).LT.0.0)ALOWER(I)=0.0
!CCCC       CDF=1.0-PCONF
!CCCC       CALL BINPPF(DBLE(CDF),DBLE(PR1),N1,DPPF)
!CCCC       T(I)=REAL(DPPF)
!CCCC       AUPPER(I)=T(I)/REAL(N1)
!CCCC       CDF=PCONF
!CCCC       CALL BINPPF(DBLE(CDF),DBLE(PR1),N1,DPPF)
!CCCC       T(I)=REAL(DPPF)
!CCCC       ALOWER(I)=T(I)/REAL(N1)
          ENDIF
 1400   CONTINUE
      ELSEIF(ICASAN.EQ.'DPRO')THEN
        IF(IBI2ME.EQ.'WALD')THEN
!
!         THIS IS THE STANDARD WALD METHOD
!
          PDIFF=PR1-PR2
          PSE=SQRT(PR1*(1.0-PR1)/REAL(N1) + PR2*(1.0-PR2)/REAL(N2))
          DO 1500 I=1,8
            PCONF=1.0-(CONF(I)/100.0)
            PCONF=PCONF/2.0
            CDF=1.0-PCONF
            CALL NORPPF(CDF,T(I))
            AUPPER(I)=PDIFF+PSE*T(I)
            IF(AUPPER(I).GT.1.0)AUPPER(I)=1.0
            ALOWER(I)=PDIFF-PSE*T(I)
            IF(ALOWER(I).LT.-1.0)ALOWER(I)=-1.0
!
            IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC2')THEN
              WRITE(ICOUT,1501)I,PSE,T(I),ALOWER(I),AUPPER(I)
 1501         FORMAT('WALD METHOD: I,PSE,CDF,T(I),ALOWER(I),',   &
                     'AUPPER(I) = ',I8,5G15.7)
              CALL DPWRST('XXX','WRIT')
            ENDIF
!
 1500     CONTINUE
        ELSEIF(IBI2ME.EQ.'ADJU')THEN
!
!         THIS IS THE ADJUSTED WALD METHOD RECOMMENDED BY
!         AGRESTI.
!
          PDIFF=PR1-PR2
          P1=(ANR1+1.0)/REAL(N1 + 2)
          P2=(ANR2+1.0)/REAL(N2 + 2)
          PDIFFT=P1-P2
          PSE=SQRT(P1*(1.0-P1)/REAL(N1+2) + P2*(1.0-P2)/REAL(N2+2))
          DO 1510 I=1,8
            PCONF=1.0-(CONF(I)/100.0)
            PCONF=PCONF/2.0
            CDF=1.0-PCONF
            CALL NORPPF(CDF,T(I))
            AUPPER(I)=PDIFFT+PSE*T(I)
            IF(AUPPER(I).GT.1.0)AUPPER(I)=1.0
            ALOWER(I)=PDIFFT-PSE*T(I)
            IF(ALOWER(I).LT.-1.0)ALOWER(I)=-1.0
!
            IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC2')THEN
              WRITE(ICOUT,1511)I,PSE,T(I),ALOWER(I),AUPPER(I)
 1511         FORMAT('ADJUSTED WALD METHOD: I,PSE,CDF,T(I),ALOWER(I),',   &
                     'AUPPER(I) = ',I8,5G15.7)
              CALL DPWRST('XXX','WRIT')
              WRITE(ICOUT,1513)ANR1,P1,ANR2,P2
 1513         FORMAT('ANR1,P1,ANR2,P2 = ',4G15.7)
              CALL DPWRST('XXX','WRIT')
            ENDIF
!
 1510     CONTINUE
        ELSEIF(IBI2ME.EQ.'BAYE')THEN
!
!         THIS IS THE BAYESIAN ADJUSTED WALD METHOD DISCUSSED BY
!         AGRESTI.
!
          PDIFF=PR1-PR2
          P1=(ANR1+1.0)/REAL(N1 + 2)
          P2=(ANR2+1.0)/REAL(N2 + 2)
          PDIFFT=P1-P2
          PSE=SQRT(P1*(1.0-P1)/REAL(N1+3) + P2*(1.0-P2)/REAL(N2+3))
          DO 1520 I=1,8
            PCONF=1.0-(CONF(I)/100.0)
            PCONF=PCONF/2.0
            CDF=1.0-PCONF
            CALL NORPPF(CDF,T(I))
            AUPPER(I)=PDIFFT+PSE*T(I)
            IF(AUPPER(I).GT.1.0)AUPPER(I)=1.0
            ALOWER(I)=PDIFFT-PSE*T(I)
            IF(ALOWER(I).LT.-1.0)ALOWER(I)=-1.0
 1520     CONTINUE
        ENDIF
      ENDIF
!
!               ****************************
!               **  STEP 7--              **
!               **  WRITE EVERYTHING OUT  **
!               ****************************
!
      ISTEPN='7'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE=' '
      ITITLZ=' '
      IF(ICASAN.EQ.'PROP')THEN
        ITITLE='Two-Sided Confidence Limits for a Proportion'
        NCTITL=44
        IF(IBINME.EQ.'WILS')THEN
          ITITLZ='(Wilson Method)'
          NCTITZ=15
        ELSEIF(IBINME.EQ.'WALD')THEN
          ITITLZ='(Adjusted Wald Method)'
          NCTITZ=22
        ELSEIF(IBINME.EQ.'JEFF')THEN
          ITITLZ='(Bayesian with Jeffreys Prior Method)'
          NCTITZ=37
        ELSEIF(IBINME.EQ.'NORM')THEN
          ITITLZ='(Normal Approximation Method)'
          NCTITZ=29
        ELSEIF(IBINME.EQ.'EXAC')THEN
          ITITLZ='(Exact Binomial Method)'
          NCTITZ=23
        ENDIF
      ELSE
        ITITLE='Difference of Proportions Two-Sided Confidence Limits'
        NCTITL=53
        IF(IBI2ME.EQ.'WALD')THEN
          ITITLZ='(Wald Method)'
          NCTITZ=13
        ELSEIF(IBI2ME.EQ.'ADJU')THEN
          ITITLZ='(Agresti-Caffo (Adjusted Wald) Method)'
          NCTITZ=38
        ELSEIF(IBI2ME.EQ.'BAYE')THEN
          ITITLZ='(Carlin and Louis Bayesian Method)'
          NCTITZ=34
        ENDIF
      ENDIF
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      IF(ICASAN.EQ.'PROP' .AND. ICASE.EQ.'VARI')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Response Variable: '
        WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(1)(1:4)
        WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(1)(1:4)
        NCTEXT(ICNT)=27
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ELSEIF(ICASAN.EQ.'DPRO' .AND. ICASE.EQ.'VARI')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='First Response Variable:  '
        WRITE(ITEXT(ICNT)(27:30),'(A4)')IVARID(1)(1:4)
        WRITE(ITEXT(ICNT)(31:34),'(A4)')IVARI2(1)(1:4)
        NCTEXT(ICNT)=34
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ENDIF
!
      IF(ICASAN.EQ.'DPRO' .AND. ICASE.EQ.'VARI')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Second Response Variable: '
        WRITE(ITEXT(ICNT)(27:30),'(A4)')IVARID(2)(1:4)
        WRITE(ITEXT(ICNT)(31:34),'(A4)')IVARI2(2)(1:4)
        NCTEXT(ICNT)=34
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      IF(ICASAN.EQ.'PROP')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Sample:'
        NCTEXT(ICNT)=7
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ELSE
        ICNT=ICNT+1
        ITEXT(ICNT)='Sample 1:'
        NCTEXT(ICNT)=9
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ENDIF
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(N1)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Successes:'
      NCTEXT(ICNT)=20
      AVALUE(ICNT)=REAL(NR1)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Proportion of Successes:'
      NCTEXT(ICNT)=24
      AVALUE(ICNT)=PR1
      IDIGIT(ICNT)=NUMDIG
      IF(ICASAN.EQ.'PROP')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Standard Error:'
        NCTEXT(ICNT)=15
        AVALUE(ICNT)=PSE
        IDIGIT(ICNT)=NUMDIG
      ENDIF
!
      IF(ICASAN.EQ.'DPRO')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=0
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Sample 2:'
        NCTEXT(ICNT)=9
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Number of Observations:'
        NCTEXT(ICNT)=23
        AVALUE(ICNT)=REAL(N2)
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)='Number of Successes:'
        NCTEXT(ICNT)=20
        AVALUE(ICNT)=REAL(NR2)
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)='Proportion of Successes:'
        NCTEXT(ICNT)=24
        AVALUE(ICNT)=PR2
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=1
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Difference Between Proportions:'
        NCTEXT(ICNT)=31
        AVALUE(ICNT)=PDIFF
        IDIGIT(ICNT)=NUMDIG
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      IF(ICASAN.EQ.'PROP' .AND. N1.LE.20)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Warning: the sample size is <= 20.'
        NCTEXT(ICNT)=34
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='         The normal approximation may'
        NCTEXT(ICNT)=37
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='         not be accurate.'
        NCTEXT(ICNT)=26
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ELSEIF(ICASAN.EQ.'DPRO' .AND.   &
            (N1.LE.20 .OR. N2.LE.20))THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Warning: if either sample size is less'
        NCTEXT(ICNT)=38
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='         than 20, the normal approximation'
        NCTEXT(ICNT)=42
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='         may not be accurate.'
        NCTEXT(ICNT)=29
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ENDIF
!
      NUMROW=ICNT
      DO 4210 I=1,NUMROW
        NTOT(I)=15
 4210 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='5A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='5B'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ITITLE=' '
      NCTITL=0
      ITITL9=' '
      NCTIT9=0
      ITITLE=' '
      NCTITL=0
      NUMLIN=2
      NUMROW=8
      NUMCOL=3
!
      ICNT=1
      ITITL2(1,ICNT)='Confidence'
      NCTIT2(1,ICNT)=10
      ITITL2(2,ICNT)='Value (%)'
      NCTIT2(2,ICNT)=9
!
      ICNT=ICNT+1
      ITITL2(1,ICNT)='Lower'
      NCTIT2(1,ICNT)=5
      ITITL2(2,ICNT)='Limit'
      NCTIT2(2,ICNT)=5
!
      ICNT=ICNT+1
      ITITL2(1,ICNT)='Upper'
      NCTIT2(1,ICNT)=5
      ITITL2(2,ICNT)='Limit'
      NCTIT2(2,ICNT)=5
!
      NMAX=0
      DO 4221 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IDIGIT(I)=NUMDIG
        ITYPCO(I)='NUME'
        IWHTML(I)=150
        IF(I.EQ.1)THEN
          NTOT(I)=12
          IDIGIT(I)=3
          IWHTML(1)=75
        ENDIF
        NMAX=NMAX+NTOT(I)
 4221 CONTINUE
      DO 4223 I=1,NUMROW
        DO 4225 J=1,NUMCOL
          NCVALU(I,J)=0
          IVALUE(I,J)=' '
          AMAT(I,J)=0.0
 4225   CONTINUE
        AMAT(I,1)=CONF(I)
        AMAT(I,2)=ALOWER(I)
        AMAT(I,3)=AUPPER(I)
 4223 CONTINUE
!
      IWRTF(1)=800
      IWRTF(2)=IWRTF(2)+2000
      IWRTF(3)=IWRTF(2)+2000
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      CALL DPDTA4(ITITL9,NCTIT9,   &
                  ITITLE,NCTITL,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXRO2,NUMROW,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPRC2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)N,IBUGA3,IERROR
 9012   FORMAT('N,IBUGA3,IERROR = ',I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPRC2
      SUBROUTINE DPPRC3(Y,N,ALPHA,PSTAMV,IBINME,XTEMP1,   &
                        P,ALOWLM,AUPPLM,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--GIVEN A VARIABLE CONTAINING 1's (FOR SUCCESS) AND
!              0's (FOR FAILURE), COMPUTE THE PROPORTION OF SUCCESSES
!              AND ALSO THE LOWER AND UPPER CONFIDENCE LIMITS FOR THIS
!              PROPORTION (BASED ON SEVERAL DIFFERENT METHODS).
!     INPUT  ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS CONTAINING 0 OR 1 VALUES.
!                       N      = THE INTEGER NUMBER OF OBSERVATIONS IN
!                                THE VECTOR Y.
!                       ALPHA  = THE SCALAR VALUE SPECIFYING THE
!                                SIGNIFICANCE LEVEL FOR THE CONFIDENCE
!                                INTERVAL.
!                       IBINME = THE CHARACTER STRING THAT SPECIFIES THE
!                                METHOD FOR THE CONFIDENCE INTERVAL.
!     OUTPUT ARGUMENTS--P      = THE SCALAR VALUE THAT SPECIFIES THE
!                                PROPORTION OF SUCCESSES.
!                     --ALOWLM = THE SCALAR VALUE THAT SPECIFIES THE
!                                LOWER LIMIT FOR THE CONFIDENCE INTERVAL.
!                     --AUPPLM = THE SCALAR VALUE THAT SPECIFIES THE
!                                UPPER LIMIT FOR THE CONFIDENCE INTERVAL.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017/11
!     ORIGINAL VERSION--NOVEMBER  2017.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBINME
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ICASE2
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IWRITE
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION XTEMP1(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPPR'
      ISUBN2='C3  '
      IERROR='NO'
      IWRITE='OFF'
!
      P=PSTAMV
      ALOWLM=PSTAMV
      AUPPLM=PSTAMV
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPPRC2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)N,ALPHA,IBINME,IBUGA3,ISUBRO
   52   FORMAT('N,ALPHA,IBINME,IBUGA3,ISUBRO = ',I8,G15.7,3(2X,A4))
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I),X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     FIRST REMOVE ANY MISSING VALUES
!
      IF(N.GE.1)THEN
        ICNT=0
        DO 110 I=1,N
          IF(Y(I).NE.PSTAMV)THEN
            ICNT=ICNT+1
            Y(ICNT)=Y(I)
          ENDIF
  110   CONTINUE
        N=ICNT
      ENDIF
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,112)
  112   FORMAT('****** ERROR IN PROPORTION CONFIDENCE LIMITS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('         AFTER REMOVING MISSING VALUES, THE NUMBER OF')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,115)N
  115   FORMAT('         OBSERVATIONS (',I5,') FOR THE RESPONSE ',   &
               'VARIABLE IS LESS THAN 1.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ***************************************************
!               **  STEP 2--                                     **
!               **  COMPUTE THE NUMBER OF SUCCESSES.             **
!               ***************************************************
!
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      EPS=0.0001
      CALL DISTIN(Y,N,IWRITE,XTEMP1,NDIST,IBUGA3,IERROR)
      IF(NDIST.GT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,112)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,122)
  122   FORMAT('      MORE THAN TWO DISTINCT VALUES DETECTED.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,124)NDIST
  124   FORMAT('      NUMBER OF DISTINCT VALUES = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NDIST.EQ.1)THEN
        IF(ABS(XTEMP1(1)).LE.EPS)THEN
!
!         ALL VALUES EQUAL 0
!
          XTEMP1(1)=0.0
          XTEMP1(2)=1.0
        ELSEIF(ABS(XTEMP1(1)-1.0).LE.EPS)THEN
!
!         ALL VALUES EQUAL 1
!
          XTEMP1(1)=0.0
          XTEMP1(2)=1.0
        ELSE
!
!         ALL VALUES EQUAL TO SOMETHING OTHER THAN 0 OR 1,
!         SO DON"T KNOW WHETHER THIS IS "ALL SUCCESS" OR
!         "ALL FAILURE" CASE.
!
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,112)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,132)
  132     FORMAT('      THERE IS ONLY ONE DISTINCT VALUE THAT IS NOT ',   &
                 'EQUAL TO EITHER 0 OR 1.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,134)
  134     FORMAT('      THEREFORE THE DEFINITION OF SUCCESS IS ',   &
                 'AMBIVALENT AND NOTHING IS COMPUTED.')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
      HOLD1=XTEMP1(1)
      HOLD2=XTEMP1(2)
      IF(HOLD1.LT.HOLD2)THEN
        XMIN=HOLD1
        XMAX=HOLD2
      ELSE
        XMAX=HOLD1
        XMIN=HOLD2
      ENDIF
!
!     NOW COMPUTE THE NUMBER OF SUCCESSES
!
      XSUM=0.0
      DO 210 I=1,N
        IF(Y(I).EQ.XMAX)THEN
          XSUM=XSUM + 1.0
        ENDIF
  210 CONTINUE
      AN=REAL(N)
      P=XSUM/AN
      Q=1.0 - P
!
!               ***************************************
!               **  STEP 3--                         **
!               **  COMPUTE CONFIDENCE LIMITS        **
!               ***************************************
!
      ISTEPN='3'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!
      SE=SQRT(P*Q/AN)
      ALP=ALPHA
      IF(ALP.LT.0.5)THEN
        P1=ALP/2.0
        P2=1.0-(ALP/2.0)
      ELSE
        ALP=1.0 - ALPHA
        P1=ALP/2.0
        P2=1.0-(ALP/2.0)
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC3')THEN
        WRITE(ICOUT,291)N,P,P1,P2
  291   FORMAT('N,XSUM,P,P1,P2 = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      IF(IBINME.EQ.'WILS')THEN
!
!       WILSON METHOD
!
        CALL NORPPF(P2,ZALPHA)
        TERM1=ZALPHA*ZALPHA/(2.0*AN)
        TERM2=ZALPHA*SQRT((P*Q/AN) + ZALPHA*ZALPHA/(4.0*AN*AN))
        TERM3=1.0 + ZALPHA*ZALPHA/AN
        TERM4=(P + TERM1 + TERM2)/TERM3
        TERM5=(P + TERM1 - TERM2)/TERM3
        ALOWLM=MIN(TERM4,TERM5)
        AUPPLM=MAX(TERM4,TERM5)
        IF(AUPPLM.GT.1.0)UPPWLM=1.0
        IF(ALOWLM.LT.0.0)ALOWLM=0.0
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC3')THEN
          WRITE(ICOUT,301)ZALPHA,TERM1,TERM2,TERM3,TERM4
  301     FORMAT('WILSON METHOD: ZALPHA,TERM1,TERM2,TERM3,TERM4 = ',   &
                 5G15.7)
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
      ELSEIF(IBINME.EQ.'WALD')THEN
!
!       ADJUSTED WALD METHOD
!
        CALL NORPPF(P2,ZALPHA)
        AK2=ZALPHA**2
        AX=AN*P
        IX=INT(AX+0.5)
        AX=REAL(IX) + (AK2/2.0)
        ANTEMP=AN + (AK2/2.0)
        PTEMP=AX/ANTEMP
        A1=PTEMP - ZALPHA*SQRT(PTEMP*(1.0-PTEMP))/SQRT(ANTEMP)
        A2=PTEMP + ZALPHA*SQRT(PTEMP*(1.0-PTEMP))/SQRT(ANTEMP)
        ALOWLM=MIN(A1,A2)
        AUPPLM=MAX(A1,A2)
        IF(AUPPLM.GT.1.0)AUPPLM=1.0
        IF(ALOWLM.LT.0.0)ALOWLM=0.0
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC3')THEN
          WRITE(ICOUT,311)ZALPHA,AK2,AX,ANTEMP,PTEMP
  311     FORMAT('WALD METHOD: ZALPHA,AK2,AX,ANTEMP,PTEMP = ',   &
                 5G15.7)
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
      ELSEIF(IBINME.EQ.'JEFF')THEN
!
!       BAYESIAN METHOD BASED ON JEFFREY'S PRIOR
!
        AX=AN*P
        IX=INT(AX+0.5)
        AX=REAL(IX)
        ALPHA2=AX+0.5
        BETA=AN-AX+0.5
        CALL BETPPF(P1,ALPHA2,BETA,ALOWLM)
        CALL BETPPF(P2,ALPHA2,BETA,AUPPLM)
        IF(AUPPLM.GT.1.0)AUPPLM=1.0
        IF(ALOWLM.LT.0.0)ALOWLM=0.0
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC3')THEN
          WRITE(ICOUT,321)AX,ALPHA2,BETA
  321     FORMAT('JEFFREYS METHOD: AX,ALPHA2,BETA = ',3G15.7)
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
      ELSEIF(IBINME.EQ.'NORM')THEN
!
!       NORMAL APPROXIMATION METHOD
!
        CALL NORPPF(P2,ZALPHA)
        ALOWLM=P - ZALPHA*SQRT(P*Q/AN)
        AUPPLM=P + ZALPHA*SQRT(P*Q/AN)
        IF(AUPPLM.GT.1.0)AUPPLM=1.0
        IF(ALOWLM.LT.0.0)ALOWLM=0.0
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC3')THEN
          WRITE(ICOUT,331)ZALPHA
  331     FORMAT('NORMAL APPROXIMATION METHOD: ZALPHA = ',G15.7)
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
      ELSEIF(IBINME.EQ.'CCOR')THEN
      ELSE
!
!       EXACT BINOMIAL METHOD
!
        ICASE2='TWOS'
        CALL DPEBLL(P,N,P2,IWRITE,ALOWLM,ICASE2,IBUGA3,IERROR)
        CALL DPEBUL(P,N,P2,IWRITE,AUPPLM,ICASE2,IBUGA3,IERROR)
        IF(AUPPLM.GT.1.0)AUPPLM=1.0
        IF(ALOWLM.LT.0.0)ALOWLM=0.0
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC3')THEN
          WRITE(ICOUT,351)ZALPHA
  351     FORMAT('EXACT BINOMIAL METHOD: ZALPHA = ',G15.7)
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPRC3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)P,ALOWLM,AUPPLM
 9012   FORMAT('P,ALOWLM,AUPPLM = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPRC3
      SUBROUTINE DPPRC4(Y1,N1,Y2,N2,ALPHA,PSTAMV,IBI2ME,XTEMP1,   &
                        PDIFF,ALOWLM,AUPPLM,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--GIVEN TWO VARIABLES CONTAINING 1's (FOR SUCCESS) AND
!              0's (FOR FAILURE), COMPUTE THE DIFFERENCE OF PROPORTION
!              OF SUCCESSES AND ALSO THE LOWER AND UPPER CONFIDENCE
!              LIMITS FOR THIS PROPORTION (BASED ON SEVERAL DIFFERENT
!              METHODS).
!     INPUT  ARGUMENTS--Y1     = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS CONTAINING 0 OR 1 VALUES
!                                FOR THE FIRST RESPONSE VARIABLE.
!                       N1     = THE INTEGER NUMBER OF OBSERVATIONS IN
!                                THE VECTOR Y1.
!                     --Y2     = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS CONTAINING 0 OR 1 VALUES
!                                FOR THE SECOND RESPONSE VARIABLE.
!                       N2     = THE INTEGER NUMBER OF OBSERVATIONS IN
!                                THE VECTOR Y2.
!                       ALPHA  = THE SCALAR VALUE SPECIFYING THE
!                                SIGNIFICANCE LEVEL FOR THE CONFIDENCE
!                                INTERVAL.
!                       IBI2ME = THE CHARACTER STRING THAT SPECIFIES THE
!                                METHOD FOR THE CONFIDENCE INTERVAL.
!     OUTPUT ARGUMENTS--P      = THE SCALAR VALUE THAT SPECIFIES THE
!                                PROPORTION OF SUCCESSES.
!                     --ALOWLM = THE SCALAR VALUE THAT SPECIFIES THE
!                                LOWER LIMIT FOR THE CONFIDENCE INTERVAL.
!                     --AUPPLM = THE SCALAR VALUE THAT SPECIFIES THE
!                                UPPER LIMIT FOR THE CONFIDENCE INTERVAL.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017/11
!     ORIGINAL VERSION--NOVEMBER  2017.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBI2ME
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IWRITE
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION XTEMP1(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPPR'
      ISUBN2='C4  '
      IERROR='NO'
      IWRITE='OFF'
!
      PDIFF=PSTAMV
      ALOWLM=PSTAMV
      AUPPLM=PSTAMV
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC4')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPPRC4--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)N1,N2,ALPHA,IBI2ME,IBUGA3,ISUBRO
   52   FORMAT('N1,N2,ALPHA,IBI2ME,IBUGA3,ISUBRO = ',2I8,G15.7,3(2X,A4))
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MAX(N1,N2)
          WRITE(ICOUT,57)I,Y1(I),Y2(I)
   57     FORMAT('I,Y1(I),Y2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC4')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     SAMPLE ONE
!
!     FIRST REMOVE ANY MISSING VALUES
!
      IF(N1.GE.1)THEN
        ICNT=0
        DO 110 I=1,N1
          IF(Y1(I).NE.PSTAMV)THEN
            ICNT=ICNT+1
            Y1(ICNT)=Y1(I)
          ENDIF
  110   CONTINUE
        N1=ICNT
      ENDIF
!
      IF(N1.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,112)
  112   FORMAT('****** ERROR IN DIFFERENCE OF PROPORTION CONFIDENCE ',   &
               'LIMITS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('         AFTER REMOVING MISSING VALUES, THE NUMBER OF')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,115)N1
  115   FORMAT('         OBSERVATIONS (',I5,') FOR THE FIRST RESPONSE ',   &
               'VARIABLE IS LESS THAN 1.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     SAMPLE TWO
!
!     FIRST REMOVE ANY MISSING VALUES
!
      IF(N2.GE.1)THEN
        ICNT=0
        DO 120 I=1,N2
          IF(Y2(I).NE.PSTAMV)THEN
            ICNT=ICNT+1
            Y2(ICNT)=Y2(I)
          ENDIF
  120   CONTINUE
        N2=ICNT
      ENDIF
!
      IF(N2.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,112)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('         AFTER REMOVING MISSING VALUES, THE NUMBER OF')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,125)N2
  125   FORMAT('         OBSERVATIONS (',I5,') FOR THE SECOND ',   &
               'RESPONSE VARIABLE IS LESS THAN 1.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ***************************************************
!               **  STEP 2--                                     **
!               **  COMPUTE THE NUMBER OF SUCCESSES.             **
!               ***************************************************
!
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC4')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      EPS=0.0001
      CALL DISTIN(Y1,N1,IWRITE,XTEMP1,NDIST1,IBUGA3,IERROR)
      IF(NDIST1.GT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,112)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,132)
  132   FORMAT('      MORE THAN TWO DISTINCT VALUES DETECTED FOR ',   &
               'THE FIRST RESPONSE VARIABLE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,134)NDIST1
  134   FORMAT('      NUMBER OF DISTINCT VALUES = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NDIST1.EQ.1)THEN
        IF(ABS(XTEMP1(1)).LE.EPS)THEN
          XTEMP1(1)=0.0
          XTEMP1(2)=1.0
        ELSEIF(ABS(XTEMP1(1)-1.0).LE.EPS)THEN
          XTEMP1(1)=0.0
          XTEMP1(2)=1.0
        ELSE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,112)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,136)
  136     FORMAT('      FOR THE FIRST RESPONSE VARIABLE, THERE IS')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,137)
  137     FORMAT('      ONLY ONE DISTINCT VALUE THAT IS NOT EQUAL TO ',   &
                 'EITHER 0 OR 1.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,139)
  139     FORMAT('      THEREFORE THE DEFINITION OF SUCCESS IS ',   &
                 'AMBIVALENT AND NOTHING IS COMPUTED.')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
      HOLD1=XTEMP1(1)
      HOLD2=XTEMP1(2)
      IF(HOLD1.LT.HOLD2)THEN
        XMIN=HOLD1
        XMAX=HOLD2
      ELSE
        XMAX=HOLD1
        XMIN=HOLD2
      ENDIF
!
!     NOW COMPUTE THE NUMBER OF SUCCESSES
!
      ANR1=0.0
      DO 140 I=1,N1
        IF(Y1(I).EQ.XMAX)THEN
          ANR1=ANR1 + 1.0
        ENDIF
  140 CONTINUE
      AN1=REAL(N1)
      P1=ANR1/AN1
      Q1=1.0 - P1
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC4')THEN
        WRITE(ICOUT,141)XMIN,XMAX,ANR1
  141   FORMAT('SAMPLE ONE: XMIN,XMAX,ANR1 = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!     NOW FOR SAMPLE TWO
!
      EPS=0.0001
      CALL DISTIN(Y2,N2,IWRITE,XTEMP1,NDIST2,IBUGA3,IERROR)
      IF(NDIST2.GT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,112)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,152)
  152   FORMAT('      MORE THAN TWO DISTINCT VALUES DETECTED FOR ',   &
               'THE SECOND RESPONSE VARIABLE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,154)NDIST2
  154   FORMAT('      NUMBER OF DISTINCT VALUES = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NDIST2.EQ.1)THEN
        IF(ABS(XTEMP1(1)).LE.EPS)THEN
          XTEMP1(1)=0.0
          XTEMP1(2)=1.0
        ELSEIF(ABS(XTEMP1(1)-1.0).LE.EPS)THEN
          XTEMP1(1)=0.0
          XTEMP1(2)=1.0
        ELSE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,112)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,156)
  156     FORMAT('      FOR THE SECOND RESPONSE VARIABLE, THERE IS')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,137)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,139)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
      HOLD1=XTEMP1(1)
      HOLD2=XTEMP1(2)
      IF(HOLD1.LT.HOLD2)THEN
        XMIN=HOLD1
        XMAX=HOLD2
      ELSE
        XMAX=HOLD1
        XMIN=HOLD2
      ENDIF
!
!     NOW COMPUTE THE NUMBER OF SUCCESSES
!
      ANR2=0.0
      DO 170 I=1,N2
        IF(Y2(I).EQ.XMAX)THEN
          ANR2=ANR2 + 1.0
        ENDIF
  170 CONTINUE
      AN2=REAL(N2)
      P2=ANR2/AN2
      Q2=1.0 - P2
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC4')THEN
        WRITE(ICOUT,171)XMIN,XMAX,ANR2
  171   FORMAT('SAMPLE TWO: XMIN,XMAX,ANR2 = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!               ***************************************
!               **  STEP 3--                         **
!               **  COMPUTE CONFIDENCE LIMITS        **
!               ***************************************
!
      ISTEPN='3'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC4')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!
      ALP=ALPHA
      IF(ALP.LT.0.5)THEN
        ALP1=ALP/2.0
        ALP2=1.0-(ALP/2.0)
      ELSE
        ALP=1.0 - ALPHA
        ALP1=ALP/2.0
        ALP2=1.0-(ALP/2.0)
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC4')THEN
        WRITE(ICOUT,291)N1,N2,P1,P2,ALP1,ALP2
  291   FORMAT('N1,N2,P1,P2,ALPHA,ALP1,ALP2 = ',2I8,5G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      IF(IBI2ME.EQ.'WALD')THEN
!
!       THIS IS THE STANDARD WALD METHOD
!
        PDIFF=P1-P2
        PSE=SQRT(P1*(1.0-P1)/REAL(N1) + P2*(1.0-P2)/REAL(N2))
        CALL NORPPF(ALP2,ANORCV)
        AUPPLM=PDIFF+PSE*ANORCV
        IF(AUPPLM.GT.1.0)AUPPLM=1.0
        ALOWLM=PDIFF-PSE*ANORCV
        IF(ALOWLM.LT.-1.0)ALOWLM=-1.0
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC4')THEN
          WRITE(ICOUT,292)PDIFF,PSE,ANORCV,ALOWLM,AUPPLM
  292     FORMAT('WALD: PDIFF,PSE,ANORCV,ALOWLM,AUPPLM = ',5G15.7)
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
      ELSEIF(IBI2ME.EQ.'ADJU')THEN
!
!       THIS IS THE ADJUSTED WALD METHOD RECOMMENDED BY
!       AGRESTI.
!
        P1T=(ANR1+1.0)/REAL(N1 + 2)
        P2T=(ANR2+1.0)/REAL(N2 + 2)
        PDIFF=P1T-P2T
        PSE=SQRT(P1T*(1.0-P1T)/REAL(N1+2) + P2T*(1.0-P2T)/REAL(N2+2))
        CALL NORPPF(ALP2,ANORCV)
        AUPPLM=PDIFF+PSE*ANORCV
        IF(AUPPLM.GT.1.0)AUPPLM=1.0
        ALOWLM=PDIFF-PSE*ANORCV
        IF(ALOWLM.LT.-1.0)ALOWLM=-1.0
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC4')THEN
          WRITE(ICOUT,293)PDIFF,P1T,P2T,PSE,ANORCV,ALOWLM,AUPPLM
  293     FORMAT('ADJUSTED WALD: PDIFF,P1T,P2T,PSE,ANORCV,ALOWLM,',   &
                 'AUPPLM = ',7G15.7)
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
      ELSEIF(IBI2ME.EQ.'BAYE')THEN
!
!       THIS IS THE BAYESIAN ADJUSTED WALD METHOD DISCUSSED BY AGRESTI.
!
        P1T=(ANR1+1.0)/REAL(N1 + 2)
        P2T=(ANR2+1.0)/REAL(N2 + 2)
        PDIFF=P1T-P2T
        PSE=SQRT(P1T*(1.0-P1T)/REAL(N1+3) + P2T*(1.0-P2T)/REAL(N2+3))
        CALL NORPPF(ALP2,ANORCV)
        AUPPLM=PDIFF+PSE*ANORCV
        IF(AUPPLM.GT.1.0)AUPPLM=1.0
        ALOWLM=PDIFF-PSE*ANORCV
        IF(ALOWLM.LT.-1.0)ALOWLM=-1.0
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRC4')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPRC4--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)PDIFF,ALOWLM,AUPPLM
 9012   FORMAT('PDIFF,ALOWLM,AUPPLM = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPRC4
      SUBROUTINE DPPRE2(Y,XMAT,MAXNXT,NUMVAR,IVARN3,IVARN4,W,N,   &
                        MODEL,NUMCHA,PARAM3,IPARN3,IPARN4,NUMPAR,   &
                        ICON3,IANGLU,IPARO3,   &
                        PARLI3,V,MAXITS,FITSD,FITPOW,CPUEPS,   &
                        ITYPEH,IW2HOL,IW22HO,W2HOLD,NWHOLD,   &
                        IHARG,IHARG2,IARGT,IARG,ARG,NUMARG,   &
                        IREP,REPSD,REPDF,RESSD,RESDF,PRED2,RES2,ALFCDF,   &
                        DUM1,DUM2,IANS,IWIDTH,   &
                        ISUBRO,IBUGA3,IBUGCO,IBUGEV,IERROR)
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--OCTOBER   1981.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MARCH     1988.      ADD LOFCDF
!     UPDATED         --MAY       1990.      MOVE SOME DIMENSIONING TO DPPREF
!     UPDATED         --NOVEMBER  1995. IANS, IWIDTH => INPUT ARGS
!     UPDATED         --NOVEMBER  1995. ALL ITERATIONS => DPST1F.DAT
!     UPDATED         --JULY      2019. REPLACE X1 ... X5 WITH XMAT
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IVARN3
      CHARACTER*4 IVARN4
      CHARACTER*4 IPARN3
      CHARACTER*4 IPARN4
      CHARACTER*4 IANGLU
      CHARACTER*4 IPARO3
      CHARACTER*4 ITYPEH
      CHARACTER*4 IW2HOL
      CHARACTER*4 IW22HO
      CHARACTER*4 IHARG
      CHARACTER*4 IHARG2
      CHARACTER*4 IARGT
      CHARACTER*4 IREP
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGCO
      CHARACTER*4 IBUGEV
      CHARACTER*4 IERROR
!
      CHARACTER*4 ICASLS
      CHARACTER*4 IHPN
      CHARACTER*4 IHPN2
      CHARACTER*4 IHPNV
      CHARACTER*4 IHPNV2
      CHARACTER*4 IPARN5
      CHARACTER*4 IPARN6
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 IH3
      CHARACTER*4 IH4
      CHARACTER*4 IH5
      CHARACTER*4 IH6
      CHARACTER*4 IH7
      CHARACTER*4 IH8
      CHARACTER*4 IH9
      CHARACTER*4 IH10
      CHARACTER*4 MODEL
      CHARACTER*4 IFOUNF
      CHARACTER*4 IANS
      CHARACTER*4 IOP
      CHARACTER*4 ISMALL
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOF2.INC'
!
      DIMENSION IHPNV(200)
      DIMENSION IHPNV2(200)
      DIMENSION ASTARV(200)
      DIMENSION AINCV(200)
      DIMENSION ASTOPV(200)
      DIMENSION NUMINV(200)
!
      DIMENSION WORST(200)
      DIMENSION BEST(200)
!
      DIMENSION Y(*)
      DIMENSION XMAT(MAXNXT,NUMVAR)
      DIMENSION PRED2(*)
      DIMENSION RES2(*)
      DIMENSION W(*)
      DIMENSION V(*)
      DIMENSION DUM1(*)
      DIMENSION DUM2(*)
!
      DIMENSION IHARG(*)
      DIMENSION IHARG2(*)
      DIMENSION IARGT(*)
      DIMENSION IARG(*)
      DIMENSION ARG(*)
!
      DIMENSION MODEL(*)
      DIMENSION IVARN3(*)
      DIMENSION IVARN4(*)
      DIMENSION PARAM3(*)
      DIMENSION IPARN3(*)
      DIMENSION IPARN4(*)
      DIMENSION ICON3(*)
      DIMENSION IPARO3(*)
      DIMENSION PARLI3(*)
!
      DIMENSION ITYPEH(*)
      DIMENSION IW2HOL(*)
      DIMENSION IW22HO(*)
      DIMENSION W2HOLD(*)
!
      DIMENSION IPARN5(100)
      DIMENSION IPARN6(100)
      DIMENSION PARAM5(100)
!
      DIMENSION IANS(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPPR'
      ISUBN2='E2  '
      IERROR='NO'
      IH2='UNKN'
!
      IPASS=2
      IRESDF=0
      IMIN=0
      KMAX=0
      J12=0
      J22=0
      J32=0
      J42=0
      J52=0
      J62=0
      J72=0
      J82=0
      J92=0
      J102=0
      IPAR2=0
      IPAR3=0
      IPAR4=0
      IPAR5=0
      IPAR6=0
      IPAR7=0
      IPAR8=0
      IPAR9=0
      IPAR10=0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PRE2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPRE2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)N,NUMVAR,NUMPAR,NUMCHA,MAXITS
   52   FORMAT('N,NUMVAR,NUMPAR,NUMCHA,MAXITS = ',5I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,83)FITPOW,FITSD,CPUEPS,V(1)
   83   FORMAT('FITPOW,FITSD,CPUEPS,V(1) = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGA3,IBUGCO,IBUGEV
   53   FORMAT('IBUGA3,IBUGCO,IBUGEV = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I),XMAT(I,1),W(I)
   56     FORMAT('I,Y(I),XMAT(I,1),W(I) = ',I5,3F20.10)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 61 J=1,NUMVAR
          WRITE(ICOUT,62)J,IPARO3(J),IVARN3(J),IVARN4(J),PARLI3(J)
   62     FORMAT('I,IPARO3(J),IVARN3(J),IVARN4(J),PARLI3(J) = ',   &
                 I8,2X,A4,2X,2A4,2X,G15.7)
          CALL DPWRST('XXX','BUG ')
   61   CONTINUE
        DO 66 J=1,NUMPAR
          WRITE(ICOUT,67)J,IPARN3(J),IPARN4(J),PARAM3(J),ICON3(J)
   67     FORMAT('I,IPARN3(I),IPARN4(I),PARAM3(I),ICON3(I) = ',   &
                 I8,2X,2A4,G15.7,I8)
          CALL DPWRST('XXX','BUG ')
   66   CONTINUE
        WRITE(ICOUT,71)(MODEL(J),J=1,MIN(100,NUMCHA))
   71   FORMAT('FUNCTIONAL EXPRESSION--',100A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!CCCCC THE FOLLOWING SECTION WAS ADDED NOVEMBER 1995
!               **************************************************
!               **  STEP 15--                                   **
!               **   OPEN THE STORAGE FILES                     **
!               **************************************************
!
      ISTEPN='15'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IOP='OPEN'
      IFLAG1=1
      IFLAG2=0
      IFLAG3=0
      IFLAG4=0
      IFLAG5=0
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               **************************************************
!               **  STEP 1--                                    **
!               **  DETERMINE THE PARAMETER NAMES IN THE MODEL  **
!               **  AND THE NUMBER NUMPAR OF PARAMETERS.        **
!               **************************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IPASS=2
!
      DO 1100 I=1,100
        IPARN5(I)='JUNK'
        IPARN6(I)='JUNK'
        PARAM5(I)=-999.0
 1100 CONTINUE
      IF(NUMPAR.GE.1)THEN
        DO 1150 I=1,NUMPAR
          IPARN5(I)=IPARN3(I)
          IPARN6(I)=IPARN4(I)
          PARAM5(I)=PARAM3(I)
 1150   CONTINUE
      ENDIF
!
      IF(NUMVAR.GE.1)THEN
        DO 1300 I=1,NUMVAR
          IPARN5(NUMPAR+I)=IVARN3(I)
          IPARN6(NUMPAR+I)=IVARN4(I)
 1300   CONTINUE
      ENDIF
!
      NUMPV=NUMPAR+NUMVAR
!
!               ********************************************************
!               **  STEP 2--                                          **
!               **  DEFINE VARIOUS CONSTANTS.                         **
!               **  DEFINE EPS = MACHINE EPSILON.                     **
!               **  DEFINE TOL = CUTOFF TOLERANCE FOR SUCCESSIVE      **
!               **               ESTIMATES.                           **
!               **  DEFINE MAXITS = MAX NUMBER OF ITERATIONS.         **
!               **  DEFINE EXPND = EXPANSION FACTOR                   **
!               **  DEFINE COMPR  = COMPRESSION FACTOR                **
!               **  DEFINE NCONST = NUMBER OF PARAMETERS HELD CONSTANT.*
!               **  DEFINE NP = NUMBER OF NON-CONSTANT PARAMETERS.    **
!               **  DEFINE DF = DEGREES OF FREEDOM.                   **
!               **  DEFINE SOME WORKING STORAGE START POINTS IN WS.   **
!               ********************************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IREP='NO'
      REPSD=0.0
      REPDF=0.0
      IREPDF=INT(REPDF+0.5)
      RESSD=0.0
      RESDF=0.0
      ALFCDF=(-999.99)
      IF(NUMPAR.LE.0)GO TO 2000
      EPS = 1.E-8
      DEPS=EPS
      TOL=0.00001
      DTOL=TOL
      ALAMBA=0.01
      EXPND=1.5
      COMPR=0.5
      NPST=NUMPAR
      NCONST=0
      DO 501 I=1,NUMPAR
        IF(ICON3(I).EQ.1)NCONST=NCONST+1
  501 CONTINUE
      NP=NUMPAR-NCONST
      IF(NP.LE.0)THEN
        WRITE(ICOUT,117) NP
117     FORMAT(10X,'NUMBER OF PARAMETERS TO BE VARIED = ',I8,   &
               '(LESS THAN ONE)')
        CALL DPWRST('XXX','BUG ')
        IER = 5
        IERROR='YES'
        GO TO 8100
      ENDIF
      DF=N-NP
      RESDF=DF
      IRESDF=INT(DF+0.5)
      IC=0
      IER=2
      IDA=NP*NP
      IDU=IDA+NP
      ID =IDU+NP
      IDX=ID +NP
      IY =IDX+NP
 2000 CONTINUE
!
      ICASLS='ON'
      IF(FITPOW.LE.1.999)ICASLS='OFF'
      IF(FITPOW.GE.2.001)ICASLS='OFF'
!
      IF(IPRINT.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IF(NUMPAR.GE.1.AND.ICASLS.EQ.'ON')THEN
          WRITE(ICOUT,101)
  101     FORMAT('LEAST SQUARES NON-LINEAR PRE-FIT')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(NUMPAR.GE.1.AND.ICASLS.EQ.'OFF')THEN
          WRITE(ICOUT,102)FITPOW
  102     FORMAT('NON-LINEAR PRE-FIT (FIT POWER = ',F10.5,')')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(NUMPAR.LE.0)THEN
          WRITE(ICOUT,105)
  105     FORMAT('FULLY-SPECIFIED MODEL')
          CALL DPWRST('XXX','BUG ')
        ENDIF
        WRITE(ICOUT,106)N
  106   FORMAT('      SAMPLE SIZE N = ',I8)
        CALL DPWRST('XXX','BUG ')
        IF(MODEL(1).NE.' ')IMIN=1
        IF(MODEL(1).EQ.' ')IMIN=2
        IMAX=NUMCHA
        IDEL=IMAX-IMIN+1
        NUMLIN=((IDEL-1)/100)+1
!
        IF(NUMLIN.GE.1)THEN
          DO 2240 KLINE=1,NUMLIN
            IF(KLINE.EQ.1)THEN
              KMIN=IMIN
              KMAX=KMIN+100-1
              IF(KMAX.GT.IMAX)KMAX=IMAX
              WRITE(ICOUT,2252)(MODEL(K),K=KMIN,KMAX)
 2252         FORMAT('      MODEL--',100A1)
              CALL DPWRST('XXX','BUG ')
            ELSEIF(KLINE.GE.2)THEN
              KMIN=KMAX+1
              KMAX=KMIN+100-1
              IF(KMAX.GT.IMAX)KMAX=IMAX
              WRITE(ICOUT,2262)(MODEL(K),K=KMIN,KMAX)
 2262         FORMAT(13X,100A1)
              CALL DPWRST('XXX','BUG ')
            ENDIF
 2240     CONTINUE
        ENDIF
      ENDIF
!
!               ********************************************************
!               **  STEP 2.5--                                        **
!               **  CHECK FOR REPLICATION AND IF EXISTENT COMPUTE A   **
!               **  (MODEL-FREE) REPLICATION STANDARD DEVIATION.      **
!               ********************************************************
!
      ISTEPN='2.5'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPREPS(Y,XMAT,MAXNXT,N,NUMVAR,DUM1,DUM2,   &
                  IREP,REPSS,REPMS,REPSD,REPDF,NUMSET,IBUGA3,IERROR)
      IREPDF=INT(REPDF+0.5)
!
      IF(IREP.EQ.'NO')THEN
        IF(IPRINT.EQ.'ON')THEN
          WRITE(ICOUT,2811)
 2811     FORMAT('      NO REPLICATION CASE')
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ELSE
        IF(IPRINT.EQ.'ON')THEN
          WRITE(ICOUT,2911)
 2911     FORMAT('      REPLICATION CASE')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2922)REPSD
 2922     FORMAT('      REPLICATION STANDARD DEVIATION = ',D20.10)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2923)IREPDF
 2923     FORMAT('      REPLICATION DEGREES OF FREEDOM = ',2X,I9)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2924)NUMSET
 2924     FORMAT('      NUMBER OF DISTINCT SUBSETS     = ',2X,I9)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
!               ********************************************************
!               **  STEP 3--                                          **
!               **  TREAT THE SPECIAL CASE WHERE NO PARAMETERS        **
!               **  EXIST IN THE MODEL--                              **
!               **  THAT IS, WE ARE REALLY INTERESTED IN GENERATING   **
!               **  PREDICTED VALUES AND RESIDUALS FROM A             **
!               **  FULLY-SPECIFIED MODEL. THIS IS USEFUL FOR         **
!               **  FOR MANUALLY ARRIVING AT REASONABLE STARTING      **
!               **  VALUES FOR A MORE COMPLICATED PRE-FIT; AND ALSO   **
!               **  FOR TESTING THE GOODNESS OF AN ALREADY-DERIVED    **
!               **  PRE-FIT FOR ONE DOMAIN OVER A SECOND DOMAIN.)     **
!               ********************************************************
!
      ISTEPN='3'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMPAR.LT.1)THEN
        CALL DPPRE3(MODEL,NUMCHA,IPASS,PARAM5,IPARN5,IPARN6,NUMPV,   &
                    IPARN3,IVARN3,PARAM3,IPARN4,IVARN4,ICON3,   &
                    NUMPAR,NUMVAR,Y,XMAT,MAXNXT,W,N,FITPOW,   &
                    IANGLU,ITYPEH,IW2HOL,IW22HO,W2HOLD,NWHOLD,   &
                    PRED2,RES2,RESSS,RESSD,RESDF,   &
                    ISUBRO,IBUGA3,IBUGCO,IBUGEV,IERROR)
        IF(IERROR.EQ.'YES')GO TO 8100
      ENDIF
!
!               *************************************************
!               **  STEP 5--                                   **
!               **  DETERMINE THE LATTICE OF PARAMETER VALUES  **
!               *************************************************
!
      ISTEPN='5'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               *************************************************
!               **  STEP 5.1--                                 **
!               **  SEARCH FOR THE FIRST OCCURRANCE OF    FOR  **
!               *************************************************
!
      ISTEPN='5.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMPF=0
      JMAX=NUMARG-1
      DO 3100 J=1,JMAX
        J2=J
        JP1=J+1
        IF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    '.AND.   &
           IHARG(JP1).EQ.'I   '.AND.IHARG2(JP1).EQ.'   ')THEN
          GO TO 3150
        ELSEIF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    ')THEN
          GO TO 3190
        ENDIF
 3100 CONTINUE
 3150 CONTINUE
      CALL DPPRE3(MODEL,NUMCHA,IPASS,PARAM5,IPARN5,IPARN6,NUMPV,   &
                  IPARN3,IVARN3,PARAM3,IPARN4,IVARN4,ICON3,   &
                  NUMPAR,NUMVAR,Y,XMAT,MAXNXT,W,N,FITPOW,   &
                  IANGLU,ITYPEH,IW2HOL,IW22HO,W2HOLD,NWHOLD,PRED2,RES2,   &
                  RESSS,RESSD,RESDF,   &
                  ISUBRO,IBUGA3,IBUGCO,IBUGEV,IERROR)
      IF(IERROR.EQ.'YES')GO TO 8100
      DO 3160 I=1,NUMPAR
        BEST(I)=PARAM3(I)
 3160 CONTINUE
      RESSMN=RESSD
      GO TO 6100
!
 3190 CONTINUE
      IFOLOC=J2
      ILALOC=IFOLOC-1
!
!               ************************************************
!               **  STEP 5.2--                                **
!               **  EXTRACT START,INCREMENT, AND STOP VALUES  **
!               **  FOR EACH PARAMETER GIVEN                  **
!               **  VIA EACH    FOR    QUALIFICATION.         **
!               ************************************************
!
      ISTEPN='5.2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMPF=0
      IF(IPRINT.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      DO 3200 ITER=1,1000
        IFOLOC=ILALOC+1
        J=IFOLOC
        JP1=J+1
        IF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    '.AND.   &
           IHARG(JP1).EQ.'I   '.AND.IHARG2(JP1).EQ.'   ')THEN
          GO TO 3280
        ELSEIF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    ')THEN
          CALL DPEXS2(IFOLOC,IHARG,IHARG2,IARGT,IARG,ARG,NUMARG,   &
                      IANS,IWIDTH,   &
                      IHPN,IHPN2,ASTART,AINC,ASTOP,NUMINC,ILALOC,   &
                      IBUGA3,IFOUNF,IERROR)
          IF(IFOUNF.EQ.'NO')GO TO 3280
          NUMPF=NUMPF+1
          IHPNV(NUMPF)=IHPN
          IHPNV2(NUMPF)=IHPN2
          ASTARV(NUMPF)=ASTART
          AINCV(NUMPF)=AINC
          ASTOPV(NUMPF)=ASTOP
          NUMINV(NUMPF)=NUMINC
          IF(IPRINT.EQ.'ON'.AND.NUMPF.GE.1)THEN
            WRITE(ICOUT,3221)IHPN,IHPN2,ASTART,AINC,ASTOP
 3221       FORMAT('      LATTICE VALUES FOR ',A4,A4,' = ',3E15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PRE2')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,3231)NUMPF
 3231       FORMAT('NUMPF = ',I8)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,3232)IHPNV(NUMPF),IHPNV2(NUMPF)
 3232       FORMAT('IHPNV(NUMPF),IHPNV2(NUMPF) = ',A4,2X,A4)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,3233)ASTARV(NUMPF),AINCV(NUMPF),ASTOPV(NUMPF)
 3233       FORMAT('ASTARV(NUMPF),AINCV(NUMPF),ASTOPV(NUMPF) = ',3G15.7)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,3234)NUMINV(NUMPF)
 3234       FORMAT('NUMINV(NUMPF) = ',I8)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ELSE
          GO TO 3280
        ENDIF
 3200 CONTINUE
 3280 CONTINUE
!
      IPROD=1
      IF(NUMPF.GT.0)THEN
        DO 3285 I=1,NUMPF
          IPROD=IPROD*NUMINV(I)
 3285   CONTINUE
      ENDIF
      NUMLAP=IPROD
      IF(IPRINT.EQ.'ON'.AND.NUMPF.GE.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3291)NUMLAP
 3291   FORMAT('      NUMBER OF LATTICE POINTS    = ',2X,I9)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PRE2')THEN
        WRITE(ICOUT,3292)NUMINV(NUMPF)
 3292   FORMAT('NUMINV(NUMPF) = ',I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***************************
!               **  STEP 5.3--           **
!               **  PRINT OUT A HEADING  **
!               ***************************
!
      ISTEPN='5.3'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'ON')THEN
        WRITE(ICOUT,3311)
 3311   FORMAT('  STEP                  RESIDUAL  *  PARAMETER')
        CALL DPWRST('XXX','BUG ')
        IF(ICASLS.EQ.'ON')THEN
          WRITE(ICOUT,3312)
 3312     FORMAT(' NUMBER                 STANDARD  *  ESTIMATES')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,3314)
 3314     FORMAT('                        DEVIATION *           ')
          CALL DPWRST('XXX','BUG ')
        ELSE
          WRITE(ICOUT,3313)
 3313     FORMAT(' NUMBER                   NORM    *  ESTIMATES')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,3315)
 3315     FORMAT('                                  *           ')
          CALL DPWRST('XXX','BUG ')
        ENDIF
        WRITE(ICOUT,3316)
 3316   FORMAT('----------------------------------*-----------')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ****************************************************
!               **  STEP 5.4--                                    **
!               **  STEP THROUGH THE VARIOUS VALUES               **
!               **  OF THE PARAMETER LATTICE;                     **
!               **  COMPUTE RESIDUAL STANDARD DEVIATION FOR EACH  **
!               **  LATTICE VALUE.                                **
!               ****************************************************
!
      ISTEPN='5.4'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      RESSMN=CPUMAX
      RESSMX=CPUMIN
!
      N1=0
      N2=0
      N3=0
      N4=0
      N5=0
      N6=0
      N7=0
      N8=0
      N9=0
      N10=0
!
      I1=1
      I2=1
      I3=1
      I4=1
      I5=1
      I6=1
      I7=1
      I8=1
      I9=1
      I10=1
!
      IF(NUMPF.LE.0)GO TO 4090
      N1=NUMINV(1)
      IF(NUMPF.LE.1)GO TO 4090
      N2=NUMINV(2)
      IF(NUMPF.LE.2)GO TO 4090
      N3=NUMINV(3)
      IF(NUMPF.LE.3)GO TO 4090
      N4=NUMINV(4)
      IF(NUMPF.LE.4)GO TO 4090
      N5=NUMINV(5)
      IF(NUMPF.LE.5)GO TO 4090
      N6=NUMINV(6)
      IF(NUMPF.LE.6)GO TO 4090
      N7=NUMINV(7)
      IF(NUMPF.LE.7)GO TO 4090
      N8=NUMINV(8)
      IF(NUMPF.LE.8)GO TO 4090
      N9=NUMINV(9)
      IF(NUMPF.LE.9)GO TO 4090
      N10=NUMINV(10)
      IF(NUMPF.LE.10)GO TO 4090
 4090 CONTINUE
!
      ISTEP=0
!
      IPAR1=1
      I1=0
 4100 CONTINUE
      I1=I1+1
      AI1=I1
      P1=ASTARV(IPAR1)+(AI1-1.0)*AINCV(IPAR1)
      IF(I1.EQ.N1)P1=ASTOPV(IPAR1)
      IF(I1.GE.2)THEN
        PARAM3(J12)=P1
        PARAM5(J12)=P1
        GO TO 4119
      ENDIF
      IH=IHPNV(IPAR1)
      IH2=IHPNV2(IPAR1)
      DO 4110 J1=1,NUMPAR
        J12=J1
        IF(IH.EQ.IPARN5(J1).AND.IH2.EQ.IPARN6(J1))THEN
          PARAM3(J12)=P1
          PARAM5(J12)=P1
          GO TO 4119
        ENDIF
 4110 CONTINUE
 4119 CONTINUE
      IF(NUMPF.LE.1)GO TO 5100
!
      IPAR2=2
      I2=0
 4200 CONTINUE
      I2=I2+1
      AI2=I2
      P2=ASTARV(IPAR2)+(AI2-1.0)*AINCV(IPAR2)
      IF(I2.EQ.N2)P2=ASTOPV(IPAR2)
      IF(I2.GE.2)THEN
        PARAM3(J22)=P2
        PARAM5(J22)=P2
        GO TO 4219
      ENDIF
      IH=IHPNV(IPAR2)
      IH2=IHPNV2(IPAR2)
      DO 4210 J2=1,NUMPAR
        J22=J2
        IF(IH.EQ.IPARN5(J2).AND.IH2.EQ.IPARN6(J2))THEN
          PARAM3(J22)=P2
          PARAM5(J22)=P2
          GO TO 4219
        ENDIF
 4210 CONTINUE
 4219 CONTINUE
      IF(NUMPF.LE.2)GO TO 5100
!
      IPAR3=3
      I3=0
 4300 CONTINUE
      I3=I3+1
      AI3=I3
      P3=ASTARV(IPAR3)+(AI3-1.0)*AINCV(IPAR3)
      IF(I3.EQ.N3)P3=ASTOPV(IPAR3)
      IF(I3.GE.2)THEN
        PARAM3(J32)=P3
        PARAM5(J32)=P3
        GO TO 4319
      ENDIF
      IH=IHPNV(IPAR3)
      IH3=IHPNV2(IPAR3)
      DO 4310 J3=1,NUMPAR
        J32=J3
        IF(IH.EQ.IPARN5(J3).AND.IH2.EQ.IPARN6(J3))THEN
          PARAM3(J32)=P3
          PARAM5(J32)=P3
          GO TO 4319
        ENDIF
 4310 CONTINUE
 4319 CONTINUE
      IF(NUMPF.LE.3)GO TO 5100
!
      IPAR4=4
      I4=0
 4400 CONTINUE
      I4=I4+1
      AI4=I4
      P4=ASTARV(IPAR4)+(AI4-1.0)*AINCV(IPAR4)
      IF(I4.EQ.N4)P4=ASTOPV(IPAR4)
      IF(I4.GE.2)THEN
        PARAM3(J42)=P4
        PARAM5(J42)=P4
        GO TO 4419
      ENDIF
      IH=IHPNV(IPAR4)
      IH4=IHPNV2(IPAR4)
      DO 4410 J4=1,NUMPAR
        J42=J4
        IF(IH.EQ.IPARN5(J4).AND.IH2.EQ.IPARN6(J4))THEN
          PARAM3(J42)=P4
          PARAM5(J42)=P4
          GO TO 4419
        ENDIF
 4410 CONTINUE
 4419 CONTINUE
      IF(NUMPF.LE.4)GO TO 5100
!
      IPAR5=5
      I5=0
 4500 CONTINUE
      I5=I5+1
      AI5=I5
      P5=ASTARV(IPAR5)+(AI5-1.0)*AINCV(IPAR5)
      IF(I5.EQ.N5)P5=ASTOPV(IPAR5)
      IF(I5.GE.2)THEN
        PARAM3(J52)=P5
        PARAM5(J52)=P5
        GO TO 4519
      ENDIF
      IH=IHPNV(IPAR5)
      IH5=IHPNV2(IPAR5)
      DO 4510 J5=1,NUMPAR
        J52=J5
        IF(IH.EQ.IPARN5(J5).AND.IH2.EQ.IPARN6(J5))THEN
          PARAM3(J52)=P5
          PARAM5(J52)=P5
          GO TO 4519
        ENDIF
 4510 CONTINUE
 4519 CONTINUE
      IF(NUMPF.LE.5)GO TO 5100
!
      IPAR6=6
      I6=0
 4600 CONTINUE
      I6=I6+1
      AI6=I6
      P6=ASTARV(IPAR6)+(AI6-1.0)*AINCV(IPAR6)
      IF(I6.EQ.N6)P6=ASTOPV(IPAR6)
      IF(I6.GE.2)THEN
        PARAM3(J62)=P6
        PARAM5(J62)=P6
        GO TO 4619
      ENDIF
      IH=IHPNV(IPAR6)
      IH6=IHPNV2(IPAR6)
      DO 4610 J6=1,NUMPAR
        J62=J6
        IF(IH.EQ.IPARN5(J6).AND.IH2.EQ.IPARN6(J6))THEN
          PARAM3(J62)=P6
          PARAM5(J62)=P6
          GO TO 4619
        ENDIF
 4610 CONTINUE
 4619 CONTINUE
      IF(NUMPF.LE.6)GO TO 5100
!
      IPAR7=7
      I7=0
 4700 CONTINUE
      I7=I7+1
      AI7=I7
      P7=ASTARV(IPAR7)+(AI7-1.0)*AINCV(IPAR7)
      IF(I7.EQ.N7)P7=ASTOPV(IPAR7)
      IF(I7.GE.2)THEN
        PARAM3(J72)=P7
        PARAM5(J72)=P7
        GO TO 4719
      ENDIF
      IH=IHPNV(IPAR7)
      IH7=IHPNV2(IPAR7)
      DO 4710 J7=1,NUMPAR
        J72=J7
        IF(IH.EQ.IPARN5(J7).AND.IH2.EQ.IPARN6(J7))THEN
          PARAM3(J72)=P7
          PARAM5(J72)=P7
          GO TO 4719
        ENDIF
 4710 CONTINUE
 4719 CONTINUE
      IF(NUMPF.LE.7)GO TO 5100
!
      IPAR8=8
      I8=0
 4800 CONTINUE
      I8=I8+1
      AI8=I8
      P8=ASTARV(IPAR8)+(AI8-1.0)*AINCV(IPAR8)
      IF(I8.EQ.N8)P8=ASTOPV(IPAR8)
      IF(I8.GE.2)THEN
        PARAM3(J82)=P8
        PARAM5(J82)=P8
        GO TO 4819
      ENDIF
      IH=IHPNV(IPAR8)
      IH8=IHPNV2(IPAR8)
      DO 4810 J8=1,NUMPAR
        J82=J8
        IF(IH.EQ.IPARN5(J8).AND.IH2.EQ.IPARN6(J8))THEN
          PARAM3(J82)=P8
          PARAM5(J82)=P8
          GO TO 4819
        ENDIF
 4810 CONTINUE
 4819 CONTINUE
      IF(NUMPF.LE.8)GO TO 5100
!
      IPAR9=9
      I9=0
 4900 CONTINUE
      I9=I9+1
      AI9=I9
      P9=ASTARV(IPAR9)+(AI9-1.0)*AINCV(IPAR9)
      IF(I9.EQ.N9)P9=ASTOPV(IPAR9)
      IF(I9.GE.2)THEN
        PARAM3(J92)=P9
        PARAM5(J92)=P9
        GO TO 4919
      ENDIF
      IH=IHPNV(IPAR9)
      IH9=IHPNV2(IPAR9)
      DO 4910 J9=1,NUMPAR
        J92=J9
        IF(IH.EQ.IPARN5(J9).AND.IH2.EQ.IPARN6(J9))THEN
          PARAM3(J92)=P9
          PARAM5(J92)=P9
          GO TO 4919
        ENDIF
 4910 CONTINUE
 4919 CONTINUE
      IF(NUMPF.LE.9)GO TO 5100
!
      IPAR10=10
      I10=0
 5000 CONTINUE
      I10=I10+1
      AI10=I10
      P10=ASTARV(IPAR10)+(AI10-1.0)*AINCV(IPAR10)
      IF(I10.EQ.N10)P10=ASTOPV(IPAR10)
      IF(I10.GE.2)THEN
        PARAM3(J102)=P10
        PARAM5(J102)=P10
        GO TO 5019
      ENDIF
      IH=IHPNV(IPAR10)
      IH10=IHPNV2(IPAR10)
      DO 5010 J10=1,NUMPAR
        J102=J10
        IF(IH.EQ.IPARN5(J10).AND.IH2.EQ.IPARN6(J10))THEN
          PARAM3(J102)=P10
          PARAM5(J102)=P10
          GO TO 5019
        ENDIF
 5010 CONTINUE
 5019 CONTINUE
      IF(NUMPF.LE.10)GO TO 5100
!
 5100 CONTINUE
      ISTEP=ISTEP+1
      CALL DPPRE3(MODEL,NUMCHA,IPASS,PARAM5,IPARN5,IPARN6,NUMPV,   &
                  IPARN3,IVARN3,PARAM3,IPARN4,IVARN4,ICON3,   &
                  NUMPAR,NUMVAR,Y,XMAT,MAXNXT,W,N,FITPOW,   &
                  IANGLU,ITYPEH,IW2HOL,IW22HO,W2HOLD,NWHOLD,PRED2,RES2,   &
                  RESSS,RESSD,RESDF,   &
                  ISUBRO,IBUGA3,IBUGCO,IBUGEV,IERROR)
      IF(IERROR.EQ.'YES')GO TO 8100
!
      IF(RESSD.GT.RESSMX)THEN
        DO 5115 I=1,NUMPAR
          WORST(I)=PARAM5(I)
 5115   CONTINUE
        RESSMX=RESSD
      ENDIF
!
!CCCC THE FOLLOWING 19 LINES WERE REWRITTEN    NOVEMBER 1995
      ISMALL='NO'
      IF(RESSD.LT.RESSMN)THEN
         DO 5125 I=1,NUMPAR
            BEST(I)=PARAM5(I)
 5125    CONTINUE
         RESSMN=RESSD
         ISMALL='YES'
      END IF
!
      IF(ISMALL.EQ.'YES')THEN
         IF(IPRINT.EQ.'ON')THEN
            WRITE(ICOUT,5191)ISTEP,RESSD,(PARAM3(J),J=1,NUMPAR)
 5191       FORMAT(I5,'--',4X,9X,1X,E12.5,' *',8E12.5)
            CALL DPWRST('XXX','BUG ')
         END IF
      END IF
!
      WRITE(IOUNI1,5192)RESSD,(PARAM3(J),J=1,NUMPAR)
 5192 FORMAT(1X,E12.5,8E12.5)
!
      IF(I10.LT.N10)GO TO 5000
      IF(I9.LT.N9)GO TO 4900
      IF(I8.LT.N8)GO TO 4800
      IF(I7.LT.N7)GO TO 4700
      IF(I6.LT.N6)GO TO 4600
      IF(I5.LT.N5)GO TO 4500
      IF(I4.LT.N4)GO TO 4400
      IF(I3.LT.N3)GO TO 4300
      IF(I2.LT.N2)GO TO 4200
      IF(I1.LT.N1)GO TO 4100
!
!               *******************************************************
!               **  STEP 12--                                        **
!               **  PRINT OUT FINAL PARAMETER ESTIMATES              **
!               **  AND THEIR STANDARD DEVIATIONS.                   **
!               **  ALSO PRINT OUT THE RESIDUAL STANDARD DEVIATION.  **
!               *******************************************************
!
 6100 CONTINUE
      ISTEPN='12'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 6110 I=1,NUMPAR
        PARAM3(I)=BEST(I)
 6110 CONTINUE
      RESSD=RESSMN
!
      IF(IPRINT.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6111)
 6111   FORMAT (7X,'FINAL PARAMETER ESTIMATES           ')
        CALL DPWRST('XXX','BUG ')
        DO 6120 I=1,NUMPAR
          WRITE(ICOUT,6121)I,IPARN3(I),IPARN4(I),PARAM3(I)
 6121     FORMAT(I8,2X,2A4,2X,G22.6)
          CALL DPWRST('XXX','BUG ')
 6120   CONTINUE
      ENDIF
!
!               *********************************************
!               **  STEP 13--                              **
!               **  PRINT OUT GOODNESS OF FIT INFORMATION  **
!               *********************************************
!
      ISTEPN='13'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'ON')THEN
        IF(NUMPAR.GE.1)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IF(ICASLS.EQ.'ON')THEN
          WRITE(ICOUT,7125)RESSD
 7125     FORMAT('      RESIDUAL    STANDARD DEVIATION = ',F20.10)
          CALL DPWRST('XXX','BUG ')
        ELSE
          WRITE(ICOUT,7126)RESSD
 7126     FORMAT('      RESIDUAL    NORM               = ',F20.10)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        WRITE(ICOUT,7127)IRESDF
 7127   FORMAT('      RESIDUAL    DEGREES OF FREEDOM = ',2X,I9)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IREP.EQ.'YES')THEN
        IFITDF=IRESDF-IREPDF
        IF(IPRINT.EQ.'ON')THEN
          WRITE(ICOUT,7227)REPSD
 7227     FORMAT('      REPLICATION STANDARD DEVIATION = ',F20.10)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,7228)IREPDF
 7228     FORMAT('      REPLICATION DEGREES OF FREEDOM = ',2X,I9)
          CALL DPWRST('XXX','BUG ')
          IF(IFITDF.LT.1)THEN
            WRITE(ICOUT,7236)
 7236       FORMAT('      LACK OF FIT F TEST CANNOT BE DONE BECAUSE')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,7237)
 7237       FORMAT('      HAVE ONLY 0 DEGREES OF FREEDOM IN ',   &
                   'NUMERATOR OF F RATIO.')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,7238)
 7238       FORMAT('      THIS HAPPENS WHEN NUMBER OF PARAMETERS ',   &
                   'FITTED')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,7239)
 7239       FORMAT('      IS IDENTICAL TO NUMBER OF DISTINCT SUBSETS.')
            CALL DPWRST('XXX','BUG ')
            GO TO 7250
          ENDIF
        ENDIF
!
        FITDF=IFITDF
        FITSS=RESSS-REPSS
        FITMS=FITSS/FITDF
        FSTAT=FITMS/REPMS
        CALL FCDF(FSTAT,IFITDF,IREPDF,CDF)
        CDF2=100.0*CDF
        ALFCDF=CDF
!
        IF(IPRINT.EQ.'ON')THEN
          WRITE(ICOUT,7240)FSTAT,CDF2
 7240     FORMAT('      LACK OF FIT F RATIO = ',F10.4,' = THE ',   &
                 F8.4,'% POINT OF THE')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,7245)IFITDF,IREPDF
 7245     FORMAT('      F DISTRIBUTION WITH ',I6,' AND ',I6,   &
                 ' DEGREES OF FREEDOM')
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
 7250 CONTINUE
      IF(NUMPAR.LE.0)GO TO 8100
!
!CCCCC THE FOLLOWING SECTION WAS ADDED NOVEMBER 1995
!               **************************************
!               **  STEP 81--                       **
!               **  CLOSE       THE STORAGE FILES.  **
!               **************************************
!
 8100 CONTINUE
!
      ISTEPN='81'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PRE2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPRE2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR,N,NUMVAR,NUMPAR,NUMCHA
 9013   FORMAT('IERROR,N,NUMVAR,NUMPAR,NUMCHA = ',A4,2X,4I8)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,NUMPAR
          WRITE(ICOUT,9016)I,IPARN3(I),IPARN4(I),PARAM3(I)
 9016     FORMAT('I,IPARN3(I),IPARN4(I),PARAM3(I) = ',I8,2X,2A4,G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
        DO 9020 I=1,N
          WRITE(ICOUT,9021)I,Y(I),W(I),PRED2(I),RES2(I)
 9021     FORMAT('I,Y(I),W(I),PRED2(I),RES2(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPPRE2
      SUBROUTINE DPPRE3(MODEL,NUMCHA,IPASS,PARAM5,IPARN5,IPARN6,NUMPV,   &
                        IPARN3,IVARN3,PARAM3,IPARN4,IVARN4,ICON3,   &
                        NUMPAR,NUMVAR,Y,XMAT,MAXNXT,W,N,FITPOW,   &
                        IANGLU,ITYPEH,IW2HOL,IW22HO,W2HOLD,NWHOLD,   &
                        PRED2,RES2,RESSS,RESSD,RESDF,   &
                        ISUBRO,IBUGA3,IBUGCO,IBUGEV,IERROR)
!
!     PURPOSE--TAKE A MODEL AND A DATA SET AND A SET OF PARAMETER VALUES
!              AND COMPUTE A RESIDUAL STANDARD DEVIATION.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--OCTOBER    1981.
!     UPDATED          --NOVEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --JULY      2019. RECODE TO USE MATRIX XMAT RATHER
!                                       THAN X1 ... X5
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 MODEL
      CHARACTER*4 IPARN5
      CHARACTER*4 IPARN6
      CHARACTER*4 IPARN3
      CHARACTER*4 IVARN3
      CHARACTER*4 IPARN4
      CHARACTER*4 IVARN4
      CHARACTER*4 IANGLU
      CHARACTER*4 ITYPEH
      CHARACTER*4 IW2HOL
      CHARACTER*4 IW22HO
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGCO
      CHARACTER*4 IBUGEV
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION XMAT(MAXNXT,NUMVAR)
      DIMENSION PRED2(*)
      DIMENSION RES2(*)
      DIMENSION W(*)
!
      DIMENSION MODEL(*)
      DIMENSION IVARN3(*)
      DIMENSION IVARN4(*)
      DIMENSION PARAM3(*)
      DIMENSION IPARN3(*)
      DIMENSION IPARN4(*)
      DIMENSION ICON3(*)
      DIMENSION ITYPEH(*)
      DIMENSION IW2HOL(*)
      DIMENSION IW22HO(*)
      DIMENSION W2HOLD(*)
!
      DIMENSION IPARN5(*)
      DIMENSION IPARN6(*)
      DIMENSION PARAM5(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPPR'
      ISUBN3='E3  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PRE3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPRE3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)N,NUMVAR,NUMPAR,NUMPV,NUMCHA,FITPOW
   52   FORMAT('N,NUMVAR,NUMPAR,NUMPV,NUMCHA,FITPOW = ',5I8,G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGA3,IBUGCO,IBUGEV
   53   FORMAT('IBUGA3,IBUGCO,IBUGEV = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I),XMAT(I,1),W(I)
   56     FORMAT('I,Y(I),XMAT(I,1),W(I) = ',I5,3F20.10)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 61 J=1,NUMVAR
          WRITE(ICOUT,62)J,IVARN3(J),IVARN4(J)
   62     FORMAT('I,IVARN3(I),IVARN4(I) = ',I8,2X,2A4)
          CALL DPWRST('XXX','BUG ')
   61   CONTINUE
        DO 66 J=1,NUMPV
          WRITE(ICOUT,67)J,IPARN3(J),IPARN4(J),PARAM3(J),ICON3(J)
   67     FORMAT('I,IPARN3(I),IPARN4(I),PARAM3(I),ICON3(I) = ',   &
                 I8,2X,2A4,G15.7,I8)
          CALL DPWRST('XXX','BUG ')
   66   CONTINUE
        WRITE(ICOUT,71)(MODEL(J),J=1,MIN(100,NUMCHA))
   71   FORMAT('FUNCTIONAL EXPRESSION--',100A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      DO 2100 I=1,N
        W(I)=1.0
 2100 CONTINUE
!
      DO 3000 I=1,N
        IF(NUMVAR.GE.1)THEN
          DO 3005 J=1,NUMVAR
            PARAM5(NUMPAR+J)=XMAT(I,J)
 3005     CONTINUE
        ENDIF
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PRE3')THEN
          WRITE(ICOUT,888)NUMPAR,NUMVAR,NUMPV
  888     FORMAT('NUMPAR,NUMVAR,NUMPV = ',3I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,889)XMAT(1,1),XMAT(I,1),IPARN5(3),   &
                          IPARN6(3),PARAM5(3)
  889     FORMAT('XMAT(1,1),XMAT(I,1),IPARN5(3),IPARN6(3),',   &
                 'PARAM5(3) = ',2G15.7,2(2X,A4),G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        CALL COMPIM(MODEL,NUMCHA,IPASS,PARAM5,IPARN5,IPARN6,NUMPV,   &
                    IANGLU,ITYPEH,IW2HOL,IW22HO,W2HOLD,NWHOLD,PRED2(I),   &
                    IBUGCO,IBUGEV,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
 3000 CONTINUE
!
      DO 3100 I=1,N
        RES2(I)=Y(I)-PRED2(I)
 3100 CONTINUE
!
      SUM=0.0
      DO 3200 I=1,N
        IF(RES2(I).NE.0.0)SUM=SUM+ABS(RES2(I))**FITPOW
 3200 CONTINUE
      RESSS=SUM
!
      IRESDF=N-NUMPAR
      RESDF=IRESDF
      RESMS=RESSS/RESDF
      IF(RESMS.LE.0.0)RESSD=0.0
      IF(RESMS.GT.0.0)RESSD=SQRT(RESMS)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PRE3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPRE3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR,N,NUMVAR,NUMPAR,NUMCHA
 9013   FORMAT('IERROR,N,NUMVAR,NUMPAR,NUMCHA = ',A4,2X,4I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9018)RESSS,RESSD,RESDF
 9018   FORMAT('RESSS,RESSD,RESDF = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,N
          WRITE(ICOUT,9021)I,Y(I),W(I),PRED2(I),RES2(I)
 9021     FORMAT('I,Y(I),W(I),PRED2(I),RES2(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPPRE3
      SUBROUTINE DPPREC(IHARG,NUMARG,IDEFPR,IHMXPR,   &
                        IPREC,IFOUND,IERROR)
!
!     PURPOSE--SPECIFY THE PRECISION SWITCH WHICH IN TURN
!              DETERMINES WHETHER SUBSEQUENT CALCULATIONS WILL BE
!              CARRIED OUT IN SINGLE, DOUBLE,
!              TRIPLE, OR QUADRUPLE PRECISION
!              (IF AVAILABLE ON THE HOST COMPUTER).
!              THE SPECIFIED PRECISION SWITCH SPECIFICATION
!              WILL BE PLACED IN THE HOLLERITH VARIABLE IPREC.
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --NUMARG (AN INTEGER VARIABLE)
!                     --IDEFPR (A  HOLLERITH VARIABLE)
!                     --IHMXPR (A  HOLLERITH VARIABLE)
!     OUTPUT ARGUMENTS--IPREC  (A HOLLERITH VARIABLE)
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1980.
!     UPDATED         --SEPTEMBER 1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --JANUARY   2017. CHECK FOR CONFLICT WITH
!                                       PRECISION STATISTIC
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IDEFPR
      CHARACTER*4 IHMXPR
      CHARACTER*4 IPREC
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHOLD
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
!     CHECK FOR CONFLICTS WITH PRECISION STATISTIC
!
      IF(IHARG(1).EQ.'PLOT')GO TO 1199
      IF(IHARG(1).EQ.'CUMU' .AND. IHARG(2).EQ.'PLOT')GO TO 1199
      IF(IHARG(1).EQ.'MOVI' .AND. IHARG(2).EQ.'PLOT')GO TO 1199
      IF(IHARG(1).EQ.'WIND' .AND. IHARG(2).EQ.'PLOT')GO TO 1199
      IF(IHARG(1).EQ.'BLOC' .AND. IHARG(2).EQ.'PLOT')GO TO 1199
      IF(IHARG(1).EQ.'INFL' .AND. IHARG(2).EQ.'PLOT')GO TO 1199
      IF(IHARG(1).EQ.'INFL' .AND. IHARG(2).EQ.'CURV')GO TO 1199
!
      IFOUND='YES'
      IF(NUMARG.LE.0)GO TO 1120
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1120
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1120
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1120
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1120
!
      IF(IHARG(NUMARG).EQ.'SING')GO TO 1130
      IF(IHARG(NUMARG).EQ.'DOUB')GO TO 1130
      IF(IHARG(NUMARG).EQ.'TRIP')GO TO 1130
      IF(IHARG(NUMARG).EQ.'QUAD')GO TO 1130
      GO TO 1120
!
 1120 CONTINUE
      IHOLD=IDEFPR
      GO TO 1160
!
 1130 CONTINUE
      IHOLD=IHARG(NUMARG)
      GO TO 1160
!
 1160 CONTINUE
      IF(IHOLD.EQ.'DOUB'.AND.IHMXPR.EQ.'SING')GO TO 1170
      IF(IHOLD.EQ.'TRIP'.AND.IHMXPR.EQ.'SING')GO TO 1170
      IF(IHOLD.EQ.'TRIP'.AND.IHMXPR.EQ.'DOUB')GO TO 1170
      IF(IHOLD.EQ.'QUAD'.AND.IHMXPR.EQ.'SING')GO TO 1170
      IF(IHOLD.EQ.'QUAD'.AND.IHMXPR.EQ.'DOUB')GO TO 1170
      IF(IHOLD.EQ.'QUAD'.AND.IHMXPR.EQ.'TRIP')GO TO 1170
      GO TO 1180
!
 1170 CONTINUE
      IERROR='YES'
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1172)
 1172 FORMAT('***** ERROR IN DPPREC--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1173)
 1173 FORMAT('      THE DESIRED PRECISION IS HIGHER')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1174)
 1174 FORMAT('      THAN PERMITTED ON THIS COMPUTER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1175)IHOLD
 1175 FORMAT('      DESIRED PRECISION           = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1176)IHMXPR
 1176 FORMAT('      MAXIMUM ALLOWABLE PRECISION = ',A4)
      CALL DPWRST('XXX','BUG ')
      GO TO 1199
!
 1180 CONTINUE
      IPREC=IHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1188)IPREC
 1188 FORMAT('THE PRECISION SWITCH HAS JUST BEEN SET TO ',   &
      A4)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 1199
!
 1199 CONTINUE
      RETURN
      END SUBROUTINE DPPREC
      SUBROUTINE DPPREE(IHARG,NUMARG,   &
      IERASW,IFOUND,IERROR)
!
!     PURPOSE--SPECIFY THE PRE-ERASE SWITCH WHICH IN TURN
!              DETERMINES WHETHER A PRE-ERASE WILL
!              AUTOMATICALLY OCCUR BEFORE PLOTS.
!              THIS CAPABILITY IS USEFUL FOR AUTOMATICALLY
!              CLEARING THE SCREEN BEFORE PLOTS.
!              THE SPECIFIED PRE-ERASE SWITCH SPECIFICATION
!              WILL BE PLACED IN THE HOLLERITH VARIABLE IERASW.
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --NUMARG (AN INTEGER VARIABLE)
!     OUTPUT ARGUMENTS--IERASW (A HOLLERITH VARIABLE)
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1980.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IERASW
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHOLD
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.EQ.0)GO TO 1199
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'ERAS')GO TO 1110
      GO TO 1199
!
 1110 CONTINUE
      IF(NUMARG.LE.0)GO TO 1150
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1150
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1160
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1150
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1150
      GO TO 1150
!
 1150 CONTINUE
      IHOLD='ON'
      GO TO 1180
!
 1160 CONTINUE
      IHOLD='OFF'
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
      IERASW=IHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1181)IERASW
 1181 FORMAT('THE PRE-ERASE SWITCH HAS JUST BEEN SET TO ',   &
      A4)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 1199
!
 1199 CONTINUE
      RETURN
      END SUBROUTINE DPPREE
      SUBROUTINE DPPREF(IBUGA2,IBUGA3,IBUGCO,IBUGEV,IBUGQ,ISUBRO,   &
                        IFOUND,IERROR)
!
!     PURPOSE--CARRY OUT A (LINEAR OR) NON-LINEAR PRE-FIT
!             = A FIT OVER A SPECIFIED LATTICE OF PARAMETER VALUES.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--OCTOBER   1981.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MARCH     1988. ADD LOFCDF
!     UPDATED         --JUNE      1990. TEMPORARY ARRAYS TO GARBAGE
!                                       COMMON
!     UPDATED         --JUNE      1990. MOVE DIMENSIONING OF ARRAYS
!     UPDATED         --NOVEMBER  1995. IANS, IWIDTH => CALLING ARGS
!     UPDATED         --MAY       2009. REPLACE USE OF DPSWAP WITH
!                                       BUILT-IN SCRATCH STORAGE
!     UPDATED         --JULY      2019. TWEAK SCRATCH STORAGE
!     UPDATED         --JULY      2019. REPLACE X1 ... X5 WITH XMAT
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGCO
      CHARACTER*4 IBUGEV
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ICASFI
      CHARACTER*4 ICASEQ
      CHARACTER*4 IKEY
      CHARACTER*4 IWD
      CHARACTER*4 IWD1
      CHARACTER*4 IWD12
      CHARACTER*4 IWD2
      CHARACTER*4 IWD22
      CHARACTER*4 ICH
      CHARACTER*4 ITYPEH
      CHARACTER*4 IW2HOL
      CHARACTER*4 IW22HO
      CHARACTER*4 IOP
      CHARACTER*4 IPAROC
      CHARACTER*4 IPARO3
      CHARACTER*4 IREPU
      CHARACTER*4 IRESU
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 IHLEFT
      CHARACTER*4 IHLEF2
      CHARACTER*4 IPARN
      CHARACTER*4 IPARN2
      CHARACTER*4 IPARN3
      CHARACTER*4 IPARN4
      CHARACTER*4 IHPARN
      CHARACTER*4 IHPAR2
      CHARACTER*4 IVARN3
      CHARACTER*4 IVARN4
      CHARACTER*4 IREP
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
!
      DIMENSION IPAROC(100)
      DIMENSION PARAM(100)
      DIMENSION IPARN(100)
      DIMENSION IPARN2(100)
      DIMENSION PARAM3(100)
      DIMENSION IPARN3(100)
      DIMENSION IPARN4(100)
      DIMENSION ICON3(100)
      DIMENSION IPARO3(100)
      DIMENSION PARLI3(100)
      DIMENSION IVARN3(100)
      DIMENSION IVARN4(100)
      DIMENSION ICOLV3(100)
      DIMENSION NIV(100)
      DIMENSION ITYPEH(1000)
      DIMENSION IW2HOL(1000)
      DIMENSION IW22HO(1000)
      DIMENSION W2HOLD(1000)
      DIMENSION ICH(10)
!
      DIMENSION XMAT(MAXOBV,5)
      DIMENSION W(MAXOBV)
      DIMENSION PRED2(MAXOBV)
      DIMENSION RES2(MAXOBV)
      DIMENSION DUM1(MAXOBV)
      DIMENSION DUM2(MAXOBV)
      DIMENSION VSCRT(10*MAXOBV)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCODA.INC'
!
!---------------------------------------------------------------------
!
      EQUIVALENCE (GARBAG(IGARB1),XMAT(1,1))
      EQUIVALENCE (GARBAG(IGARB6),DUM1(1))
      EQUIVALENCE (GARBAG(IGARB7),DUM2(1))
      EQUIVALENCE (GARBAG(IGARB8),RES2(1))
      EQUIVALENCE (GARBAG(IGARB9),W(1))
      EQUIVALENCE (GARBAG(IGAR10),PRED2(1))
      EQUIVALENCE (GARBAG(JGAR11),VSCRT(1))
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPPR'
      ISUBN2='EF  '
      IERROR='NO'
      IPAROC(1)='NONE'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
      MAXV2=5
      MINN2=2
      MAXITS=IFITIT
      MAXN2=MAXCHF
      MAXN3=MAXCHF
      MAXN4=MAXCHF
      NUMPV=(-999)
      IP=(-999)
      IV=(-999)
      IWIDMO=(-999)
      ICOLL=(-999)
      IVAL=(-999)
      K1=0
!
      CPUEPS=R1MACH(3)
      CUTOFF=2**(NUMBPW-3)
!
!               ******************************
!               **  TREAT THE PRE-FIT CASE  **
!               ******************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPREF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)IBUGA2,IBUGA3,IBUGCO,IBUGEV,IBUGQ
   54   FORMAT('IBUGA2,IBUGA3,IBUGCO,IBUGEV,IBUGQ = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,56)NUMNAM
   56   FORMAT('NUMNAM = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 57 I=1,NUMNAM
          WRITE(ICOUT,58)I,IHNAME(I),IHNAM2(I),IUSE(I),IN(I),IVALUE(I),   &
                         VALUE(I)
   58     FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I),IN(I),IVALUE(I)',   &
                 'VALUE(I) = ',I8,2X,2A4,2X,A4,2I8,G15.7)
         CALL DPWRST('XXX','BUG ')
   57   CONTINUE
      ENDIF
!
!               ***************************
!               **  STEP 1--             **
!               **  EXTRACT THE COMMAND  **
!               ***************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL CKPREF(ICASFI,ILOCFI,IBUGA3,IFOUND,IERROR)
      IF(ICASFI.EQ.'    '.OR.IFOUND.EQ.'NO')GO TO 9000
!
!               *******************************************************
!               **  STEP 2--                                         **
!               **  CHECK FOR THE PROPER NUMBER OF INPUT ARGUMENTS.  **
!               *******************************************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      MINNA=0
      MAXNA=100
      CALL CHECKA(NUMARG,MINNA,MAXNA,IANS,IWIDTH,ISUBN1,ISUBN2,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               ********************************************************
!               **  STEP 3--                                           *
!               **  FOR THE CASES WHEN HAVE PRE-FIT Y = SOME EXPRESSION*
!               **                   ROBUST PRE-FIT Y = SOME EXPRESSION*
!               **  DETERMINE IF WE HAVE A VALID FUNCTIONAL            *
!               **  EXPRESSION--IN PARTICULAR, CHECK THAT THE NUMBER   *
!               **  OF ARGUMENTS IS AT LEAST 1, AND ALSO CHECK THAT    *
!               **  THERE IS EXACTLY 1 EQUAL SIGN AND THAT THIS EQUAL  *
!               **  SIGN OCCURS AS THE SECOND ARGUMENT.                *
!               ********************************************************
!
      ISTEPN='3'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.LT.1)THEN
        WRITE(ICOUT,2001)
 2001   FORMAT('***** ERROR IN DPPREF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2002)
 2002   FORMAT('      THE NUMBER OF ARGUMENTS DETECTED FOR THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2003)NUMARG
 2003   FORMAT('      PRE-FIT COMMAND = 0.  NUMARG = ',I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2007)
 2007   FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,2008)(IANS(J),J=1,MIN(100,IWIDTH))
 2008     FORMAT('      COMMAND LINE--',100A1)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      DO 2100 J=1,NUMARG
      J1=J
      IF(IHARG(J).EQ.'SUBS'.AND.IHARG2(J).EQ.'ET  ')GO TO 2110
      IF(IHARG(J).EQ.'EXCE'.AND.IHARG2(J).EQ.'PT  ')GO TO 2110
      IF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    ')GO TO 2110
 2100 CONTINUE
      ILOCQ=NUMARG+1
      GO TO 2120
 2110 CONTINUE
      ILOCQ=J1
      GO TO 2120
 2120 CONTINUE
!
      IF(ICASFI.EQ.'FIT' .OR. ICASFI.EQ.'RFIT')THEN
        NUMEQ=0
        IMAX=ILOCQ-1
        DO 2130 I=1,IMAX
          IF(IHARG(I).EQ.'=   '.AND.IHARG2(I).EQ.'    ')NUMEQ=NUMEQ+1
 2130   CONTINUE
        IF(NUMEQ.NE.1)THEN
          WRITE(ICOUT,2001)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2132)
 2132     FORMAT('      THE NUMBER OF EQUAL SIGNS DETECTED IN THE')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2133)NUMEQ
 2133     FORMAT('      MODEL IS NOT EQUAL 1.  NUMEQ = ',I6)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2134)NUMARG,IMAX
 2134     FORMAT('      NUMARG, IMAX = ',2I10)
          CALL DPWRST('XXX','BUG ')
          DO 2135 I=1,NUMARG
            WRITE(ICOUT,2136)I,IHARG(I),IHARG2(I)
 2136       FORMAT('I,IHARG(I),IHARG2(I) = ',I8,2A4)
            CALL DPWRST('XXX','BUG ')
 2135     CONTINUE
          WRITE(ICOUT,2007)
          CALL DPWRST('XXX','BUG ')
          IF(IWIDTH.GE.1)THEN
            WRITE(ICOUT,2008)(IANS(J),J=1,MIN(100,IWIDTH))
            CALL DPWRST('XXX','BUG ')
          ENDIF
          IERROR='YES'
          GO TO 9000
      ENDIF
!
      IF((ICASFI.EQ.'FIT'.AND.IHARG(2).NE.'=') .OR.   &
         (ICASFI.EQ.'RFIT'.AND.IHARG(3).NE.'='))THEN
        WRITE(ICOUT,2001)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2202)
 2202   FORMAT('      WHEN PRE-FITTING GENERAL EXPRESSIONS, THE ',   &
               'SECOND ARGUMENT')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2203)
 2203   FORMAT('      AFTER THE WORD   PRE-FIT   SHOULD BE (BUT ',   &
               'WAS NOT) AND EQUAL SIGN.')
        CALL DPWRST('XXX','BUG ')
        IF(ICASFI.EQ.'FIT')THEN
          WRITE(ICOUT,2205)IHARG(2),IHARG2(2)
 2205     FORMAT('     THE ARGUMENT WAS ',2A4)
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICASFI.EQ.'RFIT')THEN
          WRITE(ICOUT,2205)IHARG(3),IHARG2(3)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        WRITE(ICOUT,2007)
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,2008)(IANS(J),J=1,MIN(100,IWIDTH))
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************************
!               **  STEP 4--                                          **
!               **  FOR ALL VARIATIONS OF THE PRE-FIT COMMAND, THE    **
!               **  WORD AFTER   PRE-FIT   SHOULD BE THE RESPONSE     **
!               **  VARIABLE (= THE DEPENDENT VARIABLE).  EXTRACT     **
!               **  THE RESPONSE VARIABLE AND DETERMINE IF IT IS      **
!               **  ALREADY IN THE NAME LIST AS A VARIABLE.           **
!               ********************************************************
!
      ISTEPN='4'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      I=0
      I2=I
      IP1=I+1
!
      IF(ICASFI.EQ.'RFIT')THEN
        IMAX=ILOCQ-1
        DO 2330 I=1,IMAX
          I2=I
          IF(IHARG(I).EQ.'PREF' .OR. IHARG(I).EQ.'PRE ')GO TO 2349
 2330   CONTINUE
        WRITE(ICOUT,2331)
 2331   FORMAT('***** INTERNAL ERROR IN DPPREF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2332)
 2332   FORMAT('      THE WORD    PRE   WAS NOT FOUND IN THE ',   &
               'ARGUMENT LIST')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3334)
 3334   FORMAT('      EVEN THOUGH IT HAD BEEN PREVIOSULY FOUND.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2134)NUMARG,IMAX
        CALL DPWRST('XXX','BUG ')
        DO 2336 I=1,NUMARG
          WRITE(ICOUT,2337)I,IHARG(I),IHARG2(I)
 2337     FORMAT('I,IHARG(I),IHARG2(I) = ',I8,2A4)
          CALL DPWRST('XXX','BUG ')
 2336   CONTINUE
        WRITE(ICOUT,2007)
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,2008)(IANS(J),J=1,MIN(100,IWIDTH))
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IERROR='YES'
        GO TO 9000
      ENDIF
!
 2349 CONTINUE
      ILOCFI=I2
      ILOCF1=ILOCFI+1
      IHLEFT=IHARG(ILOCF1)
      IHLEF2=IHARG2(ILOCF1)
      DO 2350 I=1,NUMNAM
        I2=I
        IF(IHLEFT.EQ.IHNAME(I2).AND.IHLEF2.EQ.IHNAM2(I2).AND.   &
           IUSE(I2).EQ.'V')THEN
          ILOCV=I2
          ICOLL=IVALUE(ILOCV)
          NLEFT=IN(ILOCV)
          GO TO 2390
        ENDIF
 2350 CONTINUE
!
      WRITE(ICOUT,2001)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2362)
 2362 FORMAT('      THE NAME FOLLOWING THE WORD    PRE-FIT    (WHICH ',   &
             'SHOULD BE THE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2363)
 2363 FORMAT('      RESPONSE VARIABLE) DOES NOT EXIST IN THE CURRENT ',   &
             'NAME TABLE AS A VARIABLE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2369)IHLEFT,IHLEF2
 2369 FORMAT('      THE NAME AFTER THE WORD   PRE-FIT   = ',2A4)
      CALL DPWRST('XXX','BUG ')
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2372)
 2372   FORMAT('      CURRENT LIST OF DEFINED VARIABLES AND ',   &
               'PARAMETERS--')
        CALL DPWRST('XXX','BUG ')
        DO 2373 K2=1,NUMNAM
          WRITE(ICOUT,2374)IHNAME(K2),IHNAM2(K2),IUSE(K2),IVALUE(K2),   &
                           VALUE(K2)
 2374     FORMAT(6X,2A4,6X,A4,6X,I6,6X,G15.7)
          CALL DPWRST('XXX','BUG ')
 2373   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2376)IHLEFT,IHLEF2,ILOCFI,ILOCF1,I2
 2376   FORMAT('      IHLEFT,IHLEF2,ILOCFI,ILOCF1,I2 = ',2(A4,2X),3I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      WRITE(ICOUT,2007)
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)THEN
        WRITE(ICOUT,2008)(IANS(J),J=1,MIN(100,IWIDTH))
        CALL DPWRST('XXX','BUG ')
      ENDIF
      IERROR='YES'
      GO TO 9000
!
 2390 CONTINUE
!
!               ********************************************************
!               **  STEP 5--                                          **
!               **  FOR ALL VARIATIONS OF THE PRE-FIT COMMAND,        **
!               **  CHECK THAT THE INPUT NUMBER OF OBSERVATIONS       **
!               **  (NLEFT) FOR THE RESPONSE VARIABLE IS 2 OR LARGER. **
!               ********************************************************
!
      ISTEPN='5'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NLEFT.LT.MINN2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2001)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,312)IHLEFT,IHLEF2
  312   FORMAT('      THE NUMBER OF OBSERVATIONS IN VARIABLE ',2A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,313)MINN2
  313   FORMAT('      FOR THE PRE-FIT COMMAND MUST BE ',I5,   &
               ' OR LARGER;')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,316)
  316   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,317)NLEFT
  317   FORMAT('      THE NUMBER OF OBSERVATIONS (NLEFT) = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2007)
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,2008)(IANS(I),I=1,MIN(100,IWIDTH))
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               *********************************************************
!               **  STEP 6.1--                                          *
!               **  FOR THE CASES WHEN HAVE PRE-FIT Y = SOME EXPRESSION *
!               **                   ROBUST PRE-FIT Y = SOME EXPRESSION *
!               **  EXTRACT THE ENTIRE (LEFT AND RIGHT SIDE) FUNCTIONAL *
!               **  EXPRESSION FROM THE INPUT COMMAND LINE.             *
!               **  COPY OUT TO IWIDTH, OR OUT TO 'SUBS' (EXCLUSIVE),   *
!               **  OR OUT THE 'EXCE' (EXCLUSIVE)                       *
!               **  OR OUT THE 'FOR' (EXCLUSIVE).                       *
!               *********************************************************
!
      ISTEPN='6.1'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.EQ.0 .OR.   &
          (IHARG(1).EQ.'SUBS'.AND.IHARG2(1).EQ.'ET  ') .OR.   &
          (IHARG(1).EQ.'EXCE'.AND.IHARG2(1).EQ.'PT  ') .OR.   &
          (IHARG(1).EQ.'FOR '.AND.IHARG2(1).EQ.'    '))GO TO 4160
        ISTART=-99
        ISTOP=-99
        DO 4110 I=1,IWIDTH
          IP1=I+1
          IP2=I+2
          IP3=I+3
          IP4=I+4
          IP5=I+5
          IP6=I+6
          IP7=I+7
!
          IF(IP2.GT.IWIDTH)GO TO 4120
          IF(IANS(I).EQ.'F'.AND.IANS(IP1).EQ.'I' .AND.   &
             IANS(IP2).EQ.'T')ISTART=IP3
!
          IF(IP4.GT.IWIDTH)GO TO 4120
          IF(IANS(I).EQ.' ' .AND. IANS(IP1).EQ.'F' .AND.   &
             IANS(IP2).EQ.'O' .AND. IANS(IP3).EQ.'R' .AND.   &
             IANS(IP4).EQ.' ')ISTOP=I
!
          IF(IP7.GT.IWIDTH)GO TO 4120
          IF(IANS(I).EQ.' ' .AND. IANS(IP1).EQ.'S' .AND.   &
             IANS(IP2).EQ.'U' .AND. IANS(IP3).EQ.'B' .AND.   &
             IANS(IP4).EQ.'S' .AND. IANS(IP5).EQ.'E' .AND.   &
             IANS(IP6).EQ.'T'.AND.IANS(IP7).EQ.' ')ISTOP=I
!
 4110   CONTINUE
 4120   CONTINUE
        IF(ISTART.LT.1)THEN
          IBRAN=4120
          WRITE(ICOUT,4121)IBRAN
 4121     FORMAT('*****INTERNAL ERROR IN DPPREF--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,4122)IBRAN
 4122     FORMAT('     AT BRANCH POINT = ',I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,4123)
 4123     FORMAT('     THE STRING   PRE-FIT  NOT FOUND FOR MODEL ',   &
                 'EXTRACTION')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2007)
          CALL DPWRST('XXX','BUG ')
          IF(IWIDTH.GE.1)THEN
            WRITE(ICOUT,2008)(IANS(I),I=1,MIN(100,IWIDTH))
            CALL DPWRST('XXX','BUG ')
          ENDIF
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        IF(ISTOP.EQ.-99)ISTOP=IWIDTH
        IF(ISTART.GT.ISTOP)THEN
          IBRAN=4130
          WRITE(ICOUT,2001)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,4122)IBRAN
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,4133)
 4133     FORMAT('      ISTART GREATER THAN ISTOP FOR MODEL EXTRACTION')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,4134)ISTART,ISTOP
 4134     FORMAT('ISTART, ISTOP = ',2I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2007)
          CALL DPWRST('XXX','BUG ')
          IF(IWIDTH.GE.1)THEN
            WRITE(ICOUT,2008)(IANS(I),I=1,MIN(100,IWIDTH))
            CALL DPWRST('XXX','BUG ')
          ENDIF
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        J=0
        DO 4150 I=ISTART,ISTOP
          J=J+1
          MODEL(J)=IANS(I)
 4150   CONTINUE
        NUMCHA=ISTOP-ISTART+1
 4160   CONTINUE
      ENDIF
!
!               ***************************************************
!               **  STEP 6.2--                                   **
!               **  FOR THE CASES WHEN HAVE ... PRE-FIT Y X   ,  **
!               **  EXTRACT THE INDEPENDENT VARIABLE,            **
!               **  AND FORM THE 1 CHARACTER PER WORD            **
!               **  REPRESENTATION OF THE MODEL.                 **
!               ***************************************************
!
      ISTEPN='6.2'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICASFI.EQ.'FIT' .OR.ICASFI.EQ.'RFIT')GO TO 4290
!
      ILOCRV=ILOCFI+1
      ILOCIV=ILOCFI+2
!
      IDEGRE=0
      IF(ICASFI.EQ.'0FIT')IDEGRE=0
      IF(ICASFI.EQ.'1FIT')IDEGRE=1
      IF(ICASFI.EQ.'2FIT')IDEGRE=2
      IF(ICASFI.EQ.'3FIT')IDEGRE=3
      IF(ICASFI.EQ.'4FIT')IDEGRE=4
      IF(ICASFI.EQ.'5FIT')IDEGRE=5
      IF(ICASFI.EQ.'6FIT')IDEGRE=6
      IF(ICASFI.EQ.'7FIT')IDEGRE=7
      IF(ICASFI.EQ.'8FIT')IDEGRE=8
      IF(ICASFI.EQ.'9FIT')IDEGRE=9
      IF(ICASFI.EQ.'10FI')IDEGRE=10
      K1=IDEGRE+1
!
      I=0
!
      IWD=IHARG(ILOCRV)
      CALL DPXH1H(IWD,ICH,IEND,IBUGA3)
      IF(IEND.LE.0)GO TO 4219
      DO 4210 J=1,IEND
        I=I+1
        MODEL(I)=ICH(J)
 4210 CONTINUE
 4219 CONTINUE
!
      IWD=IHARG2(ILOCRV)
      CALL DPXH1H(IWD,ICH,IEND,IBUGA3)
      IF(IEND.LE.0)GO TO 4229
      DO 4220 J=1,IEND
        I=I+1
        MODEL(I)=ICH(J)
 4220 CONTINUE
 4229 CONTINUE
!
      KMAX=IDEGRE+1
      I=I+1
      MODEL(I)='='
!
      KMAX=IDEGRE+1
      DO 4250 K=1,KMAX
        KM1=K-1
!
        IF(KM1.GT.0)THEN
          I=I+1
          MODEL(I)='+'
        ENDIF
!
        I=I+1
        MODEL(I)='A'
!
        IF(0.LE.KM1.AND.KM1.LE.10)I=I+1
        IF(KM1.EQ.0)MODEL(I)='0'
        IF(KM1.EQ.1)MODEL(I)='1'
        IF(KM1.EQ.2)MODEL(I)='2'
        IF(KM1.EQ.3)MODEL(I)='3'
        IF(KM1.EQ.4)MODEL(I)='4'
        IF(KM1.EQ.5)MODEL(I)='5'
        IF(KM1.EQ.6)MODEL(I)='6'
        IF(KM1.EQ.7)MODEL(I)='7'
        IF(KM1.EQ.8)MODEL(I)='8'
        IF(KM1.EQ.9)MODEL(I)='9'
        IF(KM1.EQ.10)MODEL(I)='1'
        IF(KM1.EQ.10)I=I+1
        IF(J.EQ.10)MODEL(I)='0'
!
        IF(KM1.LE.0)GO TO 4250
!
        I=I+1
        MODEL(I)='*'
!
        IWD=IHARG(ILOCIV)
        CALL DPXH1H(IWD,ICH,IEND,IBUGA3)
        IF(IEND.GT.0)THEN
          DO 4260 J=1,IEND
            I=I+1
            MODEL(I)=ICH(J)
 4260     CONTINUE
        ENDIF
!
        IWD=IHARG2(ILOCIV)
        CALL DPXH1H(IWD,ICH,IEND,IBUGA3)
        IF(IEND.GT.0)THEN
          DO 4270 J=1,IEND
            I=I+1
            MODEL(I)=ICH(J)
 4270     CONTINUE
        ENDIF
!
        IF(KM1.LE.1)GO TO 4250
!
        I=I+1
        MODEL(I)='*'
        I=I+1
        MODEL(I)='*'
!
        IF(0.LE.KM1.AND.KM1.LE.10)I=I+1
        IF(KM1.EQ.0)MODEL(I)='0'
        IF(KM1.EQ.1)MODEL(I)='1'
        IF(KM1.EQ.2)MODEL(I)='2'
        IF(KM1.EQ.3)MODEL(I)='3'
        IF(KM1.EQ.4)MODEL(I)='4'
        IF(KM1.EQ.5)MODEL(I)='5'
        IF(KM1.EQ.6)MODEL(I)='6'
        IF(KM1.EQ.7)MODEL(I)='7'
        IF(KM1.EQ.8)MODEL(I)='8'
        IF(KM1.EQ.9)MODEL(I)='9'
        IF(KM1.EQ.10)MODEL(I)='1'
        IF(KM1.EQ.10)I=I+1
        IF(J.EQ.10)MODEL(I)='0'
!
 4250 CONTINUE
 4290 CONTINUE
      IWIDMO=I
      NUMCHA=IWIDMO
!
!               **************************************************
!               **  STEP 6.3--                                  **
!               **  FOR ALL VARIATIONS OF THE PRE-FIT COMMAND,  **
!               **  CHECK TO SEE THE TYPE CASE--                **
!               **    1) UNQUALIFIED (THAT IS, FULL);           **
!               **    2) SUBSET/EXCEPT; OR                      **
!               **    3) FOR.                                   **
!               **************************************************
!
      ISTEPN='6.3'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASEQ='FULL'
      ILOCQ=NUMARG+1
      IF(NUMARG.GE.1)THEN
        DO 400 J=1,NUMARG
          J1=J
          IF((IHARG(J).EQ.'SUBS'.AND.IHARG2(J).EQ.'ET  ') .OR.   &
             (IHARG(J).EQ.'EXCE'.AND.IHARG2(J).EQ.'PT  '))THEN
            ICASEQ='SUBS'
            IKEY='SUBS'
            IF(IHARG(J1).EQ.'EXCE')IKEY='EXCE'
            ILOCQ=J1
            GO TO 490
          ELSEIF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    ')THEN
            ICASEQ='FOR'
            ILOCQ=J1
            GO TO 490
          ENDIF
  400   CONTINUE
  490   CONTINUE
      ENDIF
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')THEN
        WRITE(ICOUT,491)NUMARG,ILOCQ
  491   FORMAT('NUMARG,ILOCQ = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               **************************************************
!               **  STEP 6.4--                                  **
!               **  FOR ALL VARIATIONS OF THE PRE-FIT COMMAND,  **
!               **  EXTRACT THE UNDERLYING FUNCTION             **
!               **  FROM FUNCTION DEFINITIONS.                  **
!               **************************************************
!
!
      ISTEPN='6.4'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 5170 I=1,NUMCHA
        I2=I
        IF(MODEL(I).EQ.'=')GO TO 5175
 5170 CONTINUE
!
      IBRAN=5170
      WRITE(ICOUT,4121)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,4122)IBRAN
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5172)
 5172 FORMAT('      NO EQUAL SIGN FOUND FOR MODEL EXTRACTION')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2007)
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)THEN
        WRITE(ICOUT,2008)(IANS(I),I=1,MIN(100,IWIDTH))
        CALL DPWRST('XXX','BUG ')
      ENDIF
      IERROR='YES'
      GO TO 9000
!
 5175 CONTINUE
      ILOCEQ=I2
!
      IWD1='=   '
      IWD12='    '
      IF(ICASEQ.EQ.'FULL')IWD2='    '
      IF(ICASEQ.EQ.'FULL')IWD22='    '
      IF(ICASEQ.EQ.'SUBS'.AND.IKEY.EQ.'SUBS')IWD2='SUBS'
      IF(ICASEQ.EQ.'SUBS'.AND.IKEY.EQ.'SUBS')IWD22='ET  '
      IF(ICASEQ.EQ.'SUBS'.AND.IKEY.EQ.'EXCE')IWD2='EXCE'
      IF(ICASEQ.EQ.'SUBS'.AND.IKEY.EQ.'EXCE')IWD22='PT  '
      IF(ICASEQ.EQ.'FOR')IWD2='FOR '
      IF(ICASEQ.EQ.'FOR')IWD22='    '
!
      IF(ICASFI.EQ.'FIT'.OR.ICASFI.EQ.'RFIT')THEN
        CALL DPEXST(IANS,IWIDTH,IWD1,IWD12,IWD2,IWD22,MAXN2,   &
                    IFUNC2,N2,IBUGA3,IFOUND,IERROR)
      ELSEIF(ICASFI.NE.'FIT'.AND.ICASFI.NE.'RFIT')THEN
        CALL DPEXST(MODEL,IWIDMO,IWD1,IWD12,IWD2,IWD22,MAXN2,   &
                    IFUNC2,N2,IBUGA3,IFOUND,IERROR)
      ENDIF
      IF(IERROR.EQ.'YES')GO TO 9000
      IF(IFOUND.EQ.'NO')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2001)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3372)
 3372   FORMAT('      INVALID COMMAND FORM FOR PRE-FITTING.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3373)
 3373   FORMAT('      GENERAL FORM--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3374)
 3374   FORMAT('      PRE-FIT ... = ...  SUBSET ... ... ...')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2007)
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,2008)(IANS(I),I=1,MIN(100,IWIDTH))
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      CALL DPEXFU(IFUNC2,N2,IHNAME,IHNAM2,IUSE,IVSTAR,IVSTOP,   &
      NUMNAM,IANS,IWIDTH,IFUNC,NUMCHF,MAXCHF,IFUNC3,N3,MAXN3,   &
      IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      J=ILOCEQ
      DO 5180 I=1,N3
        J=J+1
        MODEL(J)=IFUNC3(I)
 5180 CONTINUE
      NUMCHA=J
!
!               ********************************************************
!               **  STEP 7--                                          **
!               **  MAKE A NON-CALCULATING PASS AT THE MODEL          **
!               **  SO AS TO EXTRACT ALL PARAMETER AND VARIABLE NAMES.**
!               ********************************************************
!
      ISTEPN='7'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IPASS=1
      CALL COMPIM(MODEL,NUMCHA,IPASS,PARAM,IPARN,IPARN2,NUMPV,   &
                  IANGLU,ITYPEH,IW2HOL,IW22HO,W2HOLD,NWHOLD,AJUNK,   &
                  IBUGCO,IBUGEV,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               ********************************************
!               **  STEP 8--                              **
!               **  CHECK TO MAKE SURE THAT THE COMBINED  **
!               **  NUMBER OF PARAMETERS AND VARIABLES    **
!               **  IN THE MODEL IS AT LEAST 1.           **
!               ********************************************
!
      ISTEPN='8'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMPV.LT.1)THEN
        WRITE(ICOUT,2001)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,4402)
 4402   FORMAT('      COMBINED NUMBER OF PARAMETERS AND VARIABLES')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,4403)NUMVAR
 4403   FORMAT('      DETECTED IN THE MODEL IS 0.   NUMVP = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,4407)NUMCHA
 4407   FORMAT('      NUMBER OF CHARACTERS IN MODEL = ',I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMCHA.GE.1)THEN
          WRITE(ICOUT,4408)(MODEL(J),J=1,MIN(100,NUMCHA))
 4408     FORMAT('      MODEL--',100A1)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************************
!               **  STEP 9--                                          **
!               **  CHECK THAT ALL VARIABLES IN THE MODEL ARE ALREADY **
!               **  PRESENT IN THE NAME LIST IHNAME(.) AND IHNAM2(.). **
!               **  CHECK THAT ALL PARAMETERS IN THE MODEL ARE        **
!               **  ALREADY PRESENT IN THE NAME LIST IHNAME(.) AND    **
!               **  IHNAM2(.).   ALL NAMES IN THE MODEL THAT ARE NOT  **
!               **  IN THE NAME LIST AT ALL WILL BE ADDED TO THE LIST,**
!               **  DEFINED AS PARAMETERS, AND GIVEN A VALUE OF 1.0.  **
!               **  THIS ALLOWS US TO MAKE AN INITIAL PRE-FIT WITHOUT **
!               **  HAVING TO DEFINE STARTING VALUES AT ALL (THEY WILL**
!               **  BE AUTOMATICALLY SET TO 1.0).  ALSO, FORM A NEW   **
!               **  VECTOR WHICH HAS ONLY PARAMETER NAMES AND ANOTHER **
!               **  VECTOR WHICH HAS ONLY VARIABLE NAMES.             **
!               ********************************************************
!
      ISTEPN='9'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IP=0
      IV=0
      DO 4165 J=1,NUMPV
        IHPARN=IPARN(J)
        IHPAR2=IPARN2(J)
        DO 4166 I=1,NUMNAM
          I2=I
          IF(IHPARN.EQ.IHNAME(I).AND.IHPAR2.EQ.IHNAM2(I).AND.   &
             IUSE(I).EQ.'V')THEN
            IV=IV+1
            IVARN3(IV)=IPARN(J)
            IVARN4(IV)=IPARN2(J)
            ICOLV3(IV)=IVALUE(I2)
            NIV(IV)=IN(I2)
            GO TO 4165
          ELSEIF(IHPARN.EQ.IHNAME(I).AND.IHPAR2.EQ.IHNAM2(I).AND.   &
                 IUSE(I).EQ.'P')THEN
            IP=IP+1
            IPARN3(IP)=IPARN(J)
            IPARN4(IP)=IPARN2(J)
            PARAM3(IP)=VALUE(I2)
            GO TO 4165
          ENDIF
 4166   CONTINUE
        IP=IP+1
        IPARN3(IP)=IPARN(J)
        IPARN4(IP)=IPARN2(J)
        PARAM3(IP)=1.0
!
        IF(NUMNAM.GE.MAXNAM)THEN
          WRITE(ICOUT,2001)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,7752)
 7752     FORMAT('      THE TOTAL NUMBER OF (VARIABLE + PARAMETER)')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,7753)MAXNAM
 7753     FORMAT('      NAMES MUST BE AT MOST ',I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,7754)
 7754     FORMAT('      SUCH WAS NOT THE CASE HERE--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,7755)
 7755     FORMAT('      THE MAXIMUM ALLOWABLE NUMBER OF NAMES WAS ',   &
                 'JUST EXCEEDED.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,7757)
 7757     FORMAT('      SUGGESTED ACTION--ENTER     STATUS')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,7758)
 7758     FORMAT('      TO DETERMINE THE IMPORTANT (VERSUS ',   &
                 'UNIMPORTANT) VARIABLES')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,7760)
 7760     FORMAT('      AND PARAMETERS, AND THEN REUSE SOME OF THE ',   &
                 'NAMES.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2007)
          CALL DPWRST('XXX','BUG ')
          IF(IWIDTH.GE.1)THEN
            WRITE(ICOUT,2008)(IANS(I),I=1,MIN(100,IWIDTH))
            CALL DPWRST('XXX','BUG ')
          ENDIF
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        I2=NUMNAM+1
        IHNAME(I2)=IPARN(J)
        IHNAM2(I2)=IPARN2(J)
        IUSE(I2)='P'
        IVALUE(I2)=1
        VALUE(I2)=1.0
        IN(I2)=1
        NUMNAM=I2
!
 4165 CONTINUE
      NUMPAR=IP
      NUMVAR=IV
!
!               *******************************************
!               **  STEP 10--                            **
!               **  CHECK FOR A VALID NUMBER             **
!               **  OF INDEPENDENT VARIABLES (1 TO 5).   **
!               **  CHECK THE VALIDITY OF EACH           **
!               **  OF THE INDEPENDENT VARIABLES.        **
!               **  DOES THE NAME EXIST IN THE TABLE?    **
!               **  DOES THE NUMBER OF ELEMENTS          **
!               **  AGREE WITH THE NUMBER OF ELEMENTS    **
!               **  IN THE RESPONSE VARIABLE?            **
!               *******************************************
!
      ISTEPN='10'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMVAR.LT.1.OR.NUMVAR.GT.MAXV2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2001)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,552)
  552   FORMAT('      FOR A LEAST SQUARES PRE-FIT, THE NUMBER OF ',   &
               'INDEPENDENT')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,554)MAXV2
  554   FORMAT('      VARIABLES MUST BE AT LEAST 1 AND AT MOST ',   &
               I8,';')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,555)
  555   FORMAT('      SUCH WAS NOT THE CASE HERE;  THE SPECIFIED ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,557)NUMVAR
  557   FORMAT('      NUMBER OF INDEPENDENT VARIABLES WAS ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2007)
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,2008)(IANS(I),I=1,MIN(100,IWIDTH))
          CALL DPWRST('XXX','BUG ')
        ENDIF
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,4507)NUMCHA
 4507   FORMAT('      NUMBER OF CHARACTERS IN MODEL = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,4508)(MODEL(J),J=1,MIN(100,NUMCHA))
 4508   FORMAT('      MODEL--',100A1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,4504)
 4504   FORMAT('      VARIABLES EXTRACTED FROM MODEL--')
        CALL DPWRST('XXX','BUG ')
        DO 4505 J=1,NUMVAR
          WRITE(ICOUT,4506)J,IVARN3(J),IVARN4(J),ICOLV3(J)
 4506     FORMAT('I,IVARN3(I),IVARN4(I),ICOLV3(I) = ',I8,2X,2A4,2X,I8)
          CALL DPWRST('XXX','BUG ')
 4505   CONTINUE
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      DO 540 J=1,NUMVAR
        IF(NIV(J).NE.NLEFT)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2001)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,562)
  562     FORMAT('      FOR A LEAST SQUARES PRE-FIT, THE NUMBER OF ',   &
                 'ELEMENTS')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,564)
  564     FORMAT('      IN EACH INDEPENDENT VARIABLE SHOULD BE THE ',   &
                 'SAME AS THE')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,566)
  566     FORMAT('      NUMBER OF ELEMENTS IN THE DEPENDENT VARIABLE ',   &
                 '(RESPONSE);')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,567)
  567     FORMAT('      SUCH WAS NOT THE CASE HERE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,571)
  571     FORMAT('      DEPENDENT   VARIABLE  (RESPONSE)--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,572)IHLEFT,IHLEF2,NLEFT
  572     FORMAT('                  ',2A4,'  HAS ',I8,' ELEMENTS')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,576)
  576     FORMAT('      INDEPENDENT VARIABLES           --')
          CALL DPWRST('XXX','BUG ')
          DO 580 JJ=1,NUMVAR
            WRITE(ICOUT,578)IVARN3(JJ),IVARN4(JJ),NIV(JJ)
  578       FORMAT('                  ',2A4,'  HAS ',I8,' ELEMENTS')
            CALL DPWRST('XXX','BUG ')
  580     CONTINUE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2007)
          CALL DPWRST('XXX','BUG ')
          IF(IWIDTH.GE.1)THEN
            WRITE(ICOUT,2008)(IANS(I),I=1,MIN(100,IWIDTH))
            CALL DPWRST('XXX','BUG ')
          ENDIF
          IERROR='YES'
          GO TO 9000
        ENDIF
  540 CONTINUE
!
!               ********************************************************
!               **  STEP 11--                                         **
!               **  DUMP THE COMMON VECTOR V(.) OUT ONTO MASS STORAGE **
!               **  SO AS TO PRESERVE THEIR CONTENTS FOR LATER USE    **
!               **  (AFTER DPPRE2).                                   **
!               **  THE ABOVE DUMP TO MASS STORAGE IS UNNECESSARY AND **
!               **  IS NOT DONE FOR THE SPECIAL CASE WHEN THE NUMBER  **
!               **  OF PARAMETERS IS 0 (A NO-PRE-FIT CASE WHEREBY WE  **
!               **  ARE REALLY INTERESTED IN GENERATING PREDICTED     **
!               **  VALUES AND RESIDUALS FOR A GIVEN FULLY-SPECIFIED  **
!               **  MODEL).                                           **
!               ********************************************************
!
      ISTEPN='11'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IOP='WRIT'
!CCCC CALL DPSWAP(IOP,V,NUMNAM,IHNAME,IHNAM2,IUSE,IN,
!CCCC1IVALUE,MAXN,MAXCOL,MAXN2,MAXCO2,MAXIJ2,IBUGA3,ISUBRO,IERROR)
!
!               ********************************************************
!               **  STEP 12--                                         **
!               **  BRANCH TO THE APPROPRIATE SUBCASE; THEN COPY OVER **
!               **  THE RESPONSE VECTOR TO BE USED IN THE MODEL INTO  **
!               **  THE VECTOR Y; AND COPY OVER THE VECTORS THAT WERE **
!               **  USED IN THE MODEL INTO THE VECTOR XMAT (MAX       **
!               **  NUMBER OF ALLOWABLE VECTORS = 5.)                 **
!               ********************************************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')THEN
        ISTEPN='12'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,601)N,NUMVAR
  601   FORMAT('N,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(ICASEQ.EQ.'FULL')THEN
        DO 615 I=1,NLEFT
          ISUB(I)=1
  615   CONTINUE
        NQ=NLEFT
      ELSEIF(ICASEQ.EQ.'SUBS')THEN
        NIOLD=NLEFT
        CALL DPSUBS(NIOLD,ILOCS,NS,IBUGQ,IERROR)
        NQ=NIOLD
      ELSEIF(ICASEQ.EQ.'FOR')THEN
        NIOLD=NLEFT
        CALL DPFOR(NIOLD,NFOR,IROW1,IROWN,NLOCAL,ILOCS,NS,IBUGQ,IERROR)
        NQ=NFOR
      ENDIF
!
      IROW=0
      DO 4501 JJ=1,NLEFT
        IF(ISUB(I).EQ.0)GO TO 4501
        IROW=IROW+1
 4501 CONTINUE
!
      K=ICOLL
      J=0
      DO 4500 I=1,NLEFT
        IF(ISUB(I).EQ.0)GO TO 4500
        J=J+1
        IJ=MAXN*(K-1)+I
        IF(K.LE.MAXCOL)Y(J)=V(IJ)
        IF(K.EQ.MAXCP1)Y(J)=PRED(I)
        IF(K.EQ.MAXCP2)Y(J)=RES(I)
        IF(K.EQ.MAXCP3)Y(J)=YPLOT(I)
        IF(K.EQ.MAXCP4)Y(J)=XPLOT(I)
        IF(K.EQ.MAXCP5)Y(J)=X2PLOT(I)
        IF(K.EQ.MAXCP6)Y(J)=TAGPLO(I)
!
        DO 4510 KK=1,NUMVAR
          LL=ICOLV3(KK)
          IJ=MAXN*(LL-1)+I
          IF(K.LE.MAXCOL)XMAT(J,KK)=V(IJ)
          IF(K.EQ.MAXCP1)XMAT(J,KK)=PRED(I)
          IF(K.EQ.MAXCP2)XMAT(J,KK)=RES(I)
          IF(K.EQ.MAXCP3)XMAT(J,KK)=YPLOT(I)
          IF(K.EQ.MAXCP4)XMAT(J,KK)=XPLOT(I)
          IF(K.EQ.MAXCP5)XMAT(J,KK)=X2PLOT(I)
          IF(K.EQ.MAXCP6)XMAT(J,KK)=TAGPLO(I)
 4510   CONTINUE
 4500 CONTINUE
!
      NS=J
!
!               ********************************************************
!               **  STEP 13--                                         **
!               **  PREPARE FOR ENTRANCE INTO DPPRE2--                **
!               **  SET THE WEIGHT VECTOR TO UNITY THROUGHOUT.        **
!               **  SET THE ICON3 VECTOR (WHICH INDICATES WHICH       **
!               **  PARAMETERS ARE TO BE HELD CONSTANT) EQUAL TO 0    **
!               **  THROUGHOUT.  DEFINE CONSTRAINTS AND LIMITS.       **
!               ********************************************************
!
      ISTEPN='13'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 4592 I=1,NS
        W(I)=1.0
 4592 CONTINUE
!
      DO 4195 I=1,NUMPAR
        ICON3(I)=0
 4195 CONTINUE
!
      IF(NUMCON.GT.0)THEN
        DO 4700 I=1,NUMPAR
          DO 4800 J=1,NUMCON
            J2=J
            IF(IPARN3(I).EQ.IPARNC(J).AND.IPARN4(I).EQ.IPANC2(J))THEN
              IPARO3(I)=IPAROC(J2)
              PARLI3(I)=PARLIM(J2)
              GO TO 4700
            ENDIF
 4800     CONTINUE
          IPARO3(I)='NONE'
 4700   CONTINUE
      ENDIF
!
!               ********************
!               **  STEP 14--     **
!               **  ENTER DPPRE2. **
!               ********************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')THEN
        ISTEPN='14'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6081)
 6081   FORMAT('***** FROM DPPREF, AS WE ARE ABOUT TO CALL DPPRE2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6082)NUMCHA,NLEFT,MAXN,NS,NUMPV,NUMPAR,NUMVAR
 6082   FORMAT('NUMCHA,NLEFT,MAXN,NS,NUMPV,NUMPAR,NUMVAR = ',7I8)
        CALL DPWRST('XXX','BUG ')
        DO 6083 I=1,NS
          WRITE(ICOUT,6084)I,Y(I),(XMAT(I,J),J=1,5),W(I)
 6084     FORMAT('I,Y(I),(XMAT(I,J),J=1,5),W(I) = ',I6,2X,7G15.7)
          CALL DPWRST('XXX','BUG ')
 6083   CONTINUE
        WRITE(ICOUT,6085)(MODEL(I),I=1,MIN(120,NUMCHA))
 6085   FORMAT('MODEL(.)--',120A1)
        CALL DPWRST('XXX','BUG ')
        DO 6086 J=1,NUMPAR
          WRITE(ICOUT,6087)J,IPARN3(J),IPARN4(J),PARAM3(J),ICON3(J)
 6087     FORMAT('I,IPARN3(I),IPARN4(I),PARAM3(I),ICON3(I) = ',   &
                 I8,2X,2A4,G15.7,A4)
          CALL DPWRST('XXX','BUG ')
 6086   CONTINUE
        DO 6088 J=1,NUMVAR
          WRITE(ICOUT,6089)J,IVARN3(J),IVARN4(J),ICOLV3(J)
 6089     FORMAT('I,IVARN3(I),IVARN4(I),ICOLV3(I) = ',I8,2X,2A4,2X,I8)
          CALL DPWRST('XXX','BUG ')
 6088   CONTINUE
      ENDIF
!
      CALL DPPRE2(Y,XMAT,MAXOBV,NUMVAR,IVARN3,IVARN4,W,NS,   &
                  MODEL,NUMCHA,PARAM3,IPARN3,IPARN4,NUMPAR,ICON3,   &
                  IANGLU,IPARO3,   &
                  PARLI3,VSCRT,MAXITS,FITSD,FITPOW,CPUEPS,   &
                  ITYPEH,IW2HOL,IW22HO,W2HOLD,NWHOLD,   &
                  IHARG,IHARG2,IARGT,IARG,ARG,NUMARG,   &
                  IREP,REPSD,REPDF,RESSD,RESDF,PRED2,RES2,ALFCDF,   &
                  DUM1,DUM2,IANS,IWIDTH,   &
                  ISUBRO,IBUGA3,IBUGCO,IBUGEV,IERROR)
      IF(IERROR.EQ.'YES')GO TO 8000
!
!               ***************************************
!               **  STEP 15--                        **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
      ISTEPN='15'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICOLPR=MAXCP1
      ICOLRE=MAXCP2
      IREPU='ON'
      IRESU='ON'
      CALL UPDAPR(ICOLPR,ICOLRE,PRED2,RES2,PRED,RES,ISUB,NLEFT,   &
                  IREPU,REPSD,REPDF,IRESU,RESSD,RESDF,ALFCDF,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,ILOCN,IBUGA3,IERROR)
!
      IF(ICASFI.EQ.'FIT' .OR.ICASFI.EQ.'RFIT')GO TO 7900
!
      L=0
      DO 7600 J=1,K1
        L=L+1
        IH2='    '
        IF(J.EQ.1)IH='A0  '
        IF(J.EQ.2)IH='A1  '
        IF(J.EQ.3)IH='A2  '
        IF(J.EQ.4)IH='A3  '
        IF(J.EQ.5)IH='A4  '
        IF(J.LE.5)GO TO 7640
        IF(J.EQ.6)IH='A5  '
        IF(J.EQ.7)IH='A6  '
        IF(J.EQ.8)IH='A7  '
        IF(J.EQ.9)IH='A8  '
        IF(J.EQ.10)IH='A9  '
        IF(J.LE.10)GO TO 7640
        IF(J.EQ.11)IH='A10 '
        IF(J.LE.11)GO TO 7640
!
 7640   CONTINUE
        DO 7650 I=1,NUMNAM
          I2=I
          IF(IH.EQ.IHNAME(I).AND.IH2.EQ.IHNAM2(I).AND.   &
             IUSE(I).EQ.'P')THEN
            VALUE(I2)=PARAM3(L)
            VAL=VALUE(I2)
            IF((-CUTOFF).LE.VAL.AND.VAL.LE.CUTOFF)IVAL=INT(VAL+0.5)
            IF(VAL.GT.CUTOFF)IVAL=INT(CUTOFF)
            IF(VAL.LT.(-CUTOFF))IVAL=INT((-CUTOFF))
            IVALUE(I2)=IVAL
            GO TO 7600
          ENDIF
 7650   CONTINUE
!
        IF(NUMNAM.GE.MAXNAM)THEN
          WRITE(ICOUT,2001)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,7752)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,7753)MAXNAM
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,7754)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,7755)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,7757)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,7758)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,7760)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2007)
          CALL DPWRST('XXX','BUG ')
          IF(IWIDTH.GE.1)THEN
            WRITE(ICOUT,2008)(IANS(I),I=1,MIN(100,IWIDTH))
            CALL DPWRST('XXX','BUG ')
          ENDIF
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        NUMNAM=NUMNAM+1
        ILOC=NUMNAM
        IHNAME(ILOC)=IH
        IHNAM2(ILOC)=IH2
        IUSE(ILOC)='P'
        VALUE(ILOC)=PARAM3(L)
        VAL=VALUE(ILOC)
        IF((-CUTOFF).LE.VAL.AND.VAL.LE.CUTOFF)IVAL=INT(VAL+0.5)
        IF(VAL.GT.CUTOFF)IVAL=INT(CUTOFF)
        IF(VAL.LT.(-CUTOFF))IVAL=INT(-CUTOFF)
        IVALUE(ILOC)=IVAL
        GO TO 7600
!
 7600 CONTINUE
 7900 CONTINUE
!
!               *******************************************************
!               **  STEP 16--                                        **
!               **  READ BACK IN FROM MASS STORAGE THE CONTENTS OF   **
!               **  THE V(.) VECTOR.  THE ABOVE RETRIEVAL FROM MASS  **
!               **  STORAGE IS UNNECESSARY AND IS FOR THE SPECIAL    **
!               **  CASE WHEN THE NUMBER OF PARAMETERS IS 0 (A NO    **
!               **  PRE-FIT CASE WHEREBY WE ARE REALLY INTERESTED    **
!               **  IN GENERATING PREDICTED VALUES AND RESIDUALS     **
!               **  FOR A GIVEN FULLY-SPECIFIED MODEL).              **
!               *******************************************************
!
 8000 CONTINUE
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')THEN
        ISTEPN='16'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,8101)
 8101   FORMAT('WE ARE IN DPPREF AND ARE ABOUT TO READ V BACK IN')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8102)MAXN2,MAXCO2,MAXIJ2,NLEFT,NS,V(1),   &
                         PRED(1),RES(1)
 8102   FORMAT('MAXN2,MAXCO2,MAXIJ2,NLEFT,NS,V(1),PRED(1),RES(1) = ',   &
               5I6,3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8103)
 8103   FORMAT('NOTE THAT IF NUMBER OF PARAMETERS = 0, THEN ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8104)
 8104   FORMAT('NO   DUMP TO/RETRIEVAL FROM MASS STORAGE IS DONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8106)NUMPAR
 8106   FORMAT('NUMPAR = ',I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IOP='READ'
!CCCC CALL DPSWAP(IOP,V,NUMNAM,IHNAME,IHNAM2,IUSE,IN,
!CCCC1            IVALUE,MAXN,MAXCOL,MAXN2,MAXCO2,MAXIJ2,
!CCCC1            IBUGA3,ISUBRO,IERROR)
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')THEN
        WRITE(ICOUT,8121)
 8121   FORMAT('WE ARE IN DPPREF AND HAVE JUST READ V(.) BACK IN')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8102)MAXN2,MAXCO2,MAXIJ2,NLEFT,NS,V(1),   &
                         PRED(1),RES(1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *************************************************
!               **  STEP 17--                                  **
!               **  COPY THE FINAL ESTIMATES FROM THE PRE-FIT  **
!               **  BACK INTO THE PARAMETERS.                  **
!               **  THESE FINAL ESTIMATES WILL THUS OVERWRITE  **
!               **  THE STARTING VALUES THAT WERE              **
!               **  ORIGINALLY ASSIGNED TO THE PARAMETERS.     **
!               *************************************************
!
      ISTEPN='17'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMPAR.GT.0)THEN
        DO 6100 J=1,NUMPAR
          IH=IPARN3(J)
          IH2=IPARN4(J)
          IHWUSE='P'
          MESSAG='YES'
          CALL CHECKN(IH,IH2,IHWUSE,   &
                      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
          VALUE(ILOCP)=PARAM3(J)
          VAL=VALUE(ILOCP)
          IF((-CUTOFF).LE.VAL.AND.VAL.LE.CUTOFF)IVAL=INT(VAL+0.5)
          IF(VAL.GT.CUTOFF)IVAL=INT(CUTOFF)
          IF(VAL.LT.(-CUTOFF))IVAL=INT(-CUTOFF)
          IVALUE(ILOCP)=IVAL
 6100   CONTINUE
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PREF')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPREF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)NUMNAM,NS,NUMPV,IP,IV,ICASFI
 9015   FORMAT('NUMNAM,NS,NUMPV,IP,IV,ICASFI = ',5I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 9017 I=1,NUMNAM
          WRITE(ICOUT,9018)I,IHNAME(I),IHNAM2(I),IUSE(I),IN(I),   &
                           IVALUE(I),VALUE(I)
 9018     FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I),IN(I),IVALUE(I)',   &
                 'VALUE(I) = ',I8,2X,2A4,2X,A4,2I8,G15.7)
          CALL DPWRST('XXX','BUG ')
 9017   CONTINUE
        IF(NUMPV.GT.0)THEN
          DO 9022 I=1,NUMPV
            WRITE(ICOUT,9023)I,IPARN(I),IPARN2(I)
 9023       FORMAT('I,IPARN(I),IPARN2(I) = ',I8,2X,2A4)
            CALL DPWRST('XXX','BUG ')
 9022     CONTINUE
        ENDIF
        IF(IP.GT.0)THEN
          DO 9032 I=1,IP
            WRITE(ICOUT,9033)I,IPARN3(I),IPARN4(I)
 9033       FORMAT('I,IPARN3(I),IPARN4(I) = ',I8,2X,2A4)
            CALL DPWRST('XXX','BUG ')
 9032     CONTINUE
        ENDIF
        IF(IV.GT.0)THEN
          DO 9042 I=1,IV
            WRITE(ICOUT,9043)I,IVARN3(I),IVARN4(I)
 9043       FORMAT('I,IVARN3(I),IVARN4(I) = ',I8,2X,2A4)
            CALL DPWRST('XXX','BUG ')
 9042     CONTINUE
        ENDIF
        WRITE(ICOUT,9051)MAXN2,NLEFT,NS,V(1),PRED(1),RES(1)
 9051   FORMAT('MAXN2,NLEFT,NS,V(1),PRED(1),RES(1) = ',3I8,3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9061)ICASEQ,IWIDTH,IWIDMO
 9061   FORMAT('ICASEQ,IWIDTH,IWIDMO = ',A4,2X,2I8)
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,9062)(IANS(I),I=1,MIN(100,IWIDTH))
 9062     FORMAT('(IANS(I),I=1,IWIDTH) = ',100A1)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IF(IWIDMO.GE.1)THEN
          WRITE(ICOUT,9064)(MODEL(I),I=1,MIN(100,IWIDMO))
 9064     FORMAT('(MODEL(I),I=1,IWIDMO) = ',100A1)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        WRITE(ICOUT,9069)IFOUND,IERROR
 9069   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPREF
      SUBROUTINE DPPREG(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                        IBUGG2,IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--GENERATE ONE OF THE FOLLOWING PLOTS:
!              1) A PARTIAL REGRESSION PLOT
!              2) A PARTIAL RESIDUAL PLOT
!              3) A PARTIAL LEVERAGE PLOT
!              4) A CCPR (COMPONENT AND COMPONENT-PLUS-RESIDUAL) PLOT
!              DPPRPL GENERATES THE PARTIAL REGRESSION PLOTS FOR ALL
!              OF THE X VARIABLES WHILE THIS COMMAND GENERATES THE
!              COORDINATES FOR A SINGLE X VARIABLE.  NOTE THAT THIS
!              COMMAND ASSUMES THE FIT HAS ALREADY BEEN GENERATED
!              (THIS IS DONE AUTOMATICALLY IN DPPRPL) AND THE SYNTAX
!              IS THEN: PARTIAL Y X1 TO XK INDEX
!              WHERE INDEX IS A PARAMETER THAT IDENTIFIES WHICH OF
!              THE X VARIABLES TO USE.
!     WRITTEN BY--ALAN HECKERT
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2002/6
!     ORIGINAL VERSION--JUNE      2002.
!     UPDATED         --JULY      2019. TWEAK SCRATCH SPACE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IAND1
      CHARACTER*4 IAND2
      CHARACTER*4 IBUGG2
      CHARACTER*4 IBUGG3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHP
      CHARACTER*4 IHP2
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 ICASEQ
      CHARACTER*4 IHRIGH
      CHARACTER*4 IHRIG2
      CHARACTER*4 IVARN1
      CHARACTER*4 IVARN2
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
      INCLUDE 'DPCOZ3.INC'
      INCLUDE 'DPCOZI.INC'
      INCLUDE 'DPCODA.INC'
!
!  MAXPRG IS THE MAXIMUM NUMBER OF VARIABLES TO USE IN CREATING THE
!  PARTIAL REGRESSION PLOT
!
      PARAMETER(MAXPRG=30)
!
      DIMENSION IVARN1(MAXPRG)
      DIMENSION IVARN2(MAXPRG)
      DIMENSION ILIS(MAXPRG)
!
      DIMENSION XMAT(11*MAXOBV)
      DIMENSION XSCRT1(11*MAXOBV)
      DIMENSION XSCRT2(11*MAXOBV)
      DIMENSION Y1(MAXOBV)
      DIMENSION YTEMP2(MAXOBV)
      DIMENSION YTEMP3(MAXOBV)
      DIMENSION RES2(MAXOBV)
      DIMENSION COEF(MAXPRG)
      DIMENSION ITEMP1(MAXOBV)
!
      EQUIVALENCE (G3RBAG(KGARB1),Y1(1))
      EQUIVALENCE (G3RBAG(KGARB2),YTEMP2(1))
      EQUIVALENCE (G3RBAG(KGARB3),YTEMP3(1))
      EQUIVALENCE (G3RBAG(KGARB4),RES2(1))
      EQUIVALENCE (GARBAG(IGARB1),XMAT(1))
      EQUIVALENCE (GARBAG(JGAR12),XSCRT1(1))
      EQUIVALENCE (GARBAG(IGAR13),XSCRT2(1))
!
      EQUIVALENCE (IGARBG(IIGAR1),ITEMP1(1))
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
      ISUBN1='DPPR'
      ISUBN2='EG  '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      MAXV2=2
      MINN2=1
      NLOCAL=0
      NPLOTP=0
      NZ=0
      NPLOTV=0
      NS=0
      NTEMP=0
      ICOLH=0
      NUMVAR=0
      NRIGHT=0
!
!               ***********************************************
!               **  TREAT THE PARTIAL REGRESSSION PLOT CASE  **
!               ***********************************************
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PREG')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPREG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGG2,IBUGG3,IBUGQ,ISUBRO
   52   FORMAT('IBUGG2,IBUGG3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASPL,IAND1,IAND2,NUMARG
   53   FORMAT('ICASPL,IAND1,IAND2,NUMARG = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 59 I=1,NUMARG
          WRITE(ICOUT,57)I,IHARG(I),IHARG2(I)
   57     FORMAT('I,IHARG(I),IHARG2(I) = ',I8,A4,2X,A4)
          CALL DPWRST('XXX','BUG ')
   59   CONTINUE
      ENDIF
!
!               ***************************
!               **  STEP 1--             **
!               **  EXTRACT THE COMMAND  **
!               ***************************
!
      ISTEPN='11'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PREG')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'REGR'.AND.   &
        IHARG(2).EQ.'PLOT')THEN
        ICASPL='PREG'
        GO TO 112
      ENDIF
!
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'VARI'.AND.   &
        IHARG(2).EQ.'PLOT')THEN
        ICASPL='PREG'
        GO TO 112
      ENDIF
!
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'LEVE'.AND.   &
        IHARG(2).EQ.'PLOT')THEN
        ICASPL='PLEV'
        GO TO 112
      ENDIF
!
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'RESI'.AND.   &
        IHARG(2).EQ.'PLOT')THEN
        ICASPL='PRES'
        GO TO 112
      ENDIF
!
      IF(NUMARG.GE.3.AND.IHARG(1).EQ.'PLUS'.AND.   &
        IHARG(2).EQ.'RESI'.AND.IHARG(3).EQ.'PLOT')THEN
        ICASPL='PRES'
        GO TO 112
      ENDIF
!
      IF(ICASPL.EQ.'CCPR'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'PLOT')THEN
        ICASPL='CCPR'
        GO TO 111
      ENDIF
!
      IFOUND='NO'
      GO TO 9000
!
  111 CONTINUE
      ILASTC=1
      CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      GO TO 119
!
  112 CONTINUE
      ILASTC=2
      CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      GO TO 119
!
  119 CONTINUE
      IFOUND='YES'
      GO TO 190
!
  190 CONTINUE
!
!               *******************************************************
!               **  STEP 2--                                         **
!               **  CHECK FOR THE PROPER NUMBER OF INPUT ARGUMENTS.  **
!               *******************************************************
!
      ISTEPN='2'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PREG')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      MINNA=3
      MAXNA=100
      CALL CHECKA(NUMARG,MINNA,MAXNA,IANS,IWIDTH,ISUBN1,ISUBN2,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               *****************************************
!               **  STEP 11--                          **
!               **  CHECK TO SEE THE TYPE SUBCASE      **
!               **  (BASED ON THE QUALIFIER)--         **
!               **    1) UNQUALIFIED (THAT IS, FULL);  **
!               **    2) SUBSET/EXCEPT; OR             **
!               **    3) FOR.                          **
!               *****************************************
!
      ISTEPN='11'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PREG')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASEQ='FULL'
      ILOCQ=NUMARG+1
      IF(NUMARG.LT.1)GO TO 1180
      DO 1100 J=1,NUMARG
      J1=J
      IF(IHARG(J).EQ.'SUBS'.AND.IHARG2(J).EQ.'ET  ')GO TO 1110
      IF(IHARG(J).EQ.'EXCE'.AND.IHARG2(J).EQ.'PT  ')GO TO 1110
      IF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    ')GO TO 1120
 1100 CONTINUE
      GO TO 1180
 1110 CONTINUE
      ICASEQ='SUBS'
      ILOCQ=J1
      GO TO 1190
 1120 CONTINUE
      ICASEQ='FOR'
      ILOCQ=J1
      GO TO 1190
!
 1180 CONTINUE
      GO TO 1190
!
 1190 CONTINUE
      IF(IBUGG2.EQ.'OFF'.AND.ISUBRO.NE.'PREG')GO TO 1195
      WRITE(ICOUT,1191)NUMARG,ILOCQ,ICASEQ
 1191 FORMAT('NUMARG,ILOCQ,ICASEQ = ',I8,I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
 1195 CONTINUE
!
!               **************************************************
!               **  STEP 12--                                   **
!               **  DETERMINE THE NUMBER OF VARIABLES           **
!               **  TO BE INCLUDED AS PLOT COMPONENTS           **
!               **  IF THE   TO   FEATURE IS USED IN THE        **
!               **  ARGUMENT LIST, TRANSLATE THE   TO   TO      **
!               **  EXPLICIT VARIABLE NAMES                     **
!               **  NOTE: LAST "VARIABLE" SHOULD BE A PARAMETER **
!               **        CONTAINING THE "INDEX" OF THE PRIMARY **
!               **        VARIABLE OF THE PLOT.                 **
!               **************************************************
!
      ISTEPN='12'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PREG')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      JMIN=1
      JMAX=ILOCQ-1
      CALL EXTVAR(IHARG,IHARG2,NUMARG,JMIN,JMAX,MAXPRG,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,   &
                  IVARN1,IVARN2,NUMVAR,IBUGG2,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               ***************************************
!               **  STEP 13--                        **
!               **  CHECK THE VALIDITY OF EACH       **
!               **  OF THE VARIABLES.                **
!               **  ALSO CHECK TO ASSURE THAT EACH   **
!               **  OF THE VARIABLES HAS AT LEAST    **
!               **  2 OBSERVATIONS AND THE SAME      **
!               **  NUMBER OF OBSERVATIONS           **
!               ***************************************
!
      ISTEPN='13'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PREG')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IFLAG=0
      NVTOT=NUMVAR
      NUMVAR=NUMVAR-1
      DO 1300 I=1,NVTOT
!
      IHRIGH=IVARN1(I)
      IHRIG2=IVARN2(I)
      IHWUSE='V'
      MESSAG='YES'
      CALL CHECKN(IHRIGH,IHRIG2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      NRIGHT=IN(ILOCV)
      IF(I.EQ.1)NTEMP=NRIGHT
      ILIS(I)=ILOCV
      IF(NRIGHT.LT.MINN2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1311)
 1311   FORMAT('***** ERROR IN DPPREG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1312)
 1312   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1321)
 1321   FORMAT('      (FOR WHICH A PARTIAL REGRESSSION PLOT')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1325)
 1325   FORMAT('      WAS TO HAVE BEEN FORMED)')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1326)MINN2
 1326   FORMAT('      MUST BE ',I8,' OR LARGER;')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1327)
 1327   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1328)
 1328   FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,1329)(IANS(J),J=1,MIN(80,IWIDTH))
 1329     FORMAT('      ',80A1)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IERROR='YES'
        GO TO 9000
      ELSE IF(NRIGHT.NE.NTEMP)THEN
        WRITE(ICOUT,1411)
 1411   FORMAT('***** ERROR IN DPPREG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1413)
 1413   FORMAT('      THE NUMBER OF OBSERVATIONS IN ALL VARIABLES ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1414)
 1414   FORMAT('      MUST BE THE SAME; SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        I2=ILIS(I)
        WRITE(ICOUT,1416)IVARN1(I2),IVARN2(I2),IN(I2)
 1416   FORMAT('           VARIABLE ',A4,A4,' HAS ',I8,   &
               ' OBSERVATIONS;')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1420)
 1420   FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,1421)(IANS(L),L=1,MIN(100,IWIDTH))
 1421     FORMAT('      ',100A1)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IERROR='YES'
        GO TO 9000
      ENDIF
!
 1300 CONTINUE
!
      IF(NUMVAR*NRIGHT.GT.11*MAXOBV)THEN
        WRITE(ICOUT,1311)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1503)
 1503   FORMAT('      SCRATCH SPACE EXCEEDED.  USE FEWER VARIABLES.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1505)11*MAXOBV
 1505   FORMAT('      ROWS TIMES COLUMMS MUST BE <= ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1507)NRIGHT,NUMVAR,NUMVAR*NRIGHT
 1507   FORMAT('      CURRENT: ROWS = ',I8,', COLUMNS = ',I8,   &
               ', TOTAL = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ******************************************************
!               **  STEP 1.5--                                      **
!               **  LAST VARIABLE IDENTIFIES THE PRIMARY VARIABLE   **
!               **  (WHICH SHOULD ALREADY BE IN THE LIST)           **
!               ******************************************************
!
      IHRIGH=IVARN1(NVTOT)
      IHRIG2=IVARN2(NVTOT)
!
      DO 1521 I=2,NUMVAR
        IF(IHRIGH.EQ.IVARN1(I).AND.IHRIG2.EQ.IVARN2(I))THEN
          IX=I
          GO TO 1529
        ENDIF
 1521 CONTINUE
      WRITE(ICOUT,1311)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1525)IHRIGH,IHRIG2
 1525 FORMAT('      THE NAME OF THE PRIMARY VARIABLE ',A4,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1527)
 1527 FORMAT('      DOES NOT MATCH ANY OF THE INDEPENDENT VARIABLES.')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
 1529 CONTINUE
!
!               ******************************************************
!               **  STEP 1.6--                                      **
!               **  EXTRACT FIT COEFFICIENTS FROM PREVIOUS FIT.     **
!               **  (A0, A1, ....)                                  **
!               ******************************************************
!
      IHP='A0  '
      IHP2='    '
      IHWUSE='P'
      MESSAG='YES'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      COEF(1)=VALUE(ILOCP)
!
      NX=NUMVAR-1
      DO 1610 I=1,MIN(9,NX)
        IHP='A   '
        WRITE(IHP(2:2),'(I1)')I
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
        IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
        ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        COEF(I+1)=VALUE(ILOCP)
 1610 CONTINUE
      IF(NX.GE.10)THEN
        DO 1620 I=1,MIN(10,NX)
          IHP='A   '
          WRITE(IHP(2:3),'(I2)')I
          CALL CHECKN(IHP,IHP2,IHWUSE,   &
          IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
          ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
          COEF(I+1)=VALUE(ILOCP)
 1620   CONTINUE
      ENDIF
!
      NX=NUMVAR-1
!
!               *************************************************
!               **  STEP 21--                                  **
!               **  BRANCH TO THE APPROPRIATE SUBCASE;         **
!               **  (BASED ON THE QUALIFIER)                   **
!               **  THEN FOR  EACH OF THE RESPONSE VARIABLES   **
!               **  EXTRACT THE DATA SUBSET                    **
!               **  (USUALLY ONLY 1 OBSERVATION)               **
!               **  AND ALSO EXTRACT THE                       **
!               **  MIN AND MAX FOR THE FULL VARIABLE          **
!               *************************************************
!
      ISTEPN='21'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PREG')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICASEQ.EQ.'FULL')GO TO 2110
      IF(ICASEQ.EQ.'SUBS')GO TO 2120
      IF(ICASEQ.EQ.'FOR')GO TO 2130
!
 2110 CONTINUE
      DO 2115 I=1,NRIGHT
      ISUB(I)=1
 2115 CONTINUE
      NQ=NRIGHT
      GO TO 2190
!
 2120 CONTINUE
      NIOLD=NRIGHT
      CALL DPSUBS(NIOLD,ILOCS,NS,IBUGQ,IERROR)
      NQ=NIOLD
      GO TO 2190
!
 2130 CONTINUE
      NIOLD=NRIGHT
      CALL DPFOR(NIOLD,NFOR,IROW1,IROWN,   &
      NLOCAL,ILOCS,NS,IBUGQ,IERROR)
      NQ=NFOR
      GO TO 2190
!
 2190 CONTINUE
!
!               *************************************************
!               **  STEP 22--                                  **
!               **  FOR EACH OF THE RESPONSE VARIABLES,        **
!               **  EXTRACT THE DATA SUBSET                    **
!               **  (FREQUENTLY ONLY 1 OBSERVATION)            **
!               **  AND ALSO EXTRACT THE                       **
!               **  MIN AND MAX FOR THE FULL VARIABLE          **
!               *************************************************
!
      ISTEPN='22'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PREG')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 2200 K=1,NVTOT-1
      IHRIGH=IVARN1(K)
      IHRIG2=IVARN2(K)
!
      DO 2210 I=1,NUMNAM
      I2=I
      IF(IHRIGH.EQ.IHNAME(I).AND.IHRIG2.EQ.IHNAM2(I).AND.   &
      IUSE(I).EQ.'V')GO TO 2219
 2210 CONTINUE
      WRITE(ICOUT,2211)
 2211 FORMAT('***** INTERNAL ERROR IN DPPREG AT POINT 2210--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2212)IHRIGH,IHRIG2
 2212 FORMAT('      THE VARIABLE ',A4,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2213)
 2213 FORMAT('      NOT NOW FOUND IN INTERNAL NAME LIST')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2214)
 2214 FORMAT('      ALTHOUGH ALREADY FOUND EARLIER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2215)
 2215 FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)THEN
        WRITE(ICOUT,2216)(IANS(I),I=1,IWIDTH)
 2216   FORMAT('      ',80A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      IERROR='YES'
      GO TO 9000
 2219 CONTINUE
!
      ILISTR=I2
      ICOLR=IVALUE(ILISTR)
      NRIGHT=IN(ILISTR)
!
      J=0
      IMAX=NRIGHT
      IF(NQ.LT.NRIGHT)IMAX=NQ
      DO 2240 I=1,IMAX
      IF(ISUB(I).EQ.0)GO TO 2240
      J=J+1
      IJ=MAXN*(ICOLR-1)+I
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PREG')   &
      WRITE(ICOUT,2241)I,J,MAXN,ICOLR,IJ,NRIGHT,NQ,IMAX
 2241 FORMAT('I,J,MAXN,ICOLR,IJ,NRIGHT,NQ,IMAX = ',8I8)
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PREG')   &
      CALL DPWRST('XXX','BUG ')
      IF(K.EQ.1)THEN
        IF(ICOLR.LE.MAXCOL)Y1(J)=V(IJ)
        IF(ICOLR.EQ.MAXCP1)Y1(J)=PRED(I)
        IF(ICOLR.EQ.MAXCP2)Y1(J)=RES(I)
        IF(ICOLR.EQ.MAXCP3)Y1(J)=YPLOT(I)
        IF(ICOLR.EQ.MAXCP4)Y1(J)=XPLOT(I)
        IF(ICOLR.EQ.MAXCP5)Y1(J)=X2PLOT(I)
        IF(ICOLR.EQ.MAXCP6)Y1(J)=TAGPLO(I)
        RES2(J)=RES(I)
        XMAT(J)=1.0
      ELSE
        IJK=(K-1)*NQ+J
        IF(ICOLR.LE.MAXCOL)XMAT(IJK)=V(IJ)
        IF(ICOLR.EQ.MAXCP1)XMAT(IJK)=PRED(I)
        IF(ICOLR.EQ.MAXCP2)XMAT(IJK)=RES(I)
        IF(ICOLR.EQ.MAXCP3)XMAT(IJK)=YPLOT(I)
        IF(ICOLR.EQ.MAXCP4)XMAT(IJK)=XPLOT(I)
        IF(ICOLR.EQ.MAXCP5)XMAT(IJK)=X2PLOT(I)
        IF(ICOLR.EQ.MAXCP6)XMAT(IJK)=TAGPLO(I)
      ENDIF
 2240 CONTINUE
      NLOCAL=J
      NSUB=NLOCAL
!
 2200 CONTINUE
      NZ=NUMVAR
!
!               *******************************************************
!               **  STEP 31--                                        **
!               **  FORM THE VERTICAL AND HORIZONTAL AXIS            **
!               **  VALUES Y(.) AND X(.) FOR THE PLOT.               **
!               **  DEFINE THE VECTOR D(.) SO THAT EACH ANDREW'S     **
!               **  CURVE HAS ITS OWNS TAG NUMBER.                   **
!               **  DEFINE THE NUMBER OF PLOT POINTS    (NPLOTP).    **
!               **  DEFINE THE NUMBER OF PLOT VARIABLES (NPLOTV).    **
!               *******************************************************
!
      ISTEPN='8'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PREG')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPPRG2(Y1,YTEMP2,YTEMP3,RES2,COEF,ITEMP1,   &
                  XMAT,XSCRT1,XSCRT2,ICASPL,   &
                  NLOCAL,NUMVAR,IX,MAXPRG,   &
                  Y,X,D,NPLOTP,NPLOTV,IBUGG3,ISUBRO,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PREG')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPREG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IFOUND,IERROR,NLOCAL,NZ
 9013   FORMAT('IFOUND,IERROR,NLOCAL,NZ = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2
 9014   FORMAT('NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2 = ',3I8,3(2X,A4))
        CALL DPWRST('XXX','BUG ')
        IF(NLOCAL.GT.0)THEN
          DO 9022 I=1,NLOCAL
            WRITE(ICOUT,9023)I,Y1(I),RES2(I),XMAT(I)
 9023       FORMAT('I,YTEMP1(I),RES(I),XMAT(I) = ',I8,3G15.7)
            CALL DPWRST('XXX','BUG ')
 9022     CONTINUE
        ENDIF
        IF(NPLOTP.GT.0)THEN
          DO 9052 I=1,NPLOTP
            WRITE(ICOUT,9053)I,Y(I),X(I),D(I)
 9053       FORMAT('I,Y(I),X(I),D(I) = ',I8,3F12.5)
            CALL DPWRST('XXX','BUG ')
 9052     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPPREG
      SUBROUTINE DPPRG2(Y1,Y2,Y3,RES,COEF,ITEMP1,   &
                        XMAT,XSCRT1,XSCRT2,ICASPL,   &
                        N,NUMVAR,IX,MAXPRG,   &
                        Y,X,D,NPLOTP,NPLOTV,IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--GENERATE ONE OF THE FOLLOWING PLOTS:
!              1) A PARTIAL REGRESSION PLOT
!              2) A PARTIAL RESIDUAL PLOT
!              3) A PARTIAL LEVERAGE PLOT
!              4) A CCPR (COMPONENT AND COMPONENT-PLUS-RESIDUAL) PLOT
!              DPPRPL GENERATES THE PARTIAL REGRESSION PLOTS FOR ALL
!              OF THE X VARIABLES WHILE THIS COMMAND GENERATES THE
!              COORDINATES FOR A SINGLE X VARIABLE.  NOTE THAT THIS
!              COMMAND ASSUMES THE FIT HAS ALREADY BEEN GENERATED
!              (THIS IS DONE AUTOMATICALLY IN DPPRPL) AND THE SYNTAX
!              IS THEN: PARTIAL Y X1 TO XK INDEX
!              WHERE INDEX IS A PARAMETER THAT IDENTIFIES WHICH OF
!              THE X VARIABLES TO USE.
!     WRITTEN BY--ALAN HECKERT
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2002/6
!     ORIGINAL VERSION--JUNE      2002.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSUM1
!
      DIMENSION XMAT(N,NUMVAR)
      DIMENSION XSCRT1(N,NUMVAR)
      DIMENSION XSCRT2(N,NUMVAR)
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION Y3(*)
      DIMENSION RES(*)
      DIMENSION ITEMP1(*)
      DIMENSION COEF(*)
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION D(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPPR'
      ISUBN2='G2  '
      IERROR='NO'
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LE.1)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
   31   FORMAT('***** ERROR IN DPPRG2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)
   32   FORMAT('      THE NUMBER OF OBSERVATIONS MUST BE AT LEAST 2;')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,34)N
   34   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PRG2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,71)
   71   FORMAT('***** AT THE BEGINNING OF DPPRG2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,72)ICASPL,NUMVAR,N,IX,MAXPRG
   72   FORMAT('ICASPL,NUMVAR,N,IX,MAXPRG = ',A4,2X,4I8)
        CALL DPWRST('XXX','BUG ')
        DO 81 I=1,N
          WRITE(ICOUT,82)I,Y(I),(XMAT(I,K),K=1,MIN(5,NUMVAR))
   82     FORMAT('I,Y(I),XMAT(I,K) = ',I8,6E12.5)
          CALL DPWRST('XXX','BUG ')
   81   CONTINUE
        DO 91 I=1,N
          WRITE(ICOUT,92)I,Y1(I),Y2(I),Y3(I)
   92     FORMAT('I,Y1(I),Y2(I),Y3(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
   91   CONTINUE
        DO 85 I=1,NUMVAR
          WRITE(ICOUT,87)I,COEF(I)
   87     FORMAT('I,COEF(I) = ',I8,E12.5)
          CALL DPWRST('XXX','BUG ')
   85   CONTINUE
      ENDIF
!
!               ****************************************
!               **  STEP 11--                         **
!               **  DETERMINE PLOT COORDINATES        **
!               **  PARTIAL REGRESSION PLOT CASE      **
!               ****************************************
!
      IF(ICASPL.EQ.'PREG')THEN
!
        CALL CATCHR(XMAT,XSCRT1,XSCRT2,Y2,Y3,ITEMP1,   &
                    N,NUMVAR,N,NUMVAR,   &
                    IBUGG3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
        IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PRG2')THEN
          IF(N.GT.0)THEN
            DO 101 I=1,N
            WRITE(ICOUT,102)I,(XSCRT2(I,K),K=1,MIN(7,NUMVAR))
  102       FORMAT('I,XSCRT(I,K) = ',I8,7E12.5)
            CALL DPWRST('XXX','BUG ')
  101       CONTINUE
          ENDIF
        ENDIF
!
        DSUM1=0.0D0
        DO 110 I=1,N
          DSUM1=DSUM1 + DBLE(XSCRT2(I,IX))**2
  110   CONTINUE
        DENOM=REAL(DSUM1)
        DO 120 I=1,N
          XJDOTJ=XSCRT2(I,IX)/DENOM
          Y(I)=RES(I) + COEF(IX)*XJDOTJ
          X(I)=XJDOTJ
          D(I)=1.0
  120   CONTINUE
!
        NPLOTP=N
        NPLOTV=2
        GO TO 9000
      ELSEIF(ICASPL.EQ.'PLEV')THEN
!
        CALL CATCHR(XMAT,XSCRT1,XSCRT2,Y2,Y3,ITEMP1,   &
                    N,NUMVAR,N,NUMVAR,   &
                    IBUGG3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
        IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PRG2')THEN
          IF(N.GT.0)THEN
            DO 201 I=1,N
            WRITE(ICOUT,202)I,(XSCRT2(I,K),K=1,MIN(7,NUMVAR))
  202       FORMAT('I,XSCRT(I,K) = ',I8,7E12.5)
            CALL DPWRST('XXX','BUG ')
  201       CONTINUE
          ENDIF
        ENDIF
!
        DSUM1=0.0D0
        DO 210 I=1,N
          DSUM1=DSUM1 + DBLE(XSCRT2(I,IX))**2
  210   CONTINUE
        DENOM=REAL(DSUM1)
        DSUM1=0.0
        DO 220 I=1,N
          XJDOTJ=XSCRT2(I,IX)/DENOM
          XJDOTJ=XJDOTJ*XJDOTJ
          DSUM1=DSUM1 + DBLE(XJDOTJ)
  220   CONTINUE
        DENOM2=REAL(DSUM1)
        DO 230 I=1,N
          XJDOTJ=XSCRT2(I,IX)/DENOM
          XJDOTJ=XJDOTJ*XJDOTJ
          Y(I)=XJDOTJ/DENOM2
          X(I)=REAL(I)
          D(I)=1.0
  230   CONTINUE
!
        NPLOTP=N
        NPLOTV=2
        GO TO 9000
      ELSEIF(ICASPL.EQ.'PRES')THEN
!
        DO 420 I=1,N
          Y(I)=RES(I) + COEF(IX)*XMAT(I,IX)
          X(I)=XMAT(I,IX)
          D(I)=1.0
  420   CONTINUE
!
        NPLOTP=N
        NPLOTV=2
        GO TO 9000
      ELSEIF(ICASPL.EQ.'CCPR')THEN
!
        DO 520 I=1,N
          Y(I)=RES(I) + COEF(IX)*XMAT(I,IX)
          X(I)=XMAT(I,IX)
          D(I)=1.0
  520   CONTINUE
!
        DO 530 I=1,N
          Y(I+N)=COEF(IX)*XMAT(I,IX)
          X(I+N)=XMAT(I,IX)
          D(I+N)=2.0
  530   CONTINUE
!
        NPLOTP=2*N
        NPLOTV=2
        GO TO 9000
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,410)ICASPL
  410   FORMAT('***** ERROR IN DPPRG2: PLOT TYPE ',A4,' NOT ',   &
               'RECOGNIZED.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PRG2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPRG2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICASPL,IERROR,NUMVAR,NPLOTP,NPLOTV
 9012   FORMAT('ICASPL,IERROR,NUMVAR,NPLOTP,NPLOTV = ',2(A4,2X),3I8)
        CALL DPWRST('XXX','BUG ')
        DO 9035 I=1,NPLOTP
          WRITE(ICOUT,9036)I,Y(I),X(I),D(I)
 9036     FORMAT('I,Y(I),X(I),D(I) = ',I8,2G15.7,F9.2)
          CALL DPWRST('XXX','BUG ')
 9035   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPPRG2
      SUBROUTINE DPPRES(IHARG,NUMARG,ISORSW,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE PRE-SORT SWITCH ISORSW.
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --NUMARG
!     OUTPUT ARGUMENTS--ISORSW  ('ON'  OR 'OFF')
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1978.
!     UPDATED         --SEPTEMBER 1980.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 ISORSW
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.LE.0)GO TO 1199
      IF(NUMARG.EQ.1.AND.IHARG(1).EQ.'SORT')GO TO 1150
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'SORT')GO TO 1110
      GO TO 1199
!
 1110 CONTINUE
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1150
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1160
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1150
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1150
      GO TO 1199
!
 1150 CONTINUE
      ISORSW='ON'
      GO TO 1180
!
 1160 CONTINUE
      ISORSW='OFF'
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1181)ISORSW
 1181 FORMAT('THE PRE-SORT SWITCH HAS JUST BEEN TURNED ',   &
      A4)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 1199
!
 1199 CONTINUE
      RETURN
      END SUBROUTINE DPPRES
      SUBROUTINE DPPRFI(ICOM,IANSLC,IWIDTH,IHARG,IHARG2,NUMARG,   &
                        IBUGS2,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--SEND AN INPUT FILE TO A PRINTER.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2019/03
!     ORIGINAL VERSION--MARCH     2019.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICOM
      CHARACTER*4 IANSLC(*)
      CHARACTER*4 IHARG(*)
      CHARACTER*4 IHARG2(*)
      CHARACTER*4 IBUGS2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      INCLUDE 'DPCOPA.INC'
!
!CCCC CHARACTER*80 IFILE1
      CHARACTER (LEN=MAXFNC) :: IFILE1
      CHARACTER*12 ISTAT1
      CHARACTER*12 IFORM1
      CHARACTER*12 IACCE1
      CHARACTER*12 IPROT1
      CHARACTER*12 ICURS1
!
      CHARACTER*4 IFTYPE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IANSI
!CCCC CHARACTER*255 ICANS
      CHARACTER (LEN=MAXSTR) :: ICANS
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOF2.INC'
      INCLUDE 'DPCOZC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPPR'
      ISUBN2='FI  '
      IFOUND='YES'
      IERROR='NO'
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'PRFI')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPRFI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICOM,IBUGS2,ISUBRO,IERROR
   53   FORMAT('ICOM,IBUGS2,ISUBRO,IERROR = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,55)(IANSLC(I),I=1,MIN(80,IWIDTH))
   55     FORMAT('(IANSLC(I),I=1,IWIDTH) = ',80A1)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        WRITE(ICOUT,61)IHARG(1),IHARG2(1),NUMARG
   61   FORMAT('IHARG(1),IHARG2(1),NUMARG = ',2A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               **************************
!               **  STEP 11--           **
!               **  COPY OVER VARIABLES **
!               **************************
!
      ISTEPN='11'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'PRFI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IOUNI1=ILISNU
      IFILE1=ILISNA
      ISTAT1=ILISST
      IFORM1=ILISFO
      IACCE1=ILISAC
      IPROT1=ILISPR
      ICURS1=ILISCS
!
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'PRFI')THEN
        WRITE(ICOUT,1181)IOUNI1
 1181   FORMAT('IOUNI1 = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1182)IFILE1(1:80)
 1182   FORMAT('IFILE1 = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1193)ISTAT1,IFORM1,IACCE1,IPROT1,ICURS1
 1193   FORMAT('ISTAT1,IFORM1,IACCE1,IPROT1,ICURS1 = ',   &
               4(A12,2X),A12)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***********************************************
!               **  STEP 12--                                **
!               **  CHECK TO SEE IF THE PRINT FILE MAY EXIST **
!               ***********************************************
!
      ISTEPN='12'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'PRFI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ISTAT1.EQ.'NONE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1211)
 1211   FORMAT('***** ERROR IN PRINT FILE (DPPRFI)--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1212)
 1212   FORMAT('      THE DESIRED PRINTING CANNOT BE CARRIED OUT')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1214)
 1214   FORMAT('      BECAUSE THE INTERNAL VARIABLE    ILISST ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1215)
 1215   FORMAT('      WHICH ALLOWS SUCH LISTING HAS BEEN SET TO ',   &
               '  NONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1217)ISTAT1,ILISST
 1217   FORMAT('ISTAT1,ILISST = ',A12,2X,A12)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ***************************************
!               **  STEP 13--                        **
!               **  EXTRACT THE INPUT  FILE NAME.    **
!               ***************************************
!
      ISTEPN='13'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'PRFI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 1310 I=1,MAXSTR
        IANSI=IANSLC(I)
        ICANS(I:I)=IANSI(1:1)
 1310 CONTINUE
!
      ISTART=1
      ISTOP=IWIDTH
      IWORD=2
      CALL DPEXWO(ICANS,ISTART,ISTOP,IWORD,   &
                  ICOL1,ICOL2,IFILE1,NCFIL1,   &
                  IBUGS2,ISUBRO,IERROR)
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'PRFI')THEN
        WRITE(ICOUT,1321)NCFIL1,IFILE1
 1321   FORMAT('NCFIL1,IFILE1 = ',I8,2X,A80)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(NCFIL1.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1211)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1372)
 1372   FORMAT('      NO INPUT FILE WAS SPECIFIED.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!
!               *****************************************
!               **  STEP 2--                           **
!               **  IMPLEMENT OPERATING SYSTEM PRINT   **
!               *****************************************
!
      ISTEPN='2'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'PRFI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IFTYPE='ASCI'
      CALL PRINFI(IFILE1,IFTYPE,IBUGS2,ISUBRO,IERROR)
!
 9000 CONTINUE
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'PRFI')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPRFI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPRFI
      SUBROUTINE DPPRFO(IHARG,NUMARG,IPRITY,IFOUND,IERROR)
!
!     PURPOSE--SET THE FORMAT/TYPE SWITCH FOR THE PRINTER.
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --NUMARG (AN INTEGER VARIABLE)
!     OUTPUT ARGUMENTS--IPRITY (A HOLLERITH VARIABLE)
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--92/4
!     ORIGINAL VERSION--MARCH     1992.
!     UPDATED         --FEBRUARY  1993.  DEFAULT CHANGED TO POSTSCRIPT
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IPRITY
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHOLD
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.LE.0)GO TO 1150
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1150
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1150
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1150
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1150
      IF(IHARG(NUMARG).EQ.'?')GO TO 1160
      GO TO 1170
!
 1150 CONTINUE
!CCCC THE FOLLOWING LINE WAS CHANGED FEBRUARY 1993
!CCCC IHOLD='ASCI'
      IHOLD='POST'
      GO TO 1180
!
 1160 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 1169
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1161)IPRITY
 1161 FORMAT('THE CURRENT FORMAT FOR THE PRINTER IS ',A4)
      CALL DPWRST('XXX','BUG ')
 1169 CONTINUE
      IFOUND='YES'
      GO TO 1199
!
 1170 CONTINUE
      IHOLD=IHARG(NUMARG)
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
      IPRITY=IHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1181)IPRITY
 1181 FORMAT('THE PRINTER FORMAT SWITCH HAS JUST ',   &
      'BEEN SET TO ',A4)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 1199
!
 1199 CONTINUE
      RETURN
      END SUBROUTINE DPPRFO
      SUBROUTINE DPPRIF(ILAB,NUMWDL,IFUNC,NCF,IBUGA3)
!
!     PURPOSE--PRINT OUT A FUNCTION IN A NEAT FORM.
!     NOTE--THIS SUBROUTINE IS NECESSITATED BECAUSE
!           SOME STORED WORDS HAVE 1 CHARACTER (E.G, A, B, C, ETC.)
!           WHILE OTHERS HAVE SEVERAL CHARACTERS PACKED INTO
!           A SINGLE WORD (E.G., SQRT, ARCT, ETC.).
!     NOTE--ILAB(.) AND IFUNC(.) ARE HOLLERITH A4 VECTORS.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--JANUARY   1979.
!     UPDATED         --JULY      1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ILAB
      CHARACTER*4 IFUNC
      CHARACTER*4 IBUGA3
!
      CHARACTER*4 IBLANK
      CHARACTER*4 IBUF
      CHARACTER*4 ILAST
      CHARACTER*4 IB
      CHARACTER*4 ICH
!
!---------------------------------------------------------------------
!
      DIMENSION ILAB(*)
      DIMENSION IFUNC(*)
!
      DIMENSION IB(140)
      DIMENSION ICH(10)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA MAXCPL/128/
      DATA NUMASC/4/
!
!-----START POINT-----------------------------------------------------
!
      ILAST='UNKN'
!
!               *******************************************************
!               **  DECOMPOSE EACH WORD INTO INDIVIDUAL CHARACTERS.  **
!               **  PRINT OUT ONLY THE LEADING NON-BLANK CHARACTERS. **
!               *******************************************************
!
      IBLANK=' '
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPPRIF--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)NUMWDL
   52 FORMAT('NUMWDL = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)(ILAB(I),I=1,NUMWDL)
   53 FORMAT('ILAB(.) = ',30A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,55)NCF
   55 FORMAT('NCF = ',I8)
      CALL DPWRST('XXX','BUG ')
!CCCC FEBRUARY 1995.  CHECK FOR NCF > 30.
      NPRINT=NCF
      IF(NPRINT.GT.30)NPRINT=30
!CCCC IF(NCF.GE.1)WRITE(ICOUT,56)(IFUNC(I),I=1,NCF)
      IF(NPRINT.GE.1)WRITE(ICOUT,56)(IFUNC(I),I=1,NPRINT)
   56 FORMAT('IFUNC(.) = ',30A4)
      IF(NCF.GE.1)CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
      NUMCPL=MAXCPL-NUMWDL*NUMASC
!
      L=0
      IL=0
      ICF=0
      IF(NCF.LE.0)ILAST='YES'
      IF(NCF.GE.1)ILAST='NO'
      IBUF='NO'
  100 CONTINUE
      ICF=ICF+1
      IF(IBUGA3.EQ.'ON')WRITE(ICOUT,101)ICF,L,IBUF,ILAST,IL
  101 FORMAT('ICF,L,IBUF,ILAST,IL = ',I8,I8,2X,A4,2X,A4,I8)
      IF(IBUGA3.EQ.'ON')CALL DPWRST('XXX','BUG ')
      IF(ICF.GT.NCF)GO TO 300
      IF(ICF.EQ.NCF)ILAST='YES'
!
      CALL DPXH1H(IFUNC(ICF),ICH,IEND,IBUGA3)
!
      ITEST=L+IEND
      IF(ITEST.LE.NUMCPL)GO TO 200
      IBUF='YES'
      GO TO 300
!
  200 CONTINUE
      DO 400 I=1,IEND
      L=L+1
      IB(L)=ICH(I)
  400 CONTINUE
      GO TO 100
!
  300 CONTINUE
      NUMCTL=L
      L=0
      IL=IL+1
!
      IF(NUMWDL.EQ.0)GO TO 600
      IF(NUMWDL.EQ.1)GO TO 610
      IF(NUMWDL.EQ.2)GO TO 620
      IF(NUMWDL.EQ.3)GO TO 630
      IF(NUMWDL.EQ.4)GO TO 640
      IF(NUMWDL.EQ.5)GO TO 650
      IF(NUMWDL.EQ.6)GO TO 660
      IF(NUMWDL.EQ.7)GO TO 670
      IF(NUMWDL.EQ.8)GO TO 680
      IF(NUMWDL.GE.9)GO TO 690
!
  600 CONTINUE
      IF(NUMCTL.LE.0)WRITE(ICOUT,606)
      IF(NUMCTL.LE.0)CALL DPWRST('XXX','BUG ')
      IF(NUMCTL.LE.0)GO TO 609
      IF(IL.EQ.1)WRITE(ICOUT,606)(IB(K),K=1,MIN(NUMCTL,128))
      IF(IL.EQ.1)CALL DPWRST('XXX','BUG ')
      IF(IL.GE.2)WRITE(ICOUT,606)(IB(K),K=1,MIN(NUMCTL,128))
  606 FORMAT(128A1)
      IF(IL.GE.2)CALL DPWRST('XXX','BUG ')
  609 CONTINUE
      GO TO 700
!
  610 CONTINUE
      IF(NUMCTL.LE.0)WRITE(ICOUT,616)(ILAB(J),J=1,NUMWDL)
      IF(NUMCTL.LE.0)CALL DPWRST('XXX','BUG ')
      IF(NUMCTL.LE.0)GO TO 619
      IF(IL.EQ.1)WRITE(ICOUT,616)(ILAB(J),J=1,NUMWDL),   &
                 (IB(K),K=1,MIN(NUMCTL,124))
      IF(IL.EQ.1)CALL DPWRST('XXX','BUG ')
      IF(IL.GE.2)WRITE(ICOUT,616)(IBLANK ,J=1,NUMWDL),   &
                 (IB(K),K=1,MIN(NUMCTL,128))
  616 FORMAT(A4,124A1)
      IF(IL.GE.2)CALL DPWRST('XXX','BUG ')
  619 CONTINUE
      GO TO 700
!
  620 CONTINUE
      IF(NUMCTL.LE.0)WRITE(ICOUT,626)(ILAB(J),J=1,NUMWDL)
      IF(NUMCTL.LE.0)CALL DPWRST('XXX','BUG ')
      IF(NUMCTL.LE.0)GO TO 629
      IF(IL.EQ.1)WRITE(ICOUT,626)(ILAB(J),J=1,NUMWDL),   &
                 (IB(K),K=1,MIN(NUMCTL,120))
      IF(IL.EQ.1)CALL DPWRST('XXX','BUG ')
      IF(IL.GE.2)WRITE(ICOUT,626)(IBLANK ,J=1,NUMWDL),   &
                 (IB(K),K=1,MIN(NUMCTL,120))
  626 FORMAT(2A4,120A1)
      IF(IL.GE.2)CALL DPWRST('XXX','BUG ')
  629 CONTINUE
      GO TO 700
!
  630 CONTINUE
      IF(NUMCTL.LE.0)WRITE(ICOUT,636)(ILAB(J),J=1,NUMWDL)
      IF(NUMCTL.LE.0)CALL DPWRST('XXX','BUG ')
      IF(NUMCTL.LE.0)GO TO 639
      IF(IL.EQ.1)WRITE(ICOUT,636)(ILAB(J),J=1,NUMWDL),   &
      (IB(K),K=1,MIN(NUMCTL,116))
      IF(IL.EQ.1)CALL DPWRST('XXX','BUG ')
      IF(IL.GE.2)WRITE(ICOUT,636)(IBLANK ,J=1,NUMWDL),   &
                 (IB(K),K=1,MIN(NUMCTL,116))
  636 FORMAT(3A4,116A1)
      IF(IL.GE.2)CALL DPWRST('XXX','BUG ')
  639 CONTINUE
      GO TO 700
!
  640 CONTINUE
      IF(NUMCTL.LE.0)WRITE(ICOUT,646)(ILAB(J),J=1,NUMWDL)
      IF(NUMCTL.LE.0)CALL DPWRST('XXX','BUG ')
      IF(NUMCTL.LE.0)GO TO 649
      IF(IL.EQ.1)WRITE(ICOUT,646)(ILAB(J),J=1,NUMWDL),   &
                 (IB(K),K=1,MIN(NUMCTL,112))
      IF(IL.EQ.1)CALL DPWRST('XXX','BUG ')
      IF(IL.GE.2)WRITE(ICOUT,646)(IBLANK ,J=1,NUMWDL),   &
                 (IB(K),K=1,MIN(NUMCTL,112))
  646 FORMAT(4A4,112A1)
      IF(IL.GE.2)CALL DPWRST('XXX','BUG ')
  649 CONTINUE
      GO TO 700
!
  650 CONTINUE
      IF(NUMCTL.LE.0)WRITE(ICOUT,656)(ILAB(J),J=1,NUMWDL)
      IF(NUMCTL.LE.0)CALL DPWRST('XXX','BUG ')
      IF(NUMCTL.LE.0)GO TO 659
      IF(IL.EQ.1)WRITE(ICOUT,656)(ILAB(J),J=1,NUMWDL),   &
                 (IB(K),K=1,MIN(NUMCTL,108))
      IF(IL.EQ.1)CALL DPWRST('XXX','BUG ')
      IF(IL.GE.2)WRITE(ICOUT,656)(IBLANK ,J=1,NUMWDL),   &
                (IB(K),K=1,MIN(NUMCTL,108))
  656 FORMAT(5A4,108A1)
      IF(IL.GE.2)CALL DPWRST('XXX','BUG ')
  659 CONTINUE
      GO TO 700
!
  660 CONTINUE
      IF(NUMCTL.LE.0)WRITE(ICOUT,666)(ILAB(J),J=1,NUMWDL)
      IF(NUMCTL.LE.0)CALL DPWRST('XXX','BUG ')
      IF(NUMCTL.LE.0)GO TO 669
      IF(IL.EQ.1)WRITE(ICOUT,666)(ILAB(J),J=1,NUMWDL),   &
                 (IB(K),K=1,MIN(NUMCTL,104))
      IF(IL.EQ.1)CALL DPWRST('XXX','BUG ')
      IF(IL.GE.2)WRITE(ICOUT,666)(IBLANK ,J=1,NUMWDL),   &
                 (IB(K),K=1,MIN(NUMCTL,104))
  666 FORMAT(6A4,104A1)
      IF(IL.GE.2)CALL DPWRST('XXX','BUG ')
  669 CONTINUE
      GO TO 700
!
  670 CONTINUE
      IF(NUMCTL.LE.0)WRITE(ICOUT,676)(ILAB(J),J=1,NUMWDL)
      IF(NUMCTL.LE.0)CALL DPWRST('XXX','BUG ')
      IF(NUMCTL.LE.0)GO TO 679
      IF(IL.EQ.1)WRITE(ICOUT,676)(ILAB(J),J=1,NUMWDL),   &
                 (IB(K),K=1,MIN(NUMCTL,100))
      IF(IL.EQ.1)CALL DPWRST('XXX','BUG ')
      IF(IL.GE.2)WRITE(ICOUT,676)(IBLANK ,J=1,NUMWDL),   &
                 (IB(K),K=1,MIN(NUMCTL,100))
  676 FORMAT(7A4,100A1)
      IF(IL.GE.2)CALL DPWRST('XXX','BUG ')
  679 CONTINUE
      GO TO 700
!
  680 CONTINUE
      IF(NUMCTL.LE.0)WRITE(ICOUT,686)(ILAB(J),J=1,NUMWDL)
      IF(NUMCTL.LE.0)CALL DPWRST('XXX','BUG ')
      IF(NUMCTL.LE.0)GO TO 689
      IF(IL.EQ.1)WRITE(ICOUT,686)(ILAB(J),J=1,NUMWDL),   &
                 (IB(K),K=1,MIN(NUMCTL,96))
      IF(IL.EQ.1)CALL DPWRST('XXX','BUG ')
      IF(IL.GE.2)WRITE(ICOUT,686)(IBLANK ,J=1,NUMWDL),   &
                 (IB(K),K=1,MIN(NUMCTL,96))
  686 FORMAT(8A4,96A1)
      IF(IL.GE.2)CALL DPWRST('XXX','BUG ')
  689 CONTINUE
      GO TO 700
!
  690 CONTINUE
      IF(NUMCTL.LE.0)WRITE(ICOUT,696)(ILAB(J),J=1,NUMWDL)
      IF(NUMCTL.LE.0)CALL DPWRST('XXX','BUG ')
      IF(NUMCTL.LE.0)GO TO 699
      IF(IL.EQ.1)WRITE(ICOUT,696)(ILAB(J),J=1,NUMWDL),   &
                 (IB(K),K=1,MIN(NUMCTL,92))
      IF(IL.EQ.1)CALL DPWRST('XXX','BUG ')
      IF(IL.GE.2)WRITE(ICOUT,696)(IBLANK ,J=1,NUMWDL),   &
                 (IB(K),K=1,MIN(NUMCTL,92))
  696 FORMAT(9A4,92A1)
      IF(IL.GE.2)CALL DPWRST('XXX','BUG ')
  699 CONTINUE
      GO TO 700
!
  700 CONTINUE
      IF(IL.LT.100)GO TO 710
      WRITE(ICOUT,701)
  701 FORMAT('***** INTERNAL ERROR IN DPFUIP--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,702)
  702 FORMAT('INFINITE LOOP--IL = 100')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,703)NCF,L,IBUF,ILAST,IL
  703 FORMAT('NCF,L,IBUF,ILAST,IL = ',I8,I8,2X,A4,2X,A4,I8)
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  710 CONTINUE
      IF(IBUF.EQ.'YES')GO TO 800
      GO TO 850
!
  800 CONTINUE
      DO 810 I=1,IEND
      L=L+1
      IB(L)=ICH(I)
  810 CONTINUE
      IBUF='NO'
!
      IF(ILAST.EQ.'YES')GO TO 300
      IF(ILAST.EQ.'NO')GO TO 100
!
  850 CONTINUE
      IF(ILAST.EQ.'YES')GO TO 9000
      IF(ILAST.EQ.'NO')GO TO 100
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPPRIF--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)ICF,L,IBUF,ILAST,IL,NUMCTL
 9012 FORMAT('ICF,L,IBUF,ILAST,IL,NUMCTL = ',2I8,2X,A4,2X,A4,2I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)(IB(I),I=1,MIN(NUMCTL,120))
 9013 FORMAT('IB(.) = ',120A1)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPPRIF
      SUBROUTINE DPPRLI(XTEMP1,XTEMP2,MAXNXT,ICASAN,   &
                        ICAPSW,IFORSW,IMULT,IREPL,   &
                        ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
!
!     PURPOSE--GENERATE ONE OF THE FOLLOWING:
!
!                 1) PREDICTION LIMITS
!
!                    GIVEN A SET OF ORIGINAL OBSERVATIONS, THIS
!                    GENERATES A CONFIDENCE INTERVAL FOR THE MEAN
!                    OF ONE OR MORE NEW OBSERVATIONS.
!
!                 2) PREDICTION BOUNDS
!
!                    GIVEN A SET OF ORIGINAL OBSERVATIONS, THIS
!                    GENERATES AN INTERVAL THAT WILL CONTAIN ALL
!                    (WITH A GIVEN PROBABILITY LEVEL) OF ONE OR MORE
!                    NEW OBSERVATIONS.
!
!                 3) PREDICTION LIMITS FOR THE STANDARD DEVIATION
!
!                    GIVEN A SET OF ORIGINAL OBSERVATIONS, THIS
!                    GENERATES A CONFIDENCE INTERVAL FOR THE SD
!                    OF ONE OR MORE NEW OBSERVATIONS.
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2013/4
!     ORIGINAL VERSION--APRIL     2013.
!     UPDATED         --AUGUST    2019. ADD CTL999,CTU999
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 ICASAN
      CHARACTER*4 ICASA2
      CHARACTER*4 ICASA3
      CHARACTER*4 ICASA4
      CHARACTER*4 ICASA5
      CHARACTER*4 ICASE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IFLAGU
!
      LOGICAL IFRST
      LOGICAL ILAST
!
      CHARACTER*4 IREPL
      CHARACTER*4 IMULT
      CHARACTER*4 ICTMP0
      CHARACTER*4 ICTMP1
      CHARACTER*4 ICTMP2
      CHARACTER*4 ICTMP3
      CHARACTER*4 ICTMP4
!
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      CHARACTER*4 IVARID(MAXSPN)
      CHARACTER*4 IVARI2(MAXSPN)
      REAL PVAR(MAXSPN)
      REAL PID(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION TEMP1(MAXOBV)
      DIMENSION TEMP2(MAXOBV)
      DIMENSION TEMP3(MAXOBV)
      DIMENSION TEMP4(MAXOBV)
      DIMENSION TEMP5(MAXOBV)
!
      DIMENSION XDESGN(MAXOBV,6)
      DIMENSION XIDTEM(MAXOBV)
      DIMENSION XIDTE2(MAXOBV)
      DIMENSION XIDTE3(MAXOBV)
      DIMENSION XIDTE4(MAXOBV)
      DIMENSION XIDTE5(MAXOBV)
      DIMENSION XIDTE6(MAXOBV)
!
      INCLUDE 'DPCOZZ.INC'
      EQUIVALENCE (GARBAG(IGARB1),XIDTEM(1))
      EQUIVALENCE (GARBAG(IGARB2),XIDTE2(1))
      EQUIVALENCE (GARBAG(IGARB3),XIDTE3(1))
      EQUIVALENCE (GARBAG(IGARB4),XIDTE4(1))
      EQUIVALENCE (GARBAG(IGARB5),XIDTE5(1))
      EQUIVALENCE (GARBAG(IGARB6),XIDTE6(1))
      EQUIVALENCE (GARBAG(IGARB7),TEMP1(1))
      EQUIVALENCE (GARBAG(IGARB8),TEMP2(1))
      EQUIVALENCE (GARBAG(IGARB9),TEMP3(1))
      EQUIVALENCE (GARBAG(IGAR10),TEMP4(1))
      EQUIVALENCE (GARBAG(JGAR11),TEMP5(1))
      EQUIVALENCE (GARBAG(JGAR12),XDESGN(1,1))
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPPR'
      ISUBN2='LI  '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      IFOUND='YES'
      IERROR='NO'
!
!               ****************************************
!               **  TREAT THE PREDICTION LIMITS CASE  **
!               ****************************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PRLI')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPPRLI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ISUBRO
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)MAXNXT,ICASAN,MAXV2
   55   FORMAT('MAXNXT,ICASAN,MAXV2 = ',I8,2X,A4,2X,I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************
!               **  STEP 1--                   **
!               **  EXTRACT THE COMMAND        **
!               *********************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PRLI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     THE FOLLOWING COMMANDS ARE ACCEPTED:
!
!         PREDICTION LIMITS Y               (TWO SIDED)
!         LOWER PREDICTION LIMITS Y         (ONE SIDED)
!         UPPER PREDICTION LIMITS Y         (ONE SIDED)
!
!         PREDICTION BOUNDS Y               (TWO SIDED)
!         LOWER PREDICTION BOUNDS Y         (ONE SIDED)
!         UPPER PREDICTION BOUNDS Y         (ONE SIDED)
!
!         STANDARD DEVIATION PREDICTION LIMITS Y        (TWO SIDED)
!         LOWER STANDARD DEVIATION PREDICTION LIMITS Y  (ONE SIDED)
!         UPPER STANDARD DEVIATION PREDICTION LIMITS Y  (ONE SIDED)
!
!
!     IN ADDITION, CHECK FOR THE "MULTIPLE" AND "REPLICATION" OPTIONS.
!
!     CHECK FOR "LOGNORMAL" AND "BOX-COX" OPTIONS.
!
      ILASTZ=9999
      IFOUND='NO'
      ICASAN='LIMI'
      ICASA2='UPPE'
      ICASA3='RAW'
      ICASA4='TWOS'
      ICASA5='NORM'
!
      DO 100 I=0,NUMARG-1
!
        ICTMP0='XXXX'
        IF(I.EQ.0)THEN
          ICTMP1=ICOM
          ICTMP2=IHARG(I+1)
          ICTMP3=IHARG(I+2)
          ICTMP4=IHARG(I+3)
        ELSE
          IF(I.GE.2)ICTMP0=IHARG(I-1)
          ICTMP1=IHARG(I)
          ICTMP2=IHARG(I+1)
          ICTMP3=IHARG(I+2)
          ICTMP4=IHARG(I+3)
        ENDIF
!
        IF(ICTMP1.EQ.'=   ')GO TO 9000
        IF(ICTMP1.EQ.'PRED' .AND. ICTMP2.EQ.'LIMI' .AND.   &
           ICTMP0.NE.'SD  ' .AND. ICTMP0.NE.'DEVI')THEN
          IFOUND='YES'
          ILASTZ=I+1
          ICASAN='LIMI'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'PRED' .AND. ICTMP2.EQ.'INTE' .AND.   &
           ICTMP0.NE.'SD  ' .AND. ICTMP0.NE.'DEVI')THEN
          IFOUND='YES'
          ILASTZ=I+1
          ICASAN='LIMI'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'PRED' .AND. ICTMP2.EQ.'BOUN')THEN
          IFOUND='YES'
          ILASTZ=I+1
          ICASAN='BOUN'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'SD  ' .AND. ICTMP2.EQ.'PRED' .AND.   &
               ICTMP3.EQ.'LIMI')THEN
          IFOUND='YES'
          ILASTZ=I+2
          ICASAN='SDLI'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'SD  ' .AND. ICTMP2.EQ.'PRED' .AND.   &
               ICTMP3.EQ.'INTE')THEN
          IFOUND='YES'
          ILASTZ=I+2
          ICASAN='SDLI'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'STAN' .AND. ICTMP2.EQ.'DEVI' .AND.   &
               ICTMP3.EQ.'PRED' .AND. ICTMP4.EQ.'LIMI')THEN
          IFOUND='YES'
          ILASTZ=I+3
          ICASAN='SDLI'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'STAN' .AND. ICTMP2.EQ.'DEVI' .AND.   &
               ICTMP3.EQ.'PRED' .AND. ICTMP4.EQ.'INTE')THEN
          IFOUND='YES'
          ILASTZ=I+3
          ICASAN='SDLI'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'LOWE')THEN
          ICASA4='ONES'
          ICASA2='LOWE'
        ELSEIF(ICTMP1.EQ.'UPPE')THEN
          ICASA4='ONES'
          ICASA2='UPPE'
        ELSEIF(ICTMP1.EQ.'ONE ' .AND. ICTMP2.EQ.'SIDE')THEN
          ICASA4='ONES'
        ELSEIF(ICTMP1.EQ.'REPL')THEN
          IREPL='ON'
        ELSEIF(ICTMP1.EQ.'MULT')THEN
          IMULT='ON'
        ELSEIF(ICTMP1.EQ.'LOGN')THEN
          ICASA5='LNPL'
        ELSEIF(ICTMP1.EQ.'BOXC')THEN
          ICASA5='BCPL'
        ELSEIF(ICTMP1.EQ.'BOX ' .AND. ICTMP2.EQ.'COX ')THEN
          ICASA5='BCPL'
        ENDIF
  100 CONTINUE
  109 CONTINUE
!
      IF(IFOUND.EQ.'NO')GO TO 9000
      ISHIFT=ILASTZ
      CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                  IBUGA2,IERROR)
!
      IF(IMULT.EQ.'ON')THEN
        IF(IREPL.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
  101     FORMAT('***** ERROR IN PREDICTION LIMITS--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)
  102     FORMAT('      YOU CANNOT SPECIFY BOTH "MULTIPLE" AND ',   &
                 '"REPLICATION" FOR THE PREDICTION LIMITS COMMAND.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
!               *********************************
!               **  STEP 2--                   **
!               **  EXTRACT THE VARIABLE LIST  **
!               *********************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PRLI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='PREDICTION LIMITS'
      MAXNA=100
      MINNVA=1
      MAXNVA=100
      MINNA=1
      IFLAGE=1
      IFLAGM=1
      IF(IREPL.EQ.'ON')THEN
        MAXNVA=7
        IFLAGM=0
      ELSE
        MAXNVA=30
        IFLAGE=0
      ENDIF
      MINN2=4
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(NUMVAR.GT.1 .AND. IREPL.EQ.'OFF')IMULT='ON'
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PRLI')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,181)
  181   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,182)NQ,NUMVAR,IMULT,IREPL
  182   FORMAT('NQ,NUMVAR,IMULT,IREPL = ',2I8,2(2X,A4))
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 185 I=1,NUMVAR
            WRITE(ICOUT,187)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  187       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  185     CONTINUE
        ENDIF
      ENDIF
!
!               ***********************************************
!               **  STEP 2--                                 **
!               **  DETERMINE:                               **
!               **  1) NUMBER OF REPLICATION VARIABLES (0-6) **
!               **  2) NUMBER OF RESPONSE    VARIABLES (>= 1)**
!               ***********************************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PRLI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NRESP=0
      NREPL=0
!
      IF(IMULT.EQ.'ON')THEN
        NRESP=NUMVAR
      ELSEIF(IREPL.EQ.'ON')THEN
        NRESP=1
        NREPL=NUMVAR-NRESP
        IF(NREPL.LT.1 .OR. NREPL.GT.6)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,211)
  211     FORMAT('      FOR THE REPLICATION CASE, THE NUMBER OF ',   &
                 'REPLICATION VARIABLES')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,212)
  212     FORMAT('      MUST BE BETWEEN ONE AND SIX.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,213)NREPL
  213     FORMAT('      THE NUMBER OF REPLICATION VARIABLES = ',I5)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ELSE
        NRESP=1
      ENDIF
!
      IH='NNEW'
      IH2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
      IF(IERROR.EQ.'YES')THEN
        NNEW=1
      ELSE
        NNEW=INT(VALUE(ILOCV)+0.5)
        IF(NNEW.LT.1)NNEW=1
      ENDIF
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PRLI')THEN
        WRITE(ICOUT,221)NRESP,NREPL,NNEW
  221   FORMAT('NRESP,NREPL,NNEW = ',3I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ******************************************************
!               **  STEP 3--                                        **
!               **  GENERATE THE PREDICTION LIMITS FOR THE VARIOUS  **
!               **  CASES                                           **
!               ******************************************************
!
      ISTEPN='3'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PRLI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               *****************************************
!               **  STEP 3A--                          **
!               **  CASE 1: NO REPLICATION             **
!               *****************************************
!
      IF(NREPL.EQ.0)THEN
        ISTEPN='3A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PRLI')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!       LOOP THROUGH EACH OF THE RESPONSE VARIABLES
!
        NCURVE=0
        DO 410 IRESP=1,NRESP
          NCURVE=NCURVE+1
!
          IINDX=ICOLR(IRESP)
          PID(1)=CPUMIN
          IVARID(1)=IVARN1(IRESP)
          IVARI2(1)=IVARN2(IRESP)
!
          IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PRLI')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,411)IRESP,NCURVE
  411       FORMAT('IRESP,NCURVE = ',2I5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          ICOL=IRESP
          NUMVA2=1
          CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                      INAME,IVARN1,IVARN2,IVARTY,   &
                      ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                      MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                      MAXCP4,MAXCP5,MAXCP6,   &
                      V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                      Y,XTEMP1,XTEMP2,NLOCAL,NLOCA2,NLOCA3,ICASE,   &
                      IBUGA3,ISUBRO,IFOUND,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
!         *****************************************************
!         **  STEP 4B--                                      **
!         *****************************************************
!
          ISTEPN='4B'
          IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PRLI')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
          IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PRLI')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,422)
  422       FORMAT('***** FROM THE MIDDLE  OF DPPRLI--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,423)ICASAN,NUMVAR,NLOCAL,IRESP
  423       FORMAT('ICASAN,NUMVAR,NLOCAL,IRESP = ',A4,3I8)
            CALL DPWRST('XXX','BUG ')
            IF(NLOCAL.GE.1)THEN
              DO 425 I=1,NLOCAL
                WRITE(ICOUT,426)I,Y(I)
  426           FORMAT('I,Y(I) = ',I8,F12.5)
                CALL DPWRST('XXX','BUG ')
  425         CONTINUE
            ENDIF
          ENDIF
!
          CALL DPPRL2(Y,NLOCAL,NNEW,ICASAN,ICASA2,ICASA3,ICASA4,ICASA5,   &
                      TEMP3,TEMP4,TEMP5,   &
                      PID,IVARID,IVARI2,NREPL,   &
                      CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                      CTL999,CTU999,   &
                      ICAPSW,ICAPTY,IFORSW,   &
                      ISUBRO,IBUGA3,IERROR)
!
          IFLAGU='FILE'
          IF(NRESP.EQ.1)IFLAGU='ON'
          IFRST=.FALSE.
          ILAST=.FALSE.
          IF(IRESP.EQ.1)IFRST=.TRUE.
          IF(IRESP.EQ.NRESP)ILAST=.TRUE.
          CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                      CTL999,CTU999,   &
                      IFLAGU,IFRST,ILAST,ICASAN,   &
                      IBUGA2,IBUGA3,ISUBRO,IERROR)
!
  410   CONTINUE
!
!               ****************************************************
!               **  STEP 5A--                                     **
!               **  CASE 3: ONE OR MORE REPLICATION VARIABLES.    **
!               **          FOR THIS CASE, ALL VARIABLES MUST     **
!               **          HAVE THE SAME LENGTH.                 **
!               ****************************************************
!
      ELSEIF(IREPL.EQ.'ON')THEN
        ISTEPN='5A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PRLI')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        J=0
        IMAX=NRIGHT(1)
        IF(NQ.LT.NRIGHT(1))IMAX=NQ
        DO 510 I=1,IMAX
          IF(ISUB(I).EQ.0)GO TO 510
          J=J+1
!
!         RESPONSE VARIABLE IN Y
!
          ICOLC=1
          IJ=MAXN*(ICOLR(ICOLC)-1)+I
          IF(ICOLR(ICOLC).LE.MAXCOL)Y(J)=V(IJ)
          IF(ICOLR(ICOLC).EQ.MAXCP1)Y(J)=PRED(I)
          IF(ICOLR(ICOLC).EQ.MAXCP2)Y(J)=RES(I)
          IF(ICOLR(ICOLC).EQ.MAXCP3)Y(J)=YPLOT(I)
          IF(ICOLR(ICOLC).EQ.MAXCP4)Y(J)=XPLOT(I)
          IF(ICOLR(ICOLC).EQ.MAXCP5)Y(J)=X2PLOT(I)
          IF(ICOLR(ICOLC).EQ.MAXCP6)Y(J)=TAGPLO(I)
!
          IF(NREPL.GE.1)THEN
            DO 520 IR=1,MIN(NREPL,6)
              ICOLC=ICOLC+1
              ICOLT=ICOLR(ICOLC)
              IJ=MAXN*(ICOLT-1)+I
              IF(ICOLT.LE.MAXCOL)XDESGN(J,IR)=V(IJ)
              IF(ICOLT.EQ.MAXCP1)XDESGN(J,IR)=PRED(I)
              IF(ICOLT.EQ.MAXCP2)XDESGN(J,IR)=RES(I)
              IF(ICOLT.EQ.MAXCP3)XDESGN(J,IR)=YPLOT(I)
              IF(ICOLT.EQ.MAXCP4)XDESGN(J,IR)=XPLOT(I)
              IF(ICOLT.EQ.MAXCP5)XDESGN(J,IR)=X2PLOT(I)
              IF(ICOLT.EQ.MAXCP6)XDESGN(J,IR)=TAGPLO(I)
  520       CONTINUE
          ENDIF
!
  510   CONTINUE
        NLOCAL=J
!
        ISTEPN='5B'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PRLI')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        PID(1)=CPUMIN
        IVARID(1)=IVARN1(1)
        IVARI2(1)=IVARN2(1)
        IADD=1
        DO 540 II=1,NREPL
          IVARID(II+IADD)=IVARN1(II+IADD)
          IVARI2(II+IADD)=IVARN2(II+IADD)
  540   CONTINUE
!
!       *****************************************************
!       **  STEP 5C--                                      **
!       **                                                 **
!       **  FOR THIS CASE, WE NEED TO LOOP THROUGH THE     **
!       **  VARIOUS REPLICATIONS.                          **
!       *****************************************************
!
        ISTEPN='5C'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PRLI')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PRLI')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,541)
  541     FORMAT('***** FROM THE MIDDLE  OF DPPRLI--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,542)ICASAN,NUMVAR,NLOCAL,NLOCA2,NREPL
  542     FORMAT('ICASAN,NUMVAR,NLOCAL,NLOCA2,NREPL = ',A4,2X,4I8)
          CALL DPWRST('XXX','BUG ')
          IF(NLOCAL.GE.1)THEN
            DO 545 I=1,NLOCAL
              WRITE(ICOUT,546)I,Y(I),X(I),XDESGN(I,1),XDESGN(I,2)
  546         FORMAT('I,Y(I),X(I),XDESGN(I,1),XDESGN(I,2) = ',   &
                     I8,4F12.5)
              CALL DPWRST('XXX','BUG ')
  545       CONTINUE
          ENDIF
        ENDIF
!
!       *****************************************************
!       **  STEP 5C--                                      **
!       **  FIND THE DISTINCT VALUES IN EACH OF THE        **
!       **  REPLICATION VARIABLES.                         **
!       *****************************************************
!
        CALL DPPP5(XDESGN(1,1),XDESGN(1,2),XDESGN(1,3),   &
                   XDESGN(1,4),XDESGN(1,5),XDESGN(1,6),   &
                   NREPL,NLOCAL,MAXOBV,   &
                   XIDTEM,XIDTE2,XIDTE3,XIDTE4,XIDTE5,XIDTE6,   &
                   XTEMP1,XTEMP2,   &
                   NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5,NUMSE6,   &
                   IBUGA3,ISUBRO,IERROR)
!
!       *****************************************************
!       **  STEP 5D--                                      **
!       **  NOW LOOP THROUGH THE VARIOUS REPLICATIONS      **
!       *****************************************************
!
        NPLOTP=0
        NCURVE=0
        IF(NREPL.EQ.1)THEN
          J=0
          DO 1110 ISET1=1,NUMSE1
            K=0
            PID(IADD+1)=XIDTEM(ISET1)
            DO 1130 I=1,NLOCAL
              IF(XIDTEM(ISET1).EQ.XDESGN(I,1))THEN
                K=K+1
                TEMP1(K)=Y(I)
                TEMP2(K)=X(I)
              ENDIF
 1130       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPPRL2(TEMP1,NTEMP,NNEW,ICASAN,ICASA2,ICASA3,ICASA4,   &
                          ICASA5,   &
                          TEMP3,TEMP4,TEMP5,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                          CTL999,CTU999,   &
                          ICAPSW,ICAPTY,IFORSW,   &
                          ISUBRO,IBUGA3,IERROR)
            ENDIF
!
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NUMSE1)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1110     CONTINUE
        ELSEIF(NREPL.EQ.2)THEN
          J=0
          NTOT=NUMSE1*NUMSE2
          DO 1210 ISET1=1,NUMSE1
          DO 1220 ISET2=1,NUMSE2
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            DO 1290 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
                TEMP2(K)=X(I)
              ENDIF
 1290       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            NPLOT1=NPLOTP
            IF(NTEMP.GT.0)THEN
              CALL DPPRL2(TEMP1,NTEMP,NNEW,ICASAN,ICASA2,ICASA3,ICASA4,   &
                          ICASA5,   &
                          TEMP3,TEMP4,TEMP5,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                          CTL999,CTU999,   &
                          ICAPSW,ICAPTY,IFORSW,   &
                          ISUBRO,IBUGA3,IERROR)
            ENDIF
            NPLOT2=NPLOTP
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1220     CONTINUE
 1210     CONTINUE
        ELSEIF(NREPL.EQ.3)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3
          DO 1310 ISET1=1,NUMSE1
          DO 1320 ISET2=1,NUMSE2
          DO 1330 ISET3=1,NUMSE3
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            PID(3+IADD)=XIDTE3(ISET3)
            DO 1390 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
                TEMP2(K)=X(I)
              ENDIF
 1390       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPPRL2(TEMP1,NTEMP,NNEW,ICASAN,ICASA2,ICASA3,ICASA4,   &
                          ICASA5,   &
                          TEMP3,TEMP4,TEMP5,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                          CTL999,CTU999,   &
                          ICAPSW,ICAPTY,IFORSW,   &
                          ISUBRO,IBUGA3,IERROR)
            ENDIF
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1330     CONTINUE
 1320     CONTINUE
 1310     CONTINUE
        ELSEIF(NREPL.EQ.4)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3*NUMSE4
          DO 1410 ISET1=1,NUMSE1
          DO 1420 ISET2=1,NUMSE2
          DO 1430 ISET3=1,NUMSE3
          DO 1440 ISET4=1,NUMSE4
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            PID(3+IADD)=XIDTE3(ISET3)
            PID(4+IADD)=XIDTE4(ISET4)
            DO 1490 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3) .AND.   &
                 XIDTE4(ISET4).EQ.XDESGN(I,4)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
                TEMP2(K)=X(I)
              ENDIF
 1490       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPPRL2(TEMP1,NTEMP,NNEW,ICASAN,ICASA2,ICASA3,ICASA4,   &
                          ICASA5,   &
                          TEMP3,TEMP4,TEMP5,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                          CTL999,CTU999,   &
                          ICAPSW,ICAPTY,IFORSW,   &
                          ISUBRO,IBUGA3,IERROR)
            ENDIF
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1440     CONTINUE
 1430     CONTINUE
 1420     CONTINUE
 1410     CONTINUE
        ELSEIF(NREPL.EQ.5)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3*NUMSE4*NUMSE5
          DO 1510 ISET1=1,NUMSE1
          DO 1520 ISET2=1,NUMSE2
          DO 1530 ISET3=1,NUMSE3
          DO 1540 ISET4=1,NUMSE4
          DO 1550 ISET5=1,NUMSE5
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            PID(3+IADD)=XIDTE3(ISET3)
            PID(4+IADD)=XIDTE4(ISET4)
            PID(5+IADD)=XIDTE5(ISET4)
            DO 1590 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3) .AND.   &
                 XIDTE4(ISET4).EQ.XDESGN(I,4) .AND.   &
                 XIDTE5(ISET5).EQ.XDESGN(I,5)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
                TEMP2(K)=X(I)
              ENDIF
 1590       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPPRL2(TEMP1,NTEMP,NNEW,ICASAN,ICASA2,ICASA3,ICASA4,   &
                          ICASA5,   &
                          TEMP3,TEMP4,TEMP5,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                          CTL999,CTU999,   &
                          ICAPSW,ICAPTY,IFORSW,   &
                          ISUBRO,IBUGA3,IERROR)
            ENDIF
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1550     CONTINUE
 1540     CONTINUE
 1530     CONTINUE
 1520     CONTINUE
 1510     CONTINUE
        ELSEIF(NREPL.EQ.6)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3*NUMSE4*NUMSE5*NUMSE6
          DO 1610 ISET1=1,NUMSE1
          DO 1620 ISET2=1,NUMSE2
          DO 1630 ISET3=1,NUMSE3
          DO 1640 ISET4=1,NUMSE4
          DO 1650 ISET5=1,NUMSE5
          DO 1660 ISET6=1,NUMSE6
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            PID(3+IADD)=XIDTE3(ISET3)
            PID(4+IADD)=XIDTE4(ISET4)
            PID(5+IADD)=XIDTE5(ISET4)
            PID(6+IADD)=XIDTE6(ISET4)
            DO 1690 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3) .AND.   &
                 XIDTE4(ISET4).EQ.XDESGN(I,4) .AND.   &
                 XIDTE5(ISET5).EQ.XDESGN(I,5) .AND.   &
                 XIDTE6(ISET6).EQ.XDESGN(I,6)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
                TEMP2(K)=X(I)
              ENDIF
 1690       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPPRL2(TEMP1,NTEMP,NNEW,ICASAN,ICASA2,ICASA3,ICASA4,   &
                          ICASA5,   &
                          TEMP3,TEMP4,TEMP5,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                          CTL999,CTU999,   &
                          ICAPSW,ICAPTY,IFORSW,   &
                          ISUBRO,IBUGA3,IERROR)
            ENDIF
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1660     CONTINUE
 1650     CONTINUE
 1640     CONTINUE
 1630     CONTINUE
 1620     CONTINUE
 1610     CONTINUE
        ENDIF
!
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PRLI')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPRLI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPRLI
      SUBROUTINE DPPRL2(Y,N,N2,ICASAN,ICASA2,ICASA3,ICASA4,ICASA5,   &
                        X2TEMP,Y2TEMP,D2TEMP,   &
                        PID,IVARID,IVARI2,NREPL,   &
                        CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--GENERATE ONE OF THE FOLLOWING:
!
!                 1) PREDICTION LIMITS
!
!                    GIVEN A SET OF ORIGINAL OBSERVATIONS, THIS
!                    GENERATES A CONFIDENCE INTERVAL FOR THE MEAN
!                    OF ONE OR MORE NEW OBSERVATIONS.
!
!                 2) PREDICTION BOUNDS
!
!                    GIVEN A SET OF ORIGINAL OBSERVATIONS, THIS
!                    GENERATES AN INTERVAL THAT WILL CONTAIN ALL
!                    (WITH A GIVEN PROBABILITY LEVEL) OF ONE OR MORE
!                    NEW OBSERVATIONS.
!
!                 3) STANDARD DEVIATION PREDICTION LIMITS
!
!                    GIVEN A SET OF ORIGINAL OBSERVATIONS, THIS
!                    GENERATES A CONFIDENCE INTERVAL FOR THE SD
!                    OF ONE OR MORE NEW OBSERVATIONS.
!
!     INPUT  ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF
!                                ORIGINAL OBSERVATIONS.
!                       N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     REFERENCES--HAHN AND MEEKER (1991), "STATISTICAL INTERVALS: A
!                 GUIDE FOR PRACTIONERS", WILEY, PP. 61-65.
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2013/4
!     ORIGINAL VERSION--APRIL     2013.
!     UPDATED         --JUNE      2014. SUPPORT FOR LOGNORMAL
!                                       PREDICTION INTERVALS
!     UPDATED         --JUNE      2014. SUPPORT FOR BOX-COX
!                                       PREDICTION INTERVALS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASAN
      CHARACTER*4 ICASA2
      CHARACTER*4 ICASA3
      CHARACTER*4 ICASA4
      CHARACTER*4 ICASA5
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IVARID(*)
      CHARACTER*4 IVARI2(*)
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION PID(*)
      DIMENSION X2TEMP(*)
      DIMENSION Y2TEMP(*)
      DIMENSION D2TEMP(*)
!
      PARAMETER (NUMALP=6)
      REAL ALPHA(NUMALP)
      PARAMETER (NUMAL2=3)
      REAL ALPHA2(NUMAL2)
      REAL CONF(NUMALP)
!
      DIMENSION ALOWLM(NUMALP)
      DIMENSION AUPPLM(NUMALP)
!
      PARAMETER(NUMCLI=3)
      PARAMETER(MAXLIN=2)
      PARAMETER (MAXROW=30)
      CHARACTER*70 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*40 ITITL9
      CHARACTER*60 ITEXT(MAXROW)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      CHARACTER*20 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*4  IVALUE(MAXROW,NUMCLI)
      REAL         AVALUE(MAXROW)
      REAL         AMAT(MAXROW,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DATA ALPHA /0.50, 0.80, 0.90, 0.95, 0.99, 0.999/
      DATA ALPHA2/0.90, 0.95, 0.99/
!
      ISUBN1='DPPR'
      ISUBN2='L2  '
      IERROR='NO'
      IWRITE='OFF'
!
      CUTL90=CPUMIN
      CUTU90=CPUMIN
      CUTL95=CPUMIN
      CUTU95=CPUMIN
      CUTL99=CPUMIN
      CUTU99=CPUMIN
      CTL999=CPUMIN
      CTU999=CPUMIN
      CCORG=CPUMIN
      CCMAX=CPUMIN
      ALOC=CPUMIN
      ALAMBA=CPUMIN
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PRL2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPPRL2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASAN,ICASA2,ICASA3,ICASA4,ICASA5
   52   FORMAT('IBUGA3,ISUBRO,ICASAN,ICASA2,ICASA3,ICASA4,ICASA5 = ',   &
               6(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,54)N,N2
   54   FORMAT('N,N2 = ',2I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PRL2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LE.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN PREDICTION LIMITS--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,103)
  103   FORMAT('      THE NUMBER OF OBSERVATIONS IN THE RESPONSE ',   &
               'VARIABLE IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,105)N
  105   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(N2.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,113)
  113   FORMAT('      THE NUMBER OF OBSERVATIONS IN THE NEW SAMPLE ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,105)N2
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=Y(1)
      DO 135 I=2,N
        IF(Y(I).NE.HOLD)GO TO 139
  135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,101)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,131)HOLD
  131 FORMAT('      THE RESPONSE VARIABLE HAS ALL ELEMENTS = ',G15.7)
      CALL DPWRST('XXX','WRIT')
      GO TO 9000
  139 CONTINUE
!
!               ********************************************
!               **  STEP 2--                              **
!               **  SUPPORT FOR LOGNORMAL AND BOX-COX     **
!               **  TRANSFORMATIONS                       **
!               ********************************************
!
!
!     JUNE 2014: FOR LOGNORMAL PREDICTION LIMITS, TAKE THE LOG OF THE
!                DATA, COMPUTE NORMAL PREDICTION LIMITS, AND THEN
!                TAKE EXPONENT FOR THE LIMITS.
!
!                ALSO CAN DO A BOX-COX NORMALITY TRANSFORMATION.
!
      IWRITE='OFF'
      CALL MEAN(Y,N,IWRITE,YMEANZ,IBUGA3,IERROR)
      CALL SD(Y,N,IWRITE,YSDZ,IBUGA3,IERROR)
!
      IF(ICASA5.EQ.'LNPL')THEN
        DO 210 I=1,N
          IF(Y(I).LE.0.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,211)
  211       FORMAT('***** ERROR: LOGNORMAL PREDICTION LIMITS--')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,212)I,Y(I)
  212       FORMAT('      ROW ',I8,' IS NON-POSITIVE (',G15.7,')')
            CALL DPWRST('XXX','WRIT')
            IERROR='YES'
            GO TO 9000
          ELSE
            Y(I)=LOG(Y(I))
          ENDIF
  210   CONTINUE
      ELSEIF(ICASA5.EQ.'BCPL')THEN
!
!       NORMAL ORDER STATISTIC MEDIANS
!
        CALL UNIMED(N,X2TEMP)
        DO 231 I=1,N
          CALL NORPPF(X2TEMP(I),X2OUT)
          X2TEMP(I)=X2OUT
  231   CONTINUE
!
!       COMPUTE PPCC VALUE FOR UNTRANSFORMED DATA AND
!       RETURN CRITICAL VALUE FOR 3 <= N <= 1,000.
!
        CALL SORT(Y,N,D2TEMP)
        AN1=N
        SUMY=0.0
        DO 233 I=1,N
          SUMY=SUMY+D2TEMP(I)
  233   CONTINUE
        XBAR=0.0
        YBAR=SUMY/AN1
!
        SUMX=0.0
        SUMY=0.0
        SUMXY=0.0
        DO 234 I=1,N
          SUMX=SUMX+(X2TEMP(I)-XBAR)*(X2TEMP(I)-XBAR)
          SUMY=SUMY+(D2TEMP(I)-YBAR)*(D2TEMP(I)-YBAR)
          SUMXY=SUMXY+(X2TEMP(I)-XBAR)*(D2TEMP(I)-YBAR)
  234   CONTINUE
        ARG=SUMX*SUMY
        CCORG=0.0
        IF(ARG.GT.0.0)CCORG=SUMXY/SQRT(ARG)
!
        IF(N.GE.3 .AND. N.LE.1000)THEN
          ALPHAT=0.05
          CALL NORPCV(ALPHAT,N,CV,   &
                      ISUBRO,IBUGA3,IERROR)
        ELSE
          CV=CPUMIN
        ENDIF
!
!       SORT DATA AND SHIFT DATA TO MAKE IT POSITIVE
!
!CCCC   CALL SORT(Y,N,D2TEMP)
        XMIN=D2TEMP(1)
        IF(XMIN.LE.0.0)THEN
          DO 236 I=1,N
            D2TEMP(I)=D2TEMP(I)-XMIN+1.0
  236     CONTINUE
          ALOC=XMIN-1.0
        ELSE
          ALOC=0.0
        ENDIF
!
        ALAMBA=-2.0
        ALAMSV=ALAMBA
        AINC=0.1
        CCMAX=CPUMIN
!
        DO 240 IDIS=1,41
!
!         LOG TRANSFORMATION
!
          IF(-0.001.LE.ALAMBA.AND.ALAMBA.LE.0.001)THEN
            ALAMBA=0.0
            DO 241 I=1,N
              Y2TEMP(I)=LOG(D2TEMP(I))
  241       CONTINUE
          ELSE
            DO 246 I=1,N
              Y2TEMP(I)=((D2TEMP(I)**ALAMBA)-1.0)/ALAMBA
  246       CONTINUE
          ENDIF
!
          AN1=N
          SUMY=0.0
          DO 251 I=1,N
            SUMY=SUMY+Y2TEMP(I)
  251     CONTINUE
          XBAR=0.0
          YBAR=SUMY/AN1
!
          SUMX=0.0
          SUMY=0.0
          SUMXY=0.0
          DO 252 I=1,N
            SUMX=SUMX+(X2TEMP(I)-XBAR)*(X2TEMP(I)-XBAR)
            SUMY=SUMY+(Y2TEMP(I)-YBAR)*(Y2TEMP(I)-YBAR)
            SUMXY=SUMXY+(X2TEMP(I)-XBAR)*(Y2TEMP(I)-YBAR)
  252     CONTINUE
          ARG=SUMX*SUMY
          CC=0.0
          IF(ARG.GT.0.0)CC=SUMXY/SQRT(ARG)
          IF(CC.GT.CCMAX)THEN
            CCMAX=CC
            ALAMSV=ALAMBA
          ENDIF
!
          ALAMBA=ALAMBA + AINC
!
  240   CONTINUE
!
!       NOW TRANSFORM THE DATA
!
        ALAMBA=ALAMSV
        IF(ALAMBA.EQ.0.0)THEN
          DO 261 I=1,N
            Y(I)=LOG(D2TEMP(I))
  261     CONTINUE
        ELSE
          DO 263 I=1,N
            Y(I)=((D2TEMP(I)**ALAMBA)-1.0)/ALAMBA
  263     CONTINUE
        ENDIF
!
      ENDIF
!
!               ***************************************
!               **  STEP 3--                         **
!               **  COMPUTE PREDICTION LIMITS        **
!               **  FOR VARIOUS PROBABILITY VALUES.  **
!               ***************************************
!
      ISTEPN='4'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRL2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     ICASAN - LIMI   => PREDICTION LIMIT FOR THE MEAN
!              BOUN   => PREDICTION BOUND FOR ALL OBSERVATIONS
!              SDLI   => PREDICTION LIMIT FOR THE STANDARD DEVIATION
!     ICASA2:  LOWE   => LOWER LIMIT
!              UPPE   => UPPER LIMIT
!     ICASA3:  RAW    => RAW DATA
!              SUMM   => SUMMARY DATA
!     ICASA4:  ONES   => ONE-SIDED LIMIT
!              TWOS   => TWO-SIDED LIMIT
!
      AN=N
      ICASA3='RAW'
!
!     FOR N <= 10 AND N2 <= 10, USE TABULATED VALUES FOR PREDICTION
!     BOUNDS.
!
      IF(ICASAN.EQ.'BOUN' .AND. N.LE.10 .AND. N2.LE.10)THEN
        CALL DPPRL3(Y,N,N2,ICASAN,ICASA2,ICASA3,ICASA4,   &
                    YMEAN,YSD,   &
                    ALPHA2,NUMAL2,ALOWLM,AUPPLM,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(ICASA5.EQ.'LNPL')THEN
          DO 310 II=1,NUMAL2
            ALOWLM(II)=EXP(ALOWLM(II))
            AUPPLM(II)=EXP(AUPPLM(II))
  310     CONTINUE
        ELSEIF(ICASA5.EQ.'BCPL')THEN
          IF(ALAMBA.EQ.0.0)THEN
            DO 320 II=1,NUMAL2
              ALOWLM(II)=EXP(ALOWLM(II))
              AUPPLM(II)=EXP(AUPPLM(II))
              ALOWLM(II)=ALOWLM(II)+ALOC
              AUPPLM(II)=AUPPLM(II)+ALOC
  320       CONTINUE
          ELSE
            DO 330 II=1,NUMAL2
              ALOWLM(II)=(ALAMBA*ALOWLM(II) + 1.0)**(1.0/ALAMBA)
              AUPPLM(II)=(ALAMBA*AUPPLM(II) + 1.0)**(1.0/ALAMBA)
              ALOWLM(II)=ALOWLM(II)+ALOC
              AUPPLM(II)=AUPPLM(II)+ALOC
  330       CONTINUE
          ENDIF
        ENDIF
        CUTL90=ALOWLM(1)
        CUTU90=AUPPLM(1)
        CUTL95=ALOWLM(2)
        CUTU95=AUPPLM(2)
        CUTL99=ALOWLM(3)
        CUTU99=AUPPLM(3)
        NALP=NUMAL2
        DO 340 I=1,NUMAL2
          CONF(I)=100.0*ALPHA2(I) + 0.0001
  340   CONTINUE
      ELSE
        CALL DPPRL3(Y,N,N2,ICASAN,ICASA2,ICASA3,ICASA4,   &
                    YMEAN,YSD,   &
                    ALPHA,NUMALP,ALOWLM,AUPPLM,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(ICASA5.EQ.'LNPL')THEN
          DO 410 II=1,NUMALP
            ALOWLM(II)=EXP(ALOWLM(II))
            AUPPLM(II)=EXP(AUPPLM(II))
  410     CONTINUE
        ELSEIF(ICASA5.EQ.'BCPL')THEN
          IF(ALAMBA.EQ.0.0)THEN
            DO 420 II=1,NUMALP
              ALOWLM(II)=EXP(ALOWLM(II))
              AUPPLM(II)=EXP(AUPPLM(II))
              ALOWLM(II)=ALOWLM(II)+ALOC
              AUPPLM(II)=AUPPLM(II)+ALOC
  420       CONTINUE
          ELSE
            DO 430 II=1,NUMALP
              ALOWLM(II)=(ALAMBA*ALOWLM(II) + 1.0)**(1.0/ALAMBA)
              AUPPLM(II)=(ALAMBA*AUPPLM(II) + 1.0)**(1.0/ALAMBA)
              ALOWLM(II)=ALOWLM(II)+ALOC
              AUPPLM(II)=AUPPLM(II)+ALOC
  430       CONTINUE
          ENDIF
        ENDIF
        CUTL90=ALOWLM(3)
        CUTU90=AUPPLM(3)
        CUTL95=ALOWLM(4)
        CUTU95=AUPPLM(4)
        CUTL99=ALOWLM(5)
        CUTU99=AUPPLM(5)
        CTL999=ALOWLM(6)
        CTU999=AUPPLM(6)
        NALP=NUMALP
        DO 440 I=1,NUMALP
          CONF(I)=100.0*ALPHA(I) + 0.0001
  440   CONTINUE
      ENDIF
!
!               ****************************
!               **  STEP 5--              **
!               **  WRITE EVERYTHING OUT  **
!               ****************************
!
      ISTEPN='5'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRL2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      IF(ICASAN.EQ.'LIMI')THEN
        IF(ICASA4.EQ.'TWOS')THEN
          IF(ICASA5.EQ.'LNPL')THEN
            ITITLE='Two-Sided Lognormal Prediction Limits for the Mean'
            NCTITL=50
          ELSEIF(ICASA5.EQ.'BCPL')THEN
            ITITLE='Two-Sided Box-Cox Prediction Limits for the Mean'
            NCTITL=48
          ELSE
            ITITLE='Two-Sided Prediction Limits for the Mean'
            NCTITL=40
          ENDIF
          ITITLZ=' '
          NCTITZ=0
        ELSEIF(ICASA4.EQ.'ONES')THEN
          IF(ICASA2.EQ.'LOWE')THEN
            IF(ICASA5.EQ.'LNPL')THEN
              ITITLE=   &
              'One-Sided Lower Lognormal Prediction Limits for the Mean'
              NCTITL=56
            ELSEIF(ICASA5.EQ.'BCPL')THEN
              ITITLE=   &
              'One-Sided Lower Box-Cox Prediction Limits for the Mean'
              NCTITL=54
            ELSE
              ITITLE='One-Sided Lower Prediction Limits for the Mean'
              NCTITL=46
            ENDIF
            ITITLZ=' '
            NCTITZ=0
          ELSEIF(ICASA2.EQ.'UPPE')THEN
            IF(ICASA5.EQ.'LNPL')THEN
              ITITLE=   &
              'One-Sided Lower Lognormal Prediction Limits for the Mean'
              NCTITL=56
            ELSEIF(ICASA5.EQ.'BCPL')THEN
              ITITLE=   &
              'One-Sided Lower Box-Cox Prediction Limits for the Mean'
              NCTITL=54
            ELSE
              ITITLE='One-Sided Upper Prediction Limits for the Mean'
              NCTITL=46
            ENDIF
            ITITLZ=' '
            NCTITZ=0
          ENDIF
        ENDIF
      ELSEIF(ICASAN.EQ.'BOUN')THEN
        IF(ICASA4.EQ.'TWOS')THEN
          IF(ICASA5.EQ.'LNPL')THEN
            ITITLE=   &
            'Two-Sided Lognormal Prediction Bounds for All Observations'
            NCTITL=58
          ELSEIF(ICASA5.EQ.'BCPL')THEN
            ITITLE=   &
            'Two-Sided Box-Cox Prediction Bounds for All Observations'
            NCTITL=56
          ELSE
            ITITLE='Two-Sided Prediction Bounds for All Observations'
            NCTITL=48
          ENDIF
          ITITLZ=' '
          NCTITZ=0
        ELSEIF(ICASA4.EQ.'ONES')THEN
          IF(ICASA2.EQ.'LOWE')THEN
            IF(ICASA5.EQ.'LNPL')THEN
              ITITLE(1:37)='One-Sided Lower Lognormal Prediction '
              ITITLE(38:64)='Bounds for All Observations'
              NCTITL=64
            ELSEIF(ICASA5.EQ.'BCPL')THEN
              ITITLE(1:35)='One-Sided Lower Box-Cox Prediction '
              ITITLE(36:62)='Bounds for All Observations'
              NCTITL=62
            ELSE
              ITITLE=   &
              'One-Sided Lower Prediction Bounds for All Observations'
              NCTITL=54
            ENDIF
            ITITLZ=' '
            NCTITZ=0
          ELSEIF(ICASA2.EQ.'UPPE')THEN
            IF(ICASA5.EQ.'LNPL')THEN
              ITITLE(1:37)='One-Sided Upper Lognormal Prediction '
              ITITLE(38:64)='Bounds for All Observations'
              NCTITL=64
            ELSEIF(ICASA5.EQ.'BCPL')THEN
              ITITLE(1:35)='One-Sided Upper Box-Cox Prediction '
              ITITLE(36:62)='Bounds for All Observations'
              NCTITL=62
            ELSE
              ITITLE=   &
              'One-Sided Upper Prediction Bounds for All Observations'
              NCTITL=54
            ENDIF
            ITITLZ=' '
            NCTITZ=0
          ENDIF
        ENDIF
      ELSEIF(ICASAN.EQ.'SDLI')THEN
        IF(ICASA4.EQ.'TWOS')THEN
          IF(ICASA5.EQ.'LNPL')THEN
            ITITLE='Two-Sided Lognormal Prediction Limits for the SD'
            NCTITL=48
          ELSEIF(ICASA5.EQ.'BCPL')THEN
            ITITLE='Two-Sided Box-Cox Prediction Limits for the SD'
            NCTITL=46
          ELSE
            ITITLE='Two-Sided Prediction Limits for the SD'
            NCTITL=38
          ENDIF
          ITITLZ=' '
          NCTITZ=0
        ELSEIF(ICASA4.EQ.'ONES')THEN
          IF(ICASA2.EQ.'LOWE')THEN
            IF(ICASA5.EQ.'LNPL')THEN
              ITITLE=   &
              'One-Sided Lognormal Lower Prediction Limits for the SD'
              NCTITL=54
            ELSEIF(ICASA5.EQ.'BCPL')THEN
              ITITLE=   &
              'One-Sided Box-Cox Lower Prediction Limits for the SD'
              NCTITL=52
            ELSE
              ITITLE='One-Sided Lower Prediction Limits for the SD'
              NCTITL=44
            ENDIF
            ITITLZ=' '
            NCTITZ=0
          ELSEIF(ICASA2.EQ.'UPPE')THEN
            IF(ICASA5.EQ.'LNPL')THEN
              ITITLE=   &
              'One-Sided Lognormal Upper Prediction Limits for the SD'
              NCTITL=54
            ELSEIF(ICASA5.EQ.'BCPL')THEN
              ITITLE=   &
              'One-Sided Box-Cox Upper Prediction Limits for the SD'
              NCTITL=52
            ELSE
              ITITLE='One-Sided Upper Prediction Limits for the SD'
              NCTITL=44
            ENDIF
            ITITLZ=' '
            NCTITZ=0
          ENDIF
        ENDIF
      ENDIF
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Response Variable: '
      WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(1)(1:4)
      WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(1)(1:4)
      NCTEXT(ICNT)=27
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      IF(NREPL.GT.0)THEN
        NRESP=1
        DO 4101 I=1,NREPL
          ICNT=ICNT+1
          ITEMP=I+NRESP
          ITEXT(ICNT)='Factor Variable  : '
          WRITE(ITEXT(ICNT)(17:17),'(I1)')I
          WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(ITEMP)(1:4)
          WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(ITEMP)(1:4)
          NCTEXT(ICNT)=27
          AVALUE(ICNT)=PID(ITEMP)
          IDIGIT(ICNT)=NUMDIG
 4101   CONTINUE
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      IF(ICASA5.EQ.'BCPL')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=1
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Untransformed Data:'
        NCTEXT(ICNT)=19
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Value of Normal PPCC:'
        NCTEXT(ICNT)=21
        AVALUE(ICNT)=CCORG
        IDIGIT(ICNT)=NUMDIG
        IF(CV.NE.CPUMIN)THEN
          ICNT=ICNT+1
          ITEXT(ICNT)='5% Critical Value:'
          NCTEXT(ICNT)=18
          AVALUE(ICNT)=CV
          IDIGIT(ICNT)=NUMDIG
        ENDIF
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=1
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        ICNT=ICNT+1
        ITEXT(ICNT)='Transformed Data:'
        NCTEXT(ICNT)=19
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Value of Lambda:'
        NCTEXT(ICNT)=16
        AVALUE(ICNT)=ALAMBA
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Value of Normal PPCC:'
        NCTEXT(ICNT)=21
        AVALUE(ICNT)=CCMAX
        IDIGIT(ICNT)=NUMDIG
        IF(CV.NE.CPUMIN)THEN
          ICNT=ICNT+1
          ITEXT(ICNT)='5% Critical Value:'
          NCTEXT(ICNT)=18
          AVALUE(ICNT)=CV
          IDIGIT(ICNT)=NUMDIG
        ENDIF
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=1
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ENDIF
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
!CCCC IF(ICASA5.EQ.'LNPL')THEN
!CCCC   ITEXT(ICNT)='Sample Mean of Log of Data:'
!CCCC   NCTEXT(ICNT)=27
!CCCC ELSEIF(ICASA5.EQ.'BCPL')THEN
!CCCC   ITEXT(ICNT)='Sample Mean of Transformed Data:'
!CCCC   NCTEXT(ICNT)=33
!CCCC ELSE
!CCCC   ITEXT(ICNT)='Sample Mean:'
!CCCC   NCTEXT(ICNT)=12
!CCCC ENDIF
      ITEXT(ICNT)='Sample Mean:'
      NCTEXT(ICNT)=12
      AVALUE(ICNT)=YMEANZ
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation:'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=YSDZ
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of New Observations:'
      NCTEXT(ICNT)=27
      AVALUE(ICNT)=REAL(N2)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      NUMROW=ICNT
      DO 4210 I=1,NUMROW
        NTOT(I)=15
 4210 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='5A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRL2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ITITL2(1,1)='Confidence'
      NCTIT2(1,1)=10
      ITITL2(2,1)='Value (%)'
      NCTIT2(2,1)=9
      ICOL=1
!
!CCCC print *,'icasa2,icasa4=',icasa2,' ',icasa4
      IF(ICASA4.EQ.'TWOS' .OR.   &
        (ICASA4.EQ.'ONES' .AND. ICASA2.EQ.'LOWE'))THEN
        ICOL=ICOL+1
        ITITL2(1,ICOL)='Lower'
        NCTIT2(1,ICOL)=5
        ITITL2(2,ICOL)='Limit'
        NCTIT2(2,ICOL)=5
      ENDIF
!
      IF(ICASA4.EQ.'TWOS' .OR.   &
        (ICASA4.EQ.'ONES' .AND. ICASA2.EQ.'UPPE'))THEN
        ICOL=ICOL+1
        ITITL2(1,ICOL)='Upper'
        NCTIT2(1,ICOL)=5
        ITITL2(2,ICOL)='Limit'
        NCTIT2(2,ICOL)=5
      ENDIF
!
      NUMLIN=2
      NUMCOL=ICOL
      NUMROW=NALP
      NMAX=0
      DO 4221 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IDIGIT(I)=NUMDIG
        ITYPCO(I)='NUME'
        IF(I.EQ.1)THEN
          NTOT(I)=12
          IDIGIT(I)=1
          IWHTML(1)=75
        ENDIF
        NMAX=NMAX+NTOT(I)
 4221 CONTINUE
      DO 4223 I=1,NUMROW
        DO 4225 J=1,NUMCOL
          NCVALU(I,J)=0
          IVALUE(I,J)=' '
          AMAT(I,J)=0.0
 4225   CONTINUE
        JCNT=1
        AMAT(I,1)=CONF(I)
        IF(ICASA4.EQ.'TWOS' .OR.   &
          (ICASA4.EQ.'ONES' .AND. ICASA2.EQ.'LOWE'))THEN
          JCNT=JCNT+1
          AMAT(I,JCNT)=ALOWLM(I)
        ENDIF
        IF(ICASA4.EQ.'TWOS' .OR.   &
          (ICASA4.EQ.'ONES' .AND. ICASA2.EQ.'UPPE'))THEN
          JCNT=JCNT+1
          AMAT(I,JCNT)=AUPPLM(I)
        ENDIF
 4223 CONTINUE
!
      IWHTML(1)=150
      IWHTML(2)=150
      IWHTML(3)=150
      IWRTF(1)=2000
      IWRTF(2)=IWRTF(1)+2000
      IWRTF(3)=IWRTF(2)+2000
      IFRST=.TRUE.
      ILAST=.TRUE.
      NCTIT9=0
!
!CCCC print *,'nctit9,nctitl = ',nctit9,nctitl
!CCCC print *,'maxrow,numrow,maxlin,numlin=',maxrow,numrow,maxlin,numlin
!CCCC print *,'numcli,numcol=',numcli,numcol
      CALL DPDTA4(ITITL9,NCTIT9,   &
                  ITITLE,NCTITL,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,NUMROW,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PRL2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPRL2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPRL2
      SUBROUTINE DPPRL3(Y1,N1,N2,ICASAN,ICASA2,ICASA3,ICASA4,   &
                        YMEAN,YSD,   &
                        ALPHA,NALPHA,ALOWLM,AUPPLM,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES NORMAL ONE-SIDED AND
!              TWO-SIDED NORMAL PREDICTION LOWER AND UPPER LIMITS.
!
!              THE FOLLOWING CASES ARE SUPPORTED:
!
!                 LET A = LOWER PREDICTION INTERVAL Y
!                 LET A = UPPER REDICTION INTERVAL Y
!                 LET A = ONE SIDED LOWER PREDICTION INTERVAL Y
!                 LET A = ONE SIDED UPPER PREDICTION INTERVAL Y
!
!                 LET A = LOWER PREDICTION BOUND Y
!                 LET A = UPPER REDICTION BOUND Y
!                 LET A = ONE SIDED LOWER PREDICTION BOUND Y
!                 LET A = ONE SIDED UPPER PREDICTION BOUND Y
!
!                 LET A = LOWER SD PREDICTION LIMIT Y
!                 LET A = UPPER SD PREDICTION LIMIT Y
!                 LET A = ONE SIDED LOWER SD PREDICTION INTERVAL Y
!                 LET A = ONE SIDED UPPER SD PREDICTION INTERVAL Y
!
!              THE DATA CONSISTS OF N1 ORIGINAL OBSERVATIONS IN Y1 AND
!              N2 NEW OBSERVATIONS.  FOR ALL CASES, THE NUMBER OF
!              OBSERVATIONS IN THE NEW SAMPLE IS SPECIFIED WITH THE
!              COMMAND
!
!                 LET NNEW = <VALUE>
!
!              FOR ALL OF THE CASES ABOVE, THERE IS A "SUMMARY" CASE
!              WHERE WE SPECIFY THE MEAN, STANDARD DEVIATION, AND SAMPLE
!              SIZE FOR THE FIRST SAMPLE.  FOR EXAMPLE,
!
!                 LET A = SUMMARY LOWER PREDICTION INTERVAL YMEAN YSD N1
!
!              THE PREDICITON INTERVAL IS AN INTERVAL FOR THE MEAN
!              OF THE N2 NEW OBSERVATIONS.  THE FORMULA IN THIS CASE IS:
!
!                  XBAR +/- t(1-alpha/2;N1-1)*SQRT((1/N1) + (1/N2))*S
!
!              WITH XBAR AND S DENOTING THE SAMPLE MEAN AND STANDARD
!              DEVIATION OF THE ORIGINAL SAMPLE AND t DENOTING THE
!              T PERCENT POINT FUNCTION.
!
!              THE PREDICTION BOUND IS AN INTERVAL THAT WILL
!              CONTAIN ALL OF THE N2 NEW OBSERVATIONS.  THE FORMULA FOR
!              A TWO-SIDED INTERVAL IS:
!
!                   XBAR +/- r(1-ALPHA;N2,N1)*S
!
!              A CONSERVATIVE VALUE FOR r IS:
!
!                   r(1-ALPHA;N2,N1) = SQRT(1 + (1/N1))*t(1-ALPHA/(2*N2);N1-1)
!
!              A ONE-SIDED INTERVAL IS:
!
!                   XBAR + r'(1-ALPHA;N2,N1)*S
!
!              A CONSERVATIVE VALUE FOR r' IS:
!
!                   r'(1-ALPHA;N2,N1) = SQRT(1 + (1/N1))*t(1-ALPHA/N2;N1-1)
!
!              A TWO-SIDED PREDICTION INTERVAL FOR THE STANDARD
!              DEVIATION IS:
!
!                  [s(lower),s(upper)] = [s*SQRT(1/F(1-alpha/2;n1-1,n2-1)),
!                                         s*SQRT(F(1-alpha/2;n2-1,n1-1))]
!
!     INPUT ARGUMENTS--Y1     = THE SINGLE PRECISION VECTOR OF
!                               (UNSORTED OR SORTED) OBSERVATIONS.
!                    --N1     = THE INTEGER NUMBER OF OBSERVATIONS
!                               IN THE VECTOR Y1.
!                    --Y2     = THE SINGLE PRECISION VECTOR OF
!                               OBSERVATIONS FOR WHICH THE PREDICTION
!                               LIMITS WILL BE COMPUTED.
!                    --N2     = THE INTEGER NUMBER OF OBSERVATIONS
!                               IN THE VECTOR Y2.
!                    --ALPHA  = THE SINGLE PRECISION VECTOR OF CONFIDENCE
!                               LEVELS
!                      NALPHA = THE INTEGER NUMBER OF ALPHA VALUES
!     OUTPUT ARGUMENTS-ALOWLM = THE SINGLE PRECISION VECTOR OF LOWER LIMIT
!                               VALUES
!                     -AUPPLM = THE SINGLE PRECISION VECTOR OF UPPER LIMIT
!                               VALUES
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--HAHN AND MEEKER (1991), "STATISTICAL INTERVALS: A
!                 GUIDE FOR PRACTIONERS", WILEY, PP. 61-65.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     ORIGINAL VERSION--MARCH     2013.
!     UPDATED         --JUNE      2014. SUPPORT FOR LOGNORMAL
!                                       PREDICTION INTERVALS
!     UPDATED         --JUNE      2014. SUPPORT FOR BOX-COX
!                                       PREDICTION INTERVALS
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION ALOWLM(*)
      DIMENSION AUPPLM(*)
      DIMENSION ALPHA(*)
!
      REAL R2S90(7,10)
      REAL R2S95(7,10)
      REAL R2S99(7,10)
      REAL R1S90(7,10)
      REAL R1S95(7,10)
      REAL R1S99(7,10)
!
      CHARACTER*4 ICASAN
      CHARACTER*4 ICASA2
      CHARACTER*4 ICASA3
      CHARACTER*4 ICASA4
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DATA ((R2S90(I,J),J=1,10),I=1,7)/   &
       2.631,3.329,3.742,4.032,4.255,4.435,4.585,4.713,4.826,4.925,   &
       2.335,2.909,3.246,3.483,3.665,3.812,3.936,4.041,4.134,4.216,   &
       2.177,2.685,2.982,3.190,3.350,3.480,3.589,3.682,3.764,3.836,   &
       2.077,2.546,2.818,3.008,3.155,3.273,3.373,3.458,3.533,3.599,   &
       2.010,2.452,2.706,2.884,3.021,3.132,3.225,3.305,3.375,3.437,   &
       1.960,2.383,2.625,2.794,2.924,3.029,3.118,3.193,3.259,3.318,   &
       1.923,2.331,2.564,2.726,2.851,2.951,3.036,3.108,3.172,3.228/
!
      DATA ((R2S95(I,J),J=1,10),I=1,7)/   &
       3.558,4.412,4.923,5.285,5.564,5.789,5.978,6.140,6.282,6.407,   &
       3.041,3.697,4.087,4.364,4.577,4.751,4.896,5.021,5.131,5.229,   &
       2.777,3.333,3.662,3.896,4.076,4.223,4.346,4.452,4.545,4.628,   &
       2.616,3.114,3.407,3.614,3.774,3.905,4.014,4.108,4.191,4.265,   &
       2.508,2.968,3.236,3.426,3.573,3.692,3.792,3.879,3.954,4.022,   &
       2.431,2.863,3.115,3.292,3.429,3.540,3.634,3.714,3.785,3.848,   &
       2.373,2.785,3.024,3.192,3.321,3.426,3.515,3.591,3.658,3.717/
!
      DATA ((R2S99(I,J),J=1,10),I=1,7)/   &
       6.530,7.942,8.800,9.411,9.884,10.268,10.590,10.867,11.110,11.325,   &
       5.044,5.972,6.536,6.940,7.253,7.509,7.725,7.911,8.074,8.219,   &
       4.355,5.071,5.503,5.814,6.055,6.253,6.420,6.564,6.690,6.803,   &
       3.963,4.562,4.922,5.181,5.382,5.546,5.685,5.806,5.912,6.006,   &
       3.712,4.238,4.552,4.778,4.953,5.097,5.218,5.323,5.416,5.499,   &
       3.537,4.014,4.297,4.500,4.657,4.787,4.896,4.990,5.074,5.148,   &
       3.408,3.850,4.111,4.297,4.442,4.560,4.660,4.747,4.824,4.892/
!
      DATA ((R1S90(I,J),J=1,10),I=1,7)/   &
       1.831,2.484,2.873,3.150,3.364,3.538,3.684,3.809,3.919,4.017,   &
       1.680,2.240,2.567,2.798,2.975,3.120,3.241,3.345,3.436,3.517,   &
       1.594,2.105,2.399,2.606,2.764,2.893,3.001,3.093,3.174,3.246,   &
       1.539,2.020,2.294,2.485,2.631,2.750,2.849,2.935,3.010,3.076,   &
       1.501,1.961,2.221,2.402,2.540,2.652,2.745,2.826,2.896,2.959,   &
       1.472,1.917,2.167,2.341,2.473,2.580,2.669,2.746,2.813,2.873,   &
       1.451,1.884,2.126,2.294,2.422,2.525,2.611,2.685,2.750,2.807/
!
      DATA ((R1S95(I,J),J=1,10),I=1,7)/   &
       2.631,3.401,3.871,4.209,4.472,4.686,4.867,5.023,5.160,5.282,   &
       2.335,2.952,3.320,3.583,3.788,3.955,4.095,4.216,4.323,4.418,   &
       2.177,2.715,3.033,3.259,3.433,3.576,3.696,3.799,3.890,3.971,   &
       2.077,2.570,2.857,3.060,3.217,3.345,3.452,3.545,3.627,3.699,   &
       2.010,2.471,2.738,2.926,3.071,3.189,3.288,3.374,3.449,3.516,   &
       1.960,2.400,2.652,2.830,2.966,3.077,3.170,3.250,3.321,3.384,   &
       1.923,2.346,2.587,2.757,2.887,2.992,3.081,3.157,3.224,3.284/
!
      DATA ((R1S99(I,J),J=1,10),I=1,7)/   &
       5.077,6.305,7.073,7.632,8.070,8.430,8.734,8.996,9.228,9.434,   &
       4.105,4.943,5.459,5.833,6.126,6.367,6.571,6.748,6.904,7.043,   &
       3.635,4.298,4.701,4.993,5.221,5.409,5.567,5.705,5.827,5.935,   &
       3.360,3.926,4.267,4.513,4.705,4.862,4.996,5.111,5.213,5.305,   &
       3.180,3.685,3.987,4.203,4.372,4.511,4.628,4.730,4.819,4.900,   &
       3.053,3.517,3.792,3.988,4.141,4.267,4.373,4.465,4.546,4.619,   &
       2.959,3.393,3.648,3.830,3.972,4.087,4.185,4.270,4.345,4.412/
!
      ISUBN1='PRL3'
      ISUBN2='    '
      IWRITE='OFF'
      IERROR='NO'
!
      N1INDX=0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRL3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPPRL3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASAN,ICASA2,ICASA3,ICASA4
   52   FORMAT('IBUGA3,ISUBRO,ICASAN,ICASA2,ICASA3,ICASA4 = ',   &
               5(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,53)N1,N2,NALPHA,YMEAN,YSD,ALPHA(1)
   53   FORMAT('N1,N2,NALPHA,YMEAN,YSD,ALPHA(1) = ',3I8,3G15.7)
        CALL DPWRST('XXX','WRIT')
        IF(ICASA3.EQ.'RAW')THEN
          DO 56 I=1,N1
            WRITE(ICOUT,57)I,Y1(I)
   57       FORMAT('I,Y1(I) = ',I8,G15.7)
            CALL DPWRST('XXX','WRIT')
   56     CONTINUE
        ENDIF
        DO 76 I=1,NALPHA
          WRITE(ICOUT,77)I,ALPHA(I)
   77     FORMAT('I,ALPHA(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   76   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PRL3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N1.LT.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR: PREDICTION LIMITS--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,102)
  102   FORMAT('      THE NUMBER OF ORIGINAL OBSERVATIONS  IS LESS ',   &
               'THAN FOUR.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,103)N1
  103   FORMAT('      SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(N2.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF NEW OBSERVATIONS  IS LESS ',   &
               'THAN ONE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,103)N2
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  CARRY OUT CALCULATIONS FOR PREDICTION **
!               **  LIMITS.                               **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON'.AND.ISUBRO.EQ.'PRL3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     ICASAN:  LIMI     => PREDICTION LIMIT FOR MEAN
!              BOUN     => PREDICTION BOUND
!              SDLI     => PREDICTION LIMIT FOR SD
!     ICASA2:  LOWE     => LOWER LIMIT
!              UPPE     => UPPER LIMIT
!     ICASA3:  RAW      => RAW DATA IN Y1
!              SUMM     => SUMMARY DATA IN YMEAN AND YSD
!     ICASA4:  ONES     => ONE-SIDED LIMIT
!              TWOS     => TWO-SIDED LIMIT
!
!     COMPUTE MEAN AND STANDARD DEVIATION
!
      DO 210 I=1,NALPHA
        ALOWLM(I)=CPUMIN
        AUPPLM(I)=CPUMIN
  210 CONTINUE
!
      IF(ICASA3.EQ.'RAW')THEN
        CALL MEAN(Y1,N1,IWRITE,YMEAN,IBUGA3,IERROR)
        CALL SD(Y1,N1,IWRITE,YSD,IBUGA3,IERROR)
      ENDIF
!
      IF(YSD.LE.0.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,212)
  212   FORMAT('      THE STANDARD DEVIATION OF THE ORIGINAL ',   &
               'OBSERVATIONS IS NON-POSITIVE.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      ANU=REAL(N1 - 1)
      AN1=REAL(N1)
      AN2=REAL(N2)
!
      IF(ICASAN.EQ.'LIMI')THEN
        AFACT=SQRT((1.0/AN1) + (1.0/AN2))
        IF(ICASA2.EQ.'LOWE')THEN
          IF(ICASA4.EQ.'ONES')THEN
            DO 260 I=1,NALPHA
              ALPHAT=ALPHA(I)
              IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
              IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
              IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
              CALL TPPF(ALPHAT,ANU,PPF)
              ALOWLM(I)=YMEAN - ABS(PPF)*AFACT*YSD
              AUPPLM(I)=YMEAN + ABS(PPF)*AFACT*YSD
  260       CONTINUE
          ELSEIF(ICASA4.EQ.'TWOS')THEN
            DO 265 I=1,NALPHA
              ALPHAT=ALPHA(I)
              IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
              IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
              IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
              ALPHAT=ALPHAT/2.0
              CALL TPPF(ALPHAT,ANU,PPF)
              ALOWLM(I)=YMEAN - ABS(PPF)*AFACT*YSD
              AUPPLM(I)=YMEAN + ABS(PPF)*AFACT*YSD
  265       CONTINUE
          ENDIF
        ELSEIF(ICASA2.EQ.'UPPE')THEN
          IF(ICASA4.EQ.'ONES')THEN
            DO 270 I=1,NALPHA
              ALPHAT=ALPHA(I)
              IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
              IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
              IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
              CALL TPPF(ALPHAT,ANU,PPF)
              ALOWLM(I)=YMEAN - ABS(PPF)*AFACT*YSD
              AUPPLM(I)=YMEAN + ABS(PPF)*AFACT*YSD
  270       CONTINUE
          ELSEIF(ICASA4.EQ.'TWOS')THEN
            DO 275 I=1,NALPHA
              ALPHAT=ALPHA(I)
              IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
              IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
              IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
              ALPHAT=ALPHAT/2.0
              CALL TPPF(ALPHAT,ANU,PPF)
              ALOWLM(I)=YMEAN - ABS(PPF)*AFACT*YSD
              AUPPLM(I)=YMEAN + ABS(PPF)*AFACT*YSD
  275       CONTINUE
          ENDIF
        ENDIF
      ELSEIF(ICASAN.EQ.'BOUN')THEN
        AFACT=SQRT(1.0 + (1.0/AN1))
        IF(N1.GE.4 .AND. N1.LE.10 .AND. N2.LE.10)THEN
          IFLAGT=1
          N1INDX=N1-3
        ELSE
          IFLAGT=0
        ENDIF
        EPS=0.0001
        IF(ICASA2.EQ.'LOWE')THEN
          IF(ICASA4.EQ.'ONES')THEN
            DO 360 I=1,NALPHA
              ALPHAT=ALPHA(I)
              IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
              IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
              IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
              IF(ABS(ALPHAT-0.10).LE.EPS .AND. IFLAGT.EQ.1)THEN
                PPF=R1S90(N1INDX,N2)
              ELSEIF(ABS(ALPHAT-0.05).LE.EPS .AND. IFLAGT.EQ.1)THEN
                PPF=R1S95(N1INDX,N2)
              ELSEIF(ABS(ALPHAT-0.01).LE.EPS .AND. IFLAGT.EQ.1)THEN
                PPF=R1S99(N1INDX,N2)
              ELSE
                ALPHAT=ALPHAT/AN2
                CALL TPPF(ALPHAT,ANU,PPF)
                PPF=AFACT*ABS(PPF)
              ENDIF
              ALOWLM(I)=YMEAN - PPF*YSD
  360       CONTINUE
          ELSEIF(ICASA4.EQ.'TWOS')THEN
            DO 365 I=1,NALPHA
              ALPHAT=ALPHA(I)
              IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
              IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
              IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
              IF(ABS(ALPHAT-0.10).LE.EPS .AND. IFLAGT.EQ.1)THEN
                PPF=R2S90(N1INDX,N2)
              ELSEIF(ABS(ALPHAT-0.05).LE.EPS .AND. IFLAGT.EQ.1)THEN
                PPF=R2S95(N1INDX,N2)
              ELSEIF(ABS(ALPHAT-0.01).LE.EPS .AND. IFLAGT.EQ.1)THEN
                PPF=R2S99(N1INDX,N2)
              ELSE
                ALPHAT=ALPHAT/(2.0*AN2)
                CALL TPPF(ALPHAT,ANU,PPF)
                PPF=AFACT*ABS(PPF)
              ENDIF
              ALOWLM(I)=YMEAN - PPF*YSD
              AUPPLM(I)=YMEAN + PPF*YSD
  365       CONTINUE
          ENDIF
        ELSEIF(ICASA2.EQ.'UPPE')THEN
          IF(ICASA4.EQ.'ONES')THEN
            DO 370 I=1,NALPHA
              ALPHAT=ALPHA(I)
              IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
              IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
              IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
              IF(ABS(ALPHAT-0.10).LE.EPS .AND. IFLAGT.EQ.1)THEN
                PPF=R1S90(N1INDX,N2)
              ELSEIF(ABS(ALPHAT-0.05).LE.EPS .AND. IFLAGT.EQ.1)THEN
                PPF=R1S95(N1INDX,N2)
              ELSEIF(ABS(ALPHAT-0.01).LE.EPS .AND. IFLAGT.EQ.1)THEN
                PPF=R1S99(N1INDX,N2)
              ELSE
                ALPHAT=ALPHAT/AN2
                CALL TPPF(ALPHAT,ANU,PPF)
                PPF=AFACT*ABS(PPF)
              ENDIF
              AUPPLM(I)=YMEAN + PPF*YSD
  370       CONTINUE
          ELSEIF(ICASA4.EQ.'TWOS')THEN
            DO 375 I=1,NALPHA
              ALPHAT=ALPHA(I)
              IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
              IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
              IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
              IF(ABS(ALPHAT-0.10).LE.EPS .AND. IFLAGT.EQ.1)THEN
                PPF=R2S90(N1INDX,N2)
              ELSEIF(ABS(ALPHAT-0.05).LE.EPS .AND. IFLAGT.EQ.1)THEN
                PPF=R2S95(N1INDX,N2)
              ELSEIF(ABS(ALPHAT-0.01).LE.EPS .AND. IFLAGT.EQ.1)THEN
                PPF=R2S99(N1INDX,N2)
              ELSE
                ALPHAT=ALPHAT/(2.0*AN2)
                CALL TPPF(ALPHAT,ANU,PPF)
                PPF=AFACT*ABS(PPF)
              ENDIF
              ALOWLM(I)=YMEAN - PPF*YSD
              AUPPLM(I)=YMEAN + PPF*YSD
  375       CONTINUE
          ENDIF
        ENDIF
      ELSEIF(ICASAN.EQ.'SDLI')THEN
        NU1=N1-1
        NU2=N2-1
        IF(ICASA2.EQ.'LOWE')THEN
          IF(ICASA4.EQ.'ONES')THEN
            DO 460 I=1,NALPHA
              ALPHAT=ALPHA(I)
              IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
              IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
              IF(ALPHAT.LT.0.5)ALPHAT=1.0 - ALPHAT
              CALL FPPF(ALPHAT,NU1,NU2,PPF)
              ALOWLM(I)=YSD*SQRT(1.0/PPF)
              CALL FPPF(ALPHAT,NU2,NU1,PPF)
              AUPPLM(I)=YSD*SQRT(PPF)
  460       CONTINUE
          ELSEIF(ICASA4.EQ.'TWOS')THEN
            DO 465 I=1,NALPHA
              ALPHAT=ALPHA(I)
              IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
              IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
              IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
              ALPHAT=1.0 - (ALPHAT/2.0)
              CALL FPPF(ALPHAT,NU1,NU2,PPF)
              ALOWLM(I)=YSD*SQRT(1.0/PPF)
              CALL FPPF(ALPHAT,NU2,NU1,PPF)
              AUPPLM(I)=YSD*SQRT(PPF)
  465       CONTINUE
          ENDIF
        ELSEIF(ICASA2.EQ.'UPPE')THEN
          IF(ICASA4.EQ.'ONES')THEN
            DO 470 I=1,NALPHA
              ALPHAT=ALPHA(I)
              IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
              IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
              IF(ALPHAT.LT.0.5)ALPHAT=1.0 - ALPHAT
              CALL FPPF(ALPHAT,NU1,NU2,PPF)
              ALOWLM(I)=YSD*SQRT(1.0/PPF)
              CALL FPPF(ALPHAT,NU2,NU1,PPF)
              AUPPLM(I)=YSD*SQRT(PPF)
  470       CONTINUE
          ELSEIF(ICASA4.EQ.'TWOS')THEN
            DO 475 I=1,NALPHA
              ALPHAT=ALPHA(I)
              IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
              IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
              IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
              ALPHAT=1.0 - (ALPHAT/2.0)
              CALL FPPF(ALPHAT,NU1,NU2,PPF)
              ALOWLM(I)=YSD*SQRT(1.0/PPF)
              CALL FPPF(ALPHAT,NU2,NU1,PPF)
              AUPPLM(I)=YSD*SQRT(PPF)
  475       CONTINUE
          ENDIF
        ENDIF
      ENDIF
      GO TO 9000
!
 8000 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,101)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,8001)I
 8001 FORMAT('      ROW ',I8,' OF ALPHA VALUES IS OUT OF RANGE.')
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,8003)ALPHA(I)
 8003 FORMAT('      THE VALUE OF ALPHA IS ',G15.7)
      CALL DPWRST('XXX','WRIT')
      IERROR='YES'
      GO TO 9000
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PRL3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9051)
 9051   FORMAT('**** AT THE END OF DPPRL3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9052)YMEAN,YSD,PPF,AFACT
 9052   FORMAT('YMEAN,YSD,PPF,AFACT = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9061)ALPHA(NALPHA),ALPHAT,ANU,PPF
 9061   FORMAT('ALPHA(NALPHA),ALPHAT,ANU,PPF = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPPRL3
